/**
 * DetalleEventoModal - Modal compacto para mostrar detalles de eventos del historial
 *
 * ✅ COMPONENTE PRESENTACIONAL PURO
 * ✅ DISEÑO COMPACTO Y ORGANIZADO POR SECCIONES
 * ✅ ICONOS ESPECÍFICOS POR TIPO DE DATO
 * ✅ GRID RESPONSIVE DE 2 COLUMNAS
 * ✅ USA PORTAL para renderizar fuera de la jerarquía del componente padre
 */

'use client'

import { useEffect, useState } from 'react'

import {
    Building2,
    Calendar,
    FileText,
    Hash,
    Heart,
    Home,
    Mail,
    MapPin,
    MessageSquare,
    Phone,
    User,
    Users,
} from 'lucide-react'
import { createPortal } from 'react-dom'

import type { DetalleEvento } from '@/modules/clientes/types/historial.types'
import { Modal } from '@/shared/components/ui/Modal'


interface DetalleEventoModalProps {
  isOpen: boolean
  onClose: () => void
  titulo: string
  subtitulo?: string
  detalles: DetalleEvento[]
}

export function DetalleEventoModal({
  isOpen,
  onClose,
  titulo,
  subtitulo,
  detalles,
}: DetalleEventoModalProps) {
  const [mounted, setMounted] = useState(false)

  // Asegurar que solo se renderice en el cliente
  useEffect(() => {
    setMounted(true)
    return () => setMounted(false)
  }, [])

  // No renderizar en servidor o antes de montar
  if (!mounted) return null

  // Agrupar campos por sección
  const secciones = agruparPorSeccion(detalles)

  // Renderizar modal usando portal para evitar que se renderice dentro de la card
  return createPortal(
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={titulo}
      description={subtitulo}
      size="lg"
      compact
      icon={<FileText className="w-4 h-4 sm:w-5 sm:h-5 text-white" />}
      gradientColor="cyan"
    >
      <div className="space-y-3 sm:space-y-4">
        {secciones.map((seccion, secIdx) => (
          <div key={secIdx}>
            {/* Header de sección */}
            <div className="flex items-center gap-2 mb-2 sm:mb-2.5 pb-1.5 sm:pb-2 border-b-2 border-cyan-200 dark:border-cyan-800">
              <div className="w-6 h-6 sm:w-7 sm:h-7 rounded-lg bg-gradient-to-br from-cyan-500 to-blue-500 flex items-center justify-center shadow-md flex-shrink-0">
                <seccion.icono className="w-3 h-3 sm:w-4 sm:h-4 text-white" />
              </div>
              <h4 className="text-xs sm:text-sm font-bold text-gray-900 dark:text-white uppercase tracking-wide truncate">
                {seccion.titulo}
              </h4>
              <div className="hidden sm:block flex-1 h-px bg-gradient-to-r from-cyan-200 to-transparent dark:from-cyan-800" />
            </div>

            {/* Grid de campos de la sección - 1 col móvil, 2 col desktop */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 sm:gap-2.5">
              {seccion.campos.map((detalle, idx) => {
                const IconoCampo = obtenerIconoCampo(detalle.campo)
                const esVacio = esValorVacio(detalle.valorNuevo)

                return (
                  <div
                    key={idx}
                    className={`group relative overflow-hidden rounded-lg border transition-all ${
                      esVacio
                        ? 'bg-gray-50/50 dark:bg-gray-800/30 border-gray-200 dark:border-gray-700'
                        : 'bg-white dark:bg-gray-800/50 border-cyan-200 dark:border-cyan-800 hover:shadow-md hover:border-cyan-300 dark:hover:border-cyan-700'
                    }`}
                  >
                    <div className="flex items-start gap-2 p-2 sm:p-2.5">
                      {/* Icono del campo */}
                      <div
                        className={`flex-shrink-0 w-6 h-6 sm:w-7 sm:h-7 rounded-md flex items-center justify-center ${
                          esVacio
                            ? 'bg-gray-200 dark:bg-gray-700'
                            : 'bg-gradient-to-br from-cyan-100 to-blue-100 dark:from-cyan-900/40 dark:to-blue-900/40'
                        }`}
                      >
                        <IconoCampo
                          className={`w-3 h-3 sm:w-3.5 sm:h-3.5 ${
                            esVacio
                              ? 'text-gray-400 dark:text-gray-500'
                              : 'text-cyan-600 dark:text-cyan-400'
                          }`}
                        />
                      </div>

                      {/* Contenido */}
                      <div className="flex-1 min-w-0">
                        <p
                          className={`text-[8px] sm:text-[9px] font-bold uppercase tracking-wider mb-0.5 leading-tight ${
                            esVacio
                              ? 'text-gray-400 dark:text-gray-600'
                              : 'text-gray-500 dark:text-gray-400'
                          }`}
                        >
                          {detalle.etiqueta}
                        </p>
                        <p
                          className={`text-[11px] sm:text-xs font-semibold break-words leading-snug ${
                            esVacio
                              ? 'text-gray-400 dark:text-gray-600 italic'
                              : 'text-gray-900 dark:text-white'
                          }`}
                        >
                          {formatearValor(detalle.valorNuevo, detalle.tipo)}
                        </p>
                      </div>
                    </div>
                  </div>
                )
              })}
            </div>
          </div>
        ))}
      </div>

      {/* Nota informativa al final */}
      <div className="mt-3 sm:mt-4 p-2 sm:p-2.5 rounded-lg bg-gradient-to-br from-blue-50 to-cyan-50 dark:from-blue-950/30 dark:to-cyan-950/30 border border-blue-200 dark:border-blue-800">
        <p className="text-[9px] sm:text-[10px] text-blue-700 dark:text-blue-300 leading-relaxed">
          <span className="font-bold">ℹ️ Información de auditoría:</span> Registro completo con los datos iniciales del cliente. Los campos en gris no fueron completados durante la creación.
        </p>
      </div>
    </Modal>,
    document.body
  )
}

// ========== TIPOS DE SECCIONES ==========
interface SeccionDetalles {
  titulo: string
  icono: any
  campos: DetalleEvento[]
}

// ========== MAPEO DE ICONOS POR CAMPO ==========
function obtenerIconoCampo(campo: string) {
  const iconos: Record<string, unknown> = {
    // Información personal
    nombres: User,
    apellidos: User,
    tipo_documento: FileText,
    numero_documento: Hash,
    fecha_nacimiento: Calendar,
    estado_civil: Users,

    // Contacto
    telefono: Phone,
    telefono_alternativo: Phone,
    email: Mail,
    direccion: MapPin,
    ciudad: Building2,
    departamento: Home,

    // Interés
    proyecto_interes_inicial: Building2,
    vivienda_interes_inicial: Home,
    notas_interes: Heart,
    interes_inicial: Heart,

    // Adicional
    notas: MessageSquare,
    estado: FileText,
  }

  return iconos[campo] || FileText
}

// ========== AGRUPAR CAMPOS POR SECCIÓN ==========
function agruparPorSeccion(detalles: DetalleEvento[]): SeccionDetalles[] {
  const secciones: SeccionDetalles[] = []

  // Sección 1: Información Personal
  const camposPersonales = detalles.filter(d =>
    ['nombres', 'apellidos', 'tipo_documento', 'numero_documento', 'fecha_nacimiento', 'estado_civil'].includes(d.campo)
  )
  if (camposPersonales.length > 0) {
    secciones.push({
      titulo: 'Información Personal',
      icono: User,
      campos: camposPersonales,
    })
  }

  // Sección 2: Datos de Contacto
  const camposContacto = detalles.filter(d =>
    ['telefono', 'telefono_alternativo', 'email', 'direccion', 'ciudad', 'departamento'].includes(d.campo)
  )
  if (camposContacto.length > 0) {
    secciones.push({
      titulo: 'Datos de Contacto',
      icono: Phone,
      campos: camposContacto,
    })
  }

  // Sección 3: Interés en Proyecto/Vivienda
  const camposInteres = detalles.filter(d =>
    ['proyecto_interes_inicial', 'vivienda_interes_inicial', 'notas_interes', 'interes_inicial'].includes(d.campo)
  )
  if (camposInteres.length > 0) {
    secciones.push({
      titulo: 'Interés Inicial',
      icono: Heart,
      campos: camposInteres,
    })
  }

  // Sección 4: Información Adicional
  const camposAdicionales = detalles.filter(d =>
    ['notas', 'estado'].includes(d.campo)
  )
  if (camposAdicionales.length > 0) {
    secciones.push({
      titulo: 'Información Adicional',
      icono: MessageSquare,
      campos: camposAdicionales,
    })
  }

  return secciones
}

// ========== VERIFICAR SI UN VALOR ESTÁ VACÍO ==========
function esValorVacio(valor: any): boolean {
  if (valor === null || valor === undefined) return true

  const valorStr = String(valor).toLowerCase()
  return (
    valorStr === 'no diligenciado' ||
    valorStr === 'no especificado' ||
    valorStr === 'sin observaciones' ||
    valorStr === 'sin interés específico registrado' ||
    valorStr === 'sin proyecto específico' ||
    valorStr === 'sin vivienda específica' ||
    valorStr === '' ||
    valorStr === '—'
  )
}

// ========== FORMATEAR VALOR SEGÚN TIPO ==========
function formatearValor(valor: any, tipo?: string): string {
  if (valor === null || valor === undefined) return '—'

  switch (tipo) {
    case 'numero':
      return typeof valor === 'number'
        ? `$${valor.toLocaleString('es-CO')}`
        : String(valor)
    case 'fecha':
      return new Date(String(valor)).toLocaleDateString('es-CO', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
      })
    case 'booleano':
      return valor ? 'Sí' : 'No'
    default:
      return String(valor)
  }
}

'use client'

/**
 * ✅ COMPONENTE PRESENTACIONAL PURO
 * Tab de Documentos - Refactorizado
 *
 * SEPARACIÓN DE RESPONSABILIDADES:
 * - TODA la lógica está en useDocumentosTab hook
 * - Este componente SOLO renderiza UI
 */

import { useEffect, useState } from 'react'

import { AnimatePresence } from 'framer-motion'
import { ArrowLeft, FileText, FolderCog, IdCard, Upload } from 'lucide-react'

import { useRouter } from 'next/navigation'

import { useAuth } from '@/contexts/auth-context'
import { SeccionDocumentosPendientes } from '@/modules/clientes/components/documentos-pendientes'
import { SubirCartaModal } from '@/modules/clientes/components/fuentes-pago'
import { BannerDocumentoRequerido } from '@/modules/clientes/documentos/components/BannerDocumentoRequerido'
import { useDocumentosTab } from '@/modules/clientes/hooks'
import { useCategoriasSistemaClientes } from '@/modules/clientes/hooks/useCategoriasSistemaClientes'
import type { Cliente } from '@/modules/clientes/types'
import { CategoriasManager } from '@/modules/documentos/components/categorias/categorias-manager'
import { DocumentosLista } from '@/modules/documentos/components/lista/documentos-lista'
import { DocumentoUpload } from '@/modules/documentos/components/upload/documento-upload'
import { moduleThemes } from '@/shared/config/module-themes'

interface DocumentosTabProps {
  cliente: Cliente
}

export function DocumentosTab({ cliente }: DocumentosTabProps) {
  const router = useRouter()
  const { user } = useAuth()

  // Tema cyan/azul para clientes
  const theme = moduleThemes.clientes

  // ✅ AUTO-SEED: Verificar y crear categorías del sistema
  const { verificarYCrear } = useCategoriasSistemaClientes()

  useEffect(() => {
    verificarYCrear()
  }, [verificarYCrear])

  // Estado para modal de carta de aprobación
  const [modalCartaOpen, setModalCartaOpen] = useState(false)
  const [fuenteParaCarta, setFuenteParaCarta] = useState<{
    id: string
    tipo: string
    entidad?: string
    monto_aprobado: number
    tipo_documento_sistema?: string
    requisito_config_id?: string
    vivienda?: { numero: string; manzana: string }
    cliente?: { nombre_completo: string }
  } | null>(null)

  // ✅ Hook con TODA la lógica
  const {
    vistaActual,
    tieneCedula,
    cargandoValidacion,
    uploadTipoCedula,
    metadataPendiente,
    mostrandoUpload,
    mostrandoCategorias,
    mostrandoDocumentos,
    mostrarUpload,
    mostrarCategorias,
    volverADocumentos,
    onSuccessUpload,
    onCancelUpload,
  } = useDocumentosTab({ clienteId: cliente.id })

  // Si está mostrando categorías (PATRÓN IGUAL A PROYECTOS)
  if (mostrandoCategorias && user) {
    return (
      <div className='space-y-4'>
        {/* Header con botón volver */}
        <div className={`rounded-lg border ${theme.classes.border.light} bg-white p-4 shadow-sm dark:bg-gray-800`}>
          <div className='mb-4 flex items-center gap-2.5'>
            <button
              onClick={volverADocumentos}
              className={`flex items-center gap-1.5 rounded-lg ${theme.classes.button.secondary} px-3 py-1.5 text-xs font-medium transition-colors`}
            >
              <ArrowLeft className='h-3.5 w-3.5' />
              <span>Volver a Documentos</span>
            </button>
          </div>

          <h2 className='text-xl font-bold text-gray-900 dark:text-white'>
            Gestionar Categorías
          </h2>
          <p className='mt-1.5 text-xs text-gray-500 dark:text-gray-400'>
            Organiza los documentos del cliente con categorías personalizadas
          </p>
        </div>

        {/* Gestor de categorías */}
        <div className='rounded-lg border border-gray-200 bg-white p-4 shadow-sm dark:border-gray-800 dark:bg-gray-800'>
          <CategoriasManager
            userId={user.id}
            onClose={volverADocumentos}
            modulo="clientes"
          />
        </div>
      </div>
    )
  }

  // Si está mostrando formulario de upload (PATRÓN IGUAL A PROYECTOS)
  if (mostrandoUpload && user) {
    return (
      <div className='space-y-3'>
        {/* Header premium compacto con glassmorphism */}
        <div className="relative overflow-hidden rounded-xl bg-gradient-to-br from-cyan-600 via-blue-600 to-indigo-600 dark:from-cyan-700 dark:via-blue-700 dark:to-indigo-800 p-4 shadow-xl shadow-cyan-500/20">
          <div className="absolute inset-0 bg-grid-white/10 [mask-image:linear-gradient(0deg,transparent,black,transparent)]" />
          <div className="relative z-10">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2.5">
                <div className="w-10 h-10 rounded-lg bg-white/20 backdrop-blur-sm flex items-center justify-center">
                  <IdCard className="w-5 h-5 text-white" />
                </div>
                <div>
                  <h2 className='text-lg font-bold text-white'>
                    {uploadTipoCedula ? 'Subir Documento de Identidad' : 'Subir Documento'}
                  </h2>
                  <p className='text-cyan-100 dark:text-cyan-200 text-xs'>
                    {uploadTipoCedula
                      ? 'Sube la cédula o pasaporte oficial del cliente'
                      : 'Completa la información y selecciona el archivo a subir'}
                  </p>
                </div>
              </div>

              {/* Botón volver a la derecha */}
              <button
                onClick={volverADocumentos}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-white/20 backdrop-blur-md border border-white/30 text-white text-xs font-medium hover:bg-white/30 transition-all"
              >
                <ArrowLeft className='h-3.5 w-3.5' />
                <span>Volver</span>
              </button>
            </div>
          </div>
        </div>

        <div className={`rounded-lg border ${theme.classes.border.light} bg-white p-3 shadow-sm dark:bg-gray-800`}>
          <DocumentoUpload
            entidadId={cliente.id}
            tipoEntidad="cliente"
            moduleName="clientes"
            metadata={metadataPendiente}
            onSuccess={onSuccessUpload}
            onCancel={onCancelUpload}
          />
        </div>
      </div>
    )
  }

  return (
    <div className='space-y-4'>
      {/* Header con acciones - PREMIUM GLASSMORPHISM */}
      <div className={`relative overflow-hidden rounded-xl backdrop-blur-xl bg-gradient-to-br from-cyan-50/80 via-blue-50/80 to-indigo-50/80 dark:from-cyan-950/50 dark:via-blue-950/50 dark:to-indigo-950/50 border ${theme.classes.border.light} p-4 shadow-2xl shadow-cyan-500/10 dark:shadow-cyan-500/5`}>
        {/* Pattern overlay */}
        <div className="absolute inset-0 bg-grid-white/10 [mask-image:linear-gradient(0deg,transparent,black,transparent)] pointer-events-none" />

        <div className='relative z-10 flex items-center justify-between'>
          <div className='flex items-center gap-3'>
            <div className={`rounded-xl bg-gradient-to-br ${theme.classes.gradient.primary} p-2.5 shadow-lg shadow-cyan-500/30`}>
              <FileText className='h-5 w-5 text-white' />
            </div>
            <div>
              <h2 className='text-base font-bold bg-gradient-to-br from-cyan-600 via-blue-600 to-indigo-600 dark:from-cyan-400 dark:via-blue-400 dark:to-indigo-400 bg-clip-text text-transparent'>
                Documentos del Cliente
              </h2>
              <p className='text-xs text-cyan-700 dark:text-cyan-300 font-medium'>
                Gestiona cédula, contratos y documentación legal
              </p>
            </div>
          </div>

          <div className='flex gap-2'>
            {/* Botón especial para subir cédula si no existe - DESTACADO */}
            {!tieneCedula && (
              <button
                onClick={() => mostrarUpload(true)}
                className='group flex items-center gap-2 rounded-lg bg-gradient-to-r from-orange-500 to-amber-500 px-4 py-2 text-sm font-semibold text-white shadow-lg shadow-orange-500/50 hover:shadow-2xl hover:shadow-orange-500/60 ring-2 ring-orange-300/50 dark:ring-orange-700/50 ring-offset-2 dark:ring-offset-gray-900 transition-all hover:from-orange-600 hover:to-amber-600 hover:scale-[1.02] active:scale-[0.98]'
              >
                <IdCard className='h-4 w-4 group-hover:rotate-12 transition-transform' />
                <span>Subir Cédula/Pasaporte</span>
              </button>
            )}

            <button
              onClick={mostrarCategorias}
              className={`group flex items-center gap-1.5 rounded-lg backdrop-blur-sm bg-white/60 dark:bg-gray-800/60 hover:bg-white/80 dark:hover:bg-gray-800/80 border ${theme.classes.border.light} px-3 py-1.5 text-xs font-medium transition-all hover:shadow-lg hover:scale-[1.02] active:scale-[0.98]`}
            >
              <FolderCog className='h-3.5 w-3.5 text-cyan-600 dark:text-cyan-400 group-hover:rotate-12 transition-transform' />
              <span className='text-gray-700 dark:text-gray-300'>Categorías</span>
            </button>
            {/* Botón genérico - primario si tiene cédula, secundario si no */}
            <button
              onClick={() => mostrarUpload(false)}
              className={`group flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-xs font-medium transition-all hover:scale-[1.02] active:scale-[0.98] ${
                tieneCedula
                  ? `bg-gradient-to-r ${theme.classes.gradient.primary} text-white shadow-lg shadow-cyan-500/30 hover:shadow-xl hover:shadow-cyan-500/40`
                  : 'backdrop-blur-sm bg-white/60 dark:bg-gray-800/60 hover:bg-white/80 dark:hover:bg-gray-800/80 border border-gray-300 dark:border-gray-600 text-gray-600 dark:text-gray-400 hover:shadow-lg'
              }`}
            >
              <Upload className='h-3.5 w-3.5 group-hover:-translate-y-0.5 transition-transform' />
              <span>{tieneCedula ? 'Subir Documento' : 'Otros documentos'}</span>
            </button>
          </div>
        </div>
      </div>

      {/* 🚨 Banner informativo cuando no hay documento de identidad */}
      <AnimatePresence>
        {!tieneCedula && !cargandoValidacion && (() => {
          // Si ya tiene negociación activa (vivienda asignada), mostrar advertencia suave
          const tieneNegociacion = (cliente.estadisticas?.negociaciones_activas ?? 0) > 0
          return (
            <BannerDocumentoRequerido
              variant={tieneNegociacion ? 'advertencia' : 'bloqueante'}
            />
          )
        })()}
      </AnimatePresence>

      {/* 📄 Sección de documentos pendientes de fuentes (colapsable) */}
      <SeccionDocumentosPendientes
        clienteId={cliente.id}
        onSubirDocumento={(pendienteId, tipoDocumento, metadata) => {
          // ✅ Solo abrir SubirCartaModal para cartas de aprobación específicas
          const esCarta = tipoDocumento.toLowerCase().includes('carta de aprobaci')
          if (metadata.fuente_pago_id && esCarta) {
            setFuenteParaCarta({
              id: metadata.fuente_pago_id,
              tipo: metadata.tipo_fuente,
              // ✅ La vista usa 'entidad_fuente', no 'entidad'
              entidad: metadata.entidad_fuente,
              monto_aprobado: metadata.monto_aprobado || 0,
              // ✅ Pasar tipo exacto del doc para que la vista haga match al subir
              tipo_documento_sistema: tipoDocumento,
              // ✅ FK al requisito: documentos-base.service lo guarda → vista lo detecta por UUID
              requisito_config_id: metadata.requisito_config_id,
              vivienda: metadata.vivienda,
              cliente: metadata.cliente,
            })
            setModalCartaOpen(true)
          } else {
            // Para otros documentos (Solicitud Desembolso, Boleta de Registro, etc.)
            mostrarUpload(false, metadata)
          }
        }}
      />

      {/* ✅ Lista de documentos - Componente genérico estándar */}
      <DocumentosLista
        entidadId={cliente.id}
        tipoEntidad="cliente"
        moduleName="clientes"
        defaultVista="lista"
        onUploadClick={() => mostrarUpload(false)}
      />

      {/* Modal de subir carta de aprobación */}
      {fuenteParaCarta && (
        <SubirCartaModal
          isOpen={modalCartaOpen}
          onClose={() => {
            setModalCartaOpen(false)
            setFuenteParaCarta(null)
          }}
          fuente={fuenteParaCarta}
          clienteId={cliente.id}
          onSuccess={() => {
            // Refrescar documentos
            onSuccessUpload()
          }}
        />
      )}
    </div>
  )
}

/**
 * ============================================
 * COMPONENTE PRESENTACIONAL PURO: FuentesPagoTab
 * ============================================
 *
 * ✅ SEPARACIÓN ESTRICTA DE RESPONSABILIDADES
 * - Componente: SOLO UI presentacional
 * - Hook: TODA la lógica (useFuentesPagoTab)
 *
 * Pestaña dedicada para gestión de fuentes de pago del cliente.
 * Permite visualizar, editar y validar las fuentes configuradas
 * para una vivienda asignada.
 *
 * IMPORTANTE: Esta pestaña NO registra abonos.
 * Los abonos se gestionan desde el módulo dedicado de Abonos.
 *
 * Funcionalidades:
 * - Dashboard de métricas
 * - Validación de configuración
 * - Edición de fuentes individuales
 * - Enlaces contextuales a otros módulos
 * - Guía paso a paso para completar configuración
 *
 * @version 1.0.0 - 2025-12-17 - Implementación inicial
 */

'use client'

import { AnimatePresence, motion } from 'framer-motion'
import {
    AlertCircle,
    DollarSign,
    Home,
    Info,
    Lightbulb,
    ListChecks,
    Loader2,
    RefreshCw,
    X
} from 'lucide-react'

import type { Cliente } from '@/modules/clientes/types'

import {
    AccionesRapidas,
    EstadoValidacionComponent,
    ListaFuentes,
    MetricasDashboard
} from './fuentes-pago/components'
import { useFuentesPagoTab } from './fuentes-pago/hooks/useFuentesPagoTab'
import { fuentesPagoTabStyles as styles } from './fuentes-pago-tab.styles'

// ============================================
// INTERFACES
// ============================================

interface FuentesPagoTabProps {
  cliente: Cliente
}

// ============================================
// COMPONENTE PRINCIPAL - SOLO UI
// ============================================

export function FuentesPagoTab({ cliente }: FuentesPagoTabProps) {
  // ✅ Hook con TODA la lógica
  const {
    // Estado
    negociacion,
    fuentesPago,
    metricas,
    estadoValidacion,
    isLoading,
    isUpdating,
    error,

    // Business Logic Functions (del hook)
    getTipoConfig,
    getDocumentacionEstado,
    calcularProgreso,
    getEstadoStyles,
    getProgressStyles,
    tiposDisponibles,

    // Lógica de fuentes disponibles
    todasFuentesCreadas,
    mensajeBotonDeshabilitado,

    // Handlers
    handleEditarFuente,
    handleGuardarFuente,
    handleAgregarFuente,
    handleEliminarFuente,
    handleVerHistorial,
    handleVerValidacion,
    handleNavegar,
    refetchFuentes,
  } = useFuentesPagoTab({ cliente })

  // =====================================================
  // RENDER: Loading State
  // =====================================================

  if (isLoading) {
    return (
      <motion.div
        className="flex flex-col items-center justify-center py-12"
        {...styles.animations.fadeInUp}
      >
        <motion.div
          className={`w-12 h-12 rounded-xl ${styles.theme.bg} flex items-center justify-center shadow-lg mb-4`}
          animate={{
            rotate: [0, 360],
            scale: [1, 1.1, 1]
          }}
          transition={{
            rotate: { duration: 2, repeat: Infinity, ease: 'linear' },
            scale: { duration: 1.5, repeat: Infinity, ease: 'easeInOut' }
          }}
        >
          <Loader2 className="w-6 h-6 text-white" />
        </motion.div>

        <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
          Cargando Fuentes de Pago
        </h3>

        <p className="text-sm text-gray-600 dark:text-gray-400 text-center max-w-sm">
          Obteniendo información de la vivienda asignada y configuración de fuentes de pago...
        </p>
      </motion.div>
    )
  }

  // =====================================================
  // RENDER: Error State
  // =====================================================

  if (error) {
    return (
      <motion.div
        className="flex flex-col items-center justify-center py-12"
        {...styles.animations.fadeInUp}
      >
        <motion.div
          className="w-12 h-12 rounded-xl bg-red-500 flex items-center justify-center shadow-lg mb-4"
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          transition={{ type: 'spring', stiffness: 200 }}
        >
          <AlertCircle className="w-6 h-6 text-white" />
        </motion.div>

        <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
          Error al Cargar Fuentes
        </h3>

        <p className="text-sm text-gray-600 dark:text-gray-400 text-center max-w-sm mb-4">
          No pudimos obtener la información de las fuentes de pago.
          Por favor, inténtalo nuevamente.
        </p>

        <motion.button
          onClick={() => refetchFuentes()}
          className={styles.header.actionButton}
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
        >
          <RefreshCw className="w-4 h-4" />
          Reintentar
        </motion.button>
      </motion.div>
    )
  }

  // =====================================================
  // RENDER: Sin Vivienda Asignada
  // =====================================================

  if (!negociacion) {
    return (
      <motion.div
        className={styles.emptyState.container}
        {...styles.animations.fadeInUp}
      >
        {/* Icono con gradiente */}
        <div className="flex justify-center">
          <motion.div
            className={styles.emptyState.iconWrapper}
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ type: 'spring', stiffness: 200 }}
          >
            <Home className={styles.emptyState.icon} />
          </motion.div>
        </div>

        {/* Título y descripción */}
        <h3 className={styles.emptyState.title}>
          Sin Vivienda Asignada
        </h3>
        <p className={styles.emptyState.description}>
          Las fuentes de pago se configuran una vez que el cliente tiene asignada
          una vivienda específica dentro de un proyecto.
        </p>

        {/* Checklist de requisitos */}
        <div className={styles.emptyState.checklistContainer}>
          <div className={styles.emptyState.checklistHeader}>
            <ListChecks className="w-4 h-4" />
            Requisitos previos
          </div>

          <div className={styles.emptyState.checklistItems}>
            <div className={styles.emptyState.checklistItem}>
              <div className="w-5 h-5 rounded-full bg-red-100 dark:bg-red-900/30 flex items-center justify-center flex-shrink-0 mt-0.5">
                <X className="w-3 h-3 text-red-600 dark:text-red-400" />
              </div>
              <div className="flex-1 min-w-0">
                <p className={styles.emptyState.checklistTextPending}>
                  Cliente debe tener una vivienda asignada
                </p>
              </div>
            </div>
          </div>
        </div>

        {/* Call to Action */}
        <div className={styles.emptyState.ctaContainer}>
          <div className={styles.emptyState.ctaInfo}>
            <Lightbulb className={styles.emptyState.ctaIcon} />
            <div className="flex-1">
              <h4 className={styles.emptyState.ctaTitle}>
                ¿Cómo continuar?
              </h4>
              <p className={styles.emptyState.ctaDescription}>
                Ve a la pestaña "Vivienda Asignada" para ver las instrucciones completas
                sobre cómo asignar una vivienda a este cliente.
              </p>
            </div>
          </div>

          <button
            onClick={() => {
              // Buscar tab con data-tab="vivienda-asignada" y hacer click
              const tabButton = document.querySelector('[data-tab="vivienda-asignada"]')
              if (tabButton instanceof HTMLElement) {
                tabButton.click()
              }
            }}
            className={styles.emptyState.ctaButton}
          >
            <Home className="w-4 h-4" />
            Ver Instrucciones
          </button>
        </div>

        {/* Footer informativo */}
        <div className={styles.emptyState.footerInfo}>
          <Info className={styles.emptyState.footerIcon} />
          <p className={styles.emptyState.footerText}>
            Las fuentes de pago incluyen cuotas iniciales, créditos hipotecarios y subsidios
            que se vincularán al valor de la vivienda asignada.
          </p>
        </div>
      </motion.div>
    )
  }

  // =====================================================
  // RENDER: Contenido Principal
  // =====================================================

  return (
    <AnimatePresence mode="wait">
      <motion.div
        key="fuentes-pago-content"
        className={styles.container.main}
        variants={styles.animations.staggerChildren}
        initial="initial"
        animate="animate"
      >
        {/* Header con información contextual */}
        <motion.div
          className={styles.header.container}
          variants={styles.animations.fadeInUp}
        >
          <div className={styles.header.content}>
            <div className={styles.header.leftSection}>
              <div className={styles.header.iconContainer}>
                <DollarSign className={styles.header.icon} />
              </div>

              <div className={styles.header.titleSection}>
                <h2 className={styles.header.title}>
                  Fuentes de Pago
                </h2>
                <p className={styles.header.subtitle}>
                  {(negociacion.viviendas as any)?.manzanas?.proyectos?.nombre} •
                  Mza. {(negociacion.viviendas as any)?.manzanas?.nombre}
                  Casa {negociacion.viviendas?.numero}
                </p>
              </div>
            </div>

            <div className={styles.header.rightSection}>
              {isUpdating && (
                <motion.div
                  className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-blue-100 dark:bg-blue-900/30 border border-blue-200 dark:border-blue-700"
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.8 }}
                >
                  <Loader2 className="w-3 h-3 text-blue-600 dark:text-blue-400 animate-spin" />
                  <span className="text-xs text-blue-700 dark:text-blue-300 font-medium">
                    Actualizando...
                  </span>
                </motion.div>
              )}

              <motion.button
                onClick={handleVerHistorial}
                className={styles.header.secondaryButton}
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
              >
                Ver Historial
              </motion.button>
            </div>
          </div>
        </motion.div>

        {/* Métricas Dashboard */}
        <MetricasDashboard metricas={metricas} />

        {/* Estado de Validación */}
        <EstadoValidacionComponent
          estadoValidacion={estadoValidacion}
          onNavegar={handleNavegar}
          onVerDetalle={handleVerValidacion}
        />

        {/* Lista de Fuentes Configuradas */}
        <ListaFuentes
          fuentesPago={fuentesPago as any}
          onEditarFuente={handleEditarFuente}
          onEliminarFuente={handleEliminarFuente}
          onAgregarFuente={handleAgregarFuente}
          // ✅ Funciones procesadas del hook (LÓGICA SEPARADA)
          getTipoConfig={getTipoConfig}
          getDocumentacionEstado={getDocumentacionEstado}
          calcularProgreso={calcularProgreso}
          getEstadoStyles={getEstadoStyles}
          getProgressStyles={getProgressStyles}
          tiposDisponibles={tiposDisponibles as any}
          todasFuentesCreadas={todasFuentesCreadas}
          mensajeBotonDeshabilitado={mensajeBotonDeshabilitado}
        />

        {/* Acciones Rápidas - Enlaces Contextuales */}
        <AccionesRapidas
          onNavegar={handleNavegar}
          fuentesSinDocumentacion={metricas.fuentesSinDocumentacion}
          puedeRegistrarAbonos={estadoValidacion.puedeRegistrarAbonos}
        />

        {/* Información contextual al pie */}
        <motion.div
          className={`${styles.container.card} p-4`}
          variants={styles.animations.fadeInUp}
        >
          <div className="text-center space-y-2">
            <p className="text-xs text-gray-500 dark:text-gray-500">
              💡 <strong>Recuerda:</strong> Las fuentes de pago definen cómo el cliente
              cubrirá el valor total de la vivienda. Una vez configuradas y documentadas,
              podrás registrar los abonos correspondientes en el módulo de Abonos.
            </p>

            <p className="text-xs text-gray-400 dark:text-gray-600">
              ℹ️ Cada fuente requiere documentación de respaldo antes de habilitar
              el registro de desembolsos.
            </p>
          </div>
        </motion.div>
      </motion.div>
    </AnimatePresence>
  )
}

/**
 * ============================================
 * COMPONENTE: Estado de Validación
 * ============================================
 *
 * Muestra el estado actual de validación de las fuentes de pago
 * con mensajes contextuales y acciones sugeridas.
 */

import { motion } from 'framer-motion'
import {
    AlertTriangle,
    ArrowRight,
    Calculator,
    CheckCircle,
    FileText,
    XCircle
} from 'lucide-react'

import { fuentesPagoTabStyles as styles } from '../../fuentes-pago-tab.styles'
import type { EstadoValidacion } from '../hooks/useFuentesPagoTab'

interface EstadoValidacionProps {
  estadoValidacion: EstadoValidacion
  onNavegar: (destino: 'documentos' | 'abonos') => void
  onVerDetalle: () => void
}

export function EstadoValidacionComponent({
  estadoValidacion,
  onNavegar,
  onVerDetalle
}: EstadoValidacionProps) {
  const {
    tieneFuentes,
    sumaCuadra,
    todasConDocumentacion,
    puedeRegistrarAbonos,
    mensajesValidacion
  } = estadoValidacion

  // Determinar icono y título principal
  const getMainStatus = () => {
    if (puedeRegistrarAbonos) {
      return {
        icon: CheckCircle,
        iconClass: styles.validacion.iconSuccess,
        title: '✅ Todo Listo para Abonos',
        titleClass: 'text-green-700 dark:text-green-300',
      }
    }

    if (!tieneFuentes) {
      return {
        icon: XCircle,
        iconClass: styles.validacion.iconDanger,
        title: '❌ Sin Fuentes Configuradas',
        titleClass: 'text-red-700 dark:text-red-300',
      }
    }

    return {
      icon: AlertTriangle,
      iconClass: styles.validacion.iconWarning,
      title: '⚠️ Configuración Pendiente',
      titleClass: 'text-orange-700 dark:text-orange-300',
    }
  }

  const mainStatus = getMainStatus()

  return (
    <motion.div
      className={styles.validacion.container}
      {...styles.animations.fadeInUp}
    >
      {/* Header con estado principal */}
      <div className={styles.validacion.header}>
        <mainStatus.icon className={mainStatus.iconClass} />
        <h3 className={`${styles.validacion.title} ${mainStatus.titleClass}`}>
          {mainStatus.title}
        </h3>
      </div>

      {/* Mensajes de validación */}
      {mensajesValidacion.length > 0 && (
        <div className={styles.validacion.mensajes}>
          {mensajesValidacion.map((mensaje, index) => {
            const isWarning = mensaje.includes('⚠️') || mensaje.includes('💰') || mensaje.includes('📄')
            const isDanger = mensaje.includes('❌')

            const messageClass = isDanger
              ? styles.validacion.mensajeDanger
              : isWarning
                ? styles.validacion.mensajeWarning
                : styles.validacion.mensajeSuccess

            return (
              <motion.div
                key={index}
                className={messageClass}
                initial={{ opacity: 0, x: -10 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: index * 0.1 }}
              >
                <ArrowRight className="w-3 h-3 flex-shrink-0 mt-0.5" />
                <span>{mensaje}</span>
              </motion.div>
            )
          })}
        </div>
      )}

      {/* Acciones contextuales */}
      {!puedeRegistrarAbonos && (
        <div className={styles.validacion.acciones}>
          {!todasConDocumentacion && (
            <motion.button
              onClick={() => onNavegar('documentos')}
              className={styles.header.secondaryButton}
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
            >
              <FileText className="w-4 h-4" />
              <span>Gestionar Documentos</span>
            </motion.button>
          )}

          <motion.button
            onClick={onVerDetalle}
            className={styles.header.secondaryButton}
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
          >
            <Calculator className="w-4 h-4" />
            <span>Ver Detalle</span>
          </motion.button>
        </div>
      )}

      {/* CTA principal cuando todo esté listo */}
      {puedeRegistrarAbonos && (
        <div className={styles.validacion.acciones}>
          <motion.button
            onClick={() => onNavegar('abonos')}
            className={styles.header.actionButton}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            <ArrowRight className="w-4 h-4" />
            <span>Ir al Módulo de Abonos</span>
          </motion.button>
        </div>
      )}
    </motion.div>
  )
}

/**
 * ============================================
 * COMPONENTE: Lista de Fuentes
 * ============================================
 *
 * Lista todas las fuentes de pago configuradas con
 * información detallada y acciones contextuales.
 */

import { useEffect, useState } from 'react'

import { motion } from 'framer-motion'
import {
    AlertCircle,
    CheckCircle,
    DollarSign,
    Edit,
    FileText,
    FileX,
    MoreVertical,
    Plus,
    Trash2
} from 'lucide-react'

import { logger } from '@/lib/utils/logger'
import type { FuentePago, TipoFuentePago } from '@/modules/clientes/types/fuentes-pago'
import { esCuotaInicial } from '@/shared/constants/fuentes-pago.constants'
import { formatCurrency } from '@/shared/utils/format'

import { fuentesPagoTabStyles as styles } from '../../fuentes-pago-tab.styles'

interface ListaFuentesProps {
  fuentesPago: FuentePago[]
  onEditarFuente: (fuente: FuentePago) => void
  onEliminarFuente: (id: string) => void
  onAgregarFuente: (tipo: TipoFuentePago) => void
  // Funciones del hook (lógica procesada)
  getTipoConfig: (tipo: TipoFuentePago) => {
    icon: React.ComponentType<any>
    styles: string
    iconStyles: string
  }
  getDocumentacionEstado: (fuente: FuentePago) => {
    estado: 'pendiente' | 'completo' | 'parcial' | 'no_requerido'
    mensaje: string
    detalle?: string
    documentos?: {
      total: number
      subidos: number
      pendientes: number
      obligatoriosPendientes: number
      lista?: any[]
    }
  }
  calcularProgreso: (fuente: FuentePago) => number
  getEstadoStyles: (estado: string) => string
  getProgressStyles: (porcentaje: number) => string
  tiposDisponibles: TipoFuentePago[]
  todasFuentesCreadas: boolean
  mensajeBotonDeshabilitado?: string
}

export function ListaFuentes({
  fuentesPago,
  onEditarFuente,
  onEliminarFuente,
  onAgregarFuente,
  // Funciones procesadas del hook
  getTipoConfig,
  getDocumentacionEstado,
  calcularProgreso,
  getEstadoStyles,
  getProgressStyles,
  tiposDisponibles,
  todasFuentesCreadas,
  mensajeBotonDeshabilitado
}: ListaFuentesProps) {

  // ============================================
  // STATE LOCAL (SOLO UI)
  // ============================================

  const [dropdownAbierto, setDropdownAbierto] = useState<string | null>(null)
  const [documentosExpandidos, setDocumentosExpandidos] = useState<Set<string>>(new Set())

  const toggleDropdown = (fuenteId: string, event: React.MouseEvent) => {
    event.preventDefault()
    event.stopPropagation()
    setDropdownAbierto(dropdownAbierto === fuenteId ? null : fuenteId)
  }

  const toggleDocumentos = (fuenteId: string) => {
    setDocumentosExpandidos(prev => {
      const newSet = new Set(prev)
      if (newSet.has(fuenteId)) {
        newSet.delete(fuenteId)
      } else {
        newSet.add(fuenteId)
      }
      return newSet
    })
  }

  const cerrarDropdown = () => {
    setDropdownAbierto(null)
  }

  // Cerrar dropdown al hacer click fuera
  useEffect(() => {
    const handleClickOutside = () => {
      if (dropdownAbierto) {
        setDropdownAbierto(null)
      }
    }

    if (dropdownAbierto) {
      document.addEventListener('click', handleClickOutside)
      return () => document.removeEventListener('click', handleClickOutside)
    }
  }, [dropdownAbierto])

  // ============================================
  // COMPONENTE PRESENTACIONAL PURO
  // ============================================

  return (
    <motion.div
      className={styles.fuentesList.container}
      {...styles.animations.fadeInUp}
    >
      {/* Header */}
      <div className={styles.fuentesList.header}>
        <h3 className={styles.fuentesList.headerTitle}>
          <DollarSign className={styles.fuentesList.headerIcon} />
          Fuentes de Pago Configuradas ({fuentesPago.length})
        </h3>

        {/* Botón Agregar Fuente con estado dinámico */}
        <div className="relative group">
          <button
            disabled={todasFuentesCreadas || tiposDisponibles.length === 0}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg shadow-md transition-all duration-200 text-sm font-medium ${
              todasFuentesCreadas || tiposDisponibles.length === 0
                ? 'bg-gray-300 dark:bg-gray-600 text-gray-500 dark:text-gray-400 cursor-not-allowed'
                : 'bg-gradient-to-r from-blue-500 to-blue-600 hover:from-blue-600 hover:to-blue-700 text-white hover:shadow-lg cursor-pointer'
            }`}
          >
            <Plus className="w-4 h-4" />
            <span>Agregar Fuente</span>
          </button>

          {/* Tooltip cuando está deshabilitado */}
          {todasFuentesCreadas && mensajeBotonDeshabilitado && (
            <div className="absolute bottom-full mb-2 left-1/2 transform -translate-x-1/2 bg-gray-900 text-white text-xs rounded-lg px-3 py-2 whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity duration-200 z-50 shadow-xl max-w-xs text-center">
              <div>
                <p className="font-semibold">✅ Configuración Completa</p>
                <p className="text-gray-300 mt-1">{mensajeBotonDeshabilitado}</p>
              </div>
              <div className="absolute top-full left-1/2 transform -translate-x-1/2 border-4 border-transparent border-t-gray-900"></div>
            </div>
          )}

          {/* Dropdown para tipos disponibles (solo si hay tipos disponibles) */}
          {!todasFuentesCreadas && tiposDisponibles.length > 0 && (
            <div className="absolute right-0 top-full mt-1 w-56 bg-white dark:bg-gray-800 rounded-lg shadow-xl border border-gray-200 dark:border-gray-700 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 z-10">
              <div className="p-1">
                <div className="px-3 py-2 text-xs text-gray-500 dark:text-gray-400 font-medium border-b border-gray-200 dark:border-gray-700">
                  Tipos disponibles:
                </div>
                {tiposDisponibles.map((tipoConfig: any) => (
                  <button
                    key={tipoConfig.id}
                    onClick={() => onAgregarFuente(tipoConfig.nombre as TipoFuentePago)}
                    className="w-full text-left px-3 py-2 text-sm rounded-md transition-all text-gray-700 dark:text-gray-300 hover:bg-blue-50 dark:hover:bg-blue-900/30"
                  >
                    ✨ {tipoConfig.nombre}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Lista de fuentes */}
      {fuentesPago.length > 0 ? (
        <motion.div
          className={styles.fuentesList.lista}
          variants={styles.animations.staggerChildren}
          initial="initial"
          animate="animate"
        >
          {fuentesPago.map((fuente, index) => {
            const tipoConfig = getTipoConfig(fuente.tipo)
            const progreso = calcularProgreso(fuente)
            const saldoPendiente = fuente.monto_aprobado - (fuente.monto_recibido || 0)

            return (
              <motion.div
                key={fuente.id}
                className="relative overflow-hidden rounded-xl backdrop-blur-xl bg-white/80 dark:bg-gray-800/80 border border-gray-200/50 dark:border-gray-700/50 p-3 shadow-lg hover:shadow-xl transition-all duration-200"
                variants={styles.animations.fadeInUp}
                transition={{ delay: index * 0.1 }}
                onClick={cerrarDropdown}
              >
                {/* Header Compacto */}
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2.5">
                    {/* Ícono Tipo */}
                    <div className={`w-8 h-8 rounded-lg ${tipoConfig.styles} flex items-center justify-center shadow-md`}>
                      <tipoConfig.icon className={`w-4 h-4 ${tipoConfig.iconStyles}`} />
                    </div>

                    {/* Info Principal */}
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-bold text-gray-900 dark:text-white truncate">
                        {fuente.tipo}
                      </p>
                      {fuente.entidad && (
                        <p className="text-xs text-gray-600 dark:text-gray-400 truncate">
                          {fuente.entidad}
                        </p>
                      )}
                    </div>
                  </div>

                  {/* Documentación y Menú */}
                  <div className="flex items-center gap-1.5">
                    {/* Badge Documentación - CLARO Y DESCRIPTIVO */}
                    {(() => {
                      const docEstado = getDocumentacionEstado(fuente)

                      // Estado: Sin documentos subidos
                      if (docEstado.estado === 'pendiente') {
                        const tieneDocs = (docEstado.documentos?.total ?? 0) > 0
                        return (
                          <div
                            className="flex items-center gap-1 px-2 py-1 rounded-md bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800"
                            title={`📄 Documentación Pendiente\n\n${docEstado.mensaje}\n\nRequeridos: ${docEstado.documentos?.total || 0}\nSubidos: 0\n\n💡 Sube los documentos obligatorios en la pestaña Documentos`}
                          >
                            <FileX className="w-3 h-3 text-red-600 dark:text-red-400" />
                            <span className="text-xs text-red-700 dark:text-red-300 font-medium">
                              {tieneDocs ? `0/${docEstado.documentos?.total} Docs` : 'Sin Requisitos'}
                            </span>
                          </div>
                        )
                      }

                      // Estado: Algunos documentos subidos
                      if (docEstado.estado === 'parcial') {
                        return (
                          <div
                            className="flex items-center gap-1 px-2 py-1 rounded-md bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800"
                            title={`📄 Documentación Incompleta\n\n${docEstado.mensaje}\n\nRequeridos: ${docEstado.documentos?.total}\nSubidos: ${docEstado.documentos?.subidos}\nPendientes: ${docEstado.documentos?.pendientes}\n\n⚠️ Faltan documentos obligatorios`}
                          >
                            <AlertCircle className="w-3 h-3 text-yellow-600 dark:text-yellow-400" />
                            <span className="text-xs text-yellow-700 dark:text-yellow-300 font-medium">
                              {docEstado.documentos?.subidos}/{docEstado.documentos?.total} Docs
                            </span>
                          </div>
                        )
                      }

                      // Estado: Todos los documentos subidos
                      if (docEstado.estado === 'completo') {
                        return (
                          <div
                            className="flex items-center gap-1 px-2 py-1 rounded-md bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800"
                            title={`✅ Documentación Completa\n\n${docEstado.mensaje}\n\nTodos los documentos obligatorios están subidos (${docEstado.documentos?.total}/${docEstado.documentos?.total})\n\n🎉 Esta fuente está lista para desembolso`}
                          >
                            <CheckCircle className="w-3 h-3 text-green-600 dark:text-green-400" />
                            <span className="text-xs text-green-700 dark:text-green-300 font-medium">
                              ✓ {docEstado.documentos?.total} Docs
                            </span>
                          </div>
                        )
                      }

                      // Estado: No requiere documentación específica (se gestiona por abonos)
                      return (
                        <div
                          className="flex items-center gap-1 px-2 py-1 rounded-md bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800"
                          title={`ℹ️ Sin Requisitos de Documentos\n\n${docEstado.mensaje}\n\n💰 Esta fuente se gestiona directamente por abonos en el módulo de Abonos, no requiere documentos específicos de aprobación`}
                        >
                          <DollarSign className="w-3 h-3 text-blue-600 dark:text-blue-400" />
                          <span className="text-xs text-blue-700 dark:text-blue-300 font-medium">
                            Por Abonos
                          </span>
                        </div>
                      )
                    })()}

                    {/* Menú Compacto - SOLO ONCLICK */}
                    <div className="relative">
                      <button
                        onClick={(e) => toggleDropdown(fuente.id, e)}
                        className="w-6 h-6 rounded-md bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 flex items-center justify-center transition-colors"
                      >
                        <MoreVertical className="w-3 h-3 text-gray-500 dark:text-gray-400" />
                      </button>

                      {dropdownAbierto === fuente.id && (
                        <div className="absolute right-0 top-full mt-1 w-48 bg-white dark:bg-gray-800 rounded-lg shadow-xl border border-gray-200 dark:border-gray-700 z-50 animate-in fade-in duration-150">
                        <div className="p-1">
                          <button
                            onClick={() => onEditarFuente(fuente)}
                            className="w-full text-left px-2 py-1.5 text-xs text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-md flex items-center gap-1.5"
                          >
                            <Edit className="w-3 h-3" />
                            Editar Fuente
                          </button>

                          {/* Navegación contextual a Documentos */}
                          {getDocumentacionEstado(fuente).estado === 'pendiente' && (
                            <button
                              onClick={() => logger.info('Navegar a documentos para:', fuente.id)}
                              className="w-full text-left px-2 py-1.5 text-xs text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-md flex items-center gap-1.5"
                            >
                              <FileText className="w-3 h-3" />
                              Gestionar Docs
                            </button>
                          )}

                          {getDocumentacionEstado(fuente).estado === 'completo' && (
                            <button
                              onClick={() => logger.info('Ver documentos de:', fuente.id)}
                              className="w-full text-left px-2 py-1.5 text-xs text-green-600 dark:text-green-400 hover:bg-green-50 dark:hover:bg-green-900/20 rounded-md flex items-center gap-1.5"
                            >
                              <FileText className="w-3 h-3" />
                              Ver Documentos
                            </button>
                          )}

                          <button
                            onClick={() => onEliminarFuente(fuente.id)}
                            className="w-full text-left px-2 py-1.5 text-xs text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md flex items-center gap-1.5"
                          >
                            <Trash2 className="w-3 h-3" />
                            Eliminar
                          </button>
                        </div>
                        </div>
                      )}
                    </div>
                  </div>
                </div>

                {/* Contenido Compacto */}
                <div className="space-y-2">
                  {/* Métricas en Grid 3 columnas */}
                  <div className="grid grid-cols-3 gap-2 text-xs">
                    <div className="space-y-0.5">
                      <p className="text-gray-500 dark:text-gray-400 font-medium">
                        {esCuotaInicial(fuente.tipo) ? 'Pactado' : 'Aprobado'}
                      </p>
                      <p className="text-sm font-bold bg-gradient-to-r from-cyan-600 to-blue-600 bg-clip-text text-transparent">
                        {formatCurrency(fuente.monto_aprobado)}
                      </p>
                    </div>
                    <div className="space-y-0.5">
                      <p className="text-gray-500 dark:text-gray-400 font-medium">
                        {esCuotaInicial(fuente.tipo) ? 'Pagado' : 'Desembolsado'}
                      </p>
                      <p className="text-sm font-semibold text-green-600 dark:text-green-400">
                        {formatCurrency(fuente.monto_recibido || 0)}
                      </p>
                    </div>
                    <div className="space-y-0.5">
                      <p className="text-gray-500 dark:text-gray-400 font-medium">
                        {esCuotaInicial(fuente.tipo) ? 'Por Pagar' : 'Pendiente'}
                      </p>
                      <p className="text-sm font-semibold text-orange-600 dark:text-orange-400">
                        {formatCurrency(saldoPendiente)}
                      </p>
                    </div>
                  </div>

                  {/* Barra de Progreso Compacta */}
                  <div className="space-y-1">
                    <div className="flex items-center justify-between">
                      <span className="text-xs text-gray-500 dark:text-gray-400 font-medium">Progreso Desembolso</span>
                      <span className="text-xs font-bold text-cyan-600 dark:text-cyan-400">{progreso}%</span>
                    </div>
                    <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-1.5 overflow-hidden">
                      <motion.div
                        className={`h-full rounded-full ${getProgressStyles(progreso)}`}
                        initial={{ width: 0 }}
                        animate={{ width: `${progreso}%` }}
                        transition={{ duration: 1.2, ease: 'easeOut', delay: index * 0.15 }}
                      />
                    </div>
                  </div>

                  {/* LISTA DE DOCUMENTOS REQUERIDOS - DROPDOWN INTELIGENTE */}
                  {(() => {
                    const docEstado = getDocumentacionEstado(fuente)
                    const isExpanded = documentosExpandidos.has(fuente.id)

                    // Si no requiere documentos, mostrar mensaje
                    if (docEstado.estado === 'no_requerido') {
                      return (
                        <div className="pt-2 border-t border-gray-200 dark:border-gray-700">
                          <div className="flex items-center gap-2 px-3 py-2 rounded-lg bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800">
                            <DollarSign className="w-4 h-4 text-blue-600 dark:text-blue-400 flex-shrink-0" />
                            <p className="text-xs text-blue-700 dark:text-blue-300">
                              <span className="font-semibold">Se gestiona por abonos.</span> No requiere documentos de aprobación.
                            </p>
                          </div>
                        </div>
                      )
                    }

                    // Mostrar resumen + dropdown expandible
                    return (
                      <div className="pt-2 border-t border-gray-200 dark:border-gray-700">
                        {/* Resumen clickeable - MUY VISIBLE */}
                        <button
                          onClick={() => toggleDocumentos(fuente.id)}
                          className={`w-full flex items-center justify-between px-4 py-3 rounded-xl transition-all duration-200 shadow-md ${
                            isExpanded
                              ? 'bg-gradient-to-r from-cyan-500 to-blue-500 shadow-lg shadow-cyan-500/30'
                              : 'bg-gradient-to-r from-gray-100 to-gray-50 dark:from-gray-800 dark:to-gray-700 hover:from-cyan-50 hover:to-blue-50 dark:hover:from-cyan-900/30 dark:hover:to-blue-900/30 hover:shadow-lg hover:shadow-cyan-500/20'
                          }`}
                        >
                          <div className="flex items-center gap-3">
                            <motion.div
                              animate={{ rotate: isExpanded ? 90 : 0 }}
                              transition={{ duration: 0.3, type: "spring" }}
                              className="flex-shrink-0"
                            >
                              <svg className={`w-5 h-5 ${isExpanded ? 'text-white' : 'text-cyan-600 dark:text-cyan-400'}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M9 5l7 7-7 7" />
                              </svg>
                            </motion.div>
                            <div className="flex items-center gap-2">
                              <FileText className={`w-5 h-5 ${isExpanded ? 'text-white' : 'text-cyan-600 dark:text-cyan-400'}`} />
                              <div className="flex flex-col items-start">
                                <p className={`text-sm font-bold ${isExpanded ? 'text-white' : 'text-gray-800 dark:text-gray-100'}`}>
                                  📋 Requisitos para Desembolso
                                </p>
                                {docEstado.documentos && docEstado.documentos.lista && (() => {
                                  const obligatorios = docEstado.documentos.lista.filter(d => d.obligatorio)
                                  const opcionales = docEstado.documentos.lista.filter(d => !d.obligatorio)
                                  const obligatoriosSubidos = obligatorios.filter(d => d.subido).length
                                  const opcionalesSubidos = opcionales.filter(d => d.subido).length

                                  return (
                                    <p className={`text-[10px] font-medium ${isExpanded ? 'text-cyan-100' : 'text-gray-500 dark:text-gray-400'}`}>
                                      {obligatorios.length > 0 && `${obligatoriosSubidos}/${obligatorios.length} Obligatorios`}
                                      {opcionales.length > 0 && ` • ${opcionalesSubidos}/${opcionales.length} Opcional${opcionales.length > 1 ? 'es' : ''}`}
                                    </p>
                                  )
                                })()}
                              </div>
                            </div>
                          </div>

                          {/* Badge estado - Basado en OBLIGATORIOS */}
                          {(() => {
                            const obligatorios = docEstado.documentos?.lista?.filter(d => d.obligatorio) || []
                            const obligatoriosSubidos = obligatorios.filter(d => d.subido).length
                            const todosObligatoriosCompletos = obligatorios.length > 0 && obligatoriosSubidos === obligatorios.length

                            if (todosObligatoriosCompletos) {
                              return (
                                <span className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold border-2 ${
                                  isExpanded
                                    ? 'bg-white text-green-600 border-white shadow-lg'
                                    : 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300 border-green-300 dark:border-green-700'
                                }`}>
                                  <CheckCircle className="w-4 h-4" />
                                  ✓ Completo
                                </span>
                              )
                            } else if (obligatoriosSubidos > 0) {
                              return (
                                <span className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold border-2 ${
                                  isExpanded
                                    ? 'bg-white text-yellow-600 border-white shadow-lg'
                                    : 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-300 border-yellow-300 dark:border-yellow-700'
                                }`}>
                                  <AlertCircle className="w-4 h-4" />
                                  {obligatoriosSubidos}/{obligatorios.length}
                                </span>
                              )
                            } else {
                              return (
                                <span className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-bold border-2 ${
                                  isExpanded
                                    ? 'bg-white text-red-600 border-white shadow-lg'
                                    : 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300 border-red-300 dark:border-red-700'
                                }`}>
                                  <FileX className="w-4 h-4" />
                                  0/{obligatorios.length}
                                </span>
                              )
                            }
                          })()}
                        </button>

                        {/* Lista expandible de documentos */}
                        <motion.div
                          initial={false}
                          animate={{
                            height: isExpanded ? 'auto' : 0,
                            opacity: isExpanded ? 1 : 0
                          }}
                          transition={{ duration: 0.2, ease: 'easeInOut' }}
                          className="overflow-hidden"
                        >
                          <div className="mt-2 space-y-1.5 pl-3">
                            {docEstado.documentos?.lista?.map((doc, idx) => (
                              <div
                                key={idx}
                                className={`flex items-start gap-2 px-3 py-2 rounded-lg text-xs border ${
                                  doc.subido
                                    ? 'bg-green-50 dark:bg-green-900/20 border-green-300 dark:border-green-800'
                                    : 'bg-red-50 dark:bg-red-900/20 border-red-300 dark:border-red-800'
                                }`}
                              >
                                {doc.subido ? (
                                  <CheckCircle className="w-4 h-4 text-green-600 dark:text-green-400 flex-shrink-0 mt-0.5" />
                                ) : (
                                  <FileX className="w-4 h-4 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" />
                                )}
                                <div className="flex-1 min-w-0">
                                  <div className="flex items-start gap-2 flex-wrap">
                                    <p className={`font-medium leading-tight ${
                                      doc.subido
                                        ? 'text-green-700 dark:text-green-300'
                                        : 'text-red-700 dark:text-red-300'
                                    }`}>
                                      {doc.nombre}
                                    </p>
                                    {/* Badge Obligatorio/Opcional */}
                                    <span className={`inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide ${
                                      doc.obligatorio
                                        ? 'bg-red-200 dark:bg-red-900/50 text-red-800 dark:text-red-200 border border-red-400 dark:border-red-700'
                                        : 'bg-blue-200 dark:bg-blue-900/50 text-blue-800 dark:text-blue-200 border border-blue-400 dark:border-blue-700'
                                    }`}>
                                      {doc.obligatorio ? '⚠️ Obligatorio' : 'ℹ️ Opcional'}
                                    </span>
                                  </div>
                                  {!doc.subido && doc.obligatorio && (
                                    <p className="text-red-600 dark:text-red-400 text-[10px] mt-1 font-medium">
                                      📌 Requerido para habilitar desembolso - Sube en pestaña Documentos
                                    </p>
                                  )}
                                  {!doc.subido && !doc.obligatorio && (
                                    <p className="text-blue-600 dark:text-blue-400 text-[10px] mt-1">
                                      💡 Documento opcional - Mejora el proceso
                                    </p>
                                  )}
                                </div>
                              </div>
                            ))}
                          </div>
                        </motion.div>

                        {/* Mensaje de acción si no está expandido */}
                        {!isExpanded && docEstado.estado !== 'completo' && (
                          <p className="text-xs text-gray-500 dark:text-gray-400 italic pl-5 mt-1">
                            Click para ver {docEstado.documentos?.pendientes} documento{docEstado.documentos?.pendientes === 1 ? '' : 's'} pendiente{docEstado.documentos?.pendientes === 1 ? '' : 's'}
                          </p>
                        )}
                      </div>
                    )
                  })()}
                </div>
              </motion.div>
            )
          })}
        </motion.div>
      ) : (
        /* Estado vacío */
        <motion.div
          className={styles.fuentesList.emptyState}
          {...styles.animations.fadeInUp}
        >
          <DollarSign className={styles.fuentesList.emptyIcon} />
          <h4 className={styles.fuentesList.emptyTitle}>
            No hay fuentes de pago configuradas
          </h4>
          <p className={styles.fuentesList.emptySubtitle}>
            Agrega fuentes de pago para comenzar a gestionar los pagos de esta vivienda
          </p>
        </motion.div>
      )}
    </motion.div>
  )
}

/**
 * ============================================
 * HOOK: useFuentesPagoTab
 * ============================================
 *
 * ✅ SEPARACIÓN ESTRICTA DE RESPONSABILIDADES
 * - Hook: TODA la lógica de negocio
 * - Componente: SOLO UI presentacional
 *
 * Gestiona la lógica completa de la pestaña Fuentes de Pago:
 * - Obtención de fuentes de pago del cliente
 * - Validación y edición de montos
 * - Estados de documentación requerida
 * - Progreso y métricas
 * - Gestión de modales y acciones
 *
 * @version 1.0.0 - 2025-12-17 - Implementación inicial con React Query
 */

import { useCallback, useMemo, useState } from 'react'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import {
    BadgeDollarSign,
    Banknote,
    Building,
    Building2,
    CreditCard,
    DollarSign,
    Gift,
    HandCoins,
    Home,
    Landmark,
    Shield,
    Wallet
} from 'lucide-react'
import { toast } from 'sonner'

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'
import { fuentesPagoService } from '@/modules/clientes/services/fuentes-pago.service'
import type { Cliente } from '@/modules/clientes/types'
import type {
    ActualizarFuentePagoDTO,
    FuentePago,
    TipoFuentePago
} from '@/modules/clientes/types/fuentes-pago'
import type { TipoFuentePago as TipoFuentePagoConfig } from '@/modules/configuracion/types/tipos-fuentes-pago.types'
import { esCreditoHipotecario, esSubsidioMiCasaYa } from '@/shared/constants/fuentes-pago.constants'
import { calcularCierreFinanciero } from '@/shared/hooks/useCierreFinanciero'
import { formatCurrency } from '@/shared/utils/format'

// Importar iconos para mapeo dinámico

// ============================================
// INTERFACES
// ============================================

interface UseFuentesPagoTabProps {
  cliente: Cliente
}

interface FuenteEditada {
  id: string
  monto_aprobado: number
  entidad?: string
  numero_referencia?: string
}

export interface MetricasFuentesPago {
  valorTotalVivienda: number
  totalFuentesConfiguradas: number
  saldoPendiente: number
  porcentajeCompletado: number
  fuentesConDocumentacion: number
  fuentesSinDocumentacion: number
}

export interface EstadoValidacion {
  tieneFuentes: boolean
  sumaCuadra: boolean
  todasConDocumentacion: boolean
  puedeRegistrarAbonos: boolean
  mensajesValidacion: string[]
}

// ============================================
// HOOK PRINCIPAL
// ============================================

export function useFuentesPagoTab({ cliente }: UseFuentesPagoTabProps) {
  const queryClient = useQueryClient()

  // ============================================
  // ESTADO LOCAL
  // ============================================

  const [modalEditarAbierto, setModalEditarAbierto] = useState(false)
  const [fuenteParaEditar, setFuenteParaEditar] = useState<FuentePago | null>(null)
  const [modalHistorialAbierto, setModalHistorialAbierto] = useState(false)
  const [modalValidacionAbierto, setModalValidacionAbierto] = useState(false)

  // ============================================
  // QUERIES CON REACT QUERY
  // ============================================

  // Obtener negociación activa del cliente con datos de vivienda
  const {
    data: negociacion,
    isLoading: isLoadingNegociacion,
    error: errorNegociacion
  } = useQuery({
    queryKey: ['negociacion-activa-completa', cliente.id],
    queryFn: async () => {
      // Obtener negociación activa con datos de vivienda usando relación específica
      const { data, error } = await supabase
        .from('negociaciones')
        .select(`
          id, valor_negociado, valor_total, estado,
          vivienda_id,
          viviendas!negociaciones_vivienda_id_fkey(valor_base, numero, estado)
        `)
        .eq('cliente_id', cliente.id)
        .eq('estado', 'Activa')
        .maybeSingle() // ✅ Cambiado de .single() a .maybeSingle() para evitar error cuando no hay datos

      if (error) {
        logger.warn('Error obteniendo negociación:', error)
        return null
      }

      // Si no hay negociación, retornar null (sin error)
      if (!data) {
        return null
      }

      // Fallback: Si el join falló, obtener vivienda por separado
      if (data.vivienda_id && !data.viviendas) {
        const { data: viviendaData } = await supabase
          .from('viviendas')
          .select('valor_base, numero, estado')
          .eq('id', data.vivienda_id)
          .maybeSingle()

        return {
          ...data,
          viviendas: viviendaData
        }
      }

      return data
    },
    enabled: !!cliente.id,
  })

  // Obtener fuentes de pago de la negociación
  const {
    data: fuentesPago = [],
    isLoading: isLoadingFuentes,
    error: errorFuentes,
    refetch: refetchFuentes
  } = useQuery({
    queryKey: ['fuentes-pago', negociacion?.id],
    queryFn: () => fuentesPagoService.obtenerFuentesPagoNegociacion(negociacion!.id),
    enabled: !!negociacion?.id,
    staleTime: 30 * 1000, // 30 segundos
    gcTime: 5 * 60 * 1000, // 5 minutos
  })

  // Obtener configuración de tipos de fuentes de pago
  const {
    data: tiposFuentesConfig = [],
    isLoading: isLoadingTipos
  } = useQuery({
    queryKey: ['tipos-fuentes-pago-config'],
    queryFn: async (): Promise<TipoFuentePagoConfig[]> => {
      const { data, error } = await supabase
        .from('tipos_fuentes_pago')
        .select('*')
        .eq('activo', true)
        .order('orden')

      if (error) {
        logger.error('Error obteniendo tipos de fuentes:', error)
        return []
      }

      return (data as unknown as TipoFuentePagoConfig[]) || []
    },
    staleTime: 5 * 60 * 1000, // 5 minutos (config no cambia frecuentemente)
    gcTime: 30 * 60 * 1000, // 30 minutos
  })

  // ✅ Obtener requisitos REALES desde BD (obligatorios + opcionales)
  const {
    data: requisitosConfig = [],
    isLoading: isLoadingRequisitos
  } = useQuery({
    queryKey: ['requisitos-fuentes-pago-config'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('requisitos_fuentes_pago_config')
        .select('id,tipo_fuente,paso_identificador,titulo,descripcion,instrucciones,nivel_validacion,tipo_documento_sugerido,categoria_documento,alcance,orden,activo,version,fecha_creacion,fecha_actualizacion')
        .eq('activo', true)
        // ✅ INCLUIR TODOS: obligatorios + opcionales (no filtrar por nivel_validacion)
        .order('tipo_fuente')
        .order('orden')

      if (error) {
        logger.error('Error obteniendo requisitos:', error)
        return []
      }

      return data || []
    },
    staleTime: 5 * 60 * 1000, // 5 minutos (config no cambia frecuentemente)
    gcTime: 30 * 60 * 1000, // 30 minutos
  })

  // ============================================
  // MUTATIONS
  // ============================================

  // Actualizar fuente de pago
  const actualizarFuenteMutation = useMutation({
    mutationFn: ({ id, datos }: { id: string, datos: ActualizarFuentePagoDTO }) =>
      fuentesPagoService.actualizarFuentePago(id, datos),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['fuentes-pago'] })
      queryClient.invalidateQueries({ queryKey: ['negociacion-activa'] })
      toast.success('Fuente de pago actualizada correctamente')
    },
    onError: (error) => {
      logger.error('Error actualizando fuente de pago:', error)
      toast.error('Error al actualizar la fuente de pago')
    }
  })

  // Crear nueva fuente de pago
  const crearFuenteMutation = useMutation({
    mutationFn: (tipo: TipoFuentePago) =>
      fuentesPagoService.crearFuentePago({
        negociacion_id: negociacion!.id,
        tipo,
        monto_aprobado: 0
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['fuentes-pago'] })
      toast.success('Fuente de pago agregada correctamente')
    },
    onError: (error) => {
      logger.error('Error creando fuente de pago:', error)
      toast.error('Error al agregar la fuente de pago')
    }
  })

  // Eliminar fuente de pago
  const eliminarFuenteMutation = useMutation({
    mutationFn: (id: string) => fuentesPagoService.eliminarFuentePago(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['fuentes-pago'] })
      toast.success('Fuente de pago eliminada correctamente')
    },
    onError: (error) => {
      logger.error('Error eliminando fuente de pago:', error)
      toast.error('Error al eliminar la fuente de pago')
    }
  })

  // Obtener documentos del cliente para validación
  const {
    data: documentosCliente = []
  } = useQuery({
    queryKey: ['documentos-cliente', cliente.id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('documentos_cliente')
        .select('*')
        .eq('cliente_id', cliente.id)
        .eq('estado', 'activo')
        .order('fecha_creacion', { ascending: false })

      if (error) {
        logger.error('Error obteniendo documentos del cliente:', error)
        return []
      }

      return data || []
    },
    staleTime: 30 * 1000, // 30 segundos
    gcTime: 5 * 60 * 1000, // 5 minutos
  })

  // ============================================
  // BUSINESS LOGIC - FUNCIONES DE UTILIDAD
  // ============================================

  // Mapeo dinámico de iconos disponibles
  const iconMap = useMemo(() => ({
    'Wallet': Wallet,
    'Building2': Building2,
    'Home': Home,
    'Shield': Shield,
    'CreditCard': CreditCard,
    'Landmark': Landmark,
    'BadgeDollarSign': BadgeDollarSign,
    'DollarSign': DollarSign,
    'Banknote': Banknote,
    'HandCoins': HandCoins,
    'Building': Building, // Fallback
    'Gift': Gift, // Fallback
  }), [])

  // Mapeo dinámico de colores
  const getColorClasses = useCallback((color: string) => {
    const colorMap = {
      blue: 'bg-gradient-to-br from-blue-500 to-blue-600 shadow-blue-500/50',
      green: 'bg-gradient-to-br from-green-500 to-green-600 shadow-green-500/50',
      purple: 'bg-gradient-to-br from-purple-500 to-purple-600 shadow-purple-500/50',
      orange: 'bg-gradient-to-br from-orange-500 to-orange-600 shadow-orange-500/50',
      red: 'bg-gradient-to-br from-red-500 to-red-600 shadow-red-500/50',
      cyan: 'bg-gradient-to-br from-cyan-500 to-cyan-600 shadow-cyan-500/50',
      pink: 'bg-gradient-to-br from-pink-500 to-pink-600 shadow-pink-500/50',
      indigo: 'bg-gradient-to-br from-indigo-500 to-indigo-600 shadow-indigo-500/50',
      yellow: 'bg-gradient-to-br from-yellow-500 to-yellow-600 shadow-yellow-500/50',
      emerald: 'bg-gradient-to-br from-emerald-500 to-emerald-600 shadow-emerald-500/50',
    }
    return colorMap[color as keyof typeof colorMap] || colorMap.blue // Fallback a azul
  }, [])

  // Obtener configuración dinámica de un tipo
  const getTipoConfig = useCallback((tipo: TipoFuentePago) => {
    const config = tiposFuentesConfig.find(tc => tc.nombre === tipo)

    if (!config) {
      // Fallback si no se encuentra configuración
      return {
        icon: DollarSign,
        styles: getColorClasses('blue'),
        iconStyles: 'text-white'
      }
    }

    const IconComponent = iconMap[config.icono] || DollarSign

    return {
      icon: IconComponent,
      styles: getColorClasses(config.color),
      iconStyles: 'text-white'
    }
  }, [tiposFuentesConfig, iconMap, getColorClasses])

  // ✅ Función auxiliar para obtener documentos requeridos DESDE BD (con nivel de validación)
  const getDocumentosRequeridos = useCallback((tipoFuente: string | undefined) => {
    if (!tipoFuente) return []

    // ✅ INCLUIR TODOS: obligatorios + opcionales (NO filtrar)
    const requisitosDelTipo = requisitosConfig.filter(
      req => req.tipo_fuente === tipoFuente
    )

    // Retornar objetos completos con título y nivel de validación
    return requisitosDelTipo.map(req => ({
      titulo: req.titulo,
      nivel: req.nivel_validacion,
      obligatorio: req.nivel_validacion === 'DOCUMENTO_OBLIGATORIO'
    }))
  }, [requisitosConfig])

  // Estado de documentación ESPECÍFICA por tipo de fuente
  const getDocumentacionEstado = useCallback((fuente: FuentePago) => {
    const documentosRequeridos = getDocumentosRequeridos(fuente.tipo)

    // Si no hay documentos requeridos para este tipo de fuente
    if (documentosRequeridos.length === 0) {
      return {
        estado: 'no_requerido' as const,
        mensaje: 'Se gestiona por abonos',
        detalle: 'Esta fuente no requiere documentos específicos',
        documentos: {
          total: 0,
          subidos: 0,
          pendientes: 0,
          obligatoriosPendientes: 0
        }
      }
    }

    // Buscar documentos subidos
    const documentosSubidos = documentosCliente?.filter(doc =>
      documentosRequeridos.some(reqDoc =>
        doc.titulo?.toLowerCase().includes(reqDoc.titulo.toLowerCase()) ||
        doc.tipo_documento?.toLowerCase().includes(reqDoc.titulo.toLowerCase())
      )
    ) || []

    const documentosPendientes = documentosRequeridos.filter(
      doc => !documentosSubidos.some(subido =>
        (subido.titulo?.toLowerCase() || '').includes(doc.titulo.toLowerCase()) ||
        (subido.tipo_documento?.toLowerCase() || '').includes(doc.titulo.toLowerCase())
      )
    )

    // Determinar el estado general
    let estado: 'completo' | 'pendiente' | 'parcial'
    let mensaje: string

    if (documentosPendientes.length === 0) {
      estado = 'completo'
      mensaje = `✅ Documentos completos (${documentosSubidos.length}/${documentosRequeridos.length})`
    } else if (documentosSubidos.length > 0) {
      estado = 'parcial'
      mensaje = `⚠️ Faltan ${documentosPendientes.length} documento(s)`
    } else {
      estado = 'pendiente'
      mensaje = `❌ Faltan ${documentosPendientes.length} documento(s) requerido(s)`
    }

    return {
      estado,
      mensaje,
      detalle: `${documentosSubidos.length}/${documentosRequeridos.length} documentos subidos`,
      documentos: {
        total: documentosRequeridos.length,
        subidos: documentosSubidos.length,
        pendientes: documentosPendientes.length,
        obligatoriosPendientes: documentosPendientes.filter(d => d.obligatorio).length,
        lista: documentosRequeridos.map(doc => ({
          nombre: doc.titulo,
          obligatorio: doc.obligatorio,
          nivel: doc.nivel,
          subido: documentosSubidos.some(subido =>
            (subido.titulo?.toLowerCase() || '').includes(doc.titulo.toLowerCase()) ||
            (subido.tipo_documento?.toLowerCase() || '').includes(doc.titulo.toLowerCase())
          )
        }))
      }
    }
  }, [getDocumentosRequeridos, documentosCliente])

  // Verificar si todas las fuentes posibles están creadas
  const todasFuentesCreadas = useMemo(() => {
    if (!tiposFuentesConfig.length || !fuentesPago.length) return false

    // Verificar que exista una fuente para cada tipo configurado
    const tiposCreados = new Set(fuentesPago.map(f => f.tipo).filter(Boolean))
    const tiposDisponibles = tiposFuentesConfig.map(t => t.nombre)

    return tiposDisponibles.every(tipoId => tiposCreados.has(tipoId as TipoFuentePago))
  }, [tiposFuentesConfig, fuentesPago])

  // Mensaje para el botón deshabilitado
  const mensajeBotonDeshabilitado = useMemo(() => {
    if (todasFuentesCreadas) {
      const totalTipos = tiposFuentesConfig.length
      const tiposCreados = fuentesPago.length
      return `Ya se han creado todas las fuentes de pago disponibles (${tiposCreados}/${totalTipos}). No es posible agregar más fuentes.`
    }
    return ''
  }, [todasFuentesCreadas, tiposFuentesConfig.length, fuentesPago.length])

  // Filtrar tipos disponibles (que no han sido creados aún)
  const tiposDisponibles = useMemo(() => {
    if (!tiposFuentesConfig.length) return []

    const tiposCreados = new Set(fuentesPago.map(f => f.tipo).filter(Boolean))
    return tiposFuentesConfig.filter(tipo => !tiposCreados.has(tipo.nombre as TipoFuentePago))
  }, [tiposFuentesConfig, fuentesPago])

  // Calcular progreso CORREGIDO
  const calcularProgreso = useCallback((fuente: FuentePago) => {
    if (fuente.monto_aprobado === 0) return 0
    const montoRecibido = fuente.monto_recibido || 0
    const progreso = Math.round((montoRecibido / fuente.monto_aprobado) * 100)

    // Para fuentes completadas (monto recibido = monto aprobado), mostrar 100%
    if (progreso === 0 && fuente.monto_recibido && fuente.monto_recibido >= fuente.monto_aprobado) return 100

    return progreso
  }, [])

  // Mapeo de estados (compactos)
  const getEstadoStyles = useCallback((estado: string) => {
    switch (estado) {
      case 'Activa':
        return 'bg-blue-100 dark:bg-blue-900/30 text-blue-800 dark:text-blue-300 border border-blue-200 dark:border-blue-800'
      case 'Inactiva':
        return 'bg-gray-100 dark:bg-gray-900/30 text-gray-800 dark:text-gray-300 border border-gray-200 dark:border-gray-800'
      case 'Completado':
        return 'bg-green-100 dark:bg-green-900/30 text-green-800 dark:text-green-300 border border-green-200 dark:border-green-800'
      default:
        return 'bg-gray-100 dark:bg-gray-900/30 text-gray-800 dark:text-gray-300 border border-gray-200 dark:border-gray-800'
    }
  }, [])

  // Estilos de progreso según porcentaje (compactos)
  const getProgressStyles = useCallback((porcentaje: number) => {
    if (porcentaje >= 80) return 'bg-gradient-to-r from-green-500 to-emerald-500'
    if (porcentaje >= 40) return 'bg-gradient-to-r from-yellow-500 to-orange-500'
    return 'bg-gradient-to-r from-red-500 to-pink-500'
  }, [])

  // ============================================
  // HANDLERS
  // ============================================

  // ============================================
  // COMPUTED VALUES
  // ============================================

  const valorTotalVivienda = useMemo(() => {
    if (!negociacion) {
      // Sin negociación activa, retornar 0 (estado inicial normal)
      return 0
    }

    // Prioridad: valor_total_pagar > valor_total > valor_negociado > valor_base de vivienda
    let valor = 0
    let fuente = ''

    if ((negociacion as any).valor_total_pagar) {
      valor = Number((negociacion as any).valor_total_pagar)
      fuente = 'valor_total_pagar de negociación'
    } else if (negociacion.valor_total) {
      valor = Number(negociacion.valor_total)
      fuente = 'valor_total de negociación'
    } else if (negociacion.valor_negociado) {
      valor = Number(negociacion.valor_negociado)
      fuente = 'valor_negociado de negociación'
    } else if (negociacion.viviendas?.valor_base) {
      valor = Number(negociacion.viviendas.valor_base)
      fuente = 'valor_base de vivienda'
    }

    if (valor > 0) {
    } else {
      logger.warn('❌ No se pudo obtener valor de vivienda:', {
        negociacion,
        valor_total: negociacion.valor_total,
        valor_negociado: negociacion.valor_negociado,
        vivienda_valor_base: negociacion.viviendas?.valor_base
      })
    }

    return valor
  }, [negociacion])

  const metricas = useMemo((): MetricasFuentesPago => {
    const cierre = calcularCierreFinanciero(fuentesPago, valorTotalVivienda)
    const totalFuentesConfiguradas = cierre.totalParaCierre

    const saldoPendiente = cierre.diferencia

    const porcentajeCompletado = cierre.porcentajeCubierto

    // Solo contar fuentes que requieren documentación (Crédito e Hipotecario y Subsidio Mi Casa Ya)
    const fuentesQueRequierenDoc = fuentesPago.filter(
      f => esCreditoHipotecario(f.tipo) || esSubsidioMiCasaYa(f.tipo)
    )

    const fuentesConDocumentacion = 0 // Sistema nuevo: ver vista_documentos_pendientes_fuentes
    const fuentesSinDocumentacion = 0 // Sistema nuevo: ver vista_documentos_pendientes_fuentes

    return {
      valorTotalVivienda,
      totalFuentesConfiguradas,
      saldoPendiente,
      porcentajeCompletado,
      fuentesConDocumentacion,
      fuentesSinDocumentacion,
    }
  }, [fuentesPago, valorTotalVivienda])

  const estadoValidacion = useMemo((): EstadoValidacion => {
    const mensajes: string[] = []
    const tieneFuentes = fuentesPago.length > 0
    const sumaCuadra = Math.abs(metricas.saldoPendiente) < 100 // Tolerancia de $100

    // Solo verificar documentación en fuentes que la requieren
    const fuentesQueRequierenDoc = fuentesPago.filter(
      f => esCreditoHipotecario(f.tipo) || esSubsidioMiCasaYa(f.tipo)
    )

    const todasConDocumentacion = true // Sistema nuevo: usa vista_documentos_pendientes_fuentes

    if (!tieneFuentes) {
      mensajes.push('⚠️ No hay fuentes de pago configuradas')
    }

    if (tieneFuentes && metricas.saldoPendiente > 100) {
      mensajes.push(`💰 Faltan ${formatCurrency(metricas.saldoPendiente)} por cubrir`)
    }

    if (tieneFuentes && metricas.saldoPendiente < -100) {
      mensajes.push(`📈 Excede por ${formatCurrency(Math.abs(metricas.saldoPendiente))}`)
    }

    if (tieneFuentes && !todasConDocumentacion) {
      mensajes.push(`📄 ${metricas.fuentesSinDocumentacion} fuentes sin documentación`)
    }

    const puedeRegistrarAbonos = tieneFuentes && sumaCuadra && todasConDocumentacion

    return {
      tieneFuentes,
      sumaCuadra,
      todasConDocumentacion,
      puedeRegistrarAbonos,
      mensajesValidacion: mensajes,
    }
  }, [fuentesPago, metricas])

  // ============================================
  // HANDLERS
  // ============================================

  const handleEditarFuente = useCallback((fuente: FuentePago) => {
    setFuenteParaEditar(fuente)
    setModalEditarAbierto(true)
  }, [])

  const handleGuardarFuente = useCallback(async (fuenteEditada: FuenteEditada) => {
    if (!fuenteEditada.id) return

    try {
      await actualizarFuenteMutation.mutateAsync({
        id: fuenteEditada.id,
        datos: {
          monto_aprobado: fuenteEditada.monto_aprobado,
          entidad: fuenteEditada.entidad,
          numero_referencia: fuenteEditada.numero_referencia,
        }
      })

      setModalEditarAbierto(false)
      setFuenteParaEditar(null)
    } catch (error) {
      // Error ya manejado por la mutation
    }
  }, [actualizarFuenteMutation])

  const handleAgregarFuente = useCallback(async (tipo: TipoFuentePago) => {
    if (!negociacion?.id) return

    try {
      await crearFuenteMutation.mutateAsync(tipo)
    } catch (error) {
      // Error ya manejado por la mutation
    }
  }, [crearFuenteMutation, negociacion])

  const handleEliminarFuente = useCallback(async (id: string) => {
    if (!confirm('¿Estás seguro de eliminar esta fuente de pago? Esta acción no se puede deshacer.')) {
      return
    }

    try {
      await eliminarFuenteMutation.mutateAsync(id)
    } catch (error) {
      // Error ya manejado por la mutation
    }
  }, [eliminarFuenteMutation])

  const handleVerHistorial = useCallback(() => {
    setModalHistorialAbierto(true)
  }, [])

  const handleVerValidacion = useCallback(() => {
    setModalValidacionAbierto(true)
  }, [])

  const handleNavegar = useCallback((destino: 'documentos' | 'abonos') => {
    if (destino === 'documentos') {
      // Por ahora solo mostrar console.log, se puede implementar navegación después
    } else if (destino === 'abonos') {
      // Navegar al módulo de abonos
    }
  }, [])

  const handleGestionarDocumentos = useCallback((fuenteId: string) => {
    toast.info('Navegando al módulo de Documentos para gestionar documentación...')
    // TODO: Implementar navegación real al módulo de documentos
    // router.push(`/documentos?fuente=${fuenteId}&action=upload`)
  }, [])

  const handleVerDocumentos = useCallback((fuenteId: string) => {
    toast.info('Navegando a documentos existentes...')
    // TODO: Implementar navegación real
    // router.push(`/documentos?fuente=${fuenteId}&action=view`)
  }, [])

  // ============================================
  // LOADING & ERROR STATES
  // ============================================

  const isLoading = isLoadingNegociacion || isLoadingFuentes || isLoadingTipos || isLoadingRequisitos
  const isUpdating = actualizarFuenteMutation.isPending ||
                     crearFuenteMutation.isPending ||
                     eliminarFuenteMutation.isPending

  const error = errorNegociacion || errorFuentes

  // ============================================
  // RETURN
  // ============================================

  return {
    // Estado
    negociacion,
    fuentesPago,
    tiposFuentesConfig,
    metricas,
    estadoValidacion,
    isLoading,
    isUpdating,
    error,

    // Modales
    modalEditarAbierto,
    fuenteParaEditar,
    modalHistorialAbierto,
    modalValidacionAbierto,
    setModalEditarAbierto,
    setFuenteParaEditar,
    setModalHistorialAbierto,
    setModalValidacionAbierto,

    // Business Logic Functions (LÓGICA PROCESADA)
    getTipoConfig,
    getDocumentacionEstado,
    calcularProgreso,
    getEstadoStyles,
    getProgressStyles,
    tiposDisponibles,

    // Lógica de fuentes disponibles
    todasFuentesCreadas,
    mensajeBotonDeshabilitado,

    // Handlers
    handleEditarFuente,
    handleGuardarFuente,
    handleAgregarFuente,
    handleEliminarFuente,
    handleVerHistorial,
    handleVerValidacion,
    handleNavegar,
    handleGestionarDocumentos,
    handleVerDocumentos,
    refetchFuentes,
  }
}

'use client'

/**
 * ✅ COMPONENTE ORQUESTADOR REFACTORIZADO
 * General Tab - Dividido en componentes atómicos
 *
 * SEPARACIÓN DE RESPONSABILIDADES:
 * - Este componente SOLO orquesta sub-componentes
 * - Cada sección está en su propio archivo atómico
 * - Hook separado para lógica de navegación
 *
 * COMPONENTES ATÓMICOS:
 * - BannerDocumentacion
 * - ResumenNegociacion (NUEVO: muestra estado financiero de negociación activa)
 * - EstadisticasComerciales (ahora tira horizontal compacta)
 * - InfoPersonalCard
 * - ContactoUbicacionCard
 * - NotasCard
 */

import { useMemo } from 'react'

import { motion } from 'framer-motion'
import { Clock } from 'lucide-react'

import { useRouter } from 'next/navigation'

import { formatDateCompact } from '@/lib/utils/date.utils'
import { construirURLCliente } from '@/lib/utils/slug.utils'
import { useDocumentoIdentidad } from '@/modules/clientes/documentos/hooks/useDocumentoIdentidad'
import type { Cliente } from '@/modules/clientes/types'

import * as styles from '../cliente-detalle.styles'

import {
    BannerDocumentacion,
    ContactoUbicacionCard,
    EstadisticasComerciales,
    InfoPersonalCard,
    NotasCard,
    ResumenNegociacion,
} from './general/components'

interface GeneralTabProps {
  cliente: Cliente
}

export function GeneralTab({ cliente }: GeneralTabProps) {
  const router = useRouter()

  // ✅ Hook de validación real de documento de identidad
  const { tieneCedula: tieneDocumento, cargando: cargandoValidacion } = useDocumentoIdentidad({
    clienteId: cliente.id,
  })

  const estadisticas = cliente.estadisticas || {
    total_negociaciones: 0,
    negociaciones_activas: 0,
    negociaciones_completadas: 0,
  }

  const tieneNegociacionActiva = estadisticas.negociaciones_activas > 0

  // Extraer negociación activa (datos ya cargados en cliente.negociaciones)
  const negociacionActiva = useMemo(() => {
    if (!cliente.negociaciones?.length) return null
    // Solo considerar negociaciones realmente activas
    const activa = cliente.negociaciones.find((n) => n.estado === 'Activa' || n.estado === 'Suspendida')
    return activa || null
  }, [cliente.negociaciones])

  const handleIniciarAsignacion = () => {
    if (!tieneDocumento) {
      window.dispatchEvent(new CustomEvent('cambiar-tab', { detail: 'documentos' }))
      return
    }

    const clienteSlug = construirURLCliente({
      id: cliente.id,
      nombres: cliente.nombres,
      apellidos: cliente.apellidos,
    })
      .split('/')
      .pop()

    router.push(
      `/clientes/${clienteSlug}/asignar-vivienda?nombre=${encodeURIComponent(cliente.nombres + ' ' + cliente.apellidos)}`
    )
  }

  return (
    <motion.div key="info" {...styles.animations.fadeInUp} className="space-y-3">
      {/* Banner de estado de documentación (oculto si renunció) */}
      {cliente.estado !== 'Renunció' && (
        <BannerDocumentacion
          tieneDocumento={tieneDocumento}
          cargandoValidacion={cargandoValidacion}
          tieneNegociacionActiva={tieneNegociacionActiva}
        />
      )}

      {/* Resumen financiero de negociación - hero section */}
      {negociacionActiva && (negociacionActiva.valor_total_pagar > 0 || negociacionActiva.valor_total > 0) && (
        <ResumenNegociacion negociacion={negociacionActiva} clienteId={cliente.id} />
      )}

      {/* Tira de estadísticas compacta */}
      <EstadisticasComerciales estadisticas={estadisticas} cliente={cliente} />

      {/* Grid de información: 50/50 */}
      <div className="grid gap-3 grid-cols-1 md:grid-cols-2">
        <InfoPersonalCard cliente={cliente} />
        <ContactoUbicacionCard cliente={cliente} />
      </div>

      {/* Auditoría */}
      <div className="flex items-center gap-1.5 px-1">
        <Clock className="w-3 h-3 text-gray-400 dark:text-gray-500 flex-shrink-0" />
        <p className="text-xs text-gray-400 dark:text-gray-500">
          Cliente registrado el {formatDateCompact(cliente.fecha_creacion)}
        </p>
      </div>

      {/* Notas (si existen) */}
      <NotasCard cliente={cliente} />
    </motion.div>
  )
}

