export function HistorialTab({ clienteId, clienteNombre }: HistorialTabProps) {
  const queryClient = useQueryClient()
  const [mostrarModalNota, setMostrarModalNota] = useState(false)
  const [notaIdSeleccionado, setNotaIdSeleccionado] = useState<string | null>(null)
  const { confirm } = useModal()
  const { eliminarNota, isEliminando } = useNotasHistorial(clienteId)

  const {
    eventosAgrupados,
    estadisticas,
    usuariosDisponibles,
    isLoading,
    error,
    busqueda,
    setBusqueda,
    tipoEvento,
    setTipoEvento,
    modulo,
    setModulo,
    usuarioFiltro,
    setUsuarioFiltro,
    limpiarFiltros,
    tieneAplicados,
  } = useHistorialCliente({ clienteId })

  // ✅ Calcular todos los eventos (aplanado)
  const todosLosEventos = useMemo(() => {
    return eventosAgrupados.flatMap(grupo => grupo.eventos)
  }, [eventosAgrupados])

  // ✅ Verificar permisos de forma SINCRÓNICA (instantáneo, sin delays)
  const { notasEditables } = usePermisosNotasHistorial(todosLosEventos)

  // ========== HANDLERS DE NOTAS ==========
  /**
   * ✅ REACT QUERY PRO: Pre-fetch antes de abrir modal
   * - Carga datos en cache ANTES de abrir
   * - Modal usa datos del cache (instantáneo)
   * - Sin flashes de loading
   */
  const handleEditarNota = async (notaId: string) => {
    try {
      // 1. Pre-fetch: Cargar datos en cache ANTES de abrir modal
      await queryClient.prefetchQuery({
        queryKey: ['nota-historial', notaId],
        queryFn: () => notasHistorialService.obtenerNotaPorId(notaId),
      })

      // 2. Datos YA están en cache, abrir modal instantáneamente
      setNotaIdSeleccionado(notaId)
      setMostrarModalNota(true)
    } catch (error) {
      logger.error('Error cargando nota:', error)
      toast.error('Error al cargar la nota')
    }
  }

  const handleEliminarNota = async (notaId: string) => {
    const confirmado = await confirm({
      title: '¿Eliminar nota?',
      message: 'Esta acción no se puede deshacer. La nota se eliminará permanentemente del historial.',
      confirmText: 'Eliminar',
      cancelText: 'Cancelar',
      variant: 'danger',
    })

    if (confirmado) {
      try {
        await eliminarNota(notaId)
      } catch (error) {
        logger.error('Error eliminando nota:', error)
      }
    }
  }

  const handleCerrarModal = () => {
    setMostrarModalNota(false)
    setNotaIdSeleccionado(null)
  }

  // ========== ESTADOS DE CARGA Y ERROR ==========
  if (isLoading) {
    return (
      <div className="py-12">
        <LoadingState message="Cargando historial del cliente..." />
      </div>
    )
  }

  if (error) {
    return (
      <div className={historialStyles.empty.container}>
        <EmptyState
          icon={<X className="w-12 h-12 text-red-500" />}
          title="Error al cargar historial"
          description="Ocurrió un error al cargar el historial del cliente"
        />
      </div>
    )
  }

  if (estadisticas.total === 0) {
    return (
      <div className={historialStyles.empty.container}>
        <EmptyState
          icon={<Clock className="w-12 h-12 text-gray-400" />}
          title="Sin historial"
          description="Este cliente aún no tiene eventos registrados"
        />
      </div>
    )
  }

  // ========== CONTENIDO PRINCIPAL ==========
  return (
    <div className={historialStyles.container.root}>
      {/* Panel de Métricas */}
      <MetricasHistorial
        total={estadisticas.total}
        estaSemana={estadisticas.estaSemana}
        esteMes={estadisticas.esteMes}
        criticos={estadisticas.criticos}
      />

      {/* Header con búsqueda y filtros avanzados */}
      <FiltrosYBusqueda
        clienteNombre={clienteNombre}
        estadisticasFiltrados={estadisticas.filtrados}
        estadisticasTotal={estadisticas.total}
        busqueda={busqueda}
        onBusquedaChange={setBusqueda}
        tieneAplicados={tieneAplicados}
        onLimpiarFiltros={limpiarFiltros}
        // Nuevos filtros
        tipoEvento={tipoEvento}
        onTipoEventoChange={setTipoEvento}
        modulo={modulo}
        onModuloChange={setModulo}
        usuario={usuarioFiltro}
        onUsuarioChange={setUsuarioFiltro}
        usuariosDisponibles={usuariosDisponibles}
        // Botón agregar nota
        onAgregarNota={() => setMostrarModalNota(true)}
      />

      {/* Timeline de eventos */}
      {estadisticas.filtrados === 0 ? (
        <div className={historialStyles.empty.sinResultados}>
          <EmptyState
            icon={<Filter className="w-12 h-12 text-gray-400" />}
            title="Sin resultados"
            description="No se encontraron eventos con los filtros aplicados"
          />
        </div>
      ) : (
        <div className={historialStyles.timeline.container}>
          <AnimatePresence>
            {eventosAgrupados.map((grupo) => (
              <GrupoEventosFecha
                key={grupo.fecha}
                fecha={grupo.fecha}
                fechaFormateada={grupo.fechaFormateada}
                total={grupo.total}
                eventos={grupo.eventos}
                onEditarNota={handleEditarNota}
                onEliminarNota={handleEliminarNota}
                notasEditables={notasEditables}
              />
            ))}
          </AnimatePresence>
        </div>
      )}

      {/* Modal para agregar/editar notas */}
      {/* ✅ React Query: notaId resuelve datos desde cache (instantáneo) */}
      <NotaModal
        isOpen={mostrarModalNota}
        onClose={handleCerrarModal}
        clienteId={clienteId}
        clienteNombre={clienteNombre}
        notaId={notaIdSeleccionado}
      />
    </div>
  )
}

/**
 * EventoCard - Componente Individual de Evento (DISEÑO COMPACTO)
 * Card de timeline con toda la información del evento
 */

'use client'

import { useState } from 'react'

import { motion } from 'framer-motion'
import { Clock, Edit, Eye, Plus, Trash2, User } from 'lucide-react'

import { formatDateTimeForDisplay } from '@/lib/utils/date.utils'
import type { EventoHistorialHumanizado } from '@/modules/clientes/types/historial.types'

import { DetalleEventoModal } from '../../components/DetalleEventoModal'
import { coloresEvento, historialStyles } from '../historial-tab.styles'

interface EventoCardProps {
  evento: EventoHistorialHumanizado
  isLast?: boolean
  onEditarNota?: (notaId: string) => void
  onEliminarNota?: (notaId: string) => void
  notasEditables?: Set<string> // ✅ Permisos pre-calculados desde el padre
}

// Iconos por tipo de evento
const ICONOS_TIPO = {
  CREATE: Plus,
  UPDATE: Edit,
  DELETE: Trash2,
}

export function EventoCard({ evento, _isLast, onEditarNota, onEliminarNota, notasEditables }: EventoCardProps) {
  const Icono = evento.icono
  const colores = coloresEvento[evento.color] || coloresEvento.gray

  // Detectar si es nota manual
  const esNota = evento.metadata?.esNota === true
  const notaId = evento.metadata?.notaId as string | undefined

  // Icono de tipo de acción
  const IconoTipo = esNota ? evento.icono : (ICONOS_TIPO[evento.accion as keyof typeof ICONOS_TIPO] || evento.icono)

  // ✅ Verificar permisos desde Set pre-calculado (instantáneo)
  const puedeEditar = notaId ? notasEditables?.has(notaId) ?? false : false

  return (
    <motion.div
      initial={historialStyles.animations.slideIn.initial}
      animate={historialStyles.animations.slideIn.animate}
      transition={{ duration: 0.3 }}
      className={historialStyles.eventoCard.wrapper}
    >
      {/* Punto del timeline con icono de tipo */}
      <div className={`${historialStyles.eventoCard.punto} ${colores.bg}`}>
        <IconoTipo className={`${historialStyles.eventoCard.puntoIcon} ${colores.icon}`} strokeWidth={2.5} />
      </div>

      {/* Card del evento (diseño compacto) */}
      <motion.div
        whileHover={{ ...historialStyles.animations.hoverSlide.whileHover, scale: 1.01 }}
        transition={historialStyles.animations.hoverSlide.transition}
        className={`${historialStyles.eventoCard.card} ${colores.border}`}
      >
        {/* Barra de color lateral más prominente */}
        <div className={`${historialStyles.eventoCard.barraLateral} ${colores.barraLateral}`} />

        {/* Contenido */}
        <div className="px-4 py-3 space-y-2">
          {/* Header: Título + Badge tipo */}
          <div className="flex items-start justify-between gap-3">
            <div className="flex-1 min-w-0">
              <h5 className="text-sm font-bold text-gray-900 dark:text-white">{evento.titulo}</h5>
            </div>
            {/* Badge de tipo */}
            <span className={`shrink-0 inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-[10px] font-semibold ${colores.bg} ${colores.icon}`}>
              <IconoTipo className="w-3 h-3" strokeWidth={2.5} />
              {esNota
                ? (evento.metadata?.esImportante ? 'Nota Importante' : 'Nota Manual')
                : (evento.accion === 'CREATE' ? 'Creación' : evento.accion === 'UPDATE' ? 'Actualización' : 'Eliminación')
              }
            </span>
          </div>

          {/* Contenido de la nota (más prominente para notas) */}
          {esNota ? (
            <div className="mt-2 p-3 rounded-lg bg-gray-50 dark:bg-gray-800/50 border border-gray-200 dark:border-gray-700">
              <p className="text-sm text-gray-700 dark:text-gray-300 leading-relaxed whitespace-pre-wrap">
                {evento.descripcion}
              </p>
            </div>
          ) : (
            <p className="text-xs text-gray-600 dark:text-gray-400 mt-0.5">{evento.descripcion}</p>
          )}

          {/* Usuario + Fecha */}
          <div className="space-y-2 pt-2 border-t border-gray-200 dark:border-gray-700">
            {/* Usuario con label */}
            <div className="flex items-start gap-2">
              <User className="w-3.5 h-3.5 text-gray-400 shrink-0 mt-0.5" />
              <div className="flex-1 min-w-0">
                <p className="text-[10px] font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wide">Acción realizada por:</p>
                <p className="text-xs text-gray-900 dark:text-white font-medium truncate">
                  {evento.usuario.nombres || evento.usuario.email}
                  {evento.usuario.rol ? (
                    <span className="text-gray-500 dark:text-gray-400 font-normal"> ({evento.usuario.rol})</span>
                  ) : null}
                </p>
              </div>
            </div>
            {/* Fecha */}
            <div className="flex items-center gap-1.5">
              <Clock className="w-3.5 h-3.5 text-gray-400 shrink-0" />
              <span className="text-xs text-gray-600 dark:text-gray-400">
                {formatDateTimeForDisplay(evento.fecha)}
              </span>
            </div>
          </div>

          {/* Acciones de nota (editar/eliminar) - COMPACTO */}
          {esNota && puedeEditar && notaId ? (() => {
            return (
              <div className="pt-2 flex items-center gap-2">
                <motion.button
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  onClick={() => onEditarNota?.(notaId)}
                  className="flex-1 flex items-center justify-center gap-1.5 px-2 py-1 rounded-md bg-blue-50 dark:bg-blue-950/30 border border-blue-200 dark:border-blue-800 text-blue-700 dark:text-blue-400 font-medium text-[11px] transition-all"
                >
                  <Edit className="w-3 h-3" strokeWidth={2.5} />
                  Editar
                </motion.button>
                <motion.button
                  whileHover={{ scale: 1.02 }}
                  whileTap={{ scale: 0.98 }}
                  onClick={() => onEliminarNota?.(notaId)}
                  className="flex-1 flex items-center justify-center gap-1.5 px-2 py-1 rounded-md bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 font-medium text-[11px] transition-all"
                >
                  <Trash2 className="w-3 h-3" strokeWidth={2.5} />
                  Eliminar
                </motion.button>
              </div>
            )
          })() : null}

          {/* Botón detalles solo para eventos normales */}
          {!esNota && evento.detalles && evento.detalles.length > 0 ? (
            <div className="pt-2">
              <DetallesButton evento={evento} colores={colores} />
            </div>
          ) : null}
        </div>
      </motion.div>
    </motion.div>
  )
}

/**
 * DetallesButton - Botón para abrir modal de detalles
 */
interface DetallesButtonProps {
  evento: EventoHistorialHumanizado
  colores: (typeof coloresEvento)[keyof typeof coloresEvento]
}

function DetallesButton({ evento, colores }: DetallesButtonProps) {
  const [mostrarModal, setMostrarModal] = useState(false)

  return (
    <>
      <motion.button
        whileHover={{ scale: 1.02 }}
        whileTap={{ scale: 0.98 }}
        onClick={() => setMostrarModal(true)}
        className={`w-full flex items-center justify-center gap-2 px-3 py-2 rounded-lg ${colores.border} border-2 ${colores.bg} ${colores.icon} font-semibold text-xs transition-all hover:shadow-md`}
      >
        <Eye className="w-4 h-4" strokeWidth={2.5} />
        Ver detalles ({evento.detalles?.length || 0})
      </motion.button>

      <DetalleEventoModal
        isOpen={mostrarModal}
        onClose={() => setMostrarModal(false)}
        titulo="Detalles del Evento"
        subtitulo={evento.titulo}
        detalles={evento.detalles || []}
      />
    </>
  )
}

'use client'

/**
 * RebalancearModal
 *
 * Modal Admin-only para ajustar el plan financiero de una negociación.
 * Sub-componentes extraídos en ./rebalancear/
 */

import { useEffect, useMemo, useState } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import { AlertTriangle, CheckCircle2, Lock, Plus, X } from 'lucide-react'
import { createPortal } from 'react-dom'

import type { FuentePago } from '@/modules/clientes/services/fuentes-pago.service'
import { esCreditoConstructora } from '@/shared/constants/fuentes-pago.constants'
import { formatCurrency } from '@/shared/utils/format'
import {
    calcularRestriccionesFuente,
    validarRebalanceo,
} from '@/shared/utils/reglas-cierre-financiero'

import type { AjusteLocal, DatosRebalanceo, FuAlteNueva } from '../hooks'
import { MOTIVOS_AJUSTE, getFuenteColor } from '../hooks'

import type { CambioEnriquecido, NuevaEnriquecida } from './rebalancear'
import { AdvertenciaDocumentos, FilaFuente, FilaNueva } from './rebalancear'

// ============================================
// COMPONENTE PRINCIPAL
// ============================================

interface RebalancearModalProps {
  isOpen: boolean
  onClose: () => void
  fuentesPago: FuentePago[]
  valorVivienda: number
  tiposDisponibles: { nombre: string; descripcion: string; requiere_entidad?: boolean; color?: string }[]
  /** Todos los tipos activos (no solo los disponibles), para lookup de config: requiere_entidad, etc. */
  tiposConfig: { nombre: string; requiere_entidad?: boolean }[]
  /** Mapa tipo_fuente → títulos de documentos obligatorios (desde requisitos_fuentes_pago_config) */
  requisitosMap: Map<string, string[]>
  onGuardar: (datos: DatosRebalanceo) => void
  isGuardando: boolean
}

export function RebalancearModal({
  isOpen,
  onClose,
  fuentesPago,
  valorVivienda,
  tiposDisponibles,
  tiposConfig,
  requisitosMap,
  onGuardar,
  isGuardando,
}: RebalancearModalProps) {
  // ── Estado local ──────────────────────────────────────────
  const [ajustes, setAjustes] = useState<AjusteLocal[]>([])
  const [nuevas, setNuevas] = useState<FuAlteNueva[]>([])
  const [motivo, setMotivo] = useState('')
  const [notas, setNotas] = useState('')
  const [mostrarNuevaFuente, setMostrarNuevaFuente] = useState(false)

  const [mostrandoAdvertencia, setMostrandoAdvertencia] = useState(false)

  // Mapa nombre → config para lookup sin hardcodear nombres de tipos
  const tiposConfigMap = useMemo(
    () => new Map(tiposConfig.map((t) => [t.nombre, t])),
    [tiposConfig]
  )

  // Sincronizar cuando abren el modal
  useEffect(() => {
    if (!isOpen) return
    setMostrandoAdvertencia(false)
    setAjustes(
      fuentesPago.map((f) => ({
        id: f.id,
        tipo: f.tipo,
        montoOriginal: f.monto_aprobado,
        montoEditable: f.capital_para_cierre ?? f.monto_aprobado,
        entidad: f.entidad ?? '',
        entidadEditable: f.entidad ?? '',
        paraEliminar: false,
        monto_recibido: f.monto_recibido ?? 0,
        capital_para_cierre: f.capital_para_cierre,
        tienePlanCuotas: esCreditoConstructora(f.tipo) && f.capital_para_cierre !== null,
      }))
    )
    setNuevas([])
    setMotivo('')
    setNotas('')
    setMostrarNuevaFuente(false)
  }, [isOpen, fuentesPago])

  // ── Restricciones por fuente ────────────────────────────
  const restriccionesMap = useMemo(() => {
    const map = new Map<string, ReturnType<typeof calcularRestriccionesFuente>>()
    for (const a of ajustes) {
      map.set(a.id, calcularRestriccionesFuente({
        id: a.id,
        tipo: a.tipo,
        monto_aprobado: a.montoOriginal,
        capital_para_cierre: a.capital_para_cierre,
        monto_recibido: a.monto_recibido,
        tienePlanCuotas: a.tienePlanCuotas,
      }))
    }
    return map
  }, [ajustes])

  // ── Cálculos en tiempo real ───────────────────────────────
  const subtotal = useMemo(() => {
    const activas = ajustes.filter((a) => !a.paraEliminar).reduce((s, a) => {
      const r = restriccionesMap.get(a.id)
      // Para fuentes bloqueadas (crédito con plan), usar capital_para_cierre
      // Para fuentes editables, usar el valor que el usuario escribió
      const monto = r && !r.puedeEditarMonto && a.capital_para_cierre !== null
        ? a.capital_para_cierre
        : a.montoEditable
      return s + monto
    }, 0)
    const agregadas = nuevas.reduce((s, n) => s + n.monto, 0)
    return activas + agregadas
  }, [ajustes, nuevas, restriccionesMap])

  const diferencia = valorVivienda - subtotal
  const estaBalanceado = Math.abs(diferencia) < 1

  // ── Validación global antes de guardar ────────────────────
  const erroresRebalanceo = useMemo(() => {
    return validarRebalanceo(
      ajustes.map((a) => ({
        id: a.id,
        montoEditable: a.montoEditable,
        paraEliminar: a.paraEliminar,
        restricciones: restriccionesMap.get(a.id)!,
      })),
      valorVivienda,
      subtotal,
    )
  }, [ajustes, restriccionesMap, valorVivienda, subtotal])

  const motivoRequiereNotas = motivo === 'Otro'
  const puedeGuardar =
    estaBalanceado &&
    erroresRebalanceo.length === 0 &&
    motivo !== '' &&
    (!motivoRequiereNotas || notas.trim() !== '') &&
    !isGuardando

  // ── Detectar cambios que generarán requisitos de documentos ─────────────
  // Fuentes existentes que requerirán nueva documentación (solo tipos que requieren docs según BD)
  const fuentesExistentesQueInvalidan = useMemo<CambioEnriquecido[]>(() => {
    return ajustes
      .filter((a) => !a.paraEliminar)
      .filter((a) => {
        // Solo advertir para tipos que requieren documentos — desde BD, no hardcodeado
        if (!tiposConfigMap.get(a.tipo)?.requiere_entidad) return false
        const cambioEntidad = a.entidadEditable !== a.entidad
        const aumentoMonto = a.montoEditable > a.montoOriginal // disminuir NO requiere docs
        return cambioEntidad || aumentoMonto
      })
      .map((a) => {
        const cambioEntidad = a.entidadEditable !== a.entidad
        const aumentoMonto = a.montoEditable > a.montoOriginal
        const motivoCambio =
          cambioEntidad && aumentoMonto ? 'ambos' : cambioEntidad ? 'entidad' : 'monto'
        return {
          tipo: a.tipo,
          motivoCambio,
          entidadAnterior: cambioEntidad ? (a.entidad || 'Sin entidad') : undefined,
          entidadNueva: cambioEntidad ? (a.entidadEditable || 'Sin entidad') : undefined,
          montoAnterior: aumentoMonto ? a.montoOriginal : undefined,
          montoNuevo: aumentoMonto ? a.montoEditable : undefined,
          documentos: requisitosMap.get(a.tipo) ?? [],
        }
      })
  }, [ajustes, tiposConfigMap, requisitosMap])

  // Fuentes nuevas que requerirán documentación (según flag requiere_entidad de BD)
  const fuentesNuevasQueNecesitanCarta = useMemo<NuevaEnriquecida[]>(() => {
    return nuevas
      .filter((n) => tiposConfigMap.get(n.tipo)?.requiere_entidad ?? false)
      .map((n) => ({
        tipo: n.tipo,
        documentos: requisitosMap.get(n.tipo) ?? [],
      }))
  }, [nuevas, tiposConfigMap, requisitosMap])

  const hayCambiosConAdvertencia =
    fuentesExistentesQueInvalidan.length > 0 || fuentesNuevasQueNecesitanCarta.length > 0

  // ── Handlers ──────────────────────────────────────────────

  const handleCambioMonto = (id: string, monto: number) => {
    setAjustes((prev) => prev.map((a) => (a.id === id ? { ...a, montoEditable: monto } : a)))
  }

  const handleCambioEntidad = (id: string, entidad: string) => {
    setAjustes((prev) => prev.map((a) => (a.id === id ? { ...a, entidadEditable: entidad } : a)))
  }

  const handleToggleEliminar = (id: string) => {
    setAjustes((prev) =>
      prev.map((a) => (a.id === id ? { ...a, paraEliminar: !a.paraEliminar } : a))
    )
  }

  const handleAgregarTipo = (tipo: string) => {
    setNuevas((prev) => [...prev, { tipo, monto: 0, entidad: '' }])
    setMostrarNuevaFuente(false)
  }

  const handleCambioNueva = (index: number, campo: keyof FuAlteNueva, valor: string | number) => {
    setNuevas((prev) => prev.map((n, i) => (i === index ? { ...n, [campo]: valor } : n)))
  }

  const handleEliminarNueva = (index: number) => {
    setNuevas((prev) => prev.filter((_, i) => i !== index))
  }

  const handleGuardar = () => {
    if (!puedeGuardar) return
    // Si hay cambios que generan advertencia y aún no se confirmó → mostrar aviso
    if (hayCambiosConAdvertencia && !mostrandoAdvertencia) {
      setMostrandoAdvertencia(true)
      return
    }
    onGuardar({ ajustes, nuevas, motivo, notas })
  }

  // Portal fix: evitar que transforms de padres rompan position:fixed
  if (!isOpen || typeof document === 'undefined') return null

  return createPortal(
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Overlay — z-[9999] garantiza cobertura total incluyendo headers fijos */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[9999] bg-black/60 backdrop-blur-sm"
            onClick={onClose}
          />

          {/* Modal */}
          <motion.div
            initial={{ opacity: 0, y: 24, scale: 0.97 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 16, scale: 0.97 }}
            transition={{ type: 'spring', stiffness: 320, damping: 28 }}
            className="fixed inset-0 z-[9999] flex items-end sm:items-center justify-center p-0 sm:p-4"
            onClick={(e) => e.stopPropagation()}
          >
            <div className="relative w-full sm:max-w-lg bg-white dark:bg-gray-850 rounded-t-2xl sm:rounded-2xl shadow-2xl overflow-hidden flex flex-col max-h-[90dvh]">
              {/* Header */}
              <div className="bg-gradient-to-r from-cyan-600 via-blue-600 to-indigo-600 px-5 py-4 flex items-center justify-between flex-shrink-0">
                <div className="flex items-center gap-2.5">
                  <div className="w-8 h-8 rounded-lg bg-white/20 flex items-center justify-center">
                    <Lock className="w-4 h-4 text-white" />
                  </div>
                  <div>
                    <h2 className="text-base font-bold text-white leading-tight">
                      Ajustar Cierre Financiero
                    </h2>
                    <p className="text-xs text-cyan-100 mt-0.5">Solo Administrador</p>
                  </div>
                </div>
                <button
                  type="button"
                  onClick={onClose}
                  className="w-8 h-8 flex items-center justify-center rounded-lg bg-white/20 hover:bg-white/30 text-white transition-colors"
                >
                  <X className="w-4 h-4" />
                </button>
              </div>

              {/* Subheader: valor objetivo */}
              <div className="bg-gray-50 dark:bg-gray-800/60 border-b border-gray-200 dark:border-gray-700/50 px-5 py-3 flex-shrink-0">
                <p className="text-xs text-gray-500 dark:text-gray-400">Valor de la vivienda</p>
                <p className="text-xl font-bold text-gray-900 dark:text-white tabular-nums">
                  {formatCurrency(valorVivienda)}
                </p>
              </div>

              {/* Body scrollable */}
              <div className="flex-1 overflow-y-auto px-5 py-4 space-y-3">
                {/* Fuentes existentes */}
                <div className="space-y-2">
                  <p className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider">
                    Fuentes configuradas
                  </p>
                  {ajustes.map((ajuste) => (
                    <FilaFuente
                      key={ajuste.id}
                      ajuste={ajuste}
                      restricciones={restriccionesMap.get(ajuste.id)!}
                      onChange={handleCambioMonto}
                      onCambioEntidad={handleCambioEntidad}
                      onToggleEliminar={handleToggleEliminar}
                      requiereEntidad={tiposConfigMap.get(ajuste.tipo)?.requiere_entidad ?? false}
                    />
                  ))}
                </div>

                {/* Fuentes nuevas */}
                {nuevas.length > 0 && (
                  <div className="space-y-2">
                    <p className="text-xs font-semibold text-emerald-600 dark:text-emerald-400 uppercase tracking-wider">
                      Nuevas fuentes
                    </p>
                    {nuevas.map((fuente, i) => (
                      <FilaNueva
                        key={i}
                        fuente={fuente}
                        index={i}
                        onChange={handleCambioNueva}
                        onEliminar={handleEliminarNueva}
                        requiereEntidad={tiposConfigMap.get(fuente.tipo)?.requiere_entidad ?? false}
                      />
                    ))}
                  </div>
                )}

                {/* Botón agregar fuente */}
                {tiposDisponibles.length > 0 && (
                  <div>
                    {!mostrarNuevaFuente ? (
                      <button
                        type="button"
                        onClick={() => setMostrarNuevaFuente(true)}
                        className="w-full flex items-center justify-center gap-2 py-2.5 rounded-lg border-2 border-dashed border-gray-200 dark:border-gray-600 text-sm text-gray-400 dark:text-gray-500 hover:border-cyan-400 hover:text-cyan-600 dark:hover:text-cyan-400 transition-colors"
                      >
                        <Plus className="w-4 h-4" />
                        Agregar fuente de pago
                      </button>
                    ) : (
                      <div className="rounded-lg border border-cyan-200 dark:border-cyan-800/50 overflow-hidden">
                        <p className="text-xs font-semibold text-gray-500 px-3 pt-3 pb-2">
                          Seleccionar tipo de fuente:
                        </p>
                        <div className="max-h-40 overflow-y-auto divide-y divide-gray-100 dark:divide-gray-700/50">
                          {tiposDisponibles.map((tipo) => {
                            const color = getFuenteColor(tipo.nombre)
                            return (
                              <button
                                key={tipo.nombre}
                                type="button"
                                onClick={() => handleAgregarTipo(tipo.nombre)}
                                className="w-full text-left flex items-center gap-2.5 px-3 py-2.5 hover:bg-cyan-50/60 dark:hover:bg-cyan-900/10 transition-colors"
                              >
                                <span className={`w-2 h-2 rounded-full flex-shrink-0 ${color.barra}`} />
                                <div>
                                  <p className="text-sm font-medium text-gray-900 dark:text-white">
                                    {tipo.nombre}
                                  </p>
                                  {tipo.descripcion && (
                                    <p className="text-xs text-gray-400">{tipo.descripcion}</p>
                                  )}
                                </div>
                              </button>
                            )
                          })}
                        </div>
                        <div className="px-3 pb-2 pt-1 border-t border-gray-100 dark:border-gray-700/50">
                          <button
                            type="button"
                            onClick={() => setMostrarNuevaFuente(false)}
                            className="text-xs text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
                          >
                            Cancelar
                          </button>
                        </div>
                      </div>
                    )}
                  </div>
                )}

              {/* Motivo del cambio */}
                <div className="pt-1 space-y-2 border-t border-gray-100 dark:border-gray-700/50">
                  <label className="text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                    Motivo del cambio <span className="text-red-400">*</span>
                  </label>
                  <select
                    value={motivo}
                    onChange={(e) => setMotivo(e.target.value)}
                    className="w-full px-3 py-2 text-sm bg-gray-50 dark:bg-gray-700/60 border border-gray-200 dark:border-gray-600 rounded-lg focus:outline-none focus:border-cyan-500 focus:ring-2 focus:ring-cyan-500/20 text-gray-900 dark:text-white"
                  >
                    <option value="">Seleccionar motivo...</option>
                    {MOTIVOS_AJUSTE.map((m) => (
                      <option key={m} value={m}>
                        {m}
                      </option>
                    ))}
                  </select>

                  {motivoRequiereNotas && (
                    <textarea
                      value={notas}
                      onChange={(e) => setNotas(e.target.value)}
                      placeholder="Describe el motivo del cambio... (requerido)"
                      rows={2}
                      className="w-full px-3 py-2 text-sm bg-gray-50 dark:bg-gray-700/60 border border-gray-200 dark:border-gray-600 rounded-lg focus:outline-none focus:border-cyan-500 focus:ring-2 focus:ring-cyan-500/20 text-gray-900 dark:text-white placeholder:text-gray-400 resize-none"
                    />
                  )}

                  {motivo && motivo !== 'Otro' && (
                    <textarea
                      value={notas}
                      onChange={(e) => setNotas(e.target.value)}
                      placeholder="Notas adicionales (opcional)"
                      rows={2}
                      className="w-full px-3 py-2 text-sm bg-gray-50 dark:bg-gray-700/60 border border-gray-200 dark:border-gray-600 rounded-lg focus:outline-none focus:border-cyan-500 focus:ring-2 focus:ring-cyan-500/20 text-gray-900 dark:text-white placeholder:text-gray-400 resize-none"
                    />
                  )}
                </div>
              </div>

              {/* Footer fijo: balance + botones */}
              <div className="border-t border-gray-200 dark:border-gray-700 px-5 py-4 flex-shrink-0 space-y-3">
                {/* Advertencia: cambios que invalidarán cartas */}
                <AdvertenciaDocumentos
                  visible={mostrandoAdvertencia}
                  fuentesExistentes={fuentesExistentesQueInvalidan}
                  fuentesNuevas={fuentesNuevasQueNecesitanCarta}
                />

                {/* Errores de validación de montos mínimos */}
                {erroresRebalanceo.filter((e) => e.campo !== 'balance').length > 0 ? (
                  <div className="space-y-1">
                    {erroresRebalanceo
                      .filter((e) => e.campo !== 'balance')
                      .map((err) => (
                        <p
                          key={err.campo}
                          className="text-xs text-red-600 dark:text-red-400 flex items-center gap-1.5 px-3 py-1.5 bg-red-50 dark:bg-red-900/20 rounded-lg border border-red-200 dark:border-red-800/50"
                        >
                          <AlertTriangle className="w-3.5 h-3.5 flex-shrink-0" />
                          {err.mensaje}
                        </p>
                      ))}
                  </div>
                ) : null}

                {/* Balance indicator */}
                <div
                  className={`flex items-center gap-2.5 px-3.5 py-2.5 rounded-xl ${
                    estaBalanceado
                      ? 'bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800/60'
                      : 'bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800/60'
                  }`}
                >
                  {estaBalanceado ? (
                    <CheckCircle2 className="w-4 h-4 text-emerald-600 dark:text-emerald-400 flex-shrink-0" />
                  ) : (
                    <AlertTriangle className="w-4 h-4 text-red-500 dark:text-red-400 flex-shrink-0" />
                  )}
                  <div className="flex-1">
                    <div className="flex items-center justify-between">
                      <span
                        className={`text-xs font-semibold ${estaBalanceado ? 'text-emerald-700 dark:text-emerald-300' : 'text-red-600 dark:text-red-400'}`}
                      >
                        {estaBalanceado
                          ? '✅ Ecuación balanceada'
                          : diferencia > 0
                            ? `❌ Déficit: ${formatCurrency(Math.abs(diferencia))}`
                            : `❌ Excedente: ${formatCurrency(Math.abs(diferencia))}`}
                      </span>
                      <span className="text-xs text-gray-400 tabular-nums">
                        {formatCurrency(subtotal)} / {formatCurrency(valorVivienda)}
                      </span>
                    </div>
                  </div>
                </div>

                {/* Botones */}
                <div className="flex items-center gap-2.5">
                  <button
                    type="button"
                    onClick={onClose}
                    disabled={isGuardando}
                    className="flex-1 py-2.5 rounded-xl border border-gray-200 dark:border-gray-600 text-sm font-medium text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-700/40 transition-colors"
                  >
                    Cancelar
                  </button>
                  <button
                    type="button"
                    onClick={handleGuardar}
                    disabled={!puedeGuardar}
                    className={`flex-1 py-2.5 rounded-xl text-sm font-semibold transition-all ${
                      puedeGuardar
                        ? 'bg-gradient-to-r from-cyan-600 to-blue-600 hover:from-cyan-700 hover:to-blue-700 text-white shadow-lg shadow-cyan-500/25'
                        : 'bg-gray-100 dark:bg-gray-700/40 text-gray-400 dark:text-gray-500 cursor-not-allowed'
                    }`}
                  >
                    {isGuardando
                    ? 'Guardando...'
                    : mostrandoAdvertencia && hayCambiosConAdvertencia
                      ? 'Entendido, guardar'
                      : 'Guardar cambios'
                  }
                  </button>
                </div>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>,
    document.body
  )
}

/**
 * ============================================
 * COMPONENTE PRESENTACIONAL PURO: ViviendaAsignadaTab
 * ============================================
 *
 * ✅ SEPARACIÓN ESTRICTA DE RESPONSABILIDADES
 * - Componente: SOLO UI presentacional
 * - Hook: TODA la lógica (useViviendaAsignadaTab)
 *
 * Tab que muestra la vivienda asignada al cliente con:
 * - Progreso de validación de fuentes de pago
 * - Requisitos faltantes para desembolso
 * - Métricas y estados
 *
 * IMPORTANTE: Este tab NO registra desembolsos.
 * Los desembolsos se registran desde el módulo de Abonos.
 *
 * @version 2.0.0 - 2025-12-11 - Refactorizado con separación estricta
 */

'use client'

import { AlertCircle, ArrowUp, Building2, CheckCircle2, Home, IdCard, XCircle } from 'lucide-react'
import { toast } from 'sonner'

import { HistorialVersionesModal } from '@/modules/clientes/components'
import { SubirCartaModal } from '@/modules/clientes/components/fuentes-pago'
import type { Cliente } from '@/modules/clientes/types'
import {
    FuentePagoCard,
    ModalMarcarPasoCompletado
} from '@/modules/fuentes-pago/components'

import {
    AccionesSection,
    EditarFuentesPagoModal,
    MetricasDashboard,
    ProgressBarProminente,
    UltimosAbonosSection,
} from './vivienda-asignada/components'
import { useViviendaAsignadaTab } from './vivienda-asignada/hooks'
import { viviendaAsignadaTabStyles as styles } from './vivienda-asignada-tab.styles'

// ============================================
// TYPES
// ============================================

interface ViviendaAsignadaTabProps {
  cliente: Cliente
}

// ============================================
// COMPONENTE PRINCIPAL - SOLO UI
// ============================================

export function ViviendaAsignadaTab({ cliente }: ViviendaAsignadaTabProps) {
  // ✅ Hook con TODA la lógica
  const {
    // Estado
    viviendas,
    viviendaActiva,
    isLoading,
    isLoadingDetalle,
    stats,
    fuentesPago,
    abonos,
    totales,
    diasDesdeUltimoAbono,

    // Validación documento
    tieneDocumentoFisico,
    cargandoDoc,

    // Modales
    showHistorial,
    viviendaSeleccionadaId,
    modalSubirCartaOpen,
    fuenteParaCarta,
    modalMarcarPasoOpen,
    pasoSeleccionado,
    isEditarFuentesOpen,
    isGenerating,

    // Handlers
    verDetalleVivienda,
    volverALista,
    navegarAAsignarVivienda,
    navegarARegistrarAbono,
    abrirHistorial,
    cerrarHistorial,
    abrirModalSubirCarta,
    cerrarModalSubirCarta,
    handleSuccessSubirCarta,
    abrirModalMarcarPaso,
    cerrarModalMarcarPaso,
    handleConfirmarPaso,
    handleGenerarPDF,
    abrirEditarFuentes,
    cerrarEditarFuentes,
    guardarFuentes,
  } = useViviendaAsignadaTab({ cliente }) as any

  // =====================================================
  // RENDER: Loading State
  // =====================================================

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="text-center space-y-3">
          <div className="w-12 h-12 border-4 border-cyan-600 border-t-transparent rounded-full animate-spin mx-auto" />
          <p className="text-sm text-gray-600 dark:text-gray-400">
            Cargando información de vivienda...
          </p>
        </div>
      </div>
    )
  }

  // =====================================================
  // RENDER: Vista Detallada (Vivienda Activa)
  // =====================================================

  // Si tiene vivienda asignada, mostrar detalle directamente
  if (viviendas.length > 0 && !viviendaActiva) {
    // Auto-seleccionar la primera (única) vivienda
    verDetalleVivienda(viviendas[0])
    return null
  }

  if (viviendaActiva) {
    const valorFinal = viviendaActiva.valorFinal

    return (
      <div className={styles.container.detalle}>
        {/* Header */}
        <div className={styles.header.container}>
          <div>
            <h3 className={styles.header.detalleTitle}>
              <Building2 className={styles.header.detalleIcon} />
              {viviendaActiva.proyecto?.nombre || 'Proyecto'}
            </h3>
            <div className={styles.detalle.info}>
              <Home className={styles.detalle.infoIcon} />
              <span className={styles.detalle.infoText}>
                {viviendaActiva.vivienda?.manzanas?.nombre
                  ? `${viviendaActiva.vivienda.manzanas.nombre} - `
                  : ''}
                Casa {viviendaActiva.vivienda?.numero || '—'}
              </span>
              <span className={styles.detalle.separator}>•</span>
              <span
                className={`${styles.detalle.estadoBadge} ${
                  viviendaActiva.estado === 'Activa'
                    ? 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300'
                    : 'bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-300'
                }`}
              >
                {viviendaActiva.estado}
              </span>
            </div>
          </div>
        </div>

        {/* Loading detalle */}
        {isLoadingDetalle ? (
          <div className="flex items-center justify-center py-8">
            <div className="text-center space-y-2">
              <div className="w-8 h-8 border-4 border-cyan-600 border-t-transparent rounded-full animate-spin mx-auto" />
              <p className="text-xs text-gray-500">Cargando detalles...</p>
            </div>
          </div>
        ) : (
          <div className="space-y-2.5">
            {/* Acciones STICKY */}
            <div className="sticky top-0 z-20 -mx-1 px-1 pt-2 pb-3 bg-gray-50/95 dark:bg-gray-900/95 backdrop-blur-sm">
              <AccionesSection
                estado={viviendaActiva.estado}
                onRegistrarAbono={() => navegarARegistrarAbono(viviendaActiva.id)}
                onRenunciar={() => toast.info('❌ Modal de Renuncia en desarrollo')}
                onGenerarPDF={handleGenerarPDF}
                disabled={isGenerating}
              />
            </div>

            {/* Dashboard de Métricas Reorganizado */}
            <MetricasDashboard
              valorVivienda={
                (viviendaActiva.vivienda as any)?.valor_base ||
                (viviendaActiva.valor_negociado || 0) - 5000000
              }
              gastosNotariales={5000000}
              recargoEsquinera={(viviendaActiva.vivienda as any)?.recargo_esquinera || 0}
              descuento={viviendaActiva.descuento_aplicado || 0}
              valorFinal={valorFinal}
              totalPagado={totales.totalAbonado}
              totalFuentesPago={totales.totalFuentesPago}
              saldoPendiente={totales.saldoPendiente}
              fuentesCount={fuentesPago.length}
            />

            {/* Alert: Sin pagos recientes */}
            {diasDesdeUltimoAbono !== null && diasDesdeUltimoAbono > 30 ? (
              <div className="p-3 rounded-lg bg-rose-50 dark:bg-rose-900/20 border-2 border-rose-300 dark:border-rose-700">
                <div className="flex items-start gap-2">
                  <AlertCircle className="w-5 h-5 text-rose-600 dark:text-rose-400 flex-shrink-0 mt-0.5" />
                  <div className="flex-1">
                    <p className="text-sm font-semibold text-rose-900 dark:text-rose-100">
                      ⚠️ Sin pagos recientes
                    </p>
                    <p className="text-xs text-rose-700 dark:text-rose-300 mt-1">
                      Hace <strong>{diasDesdeUltimoAbono} días</strong> que no se registra un
                      abono. Considera hacer seguimiento con el cliente.
                    </p>
                  </div>
                </div>
              </div>
            ) : null}

            {/* Barra de Progreso */}
            <ProgressBarProminente
              valorTotal={valorFinal}
              totalAbonado={totales.totalAbonado}
              totalFuentesPago={totales.totalFuentesPago}
              diasDesdeUltimoAbono={diasDesdeUltimoAbono}
            />

            {/* Fuentes de Pago con Sistema de Validación */}
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold text-gray-900 dark:text-white flex items-center gap-2">
                  <Building2 className="w-5 h-5 text-cyan-600 dark:text-cyan-400" />
                  Fuentes de Pago ({fuentesPago.length})
                </h3>
                <button
                  onClick={abrirEditarFuentes}
                  className="px-3 py-1.5 text-sm font-medium text-cyan-600 dark:text-cyan-400 hover:bg-cyan-50 dark:hover:bg-cyan-900/20 rounded-lg transition-colors"
                >
                  Editar Fuentes
                </button>
              </div>

              {isLoadingDetalle ? (
                <div className="flex items-center justify-center py-8">
                  <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-cyan-600" />
                </div>
              ) : fuentesPago.length === 0 ? (
                <div className="text-center py-8 text-gray-500 dark:text-gray-400">
                  No hay fuentes de pago configuradas
                </div>
              ) : (
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                  {fuentesPago.map((fuente: any) => (
                    <div key={fuente.id} className="space-y-2">
                      <FuentePagoCard
                        fuente={{
                          id: fuente.id,
                          tipo: fuente.tipo,
                          monto_aprobado: fuente.monto,
                          monto_recibido: fuente.monto_recibido,
                          entidad: fuente.entidad,
                          numero_referencia: fuente.numero_referencia,
                        }}
                        clienteId={cliente.id}
                        onMarcarPaso={(pasoId, paso) => abrirModalMarcarPaso(paso)}
                        onVerDocumento={documentoId => {
                          toast.info(`Ver documento ${documentoId}`)
                        }}
                      />
                      {/* Comentado temporalmente - FuentePagoCard ya muestra toda la info */}
                      {/* <EstadoDocumentacionFuenteCard
                        fuentePagoId={fuente.id}
                        compacto={true}
                      /> */}
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Últimos Abonos */}
            <UltimosAbonosSection
              abonos={abonos.map((abono: any) => ({
                id: abono.id,
                monto: abono.monto,
                fecha_abono: abono.fecha_abono,
                metodo_pago: abono.metodo_pago,
                numero_recibo: abono.numero_recibo,
                observaciones: abono.observaciones,
              }))}
              onVerTodos={() => {
                toast.info(
                  `📊 Vista completa: ${abonos.length} abonos - Total: $${totales.totalAbonado.toLocaleString('es-CO')}`
                )
              }}
            />
          </div>
        )}

        {/* Modal de Editar Fuentes */}
        <EditarFuentesPagoModal
          isOpen={isEditarFuentesOpen}
          onClose={cerrarEditarFuentes}
          fuentesActuales={fuentesPago}
          valorFinal={viviendaActiva?.valorFinal || 0}
          onGuardar={guardarFuentes as any}
          viviendaNumero={
            viviendaActiva?.vivienda
              ? `${viviendaActiva.vivienda.manzanas?.nombre || ''}${viviendaActiva.vivienda.numero}`
              : undefined
          }
          clienteNombre={cliente.nombre_completo}
        />
      </div>
    )
  }

  // =====================================================
  // RENDER: Empty State (Sin vivienda asignada)
  // =====================================================

  // ✅ Validar requisitos para asignar vivienda
  const tieneNumeroCedula = cliente.numero_documento && cliente.numero_documento.trim() !== ''
  const documentoCompleto = tieneNumeroCedula && tieneDocumentoFisico

  return (
    <div className={styles.container.base}>
      {/* Empty State Premium */}
      <div className={styles.empty.container}>
        {/* Icono con gradiente */}
        <div className={styles.empty.iconWrapper}>
          <Home className={styles.empty.icon} />
        </div>

        {/* Título y descripción */}
        <h3 className={styles.empty.title}>Sin vivienda asignada</h3>
        <p className={styles.empty.description}>
          Este cliente aún no tiene una vivienda asignada. Para poder asignar una vivienda
          y gestionar el proceso de compra, asegúrate de completar los requisitos necesarios.
        </p>

        {/* Checklist de requisitos */}
        <div className={styles.empty.checklistContainer}>
          <div className={styles.empty.checklistHeader}>
            <IdCard className="w-4 h-4" />
            <span>Requisitos para asignar vivienda</span>
          </div>

          <div className={styles.empty.checklistItems}>
            {/* Requisito 1: Número de documento */}
            <div className={styles.empty.checklistItem}>
              {tieneNumeroCedula ? (
                <CheckCircle2 className={styles.empty.checklistIconSuccess} />
              ) : (
                <XCircle className={styles.empty.checklistIconPending} />
              )}
              <div className="flex-1">
                <p className={tieneNumeroCedula ? styles.empty.checklistTextSuccess : styles.empty.checklistTextPending}>
                  Número de documento registrado
                </p>
                {!tieneNumeroCedula && (
                  <p className={styles.empty.checklistSubtext}>
