/**
 * ============================================
 * HOOK: useEditarFuentesPago
 * ============================================
 *
 * ✅ LÓGICA DE NEGOCIO PARA EDITAR FUENTES
 * Maneja el estado del modal y la actualización de fuentes en DB.
 *
 * Features:
 * - State management del modal
 * - Transformación de datos para API
 * - Manejo de errores
 * - Invalidación de cache React Query
 *
 * @version 1.0.0 - 2025-11-28
 */

import { useState } from 'react'

import { useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { logger } from '@/lib/utils/logger'
import { negociacionesQueryKeys } from '@/modules/clientes/hooks/useNegociacionesQuery'
import { negociacionesService } from '@/modules/clientes/services/negociaciones.service'

import type { FuentePagoEditable } from '../components/EditarFuentesPagoModal'

// ============================================
// TYPES
// ============================================

interface UseEditarFuentesPagoProps {
  negociacionId: string
}

// ============================================
// HOOK
// ============================================

export function useEditarFuentesPago({ negociacionId }: UseEditarFuentesPagoProps) {
  const queryClient = useQueryClient()
  const [isModalOpen, setIsModalOpen] = useState(false)

  // =====================================================
  // HANDLERS
  // =====================================================

  const abrirModal = () => {
    setIsModalOpen(true)
  }

  const cerrarModal = () => {
    setIsModalOpen(false)
  }

  const guardarFuentes = async (fuentes: FuentePagoEditable[], motivoCambio: string) => {
    try {
      // Transformar datos para API
      const fuentesParaGuardar = fuentes.map((f) => ({
        id: f.id, // undefined si es nueva
        tipo: f.tipo,
        monto_aprobado: f.monto, // ✅ Mapear monto → monto_aprobado
        entidad: f.entidad || null,
        numero_referencia: f.numero_referencia || null,
        detalles: (f as any).detalles || null,
      }))

      // Llamar al service CON MOTIVO
      await negociacionesService.actualizarFuentesPago(
        negociacionId,
        fuentesParaGuardar,
        motivoCambio // ✅ Nuevo parámetro obligatorio
      )

      // Invalidar cache para refrescar datos inmediatamente
      await queryClient.invalidateQueries({
        queryKey: negociacionesQueryKeys.fuentesPago(negociacionId),
      })

      // También invalidar el detalle de la negociación (por si acaso)
      await queryClient.invalidateQueries({
        queryKey: negociacionesQueryKeys.detalle(negociacionId),
      })

      toast.success('Fuentes de pago actualizadas correctamente')
    } catch (error) {
      logger.error('Error al actualizar fuentes:', error)
      toast.error('Error al guardar las fuentes de pago')
      throw error
    }
  }

  // =====================================================
  // RETURN
  // =====================================================

  return {
    isModalOpen,
    abrirModal,
    cerrarModal,
    guardarFuentes,
  }
}

/**
 * ============================================
 * HOOK: useViviendaAsignadaTab
 * ============================================
 *
 * ✅ TODA LA LÓGICA DE NEGOCIO
 * Hook principal con toda la lógica del tab de Vivienda Asignada.
 *
 * SEPARACIÓN ESTRICTA:
 * - Hook: Lógica + Estado + Queries + Handlers
 * - Componente: SOLO UI presentacional
 *
 * @version 1.0.0 - 2025-12-11
 */

import { useState } from 'react'

import { toast } from 'sonner'

import { useRouter } from 'next/navigation'

import { logger } from '@/lib/utils/logger'
import { construirURLCliente } from '@/lib/utils/slug.utils'
import { useDocumentoIdentidad } from '@/modules/clientes/documentos/hooks/useDocumentoIdentidad'
import {
    useGenerarReportePDF
} from '@/modules/clientes/hooks'
import {
    useNegociacionDetalle,
    useNegociacionesQuery,
    type NegociacionConValores,
} from '@/modules/clientes/hooks/useNegociacionesQuery'
import type { Cliente } from '@/modules/clientes/types'

import { useEditarFuentesPago } from './useEditarFuentesPago'

// ============================================
// TYPES
// ============================================

interface UseViviendaAsignadaTabProps {
  cliente: Cliente
}

// ============================================
// HOOK
// ============================================

export function useViviendaAsignadaTab({ cliente }: UseViviendaAsignadaTabProps) {
  const router = useRouter()

  // =====================================================
  // REACT QUERY: Lista de negociaciones
  // =====================================================

  const { negociaciones, isLoading, stats, invalidarNegociaciones } = useNegociacionesQuery({
    clienteId: cliente.id,
  })

  // =====================================================
  // VALIDACIÓN: Documento de identidad
  // =====================================================

  const { tieneCedula: tieneDocumentoFisico, cargando: cargandoDoc } = useDocumentoIdentidad({
    clienteId: cliente.id
  })

  // =====================================================
  // ESTADO LOCAL: UI y modales
  // =====================================================

  const [viviendaActiva, setViviendaActiva] = useState<NegociacionConValores | null>(null)
  const [showHistorial, setShowHistorial] = useState(false)
  const [viviendaSeleccionadaId, setViviendaSeleccionadaId] = useState<string | null>(null)

  // Modal de subir carta
  const [modalSubirCartaOpen, setModalSubirCartaOpen] = useState(false)
  const [fuenteParaCarta, setFuenteParaCarta] = useState<{
    id: string
    tipo: string
    entidad?: string
    monto_aprobado: number
    vivienda?: { numero: string; manzana: string }
    cliente?: { nombre_completo: string }
  } | null>(null)

  // Modal de marcar paso completado
  const [modalMarcarPasoOpen, setModalMarcarPasoOpen] = useState(false)
  const [pasoSeleccionado, setPasoSeleccionado] = useState<Record<string, unknown> | null>(null)

  // =====================================================
  // REACT QUERY: Detalle de vivienda activa
  // =====================================================

  const {
    fuentesPago,
    abonos,
    totales,
    diasDesdeUltimoAbono,
    isLoading: isLoadingDetalle,
  } = useNegociacionDetalle({
    negociacionId: viviendaActiva?.id || null,
    enabled: !!viviendaActiva,
  })

  // =====================================================
  // HOOKS: PDF y Edición
  // =====================================================

  const { generarReporte, isGenerating } = useGenerarReportePDF()

  const {
    isModalOpen: isEditarFuentesOpen,
    abrirModal: abrirEditarFuentes,
    cerrarModal: cerrarEditarFuentes,
    guardarFuentes,
  } = useEditarFuentesPago({
    negociacionId: viviendaActiva?.id || '',
  })

  // =====================================================
  // HANDLERS: Navegación y vistas
  // =====================================================

  const verDetalleVivienda = (vivienda: NegociacionConValores) => {
    setViviendaActiva(vivienda)
  }

  const volverALista = () => {
    setViviendaActiva(null)
  }

  const abrirHistorial = (viviendaId: string) => {
    setViviendaSeleccionadaId(viviendaId)
    setShowHistorial(true)
  }

  const cerrarHistorial = () => {
    setShowHistorial(false)
    setViviendaSeleccionadaId(null)
  }

  const handleGenerarPDF = async () => {
    if (!viviendaActiva) return

    try {
      await generarReporte({
        cliente,
        negociacion: viviendaActiva as any,
        fuentesPago,
        abonos,
        totales,
      })
    } catch (error) {
      logger.error('Error generando PDF:', error)
    }
  }

  // =====================================================
  // HANDLERS: Modal de carta de aprobación
  // =====================================================

  const abrirModalSubirCarta = (fuenteId: string) => {
    const fuente = fuentesPago.find(f => f.id === fuenteId)
    if (!fuente) return

    const datosParaModal = {
      id: fuente.id,
      tipo: fuente.tipo,
      entidad: fuente.entidad,
      monto_aprobado: fuente.monto,
      vivienda: viviendaActiva?.vivienda
        ? {
            numero: viviendaActiva.vivienda.numero || 'â€”',
            manzana: viviendaActiva.vivienda.manzanas?.nombre || '',
          }
        : undefined,
      cliente: {
        nombre_completo:
          cliente.nombre_completo || `${cliente.nombres} ${cliente.apellidos}`,
      },
    }

    setFuenteParaCarta(datosParaModal)
    setModalSubirCartaOpen(true)
  }

  const cerrarModalSubirCarta = () => {
    setModalSubirCartaOpen(false)
    setFuenteParaCarta(null)
  }

  const handleSuccessSubirCarta = () => {
    invalidarNegociaciones()
  }

  // =====================================================
  // HANDLERS: Modal de marcar paso completado
  // =====================================================

  const abrirModalMarcarPaso = (paso: Record<string, unknown>) => {
    setPasoSeleccionado(paso)
    setModalMarcarPasoOpen(true)
  }

  const cerrarModalMarcarPaso = () => {
    setModalMarcarPasoOpen(false)
    setPasoSeleccionado(null)
  }

  const handleConfirmarPaso = async (datos: { fecha_completado: string; documento_id?: string; observaciones?: string }) => {
    try {
      // TODO: Llamar mutation para marcar paso
      toast.info('✅ Paso marcado como completado')
      cerrarModalMarcarPaso()
      invalidarNegociaciones()
    } catch (error) {
      logger.error('Error marcando paso:', error)
      toast.info('❌ Error al marcar paso')
    }
  }

  // =====================================================
  // HANDLERS: Navegación externa
  // =====================================================

  const navegarAAsignarVivienda = () => {
    const clienteSlug = construirURLCliente({
      id: cliente.id,
      nombre_completo: cliente.nombre_completo,
      nombres: cliente.nombres,
      apellidos: cliente.apellidos,
    })
      .split('/')
      .pop()

    const nombreCliente = cliente.nombre_completo || cliente.nombres || ''
    router.push(
      `/clientes/${clienteSlug}/asignar-vivienda?nombre=${encodeURIComponent(nombreCliente)}` as any
    )
  }

  const navegarARegistrarAbono = (viviendaId: string) => {
    const nombreCliente = cliente.nombre_completo || cliente.nombres || ''
    router.push(
      `/abonos?cliente_id=${cliente.id}&negociacion_id=${viviendaId}&cliente_nombre=${encodeURIComponent(nombreCliente)}` as any
    )
  }

  // =====================================================
  // RETURN: Estado y handlers
  // =====================================================

  return {
    // Estado de datos
    viviendas: negociaciones,
    viviendaActiva,
    isLoading,
    isLoadingDetalle,
    stats,

    // Detalle de vivienda activa
    fuentesPago,
    abonos,
    totales,
    diasDesdeUltimoAbono,

    // Modal de historial
    showHistorial,
    viviendaSeleccionadaId,

    // Modal de carta
    modalSubirCartaOpen,
    fuenteParaCarta,

    // Modal de marcar paso
    modalMarcarPasoOpen,
    pasoSeleccionado,

    // Modal de editar fuentes
    isEditarFuentesOpen,

    // PDF
    isGenerating,

    // Handlers - Navegación
    verDetalleVivienda,
    volverALista,
    navegarAAsignarVivienda,
    navegarARegistrarAbono,

    // Handlers - Modales
    abrirHistorial,
    cerrarHistorial,
    abrirModalSubirCarta,
    cerrarModalSubirCarta,
    handleSuccessSubirCarta,
    abrirModalMarcarPaso,
    cerrarModalMarcarPaso,
    handleConfirmarPaso,

    // Handlers - Acciones
    handleGenerarPDF,
    abrirEditarFuentes,
    cerrarEditarFuentes,
    guardarFuentes,
  }
}

'use client'

import { Suspense, useEffect, useRef, useState } from 'react'

import { motion } from 'framer-motion'
import { AlertCircle, Eye, EyeOff, Lock, Mail } from 'lucide-react'

import Image from 'next/image'
import { useSearchParams } from 'next/navigation'






import { loginStyles } from './page.styles'
import { ResetPasswordModal } from './reset-password-modal'
import { useLogin } from './useLogin'

const { classes: s, texts: t, animations: a, inlineStyles } = loginStyles

function LoginForm() {
  const {
    email,
    password,
    loading,
    error,
    estaBloqueado,
    minutosRestantes,
    intentosRestantes,
    loginExitoso,
    mensajeExito,
    recordarUsuario,
    navegando, // ✅ Estado de navegación
    setEmail,
    setPassword,
    setRecordarUsuario,
    handleSubmit,
  } = useLogin()

  const [showResetPassword, setShowResetPassword] = useState(false)
  const [showPassword, setShowPassword] = useState(false)

  // ✅ Refs para autofocus inteligente
  const emailInputRef = useRef<HTMLInputElement>(null)
  const passwordInputRef = useRef<HTMLInputElement>(null)





  // ✅ Autofocus inteligente: Si hay email guardado -> password, si no -> email
  useEffect(() => {
    // Esperar a que recordarUsuario y email estén inicializados desde el hook
    const timer = setTimeout(() => {
      if (recordarUsuario && email) {
        // Si hay email guardado, hacer foco en la contraseña
        passwordInputRef.current?.focus()
      } else {
        // Si no hay email guardado, hacer foco en el email
        emailInputRef.current?.focus()
      }
    }, 150) // Aumentar el delay para asegurar que el hook haya cargado el email

    return () => clearTimeout(timer)
  }, [recordarUsuario, email]) // ✅ Ejecutar cuando recordarUsuario o email cambien





  // Mostrar toast cuando login es exitoso
  // ❌ DESACTIVADO: Ahora usamos toast moderno personalizado en useLogin.ts
  // useEffect(() => {
  //   if (loginExitoso) {
  //     setShowToast(true)
  //   }
  // }, [loginExitoso])



  return (
    <div className={s.container}>
      {/* Fondo personalizado - FULL WIDTH */}
      <div className={s.backgroundWrapper}>
        <Image
          src='/images/fondo-login.png'
          alt='Fondo RyR Constructora'
          fill
          sizes='100vw'
          className={s.backgroundImage}
          priority
          fetchPriority="low"
          quality={90}
        />
        {/* Overlay oscuro para mejorar legibilidad */}
        <div className={s.overlay} />
      </div>

      {/* Contenido del login - ABSOLUTAMENTE CENTRADO */}
      <div className={s.content}>
        {/* Branding - Logo principal centrado */}
        <motion.div {...a.branding} className={s.brandingContainer}>
          {/* Logo principal - versión dark optimizada */}
          <div className={s.logo1Container}>
            <Image
              src='/images/logo1-dark.png'
              alt='Logo RyR Constructora'
              fill
              sizes='(max-width: 640px) 280px, (max-width: 1024px) 400px, 600px'
              className={s.logo1Image}
              style={inlineStyles.logo1Filter}
              priority
              fetchPriority="high"
            />
          </div>

          <h2 className={s.mainTitle}>{t.systemTitle}</h2>
        </motion.div>

        {/* Formulario - Centrado debajo de los logos */}
        <motion.div {...a.form} className={s.formWrapper}>
          <div className={s.formCard}>
            {/* Logo secundario dentro del formulario */}
            <div className={s.logo2Container}>
              <Image
                src='/images/logo2-dark.png'
                alt='Logo RyR Constructora 2'
                fill
                sizes='(max-width: 768px) 100vw, 600px'
                className={s.logo2Image}
                style={inlineStyles.logo2Filter}
              />
            </div>

            <div className={s.formHeader}>
              <h1 className={s.formTitle}>{t.welcome}</h1>
              <p className={s.formSubtitle}>{t.loginSubtitle}</p>
            </div>

            <form onSubmit={handleSubmit} className={s.form}>
              <div>
                <label className={s.label}>{t.emailLabel}</label>
                <div className={s.inputGroup}>
                  <div className={s.iconWrapper}>
                    <Mail className={s.icon} />
                  </div>
                  <input
                    ref={emailInputRef}
                    type='email'
                    value={email}
                    onChange={e => setEmail(e.target.value)}
                    disabled={loading || loginExitoso}
                    className={s.inputWithIcon}
                    style={inlineStyles.emailInput}
                    placeholder={t.emailPlaceholder}
                    required
                  />
                </div>
              </div>

              <div>
                <label className={s.label}>{t.passwordLabel}</label>
                <div className={s.inputGroup}>
                  <div className={s.iconWrapper}>
                    <Lock className={s.icon} />
                  </div>
                  <input
                    ref={passwordInputRef}
                    type={showPassword ? 'text' : 'password'}
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    disabled={loading || loginExitoso}
                    className={s.passwordInput}
                    placeholder={t.passwordPlaceholder}
                    required
                    minLength={6}
                  />
                  <button
                    type='button'
                    onClick={() => setShowPassword(!showPassword)}
                    className={s.togglePasswordBtn}
                    tabIndex={-1}
                  >
                    {showPassword ? <EyeOff className={s.icon} /> : <Eye className={s.icon} />}
                  </button>
                </div>
              </div>

              {/* Recordar usuario */}
              <div className={s.checkboxContainer}>
                <input
                  type='checkbox'
                  id='recordar-usuario'
                  checked={recordarUsuario}
                  onChange={e => setRecordarUsuario(e.target.checked)}
                  className={s.checkbox}
                />
                <label htmlFor='recordar-usuario' className={s.checkboxLabel}>
                  {t.rememberMe}
                </label>
              </div>

              {error && (
                <motion.div
                  {...a.error}
                  className={`${s.errorContainer} ${
                    estaBloqueado
                      ? s.errorBlocked
                      : intentosRestantes <= 2 && intentosRestantes > 0
                        ? s.errorWarning
                        : s.errorNormal
                  }`}
                >
                  <div
                    className={`${s.errorIconWrapper} ${
                      estaBloqueado
                        ? s.errorIconBgBlocked
                        : intentosRestantes <= 2 && intentosRestantes > 0
                          ? s.errorIconBgWarning
