                        strokeLinecap='round'
                        strokeLinejoin='round'
                        strokeWidth={2}
                        d='M5 13l4 4L19 7'
                      />
                    </svg>
                    {t.loginSuccess}
                  </span>
                ) : loading ? (
                  <span className={s.submitContent}>
                    <svg
                      className={s.spinner}
                      xmlns='http://www.w3.org/2000/svg'
                      fill='none'
                      viewBox='0 0 24 24'
                    >
                      <circle
                        className='opacity-25'
                        cx='12'
                        cy='12'
                        r='10'
                        stroke='currentColor'
                        strokeWidth='4'
                      ></circle>
                      <path
                        className='opacity-75'
                        fill='currentColor'
                        d='M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z'
                      ></path>
                    </svg>
                    {t.validating}
                  </span>
                ) : estaBloqueado ? (
                  `${t.blockedPrefix}${minutosRestantes}${t.blockedSuffix}`
                ) : (
                  t.loginButton
                )}
              </button>
            </form>

            <div className={s.resetPasswordContainer}>
              <button onClick={() => setShowResetPassword(true)} className={s.resetPasswordBtn}>
                {t.forgotPassword}
              </button>
            </div>
          </div>
        </motion.div>
      </div>

      {/* Modal de Reset Password */}
      <ResetPasswordModal
        isOpen={showResetPassword}
        onClose={() => setShowResetPassword(false)}
      />

      {/* ❌ OVERLAY REMOVIDO - Usamos spinner inline en el botón */}

      {/* ❌ TOAST VIEJO DESACTIVADO - Ahora usamos toast moderno en useLogin.ts */}
      {/* <Toast
        show={showToast}
        message={mensajeExito}
        onClose={() => setShowToast(false)}
        type="success"
        duration={2000}
      /> */}
    </div>
  )
}

