/**
 * ============================================
 * AUTH CONTEXT - Refactorizado con React Query
 * ============================================
 *
 * Context de autenticaci�n que usa React Query internamente.
 * Mantiene la misma API para compatibilidad con c�digo existente.
 *
 * BENEFICIOS:
 * - ? Cache autom�tico de sesi�n y perfil
 * - ? Invalidaci�n inteligente
 * - ? Sin problemas de closures
 * - ? Estados de carga precisos
 * - ? Refetch autom�tico en background
 */

'use client'

import { createContext, useContext } from 'react'

import type { User } from '@supabase/supabase-js'

import {
    useAuthPerfilQuery,
    useAuthSessionQuery,
    useAuthUserQuery,
    useLoginMutation,
    useLogoutMutation,
    type Perfil,
} from '@/hooks/auth'
import { debugLog, errorLog, successLog } from '@/lib/utils/logger'


// ============================================
// TYPES
// ============================================

interface AuthContextType {
  user: User | null
  perfil: Perfil | null
  loading: boolean
  signIn: (email: string, password: string) => Promise<unknown>
  signOut: () => Promise<void>
}

// ============================================
// CONTEXT
// ============================================

const AuthContext = createContext<AuthContextType | undefined>(undefined)

// ============================================
// PROVIDER
// ============================================

export function AuthProvider({ children }: { children: React.ReactNode }) {
  // Queries de React Query
  const { data: session, isLoading: sessionLoading } = useAuthSessionQuery()
  const { data: user, isLoading: userLoading } = useAuthUserQuery()
  const { data: perfil, isLoading: perfilLoading } = useAuthPerfilQuery(user?.id)

  // Mutaciones
  const loginMutation = useLoginMutation()
  const logoutMutation = useLogoutMutation()

  // ============================================
  // SIGN IN - Wrapper para mantener API
  // ============================================

  const signIn = async (email: string, password: string) => {
    debugLog('?? AuthContext.signIn() invocado', { email })

    try {
      const result = await loginMutation.mutateAsync({ email, password })
      successLog('Login mutation completado')
      return result
    } catch (error) {
      errorLog('auth-context-signin', error, { email })
      throw error
    }
  }

  // ============================================
  // SIGN OUT - Wrapper para mantener API
  // ============================================

  const signOut = async () => {
    debugLog('?? AuthContext.signOut() invocado')
    try {
      await logoutMutation.mutateAsync()
      successLog('Logout completado desde AuthContext')
    } catch (error) {
      errorLog('auth-context-signout', error)
      throw error
    }
  }

  // ============================================
  // LOADING STATE
  // ============================================

  const loading = sessionLoading || userLoading || perfilLoading

  // ============================================
  // CONTEXT VALUE
  // ============================================

  const value: AuthContextType = {
    user: user ?? null,
    perfil: perfil ?? null,
    loading,
    signIn,
    signOut,
  }

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  )
}

// ============================================
// HOOK
// ============================================

export function useAuth() {
  const context = useContext(AuthContext)
  if (context === undefined) {
    throw new Error('useAuth debe usarse dentro de AuthProvider')
  }
  return context
}

// Re-export Perfil type para compatibilidad
export type { Perfil }

/**
 * ============================================
 * REACT QUERY: Autenticación - Mutations
 * ============================================
 *
 * Mutaciones de React Query para login, logout y gestión de sesión.
 * Invalida automáticamente las queries relacionadas.
 */

'use client'

import { useMutation, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { createClient } from '@/lib/supabase/client'
import { debugLog, errorLog, successLog, warnLog } from '@/lib/utils/logger'

import { authKeys } from './useAuthQuery'

const supabase = createClient()

// ============================================
// MUTATION: Login
// ============================================

interface LoginCredentials {
  email: string
  password: string
}

/**
 * Mutación para iniciar sesión
 * Invalida queries de auth después del login exitoso
 */
export function useLoginMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async ({ email, password }: LoginCredentials) => {
      debugLog('ðŸ” Login mutation iniciado', { email })

      // 1. Iniciar sesión con Supabase Auth
      const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
        email,
        password,
      })

      debugLog('ðŸ“¥ Respuesta de Supabase Auth', {
        hasUser: !!authData?.user,
        hasSession: !!authData?.session,
      })

      if (authError) {
        errorLog('login-mutation-auth', authError, { email })
        throw authError
      }
      if (!authData.user) {
        const error = new Error('No se pudo obtener el usuario')
        errorLog('login-mutation-no-user', error, { email })
        throw error
      }

      successLog('Usuario autenticado con Supabase')

      // 2. Obtener perfil del usuario
      const { data: perfilData, error: perfilError } = await supabase
        .from('usuarios')
        .select('*')
        .eq('id', authData.user.id)
        .single()

      debugLog('ðŸ“¥ Perfil obtenido', {
        hasPerfil: !!perfilData,
        rol: perfilData?.rol,
      })

      if (perfilError) {
        errorLog('login-mutation-perfil', perfilError, { userId: authData.user.id })
        throw perfilError
      }

      // ✅ 3. Sincronizar permisos al JWT (async, no bloquea login)
      try {
        const syncResponse = await fetch('/api/auth/sync-permisos', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            userId: authData.user.id,
            rol: perfilData.rol,
          }),
        })

        if (syncResponse.ok) {
          successLog('Permisos sincronizados al JWT')
        } else {
          warnLog('Error sincronizando permisos (no crítico)', { status: syncResponse.status })
        }
      } catch (error) {
        warnLog('Error sincronizando permisos (no crítico)', error)
      }

      debugLog('ðŸŽ‰ Login mutation completado exitosamente')

      return {
        session: authData.session,
        user: authData.user,
        perfil: perfilData,
      }
    },
    onSuccess: (data) => {
      debugLog('✅ Login mutation onSuccess ejecutado')

      // ✅ LIMPIAR TODOS LOS TOASTS anteriores (especialmente "Sesión cerrada")
      toast.dismiss()

      // Invalidar todas las queries de autenticación
      queryClient.invalidateQueries({ queryKey: authKeys.all })

      // Establecer datos en cache inmediatamente
      queryClient.setQueryData(authKeys.session(), data.session)
      queryClient.setQueryData(authKeys.user(), data.user)
      queryClient.setQueryData(authKeys.perfil(data.user.id), data.perfil)

      successLog(`Login exitoso: ${data.user.email}`)
    },
    onError: (error: Error) => {
      errorLog('login-mutation-general', error)
    },
  })
}

// ============================================
// MUTATION: Logout
// ============================================

/**
 * Mutación para cerrar sesión
 * Limpia todo el cache de autenticación
 * NOTA: No maneja navegación ni toasts (responsabilidad del hook useLogout)
 */
export function useLogoutMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async () => {
      debugLog('ðŸ” Ejecutando supabase.auth.signOut()...')
      const { error } = await supabase.auth.signOut()
      if (error) {
        errorLog('logout-mutation', error)
        throw error
      }
      successLog('SignOut ejecutado correctamente')
    },
    onSuccess: () => {
      debugLog('🧹 Limpiando cache de autenticación...')

      // Limpiar TODAS las queries de autenticación
      queryClient.removeQueries({ queryKey: authKeys.all })

      // Resetear cache completo (opcional, pero recomendado)
      queryClient.clear()

      successLog('Cache de autenticación limpiado')
    },
    onError: (error: Error) => {
      errorLog('logout-mutation-error', error)
    },
  })
}

// ============================================
// MUTATION: Actualizar Perfil
// ============================================

interface UpdatePerfilData {
  nombres?: string
  apellidos?: string
  debe_cambiar_password?: boolean
}

/**
 * Mutación para actualizar el perfil del usuario
 * Usa optimistic updates para mejor UX
 */
export function useUpdatePerfilMutation(userId: string) {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async (updates: UpdatePerfilData) => {
      const { data, error } = await supabase
        .from('usuarios')
        .update(updates)
        .eq('id', userId)
        .select()
        .single()

      if (error) throw error
      return data
    },
    onMutate: async (updates) => {
      // Cancelar queries en progreso
      await queryClient.cancelQueries({ queryKey: authKeys.perfil(userId) })

      // Snapshot del valor anterior
      const previousPerfil = queryClient.getQueryData(authKeys.perfil(userId))

      // Actualización optimista
      queryClient.setQueryData(authKeys.perfil(userId), (old: any) => ({
        ...old,
        ...updates,
      }))

      return { previousPerfil }
    },
    onError: (err, updates, context) => {
      // Revertir en caso de error
      if (context?.previousPerfil) {
        queryClient.setQueryData(authKeys.perfil(userId), context.previousPerfil)
      }
      logger.error('❌ Error actualizando perfil:', err)
    },
    onSuccess: () => {
      // Invalidar para refetch
      queryClient.invalidateQueries({ queryKey: authKeys.perfil(userId) })
    },
  })
}

// ============================================
// MUTATION: Refrescar Sesión
// ============================================

/**
 * Mutación para refrescar la sesión actual
 * Útil cuando el token está por expirar
 */
export function useRefreshSessionMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async () => {
      const { data, error } = await supabase.auth.refreshSession()
      if (error) throw error
      return data.session
    },
    onSuccess: (session) => {
      queryClient.setQueryData(authKeys.session(), session)
    },
    onError: (error: Error) => {
      logger.error('❌ Error refrescando sesión:', error.message)
    },
  })
}

/**
 * ============================================
 * HOOK: useLogout - Lógica de Cierre de Sesión
 * ============================================
 *
 * Hook personalizado que maneja toda la lógica de logout.
 * Separación de responsabilidades: SOLO lógica, sin UI.
 *
 * CARACTERÍSTICAS:
 * - ✅ Estado de loading (isLoggingOut)
 * - ✅ Invalidación de queries antes de logout
 * - ✅ Toasts con feedback visual completo
 * - ✅ Logging profesional
 * - ✅ router.replace() en lugar de push()
 * - ✅ Error handling robusto
 * - ✅ Callbacks opcionales (onBeforeLogout, onAfterLogout)
 * - ✅ Confirmación opcional
 */

'use client'

import { useCallback, useState } from 'react'

import { useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { useRouter } from 'next/navigation'

import {
  showLoggingOutToast,
  showLogoutErrorToast,
  showLogoutToast
} from '@/components/toasts/custom-toasts'
import { debugLog, errorLog, successLog } from '@/lib/utils/logger'

import { useLogoutMutation } from './useAuthMutations'

// ============================================
// TYPES
// ============================================

interface UseLogoutOptions {
  /** Mostrar confirmación antes de cerrar sesión */
  requireConfirmation?: boolean
  /** Mostrar toast de despedida */
  showToast?: boolean
  /** Ruta de redirección (default: /login) */
  redirectTo?: string
  /** Callback antes de logout (útil para guardar estado) */
  onBeforeLogout?: () => void | Promise<void>
  /** Callback después de logout exitoso */
  onAfterLogout?: () => void
}

interface UseLogoutReturn {
  /** Función para ejecutar logout */
  logout: () => Promise<void>
  /** Estado de loading durante logout */
  isLoggingOut: boolean
}

// ============================================
// HOOK
// ============================================

/**
 * Hook para manejar logout con feedback completo
 *
 * @example
 * ```tsx
 * const { logout, isLoggingOut } = useLogout({
 *   showToast: true,
 *   redirectTo: '/login'
 * })
 *
 * <button onClick={logout} disabled={isLoggingOut}>
 *   {isLoggingOut ? 'Cerrando...' : 'Cerrar sesión'}
 * </button>
 * ```
 */
export function useLogout(options: UseLogoutOptions = {}): UseLogoutReturn {
  const {
    requireConfirmation = false,
    showToast = true,
    redirectTo = '/login',
    onBeforeLogout,
    onAfterLogout,
  } = options

  const router = useRouter()
  const queryClient = useQueryClient()
  const logoutMutation = useLogoutMutation()
  const [isLoggingOut, setIsLoggingOut] = useState(false)

  /**
   * Ejecutar logout con feedback completo
   */
  const logout = useCallback(async () => {
    // Evitar múltiples ejecuciones simultáneas
    if (isLoggingOut) {
      debugLog('⚠️ Logout ya en progreso, ignorando nueva invocación')
      return
    }

    // Confirmación (si está habilitada)
    if (requireConfirmation) {
      const confirmed = window.confirm('¿Estás seguro de que quieres cerrar sesión?')
      if (!confirmed) {
        debugLog('❌ Logout cancelado por el usuario')
        return
      }
    }

    try {
      setIsLoggingOut(true)
      debugLog('🚪 Iniciando proceso de logout...', { redirectTo, showToast })

      // Callback pre-logout (ej: guardar estado, cancelar requests)
      if (onBeforeLogout) {
        debugLog('🔄 Ejecutando callback pre-logout...')
        await onBeforeLogout()
      }

      // Toast de loading (solo si showToast está habilitado)
      let loadingToastId: string | number | undefined
      if (showToast) {
        loadingToastId = showLoggingOutToast()
      }

      // ✅ ORDEN CORRECTO:
      // 1. Logout en Supabase (limpia cookies del servidor)
      debugLog('🔐 Ejecutando signOut en Supabase...')
      await logoutMutation.mutateAsync()
      // El mutation ya hace queryClient.clear() en onSuccess

      // 2. Limpiar almacenamiento local
      debugLog('🧹 Limpiando localStorage y sessionStorage...')
      localStorage.removeItem('supabase.auth.token')
      sessionStorage.clear()

      // Limpiar toast de loading
      if (loadingToastId) {
        toast.dismiss(loadingToastId)
      }

      // Toast de éxito (despedida)
      if (showToast) {
        showLogoutToast()
      }

      successLog('Logout completado exitosamente')

      // Callback post-logout
      if (onAfterLogout) {
        debugLog('✅ Ejecutando callback post-logout...')
        onAfterLogout()
      }

      // Navegación (usar replace para evitar volver atrás)
      debugLog(`🧭 Redirigiendo a ${redirectTo} (replace)...`)

      // ✅ SOLUCIÓN DEFINITIVA: Hard reload para garantizar estado limpio
      // window.location.href fuerza recarga completa, limpiando TODO el estado de React
      window.location.href = redirectTo

    } catch (error) {
      errorLog('logout-hook', error)

      // Toast de error
      if (showToast) {
        showLogoutErrorToast()
      }

      // Re-lanzar error para que el componente pueda manejarlo si es necesario
      throw error
    } finally {
      setIsLoggingOut(false)
    }
  }, [
    isLoggingOut,
    requireConfirmation,
    showToast,
    redirectTo,
    onBeforeLogout,
    onAfterLogout,
    queryClient,
    logoutMutation,
    router,
  ])

  return {
    logout,
    isLoggingOut,
  }
}

/**
 * ============================================
 * HOOK: Sistema Profesional de Inactividad
 * ============================================
 *
 * Sistema de nivel enterprise con:
 * - ⚠️ Advertencias escalonadas (3 niveles)
 * - 🔔 Modal de advertencia final con countdown
 * - 📊 Tracking detallado de actividad
 * - 🔄 Sistema de "keep alive" robusto
 * - 📝 Logs profesionales
 * - 💾 Estado persistente
 *
 * Sin problemas de closures ni stale references.
 */

'use client'

import { useCallback, useEffect, useRef } from 'react'

import { useAuth } from '@/contexts/auth-context'
import { useLogoutMutation } from '@/hooks/auth'

export type IdleWarningLevel = 'info' | 'warning' | 'critical'

export interface IdleTimerConfig {
  /** Tiempo total de inactividad en minutos (default: 60) */
  timeoutMinutes?: number
  /** Habilitar sistema (default: true) */
  enabled?: boolean
  /** Si hay una modal de advertencia abierta (default: false) */
  modalIsOpen?: boolean
  /** Callbacks de notificación */
  onWarning?: (level: IdleWarningLevel, remainingMinutes: number, remainingSeconds: number) => void
  onTimeout?: () => void
}

interface IdleTimerState {
  lastActivity: number
  warningShown: { info: boolean; warning: boolean; critical: boolean }
  logoutExecuted: boolean
  pageVisible: boolean
}

const ACTIVITY_EVENTS = [
  'mousedown',
  // 'mousemove', // ❌ Removido: muy costoso (se dispara cientos de veces/seg)
  'keydown',
  'scroll',
  'touchstart',
  'click',
] as const

export function useIdleTimer(config: IdleTimerConfig = {}) {
  const {
    timeoutMinutes = 60,
    enabled = true,
    modalIsOpen = false,
    onWarning,
    onTimeout,
  } = config

  const { user } = useAuth()
  const logoutMutation = useLogoutMutation()

  // ✅ Estado en refs para evitar closures
  const stateRef = useRef<IdleTimerState>({
    lastActivity: Date.now(),
    warningShown: { info: false, warning: false, critical: false },
    logoutExecuted: false,
    pageVisible: true,
  })

  const timeoutRef = useRef<NodeJS.Timeout | null>(null)
  const checkIntervalRef = useRef<NodeJS.Timeout | null>(null)

  // Convertir a milisegundos
  const TIMEOUT_MS = timeoutMinutes * 60 * 1000

  // Niveles de advertencia (porcentajes del tiempo total)
  // ✅ PRODUCCIÓN: Niveles de advertencia para 60 minutos
  const WARNING_LEVELS = {
    info: 0.833,     // 83.3% del tiempo (50 min en 60 min)
    warning: 0.917,  // 91.7% del tiempo (55 min en 60 min)
    critical: 0.967, // 96.7% del tiempo (58 min en 60 min)
  }

  /**
   * Ejecutar logout con logging detallado
   */
  const executeLogout = useCallback(() => {
    const state = stateRef.current

    if (state.logoutExecuted) {
      return
    }



    state.logoutExecuted = true

    // Limpiar timers
    if (timeoutRef.current) clearTimeout(timeoutRef.current)
    if (checkIntervalRef.current) clearInterval(checkIntervalRef.current)

    // Guardar motivo de cierre en sessionStorage
    sessionStorage.setItem('logout_reason', 'inactivity')
    sessionStorage.setItem('logout_timestamp', Date.now().toString())

    // Callback opcional
    onTimeout?.()

    // Ejecutar logout
    logoutMutation.mutate()
  }, [logoutMutation, onTimeout])

  /**
   * Verificar nivel de inactividad y mostrar advertencias
   */
  const checkInactivity = useCallback(() => {
    const state = stateRef.current
    const now = Date.now()
    const inactiveTime = now - state.lastActivity
    const progress = inactiveTime / TIMEOUT_MS
    const remainingMs = TIMEOUT_MS - inactiveTime
    const remainingSeconds = Math.floor(remainingMs / 1000)
    const remainingMinutes = Math.ceil(remainingMs / 1000 / 60)



    // Verificar si se superó el tiempo límite
    if (progress >= 1.0) {
      executeLogout()
      return
    }

    // Determinar nivel actual
    let currentLevel: IdleWarningLevel | null = null

    if (progress >= WARNING_LEVELS.critical) {
      currentLevel = 'critical'
      if (!state.warningShown.critical) {
        state.warningShown.critical = true
        onWarning?.('critical', remainingMinutes, remainingSeconds)
      }
    } else if (progress >= WARNING_LEVELS.warning) {
      currentLevel = 'warning'
      if (!state.warningShown.warning) {
        state.warningShown.warning = true
        onWarning?.('warning', remainingMinutes, remainingSeconds)
      }
    } else if (progress >= WARNING_LEVELS.info) {
      currentLevel = 'info'
      // 🚨 NO mostrar advertencia INFO si ya se mostró WARNING o CRITICAL
      if (!state.warningShown.info && !state.warningShown.warning && !state.warningShown.critical) {
        state.warningShown.info = true
        onWarning?.('info', remainingMinutes, remainingSeconds)
      }
    }
  }, [TIMEOUT_MS, WARNING_LEVELS, onWarning, executeLogout])

  /**
   * Reiniciar actividad (llamado por usuario o eventos)
   */
  const resetActivity = useCallback(() => {
    const state = stateRef.current

    // Actualizar estado
    state.lastActivity = Date.now()
    state.warningShown = { info: false, warning: false, critical: false }

    // Limpiar timers antiguos
    if (timeoutRef.current) clearTimeout(timeoutRef.current)
    if (checkIntervalRef.current) clearInterval(checkIntervalRef.current)

    // ✅ PRODUCCIÓN: Verificar cada 15s (buen balance entre precisión y performance)
    const checkInterval = 15000
    checkIntervalRef.current = setInterval(checkInactivity, checkInterval)

    // Timeout de seguridad (por si falla el interval)
    timeoutRef.current = setTimeout(executeLogout, TIMEOUT_MS + 5000)
  }, [checkInactivity, executeLogout, TIMEOUT_MS])

  /**
   * Manejar actividad del usuario
   */
  const handleUserActivity = useCallback(() => {
    if (!user || !enabled) return

    const state = stateRef.current

    // 🚨 Si ya se mostró warning/critical O hay modal abierta, ignorar actividad automática
    // Solo el botón "Mantener sesión activa" puede resetear el timer
    if (state.warningShown.warning || state.warningShown.critical || modalIsOpen) {
      return
    }

    // Throttle agresivo: solo actualizar si pasaron más de 10 segundos
    // (reduce carga de CPU sin afectar UX)
    const now = Date.now()
    if (now - state.lastActivity < 10000) return

    resetActivity()
  }, [user, enabled, modalIsOpen, resetActivity])

  /**
   * API pública: Mantener sesión activa (botón manual)
   */
  const keepAlive = useCallback(() => {
    resetActivity()
  }, [resetActivity])

  /**
   * API pública: Obtener tiempo restante
   */
  const getRemainingTime = useCallback(() => {
    const state = stateRef.current
    const elapsed = Date.now() - state.lastActivity
    const remaining = Math.max(0, TIMEOUT_MS - elapsed)

    return {
      remainingMs: remaining,
      remainingMinutes: Math.ceil(remaining / 1000 / 60),
      remainingSeconds: Math.ceil(remaining / 1000),
      progress: elapsed / TIMEOUT_MS,
    }
  }, [TIMEOUT_MS])

  /**
   * Effect principal: Inicializar y limpiar
   */
  useEffect(() => {
    if (!user || !enabled) {

      // Resetear estado al cerrar sesión
      stateRef.current = {
        lastActivity: Date.now(),
        warningShown: { info: false, warning: false, critical: false },
        logoutExecuted: false,
        pageVisible: true,
      }

      return
    }



    // Resetear estado al iniciar sesión
    stateRef.current.logoutExecuted = false
    stateRef.current.warningShown = { info: false, warning: false, critical: false }

    // Iniciar timers
    resetActivity()

    // Agregar event listeners
    ACTIVITY_EVENTS.forEach(event => {
      document.addEventListener(event, handleUserActivity, { passive: true })
    })

    // Page Visibility API
    const handleVisibilityChange = () => {
      const isVisible = !document.hidden
      stateRef.current.pageVisible = isVisible
    }

    document.addEventListener('visibilitychange', handleVisibilityChange)

    // Cleanup
    return () => {

      if (timeoutRef.current) clearTimeout(timeoutRef.current)
      if (checkIntervalRef.current) clearInterval(checkIntervalRef.current)

      ACTIVITY_EVENTS.forEach(event => {
        document.removeEventListener(event, handleUserActivity)
      })

      document.removeEventListener('visibilitychange', handleVisibilityChange)
    }
  }, [user, enabled, timeoutMinutes, modalIsOpen, handleUserActivity, resetActivity, WARNING_LEVELS])

  return {
    keepAlive,
    getRemainingTime,
    resetActivity,
  }
}

