import { createServerClient, type CookieOptions } from '@supabase/ssr'

import { cookies } from 'next/headers'

import type { Database } from './database.types'

/**
 * Cliente de Supabase para API Routes (Route Handlers)
 * Este cliente tiene acceso a las cookies de sesión del usuario usando @supabase/ssr
 */
export async function createRouteClient() {
  const cookieStore = await cookies()

  return createServerClient<Database>(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        get(name: string) {
          return cookieStore.get(name)?.value
        },
        set(name: string, value: string, options: CookieOptions) {
          try {
            cookieStore.set({ name, value, ...options })
          } catch (_error) {
            // The `set` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
        remove(name: string, options: CookieOptions) {
          try {
            cookieStore.set({ name, value: '', ...options })
          } catch (_error) {
            // The `delete` method was called from a Server Component.
            // This can be ignored if you have middleware refreshing
            // user sessions.
          }
        },
      },
    }
  )
}

/**
 * 🧹 UTILIDADES DE SANITIZACIÓN DE DATOS
 *
 * Funciones centralizadas para limpiar y normalizar datos antes de enviarlos a la BD.
 * Convierte strings vacíos, undefined, y valores inválidos a null.
 *
 * @module sanitize
 */

/**
 * Sanitizar string: convierte strings vacíos a null
 * @param value - Valor a sanitizar
 * @returns String limpio o null
 */
export function sanitizeString(value: string | null | undefined): string | null {
  if (value === null || value === undefined) return null
  const trimmed = value.trim()
  return trimmed === '' ? null : trimmed
}

/**
 * Sanitizar fecha: convierte strings vacíos y fechas inválidas a null
 * @param value - Valor de fecha a sanitizar
 * @returns Fecha válida o null
 */
export function sanitizeDate(value: string | null | undefined): string | null {
  if (value === null || value === undefined) return null
  const trimmed = value.trim()
  if (trimmed === '') return null

  // Validar que sea una fecha válida
  const date = new Date(trimmed)
  if (isNaN(date.getTime())) return null

  return trimmed
}

/**
 * Sanitizar enum: convierte strings vacíos y valores inválidos a null
 * @param value - Valor del enum a sanitizar
 * @param validValues - Array de valores válidos del enum
 * @returns Valor del enum o null
 */
export function sanitizeEnum<T extends string>(
  value: T | string | null | undefined,
  validValues: readonly T[]
): T | null {
  if (value === null || value === undefined) return null
  const trimmed = value.trim()
  if (trimmed === '') return null

  // Verificar que el valor esté en los valores válidos
  if (validValues.includes(trimmed as T)) {
    return trimmed as T
  }

  return null
}

/**
 * Sanitizar objeto completo: aplica sanitización recursiva
 * @param obj - Objeto a sanitizar
 * @returns Objeto con valores sanitizados
 */
export function sanitizeObject<T extends Record<string, unknown>>(obj: T): T {
  const result: any = {}

  for (const [key, value] of Object.entries(obj)) {
    if (value === null || value === undefined) {
      result[key] = null
    } else if (typeof value === 'string') {
      result[key] = sanitizeString(value)
    } else if (typeof value === 'object' && !Array.isArray(value)) {
      result[key] = sanitizeObject(value)
    } else {
      result[key] = value
    }
  }

  return result as T
}

/**
 * Palabras que NO deben capitalizarse en nombres propios en español
 * (excepto si son la primera palabra)
 */
const PALABRAS_MINUSCULAS_ES = new Set([
  'de', 'del', 'la', 'las', 'los', 'el', 'y', 'e', 'o', 'u',
  'a', 'al', 'con', 'en', 'por', 'para', 'sin', 'sobre',
])

function capitalizarPalabra(word: string): string {
  // Maneja palabras con guion: "Ana-Maria" → "Ana-Maria"
  return word
    .split('-')
    .map((part) => (part.length > 0 ? part.charAt(0).toUpperCase() + part.slice(1) : part))
    .join('-')
}

/**
 * Formatear nombre propio con Title Case inteligente en español.
 * Capitaliza la primera letra de cada palabra excepto preposiciones y artículos.
 * Siempre capitaliza la primera palabra.
 *
 * @example
 * formatNombrePropio("JUAN PABLO")          → "Juan Pablo"
 * formatNombrePropio("maria de los angeles") → "Maria de los Angeles"
 * formatNombrePropio("ana-maria")            → "Ana-Maria"
 * formatNombrePropio("juan de dios")         → "Juan de Dios"
 *
 * @param value - Nombre a formatear
 * @returns Nombre formateado o null si está vacío
 */
export function formatNombrePropio(value: string | null | undefined): string | null {
  if (value === null || value === undefined) return null
  const trimmed = value.trim()
  if (trimmed === '') return null

  const palabras = trimmed.toLowerCase().split(/\s+/).filter((w) => w.length > 0)

  return palabras
    .map((word, index) => {
      if (index === 0) return capitalizarPalabra(word)
      if (PALABRAS_MINUSCULAS_ES.has(word)) return word
      return capitalizarPalabra(word)
    })
    .join(' ')
}

/**
 * Remover campos con valores null/undefined de un objeto
 * Útil para updates parciales donde solo quieres enviar campos modificados
 * @param obj - Objeto a limpiar
 * @returns Objeto sin campos null/undefined
 */
export function removeNullish<T extends Record<string, unknown>>(obj: T): Partial<T> {
  const result: any = {}

  for (const [key, value] of Object.entries(obj)) {
    if (value !== null && value !== undefined) {
      result[key] = value
    }
  }

  return result
}

/**
 * 🔗 UTILIDADES: GENERACIÓN Y RESOLUCIÓN DE SLUGS
 *
 * Convierte UUIDs en URLs amigables para mejor UX y SEO.
 *
 * Ejemplos:
 * - UUID: 3af5d98c-2747-441e-8114-224d37a7c050
 * - Slug: maria-garcia-lopez-3af5d98c
 * - URL: /clientes/maria-garcia-lopez-3af5d98c
 */

import { createClient } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

// ===================================
// GENERACIÓN DE SLUGS
// ===================================

/**
 * Normaliza texto para slug (quita tildes, convierte a minúsculas, etc.)
 */
function normalizarTexto(texto: string): string {
  if (!texto) return ''
  return texto
    .toLowerCase()
    .normalize('NFD') // Descomponer caracteres con tildes
    .replace(/[\u0300-\u036f]/g, '') // Quitar marcas diacríticas (tildes)
    .replace(/[^a-z0-9]+/g, '-') // Reemplazar caracteres especiales con guiones
    .replace(/^-+|-+$/g, '') // Quitar guiones al inicio/final
    .trim()
}

/**
 * Extrae los primeros 8 caracteres del UUID para el slug
 */
function extraerShortId(uuid: string): string {
  if (!uuid) {
    logger.error('extraerShortId: UUID es undefined o vacío')
    return 'no-id'
  }
  return uuid.split('-')[0]
}

/**
 * Genera slug para cliente: nombres-apellidos-shortid
 *
 * @example
 * generarSlugCliente({ nombres: 'María José', apellidos: 'García López', id: '3af5d98c-...' })
 * // Returns: 'maria-jose-garcia-lopez-3af5d98c'
 */
export function generarSlugCliente(cliente: {
  nombres: string
  apellidos: string
  id: string
}): string {
  const nombreCompleto = `${cliente.nombres} ${cliente.apellidos}`
  const nombreNormalizado = normalizarTexto(nombreCompleto)
  const shortId = extraerShortId(cliente.id)

  return `${nombreNormalizado}-${shortId}`
}

/**
 * Genera slug para proyecto: nombre-shortid
 */
export function generarSlugProyecto(proyecto: {
  nombre: string
  id: string
}): string {
  const nombreNormalizado = normalizarTexto(proyecto.nombre)
  const shortId = extraerShortId(proyecto.id)

  return `${nombreNormalizado}-${shortId}`
}

/**
 * Genera slug para vivienda: proyecto-manzana-numero-shortid
 */
export function generarSlugVivienda(vivienda: {
  numero: string
  id: string
}, manzana?: string, proyecto?: string): string {
  const partes: string[] = []

  // Solo agregar partes si existen y no están vacías
  if (proyecto) {
    const proyectoNorm = normalizarTexto(proyecto)
    if (proyectoNorm) partes.push(proyectoNorm)
  }
  if (manzana) {
    const manzanaNorm = normalizarTexto(manzana)
    if (manzanaNorm) partes.push(manzanaNorm)
  }

  // Número es obligatorio
  const numeroNorm = normalizarTexto(vivienda.numero)
  if (numeroNorm) partes.push(numeroNorm)

  // Short ID siempre al final
  partes.push(extraerShortId(vivienda.id))

  return partes.join('-')
}

// ===================================
// RESOLUCIÓN DE SLUGS
// ===================================

/**
 * Verifica si un string es un UUID válido
 */
export function esUUID(valor: string): boolean {
  const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i
  return uuidRegex.test(valor)
}

/**
 * Extrae el UUID de un slug
 *
 * @example
 * extraerUUIDDeSlug('maria-garcia-lopez-3af5d98c')
 * // Returns: '3af5d98c' (short ID para buscar en DB)
 */
export function extraerShortIDDeSlug(slug: string): string {
  const partes = slug.split('-')
  const ultimaParte = partes[partes.length - 1]

  // Verificar que sea un short ID válido (8 caracteres hexadecimales)
  if (/^[0-9a-f]{8}$/i.test(ultimaParte)) {
    return ultimaParte
  }

  throw new Error(`Slug inválido: ${slug}`)
}

/**
 * Resuelve un slug o UUID a un UUID completo consultando la BD
 *
 * @param slugOUUID - Puede ser un slug (maria-garcia-3af5d98c) o UUID completo
 * @param tabla - Tabla de la base de datos a consultar
 * @returns UUID completo del registro
 */
export async function resolverSlugAUUID(
  slugOUUID: string,
  tabla: 'clientes' | 'proyectos' | 'viviendas' | 'negociaciones'
): Promise<string | null> {
  // Si ya es un UUID completo, retornarlo directamente
  if (esUUID(slugOUUID)) {
    return slugOUUID
  }

  try {
    // Extraer el short ID del slug
    const shortId = extraerShortIDDeSlug(slugOUUID)

    // Buscar en la base de datos por coincidencia del inicio del UUID
    const supabase = createClient()

    // Obtener todos los registros y filtrar en cliente
    // Esto es más eficiente que una query LIKE que puede no estar soportada por RLS
    const { data, error } = await supabase
      .from(tabla)
      .select('id')

    if (error) {
      logger.error(`❌ Error al buscar en ${tabla}:`, error)
      return null
    }

    if (!data || data.length === 0) {
      logger.error(`❌ No hay registros en tabla: ${tabla}`)
      return null
    }

    // Filtrar en cliente por UUID que empiece con el short ID
    const registro = data.find((item: any) =>
      item.id.toLowerCase().startsWith(shortId.toLowerCase())
    )

    if (!registro) {
      logger.error(`❌ No se encontró registro con short ID: ${shortId} en tabla: ${tabla}`)
      return null
    }

    return registro.id
  } catch (error) {
    logger.error('❌ Error al resolver slug:', error)
    return null
  }
}

/**
 * Hook para resolver slug en componentes de cliente
 */
export async function resolverSlugCliente(slugOUUID: string): Promise<string | null> {
  return resolverSlugAUUID(slugOUUID, 'clientes')
}

/**
 * Hook para resolver slug de proyecto
 */
export async function resolverSlugProyecto(slugOUUID: string): Promise<string | null> {
  return resolverSlugAUUID(slugOUUID, 'proyectos')
}

/**
 * Hook para resolver slug de vivienda
 */
export async function resolverSlugVivienda(slugOUUID: string): Promise<string | null> {
  return resolverSlugAUUID(slugOUUID, 'viviendas')
}

// ===================================
// UTILIDADES PARA LINKS
// ===================================

/**
 * Construye URL de cliente con slug
 * Acepta nombres/apellidos separados o nombre_completo
 */
export function construirURLCliente(cliente: {
  id: string
  nombres?: string
  apellidos?: string
  nombre_completo?: string
}): string {
  let slug: string

  if (cliente.nombres && cliente.apellidos) {
    // Usar nombres y apellidos separados
    slug = generarSlugCliente({
      nombres: cliente.nombres,
      apellidos: cliente.apellidos,
      id: cliente.id
    })
  } else if (cliente.nombre_completo) {
    // Usar nombre completo y normalizarlo
    const nombreNormalizado = normalizarTexto(cliente.nombre_completo)
    const shortId = cliente.id.split('-')[0]
    slug = `${nombreNormalizado}-${shortId}`
  } else {
    // Fallback: solo usar el ID
    const shortId = cliente.id.split('-')[0]
    slug = `cliente-${shortId}`
  }

  return `/clientes/${slug}`
}

/**
 * Construye URL de proyecto con slug
 */
export function construirURLProyecto(proyecto: {
  nombre: string
  id: string
}): string {
  const slug = generarSlugProyecto(proyecto)
  return `/proyectos/${slug}`
}

/**
 * Construye URL de vivienda con slug
 */
export function construirURLVivienda(
  vivienda: {
    numero: string
    id: string
  },
  manzana?: string,
  proyecto?: string
): string {
  const slug = generarSlugVivienda(vivienda, manzana, proyecto)
  return `/viviendas/${slug}`
}

import type { NextRequest } from 'next/server'
import { NextResponse } from 'next/server'

import { createMiddlewareClient } from '@/lib/supabase/middleware'
import { debugLog, errorLog } from '@/lib/utils/logger'

/**
 * ============================================
 * MIDDLEWARE: Autenticación y Autorización
 * ============================================
 *
 * Intercepta TODAS las requests ANTES de llegar a las páginas.
 * Valida autenticación y permisos en el SERVIDOR.
 *
 * ARQUITECTURA:
 * 1. Rutas públicas → Pasan sin validación
 * 2. Assets estáticos → Pasan sin validación
 * 3. Verificar sesión → Si no hay, redirect a /login
 * 4. Verificar permisos → Si no tiene acceso, redirect a /dashboard
 * 5. Agregar headers con info de usuario → Para Server Components
 */

// ============================================
// CONFIGURACIÓN DE RUTAS
// ============================================

/** Rutas públicas que NO requieren autenticación */
const PUBLIC_ROUTES = ['/login', '/reset-password', '/update-password']

/**
 * Mapeo de rutas a módulo+acción de permisos
 * El middleware consultará permisos_rol en tiempo real
 * Si una ruta no está aquí, es accesible por todos los autenticados
 */
const ROUTE_TO_PERMISSION: Record<string, { modulo: string; accion: string }> = {
  // Módulos principales
  '/viviendas': { modulo: 'viviendas', accion: 'ver' },
  '/clientes': { modulo: 'clientes', accion: 'ver' },
  '/proyectos': { modulo: 'proyectos', accion: 'ver' },
  '/negociaciones': { modulo: 'negociaciones', accion: 'ver' },
  '/documentos': { modulo: 'documentos', accion: 'ver' },

  // Módulos restringidos
  '/abonos': { modulo: 'abonos', accion: 'ver' },
  '/renuncias': { modulo: 'renuncias', accion: 'ver' },
  '/auditorias': { modulo: 'auditorias', accion: 'ver' },

  // Administración
  '/admin': { modulo: 'administracion', accion: 'ver' },
  '/usuarios': { modulo: 'usuarios', accion: 'ver' },
  '/reportes': { modulo: 'reportes', accion: 'ver' },
}

// ============================================
// HELPERS
// ============================================

/** Verificar si una ruta es pública */
function isPublicRoute(pathname: string): boolean {
  return PUBLIC_ROUTES.some(route => pathname.startsWith(route))
}

/** Verificar si una ruta es un asset estático */
function isStaticAsset(pathname: string): boolean {
  return (
    pathname.startsWith('/_next') ||
    pathname.startsWith('/images') ||
    pathname.startsWith('/favicon.ico') ||
    pathname.startsWith('/icon.svg') ||
    pathname.match(/\.(png|jpg|jpeg|gif|svg|webp|ico|css|js)$/) !== null
  )
}

/** Verificar si el usuario tiene acceso a una ruta basado en cache de permisos en JWT */
function canAccessRoute(
  pathname: string,
  userRole: string,
  permisosCache: string[]
): boolean {
  // Administrador siempre tiene acceso (bypass)
  if (userRole === 'Administrador') {
    return true
  }

  // Buscar permiso por coincidencia de prefijo
  for (const [route, permission] of Object.entries(ROUTE_TO_PERMISSION)) {
    if (pathname === route || pathname.startsWith(`${route}/`)) {
      // ✅ OPTIMIZACIÓN: Leer del cache del JWT (0ms, sin query)
      const permisoRequerido = `${permission.modulo}.${permission.accion}`

      // Wildcard para admin
      if (permisosCache.includes('*.*')) {
        return true
      }

      // Verificar permiso específico en cache
      const tienePermiso = permisosCache.includes(permisoRequerido)

      if (!tienePermiso) {
        debugLog('❌ Permiso denegado', {
          permiso: permisoRequerido,
          rol: userRole,
        })
      }

      return tienePermiso
    }
  }

  // Si no está en el mapa, es accesible por todos autenticados
  return true
}

// ============================================
// MIDDLEWARE PRINCIPAL
// ============================================

export async function middleware(req: NextRequest) {
  const { pathname } = req.nextUrl

  debugLog('🔍 Middleware request', { pathname, cookies: req.cookies.getAll().length })

  // ============================================
  // 1. ASSETS ESTÁTICOS → Permitir sin validación
  // ============================================

  if (isStaticAsset(pathname)) {
    return NextResponse.next()
  }

  // ============================================
  // 2. RUTAS PÚBLICAS → Permitir sin validación
  // ============================================

  if (isPublicRoute(pathname)) {
    return NextResponse.next()
  }

  // ============================================
  // 3. CREAR CLIENTE SUPABASE PARA MIDDLEWARE
  // ============================================

  const res = NextResponse.next()

  try {
    const supabase = createMiddlewareClient(req, res)

    // ============================================
    // 4. VERIFICAR SESIÓN (SEGURO)
    // ============================================

    const {
      data: { user },
      error: authError,
    } = await supabase.auth.getUser()

    debugLog('🔑 Auth check', {
      hasUser: !!user,
      email: user?.email,
    })

    if (!user || authError) {
      debugLog('❌ Sin sesión válida, redirigiendo a login', { pathname })

      // Sin sesión válida → Redirigir a login con URL de retorno
      const redirectUrl = req.nextUrl.clone()
      redirectUrl.pathname = '/login'

      // Guardar ruta original para redirect después del login
      // Solo si no es la raíz
      if (pathname !== '/' && pathname !== '/login') {
        redirectUrl.searchParams.set('redirect', pathname)
      }

      return NextResponse.redirect(redirectUrl)
    }

    debugLog('✅ Usuario autenticado', { email: user.email, pathname })

    // ============================================
    // 5. SI ESTÁ EN /login CON SESIÓN → Permitir (el componente manejará la redirección)
    // ============================================

    // ✅ CORRECCIÓN: No redirigir desde middleware, dejar que useLogin maneje la navegación
    // Esto evita race conditions entre middleware y router.push()
    if (pathname === '/login') {
      debugLog('🔀 Usuario autenticado en /login, permitiendo (componente redirigirá)')
      return res // Permitir acceso, el componente de login manejará la navegación
    }

    // ============================================
    // 6. OBTENER ROL Y PERMISOS DEL JWT (EDGE RUNTIME COMPATIBLE)
    // ============================================

    let rol = 'Supervisor'
    let nombres = ''
    let email = user.email || ''
    let permisosCache: string[] = [] // ✅ Cache de permisos desde JWT

    // Obtener sesión para acceder al JWT
    const {
      data: { session },
    } = await supabase.auth.getSession()

    // Decodificar JWT (compatible con Edge Runtime - sin Buffer)
    if (session?.access_token) {
      try {
        const parts = session.access_token.split('.')
        if (parts.length === 3) {
          // Decodificar base64 sin Buffer (Edge Runtime compatible)
          let base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/')
          // Agregar padding si es necesario
          while (base64.length % 4) {
            base64 += '='
          }

          const jsonPayload = decodeURIComponent(
            atob(base64)
              .split('')
              .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
              .join('')
          )
          const payload = JSON.parse(jsonPayload)

          // Leer claims custom del payload
          rol = payload.user_rol || 'Supervisor'
          nombres = payload.user_nombres || ''
          email = payload.user_email || user.email || ''

          // ✅ OPTIMIZACIÓN: Leer permisos del cache en user_metadata
          permisosCache = payload.user_metadata?.permisos_cache || []
        }
      } catch (error) {
        // Fallback a valores por defecto si falla decodificación
        errorLog('middleware-jwt-decode', error as Error, { pathname })
      }
    }

    // ============================================
    // 7. VERIFICAR PERMISOS PARA LA RUTA (DESDE JWT CACHE - 0ms)
    // ============================================

    const hasAccess = canAccessRoute(pathname, rol, permisosCache)

    if (!hasAccess) {
      // Sin permiso → Redirigir a dashboard
      return NextResponse.redirect(new URL('/dashboard', req.url))
    }

    // ============================================
    // 8. AGREGAR HEADERS CON INFO DE USUARIO
    // ============================================
    // IMPORTANTE: Headers solo aceptan ASCII, encodear caracteres especiales

    res.headers.set('x-user-id', user.id)
    res.headers.set('x-user-rol', encodeURIComponent(rol))
    res.headers.set('x-user-email', encodeURIComponent(email))
    res.headers.set('x-user-nombres', encodeURIComponent(nombres))

    return res
  } catch (_error) {
    // Si hay cualquier error, redirigir a login
    const redirectUrl = req.nextUrl.clone()
    redirectUrl.pathname = '/login'
    return NextResponse.redirect(redirectUrl)
  }
}

// ============================================
// CONFIGURACIÓN: QUÉ RUTAS INTERCEPTAR
// ============================================

export const config = {
  /*
   * Interceptar todas las rutas EXCEPTO:
   * - _next/static (archivos estáticos de Next.js)
   * - _next/image (optimización de imágenes)
   * - favicon.ico, robots.txt, etc.
   * - Archivos con extensiones de imagen/CSS/JS
   */
  matcher: [
    '/((?!_next/static|_next/image|favicon.ico|robots.txt|.*\\.(?:png|jpg|jpeg|gif|svg|webp|ico|css|js)).*)',
  ],
}

'use client'

import { memo, useState } from 'react'

import { motion } from 'framer-motion'
import { AlertTriangle, Ban, CheckCircle, ChevronDown, Home, Loader2, PartyPopper, Sparkles, Tag, User, X } from 'lucide-react'

import { formatDateCompact } from '@/lib/utils/date.utils'

import { formatearNumeroRecibo } from '../../utils/formato-recibo'

const formatCurrency = (v: number) =>
  new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(v)

import type { MotivoAnulacion } from '../../types'

import { modalAnularAbonoStyles as s } from './ModalAnularAbono.styles'
import { useModalAnularAbono } from './useModalAnularAbono'

// ─────────────────────────────────────────────────────────────────────────────
// Celebración de éxito: confetti (matching AccordionWizardSuccess)
// ─────────────────────────────────────────────────────────────────────────────
const CONFETTI_PARTICLES = Array.from({ length: 12 }, (_, i) => ({
  id: i,
  x: Math.random() * 200 - 100,
  y: -(Math.random() * 120 + 40),
  rotate: Math.random() * 360,
  scale: Math.random() * 0.5 + 0.5,
  delay: Math.random() * 0.3,
}))
const CONFETTI_COLORS = ['#FFD700', '#FF6B6B', '#4ECDC4', '#A78BFA', '#F97316', '#06B6D4']

// ─────────────────────────────────────────────────────────────────────────────
// Subcomponente memoizado para la textarea
// Gestiona su propio estado local → el padre NO re-renderiza en cada tecla.
// ─────────────────────────────────────────────────────────────────────────────
const TextareaDetalle = memo(function TextareaDetalle({
  onChange,
  disabled,
  detalleObligatorio,
  maxChars,
}: {
  onChange: (valor: string) => void
  disabled: boolean
  detalleObligatorio: boolean
  maxChars: number
}) {
  const [value, setValue] = useState('')

  const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const nueva = e.target.value
    if (nueva.length <= maxChars) {
      setValue(nueva)
      onChange(nueva)
    }
  }

  return (
    <div className={s.form.fieldGroup}>
      <label htmlFor='motivo-detalle' className={s.form.label}>
        Detalle adicional
        {detalleObligatorio ? (
          <span className={s.form.labelRequired}>*</span>
        ) : (
          <span className='ml-1 font-normal normal-case tracking-normal text-gray-400'>
            (opcional)
          </span>
        )}
      </label>
      <textarea
        id='motivo-detalle'
        rows={3}
        className={s.form.textarea}
        placeholder={
          detalleObligatorio
            ? 'Describe el motivo específico de la anulación…'
            : 'Información adicional sobre la anulación…'
        }
        value={value}
        onChange={handleChange}
        disabled={disabled}
      />
      <p className={s.form.charCount}>
        {value.length}/{maxChars}
      </p>
    </div>
  )
})

// ─────────────────────────────────────────────────────────────────────────────
// Props — sin isOpen: el callsite controla el montaje con {cond && <Modal />}
// ─────────────────────────────────────────────────────────────────────────────
interface ModalAnularAbonoProps {
  abono: {
    id: string
    numero_recibo: number
    monto: number
    fecha_abono: string
    /** Nombre completo del cliente (opcional, para confirmación visual) */
    cliente_nombre?: string
    /** Texto de vivienda, ej: "Mz.A Casa No. 5" (opcional) */
    vivienda_info?: string
    /** Nombre del proyecto (opcional) */
    proyecto_nombre?: string
    /** Tipo/nombre de la fuente de pago (opcional) */
    fuente_tipo?: string
  }
  onClose: () => void
  /** Callback automático ~2s después de anulación exitosa. Debe cerrar el modal y refrescar datos. */
  onAnulacionExitosa?: () => void
}

// ─────────────────────────────────────────────────────────────────────────────
// Componente
// ─────────────────────────────────────────────────────────────────────────────
export function ModalAnularAbono({
  abono,
  onClose,
  onAnulacionExitosa,
}: ModalAnularAbonoProps) {
  const {
    motivoCategoria,
    detalleObligatorio,
    formularioValido,
    anulando,
    error,
    exitoso,
    motivos,
    detalleMaxChars,
    handleMotivoChange,
    handleDetalleChange,
    handleConfirmar,
  } = useModalAnularAbono({ abono, onAnulacionExitosa })

  // ── Vista: loading (animación profesional) ─────────────────────────────────
  if (anulando) {
    return (
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        className={s.overlay}
        onClick={() => {}}
      >
        <motion.div
          initial={{ scale: 0.9, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          transition={{ type: 'spring', stiffness: 300, damping: 25 }}
          className={s.container}
          onClick={(e) => e.stopPropagation()}
          role="dialog"
          aria-modal="true"
          aria-label="Anulando abono"
        >
          <div className="flex flex-col items-center justify-center py-16 px-6 gap-6">
            <div className="relative flex items-center justify-center">
              <motion.div
                animate={{ rotate: 360 }}
                transition={{ repeat: Infinity, duration: 1.2, ease: 'linear' }}
              >
                <Loader2 className="w-12 h-12 text-red-500 dark:text-red-400" />
              </motion.div>
              <motion.div
                initial={{ scale: 0.8, opacity: 0.4 }}
                animate={{ scale: 1.6, opacity: 0 }}
                transition={{ repeat: Infinity, duration: 1.5, ease: 'easeOut' }}
                className="absolute inset-0 m-auto w-12 h-12 rounded-full bg-red-500/20"
              />
            </div>
            <motion.div
              initial={{ opacity: 0, y: 8 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.2 }}
              className="text-center space-y-2"
            >
              <p className="text-lg font-bold text-gray-900 dark:text-white">Anulando abono…</p>
              <p className="text-sm text-gray-500 dark:text-gray-400">Este proceso puede tomar unos segundos.</p>
            </motion.div>
          </div>
        </motion.div>
      </motion.div>
    )
  }

  // ── Vista: éxito (celebración consistente con AccordionWizardSuccess) ─────
  if (exitoso) {
    return (
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        className="fixed inset-0 z-[10001] flex items-center justify-center bg-black/60 backdrop-blur-sm"
      >
        <motion.div
          initial={{ scale: 0.5, opacity: 0, y: 30 }}
          animate={{ scale: 1, opacity: 1, y: 0 }}
          transition={{ type: 'spring', stiffness: 300, damping: 20 }}
          className="relative flex flex-col items-center gap-4 p-8 text-center"
        >
          {/* Confetti */}
          <div className="absolute inset-0 pointer-events-none overflow-visible">
            {CONFETTI_PARTICLES.map((p) => (
              <motion.div
                key={p.id}
                initial={{ x: 0, y: 0, opacity: 1, scale: 0 }}
                animate={{ x: p.x, y: p.y, opacity: [1, 1, 0], scale: p.scale, rotate: p.rotate }}
                transition={{ duration: 1.2, delay: p.delay, ease: 'easeOut' }}
                className="absolute left-1/2 top-1/2 w-2 h-2 rounded-full"
                style={{ backgroundColor: CONFETTI_COLORS[p.id % CONFETTI_COLORS.length] }}
              />
            ))}
          </div>

          {/* Checkmark principal */}
          <motion.div
            initial={{ scale: 0, rotate: -180 }}
            animate={{ scale: 1, rotate: 0 }}
            transition={{ type: 'spring', stiffness: 300, damping: 15, delay: 0.15 }}
            className="relative w-20 h-20 rounded-full bg-gradient-to-br from-emerald-500 to-teal-500 shadow-2xl shadow-emerald-500/40 flex items-center justify-center"
          >
            <CheckCircle className="w-10 h-10 text-white" strokeWidth={2.5} />
            <motion.div
              initial={{ scale: 1, opacity: 0.5 }}
              animate={{ scale: 1.8, opacity: 0 }}
              transition={{ duration: 1, repeat: 2, repeatType: 'loop' }}
              className="absolute inset-0 rounded-full bg-gradient-to-br from-emerald-500 to-teal-500 opacity-30"
            />
          </motion.div>

          {/* Sparkles */}
          <motion.div initial={{ opacity: 0, scale: 0 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: 0.4 }} className="absolute -top-2 -right-4">
            <Sparkles className="w-6 h-6 text-yellow-400" />
          </motion.div>
          <motion.div initial={{ opacity: 0, scale: 0 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: 0.5 }} className="absolute top-0 -left-6">
            <PartyPopper className="w-5 h-5 text-orange-400" />
          </motion.div>

          {/* Texto */}
          <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 }}>
            <h2 className="text-2xl font-bold text-white tracking-tight">¡Abono anulado!</h2>
            <p className="text-white/70 text-sm mt-1">
              Recibo {formatearNumeroRecibo(abono.numero_recibo)} anulado correctamente
            </p>
          </motion.div>

          <motion.p
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
            className="text-white/40 text-xs"
          >
            Redirigiendo…
          </motion.p>
        </motion.div>
      </motion.div>
    )
  }

  // ── Vista: formulario ──────────────────────────────────────────────────────
  return (
    <div className={s.overlay} onClick={onClose}>
      <div
        className={s.container}
        onClick={(e) => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-label="Anular abono"
      >
        {/* Header */}
        <div className={s.header.container}>
          <div className={s.header.left}>
            <div className={s.header.iconWrap}>
              <Ban className="w-4 h-4 text-white" />
            </div>
            <div>
              <p className={s.header.title}>Anular abono</p>
              <p className={s.header.subtitle}>Esta acción es irreversible</p>
            </div>
          </div>
          <button
            type="button"
            className={s.header.btnClose}
            onClick={onClose}
            disabled={anulando}
            aria-label="Cerrar"
          >
            <X className="w-4 h-4" />
          </button>
        </div>

        {/* Body */}
        <div className={s.body}>
          {/* Info del abono */}
          <div className={s.infoBadge}>
            <div className="flex-1 min-w-0">
              <p className={s.infoBadgeLabel}>Recibo</p>
              <p className={s.infoBadgeValue}>{formatearNumeroRecibo(abono.numero_recibo)}</p>
            </div>
            <div className="flex-1 min-w-0">
              <p className={s.infoBadgeLabel}>Monto</p>
              <p className={s.infoBadgeValue}>{formatCurrency(abono.monto)}</p>
            </div>
            <div className="flex-1 min-w-0">
              <p className={s.infoBadgeLabel}>Fecha</p>
              <p className={s.infoBadgeValue}>{formatDateCompact(abono.fecha_abono)}</p>
            </div>
          </div>

          {/* Contexto: cliente, vivienda, fuente */}
          {(abono.cliente_nombre || abono.vivienda_info || abono.fuente_tipo) ? (
            <div className="grid grid-cols-1 gap-2.5 rounded-xl border border-gray-200 bg-gray-100/80 px-3 py-3 dark:border-gray-700/60 dark:bg-gray-800/80">
              {abono.cliente_nombre ? (
                <div className="flex items-start gap-2">
                  <User className="mt-0.5 h-3.5 w-3.5 flex-shrink-0 text-gray-400" />
                  <div className="min-w-0">
                    <p className="text-[10px] font-semibold uppercase tracking-widest text-gray-400 dark:text-gray-500">Cliente</p>
                    <p className="truncate text-sm font-semibold text-gray-900 dark:text-gray-100">{abono.cliente_nombre}</p>
                  </div>
                </div>
              ) : null}
              {abono.vivienda_info ? (
                <div className="flex items-start gap-2">
                  <Home className="mt-0.5 h-3.5 w-3.5 flex-shrink-0 text-gray-400" />
                  <div className="min-w-0">
                    <p className="text-[10px] font-semibold uppercase tracking-widest text-gray-400 dark:text-gray-500">
                      Vivienda{abono.proyecto_nombre ? ` — ${abono.proyecto_nombre}` : ''}
                    </p>
                    <p className="truncate text-sm font-semibold text-gray-900 dark:text-gray-100">{abono.vivienda_info}</p>
                  </div>
                </div>
              ) : null}
              {abono.fuente_tipo ? (
                <div className="flex items-start gap-2">
                  <Tag className="mt-0.5 h-3.5 w-3.5 flex-shrink-0 text-gray-400" />
                  <div className="min-w-0">
                    <p className="text-[10px] font-semibold uppercase tracking-widest text-gray-400 dark:text-gray-500">Fuente de pago</p>
                    <p className="truncate text-sm font-semibold text-gray-900 dark:text-gray-100">{abono.fuente_tipo}</p>
                  </div>
                </div>
              ) : null}
            </div>
          ) : null}

          {/* Advertencia */}
          <div className={s.warningBox}>
            <AlertTriangle className="w-4 h-4 text-amber-500 dark:text-amber-400 mt-0.5 flex-shrink-0" />
            <p className={s.warningText}>
              Al anular este abono, el saldo de la fuente de pago y de la negociación
              se recalculará automáticamente. No se puede reactivar un abono anulado.
            </p>
          </div>

          {/* Motivo categoría */}
          <div className={s.form.fieldGroup}>
            <label htmlFor="motivo-categoria" className={s.form.label}>
              Motivo de la anulación
              <span className={s.form.labelRequired}>*</span>
            </label>
            <div className="relative">
              <select
                id="motivo-categoria"
                className={s.form.select}
                value={motivoCategoria}
                onChange={(e) => handleMotivoChange(e.target.value as MotivoAnulacion | '')}
                disabled={anulando}
              >
                <option value="">Seleccionar motivo…</option>
                {motivos.map((m) => (
                  <option key={m} value={m}>
                    {m}
                  </option>
                ))}
              </select>
              <ChevronDown className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            </div>
          </div>

          {/* Detalle libre — memoizado para no re-renderizar el padre en cada tecla */}
          <TextareaDetalle
            onChange={handleDetalleChange}
            disabled={anulando}
            detalleObligatorio={detalleObligatorio}
            maxChars={detalleMaxChars}
          />

          {/* Error */}
          {error ? (
            <p className={s.form.errorText} role="alert">
              {error}
            </p>
          ) : null}
        </div>

        {/* Footer */}
        <div className={s.footer}>
          <button
            type="button"
            className={s.btnCancel}
            onClick={onClose}
            disabled={anulando}
          >
            Cancelar
          </button>
          <button
            type="button"
            className={s.btnConfirm}
            onClick={handleConfirmar}
            disabled={!formularioValido}
          >
            {anulando ? (
              <>
                <Loader2 className="w-4 h-4 animate-spin" />
                Anulando…
              </>
            ) : (
              <>
                <Ban className="w-4 h-4" />
                Anular abono
              </>
            )}
          </button>
        </div>
      </div>
    </div>
  )
}

'use client'

import { AnimatePresence, motion } from 'framer-motion'
import { AlertCircle, Calendar, CheckCircle2, DollarSign, FileText, Upload, X } from 'lucide-react'

import { Button } from '@/components/ui/button'
import { Dialog, DialogContent } from '@/components/ui/dialog'
import { Label } from '@/components/ui/label'
import { getTodayDateString } from '@/lib/utils/date.utils'

import type { FuentePagoConAbonos } from '../types'

import { CampoComprobante } from './modal-registrar-abono/CampoComprobante'
import { CampoMonto } from './modal-registrar-abono/CampoMonto'
import { MetodosPagoSelector } from './modal-registrar-abono/MetodosPagoSelector'
import { ModalHeader } from './modal-registrar-abono/ModalHeader'
import { colorSchemes, modalStyles } from './modal-registrar-abono/styles'
import { useModalRegistrarAbono } from './modal-registrar-abono/useModalRegistrarAbono'

interface ModalRegistrarAbonoProps {
  open: boolean
  onClose: () => void
  negociacionId: string
  clienteId: string  // ✅ NUEVO: Necesario para redirección al proceso
  fechaMinima?: string  // fecha_negociacion — límite inferior para fecha_abono
  fuentesPago: FuentePagoConAbonos[]
  fuenteInicial?: FuentePagoConAbonos
  onSuccess: () => void
}

export function ModalRegistrarAbono({
  open,
  onClose,
  negociacionId,
  clienteId,
  fechaMinima,
  fuentesPago,
  fuenteInicial,
  onSuccess,
}: ModalRegistrarAbonoProps) {
  const fuentePreseleccionada = fuenteInicial || fuentesPago[0]

  const {
    formData,
    errors,
    faseLoading,
    loading,
    metodoSeleccionado,
    esDesembolsoCompleto,
    montoAutomatico,
    saldoPendiente,
    montoIngresado,
    comprobante,
    handleSubmit,
    handleClose,
    updateField,
    selectMetodo,
    limpiarValidacion,
    setComprobante,
    formatCurrency,
  } = useModalRegistrarAbono({
    negociacionId,
    fuentePreseleccionada,
    fechaMinima,
    onSuccess,
    onClose,
  })

  if (!fuentePreseleccionada) return null

  const colorScheme = colorSchemes[fuentePreseleccionada.tipo as keyof typeof colorSchemes] || colorSchemes['Cuota Inicial']

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-[550px] p-0 gap-0 border-0 bg-white dark:bg-gray-900 overflow-hidden">
        {/* Header Premium */}
        <ModalHeader
          fuente={fuentePreseleccionada}
          esDesembolso={esDesembolsoCompleto}
          montoAprobado={fuentePreseleccionada.monto_aprobado}
          saldoPendiente={saldoPendiente}
          formatCurrency={formatCurrency}
        />

        {/* Formulario con Scroll */}
        <form onSubmit={handleSubmit}>
          <div className="max-h-[60vh] sm:max-h-[70vh] overflow-y-auto">
            <div className={modalStyles.form.container}>
              {/* Campo Monto */}
              <CampoMonto
                esDesembolso={esDesembolsoCompleto}
                fuente={fuentePreseleccionada}
                monto={formData.monto}
                montoAutomatico={montoAutomatico}
                saldoPendiente={saldoPendiente}
                montoIngresado={montoIngresado}
                error={errors.monto}
                onChange={(value) => updateField('monto', value)}
                formatCurrency={formatCurrency}
              />

              {/* Fecha */}
              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.3 }}
              >
                <Label htmlFor="fecha_abono" className={modalStyles.form.label}>
                  <Calendar className={modalStyles.form.labelIcon} />
                  Fecha del {esDesembolsoCompleto ? 'Desembolso' : 'Abono'}{' '}
                  <span className={modalStyles.form.required}>*</span>
                </Label>
                <input
                  type="date"
                  id="fecha_abono"
                  value={formData.fecha_abono}
                  min={fechaMinima}
                  max={getTodayDateString()}
                  onChange={(e) => updateField('fecha_abono', e.target.value)}
                  className={`${modalStyles.form.input} ${errors.fecha_abono ? 'border-red-400 focus:ring-red-400/20' : ''}`}
                />
                {errors.fecha_abono && (
                  <p className="mt-1 text-xs text-red-500 flex items-center gap-1">
                    <AlertCircle className="w-3 h-3 flex-shrink-0" />
                    {errors.fecha_abono}
                  </p>
                )}
              </motion.div>

              {/* Métodos de Pago */}
              <MetodosPagoSelector metodoSeleccionado={metodoSeleccionado} onSelect={selectMetodo} />

              {/* Comprobante de pago */}
              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.45 }}
              >
                <Label className={modalStyles.form.label}>
                  <Upload className={modalStyles.form.labelIcon} />
                  Comprobante de pago{' '}
                  <span className={modalStyles.form.required}>*</span>
                </Label>
                <CampoComprobante
                  archivo={comprobante}
                  error={errors.comprobante}
                  onChange={setComprobante}
                />
              </motion.div>

              {/* Observaciones */}
              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.5 }}
              >
                <Label htmlFor="observaciones" className={modalStyles.form.label}>
                  <FileText className={modalStyles.form.labelIcon} />
                  Observaciones (Opcional)
                </Label>
                <textarea
                  id="observaciones"
                  value={formData.observaciones}
                  onChange={(e) => updateField('observaciones', e.target.value)}
                  rows={3}
                  className={modalStyles.form.textarea}
                  placeholder="Notas adicionales sobre este pago..."
                />
              </motion.div>

              {/* Error general */}
              <AnimatePresence>
                {errors.submit ? (
                  <motion.div
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                    className={modalStyles.form.errorAlert}
                  >
                    <AlertCircle className={modalStyles.form.errorAlertIcon} />
                    <p className={modalStyles.form.errorAlertText}>{errors.submit}</p>
                  </motion.div>
                ) : null}
              </AnimatePresence>
            </div>
          </div>

          {/* Footer con Botones - Fijo abajo */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.6 }}
            className={modalStyles.footer.container}
          >
            <Button
              type="button"
              variant="outline"
              onClick={handleClose}
              disabled={loading}
              className={`${modalStyles.footer.button} ${modalStyles.footer.cancelButton}`}
            >
              <X className={modalStyles.footer.cancelIcon} />
              Cancelar
            </Button>
            <Button
              type="submit"
              disabled={loading || !comprobante}
              className={`${modalStyles.footer.button} ${modalStyles.footer.submitButton} bg-gradient-to-r ${colorScheme.gradient}`}
            >
              {faseLoading === 'subiendo' ? (
                <>
                  <motion.div
                    animate={{ rotate: 360 }}
                    transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
                  >
                    <Upload className={modalStyles.footer.submitIcon} />
                  </motion.div>
                  Subiendo comprobante...
                </>
              ) : faseLoading === 'guardando' ? (
                <>
                  <motion.div
                    animate={{ rotate: 360 }}
                    transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
                  >
                    <DollarSign className={modalStyles.footer.submitIcon} />
                  </motion.div>
                  Guardando abono...
                </>
              ) : (
                <>
                  <CheckCircle2 className={modalStyles.footer.submitIcon} />
                  Confirmar {esDesembolsoCompleto ? 'Desembolso' : 'Abono'}
                </>
              )}
            </Button>
          </motion.div>
        </form>
      </DialogContent>
    </Dialog>
  )
}

/**
