'use client'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

import { anularAbono } from '../services/anular-abono.service'
import { editarAbonoService } from '../services/editar-abono.service'
import { registrarAbonoApi, type RegistrarAbonoPayload } from '../services/registrar-abono.service'
import type { AnularAbonoPayload } from '../types'
import type { EditarAbonoPayload } from '../types/editar-abono.types'

// ============================================
// TIPOS (basados en vista_abonos_completos)
// ============================================

/** Fila plana tal como viene de la vista SQL */
export interface AbonoCompletoRow {
  id: string
  numero_recibo: number
  negociacion_id: string
  fuente_pago_id: string
  monto: number
  fecha_abono: string
  metodo_pago: string
  numero_referencia: string | null
  comprobante_url: string | null
  notas: string | null
  fecha_creacion: string
  fecha_actualizacion: string
  usuario_registro: string | null
  estado: 'Activo' | 'Anulado'
  motivo_categoria: string | null
  motivo_detalle: string | null
  anulado_por_id: string | null
  anulado_por_nombre: string | null
  fecha_anulacion: string | null
  cliente_id: string
  cliente_nombres: string
  cliente_apellidos: string
  cliente_numero_documento: string
  negociacion_estado: 'Activa' | 'Suspendida' | 'Cerrada por Renuncia' | 'Completada'
  vivienda_id: string
  vivienda_numero: string
  manzana_id: string
  manzana_nombre: string
  proyecto_id: string
  proyecto_nombre: string
  fuente_pago_tipo: string
}

/** Estructura anidada para consumo en componentes */
export interface AbonoConInfo {
  id: string
  numero_recibo: number
  negociacion_id: string
  fuente_pago_id: string
  monto: number
  fecha_abono: string
  metodo_pago: string
  numero_referencia: string | null
  comprobante_url: string | null
  notas: string | null
  fecha_creacion: string
  fecha_actualizacion: string
  usuario_registro: string | null
  estado: 'Activo' | 'Anulado'
  motivo_categoria: string | null
  motivo_detalle: string | null
  anulado_por_nombre: string | null
  fecha_anulacion: string | null
  cliente: {
    id: string
    nombres: string
    apellidos: string
    numero_documento: string
  }
  negociacion: {
    id: string
    estado: 'Activa' | 'Suspendida' | 'Cerrada por Renuncia' | 'Completada'
  }
  vivienda: {
    id: string
    numero: string
    manzana: { identificador: string }
  }
  proyecto: {
    id: string
    nombre: string
  }
  fuente_pago: {
    id: string
    tipo: string
  }
}

// ============================================
// QUERY KEYS (Constantes para cache)
// ============================================
export const abonosKeys = {
  all: ['abonos'] as const,
  lists: () => [...abonosKeys.all, 'list'] as const,
  list: (filtros?: Record<string, unknown>) => [...abonosKeys.lists(), { filtros }] as const,
  details: () => [...abonosKeys.all, 'detail'] as const,
  detail: (id: string) => [...abonosKeys.details(), id] as const,
}

// ============================================
// HELPERS
// ============================================

/** Transforma fila plana de la vista SQL a estructura anidada */
function transformarFila(row: AbonoCompletoRow): AbonoConInfo {
  return {
    id: row.id,
    numero_recibo: row.numero_recibo,
    negociacion_id: row.negociacion_id,
    fuente_pago_id: row.fuente_pago_id,
    monto: row.monto,
    fecha_abono: row.fecha_abono,
    metodo_pago: row.metodo_pago,
    numero_referencia: row.numero_referencia,
    comprobante_url: row.comprobante_url,
    notas: row.notas,
    fecha_creacion: row.fecha_creacion,
    fecha_actualizacion: row.fecha_actualizacion,
    usuario_registro: row.usuario_registro,
    estado: (row.estado ?? 'Activo') as 'Activo' | 'Anulado',
    motivo_categoria: row.motivo_categoria ?? null,
    motivo_detalle: row.motivo_detalle ?? null,
    anulado_por_nombre: row.anulado_por_nombre ?? null,
    fecha_anulacion: row.fecha_anulacion ?? null,
    cliente: {
      id: row.cliente_id || '',
      nombres: row.cliente_nombres || 'N/A',
      apellidos: row.cliente_apellidos || '',
      numero_documento: row.cliente_numero_documento || '',
    },
    negociacion: {
      id: row.negociacion_id || '',
      estado: row.negociacion_estado || 'Activa',
    },
    vivienda: {
      id: row.vivienda_id || '',
      numero: row.vivienda_numero || 'N/A',
      manzana: { identificador: row.manzana_nombre || 'N/A' },
    },
    proyecto: {
      id: row.proyecto_id || '',
      nombre: row.proyecto_nombre || 'N/A',
    },
    fuente_pago: {
      id: row.fuente_pago_id || '',
      tipo: row.fuente_pago_tipo || 'N/A',
    },
  }
}

/** Obtiene todos los abonos desde la vista optimizada */
async function fetchAbonos(): Promise<AbonoConInfo[]> {
  // @ts-ignore - vista existe pero tipos no están actualizados
  const { data, error } = await supabase
    .from('vista_abonos_completos')
    .select('*')

  if (error) {
    logger.error('❌ Error fetching abonos:', error)
    throw new Error(error.message)
  }

  if (!data || data.length === 0) return []

  return (data as unknown as AbonoCompletoRow[]).map(transformarFila)
}

// ============================================
// HOOK PRINCIPAL: useAbonosQuery (solo query)
// ============================================
export function useAbonosQuery() {
  const {
    data: abonos = [],
    isLoading: cargando,
    error,
    refetch: refrescar,
  } = useQuery({
    queryKey: abonosKeys.lists(),
    queryFn: fetchAbonos,
    staleTime: 30 * 1000, // 30 segundos — datos de pagos cambian con frecuencia
    gcTime: 5 * 60 * 1000,
    placeholderData: (previousData) => previousData, // Smooth UX: mantener datos previos
  })

  return {
    abonos,
    cargando,
    error: error as Error | null,
    refrescar,
  }
}

// ============================================
// MUTATIONS STANDALONE (sin suscripción a query)
// ============================================

/** Mutation: Anular abono */
export function useAnularAbonoMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (payload: AnularAbonoPayload) => anularAbono(payload).then(({ data, error }) => {
      if (error) throw new Error(error)
      return data
    }),
    onSuccess: async () => {
      await queryClient.invalidateQueries({
        queryKey: abonosKeys.lists(),
        refetchType: 'all',
      })
    },
    onError: (error: Error) => {
      logger.error('❌ Error anulando abono:', error.message)
    },
  })
}

/** Mutation: Editar abono */
export function useEditarAbonoMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (payload: EditarAbonoPayload) => editarAbonoService(payload).then(({ ok, error, abono }) => {
      if (!ok) throw new Error(error ?? 'Error al editar el abono')
      return abono
    }),
    onSuccess: async () => {
      await queryClient.invalidateQueries({
        queryKey: abonosKeys.lists(),
        refetchType: 'all',
      })
      toast.success('Abono actualizado correctamente')
    },
    onError: (error: Error) => {
      toast.error('Error al editar abono', { description: error.message })
    },
  })
}

/** Mutation: Registrar abono */
export function useRegistrarAbonoMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (payload: RegistrarAbonoPayload) => registrarAbonoApi(payload),
    onSuccess: async () => {
      await queryClient.invalidateQueries({
        queryKey: abonosKeys.lists(),
        refetchType: 'all',
      })
    },
    onError: (error: Error) => {
      logger.error('❌ Error registrando abono:', error.message)
    },
  })
}

// ============================================
// HELPER: Invalidar cache de abonos (uso externo)
// ============================================
export function useInvalidateAbonos() {
  const queryClient = useQueryClient()
  return () =>
    queryClient.invalidateQueries({
      queryKey: abonosKeys.lists(),
      refetchType: 'all',
    })
}

/**
 * Servicio para gestión de categorías de sistema
 */

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

export interface CategoriasSistemaResult {
  categoria_id: string
  categoria_nombre: string
  accion: string
}

/**
 * Verifica y crea categorías por módulo específico
 */
export async function verificarCategoriasPorModulo(modulo: 'clientes' | 'proyectos' | 'viviendas'): Promise<{
  success: boolean
  categorias: CategoriasSistemaResult[]
  mensaje: string
  error?: string
}> {
  try {
    const functionName = `verificar_categorias_${modulo}`
    const { data, error } = await supabase.rpc(functionName as any)

    if (error) {
      logger.error(`❌ Error verificando categorías de ${modulo}:`, error)
      return {
        success: false,
        categorias: [],
        mensaje: `Error al verificar categorías de ${modulo}`,
        error: error.message,
      }
    }

    return {
      success: true,
      categorias: data || [],
      mensaje: `${data?.length || 0} categorías de ${modulo} verificadas correctamente`,
    }
  } catch (error) {
    const mensaje = error instanceof Error ? error.message : 'Error desconocido'
    logger.error(`❌ Error en verificarCategoriasPorModulo(${modulo}):`, mensaje)
    return {
      success: false,
      categorias: [],
      mensaje: `Error inesperado al verificar categorías de ${modulo}`,
      error: mensaje,
    }
  }
}

/**
 * Obtiene el estado actual de categorías por módulo
 */
export async function obtenerEstadoCategoriasPorModulo(modulo: 'clientes' | 'proyectos' | 'viviendas'): Promise<{
  total: number
  activas: number
}> {
  try {
    const { data, error } = await supabase
      .from('categorias_documento')
      .select('id, nombre')
      .contains('modulos_permitidos', [modulo])

    if (error) {
      logger.error(`❌ Error obteniendo categorías de ${modulo}:`, error)
      return { total: 0, activas: 0 }
    }

    return {
      total: data?.length || 0,
      activas: data?.length || 0,
    }
  } catch (error) {
    logger.error(`❌ Error en obtenerEstadoCategoriasPorModulo(${modulo}):`, error)
    return { total: 0, activas: 0 }
  }
}

/**
 * Factory de Renderers - Sistema inteligente de selección
 * Mapea módulo + acción → Renderer específico
 */

import { logger } from '@/lib/utils/logger'

import { ActualizacionProyectoRenderer, CreacionProyectoRenderer } from './proyectos'
import { RendererGenerico } from './shared/RendererGenerico'

// Tipo para los renderers
type RendererComponent = React.ComponentType<any>

// Mapa de renderers por módulo y acción
const RENDERERS_MAP: Record<string, Record<string, RendererComponent>> = {
  proyectos: {
    CREATE: CreacionProyectoRenderer,
    UPDATE: ActualizacionProyectoRenderer,
    // DELETE: EliminacionRenderer,             // ← Agregar después
  },
  // viviendas: {
  //   CREATE: CreacionViviendaRenderer,        // ← Agregar después
  //   UPDATE: ActualizacionViviendaRenderer,
  // },
  // clientes: {
  //   CREATE: CreacionClienteRenderer,         // ← Agregar después
  // },
}

/**
 * Obtiene el renderer apropiado para un módulo y acción
 * Si no existe, retorna el renderer genérico
 */
export function getAuditoriaRenderer(modulo: string, accion: string): RendererComponent {
  const moduloRenderers = RENDERERS_MAP[modulo]

  if (!moduloRenderers) {
    logger.warn(`No hay renderers definidos para el módulo: ${modulo}. Usando renderer genérico.`)
    return RendererGenerico
  }

  const renderer = moduloRenderers[accion]

  if (!renderer) {
    logger.warn(`No hay renderer definido para ${modulo}/${accion}. Usando renderer genérico.`)
    return RendererGenerico
  }

  return renderer
}

/**
 * Verifica si existe un renderer específico para módulo/acción
 */
export function hasCustomRenderer(modulo: string, accion: string): boolean {
  return !!RENDERERS_MAP[modulo]?.[accion]
}

/**
 * ActualizacionProyectoRenderer - Renderer para actualizaciones de proyectos
 *
 * ✅ Muestra diferencias campo por campo
 * ✅ Resalta cambios con colores (rojo=anterior, verde=nuevo)
 * ✅ Compara estados, manzanas, datos generales
 * ✅ Diseño profesional con glassmorphism
 */

'use client'

import { ArrowRight, Building, FileText, MapPin, TrendingUp } from 'lucide-react'

import { AuditoriaEstado } from '../../sections/AuditoriaEstado'

interface ActualizacionProyectoRendererProps {
  metadata?: any
  datosNuevos?: any
  datosAnteriores?: any
}

export function ActualizacionProyectoRenderer({
  metadata,
  datosNuevos,
  datosAnteriores,
}: ActualizacionProyectoRendererProps) {
  // Datos del proyecto
  const proyectoNuevo = datosNuevos?.proyecto || {}
  const proyectoAnterior = datosAnteriores?.proyecto || {}

  // Detectar campos modificados
  const camposModificados = []

  if (proyectoNuevo.nombre !== proyectoAnterior.nombre) {
    camposModificados.push({
      campo: 'Nombre del Proyecto',
      icon: Building,
      anterior: proyectoAnterior.nombre,
      nuevo: proyectoNuevo.nombre,
    })
  }

  if (proyectoNuevo.ubicacion !== proyectoAnterior.ubicacion) {
    camposModificados.push({
      campo: 'Ubicación',
      icon: MapPin,
      anterior: proyectoAnterior.ubicacion,
      nuevo: proyectoNuevo.ubicacion,
    })
  }

  if (proyectoNuevo.descripcion !== proyectoAnterior.descripcion) {
    camposModificados.push({
      campo: 'Descripción',
      icon: FileText,
      anterior: proyectoAnterior.descripcion,
      nuevo: proyectoNuevo.descripcion,
    })
  }

  if (proyectoNuevo.estado !== proyectoAnterior.estado) {
    camposModificados.push({
      campo: 'Estado',
      icon: TrendingUp,
      anterior: proyectoAnterior.estado,
      nuevo: proyectoNuevo.estado,
      esEstado: true,
    })
  }

  // Manzanas modificadas
  const manzanasNuevas = datosNuevos?.manzanas || []
  const manzanasAnteriores = datosAnteriores?.manzanas || []
  const manzanasAgregadas = manzanasNuevas.filter(
    (m: any) => !manzanasAnteriores.find((a: any) => a.nombre === m.nombre)
  )
  const manzanasEliminadas = manzanasAnteriores.filter(
    (m: any) => !manzanasNuevas.find((n: any) => n.nombre === m.nombre)
  )

  return (
    <div className="space-y-4 p-6">
      {/* Resumen de cambios */}
      <div className="flex items-center gap-2 px-4 py-2 rounded-lg bg-blue-50 dark:bg-blue-950/30 border border-blue-200 dark:border-blue-800">
        <TrendingUp className="w-4 h-4 text-blue-600 dark:text-blue-400" />
        <p className="text-sm font-medium text-blue-900 dark:text-blue-100">
          {camposModificados.length} campo{camposModificados.length !== 1 ? 's' : ''} modificado
          {camposModificados.length !== 1 ? 's' : ''}
          {manzanasAgregadas.length > 0 && ` • ${manzanasAgregadas.length} manzana${manzanasAgregadas.length !== 1 ? 's' : ''} agregada${manzanasAgregadas.length !== 1 ? 's' : ''}`}
          {manzanasEliminadas.length > 0 && ` • ${manzanasEliminadas.length} manzana${manzanasEliminadas.length !== 1 ? 's' : ''} eliminada${manzanasEliminadas.length !== 1 ? 's' : ''}`}
        </p>
      </div>

      {/* Campos modificados */}
      {camposModificados.length > 0 && (
        <div className="space-y-3">
          {camposModificados.map((cambio, index) => {
            const Icon = cambio.icon

            if (cambio.esEstado) {
              return (
                <div
                  key={index}
                  className="relative overflow-hidden rounded-xl backdrop-blur-xl bg-white/80 dark:bg-gray-800/80 border border-gray-200/50 dark:border-gray-700/50 p-4"
                >
                  <div className="flex items-center gap-3 mb-3">
                    <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center shadow-lg shadow-indigo-500/50">
                      <Icon className="w-4 h-4 text-white" />
                    </div>
                    <p className="text-sm font-semibold text-gray-900 dark:text-white">{cambio.campo}</p>
                  </div>
                  <div className="flex items-center gap-3">
                    <div className="flex-1">
                      <p className="text-xs text-gray-500 dark:text-gray-400 mb-1.5 font-medium">Estado anterior</p>
                      <AuditoriaEstado estado={cambio.anterior} />
                    </div>
                    <ArrowRight className="w-5 h-5 text-gray-400 flex-shrink-0" />
                    <div className="flex-1">
                      <p className="text-xs text-gray-500 dark:text-gray-400 mb-1.5 font-medium">Estado nuevo</p>
                      <AuditoriaEstado estado={cambio.nuevo} />
                    </div>
                  </div>
                </div>
              )
            }

            return (
              <div
                key={index}
                className="relative overflow-hidden rounded-xl backdrop-blur-xl bg-white/80 dark:bg-gray-800/80 border border-gray-200/50 dark:border-gray-700/50 p-4"
              >
                <div className="flex items-center gap-3 mb-3">
                  <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center shadow-lg shadow-blue-500/50">
                    <Icon className="w-4 h-4 text-white" />
                  </div>
                  <p className="text-sm font-semibold text-gray-900 dark:text-white">{cambio.campo}</p>
                </div>
                <div className="space-y-2">
                  <div className="flex items-start gap-2">
                    <div className="px-2 py-1 rounded bg-red-100 dark:bg-red-950/50 border border-red-300 dark:border-red-800 flex-1">
                      <p className="text-xs text-red-600 dark:text-red-400 font-medium mb-0.5">Anterior:</p>
                      <p className="text-sm text-red-900 dark:text-red-100 line-through">
                        {cambio.anterior || '(vacío)'}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center justify-center">
                    <ArrowRight className="w-4 h-4 text-gray-400" />
                  </div>
                  <div className="flex items-start gap-2">
                    <div className="px-2 py-1 rounded bg-green-100 dark:bg-green-950/50 border border-green-300 dark:border-green-800 flex-1">
                      <p className="text-xs text-green-600 dark:text-green-400 font-medium mb-0.5">Nuevo:</p>
                      <p className="text-sm text-green-900 dark:text-green-100 font-semibold">
                        {cambio.nuevo || '(vacío)'}
                      </p>
                    </div>
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      )}

      {/* Manzanas agregadas */}
      {manzanasAgregadas.length > 0 && (
        <div className="relative overflow-hidden rounded-xl backdrop-blur-xl bg-green-50 dark:bg-green-950/30 border border-green-200/50 dark:border-green-800/50 p-4">
          <div className="flex items-center gap-2 mb-3">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center shadow-lg shadow-green-500/50">
              <Building className="w-4 h-4 text-white" />
