      <div className="backdrop-blur-xl bg-white/80 dark:bg-gray-800/80 border border-gray-200/50 dark:border-gray-700/50 rounded-xl p-3 space-y-2.5 shadow-xl hover:shadow-2xl transition-shadow">
        <SectionHeader
