/**
 * Hook para formulario de Asignar Vivienda
 * ✅ React Hook Form + Zod (ESTÁNDAR DE LA APLICACIÓN)
 * ✅ Validación por paso
 * ✅ Sistema touchedFields (no mostrar errores hasta interacción)
 */

import { useEffect } from 'react'

import { zodResolver } from '@hookform/resolvers/zod'
import { useForm } from 'react-hook-form'

import { esCreditoHipotecario, esCuotaInicial, esSubsidioCajaCompensacion, esSubsidioMiCasaYa } from '@/shared/constants/fuentes-pago.constants'

import type { AsignarViviendaFormData } from '../schemas'
import { asignarViviendaSchema } from '../schemas'

interface UseAsignarViviendaFormProps {
  initialData?: Partial<AsignarViviendaFormData>
  currentStep: number
}

export function useAsignarViviendaForm({
  initialData,
  currentStep,
}: UseAsignarViviendaFormProps) {

  // ============================================
  // REACT HOOK FORM CON ZOD
  // ============================================

  const {
    register,
    handleSubmit,
    formState: { errors, touchedFields, isSubmitting, isValid },
    setValue,
    watch,
    trigger,
    reset,
  } = useForm<any>({ // Usar any temporalmente para evitar conflictos de tipos
    resolver: zodResolver(asignarViviendaSchema),
    mode: 'onChange', // Validar mientras escribe
    defaultValues: {
      proyecto_id: initialData?.proyecto_id || '',
      vivienda_id: initialData?.vivienda_id || '',
      valor_negociado: initialData?.valor_negociado || 0,
      aplicar_descuento: initialData?.aplicar_descuento || false,
      descuento_aplicado: initialData?.descuento_aplicado || 0,
      tipo_descuento: initialData?.tipo_descuento || '',
      motivo_descuento: initialData?.motivo_descuento || '',
      valor_escritura_publica: initialData?.valor_escritura_publica || 128000000,
      notas: initialData?.notas || '',
      fuentes: initialData?.fuentes || [],
      valor_total: initialData?.valor_total || 0,
    },
  })

  // ============================================
  // VALORES OBSERVADOS
  // ============================================

  const watchedFields = watch()

  const proyecto_id = watch('proyecto_id')
  const vivienda_id = watch('vivienda_id')
  const valor_negociado = watch('valor_negociado')
  const aplicar_descuento = watch('aplicar_descuento')
  const descuento_aplicado = watch('descuento_aplicado')
  const tipo_descuento = watch('tipo_descuento')
  const motivo_descuento = watch('motivo_descuento')
  const valor_escritura_publica = watch('valor_escritura_publica')
  const notas = watch('notas')
  const fuentes = watch('fuentes')
  const valor_total = watch('valor_total')

  // ============================================
  // VALIDACIÓN POR PASO
  // ============================================

  // Validar SOLO campos del paso actual
  const validarPaso = async (step: number): Promise<boolean> => {
    let isValid = false

    switch (step) {
      case 1:
        // Validar paso 1 (incluir todos los campos de descuento)
        isValid = await trigger([
          'proyecto_id',
          'vivienda_id',
          'valor_negociado',
          'aplicar_descuento',
          'descuento_aplicado',
          'tipo_descuento',
          'motivo_descuento',
          'valor_escritura_publica',
        ])
        break

      case 2:
        // Validar paso 2
        isValid = await trigger(['fuentes', 'valor_total'])
        break

      case 3:
        // Paso 3 es solo revisión, no tiene validación
        isValid = true
        break

      default:
        isValid = false
    }

    return isValid
  }

  // ============================================
  // PASO 1: HELPERS
  // ============================================

  const paso1Valido = () => {
    return (
      !!proyecto_id &&
      !!vivienda_id &&
      valor_negociado > 0 &&
      descuento_aplicado >= 0 &&
      descuento_aplicado < valor_negociado
    )
  }

  const camposCompletadosPaso1 = () => {
    return [
      !!proyecto_id,
      !!vivienda_id,
      valor_negociado > 0,
      descuento_aplicado >= 0 && descuento_aplicado < valor_negociado,
    ].filter(Boolean).length
  }

  const porcentajeProgresoPaso1 = () => {
    return Math.round((camposCompletadosPaso1() / 4) * 100)
  }

  // ============================================
  // PASO 2: HELPERS
  // ============================================

  const totalFuentes = fuentes.reduce((acc: number, f: { monto_aprobado?: number | null }) => acc + (f.monto_aprobado ?? 0), 0)
  const diferencia = valor_total - totalFuentes
  const sumaCierra = Math.abs(diferencia) < 0.01

  const paso2Valido = () => {
    return (
      fuentes.length > 0 &&
      sumaCierra &&
      fuentes.every((f: { tipo?: string; monto_aprobado?: number | null; entidad?: string | null; numero_referencia?: string | null; fecha_acta?: string | null }) => {
        // Validar monto obligatorio para todas las fuentes
        const montoValido = (f.monto_aprobado ?? 0) > 0

        // Cuota Inicial: solo requiere monto
        if (esCuotaInicial(f.tipo)) {
          return montoValido
        }

        // Subsidio Mi Casa Ya: requiere monto, entidad NO es obligatoria, numero_referencia es opcional
        if (esSubsidioMiCasaYa(f.tipo)) {
          return montoValido
        }

        // Crédito Hipotecario: requiere monto, entidad (banco), numero_referencia
        if (esCreditoHipotecario(f.tipo)) {
          const entidadValida = f.entidad && f.entidad.trim() !== ''
          const numeroValido = f.numero_referencia && f.numero_referencia.trim() !== ''
          return montoValido && entidadValida && numeroValido
        }

        // Subsidio Caja Compensación: requiere monto, entidad (caja), numero_referencia (acta), fecha_acta
        if (esSubsidioCajaCompensacion(f.tipo)) {
          const entidadValida = f.entidad && f.entidad.trim() !== ''
          const numeroValido = f.numero_referencia && f.numero_referencia.trim() !== ''
          const fechaActaValida = f.fecha_acta && f.fecha_acta.trim() !== ''
          return montoValido && entidadValida && numeroValido && fechaActaValida
        }

        // Fallback: requiere monto, entidad y número
        const entidadValida = f.entidad && f.entidad.trim() !== ''
        const numeroValido = f.numero_referencia && f.numero_referencia.trim() !== ''
        return montoValido && entidadValida && numeroValido
      })
    )
  }

  // ============================================
  // RESET AL CAMBIAR INITIALDATA
  // ============================================

  useEffect(() => {
    if (initialData) {
      reset(initialData)
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initialData]) // ✅ SOLO initialData (reset es estable pero ESLint no lo detecta)

  // ============================================
  // RETURN
  // ============================================

  return {
    // React Hook Form
    register,
    handleSubmit,
    errors,
    touchedFields, // ✅ SISTEMA ESTÁNDAR: mostrar error solo si touched
    isSubmitting,
    isValid,
    setValue,
    watch,
    trigger,
    reset,

    // Valores observados
    proyecto_id,
    vivienda_id,
    valor_negociado,
    aplicar_descuento,
    descuento_aplicado,
    tipo_descuento,
    motivo_descuento,
    valor_escritura_publica,
    notas,
    fuentes,
    valor_total,

    // Validación por paso
    validarPaso,
    paso1Valido: paso1Valido(),
    paso2Valido: paso2Valido(),

    // Progreso Paso 1
    camposCompletadosPaso1: camposCompletadosPaso1(),
    porcentajeProgresoPaso1: porcentajeProgresoPaso1(),

    // Progreso Paso 2
    totalFuentes,
    diferencia,
    sumaCierra,
  }
}

/**
 * Hook principal para el Modal de Crear Negociación
 * Orquesta el stepper, form data y navegación entre pasos
 */

import { useCallback, useMemo, useState } from 'react'

import { logger } from '@/lib/utils/logger'
import { useCrearNegociacion } from '@/modules/clientes/hooks'
import { validarSumaTotal } from '@/modules/clientes/utils/validar-edicion-fuentes'
import { useTiposFuentesConCampos } from '@/modules/configuracion/hooks/useTiposFuentesConCampos'

import type { StepNumber } from '../types'

import { useFuentesPago } from './useFuentesPago'
import { useProyectosViviendas } from './useProyectosViviendas'

interface UseModalNegociacionProps {
  isOpen: boolean
  clienteId: string
  viviendaId?: string
  valorVivienda?: number
  onSuccess: (negociacionId: string) => void
  onClose: () => void
}

export function useModalNegociacion({
  isOpen,
  clienteId,
  viviendaId: viviendaIdProp,
  valorVivienda,
  onSuccess,
  onClose,
}: UseModalNegociacionProps) {
  // ============================================
  // HOOKS EXTERNOS
  // ============================================

  const {
    crearNegociacion,
    creando: creandoHook,
    error: errorHook,
    limpiar: limpiarHook,
  } = useCrearNegociacion()

  // ============================================
  // ESTADO LOCAL
  // ============================================

  const [currentStep, setCurrentStep] = useState<StepNumber>(1)
  const [completedSteps, setCompletedSteps] = useState<number[]>([])
  const [descuentoAplicado, setDescuentoAplicado] = useState(0)
  const [notas, setNotas] = useState('')
  const [creando, setCreando] = useState(false)
  const [error, setError] = useState<string | null>(null)

  // ============================================
  // HOOKS PERSONALIZADOS
  // ============================================

  const proyectosViviendas = useProyectosViviendas({
    viviendaIdInicial: viviendaIdProp,
    valorViviendaInicial: valorVivienda,
  })

  // Vivienda seleccionada (objeto completo, para acceder a gastos/recargo)
  const viviendaSeleccionada = useMemo(() => {
    return proyectosViviendas.viviendas.find((v) => v.id === proyectosViviendas.viviendaId) ?? null
  }, [proyectosViviendas.viviendas, proyectosViviendas.viviendaId])

  // ⚠️ CRÍTICO: El target de fuentes DEBE ser la obligación real del cliente:
  // valorNegociado (= valor_base) − descuento + gastos_notariales + recargo_esquinera.
  // Esto coincide exactamente con valor_total_pagar que el trigger calculará en BD.
  const valorTotal = useMemo(() => {
    const gastos  = viviendaSeleccionada?.gastos_notariales ?? 0
    const recargo = (viviendaSeleccionada?.es_esquinera && viviendaSeleccionada?.recargo_esquinera)
      ? viviendaSeleccionada.recargo_esquinera
      : 0
    return Math.max(0, proyectosViviendas.valorNegociado - descuentoAplicado + gastos + recargo)
  }, [proyectosViviendas.valorNegociado, descuentoAplicado, viviendaSeleccionada])

  const { data: tiposConCampos = [], isLoading: cargandoTipos } = useTiposFuentesConCampos()

  const fuentesPago = useFuentesPago({ valorTotal, tiposConCampos, cargandoTipos })

  // ============================================
  // VALIDACIONES POR PASO
  // ============================================

  const paso1Valido = useMemo(() => {
    return (
      proyectosViviendas.viviendaId !== '' &&
      proyectosViviendas.valorNegociado > 0 &&
      descuentoAplicado >= 0 &&
      descuentoAplicado < proyectosViviendas.valorNegociado &&
      valorTotal > 0
    )
  }, [proyectosViviendas.viviendaId, proyectosViviendas.valorNegociado, descuentoAplicado, valorTotal])

  // paso2Valido viene de useFuentesPago
  const { paso2Valido } = fuentesPago

  // ============================================
  // EFECTOS
  // ============================================


  // ============================================
  // NAVEGACIÓN
  // ============================================

  const handleNext = useCallback(() => {
    if (currentStep === 1 && paso1Valido) {
      setCompletedSteps((prev) => [...new Set([...prev, 1])])
      setCurrentStep(2)
    } else if (currentStep === 2 && paso2Valido) {
      setCompletedSteps((prev) => [...new Set([...prev, 1, 2])])
      setCurrentStep(3)
    }
  }, [currentStep, paso1Valido, paso2Valido])

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => (prev - 1) as StepNumber)
    }
  }, [currentStep])

  // ============================================
  // SUBMIT
  // ============================================

  const handleSubmit = useCallback(async () => {
    setCreando(true)
    setError(null)

    try {
      // Obtener fuentes para crear
      const fuentesParaCrear = fuentesPago.obtenerFuentesParaCrear()

      // Validar suma total
      const validacion = validarSumaTotal(fuentesParaCrear, valorTotal)

      if (!validacion.valido) {
        setError(validacion.errores.join('\n'))
        setCreando(false)
        return
      }

      // Crear negociación con fuentes de pago
      const negociacion = await crearNegociacion({
        cliente_id: clienteId,
        vivienda_id: proyectosViviendas.viviendaId,
        valor_negociado: proyectosViviendas.valorNegociado,
        descuento_aplicado: descuentoAplicado,
        notas,
        fuentes_pago: fuentesParaCrear,
      })

      if (!negociacion) {
        setError(errorHook || 'Error al crear negociación')
        setCreando(false)
        return
      }


      // Limpiar y cerrar
      limpiarHook()
      onSuccess(negociacion.id)
      handleClose()
    } catch (err) {
      logger.error('❌ Error creando negociación:', err)
      setError(err instanceof Error ? err.message : 'Error al crear negociación')
    } finally {
      setCreando(false)
    }
  }, [
    clienteId,
    proyectosViviendas.viviendaId,
    proyectosViviendas.valorNegociado,
    descuentoAplicado,
    notas,
    valorTotal,
    fuentesPago,
    crearNegociacion,
    errorHook,
    limpiarHook,
    onSuccess,
  ])

  // ============================================
  // CERRAR Y RESETEAR
  // ============================================

  const handleClose = useCallback(() => {
    setCurrentStep(1)
    setCompletedSteps([])
    setDescuentoAplicado(0)
    setNotas('')
    setError(null)
    proyectosViviendas.resetear()
    fuentesPago.resetear()
    onClose()
  }, [proyectosViviendas, fuentesPago, onClose])

  // ============================================
  // RETURN
  // ============================================

  return {
    // Stepper
    currentStep,
    completedSteps,

    // Proyectos y Viviendas
    ...proyectosViviendas,

    // Descuento y Notas
    descuentoAplicado,
    setDescuentoAplicado,
    notas,
    setNotas,

    // Valor Total
    valorTotal,

    // Fuentes de Pago
    ...fuentesPago,

    // Validaciones
    paso1Valido,
    paso2Valido,

    // Estado de creación
    creando: creando || creandoHook,
    error: error || errorHook,

    // Navegación
    handleNext,
    handleBack,

    // Acciones
    handleSubmit,
    handleClose,
  }
}

/**
 * Hook con React Query para cargar proyectos
 * ✅ Cache automático
 * ✅ Revalidación inteligente
 * ✅ Estados de loading/error
 * ✅ Filtra solo proyectos con viviendas disponibles
 */

import { useQuery } from '@tanstack/react-query'

import { supabase } from '@/lib/supabase/client'
import { proyectosService } from '@/modules/proyectos/services/proyectos.service'

/**
 * Cargar solo proyectos que tengan al menos 1 vivienda disponible.
 * Consulta las viviendas con estado 'Disponible' y sin asignar,
 * luego filtra los proyectos por IDs encontrados.
 */
export function useProyectosQuery() {
  return useQuery({
    queryKey: ['proyectos', 'con-viviendas-disponibles'],
    queryFn: async () => {
      // 1. Obtener IDs de proyectos que tienen viviendas disponibles
      //    viviendas → manzanas.proyecto_id (viviendas no tiene proyecto_id directo)
      const { data: viviendasDisponibles } = await supabase
        .from('viviendas')
        .select('manzana_id, manzanas!inner(proyecto_id)')
        .eq('estado', 'Disponible')
        .is('negociacion_id', null)
        .is('cliente_id', null)

      const idsConDisponibles = [
        ...new Set(
          (viviendasDisponibles ?? []).map(
            (v: any) => v.manzanas?.proyecto_id
          ).filter(Boolean)
        ),
      ]

      if (idsConDisponibles.length === 0) return []

      // 2. Obtener todos los proyectos activos
      const proyectos = await proyectosService.obtenerProyectos()

      // 3. Filtrar solo los que tienen viviendas disponibles
      return (proyectos || []).filter(p => idsConDisponibles.includes(p.id))
    },
    staleTime: 2 * 60 * 1000, // 2 minutos (más fresco para asignación)
    gcTime: 10 * 60 * 1000,
    refetchOnWindowFocus: false,
  })
}

/**
 * Hook con React Query para cargar viviendas disponibles de un proyecto
 * ✅ Cache automático por proyecto
 * ✅ Invalidación cuando cambia proyecto
 * ✅ Búsqueda optimizada
 */

import { useQuery } from '@tanstack/react-query'

import { supabase } from '@/lib/supabase/client'

import type { ViviendaDetalle } from '../types'

export function useViviendasQuery(proyectoId: string | undefined) {
  return useQuery({
    queryKey: ['viviendas', 'disponibles', proyectoId],
    queryFn: async () => {
      if (!proyectoId) return []

      const { data, error } = await supabase
        .from('viviendas')
        .select(`
          *,
          manzanas!inner (
            id,
            nombre,
            proyecto_id
          )
        `)
        .eq('manzanas.proyecto_id', proyectoId)
        .eq('estado', 'Disponible')
        .is('negociacion_id', null) // ⭐ CRÍTICO: Solo viviendas sin negociación activa
        .is('cliente_id', null)      // ⭐ Y sin cliente asignado

      if (error) throw error

      // Transformar para incluir manzana_nombre directamente
      const viviendasConManzana: ViviendaDetalle[] = (data || []).map((v: any) => ({
        ...v,
        manzana_nombre: v.manzanas?.nombre,
      }))

      // Ordenar primero por manzana (alfabéticamente) y luego por número (numéricamente)
      return viviendasConManzana.sort((a, b) => {
        // Primero comparar por nombre de manzana
        const manzanaA = (a.manzana_nombre || '').toLowerCase()
        const manzanaB = (b.manzana_nombre || '').toLowerCase()

        if (manzanaA < manzanaB) return -1
        if (manzanaA > manzanaB) return 1

        // Si las manzanas son iguales, ordenar por número (numéricamente)
        return parseInt(a.numero, 10) - parseInt(b.numero, 10)
      })
    },
    enabled: !!proyectoId, // Solo ejecutar si hay proyecto
    staleTime: 3 * 60 * 1000, // 3 minutos
    gcTime: 10 * 60 * 1000,
    refetchOnWindowFocus: false,
  })
}

/**
 * Helper: Subir Documentos de Fuentes de Pago
 *
 * ✅ Sube documentos a la pestaña de documentos del cliente
 * ✅ Usa nombres formateados según especificación
 * ✅ Categoría: "Cartas de aprobación, Promesas de Compraventa y Documentos del Proceso"
 *
 * Formato de nombres:
 * - Crédito Hipotecario: "CARTA DE APROBACIÓN CRÉDITO A1 - PEPE PEREZ"
 * - Caja Compensación: "CARTA CAJA DE COMPENSACIÓN A1 - PEPE PEREZ"
 */

import { logger } from '@/lib/utils/logger'
import type { TipoFuentePago } from '@/modules/clientes/types'
import { DocumentosBaseService } from '@/modules/documentos/services/documentos-base.service'

import type { FuentePagoConfig } from '../types'

// â­ ID de la categoría (verificado en DB)
const CATEGORIA_CARTAS_APROBACION_ID = '4898e798-c188-4f02-bfcf-b2b15be48e34'

interface SubirDocumentoFuenteParams {
  clienteId: string
  clienteNombre: string
  manzana: string
  numeroVivienda: string
  tipoFuente: TipoFuentePago
  entidad: string
  archivo: File
  negociacionId?: string // Para vincular con la negociación
}

/**
 * Genera el título del documento según el tipo de fuente
 */
function generarTituloDocumento(
  tipoFuente: TipoFuentePago,
  manzana: string,
  numeroVivienda: string,
  clienteNombre: string
): string {
  const vivienda = `${manzana}${numeroVivienda}` // Ej: "A1"
  const nombreMayusculas = clienteNombre.toUpperCase()

  switch (tipoFuente) {
    case 'Crédito Hipotecario':
      return `CARTA DE APROBACIÓN CRÉDITO ${vivienda} - ${nombreMayusculas}`

    case 'Subsidio Caja Compensación':
      return `CARTA CAJA DE COMPENSACIÓN ${vivienda} - ${nombreMayusculas}`

    default:
      return `DOCUMENTO ${tipoFuente.toUpperCase()} ${vivienda} - ${nombreMayusculas}`
  }
}

/**
 * Sube un documento de fuente de pago al sistema de documentos del cliente
 */
export async function subirDocumentoFuente(
  params: SubirDocumentoFuenteParams
): Promise<string> {
  const { clienteId, clienteNombre, manzana, numeroVivienda, tipoFuente, entidad, archivo, negociacionId } = params

  // Generar título formateado
  const titulo = generarTituloDocumento(tipoFuente, manzana, numeroVivienda, clienteNombre)

  // Generar descripción
  const descripcion = `Carta de aprobación de ${tipoFuente} - ${entidad}`

  // Subir documento al sistema
  const documento = await (DocumentosBaseService as any).subirDocumento({
    entidad_id: clienteId,
    tipoEntidad: 'cliente',
    categoria_id: CATEGORIA_CARTAS_APROBACION_ID,
    titulo,
    descripcion,
    archivo,
    metadata: {
      tipo_fuente: tipoFuente,
      entidad,
      negociacion_id: negociacionId,
      vivienda: `${manzana}${numeroVivienda}`,
    },
  })

  return (documento as any).url_archivo
}

/**
 * Sube todos los documentos de las fuentes de pago configuradas
 */
export async function subirDocumentosFuentesPago(
  clienteId: string,
  clienteNombre: string,
  manzana: string,
  numeroVivienda: string,
  fuentes: FuentePagoConfig[],
  negociacionId?: string
): Promise<Record<TipoFuentePago, string | undefined>> {
  const urls: Record<string, string | undefined> = {}

  for (const fuente of fuentes) {
    // Solo subir si tiene archivo pendiente
    if ((fuente as any).archivo) {
      try {

        const url = await subirDocumentoFuente({
          clienteId,
          clienteNombre,
          manzana,
          numeroVivienda,
          tipoFuente: fuente.tipo,
          entidad: fuente.entidad || '',
          archivo: (fuente as any).archivo,
          negociacionId,
        })

        urls[fuente.tipo] = url
      } catch (error) {
        logger.error(`❌ Error subiendo documento de ${fuente.tipo}:`, error)
        throw new Error(`Error al subir documento de ${fuente.tipo}`)
      }
    }
  }

  return urls as Record<TipoFuentePago, string | undefined>
}

