  tieneCedula = false,
  onVer,
  onEditar,
  onEliminar,
  onIniciarAsignacion,
}: ClienteCardCompactaProps) {
  // Renderizado condicional según estado del cliente
  switch (cliente.estado) {
    case 'Activo':
