        <ClienteCardInactivo
          cliente={cliente}
          onVer={onVer}
          onEditar={onEditar}
          onEliminar={onEliminar}
        />
      )

    case 'Inactivo':
      return (
        <ClienteCardInactivo
          cliente={cliente}
          onVer={onVer}
          onEditar={onEditar}
          onEliminar={onEliminar}
        />
      )

    case 'Interesado':
    default:
      return (
        <ClienteCardInteresado
          cliente={cliente}
          tieneCedula={tieneCedula}
          onVer={onVer}
          onEditar={onEditar}
          onEliminar={onEliminar}
        />
      )
  }
}

