  const { data: documentosPendientes = [], isLoading } = useDocumentosPendientes(clienteId)

  // Agrupar pendientes por fuente
  const pendientesPorFuente = useMemo(() => {
    const agrupados: Record<string, DocumentoPorFuente> = {}

    documentosPendientes.forEach((doc) => {
      const fuenteId = doc.fuente_pago_id
      const tipoFuente = doc.metadata?.tipo_fuente || 'Sin especificar'
      // ✅ La vista genera 'entidad_fuente' (no 'entidad') en el JSON
      const entidad = (doc.metadata as any)?.entidad_fuente || ''

      if (!agrupados[fuenteId]) {
        agrupados[fuenteId] = {
          fuenteId,
          tipo: tipoFuente,
          entidad,
          pendientes: [],
          completados: 0,
          total: 0,
        }
      }

      if (doc.estado === 'Pendiente') {
        agrupados[fuenteId].pendientes.push({
          id: doc.id,
          tipo_documento: doc.tipo_documento,
          nivel: (doc.metadata as any)?.nivel_validacion || '',
          prioridad: doc.prioridad,
          metadata: doc.metadata,
        })
      } else if (doc.estado === 'Completado') {
        agrupados[fuenteId].completados++
      }

      agrupados[fuenteId].total++
    })

    return Object.values(agrupados)
      .filter((grupo) => grupo.pendientes.length > 0)
      .sort((a, b) => {
        // Documentación final (docs compartidos como Boleta de Registro) siempre van al final
        const aEsCompartida = a.tipo === 'Compartido'
        const bEsCompartida = b.tipo === 'Compartido'
        if (aEsCompartida && !bEsCompartida) return 1
        if (!aEsCompartida && bEsCompartida) return -1
        return 0
      })
  }, [documentosPendientes])

  // Contar totales
  const totalPendientes = useMemo(
    () => pendientesPorFuente.reduce((sum, grupo) => sum + grupo.pendientes.length, 0),
    [pendientesPorFuente]
  )

  const totalObligatorios = useMemo(
    () =>
      pendientesPorFuente.reduce(
        (sum, grupo) =>
          sum + grupo.pendientes.filter((p) => p.nivel === 'DOCUMENTO_OBLIGATORIO').length,
        0
      ),
    [pendientesPorFuente]
  )

  // No mostrar si no hay pendientes o está cargando
  if (isLoading || totalPendientes === 0) {
    return null
  }

  return (
    <div className="mb-4">
      {/* Header Colapsable */}
      <button
        onClick={() => setExpandido(!expandido)}
        className="w-full flex items-center justify-between p-3 rounded-lg
                   bg-gradient-to-r from-amber-50 via-orange-50 to-amber-50
                   dark:from-amber-950/30 dark:via-orange-950/30 dark:to-amber-950/30
                   border-2 border-amber-200 dark:border-amber-800
                   hover:border-amber-300 dark:hover:border-amber-700
                   hover:shadow-lg hover:shadow-amber-500/20
                   transition-all duration-300"
      >
        <div className="flex items-center gap-3">
          <motion.div
            animate={{ scale: [1, 1.05, 1] }}
            transition={{ repeat: Infinity, duration: 2 }}
            className="rounded-lg p-2 bg-gradient-to-br from-amber-500 to-orange-600 shadow-lg shadow-amber-500/30"
          >
            <AlertTriangle className="h-5 w-5 text-white" />
          </motion.div>
          <div className="text-left">
            <div className="flex items-center gap-2">
              <span className="text-sm font-bold text-gray-900 dark:text-white">
                Tienes {totalPendientes} documentos pendientes de fuentes de pago
              </span>
              {totalObligatorios > 0 && (
                <span className="px-2 py-0.5 text-xs font-bold bg-red-500 text-white rounded-full">
                  {totalObligatorios} obligatorios
                </span>
              )}
            </div>
            <p className="text-xs text-gray-600 dark:text-gray-400 mt-0.5">
              {expandido ? 'Clic para ocultar detalles' : 'Clic para ver detalles y subir documentos'}
            </p>
          </div>
        </div>
        <motion.div animate={{ rotate: expandido ? 180 : 0 }} transition={{ duration: 0.3 }}>
          <ChevronDown className="h-5 w-5 text-amber-600 dark:text-amber-400" />
        </motion.div>
      </button>

      {/* Contenido Expandible */}
      <AnimatePresence>
        {expandido && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.3 }}
            className="overflow-hidden"
          >
            <div className="mt-2 p-4 rounded-lg border-2 border-amber-200 dark:border-amber-800 bg-white dark:bg-gray-800 space-y-4">
              {/* Agrupación por fuente */}
              {pendientesPorFuente.map((grupo) => {
                const IconoFuente = getIconoPorTipo(grupo.tipo)

                return (
                  <motion.div
                    key={grupo.fuenteId}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="pb-4 border-b border-gray-200 dark:border-gray-700 last:border-0 last:pb-0"
                  >
                    {/* Header de fuente */}
                    <div className="flex items-center gap-2 mb-3">
                      <div className="p-2 rounded-lg bg-gradient-to-br from-cyan-500 to-blue-600">
                        <IconoFuente className="h-4 w-4 text-white" />
                      </div>
                      <div className="flex-1">
                        <h4 className="text-sm font-bold text-gray-900 dark:text-white">
                          {grupo.tipo === 'Compartido' ? 'Documentación final' : grupo.tipo}
                          {grupo.tipo !== 'Compartido' && grupo.entidad && <span className="text-cyan-600 dark:text-cyan-400"> • {grupo.entidad}</span>}
                        </h4>
                        <p className="text-xs text-gray-500 dark:text-gray-400">
                          {grupo.pendientes.length} pendiente{grupo.pendientes.length !== 1 ? 's' : ''}
                          {grupo.completados > 0 && ` • ${grupo.completados} completado${grupo.completados !== 1 ? 's' : ''}`}
                        </p>
                      </div>
                    </div>

                    {/* Lista de documentos pendientes */}
                    <div className="space-y-2 pl-4">
                      {grupo.pendientes.map((doc, index) => {
                        const esObligatorio = doc.nivel === 'DOCUMENTO_OBLIGATORIO'

                        return (
                          <motion.div
                            key={doc.id}
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            transition={{ delay: index * 0.1 }}
                            whileHover={{ x: 4, scale: 1.01 }}
                            className={`group flex items-center justify-between p-2.5 rounded-lg
                                       backdrop-blur-sm transition-all duration-300
                                       ${
                                         esObligatorio
                                           ? 'bg-red-50 dark:bg-red-950/30 border-l-4 border-red-500'
                                           : 'bg-blue-50 dark:bg-blue-950/30 border-l-4 border-blue-500'
                                       }
                                       hover:shadow-md`}
                          >
                            <div className="flex items-center gap-2 flex-1">
                              <FileText
                                className={`h-4 w-4 ${
                                  esObligatorio
                                    ? 'text-red-600 dark:text-red-400'
                                    : 'text-blue-600 dark:text-blue-400'
                                }`}
                              />
                              <div className="flex-1">
                                <p className="text-sm font-semibold text-gray-900 dark:text-white">
                                  {doc.tipo_documento}
                                </p>
                                <span
                                  className={`text-xs font-medium ${
                                    esObligatorio
                                      ? 'text-red-600 dark:text-red-400'
                                      : 'text-blue-600 dark:text-blue-400'
                                  }`}
                                >
                                  {esObligatorio ? 'OBLIGATORIO' : 'Opcional'}
                                </span>
                                {(doc.metadata as any)?.alcance === 'COMPARTIDO_CLIENTE' && (
                                  <p className="text-xs text-gray-400 dark:text-gray-500 mt-0.5">
                                    Documento final · Se obtiene tras escrituración
                                  </p>
                                )}
                              </div>
                            </div>

                            <motion.button
                              whileHover={{ scale: 1.05 }}
                              whileTap={{ scale: 0.95 }}
                              onClick={() =>
                                onSubirDocumento?.(doc.id, doc.tipo_documento, {
                                  ...doc.metadata,
                                  fuente_pago_id: grupo.fuenteId,
                                })
                              }
                              className={`flex items-center gap-1.5 rounded-lg px-3 py-1.5
                                         text-xs font-medium text-white transition-all duration-300
                                         ${
                                           esObligatorio
                                             ? 'bg-gradient-to-r from-red-500 to-red-600 hover:from-red-600 hover:to-red-700 shadow-lg shadow-red-500/30'
                                             : 'bg-gradient-to-r from-orange-500 to-orange-600 hover:from-orange-600 hover:to-orange-700 shadow-lg shadow-orange-500/30'
                                         }`}
                            >
                              <Upload className="h-3.5 w-3.5" />
                              Subir
                            </motion.button>
                          </motion.div>
                        )
                      })}
                    </div>
                  </motion.div>
                )
              })}

              {/* Footer informativo */}
              <div className="pt-3 border-t border-amber-200 dark:border-amber-800">
                <p className="text-xs text-gray-600 dark:text-gray-400 flex items-center gap-2">
                  <CheckCircle2 className="h-3.5 w-3.5 text-green-600 dark:text-green-400 flex-shrink-0" />
                  Los documentos se vincularán automáticamente a la fuente al subirlos
                </p>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

/**
 * 📋 FORMULARIO CLIENTE - Modal Moderno
 *
 * Formulario multi-step para crear/editar clientes.
 * Diseño moderno con animaciones y glassmorphism.
 * ✅ TEMA: Cyan/Blue/Indigo (módulo Clientes)
 *
 * ⭐ REFACTORIZADO: Usa componentes shared de formulario
 */

'use client'

import { useEffect, useState } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import {
    Building2,
    Calendar,
    Check,
    ChevronLeft,
    ChevronRight,
    FileText,
    Heart,
    Home,
    Mail,
    MapPin,
    MessageSquare,
    Phone,
    Sparkles,
    User,
    Users,
    X,
} from 'lucide-react'

import { ModernInput, ModernSelect, ModernTextarea } from '@/shared/components/forms'
import { useLocationSelector } from '@/shared/hooks/useLocationSelector'

import type { CrearClienteDTO, EstadoCivil, TipoDocumento } from '../types'
import { ESTADOS_CIVILES, TIPOS_DOCUMENTO } from '../types'

interface FormularioClienteProps {
  isOpen: boolean
  onClose: () => void
  formData: CrearClienteDTO
  errors: Record<string, string>
  isSubmitting: boolean
  esEdicion: boolean
  hayCambios?: boolean
  cargandoDatos?: boolean
  onSubmit: (e: React.FormEvent) => void
  onChange: (campo: keyof CrearClienteDTO, valor: any) => void
  // Props adicionales para el interés
  proyectos?: Array<{ id: string; nombre: string; ubicacion: string }>
  viviendas?: Array<{ id: string; numero: string; manzana_nombre: string; valor_total: number }>
  cargandoProyectos?: boolean
  cargandoViviendas?: boolean
  onProyectoChange?: (proyectoId: string) => void
  onViviendaChange?: (viviendaId: string) => void
  // Validaciones por step (Step 0 es async para verificar duplicados)
  validarStep0?: () => Promise<boolean>
  validarStep1?: () => boolean
  validarStep2?: () => boolean
  validarStep3?: () => boolean
}

export function FormularioCliente({
  isOpen,
  onClose,
  formData,
  errors,
  isSubmitting,
  esEdicion,
  hayCambios = true,
  cargandoDatos = false,
  onSubmit,
  onChange,
  proyectos = [],
  viviendas = [],
  cargandoProyectos = false,
  cargandoViviendas = false,
  onProyectoChange,
  onViviendaChange,
  validarStep0,
  validarStep1,
  validarStep2,
  validarStep3,
}: FormularioClienteProps) {
  const [currentStep, setCurrentStep] = useState(0)

  // Hook para selección de departamento/ciudad en cascada
  const {
    departamentos,
    departamentoSeleccionado,
    ciudadesDisponibles,
    ciudadSeleccionada,
    handleDepartamentoChange,
    handleCiudadChange,
    ciudadDeshabilitada,
  } = useLocationSelector({
    departamentoInicial: formData.departamento || '',
    ciudadInicial: formData.ciudad || '',
    onDepartamentoChange: (departamento) => onChange('departamento', departamento),
    onCiudadChange: (ciudad) => onChange('ciudad', ciudad),
  })

  // ✅ Steps dinámicos: En edición no incluye paso de Interés
  const steps = esEdicion
    ? [
        { id: 0, label: 'Personal', icon: User, color: 'from-cyan-500 to-blue-500' },
        { id: 1, label: 'Contacto', icon: Phone, color: 'from-blue-500 to-indigo-500' },
        { id: 2, label: 'Adicional', icon: MessageSquare, color: 'from-cyan-500 to-blue-500' },
      ]
    : [
        { id: 0, label: 'Personal', icon: User, color: 'from-cyan-500 to-blue-500' },
        { id: 1, label: 'Contacto', icon: Phone, color: 'from-blue-500 to-indigo-500' },
        { id: 2, label: 'Interés', icon: Heart, color: 'from-indigo-500 to-cyan-500' },
        { id: 3, label: 'Adicional', icon: MessageSquare, color: 'from-cyan-500 to-blue-500' },
      ]

  // Resetear step cuando se abre/cierra el modal
  useEffect(() => {
    if (isOpen) {
      setCurrentStep(0)
    }
  }, [isOpen])

  const nextStep = async () => {
    // Validar el step actual antes de avanzar
    let esValido = true

    if (currentStep === 0 && validarStep0) {
      // ⚠️ Step 0 es ASYNC (verifica duplicados en DB)
      esValido = await validarStep0()
    } else if (currentStep === 1 && validarStep1) {
      esValido = validarStep1()
    } else if (currentStep === 2 && validarStep2) {
      esValido = validarStep2()
    } else if (currentStep === 3 && validarStep3) {
      esValido = validarStep3()
    }

    // Solo avanzar si es válido
    if (esValido && currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1)
    }
  }

  const prevStep = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1)
    }
  }

  /**
   * Cambiar a un step específico desde el stepper
   * Valida todos los pasos intermedios antes de permitir el salto
   */
  const goToStep = async (targetStep: number) => {
    // Si el paso target es anterior o igual al actual, permitir sin validación
    if (targetStep <= currentStep) {
      setCurrentStep(targetStep)
      return
    }

    // Si intenta avanzar, validar cada paso intermedio
    for (let i = currentStep; i < targetStep; i++) {
      let esValido = true

      if (i === 0 && validarStep0) {
        // ⚠️ Step 0 es ASYNC (verifica duplicados en DB)
        esValido = await validarStep0()
      } else if (i === 1 && validarStep1) {
        esValido = validarStep1()
      } else if (i === 2 && validarStep2) {
        esValido = validarStep2()
      } else if (i === 3 && validarStep3) {
        esValido = validarStep3()
      }

      // Si algún paso intermedio no es válido, detener
      if (!esValido) {
        // Mover al paso que falló para que el usuario vea los errores
        setCurrentStep(i)
        return
      }
    }

    // Si todos los pasos intermedios son válidos, avanzar al target
    setCurrentStep(targetStep)
  }

  return (
    <AnimatePresence>
      {isOpen && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className='fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-md p-4'
        >
          <motion.div
            initial={{ scale: 0.95, opacity: 0, y: 20 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.95, opacity: 0, y: 20 }}
            transition={{ type: 'spring', duration: 0.5, bounce: 0.3 }}
            onClick={(e) => e.stopPropagation()}
            className='relative w-full max-w-4xl max-h-[90vh] overflow-hidden rounded-2xl bg-white shadow-2xl dark:bg-gray-900'
          >
            {/* Loading State cuando carga datos en edición */}
            {cargandoDatos && esEdicion ? (
              <div className='flex items-center justify-center min-h-[600px] bg-white dark:bg-gray-900'>
                <div className='flex flex-col items-center gap-4'>
                  <div className='relative'>
                    <div className='w-16 h-16 border-4 border-cyan-200 dark:border-cyan-900 rounded-full' />
                    <div className='absolute inset-0 w-16 h-16 border-4 border-t-cyan-600 dark:border-t-cyan-400 rounded-full animate-spin' />
                  </div>
                  <div className='text-center'>
                    <p className='text-base font-semibold text-gray-900 dark:text-gray-100'>
                      Cargando datos del cliente...
                    </p>
                    <p className='text-sm text-gray-500 dark:text-gray-400 mt-1'>
                      Espera un momento
                    </p>
                  </div>
                </div>
              </div>
            ) : (
              <>
                {/* Header con gradiente animado */}
                <div className='relative overflow-hidden bg-gradient-to-r from-cyan-600 via-blue-600 to-indigo-600 px-6 py-5'>
              {/* Patrón de fondo animado */}
              <div className='absolute inset-0 opacity-20'>
                <div className='absolute inset-0 bg-[radial-gradient(circle_at_50%_120%,rgba(255,255,255,0.3),transparent)]' />
              </div>

              <div className='relative flex items-center justify-between'>
                <div className='flex items-center gap-3'>
                  <motion.div
                    initial={{ rotate: -180, scale: 0 }}
                    animate={{ rotate: 0, scale: 1 }}
                    transition={{ type: 'spring', delay: 0.2 }}
                    className='flex h-12 w-12 items-center justify-center rounded-xl bg-white/20 backdrop-blur-sm ring-2 ring-white/30'
                  >
                    <Sparkles className='h-6 w-6 text-white' />
                  </motion.div>
                  <div>
                    <div className='flex items-center gap-2'>
                      <h2 className='text-xl font-bold text-white'>
                        {esEdicion ? 'Editar Cliente' : 'Nuevo Cliente'}
                      </h2>
                      {esEdicion && (
                        <span
                          className={`inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-xs font-medium ${
                            hayCambios
                              ? 'bg-amber-500/90 text-white'
                              : 'bg-white/20 text-white'
                          }`}
                          title={
                            hayCambios
                              ? 'Hay cambios sin guardar'
                              : 'No hay cambios pendientes'
                          }
                        >
                          {hayCambios ? '● Modificado' : '✓ Sin cambios'}
                        </span>
                      )}
                    </div>
                    <p className='text-xs text-cyan-100'>
                      {esEdicion
                        ? 'Actualiza la información del cliente'
                        : 'Paso ' + (currentStep + 1) + ' de ' + steps.length}
                    </p>
                  </div>
                </div>
                <button
                  onClick={onClose}
                  className='group rounded-lg p-2 text-white/80 transition-all hover:bg-white/20 hover:text-white hover:rotate-90'
                  type='button'
                >
                  <X className='h-5 w-5 transition-transform' />
                </button>
              </div>

              {/* Steps Indicator */}
              <div className='relative mt-5 flex items-center justify-between'>
                {steps.map((step, idx) => {
                  const StepIcon = step.icon
                  const isActive = currentStep === step.id
                  const isCompleted = currentStep > step.id

                  return (
                    <div key={step.id} className='flex flex-1 items-center'>
                      <button
                        type='button'
                        onClick={() => goToStep(step.id)}
                        className='group relative flex items-center gap-3'
                      >
                        <motion.div
                          initial={false}
                          animate={{
                            scale: isActive ? 1.15 : 1,
                          }}
                          className={`flex h-10 w-10 items-center justify-center rounded-lg shadow-lg transition-all ${
                            isCompleted
                              ? 'bg-white text-cyan-600'
                              : isActive
                                ? 'bg-white text-cyan-600'
                                : 'bg-white/20 text-white backdrop-blur-sm'
                          }`}
                        >
                          {isCompleted ? (
                            <Check className='h-4 w-4' />
                          ) : (
                            <StepIcon className='h-4 w-4' />
                          )}
                        </motion.div>
                        <span
                          className={`hidden text-xs font-semibold sm:block ${
                            isActive
                              ? 'text-white'
                              : 'text-white/70'
                          }`}
                        >
                          {step.label}
                        </span>
                      </button>
                      {idx < steps.length - 1 && (
                        <div className='mx-2.5 h-1 flex-1 overflow-hidden rounded-full bg-white/20'>
                          <motion.div
                            initial={false}
                            animate={{
                              width: isCompleted ? '100%' : '0%',
                            }}
                            transition={{ duration: 0.3 }}
                            className='h-full bg-white shadow-lg'
                          />
                        </div>
                      )}
                    </div>
                  )
                })}
              </div>
            </div>

            {/* Form Content con scroll */}
            <div className='max-h-[calc(90vh-210px)] overflow-y-auto'>
              <form onSubmit={onSubmit} className='p-6'>
                <AnimatePresence mode='wait'>
                  <motion.div
                    key={currentStep}
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.3 }}
                  >
                    {/* Step 0: Información Personal */}
                    {currentStep === 0 && (
                      <div className='space-y-4'>
                        <div className='mb-5'>
                          <h3 className='text-base font-semibold text-gray-900 dark:text-white flex items-center gap-1.5'>
                            <User className='h-4 w-4 text-cyan-500' />
                            Información Personal
                          </h3>
                          <p className='mt-0.5 text-xs text-gray-500 dark:text-gray-400'>
                            Datos básicos de identificación del cliente
                          </p>
                        </div>

                        <div className='grid grid-cols-1 gap-4 md:grid-cols-2'>
                          <ModernInput
                            icon={User}
                            label='Nombres'
                            required
                            type='text'
                            value={formData.nombres}
                            onChange={(e: any) => onChange('nombres', e.target.value)}
                            placeholder='Ej: Juan Carlos'
                            disabled={isSubmitting}
                            error={errors.nombres}
                          />

                          <ModernInput
                            icon={User}
                            label='Apellidos'
                            required
                            type='text'
                            value={formData.apellidos}
                            onChange={(e: any) => onChange('apellidos', e.target.value)}
                            placeholder='Ej: Pérez García'
                            disabled={isSubmitting}
                            error={errors.apellidos}
                          />

                          <ModernSelect
                            icon={FileText}
                            label='Tipo de Documento'
                            required
                            value={formData.tipo_documento}
                            onChange={(e: any) =>
                              onChange('tipo_documento', e.target.value as TipoDocumento)
                            }
                            disabled={isSubmitting}
                            error={errors.tipo_documento}
                          >
                            {Object.entries(TIPOS_DOCUMENTO).map(([key, value]) => (
                              <option key={key} value={key}>
                                {value}
                              </option>
                            ))}
                          </ModernSelect>

                          <ModernInput
                            icon={FileText}
                            label='Número de Documento'
                            required
                            type='text'
                            value={formData.numero_documento}
                            onChange={(e: any) => onChange('numero_documento', e.target.value)}
                            placeholder='Ej: 1234567890'
                            disabled={isSubmitting}
                            error={errors.numero_documento}
                          />

                          <ModernInput
                            icon={Calendar}
                            label='Fecha de Nacimiento'
                            type='date'
                            value={formData.fecha_nacimiento}
                            onChange={(e: any) => onChange('fecha_nacimiento', e.target.value)}
                            disabled={isSubmitting}
                          />

                          <ModernSelect
                            icon={Users}
                            label='Estado Civil'
                            value={formData.estado_civil || ''}
                            onChange={(e: any) =>
                              onChange('estado_civil', e.target.value as EstadoCivil || undefined)
                            }
                            disabled={isSubmitting}
                          >
                            <option value=''>Seleccione...</option>
                            {Object.entries(ESTADOS_CIVILES).map(([key, value]) => (
                              <option key={key} value={key}>
                                {value}
                              </option>
                            ))}
                          </ModernSelect>
                        </div>
                      </div>
                    )}

                    {/* Step 1: Información de Contacto */}
                    {currentStep === 1 && (
                      <div className='space-y-4'>
                        <div className='mb-5'>
                          <h3 className='text-base font-semibold text-gray-900 dark:text-white flex items-center gap-1.5'>
                            <Phone className='h-4 w-4 text-blue-500' />
                            Información de Contacto
                          </h3>
                          <p className='mt-0.5 text-xs text-gray-500 dark:text-gray-400'>
                            Datos para comunicarnos con el cliente
                          </p>
                        </div>

                        <div className='grid grid-cols-1 gap-4 md:grid-cols-2'>
                          <ModernInput
                            icon={Phone}
                            label='Teléfono Principal'
                            type='tel'
                            value={formData.telefono}
                            onChange={(e: any) => onChange('telefono', e.target.value)}
                            placeholder='Ej: 3001234567'
                            disabled={isSubmitting}
                            error={errors.telefono}
                          />

                          <ModernInput
                            icon={Phone}
                            label='Teléfono Alternativo'
                            type='tel'
                            value={formData.telefono_alternativo}
                            onChange={(e: any) => onChange('telefono_alternativo', e.target.value)}
                            placeholder='Ej: 3007654321'
                            disabled={isSubmitting}
                          />

                          <ModernInput
                            icon={Mail}
                            label='Correo Electrónico'
                            type='email'
                            value={formData.email}
                            onChange={(e: any) => onChange('email', e.target.value)}
                            placeholder='cliente@example.com'
                            disabled={isSubmitting}
                            error={errors.email}
                          />

                          <ModernInput
                            icon={MapPin}
                            label='Dirección'
                            type='text'
                            value={formData.direccion}
                            onChange={(e: any) => onChange('direccion', e.target.value)}
                            placeholder='Calle 123 #45-67'
                            disabled={isSubmitting}
                          />

                          {/* Departamento (Select en cascada) */}
                          <ModernSelect
                            icon={Home}
                            label='Departamento'
                            value={departamentoSeleccionado}
                            onChange={(e: any) => handleDepartamentoChange(e.target.value)}
                            disabled={isSubmitting}
                            required
                            error={errors.departamento}
                          >
                            <option value=''>Seleccione un departamento</option>
                            {departamentos.map((dept) => (
                              <option key={dept} value={dept}>
                                {dept}
                              </option>
                            ))}
                          </ModernSelect>

                          {/* Ciudad/Municipio (Select que depende de departamento) */}
                          <ModernSelect
                            icon={Building2}
                            label='Ciudad / Municipio'
                            value={ciudadSeleccionada}
                            onChange={(e: any) => handleCiudadChange(e.target.value)}
                            disabled={isSubmitting || ciudadDeshabilitada}
                            required
                            error={errors.ciudad}
                          >
                            <option value=''>
                              {!departamentoSeleccionado
                                ? 'Primero selecciona un departamento'
                                : ciudadesDisponibles.length === 0
                                  ? 'No hay municipios disponibles'
                                  : 'Seleccione un municipio'}
                            </option>
                            {ciudadesDisponibles.map((ciudad) => (
                              <option key={ciudad} value={ciudad}>
                                {ciudad}
                              </option>
                            ))}
                          </ModernSelect>
                        </div>
                      </div>
                    )}

                    {/* Step 2: Interés en Proyectos/Viviendas */}
                    {currentStep === 2 && !esEdicion && (
                      <div className='space-y-4'>
                        <div className='mb-5'>
                          <h3 className='text-base font-semibold text-gray-900 dark:text-white flex items-center gap-1.5'>
                            <Heart className='h-4 w-4 text-indigo-500' />
                            ¿En qué está interesado?
                          </h3>
                          <p className='mt-0.5 text-xs text-gray-500 dark:text-gray-400'>
                            Opcional: Registra el proyecto o vivienda de interés del cliente
                          </p>
                        </div>

                        <div className='grid grid-cols-1 gap-4'>
                          <ModernSelect
                            icon={Building2}
                            label='Proyecto de Interés'
                            value={formData.interes_inicial?.proyecto_id || ''}
                            onChange={(e: any) => {
                              const proyectoId = e.target.value
                              onProyectoChange?.(proyectoId)
                              onChange('interes_inicial', {
                                ...formData.interes_inicial,
                                proyecto_id: proyectoId,
                                vivienda_id: undefined, // Reset vivienda
                              })
                            }}
                            disabled={isSubmitting || cargandoProyectos}
                          >
                            <option value=''>Ninguno (sin interés específico)</option>
                            {cargandoProyectos && <option disabled>Cargando proyectos...</option>}
                            {proyectos.map((proyecto) => (
                              <option key={proyecto.id} value={proyecto.id}>
                                {proyecto.nombre} - {proyecto.ubicacion}
                              </option>
                            ))}
                          </ModernSelect>

                          {formData.interes_inicial?.proyecto_id && (
                            <motion.div
                              initial={{ opacity: 0, height: 0 }}
                              animate={{ opacity: 1, height: 'auto' }}
                              exit={{ opacity: 0, height: 0 }}
                              className='space-y-4'
                            >
                              <ModernSelect
                                icon={Home}
                                label='Vivienda Específica (Opcional)'
                                value={formData.interes_inicial?.vivienda_id || ''}
                                onChange={(e: any) => {
                                  const viviendaId = e.target.value
                                  onViviendaChange?.(viviendaId)
                                  onChange('interes_inicial', {
                                    ...formData.interes_inicial,
                                    vivienda_id: viviendaId || undefined,
                                  })
                                }}
                                disabled={isSubmitting || cargandoViviendas}
                              >
                                <option value=''>
                                  {cargandoViviendas
                                    ? 'Cargando viviendas...'
                                    : 'Interesado en el proyecto en general'}
                                </option>
                                {viviendas.map((vivienda) => (
                                  <option key={vivienda.id} value={vivienda.id}>
                                    Manzana {vivienda.manzana_nombre} - Casa {vivienda.numero} (
                                    {new Intl.NumberFormat('es-CO', {
                                      style: 'currency',
                                      currency: 'COP',
                                      minimumFractionDigits: 0,
                                    }).format(vivienda.valor_total)}
                                    )
                                  </option>
                                ))}
                              </ModernSelect>

                              <ModernTextarea
                                icon={MessageSquare}
                                label='Notas del Interés'
                                value={formData.interes_inicial?.notas_interes || ''}
                                onChange={(e: any) =>
                                  onChange('interes_inicial', {
                                    ...formData.interes_inicial,
                                    notas_interes: e.target.value,
                                  })
                                }
                                placeholder='Ej: Interesado en casa de 2 pisos, presupuesto hasta $200M, necesita crédito...'
                                rows={3}
                                disabled={isSubmitting}
                              />
                            </motion.div>
                          )}

                          {!formData.interes_inicial?.proyecto_id && (
                            <div className='rounded-lg border-2 border-dashed border-gray-200 bg-gray-50 p-5 text-center dark:border-gray-700 dark:bg-gray-800/50'>
                              <Heart className='mx-auto h-10 w-10 text-gray-300 dark:text-gray-600' />
                              <p className='mt-2.5 text-xs text-gray-500 dark:text-gray-400'>
                                Si el cliente no tiene un proyecto específico en mente,
                                <br />
                                puedes dejar esta sección vacía y continuar.
                              </p>
                            </div>
                          )}
                        </div>
                      </div>
                    )}

                    {/* Step 2 (Edición) / Step 3 (Creación): Información Adicional */}
                    {((esEdicion && currentStep === 2) || (!esEdicion && currentStep === 3)) && (
                      <div className='space-y-4'>
                        <div className='mb-5'>
                          <h3 className='text-base font-semibold text-gray-900 dark:text-white flex items-center gap-1.5'>
                            <MessageSquare className='h-4 w-4 text-indigo-500' />
                            Información Adicional
                          </h3>
                          <p className='mt-0.5 text-xs text-gray-500 dark:text-gray-400'>
                            Datos complementarios y observaciones
                          </p>
                        </div>

                        <div className='grid grid-cols-1 gap-4'>
                          <ModernTextarea
                            icon={MessageSquare}
                            label='Notas y Observaciones'
                            value={formData.notas}
                            onChange={(e: any) => onChange('notas', e.target.value)}
                            placeholder='Observaciones adicionales sobre el cliente...'
                            rows={4}
                            disabled={isSubmitting}
                          />
                        </div>
                      </div>
                    )}
                  </motion.div>
                </AnimatePresence>
              </form>
            </div>

            {/* Footer con botones */}
            <div className='border-t border-gray-200 bg-gray-50 px-6 py-4 dark:border-gray-800 dark:bg-gray-900/50'>
              <div className='flex items-center justify-between'>
                <button
                  type='button'
                  onClick={prevStep}
                  disabled={currentStep === 0}
                  className='flex items-center gap-1.5 rounded-lg border-2 border-gray-300 px-4 py-2 font-medium text-gray-700 transition-all hover:bg-gray-100 disabled:cursor-not-allowed disabled:opacity-40 dark:border-gray-700 dark:text-gray-300 dark:hover:bg-gray-800'
                >
                  <ChevronLeft className='h-4 w-4' />
                  Anterior
                </button>

                <div className='flex gap-2.5'>
                  <button
                    type='button'
                    onClick={onClose}
                    className='rounded-lg border-2 border-gray-300 px-5 py-2 font-medium text-gray-700 transition-all hover:bg-gray-100 dark:border-gray-700 dark:text-gray-300 dark:hover:bg-gray-800'
                    disabled={isSubmitting}
                  >
                    Cancelar
                  </button>

                  {currentStep < steps.length - 1 ? (
                    <button
                      type='button'
                      onClick={nextStep}
                      className='flex items-center gap-1.5 rounded-lg bg-gradient-to-r from-cyan-600 to-blue-600 px-5 py-2 font-medium text-white shadow-lg shadow-cyan-500/30 transition-all hover:shadow-xl hover:shadow-cyan-500/40 hover:-translate-y-0.5'
                    >
                      Siguiente
                      <ChevronRight className='h-4 w-4' />
                    </button>
                  ) : (
                    <button
                      type='submit'
                      onClick={onSubmit}
                      disabled={isSubmitting || (esEdicion && !hayCambios)}
                      title={
                        esEdicion && !hayCambios
                          ? 'No hay cambios por guardar'
                          : esEdicion
                            ? 'Guardar cambios'
                            : 'Crear cliente'
                      }
                      className='group flex items-center gap-1.5 rounded-lg bg-gradient-to-r from-cyan-600 to-blue-600 px-5 py-2 font-medium text-white shadow-lg shadow-cyan-500/30 transition-all hover:shadow-xl hover:shadow-cyan-500/40 hover:-translate-y-0.5 disabled:cursor-not-allowed disabled:opacity-50 disabled:hover:translate-y-0 disabled:shadow-none'
                    >
                      {isSubmitting ? (
                        <>
                          <motion.div
                            animate={{ rotate: 360 }}
                            transition={{ duration: 1, repeat: Infinity, ease: 'linear' }}
                            className='h-4 w-4 rounded-full border-2 border-white border-t-transparent'
                          />
                          Guardando...
                        </>
                      ) : esEdicion && !hayCambios ? (
                        <>
                          <Check className='h-4 w-4' />
                          Sin Cambios
                        </>
                      ) : (
                        <>
                          <Check className='h-4 w-4' />
                          {esEdicion ? 'Actualizar Cliente' : 'Crear Cliente'}
                        </>
                      )}
                    </button>
                  )}
                </div>
              </div>
            </div>
              </>
            )}
          </motion.div>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

/**
 * Smart Card Adaptiva para Fuentes de Pago V6 - CAMPOS DINÁMICOS
 *
 * ✨ ARQUITECTURA MODULAR:
 * - Configuración de campos desde BD (sin hardcode)
 * - CampoFormularioDinamico renderiza cualquier tipo
 * - Escalable: agregar fuentes sin cambiar código
 * - React Query para caché y tiempo real
 *
 * ✨ DISEÑO COMPACTO Y EFICIENTE:
 * - Vista compacta por defecto (info esencial en una línea)
 * - Expansión inteligente al click (todos los detalles)
 * - Estados visuales claros (completo, pendiente)
 * - Inputs reducidos (py-2) para mejor densidad
 *
 * 📋 SISTEMA DE DOCUMENTOS (MENSAJE CLARO):
 * - Si requiere carta → Mensaje informativo
 * - Usuario sabe que debe subir desde pestaña Documentos
 * - Sistema crea pendiente automático
 *
 * @version 6.0 - Sistema de Campos Dinámicos
 */

'use client'

import { memo, useState } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import { AlertCircle, Building2, CheckCircle2, DollarSign, Gift, Home, X } from 'lucide-react'

import type { TipoFuentePago } from '@/modules/clientes/types'
import { obtenerMonto } from '@/modules/clientes/utils/fuentes-pago-campos.utils'
import type { CampoConfig } from '@/modules/configuracion/types/campos-dinamicos.types'
import { esCreditoHipotecario, esCuotaInicial, esSubsidioCajaCompensacion, esSubsidioMiCasaYa } from '@/shared/constants/fuentes-pago.constants'

import type { FuentePagoConfig, FuentePagoErrores } from '../asignar-vivienda/types'

import { CampoFormularioDinamico } from './CampoFormularioDinamico'
import { useFuentePagoCard } from './useFuentePagoCard'

// ============================================
// CONFIGURACIÓN VISUAL
// ============================================

type TipoConfigItem = {
  icon: typeof DollarSign
  color: string
  bgColor: string
  borderColor: string
  descripcion: string
  requiereCarta: boolean
  requiereEntidad?: boolean // Si necesita banco o caja de compensación
  obligatorio?: boolean
}

const TIPO_CONFIG: Record<TipoFuentePago, TipoConfigItem> = {
  'Cuota Inicial': {
    icon: Home,
    color: 'text-green-600 dark:text-green-400',
    bgColor: 'bg-green-50 dark:bg-green-900/20',
    borderColor: 'border-green-300 dark:border-green-700',
    descripcion: 'Cuota inicial del cliente (pago directo)',
    requiereCarta: false,
  },
  'Crédito Hipotecario': {
    icon: Building2,
    color: 'text-blue-600 dark:text-blue-400',
    bgColor: 'bg-blue-50 dark:bg-blue-900/20',
    borderColor: 'border-blue-300 dark:border-blue-700',
    descripcion: 'Crédito bancario aprobado',
    requiereCarta: true,
    requiereEntidad: true, // ✅ Requiere banco
  },
  'Subsidio Mi Casa Ya': {
    icon: Gift,
    color: 'text-purple-600 dark:text-purple-400',
    bgColor: 'bg-purple-50 dark:bg-purple-900/20',
    borderColor: 'border-purple-300 dark:border-purple-700',
    descripcion: 'Subsidio nacional de vivienda',
    requiereCarta: true,
    requiereEntidad: false, // ❌ NO requiere banco/caja (solo número resolución)
  },
  'Subsidio Caja Compensación': {
    icon: DollarSign,
    color: 'text-orange-600 dark:text-orange-400',
    bgColor: 'bg-orange-50 dark:bg-orange-900/20',
    borderColor: 'border-orange-300 dark:border-orange-700',
    descripcion: 'Subsidio de caja de compensación',
    requiereCarta: true,
    requiereEntidad: true, // ✅ Requiere caja de compensación
  },
}

// 🔥 Configuración por defecto para fuentes dinámicas desconocidas
const DEFAULT_TIPO_CONFIG: TipoConfigItem = {
  icon: DollarSign,
  color: 'text-cyan-600 dark:text-cyan-400',
  bgColor: 'bg-cyan-50 dark:bg-cyan-900/20',
  borderColor: 'border-cyan-300 dark:border-cyan-700',
  descripcion: 'Fuente de pago personalizada',
  requiereCarta: true,
  requiereEntidad: false,
  obligatorio: false,
}

/**
 * 🔥 Obtener configuración de tipo (con fallback para fuentes dinámicas)
 */
function getTipoConfig(tipo: TipoFuentePago): TipoConfigItem {
  return TIPO_CONFIG[tipo] || DEFAULT_TIPO_CONFIG
}

const CATEGORIA_CARTAS_APROBACION_ID = '4898e798-c188-4f02-bfcf-b2b15be48e34'

// ============================================
// HELPERS
// ============================================

/**
 * Genera el título formateado del documento según el tipo de fuente
 */
function generarTituloDocumento(
  tipoFuente: TipoFuentePago,
  manzana: string | undefined,
  numeroVivienda: string | undefined,
  clienteNombre: string
): string {
  const vivienda = `${manzana}${numeroVivienda}` // Ej: "A1"
  const nombreMayusculas = clienteNombre.toUpperCase()

  switch (tipoFuente) {
    case 'Crédito Hipotecario':
      return `CARTA DE APROBACIÓN CRÉDITO ${vivienda} - ${nombreMayusculas}`

    case 'Subsidio Caja Compensación':
      return `CARTA CAJA DE COMPENSACIÓN ${vivienda} - ${nombreMayusculas}`

    case 'Subsidio Mi Casa Ya':
      return `CARTA SUBSIDIO MI CASA YA ${vivienda} - ${nombreMayusculas}`

    default:
      return `DOCUMENTO ${tipoFuente.toUpperCase()} ${vivienda} - ${nombreMayusculas}`
  }
}

// ============================================
// PROPS
// ============================================

export interface FuentePagoCardProps {
  tipo: TipoFuentePago
  config: FuentePagoConfig | null
  /** ✨ Configuración dinámica de campos desde BD */
  camposConfig: CampoConfig[]
  enabled?: boolean
  valorTotal: number
  errores?: FuentePagoErrores
  clienteId: string
  clienteNombre: string
  manzana?: string
  numeroVivienda?: string
  onEnabledChange?: (enabled: boolean) => void
  onChange: (config: FuentePagoConfig | null) => void
}

// ============================================
// COMPONENTE (SMART CARD ADAPTIVA)
// ============================================

function FuentePagoCardComponent(props: FuentePagoCardProps) {
  const {
    tipo, config, camposConfig, valorTotal, _errores, onChange,
    enabled = false,
    onEnabledChange
  } = props

  // ✨ ESTADO DE EXPANSIÓN (se expande automáticamente al activar)
  const [isExpanded, setIsExpanded] = useState(enabled)

  // ✅ Hook con lógica de campos dinámicos
  const hook = useFuentePagoCard({
    tipo,
    config,
    camposConfig, // ← Pasar configuración de campos
    obligatorio: getTipoConfig(tipo).obligatorio || false,
    enabledProp: props.enabled,
    onEnabledChange: props.onEnabledChange,
    onChange,
  })

  const tipoConfig = getTipoConfig(tipo) // 🔥 Usar función con fallback
  const Icon = tipoConfig.icon

  // 🔥 Obtener monto usando campos dinámicos
  const monto = obtenerMonto(config, camposConfig)

  const porcentaje = monto > 0 && valorTotal > 0
    ? ((monto / valorTotal) * 100).toFixed(1)
    : '0.0'

  // ✨ DETERMINAR ESTADO VISUAL (solo si está enabled y configurado)
  const getEstadoVisual = () => {
    if (!enabled || monto === 0) return null // No mostrar badge si no está activa o sin monto

    // ✅ Solo validar CAMPOS (no documentos)
    const tieneEntidad = !tipoConfig.requiereEntidad || (config?.entidad && config.entidad.trim() !== '')
    const tieneReferencia = esCuotaInicial(tipo) || (config?.numero_referencia && config.numero_referencia.trim() !== '')

    // ✅ Si todos los campos requeridos están llenos → Badge verde "Configurado"
    if (tieneEntidad && tieneReferencia) {
      return { icon: CheckCircle2, label: 'Configurado', color: 'text-green-600', bg: 'bg-green-100' }
    }

    // ❌ Si faltan campos → Sin badge (o podrías mostrar "Incompleto" si prefieres)
    return null
  }

  const estadoVisual = getEstadoVisual()

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      className={`rounded-xl border transition-all duration-200 ${
        enabled
          ? 'border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 hover:shadow-md'
          : 'border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50'
      }`}
    >
      {/* 🎯 VISTA COMPACTA (SIEMPRE VISIBLE) */}
      <div
        className="flex items-center justify-between p-3 cursor-pointer hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
        onClick={() => enabled && setIsExpanded(!isExpanded)}
      >
        {/* Left: Icono + Info Principal */}
        <div className="flex items-center gap-3 flex-1">
          {/* Toggle Enabled */}
          {!tipoConfig.obligatorio && (
            <label
              className="relative inline-flex cursor-pointer items-center"
              onClick={(e) => e.stopPropagation()}
            >
              <input
                type="checkbox"
                className="peer sr-only"
                checked={enabled}
                onChange={(e) => {
                  const isChecked = e.target.checked
                  onEnabledChange?.(isChecked)
                  // 🔥 Si activa, expandir automáticamente
                  setIsExpanded(isChecked)
                }}
              />
              <div className="peer h-5 w-9 rounded-full bg-gray-300 after:absolute after:left-[2px] after:top-[2px] after:h-4 after:w-4 after:rounded-full after:border after:border-gray-300 after:bg-white after:transition-all after:content-[''] peer-checked:bg-blue-600 peer-checked:after:translate-x-full peer-checked:after:border-white peer-focus:outline-none peer-focus:ring-2 peer-focus:ring-blue-300 dark:border-gray-600 dark:bg-gray-700"></div>
            </label>
          )}

          {/* Icono de tipo */}
          <div className={`flex h-8 w-8 items-center justify-center rounded-lg ${enabled ? tipoConfig.bgColor : 'bg-gray-200 dark:bg-gray-700'}`}>
            <Icon className={`h-4 w-4 ${enabled ? tipoConfig.color : 'text-gray-500'}`} />
          </div>

          {/* Info principal */}
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2">
              <h4 className="font-semibold text-gray-900 dark:text-white text-sm truncate">
                {tipo}
                {config?.entidad && (
                  <span className="text-xs text-gray-500 font-normal ml-1">
                    - {config.entidad}
                  </span>
                )}
              </h4>
            </div>

            {enabled && monto > 0 && (
              <p className="text-sm text-gray-600 dark:text-gray-400">
                ${monto.toLocaleString('es-CO')} ({porcentaje}%)
              </p>
            )}
            {!enabled && (
              <p className="text-xs text-gray-500">Clic en el toggle para activar</p>
            )}
          </div>
        </div>

        {/* Right: Solo badge de estado */}
        <div className="flex items-center gap-2">
          {/* Badge de estado (solo si está enabled y tiene config) */}
          {estadoVisual && (
            <div className={`flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium ${estadoVisual.bg} ${estadoVisual.color}`}>
              <estadoVisual.icon className="h-3 w-3" />
              <span className="hidden sm:inline">{estadoVisual.label}</span>
            </div>
          )}
        </div>
      </div>

      {/* 🎯 VISTA EXPANDIDA (CON ANIMACIÓN) */}
      <AnimatePresence>
        {enabled && isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.3, ease: 'easeInOut' }}
            className="overflow-hidden border-t border-gray-200 dark:border-gray-700"
          >
            <div className="p-3 space-y-3 bg-gray-50/50 dark:bg-gray-700/20">
              {/* ============================================ */}
              {/* CAMPOS DINÁMICOS DESDE BD */}
              {/* ============================================ */}

              {camposConfig
                .sort((a, b) => a.orden - b.orden) // ← Ordenar por propiedad "orden"
                .map((campoConfig) => (
                  <CampoFormularioDinamico
                    key={campoConfig.nombre}
                    config={campoConfig}
                    value={hook.valores[campoConfig.nombre] || null}
                    onChange={(valor) => hook.handleCampoChange(campoConfig.nombre, valor)}
                    error={hook.errores[campoConfig.nombre]}
                  />
                ))}

              {/* Mensaje de porcentaje (solo para monto_aprobado) */}
              {!!config?.monto_aprobado && valorTotal > 0 && (
                <div className="px-3 py-2 rounded-lg bg-gradient-to-r from-cyan-50 to-blue-50 dark:from-cyan-950/30 dark:to-blue-950/30 border border-cyan-200 dark:border-cyan-800">
                  <p className="text-xs text-cyan-800 dark:text-cyan-200 font-medium">
                    💰 Representa el <span className="font-bold">{porcentaje}%</span> del valor total (${valorTotal.toLocaleString('es-CO')})
                  </p>
                </div>
              )}

              {/* Mensaje informativo para documentación */}
              {tipoConfig.requiereCarta && (
                <div>
                  {/* Mensaje específico según tipo de fuente */}
                  <div className="p-3 rounded-lg border border-blue-200 dark:border-blue-800 bg-blue-50/80 dark:bg-blue-950/30">
                    <div className="flex items-start gap-2">
                      <AlertCircle className="h-4 w-4 text-blue-600 dark:text-blue-400 mt-0.5 flex-shrink-0" />
                      <div className="flex-1">
                        <p className="text-sm font-semibold text-blue-900 dark:text-blue-100">
                          {esCreditoHipotecario(tipo) && '📄 Carta de Aprobación del Banco'}
                          {esSubsidioMiCasaYa(tipo) && '📄 Carta de Asignación del Subsidio'}
                          {esSubsidioCajaCompensacion(tipo) && '📄 Carta de Asignación de la Caja'}
                          {!esCreditoHipotecario(tipo) && !esSubsidioMiCasaYa(tipo) && !esSubsidioCajaCompensacion(tipo) && '📄 Documentación Requerida'}
                        </p>
                        <p className="text-xs text-blue-700 dark:text-blue-300 mt-1">
                          Una vez asignada la vivienda, ve a la pestaña <span className="font-semibold">"Documentos"</span> del cliente para subir {esCreditoHipotecario(tipo) ? 'la carta de aprobación del banco' : esSubsidioMiCasaYa(tipo) ? 'la carta de asignación del subsidio' : esSubsidioCajaCompensacion(tipo) ? 'la carta de asignación de la caja de compensación' : 'la documentación requerida'}.
                        </p>
                      </div>
                    </div>
                  </div>

                  {/* Mostrar estado de documento si ya existe */}
                  {config?.carta_aprobacion_url && (
                    <div className="mt-2 flex items-center justify-between p-2.5 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-lg">
                      <div className="flex items-center gap-2">
                        <CheckCircle2 className="h-4 w-4 text-green-600" />
                        <span className="text-sm font-medium text-green-800 dark:text-green-200">
                          {esCreditoHipotecario(tipo) && 'Carta del banco registrada'}
                          {esSubsidioMiCasaYa(tipo) && 'Carta del subsidio registrada'}
                          {esSubsidioCajaCompensacion(tipo) && 'Carta de la caja registrada'}
                          {!esCreditoHipotecario(tipo) && !esSubsidioMiCasaYa(tipo) && !esSubsidioCajaCompensacion(tipo) && 'Documento registrado'}
                        </span>
                      </div>
                      <button
                        type="button"
                        onClick={hook.handleRemoveDocument}
                        className="p-1.5 text-red-600 hover:text-red-800 transition-colors rounded-lg hover:bg-red-100 dark:hover:bg-red-900/30"
                        title="Desvincular documento"
                      >
                        <X className="h-4 w-4" />
                      </button>
                    </div>
                  )}
                </div>
              )}

            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  )
}

// ✅ Exportar con React.memo para optimización de rendimiento
// Solo re-renderiza si las props relevantes cambian
export const FuentePagoCard = memo(FuentePagoCardComponent, (prevProps, nextProps) => {
  // Comparación personalizada: solo re-renderizar si estas props cambian
  return (
    prevProps.tipo === nextProps.tipo &&
    prevProps.enabled === nextProps.enabled &&
    prevProps.valorTotal === nextProps.valorTotal &&
    JSON.stringify(prevProps.config) === JSON.stringify(nextProps.config) &&
    JSON.stringify(prevProps.errores) === JSON.stringify(nextProps.errores) &&
    JSON.stringify(prevProps.camposConfig) === JSON.stringify(nextProps.camposConfig) // ← Comparar configuración de campos
  )
})

'use client'

import { FileText } from 'lucide-react'

import type { SnapshotVersion } from '../../types/historial'
import { historialVersionesModalStyles as styles } from '../modals/HistorialVersionesModal.styles'

interface ResumenCambiosProps {
  version: SnapshotVersion
}

export function ResumenCambios({ version }: ResumenCambiosProps) {
  const datos = version.datos_nuevos as any

  // Si no tiene motivo_usuario, no mostrar nada
  if (!datos?.motivo_usuario) return null

  const { motivo_usuario, resumen } = datos

  return (
    <div className={styles.resumen.container}>
      {/* Motivo del Usuario */}
      <div className={styles.resumen.motivoBox}>
        <p className={styles.resumen.motivoLabel}>
          <FileText className={styles.resumen.motivoIcon} />
          Motivo del cambio:
        </p>
        <p className={styles.resumen.motivoText}>{motivo_usuario}</p>
      </div>

      {/* Estadísticas de Cambios */}
      {resumen &&
        (resumen.agregadas > 0 || resumen.eliminadas > 0 || resumen.modificadas > 0) && (
          <div className={styles.resumen.statsGrid}>
            {resumen.agregadas > 0 && (
              <div className={styles.resumen.statCard.agregada}>
                <p className={styles.resumen.statValue.agregada}>+{resumen.agregadas}</p>
                <p className={styles.resumen.statLabel.agregada}>Agregada(s)</p>
              </div>
            )}
            {resumen.eliminadas > 0 && (
              <div className={styles.resumen.statCard.eliminada}>
                <p className={styles.resumen.statValue.eliminada}>-{resumen.eliminadas}</p>
                <p className={styles.resumen.statLabel.eliminada}>Eliminada(s)</p>
              </div>
            )}
            {resumen.modificadas > 0 && (
              <div className={styles.resumen.statCard.modificada}>
                <p className={styles.resumen.statValue.modificada}>✏️{resumen.modificadas}</p>
                <p className={styles.resumen.statLabel.modificada}>Modificada(s)</p>
              </div>
            )}
          </div>
        )}
    </div>
  )
}

'use client'

import { AnimatePresence, motion } from 'framer-motion'
import { CheckCircle2, ChevronDown, DollarSign } from 'lucide-react'

import {
    formatCurrency,
    formatDateTime,
    getTipoCambioIcon,
    getTipoCambioLabel,
} from '../../hooks/useHistorialVersionesModal'
import type { SnapshotVersion } from '../../types/historial'
import { historialVersionesModalStyles as styles } from '../modals/HistorialVersionesModal.styles'

import { CambioVisual } from './CambioVisual'
import { ResumenCambios } from './ResumenCambios'

interface VersionCardProps {
  version: SnapshotVersion
  isExpanded: boolean
  onToggle: () => void
