export function VersionCard({ version, isExpanded, onToggle }: VersionCardProps) {
  const fuentesPago = (version.fuentes_pago_snapshot || []) as any[]

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className={styles.versionCard.container}
    >
      {/* Header */}
      <div className={styles.versionCard.header.container} onClick={onToggle}>
        <div className={styles.versionCard.header.content}>
          {/* Información */}
          <div className={styles.versionCard.header.leftSection}>
            <div className="flex items-center gap-2">
              <span className={styles.versionCard.header.versionBadge}>
                {getTipoCambioIcon(version.tipo_cambio)}
                v{version.version}
              </span>
            </div>
            <p className={styles.versionCard.header.typeLabel}>
              {getTipoCambioLabel(version.tipo_cambio)}
            </p>
            {version.razon_cambio && (
              <p className={styles.versionCard.header.reasonText}>
                {version.razon_cambio}
              </p>
            )}
            <p className={styles.versionCard.header.dateText}>
              {formatDateTime(version.created_at)}
            </p>
          </div>

          {/* Botón Expandir */}
          <button className={styles.versionCard.header.expandButton}>
            <ChevronDown
              className={
                isExpanded
                  ? styles.versionCard.header.expandIconRotated
                  : styles.versionCard.header.expandIcon
              }
            />
          </button>
        </div>
      </div>

      {/* Contenido Expandido */}
      <AnimatePresence>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
            className={styles.versionCard.expanded.container}
          >
            {/* Campos Modificados */}
            {version.campos_modificados && version.campos_modificados.length > 0 && (
              <div className={styles.versionCard.expanded.badgeContainer}>
                {version.campos_modificados.map((campo, i) => (
                  <span key={i} className={styles.versionCard.expanded.badge}>
                    {campo}
                  </span>
                ))}
              </div>
            )}

            {/* Fuentes de Pago Snapshot */}
            {fuentesPago.length > 0 && (
              <div>
                <p className={styles.fuentesPago.title}>
                  <DollarSign className={styles.fuentesPago.titleIcon} />
                  Fuentes de Pago Activas en esta Versión
                </p>
                <div className={styles.fuentesPago.container}>
                  {fuentesPago.map((fuente: any, i: number) => (
                    <div key={i} className={styles.fuentesPago.card}>
                      <div className={styles.fuentesPago.cardHeader}>
                        <div>
                          <p className={styles.fuentesPago.cardType}>{fuente.tipo}</p>
                          {fuente.entidad && (
                            <p className={styles.fuentesPago.cardEntidad}>
                              {fuente.entidad}
                            </p>
                          )}
                        </div>
                        <p className={styles.fuentesPago.cardMonto}>
                          {formatCurrency(fuente.monto_aprobado || 0)}
                        </p>
                      </div>
                      {fuente.monto_recibido > 0 && (
                        <div className={styles.fuentesPago.cardRecibido}>
                          <CheckCircle2 className={styles.fuentesPago.cardRecibidoIcon} />
                          Recibido: {formatCurrency(fuente.monto_recibido)}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Resumen de Cambios (motivo + estadísticas) */}
            {version.datos_nuevos && <ResumenCambios version={version} />}

            {/* Cambio Visual (diff anterior vs nuevo) */}
            {version.datos_anteriores && version.datos_nuevos && (
              <CambioVisual version={version} />
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  )
}

'use client'

import { useEffect, useMemo, useState } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import {
    AlertCircle,
    DollarSign,
    FileText,
    Plus,
    Save,
    Trash2,
    X
} from 'lucide-react'

interface FuentePago {
  id?: string
  tipo: string
  entidad?: string
  monto_aprobado: number
  monto_recibido: number
}

interface FuentesPagoEditarModalProps {
  isOpen: boolean
  onClose: () => void
  fuentesActuales: FuentePago[]
  valorFinal?: number
  onGuardar: (fuentes: Partial<FuentePago>[], motivoCambio: string) => Promise<void>
}

export function FuentesPagoEditarModal({
  isOpen,
  onClose,
  fuentesActuales,
  onGuardar,
}: FuentesPagoEditarModalProps) {
  const [fuentes, setFuentes] = useState<Partial<FuentePago>[]>(
    fuentesActuales.map((f) => ({ ...f }))
  )
  const [motivoCambio, setMotivoCambio] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [isSubmitting, setIsSubmitting] = useState(false)

  // ✅ Resetear estado cuando se abre el modal
  useEffect(() => {
    if (isOpen) {
      setFuentes(fuentesActuales.map((f) => ({ ...f })))
      setMotivoCambio('')
      setError(null)
    }
  }, [isOpen, fuentesActuales])

  // ✅ Calcular total de fuentes
  const totalFuentes = useMemo(() => {
    return fuentes.reduce((sum, f) => sum + (Number(f.monto_aprobado) || 0), 0)
  }, [fuentes])

  const agregarFuente = () => {
    setFuentes([
      ...fuentes,
      {
        tipo: '',
        entidad: '',
        monto_aprobado: 0,
        monto_recibido: 0,
      },
    ])
  }

  const eliminarFuente = (index: number) => {
    setFuentes(fuentes.filter((_, i) => i !== index))
  }

  const actualizarFuente = (index: number, campo: string, valor: any) => {
    const nuevasFuentes = [...fuentes]

    // ✅ Convertir a número si es campo de monto
    const valorFinal = (campo === 'monto_aprobado' || campo === 'monto_recibido')
      ? Number(valor) || 0
      : valor

    nuevasFuentes[index] = {
      ...nuevasFuentes[index],
      [campo]: valorFinal,
    }

    setFuentes(nuevasFuentes)
  }

  const handleGuardar = async () => {
    // Validar motivo obligatorio
    if (!motivoCambio.trim()) {
      setError('Debes proporcionar un motivo para este cambio')
      return
    }

    // Validar fuentes
    const fuentesValidas = fuentes.filter(
      (f) => f.tipo && f.monto_aprobado && f.monto_aprobado > 0
    )

    if (fuentesValidas.length === 0) {
      setError('Debe haber al menos una fuente de pago válida')
      return
    }

    setError(null)
    setIsSubmitting(true)

    try {
      await onGuardar(fuentesValidas, motivoCambio)
      onClose()
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Error al guardar')
    } finally {
      setIsSubmitting(false)
    }
  }

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Overlay */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50"
          />

          {/* Modal */}
          <motion.div
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4"
          >
            <div className="w-full max-w-3xl bg-white dark:bg-gray-800 rounded-2xl shadow-2xl overflow-hidden">
              {/* Header */}
              <div className="bg-gradient-to-r from-blue-600 via-indigo-600 to-purple-600 px-6 py-4">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-xl bg-white/20 backdrop-blur-sm flex items-center justify-center">
                      <DollarSign className="w-6 h-6 text-white" />
                    </div>
                    <div>
                      <h2 className="text-xl font-bold text-white">
                        Editar Fuentes de Pago
                      </h2>
                      <p className="text-blue-100 text-sm">
                        {fuentes.length} fuente(s) configurada(s)
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={onClose}
                    className="p-2 hover:bg-white/20 rounded-lg transition-colors"
                  >
                    <X className="w-5 h-5 text-white" />
                  </button>
                </div>
              </div>

              {/* Content */}
              <div className="p-6 space-y-6 max-h-[70vh] overflow-y-auto">
                {/* Motivo del Cambio (OBLIGATORIO) */}
                <div className="p-4 rounded-xl bg-yellow-50 dark:bg-yellow-950/30 border border-yellow-200 dark:border-yellow-800">
                  <label className="flex items-center gap-2 text-sm font-semibold text-yellow-900 dark:text-yellow-100 mb-2">
                    <FileText className="w-4 h-4" />
                    ¿Por qué estás realizando este cambio? *
                  </label>
                  <textarea
                    value={motivoCambio}
                    onChange={(e) => setMotivoCambio(e.target.value)}
                    placeholder="Ejemplo: Cliente no fue aprobado para subsidio, se cambia por crédito hipotecario..."
                    className="w-full px-3 py-2 bg-white dark:bg-gray-900 border-2 border-yellow-300 dark:border-yellow-700 rounded-lg focus:border-yellow-500 focus:ring-2 focus:ring-yellow-500/20 transition-all text-sm resize-none"
                    rows={3}
                    required
                  />
                  <p className="text-xs text-yellow-700 dark:text-yellow-300 mt-1">
                    Este motivo quedará registrado en el historial de versiones
                  </p>
                </div>

                {/* Error */}
                {error && (
                  <div className="p-3 rounded-lg bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-800 flex items-start gap-2">
                    <AlertCircle className="w-5 h-5 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" />
                    <p className="text-sm text-red-700 dark:text-red-300">{error}</p>
                  </div>
                )}

                {/* Fuentes de Pago */}
                <div className="space-y-3">
                  {fuentes.map((fuente, index) => (
                    <div
                      key={index}
                      className="p-4 rounded-xl bg-gray-50 dark:bg-gray-900/50 border border-gray-200 dark:border-gray-700"
                    >
                      <div className="flex items-start justify-between mb-3">
                        <p className="text-sm font-semibold text-gray-700 dark:text-gray-300">
                          Fuente {index + 1}
                        </p>
                        {fuentes.length > 1 && (
                          <button
                            onClick={() => eliminarFuente(index)}
                            className="p-1.5 hover:bg-red-100 dark:hover:bg-red-900/30 rounded-lg transition-colors"
                          >
                            <Trash2 className="w-4 h-4 text-red-600 dark:text-red-400" />
                          </button>
                        )}
                      </div>

                      <div className="grid grid-cols-2 gap-3">
                        {/* Tipo */}
                        <div>
                          <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">
                            Tipo de Fuente *
                          </label>
                          <select
                            value={fuente.tipo || ''}
                            onChange={(e) => actualizarFuente(index, 'tipo', e.target.value)}
                            className="w-full px-3 py-2 bg-white dark:bg-gray-900 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all text-sm"
                            required
                          >
                            <option value="">Seleccionar...</option>
                            <option value="Crédito Hipotecario">Crédito Hipotecario</option>
                            <option value="Subsidio Caja Compensación">Subsidio Caja</option>
                            <option value="Subsidio Nacional">Subsidio Nacional</option>
                            <option value="Cuota Inicial">Cuota Inicial</option>
                            <option value="Recursos Propios">Recursos Propios</option>
                          </select>
                        </div>

                        {/* Entidad */}
                        <div>
                          <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">
                            Entidad
                          </label>
                          <input
                            type="text"
                            value={fuente.entidad || ''}
                            onChange={(e) => actualizarFuente(index, 'entidad', e.target.value)}
                            placeholder="Banco, Caja..."
                            className="w-full px-3 py-2 bg-white dark:bg-gray-900 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all text-sm"
                          />
                        </div>

                        {/* Monto Aprobado */}
                        <div>
                          <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">
                            Monto Aprobado *
                          </label>
                          <input
                            type="number"
                            value={fuente.monto_aprobado || 0}
                            onChange={(e) =>
                              actualizarFuente(index, 'monto_aprobado', parseFloat(e.target.value))
                            }
                            placeholder="0"
                            className="w-full px-3 py-2 bg-white dark:bg-gray-900 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all text-sm"
                            required
                          />
                        </div>

                        {/* Monto Recibido */}
                        <div>
                          <label className="block text-xs font-medium text-gray-600 dark:text-gray-400 mb-1">
                            Monto Recibido
                          </label>
                          <input
                            type="number"
                            value={fuente.monto_recibido || 0}
                            onChange={(e) =>
                              actualizarFuente(index, 'monto_recibido', parseFloat(e.target.value))
                            }
                            placeholder="0"
                            className="w-full px-3 py-2 bg-white dark:bg-gray-900 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all text-sm"
                          />
                        </div>
                      </div>
                    </div>
                  ))}

                  {/* Botón Agregar */}
                  <button
                    onClick={agregarFuente}
                    className="w-full p-3 rounded-xl border-2 border-dashed border-gray-300 dark:border-gray-600 hover:border-blue-500 dark:hover:border-blue-500 hover:bg-blue-50 dark:hover:bg-blue-950/30 transition-all flex items-center justify-center gap-2 text-gray-600 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400"
                  >
                    <Plus className="w-5 h-5" />
                    <span className="text-sm font-medium">Agregar otra fuente</span>
                  </button>
                </div>
              </div>

              {/* Footer */}
              <div className="px-6 py-4 bg-gray-50 dark:bg-gray-900/50 border-t border-gray-200 dark:border-gray-700 flex items-center justify-end gap-3">
                <button
                  onClick={onClose}
                  disabled={isSubmitting}
                  className="px-4 py-2 rounded-lg border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors text-sm font-medium disabled:opacity-50"
                >
                  Cancelar
                </button>
                <button
                  onClick={handleGuardar}
                  disabled={isSubmitting}
                  className="px-4 py-2 rounded-lg bg-gradient-to-r from-blue-600 to-indigo-600 text-white hover:from-blue-700 hover:to-indigo-700 transition-all text-sm font-medium disabled:opacity-50 flex items-center gap-2"
                >
                  <Save className="w-4 h-4" />
                  {isSubmitting ? 'Guardando...' : 'Guardar Cambios'}
                </button>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  )
}

'use client'

/**
 * Modal de reactivación de cliente
 * Flujo: Confirmar → Loading (doble anillo) → Éxito (con animación)
 */

import { useEffect, useRef, useState } from 'react'

import { motion } from 'framer-motion'
import { RefreshCw, UserCheck, X } from 'lucide-react'
import { createPortal } from 'react-dom'

type ModalState = 'confirm' | 'loading' | 'success'

interface ReactivarClienteModalProps {
  isOpen: boolean
  nombreCliente: string
  onClose: () => void
  onConfirm: () => Promise<void>
}

const OVERLAY_CLS =
  'fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-[3px]'
const CONTAINER_CLS =
  'relative w-full max-w-sm overflow-hidden rounded-2xl bg-white dark:bg-gray-900 shadow-2xl border border-white/10'

const PARTICLE_COLORS = ['#06b6d4', '#3b82f6', '#10b981', '#8b5cf6', '#f59e0b', '#ec4899', '#06b6d4', '#3b82f6']

export function ReactivarClienteModal({
  isOpen,
  nombreCliente,
  onClose,
  onConfirm,
}: ReactivarClienteModalProps) {
  const [estado, setEstado] = useState<ModalState>('confirm')
  const prevOpen = useRef(isOpen)

  // Resetear al 'confirm' cada vez que el modal se re-abra
  useEffect(() => {
    if (isOpen && !prevOpen.current) {
      setEstado('confirm')
    }
    prevOpen.current = isOpen
  }, [isOpen])

  const handleConfirmar = async () => {
    setEstado('loading')
    try {
      await onConfirm()
      setEstado('success')
      setTimeout(() => onClose(), 2400)
    } catch {
      setEstado('confirm')
    }
  }

  if (typeof window === 'undefined' || !isOpen) return null

  // ── LOADING ───────────────────────────────────────────────────────────
  if (estado === 'loading') {
    return createPortal(
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className={OVERLAY_CLS}>
        <motion.div
          initial={{ scale: 0.92, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          transition={{ type: 'spring', stiffness: 420, damping: 28 }}
          className={CONTAINER_CLS}
          onClick={(e) => e.stopPropagation()}
          role="dialog"
          aria-modal="true"
          aria-label="Reactivando cliente"
        >
          {/* Ambient glow cyan */}
          <div
            className="pointer-events-none absolute inset-0"
            style={{ background: 'radial-gradient(ellipse at bottom right, rgba(6,182,212,0.10) 0%, transparent 65%)' }}
          />
          {/* Left accent bar */}
          <div
            className="absolute bottom-0 left-0 top-0 w-[3px]"
            style={{ background: 'linear-gradient(to bottom, #06b6d4 0%, transparent 100%)' }}
          />

          <div className="flex flex-col items-center justify-center py-14 px-6 gap-5">
            <p className="text-xs font-semibold uppercase tracking-widest text-cyan-500 dark:text-cyan-400">
              Reactivando cliente...
            </p>

            {/* Doble anillo — mismo patrón que formularios de clientes/viviendas/proyectos */}
            <div className="relative">
              <div className="w-16 h-16 border-4 border-cyan-200 dark:border-cyan-900 rounded-full" />
              <div className="absolute inset-0 w-16 h-16 border-4 border-t-cyan-600 dark:border-t-cyan-400 rounded-full animate-spin" />
            </div>

            <div className="text-center">
              <p className="text-sm font-semibold text-gray-900 dark:text-gray-100">
                Procesando cambio de estado
              </p>
              <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                Esto tomará solo un momento
              </p>
            </div>
          </div>
        </motion.div>
      </motion.div>,
      document.body
    )
  }

  // ── ÉXITO ─────────────────────────────────────────────────────────────
  if (estado === 'success') {
    return createPortal(
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className={OVERLAY_CLS}>
        <motion.div
          initial={{ scale: 0.85, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          transition={{ type: 'spring', stiffness: 280, damping: 22 }}
          className={CONTAINER_CLS}
          onClick={(e) => e.stopPropagation()}
          role="dialog"
          aria-modal="true"
          aria-label="Cliente reactivado exitosamente"
        >
          {/* Ambient glow verde */}
          <div
            className="pointer-events-none absolute inset-0"
            style={{ background: 'radial-gradient(ellipse at bottom right, rgba(16,185,129,0.12) 0%, transparent 65%)' }}
          />
          {/* Left accent bar verde */}
          <div
            className="absolute bottom-0 left-0 top-0 w-[3px]"
            style={{ background: 'linear-gradient(to bottom, #10b981 0%, transparent 100%)' }}
          />

          <div className="flex flex-col items-center justify-center py-12 px-6 overflow-hidden relative">
            {/* Partículas de confeti */}
            {PARTICLE_COLORS.map((color, i) => (
              <motion.div
                key={i}
                initial={{ x: 0, y: 0, opacity: 1, scale: 0 }}
                animate={{
                  x: Math.cos(i * (Math.PI / 4)) * 70,
                  y: Math.sin(i * (Math.PI / 4)) * 70,
                  opacity: 0,
                  scale: 1.4,
                }}
                transition={{ duration: 1.1, delay: 0.05, ease: 'easeOut' }}
                className="absolute top-[30%] left-1/2 w-2 h-2 rounded-full"
                style={{ backgroundColor: color }}
              />
            ))}

            {/* Ícono de éxito */}
            <motion.div
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ type: 'spring', stiffness: 300, damping: 20, delay: 0.05 }}
              className="w-20 h-20 rounded-full bg-gradient-to-br from-cyan-400 to-cyan-600 flex items-center justify-center shadow-xl shadow-cyan-500/30"
            >
              <UserCheck className="w-10 h-10 text-white" />
            </motion.div>

            {/* Texto */}
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.28 }}
              className="text-center mt-5"
            >
              <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-1.5">
                ¡Cliente Reactivado!
              </h3>
              <p className="text-sm text-gray-600 dark:text-gray-400">
                <span className="font-semibold text-cyan-600 dark:text-cyan-400">{nombreCliente}</span>{' '}
                ahora está en estado{' '}
                <span className="font-semibold text-emerald-600 dark:text-emerald-400">Interesado</span>
              </p>
            </motion.div>

            {/* Cierre automático */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.9 }}
              className="flex items-center gap-1.5 mt-5 text-xs text-gray-400 dark:text-gray-500"
            >
              <div className="w-3 h-3 rounded-full border-2 border-gray-300 dark:border-gray-600 border-t-gray-500 dark:border-t-gray-300 animate-spin" />
              <span>Cerrando automáticamente...</span>
            </motion.div>
          </div>
        </motion.div>
      </motion.div>,
      document.body
    )
  }

  // ── CONFIRM (estado por defecto) ───────────────────────────────────────
  return createPortal(
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className={OVERLAY_CLS}
      onClick={onClose}
    >
      <motion.div
        initial={{ opacity: 0, y: 20, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ type: 'spring', stiffness: 500, damping: 28 }}
        className={CONTAINER_CLS}
        onClick={(e) => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-label="Confirmar reactivación de cliente"
      >
        {/* Ambient glow cyan */}
        <div
          className="pointer-events-none absolute inset-0"
          style={{ background: 'radial-gradient(ellipse at bottom right, rgba(6,182,212,0.10) 0%, transparent 65%)' }}
        />
        {/* Left accent bar */}
        <div
          className="absolute bottom-0 left-0 top-0 w-[3px]"
          style={{ background: 'linear-gradient(to bottom, #06b6d4 0%, transparent 100%)' }}
        />

        {/* Botón cerrar */}
        <button
          onClick={onClose}
          aria-label="Cerrar"
          className="absolute right-3.5 top-3.5 z-10 rounded-lg p-1.5 text-zinc-400 transition-colors hover:bg-black/[0.06] hover:text-zinc-700 dark:text-zinc-500 dark:hover:bg-white/[0.07] dark:hover:text-zinc-200"
        >
          <X className="h-4 w-4" />
        </button>

        <div className="relative pb-5 pl-6 pr-5 pt-5">
          {/* Ícono + Título */}
          <div className="mb-3.5 flex items-start gap-3 pr-8">
            <div className="mt-0.5 flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-xl bg-cyan-500/10 ring-1 ring-cyan-500/25">
              <RefreshCw className="h-4 w-4 text-cyan-400" />
            </div>
            <h2 className="text-[15px] font-semibold leading-snug text-zinc-900 dark:text-white">
              ¿Reactivar cliente?
            </h2>
          </div>

          {/* Mensaje */}
          <div className="mb-5 pl-11 text-[13px] leading-relaxed text-zinc-500 dark:text-zinc-400">
            <p>
              El estado de{' '}
              <span className="font-semibold text-cyan-600 dark:text-cyan-400">{nombreCliente}</span>{' '}
              cambiará a{' '}
              <span className="font-semibold text-emerald-600 dark:text-emerald-400">"Interesado"</span>{' '}
              y podrá asignársele una nueva vivienda.
            </p>
          </div>

          {/* Separador */}
          <div className="mb-4 h-px bg-zinc-900/[0.06] dark:bg-white/[0.07]" />

          {/* Acciones */}
          <div className="flex items-center justify-end gap-2">
            <button
              onClick={onClose}
              className="rounded-lg px-4 py-2 text-[13px] font-medium text-zinc-500 transition-colors hover:bg-zinc-100 hover:text-zinc-800 dark:text-zinc-400 dark:hover:bg-white/[0.07] dark:hover:text-zinc-100"
            >
              Cancelar
            </button>
            <button
              onClick={handleConfirmar}
              className="inline-flex items-center gap-2 rounded-lg px-4 py-2 text-[13px] font-semibold text-white bg-cyan-600 hover:bg-cyan-500 active:scale-[0.98] transition-all duration-150 shadow-[0_4px_18px_rgba(6,182,212,0.38)]"
            >
              <RefreshCw className="h-3.5 w-3.5" />
              Reactivar Cliente
            </button>
          </div>
        </div>
      </motion.div>
    </motion.div>,
    document.body
  )
}

/**
 * Componente: Diff de Fuentes de Pago
 * Muestra los cambios realizados entre versiones de fuentes de pago
 * ✅ Separación de responsabilidades: Usa helpers para lógica, solo renderiza
 */

'use client'

import { CheckCircle2, Plus, RefreshCw, Trash2 } from 'lucide-react'

import { detectarCambiosFuentes, filtrarCambiosReales, formatCurrency } from '../historial-helpers'

interface DiffFuentesPagoProps {
  fuentesActuales: any[]
  fuentesAnteriores: any[]
}

export function DiffFuentesPago({ fuentesActuales, fuentesAnteriores }: DiffFuentesPagoProps) {
  // ✅ Usar helpers para lógica
  const cambios = detectarCambiosFuentes(fuentesActuales, fuentesAnteriores)
  const cambiosReales = filtrarCambiosReales(cambios)

  // Calcular total de fuentes actuales
  const totalFuentes = fuentesActuales.reduce(
    (sum, fuente) => sum + (fuente.monto_aprobado || 0),
    0
  )

  if (cambiosReales.length === 0) {
    return (
      <div className="text-center py-4 text-sm text-gray-500 dark:text-gray-400">
        No se detectaron cambios en las fuentes de pago
      </div>
    )
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="mb-3 p-2.5 rounded-lg bg-purple-50 dark:bg-purple-950/30 border border-purple-200 dark:border-purple-800">
        <p className="text-xs font-bold text-purple-900 dark:text-purple-100 flex items-center gap-1.5">
          <RefreshCw className="w-3.5 h-3.5" />
          Detalle de cambios realizados:
        </p>
      </div>

      {/* Lista de cambios */}
      {cambiosReales.map((cambio, index) => (
        <div
          key={index}
          className={`p-2.5 rounded-lg border text-xs ${
            cambio.tipo === 'agregada'
              ? 'bg-green-50 dark:bg-green-950/20 border-green-300 dark:border-green-800'
              : cambio.tipo === 'eliminada'
              ? 'bg-rose-50 dark:bg-rose-950/20 border-rose-300 dark:border-rose-800'
              : 'bg-blue-50 dark:bg-blue-950/20 border-blue-300 dark:border-blue-800'
          }`}
        >
          <div className="flex items-start gap-2">
            {/* Icono */}
            {cambio.tipo === 'agregada' ? (
              <Plus className="w-3.5 h-3.5 text-green-600 dark:text-green-400 mt-0.5 flex-shrink-0" />
            ) : cambio.tipo === 'eliminada' ? (
              <Trash2 className="w-3.5 h-3.5 text-rose-600 dark:text-rose-400 mt-0.5 flex-shrink-0" />
            ) : (
              <RefreshCw className="w-3.5 h-3.5 text-blue-600 dark:text-blue-400 mt-0.5 flex-shrink-0" />
            )}

            {/* Contenido */}
            <div className="flex-1 min-w-0">
              <p
                className={`font-semibold text-xs ${
                  cambio.tipo === 'agregada'
                    ? 'text-green-900 dark:text-green-100'
                    : cambio.tipo === 'eliminada'
                    ? 'text-rose-900 dark:text-rose-100'
                    : 'text-blue-900 dark:text-blue-100'
                }`}
              >
                {cambio.tipo === 'agregada' && '✅ Agregada: '}
                {cambio.tipo === 'eliminada' && '❌ Eliminada: '}
                {cambio.tipo === 'modificada' && '🔄 Modificada: '}
                {cambio.fuente.tipo}
              </p>

              {/* Detalles: Fuente agregada */}
              {cambio.tipo === 'agregada' && (
                <div className="mt-1 space-y-0.5 text-green-700 dark:text-green-300">
                  <p>• Monto: {formatCurrency(cambio.fuente.monto_aprobado || 0)}</p>
                  {cambio.fuente.entidad && <p>• Entidad: {cambio.fuente.entidad}</p>}
                </div>
              )}

              {/* Detalles: Fuente eliminada */}
              {cambio.tipo === 'eliminada' && (
                <div className="mt-1 text-rose-700 dark:text-rose-300">
                  <p>• Se eliminó: {formatCurrency(cambio.fuente.monto_aprobado || 0)}</p>
                </div>
              )}

              {/* Detalles: Fuente modificada */}
              {cambio.tipo === 'modificada' && cambio.cambiosDetectados && (
                <div className="mt-1.5 space-y-1">
                  {/* Cambio de monto */}
                  {cambio.cambiosDetectados.monto && (
                    <div className="flex items-center gap-2">
                      <span className="text-rose-600 dark:text-rose-400 line-through text-xs">
                        {formatCurrency(cambio.cambiosDetectados.monto.anterior)}
                      </span>
                      <span className="text-gray-400">→</span>
                      <span className="text-green-600 dark:text-green-400 font-semibold text-xs">
                        {formatCurrency(cambio.cambiosDetectados.monto.nuevo)}
                      </span>
                      <span
                        className={`text-xs font-medium ${
                          cambio.cambiosDetectados.monto.nuevo > cambio.cambiosDetectados.monto.anterior
                            ? 'text-green-600 dark:text-green-400'
                            : 'text-rose-600 dark:text-rose-400'
                        }`}
                      >
                        (
                        {cambio.cambiosDetectados.monto.nuevo > cambio.cambiosDetectados.monto.anterior
                          ? '+'
                          : ''}
                        {formatCurrency(
                          cambio.cambiosDetectados.monto.nuevo - cambio.cambiosDetectados.monto.anterior
                        )}
                        )
                      </span>
                    </div>
                  )}

                  {/* Cambio de entidad */}
                  {cambio.cambiosDetectados.entidad && (
                    <p className="text-xs text-blue-700 dark:text-blue-300">
                      • Entidad: {cambio.cambiosDetectados.entidad.anterior || 'Sin entidad'} →{' '}
                      {cambio.cambiosDetectados.entidad.nuevo || 'Sin entidad'}
                    </p>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      ))}

      {/* Separador */}
      <div className="my-4 border-t-2 border-dashed border-gray-300 dark:border-gray-600" />

      {/* Estado Final de Fuentes */}
      <div className="mt-4 p-3 rounded-lg bg-cyan-50 dark:bg-cyan-950/30 border border-cyan-200 dark:border-cyan-800">
        <div className="flex items-center gap-2 mb-3">
          <CheckCircle2 className="w-4 h-4 text-cyan-600 dark:text-cyan-400" />
          <p className="text-xs font-bold text-cyan-900 dark:text-cyan-100">
            Estado final de fuentes en esta versión:
          </p>
        </div>

        {fuentesActuales.length === 0 ? (
          <p className="text-xs text-cyan-700 dark:text-cyan-300 italic text-center py-2">
            Sin fuentes de pago activas
          </p>
        ) : (
          <div className="space-y-2">
            {fuentesActuales.map((fuente, index) => (
              <div
                key={index}
                className="flex items-center justify-between p-2 rounded-md bg-white dark:bg-gray-800 border border-cyan-200 dark:border-cyan-700"
              >
                <div className="flex-1">
                  <p className="text-xs font-semibold text-gray-900 dark:text-white">
                    {fuente.tipo}
                  </p>
                  {fuente.entidad && (
                    <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                      {fuente.entidad}
                    </p>
                  )}
                </div>
                <div className="text-right">
                  <p className="text-sm font-bold text-cyan-600 dark:text-cyan-400">
                    {formatCurrency(fuente.monto_aprobado || 0)}
                  </p>
                </div>
              </div>
            ))}

            {/* Total */}
            <div className="pt-2 border-t border-cyan-200 dark:border-cyan-700">
              <div className="flex items-center justify-between p-2 rounded-md bg-cyan-100 dark:bg-cyan-900/50">
                <p className="text-xs font-bold text-cyan-900 dark:text-cyan-100">
                  Total fuentes de pago:
                </p>
                <p className="text-base font-bold text-cyan-700 dark:text-cyan-300">
                  {formatCurrency(totalFuentes)}
                </p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

/**
 * Componente: Card de Versión Individual
 * Tarjeta que muestra una versión con header colapsable y contenido expandible
 * ✅ Separación de responsabilidades: Orquestador, delega en sub-componentes
 */

'use client'

import { motion } from 'framer-motion'

import type { SnapshotVersion } from '../../../hooks/useHistorialVersiones'

import { VersionCardContent } from './VersionCardContent'
import { VersionCardHeader } from './VersionCardHeader'

interface VersionCardProps {
  version: SnapshotVersion
  versionAnterior: SnapshotVersion | null
  isLatest: boolean
  isExpanded: boolean
  onToggle: () => void
}

export function VersionCard({ version, versionAnterior, isLatest, isExpanded, onToggle }: VersionCardProps) {
  const fuentesPago = version.fuentes_pago_snapshot || []
  const fuentesPagoAnteriores = versionAnterior?.fuentes_pago_snapshot || []

  return (
    <motion.div
      layout
      className={`
        rounded-xl border-2 overflow-hidden transition-all
        ${
          isLatest
            ? 'border-green-500 bg-green-50 dark:bg-green-950/30'
            : 'border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800'
        }
      `}
    >
      <VersionCardHeader version={version} isLatest={isLatest} isExpanded={isExpanded} onToggle={onToggle} />

      <VersionCardContent
        isExpanded={isExpanded}
        fuentesPago={fuentesPago}
        fuentesPagoAnteriores={fuentesPagoAnteriores}
      />
    </motion.div>
  )
}

/**
 * Componente: Contenido Expandible de Card de Versión
 * Muestra el diff detallado de los cambios
 * ✅ Separación de responsabilidades: Solo UI, usa DiffFuentesPago
 */

'use client'

import { AnimatePresence, motion } from 'framer-motion'

import { DiffFuentesPago } from './DiffFuentesPago'

interface VersionCardContentProps {
  isExpanded: boolean
  fuentesPago: any[]
  fuentesPagoAnteriores: any[]
}

export function VersionCardContent({ isExpanded, fuentesPago, fuentesPagoAnteriores }: VersionCardContentProps) {
  return (
    <AnimatePresence>
      {isExpanded && (
        <motion.div
          initial={{ height: 0, opacity: 0 }}
          animate={{ height: 'auto', opacity: 1 }}
          exit={{ height: 0, opacity: 0 }}
          className="border-t border-gray-200 dark:border-gray-700"
        >
          <div className="p-4 bg-gray-50 dark:bg-gray-900/50">
            <DiffFuentesPago fuentesActuales={fuentesPago} fuentesAnteriores={fuentesPagoAnteriores} />
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

/**
 * Componente: Header de Card de Versión
 * Header colapsable con información resumida del cambio
 * ✅ Separación de responsabilidades: Solo UI, recibe datos procesados
 */

'use client'

import { ChevronDown, ChevronUp, Clock, Plus, RefreshCw, Trash2 } from 'lucide-react'

import { formatDateCompact } from '@/lib/utils/date.utils'

import type { SnapshotVersion } from '../../../hooks/useHistorialVersiones'
import { getTipoCambioLabel } from '../historial-helpers'

import { TipoCambioIcon } from './TipoCambioIcon'

interface VersionCardHeaderProps {
  version: SnapshotVersion
  isLatest: boolean
  isExpanded: boolean
  onToggle: () => void
}

export function VersionCardHeader({ version, isLatest, isExpanded, onToggle }: VersionCardHeaderProps) {
  const resumen = version.datos_nuevos?.resumen

  return (
    <button
      onClick={onToggle}
      className="w-full p-4 flex items-center justify-between hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
    >
      <div className="flex items-center gap-3">
        {/* Badge Versión */}
        <div
          className={`
            px-3 py-1 rounded-full text-sm font-bold
            ${
              isLatest
                ? 'bg-green-500 text-white'
                : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300'
            }
          `}
        >
          v{version.version}
        </div>

        {/* Info */}
        <div className="text-left flex-1">
          <div className="flex items-center gap-2">
            <TipoCambioIcon tipoCambio={version.tipo_cambio} />
            <p className="text-sm font-semibold text-gray-900 dark:text-white">
              {getTipoCambioLabel(version.tipo_cambio)}
            </p>
          </div>

          {/* Motivo */}
          <div className="mt-2">
            <p className="text-xs font-semibold text-gray-500 dark:text-gray-400">Motivo:</p>
            <p className="text-xs text-gray-600 dark:text-gray-400 italic">
              "{version.datos_nuevos?.motivo_usuario || version.razon_cambio}"
            </p>
          </div>

          {/* Resumen de cambios */}
          {resumen ? (
            <div className="mt-2">
              <p className="text-xs font-semibold text-gray-500 dark:text-gray-400 mb-1">
                Cambios realizados:
              </p>
              <div className="flex items-center gap-3 text-xs">
                {resumen.agregadas > 0 && (
                  <span className="flex items-center gap-1 text-green-600 dark:text-green-400">
                    <Plus className="w-3 h-3" />
                    {resumen.agregadas} agregada(s)
                  </span>
                )}
                {resumen.eliminadas > 0 && (
                  <span className="flex items-center gap-1 text-red-600 dark:text-red-400">
                    <Trash2 className="w-3 h-3" />
                    {resumen.eliminadas} eliminada(s)
                  </span>
                )}
                {resumen.modificadas > 0 && (
                  <span className="flex items-center gap-1 text-amber-600 dark:text-amber-400">
                    <RefreshCw className="w-3 h-3" />
                    {resumen.modificadas} modificada(s)
                  </span>
                )}
              </div>
            </div>
          ) : null}

          {/* Fecha y usuario */}
          <div className="flex flex-wrap items-center gap-x-3 gap-y-1 mt-2">
            <div className="flex items-center gap-1 text-xs text-gray-500 dark:text-gray-500">
              <Clock className="w-3 h-3" />
              <span className="font-medium">Fecha:</span>
              {formatDateCompact(version.fecha_cambio)}
            </div>
            {version.usuario_nombre && (
              <div className="flex items-center gap-1 text-xs">
                <span className="font-medium text-gray-500 dark:text-gray-500">Realizado por:</span>
                <span className="px-2 py-0.5 rounded-full bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 font-medium">
                  {version.usuario_nombre}
                </span>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Expand Icon */}
      {isExpanded ? (
        <ChevronUp className="w-5 h-5 text-gray-400" />
      ) : (
        <ChevronDown className="w-5 h-5 text-gray-400" />
      )}
    </button>
  )
}

/**
 * ============================================
 * HELPERS: Historial de Versiones
 * ============================================
 * Funciones puras para iconos, labels y lógica de diff
 * Separación: Solo lógica, sin UI
 */

import type { LucideIcon } from 'lucide-react'
import {
    DollarSign,
    FileText,
    Plus,
    RefreshCw,
    Trash2,
} from 'lucide-react'

// ============================================
// Iconos por tipo de cambio
// ============================================

export function getTipoCambioIcon(tipo: string): LucideIcon {
  const icons: Record<string, LucideIcon> = {
    fuentes_pago_actualizadas: DollarSign,
    fuente_agregada: Plus,
    fuente_eliminada: Trash2,
    fuente_modificada: RefreshCw,
    estado_cambiado: RefreshCw,
    creacion: Plus,
  }

  return icons[tipo] || FileText
}

// ============================================
// Color por tipo de cambio
// ============================================

export function getTipoCambioColor(tipo: string): string {
  const colors: Record<string, string> = {
    fuentes_pago_actualizadas: 'text-purple-600 dark:text-purple-400',
    fuente_agregada: 'text-green-600 dark:text-green-400',
    fuente_eliminada: 'text-red-600 dark:text-red-400',
    fuente_modificada: 'text-blue-600 dark:text-blue-400',
    estado_cambiado: 'text-orange-600 dark:text-orange-400',
    creacion: 'text-cyan-600 dark:text-cyan-400',
  }

  return colors[tipo] || 'text-gray-600 dark:text-gray-400'
}

// ============================================
// Labels legibles por tipo de cambio
// ============================================

export function getTipoCambioLabel(tipo: string): string {
  const labels: Record<string, string> = {
    fuentes_pago_actualizadas: '💰 Fuentes de pago actualizadas',
    fuente_agregada: '➕ Fuente agregada',
    fuente_eliminada: '🗑️ Fuente eliminada',
    fuente_modificada: '🔄 Fuente modificada',
    estado_cambiado: '📊 Estado modificado',
    creacion: '✨ Negociación creada',
  }

  // Fallback: convertir snake_case a Title Case
  return labels[tipo] || tipo.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())
}

// ============================================
// Detectar cambios entre fuentes (Diff)
// ============================================

export interface CambioFuente {
  tipo: 'agregada' | 'eliminada' | 'modificada' | 'sin_cambios'
  fuente: any
  cambiosDetectados?: {
    monto?: { anterior: number; nuevo: number }
    entidad?: { anterior?: string; nuevo?: string }
  }
}

export function detectarCambiosFuentes(
  fuentesActuales: any[],
  fuentesAnteriores: any[]
): CambioFuente[] {
  const cambios: CambioFuente[] = []

  // Detectar fuentes eliminadas
  fuentesAnteriores.forEach(anterior => {
    const existe = fuentesActuales.find(actual => actual.tipo === anterior.tipo)
    if (!existe) {
      cambios.push({
        tipo: 'eliminada',
        fuente: anterior,
      })
    }
  })

  // Detectar fuentes agregadas o modificadas
  fuentesActuales.forEach(actual => {
    const anterior = fuentesAnteriores.find(a => a.tipo === actual.tipo)

    if (!anterior) {
      // Nueva fuente
      cambios.push({
        tipo: 'agregada',
        fuente: actual,
      })
    } else {
      // Verificar si hay cambios
      const cambiosDetectados: any = {}

      if (anterior.monto_aprobado !== actual.monto_aprobado) {
        cambiosDetectados.monto = {
          anterior: anterior.monto_aprobado,
          nuevo: actual.monto_aprobado,
        }
      }

      if (anterior.entidad !== actual.entidad) {
        cambiosDetectados.entidad = {
          anterior: anterior.entidad,
          nuevo: actual.entidad,
        }
      }

      if (Object.keys(cambiosDetectados).length > 0) {
        cambios.push({
          tipo: 'modificada',
          fuente: actual,
          cambiosDetectados,
        })
      } else {
        cambios.push({
          tipo: 'sin_cambios',
          fuente: actual,
        })
      }
    }
  })

  return cambios
}

// ============================================
// Filtrar solo cambios reales
// ============================================

export function filtrarCambiosReales(cambios: CambioFuente[]): CambioFuente[] {
  return cambios.filter(c => c.tipo !== 'sin_cambios')
}

// ============================================
// Formatear monto (helper reutilizable)
// ============================================

export function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount)
}

