/**
 * PasoPersonal — Paso 1: Datos personales del cliente
 * Campos: nombres, apellidos, tipo_documento, numero_documento,
 *         fecha_nacimiento (opcional), estado_civil (opcional)
 *
 * ✅ Filtrado en tiempo real del número de documento según tipo seleccionado
 * ✅ inputMode dinámico (teclado numérico en móvil para CC, TI, CE, PEP)
 * ✅ maxLength y placeholder dinámicos
 */

'use client'

import { useCallback, useEffect, useRef } from 'react'

import { motion } from 'framer-motion'
import type { FieldErrors, UseFormRegister, UseFormSetValue, UseFormWatch } from 'react-hook-form'

import { REGLAS_DOCUMENTO, type TipoDocumentoColombia } from '@/modules/clientes/utils/validacion-documentos-colombia'
import {
    AccordionWizardField,
    AccordionWizardSelect,
    fieldStaggerAnim,
} from '@/shared/components/accordion-wizard'

const TIPOS_DOCUMENTO = [
  { value: 'CC', label: 'Cédula de Ciudadanía' },
  { value: 'CE', label: 'Cédula de Extranjería' },
  { value: 'TI', label: 'Tarjeta de Identidad' },
  { value: 'NIT', label: 'NIT' },
  { value: 'PP', label: 'Pasaporte' },
  { value: 'PEP', label: 'PEP' },
]

const ESTADOS_CIVILES = [
  { value: 'Soltero(a)', label: 'Soltero(a)' },
  { value: 'Casado(a)', label: 'Casado(a)' },
  { value: 'Unión libre', label: 'Unión libre' },
  { value: 'Viudo(a)', label: 'Viudo(a)' },
]

interface PasoPersonalProps {
  register: UseFormRegister<any>
  errors: FieldErrors<any>
  watch: UseFormWatch<any>
  setValue: UseFormSetValue<any>
}

export function PasoPersonal({ register, errors, watch, setValue }: PasoPersonalProps) {
  const tipoDocumento = watch('tipo_documento') as TipoDocumentoColombia
  const reglas = REGLAS_DOCUMENTO[tipoDocumento] ?? REGLAS_DOCUMENTO.CC
  const prevTipoRef = useRef(tipoDocumento)

  // Limpiar numero_documento cuando cambia el tipo de documento
  useEffect(() => {
    if (prevTipoRef.current !== tipoDocumento) {
      setValue('numero_documento', '', { shouldValidate: false })
      prevTipoRef.current = tipoDocumento
    }
  }, [tipoDocumento, setValue])

  /**
   * Filtro en tiempo real: bloquea caracteres inválidos según tipo de documento.
   * - CC, TI, CE, PEP → solo dígitos
   * - NIT → dígitos y guión
   * - PP → letras mayúsculas y dígitos
   */
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    // Permitir teclas de control: backspace, delete, tab, arrows, enter, ctrl+A/C/V/X
    const controlKeys = ['Backspace', 'Delete', 'Tab', 'ArrowLeft', 'ArrowRight', 'Enter', 'Home', 'End']
    if (controlKeys.includes(e.key)) return
    if (e.ctrlKey || e.metaKey) return

    if (reglas.soloDigitos) {
      // CC, TI, CE, PEP → solo dígitos
      if (!/^\d$/.test(e.key)) {
        e.preventDefault()
      }
    } else if (tipoDocumento === 'NIT') {
      // NIT → dígitos y un guión
      if (!/^[\d-]$/.test(e.key)) {
        e.preventDefault()
      }
    } else if (tipoDocumento === 'PP') {
      // Pasaporte → letras y dígitos (se convierte a mayúsculas en onInput)
      if (!/^[a-zA-Z0-9]$/.test(e.key)) {
        e.preventDefault()
      }
    }
  }, [reglas.soloDigitos, tipoDocumento])

  /** Para pasaporte: convertir a mayúsculas automáticamente */
  const handleInput = useCallback((e: React.FormEvent<HTMLInputElement>) => {
    if (tipoDocumento === 'PP') {
      const input = e.currentTarget
      const upper = input.value.toUpperCase()
      if (input.value !== upper) {
        input.value = upper
      }
    }
  }, [tipoDocumento])

  return (
    <div className="space-y-4">
      {/* Nombres y Apellidos */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <motion.div {...fieldStaggerAnim(0)}>
          <AccordionWizardField
            {...register('nombres')}
            label="Nombres"
            required
            moduleName="clientes"
            error={errors.nombres?.message as string}
          />
        </motion.div>
        <motion.div {...fieldStaggerAnim(1)}>
          <AccordionWizardField
            {...register('apellidos')}
            label="Apellidos"
            required
            moduleName="clientes"
            error={errors.apellidos?.message as string}
          />
        </motion.div>
      </div>

      {/* Tipo y Número de Documento */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <motion.div {...fieldStaggerAnim(2)}>
          <AccordionWizardSelect
            {...register('tipo_documento')}
            label="Tipo de Documento"
            required
            moduleName="clientes"
            error={errors.tipo_documento?.message as string}
          >
            {TIPOS_DOCUMENTO.map((t) => (
              <option key={t.value} value={t.value}>{t.label}</option>
            ))}
          </AccordionWizardSelect>
        </motion.div>
        <motion.div {...fieldStaggerAnim(3)}>
          <AccordionWizardField
            {...register('numero_documento')}
            label="Número de Documento"
            required
            moduleName="clientes"
            error={errors.numero_documento?.message as string}
            inputMode={reglas.inputMode}
            maxLength={reglas.maxLength}
            onKeyDown={handleKeyDown}
            onInput={handleInput}
          />
          <p className="mt-1 text-[11px] text-gray-400 dark:text-gray-500">
            {reglas.descripcion}
          </p>
        </motion.div>
      </div>

      {/* Fecha Nacimiento y Estado Civil (opcionales) */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <motion.div {...fieldStaggerAnim(4)}>
          <AccordionWizardField
            {...register('fecha_nacimiento')}
            label="Fecha de Nacimiento"
            type="date"
            moduleName="clientes"
            error={errors.fecha_nacimiento?.message as string}
          />
        </motion.div>
        <motion.div {...fieldStaggerAnim(5)}>
          <AccordionWizardSelect
            {...register('estado_civil')}
            label="Estado Civil"
            moduleName="clientes"
            error={errors.estado_civil?.message as string}
          >
            <option value="">Sin especificar</option>
            {ESTADOS_CIVILES.map((e) => (
              <option key={e.value} value={e.value}>{e.label}</option>
            ))}
          </AccordionWizardSelect>
        </motion.div>
      </div>
    </div>
  )
}

'use client'

import { useState } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import { ChevronDown, ChevronRight } from 'lucide-react'

import { DocumentoCardHorizontal } from '@/modules/documentos/components/lista/documento-card-horizontal'
import { CategoriaIcon } from '@/modules/documentos/components/shared/categoria-icon'


interface DocumentosAgrupadosProps {
  documentos: any[]
  categorias: any[]
  onView: (doc: any) => void
  onDownload: (doc: any) => void
  onToggleImportante: (doc: any) => void
  onArchive: (doc: any) => void
  onDelete: (doc: any) => void
  onRename: (doc: any) => void
  onAsignarCategoria: (doc: any) => void
  onRefresh?: () => void | Promise<void> // 🆕 Callback para refrescar
}

export function DocumentosAgrupados({
  documentos,
  categorias,
  onView,
  onDownload,
  onToggleImportante,
  onArchive,
  onDelete,
  onRename,
  onAsignarCategoria,
  onRefresh, // 🆕 Prop de refresh
}: DocumentosAgrupadosProps) {
  const [categoriasExpandidas, setCategoriasExpandidas] = useState<Set<string>>(
    new Set(categorias.map(c => c.id))
  )

  const toggleCategoria = (categoriaId: string) => {
    setCategoriasExpandidas(prev => {
      const nuevo = new Set(prev)
      if (nuevo.has(categoriaId)) {
        nuevo.delete(categoriaId)
      } else {
        nuevo.add(categoriaId)
      }
      return nuevo
    })
  }

  // Agrupar documentos por categoría
  const documentosPorCategoria = categorias.map(categoria => ({
    categoria,
    documentos: documentos.filter(doc => doc.categoria_id === categoria.id)
  }))

  // Documentos sin categoría
  const docsSinCategoria = documentos.filter(doc => !doc.categoria_id)

  return (
    <div className='space-y-4'>
      {/* Categorías con documentos */}
      {documentosPorCategoria.map(({ categoria, documentos: docs }) => {
        if (docs.length === 0) return null

        const estaExpandida = categoriasExpandidas.has(categoria.id)

        return (
          <div key={categoria.id} className='overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm dark:border-gray-700 dark:bg-gray-800'>
            {/* Header de categoría */}
            <button
              onClick={() => toggleCategoria(categoria.id)}
              className='flex w-full items-center justify-between p-4 transition-colors hover:bg-gray-50 dark:hover:bg-gray-700/50'
            >
              <div className='flex items-center gap-3'>
                {/* Ícono de categoría */}
                <div
                  className='flex h-10 w-10 items-center justify-center rounded-lg'
                  style={{
                    background: `linear-gradient(135deg, ${categoria.color}22, ${categoria.color}44)`
                  }}
                >
                  <CategoriaIcon
                    icono={categoria.icono}
                    color={categoria.color}
                    size={20}
                  />
                </div>

                {/* Nombre y contador */}
                <div className='text-left'>
                  <h3 className='font-semibold text-gray-900 dark:text-white'>
                    {categoria.nombre}
                  </h3>
                  <p className='text-sm text-gray-500 dark:text-gray-400'>
                    {docs.length} {docs.length === 1 ? 'documento' : 'documentos'}
                  </p>
                </div>
              </div>

              {/* Ícono expandir/contraer */}
              <div className='text-gray-400'>
                {estaExpandida ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
              </div>
            </button>

            {/* Lista de documentos */}
            <AnimatePresence>
              {estaExpandida && (
                <motion.div
                  initial={{ height: 0, opacity: 0 }}
                  animate={{ height: 'auto', opacity: 1 }}
                  exit={{ height: 0, opacity: 0 }}
                  transition={{ duration: 0.2 }}
                  className='border-t border-gray-200 bg-gray-50 dark:border-gray-700 dark:bg-gray-900/20'
                >
                  <div className='space-y-2 p-4'>
                    {docs.map(documento => (
                      <DocumentoCardHorizontal
                        key={documento.id}
                        documento={documento}
                        categoria={categoria}
                        onView={onView}
                        onDownload={onDownload}
                        onToggleImportante={onToggleImportante}
                        onArchive={onArchive}
                        onDelete={onDelete}
                        onRename={onRename}
                        onRefresh={onRefresh} // 🆕 Callback para refrescar
                        // No permitir categorizar la cédula (ya tiene categoría fija)
                        onAsignarCategoria={documento.id === 'cedula-ciudadania' ? undefined : onAsignarCategoria}
                      />
                    ))}
                  </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        )
      })}

      {/* Documentos sin categoría */}
      {docsSinCategoria.length > 0 && (
        <div className='overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm dark:border-gray-700 dark:bg-gray-800'>
          <button
            onClick={() => toggleCategoria('sin-categoria')}
            className='flex w-full items-center justify-between p-4 transition-colors hover:bg-gray-50 dark:hover:bg-gray-700/50'
          >
            <div className='flex items-center gap-3'>
              <div className='flex h-10 w-10 items-center justify-center rounded-lg bg-gray-100 dark:bg-gray-700'>
                <span className='text-xl'>📁</span>
              </div>

              <div className='text-left'>
                <h3 className='font-semibold text-gray-900 dark:text-white'>
                  Sin Categoría
                </h3>
                <p className='text-sm text-gray-500 dark:text-gray-400'>
                  {docsSinCategoria.length} {docsSinCategoria.length === 1 ? 'documento' : 'documentos'}
                </p>
              </div>
            </div>

            <div className='text-gray-400'>
              {categoriasExpandidas.has('sin-categoria') ? <ChevronDown size={20} /> : <ChevronRight size={20} />}
            </div>
          </button>

          <AnimatePresence>
            {categoriasExpandidas.has('sin-categoria') && (
              <motion.div
                initial={{ height: 0, opacity: 0 }}
                animate={{ height: 'auto', opacity: 1 }}
                exit={{ height: 0, opacity: 0 }}
                transition={{ duration: 0.2 }}
                className='border-t border-gray-200 bg-gray-50 dark:border-gray-700 dark:bg-gray-900/20'
              >
                <div className='space-y-2 p-4'>
                  {docsSinCategoria.map(documento => (
                    <DocumentoCardHorizontal
                      key={documento.id}
                      documento={documento}
                      onView={onView}
                      onDownload={onDownload}
                      onToggleImportante={onToggleImportante}
                      onArchive={onArchive}
                      onDelete={onDelete}
                      onRename={onRename}
                      onRefresh={onRefresh} // 🆕 Callback para refrescar
                      // No permitir categorizar la cédula (ya tiene categoría fija)
                      onAsignarCategoria={documento.id === 'cedula-ciudadania' ? undefined : onAsignarCategoria}
                    />
                  ))}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      )}
    </div>
  )
}

// ============================================
// HOOK: useCategoriasCliente
// Gestión de categorías de documentos para clientes
// ============================================

import { useCallback, useEffect, useState } from 'react'

import { logger } from '@/lib/utils/logger'
import { CategoriasService } from '@/modules/documentos/services/categorias.service'
import type { CategoriaDocumento, CategoriaFormData } from '@/modules/documentos/types/documento.types'

import { useDocumentosClienteStore } from '../store/documentos-cliente.store'

interface UseCategoriasClienteProps {
  userId: string
}

type ModoVista = 'lista' | 'crear' | 'editar'

export function useCategoriasCliente({ userId }: UseCategoriasClienteProps) {
  const { categorias, cargandoCategorias, cargarCategorias } = useDocumentosClienteStore()

  const [modo, setModo] = useState<ModoVista>('lista')
  const [categoriaEditando, setCategoriaEditando] = useState<CategoriaDocumento | null>(null)
  const [eliminando, setEliminando] = useState<string | null>(null)

  // Cargar categorías al montar
  useEffect(() => {
    cargarCategorias(userId)
  }, [userId, cargarCategorias])

  // Navegación
  const handleIrACrear = useCallback(() => {
    setModo('crear')
    setCategoriaEditando(null)
  }, [])

  const handleIrAEditar = useCallback((categoria: CategoriaDocumento) => {
    setModo('editar')
    setCategoriaEditando(categoria)
  }, [])

  const handleVolverALista = useCallback(() => {
    setModo('lista')
    setCategoriaEditando(null)
  }, [])

  // CRUD
  const handleCrear = useCallback(
    async (data: CategoriaFormData) => {
      try {
        const maxOrden = Math.max(0, ...categorias.map(c => c.orden || 0))
        const datosAInsertar = {
          nombre: data.nombre,
          descripcion: data.descripcion,
          color: data.color,
          icono: data.icono,
          orden: maxOrden + 1,
          es_global: data.esGlobal ?? false,
          modulos_permitidos: data.esGlobal ? [] : (data.modulosPermitidos ?? ['clientes']),
        }

        await CategoriasService.crearCategoria(userId, datosAInsertar)
        await cargarCategorias(userId)
        handleVolverALista()
      } catch (error) {
        const mensaje = error instanceof Error ? error.message : 'Error desconocido'
        logger.error('[CLIENTES] Error al crear categoría:', mensaje, error)
        throw error
      }
    },
    [userId, categorias, cargarCategorias, handleVolverALista]
  )

  const handleActualizar = useCallback(
    async (data: CategoriaFormData) => {
      if (!categoriaEditando?.id) return

      try {
        await CategoriasService.actualizarCategoria(categoriaEditando.id, data)
        await cargarCategorias(userId)
        handleVolverALista()
      } catch (error) {
        const mensaje = error instanceof Error ? error.message : 'Error desconocido'
        logger.error('[CLIENTES] Error al actualizar categoría:', mensaje, error)
        throw error
      }
    },
    [categoriaEditando, userId, cargarCategorias, handleVolverALista]
  )

  const handleEliminar = useCallback(
    async (categoriaId: string) => {
      if (!confirm('¿Estás seguro de eliminar esta categoría?')) return

      setEliminando(categoriaId)
      try {
        await CategoriasService.eliminarCategoria(categoriaId)
        await cargarCategorias(userId)
      } catch (error) {
        const mensaje = error instanceof Error ? error.message : 'Error desconocido'
        logger.error('[CLIENTES] Error al eliminar categoría:', mensaje, error)
      } finally {
        setEliminando(null)
      }
    },
    [userId, cargarCategorias]
  )

  const handleInicializarDefault = useCallback(async () => {
    try {
      await CategoriasService.crearCategoriasDefault(userId)
      await cargarCategorias(userId)
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error al inicializar categorías:', mensaje, error)
    }
  }, [userId, cargarCategorias])

  return {
    // Estado
    modo,
    categoriaEditando,
    eliminando,
    categorias,
    estaCargando: cargandoCategorias,
    tieneCategorias: categorias.length > 0,

    // Acciones
    handleIrACrear,
    handleIrAEditar,
    handleVolverALista,
    handleCrear,
    handleActualizar,
    handleEliminar,
    handleInicializarDefault,
  }
}

