/**
 * ============================================
 * HOOK: useClienteDetalle
 * ============================================
 *
 * ✅ SEPARACIÓN DE RESPONSABILIDADES
 * Hook que maneja TODA la lógica de la vista de detalle del cliente.
 * Consolida los 5 useEffect del componente original.
 *
 * Responsabilidades:
 * - Resolver slug a UUID del cliente
 * - Cargar datos del cliente con React Query
 * - Gestionar tabs activos
 * - Cargar categorías de documentos
 * - Escuchar eventos de actualización y cambio de tab
 * - Validar documento de identidad
 * - Cargar documentos del cliente
 */

import { useCallback, useEffect, useState } from 'react'

import { useRouter } from 'next/navigation'

import { useAuth } from '@/contexts/auth-context'
import { logger } from '@/lib/utils/logger'
import { resolverSlugCliente } from '@/lib/utils/slug.utils'
import { useDocumentoIdentidad } from '@/modules/clientes/documentos/hooks/useDocumentoIdentidad'
import { useClienteQuery } from '@/modules/clientes/hooks'
import { useDocumentosQuery } from '@/modules/documentos/hooks/useDocumentosQuery'
import { CategoriasService } from '@/modules/documentos/services'
import { useDocumentosStore } from '@/modules/documentos/store/documentos.store'

interface UseClienteDetalleProps {
  clienteIdSlug: string // Puede ser slug o UUID
}

export type TabType = 'general' | 'intereses' | 'negociacion' | 'negociaciones' | 'documentos' | 'historial' | 'vivienda-asignada' | 'fuentes-pago'

export function useClienteDetalle({ clienteIdSlug }: UseClienteDetalleProps) {
  const router = useRouter()
  const { user } = useAuth()

  // =====================================================
  // ESTADO
  // =====================================================

  const [clienteUUID, setClienteUUID] = useState<string | null>(null)
  const [activeTab, setActiveTab] = useState<TabType>('general')
  const [modalInteresAbierto, setModalInteresAbierto] = useState(false)

  // Activar tab desde intent guardado en sessionStorage (p.ej. desde módulo Abonos)
  useEffect(() => {
    const intent = sessionStorage.getItem('cliente-tab-intent')
    if (intent && ['general', 'intereses', 'negociacion', 'documentos', 'historial'].includes(intent)) {
      setActiveTab(intent as TabType)
      sessionStorage.removeItem('cliente-tab-intent')
    }
  }, [])

  // =====================================================
  // STORES Y QUERIES
  // =====================================================

  // Store de documentos (GENÉRICO)
  const {
    modalSubirAbierto,
    cerrarModalSubir,
  } = useDocumentosStore()

  // Función para cargar categorías (reemplaza método del store legacy)
  const cargarCategorias = useCallback(async () => {
    if (!user?.id) return
    try {
      await CategoriasService.obtenerCategoriasPorModulo(user.id, 'clientes')
    } catch (error) {
      logger.error('Error cargando categorías:', error)
    }
  }, [user?.id])

  // ✅ REACT QUERY: Cargar cliente automáticamente
  const {
    data: cliente,
    isLoading: loading,
    error,
    refetch: recargarCliente,
  } = useClienteQuery(clienteUUID)

  // ✅ Hook de validación de documento de identidad
  const { tieneCedula, cargando: cargandoValidacion } = useDocumentoIdentidad({
    clienteId: clienteUUID || '',
  })

  // ✅ Query de documentos para contador
  const { documentos: documentosCliente } = useDocumentosQuery(clienteUUID || '', 'cliente')

  // =====================================================
  // EFECTOS
  // =====================================================

  // 1. Resolver slug a UUID
  useEffect(() => {
    const resolverSlug = async () => {
      const uuid = await resolverSlugCliente(clienteIdSlug)
      if (uuid) {
        setClienteUUID(uuid)
      } else {
        logger.error('❌ [useClienteDetalle] No se pudo resolver el cliente')
        router.push('/clientes')
      }
    }

    resolverSlug()
  }, [clienteIdSlug, router])

  // 2. Cargar categorías al montar (si hay usuario)
  useEffect(() => {
    if (user?.id) {
      cargarCategorias()
    }
  }, [user?.id, cargarCategorias])

  // 3. Listener para cambio de tab (desde otros componentes)
  useEffect(() => {
    const handleCambiarTab = (event: any) => {
      const nuevoTab = event.detail as TabType
      setActiveTab(nuevoTab)
    }

    if (typeof window !== 'undefined') {
      window.addEventListener('cambiar-tab', handleCambiarTab)
      return () => window.removeEventListener('cambiar-tab', handleCambiarTab)
    }
  }, [])

  // 4. Listener para actualización de cliente (cuando se sube cédula)
  useEffect(() => {
    if (!clienteUUID) return

    const handleClienteActualizado = () => {
      recargarCliente()
    }

    if (typeof window !== 'undefined') {
      window.addEventListener('cliente-actualizado', handleClienteActualizado)
      return () => window.removeEventListener('cliente-actualizado', handleClienteActualizado)
    }
  }, [clienteUUID, recargarCliente])

  // =====================================================
  // ACCIONES
  // =====================================================

  /**
   * Cambiar tab activo programáticamente
   */
  const cambiarTab = useCallback((tab: TabType) => {
    setActiveTab(tab)
  }, [])

  /**
   * Abrir modal de registrar interés
   */
  const abrirModalInteres = useCallback(() => {
    setModalInteresAbierto(true)
  }, [])

  /**
   * Cerrar modal de registrar interés
   */
  const cerrarModalInteres = useCallback(() => {
    setModalInteresAbierto(false)
  }, [])

  /**
   * Cambiar a tab de documentos (usado desde otros tabs)
   */
  const irATabDocumentos = useCallback(() => {
    setActiveTab('documentos')
  }, [])

  // =====================================================
  // COMPUTED
  // =====================================================

  const totalDocumentos = documentosCliente?.length || 0

  // =====================================================
  // RETURN
  // =====================================================

  return {
    // Estado
    clienteUUID,
    cliente,
    loading,
    error,
    activeTab,
    modalInteresAbierto,

    // Validaciones
    tieneCedula,
    cargandoValidacion,

    // Documentos
    totalDocumentos,
    modalSubirAbierto,

    // Acciones
    cambiarTab,
    abrirModalInteres,
    cerrarModalInteres,
    cerrarModalSubir,
    recargarCliente,
    irATabDocumentos,
  }
}

/**
 * Hook para obtener intereses de un cliente específico
 *
 * ✅ Carga intereses desde tabla cliente_intereses
 * ✅ Incluye información de proyecto, vivienda y manzana
 */

import { useEffect, useState } from 'react'

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

interface InteresCliente {
  id: string
  proyecto_id: string
  proyecto_nombre?: string
  proyecto_ubicacion?: string
  vivienda_id?: string
  vivienda_numero?: string
  manzana_nombre?: string
  fecha_interes: string
  notas?: string
}

interface UseClienteInteresesReturn {
  intereses: InteresCliente[]
  isLoading: boolean
  error: string | null
}

export function useClienteIntereses(clienteId: string): UseClienteInteresesReturn {
  const [intereses, setIntereses] = useState<InteresCliente[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    async function cargarIntereses() {
      try {
        setIsLoading(true)
        setError(null)

        const { data, error: queryError } = await supabase
          .from('cliente_intereses')
          .select(`
            id,
            proyecto_id,
            vivienda_id,
            fecha_interes,
            notas,
            proyectos!cliente_intereses_proyecto_id_fkey (
              nombre,
              ubicacion
            ),
            viviendas!cliente_intereses_vivienda_id_fkey (
              numero,
              manzanas!viviendas_manzana_id_fkey (
                nombre
              )
            )
          `)
          .eq('cliente_id', clienteId)
          .order('fecha_interes', { ascending: false })

        if (queryError) throw queryError

        // Mapear datos
        const interesesMapeados = (data || []).map((interes: any) => ({
          id: interes.id,
          proyecto_id: interes.proyecto_id,
          proyecto_nombre: interes.proyectos?.nombre || 'Proyecto no especificado',
          proyecto_ubicacion: interes.proyectos?.ubicacion || 'No especifica',
          vivienda_id: interes.vivienda_id,
          vivienda_numero: interes.viviendas?.numero || null,
          manzana_nombre: interes.viviendas?.manzanas?.nombre || null,
          fecha_interes: interes.fecha_interes,
          notas: interes.notas,
        }))

        setIntereses(interesesMapeados)
      } catch (err: unknown) {
        logger.error('❌ Error cargando intereses del cliente:', err)
        setError(err.message || 'Error cargando intereses')
        setIntereses([])
      } finally {
        setIsLoading(false)
      }
    }

    if (clienteId) {
      cargarIntereses()
    }
  }, [clienteId])

  return { intereses, isLoading, error }
}

/**
 * ============================================
 * CLIENTES - REACT QUERY HOOKS
 * ============================================
 *
 * Queries y Mutations para el módulo de Clientes.
 * Migrado desde Zustand store a React Query para mejor cache management.
 *
 * QUERIES:
 * - useClientesQuery(filtros) - Lista de clientes con filtros
 * - useClienteQuery(id) - Detalle de cliente individual
 * - useEstadisticasClientesQuery() - Estadísticas generales
 *
 * MUTATIONS:
 * - useCrearClienteMutation() - Crear nuevo cliente
 * - useActualizarClienteMutation() - Actualizar cliente existente
 * - useEliminarClienteMutation() - Eliminar cliente
 * - useCambiarEstadoClienteMutation() - Cambiar estado de cliente
 */

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { clientesService } from '../services/clientes.service'
import type {
    ActualizarClienteDTO,
    CrearClienteDTO,
    FiltrosClientes
} from '../types'

// ============================================================================
// QUERY KEYS CENTRALIZADOS
// ============================================================================

export const clientesKeys = {
  all: ['clientes'] as const,
  lists: () => [...clientesKeys.all, 'list'] as const,
  list: (filtros?: FiltrosClientes) => [...clientesKeys.lists(), filtros] as const,
  details: () => [...clientesKeys.all, 'detail'] as const,
  detail: (id: string) => [...clientesKeys.details(), id] as const,
  estadisticas: () => [...clientesKeys.all, 'estadisticas'] as const,
}

// ============================================================================
// QUERIES
// ============================================================================

/**
 * Query: Lista de clientes con filtros
 */
export function useClientesQuery(filtros?: FiltrosClientes) {
  return useQuery({
    queryKey: clientesKeys.list(filtros),
    queryFn: () => clientesService.obtenerClientes(filtros),
    staleTime: 0, // Siempre refetch para datos actualizados
    gcTime: 1000 * 60 * 5, // Cache 5 minutos
    placeholderData: (previousData) => previousData, // ⭐ Mantener datos anteriores mientras carga
  })
}

/**
 * Query: Detalle de cliente individual
 */
export function useClienteQuery(id: string | null) {
  return useQuery({
    queryKey: clientesKeys.detail(id || ''),
    queryFn: () => clientesService.obtenerCliente(id!),
    enabled: !!id, // Solo ejecutar si hay ID
    staleTime: 1000 * 60 * 2, // 2 minutos
    gcTime: 1000 * 60 * 10, // Cache 10 minutos
  })
}

/**
 * Query: Estadísticas generales de clientes
 */
export function useEstadisticasClientesQuery() {
  return useQuery({
    queryKey: clientesKeys.estadisticas(),
    queryFn: () => clientesService.obtenerEstadisticas(),
    staleTime: 1000 * 60, // 1 minuto
    gcTime: 1000 * 60 * 5, // Cache 5 minutos
  })
}

// ============================================================================
// MUTATIONS
// ============================================================================

/**
 * Mutation: Crear cliente
 */
export function useCrearClienteMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (datos: CrearClienteDTO) => clientesService.crearCliente(datos),
    onSuccess: (cliente) => {
      // Invalidar todas las listas de clientes
      queryClient.invalidateQueries({ queryKey: clientesKeys.lists() })
      queryClient.invalidateQueries({ queryKey: clientesKeys.estadisticas() })

      // 🎉 Toast de éxito
      toast.success('Cliente creado exitosamente', {
        description: `${cliente.nombres} ${cliente.apellidos}`,
        duration: 4000,
      })
    },
    onError: (error: Error) => {
      // ❌ Toast de error
      toast.error('Error al crear cliente', {
        description: error.message,
        duration: 5000,
      })
    },
  })
}

/**
 * Mutation: Actualizar cliente
 */
export function useActualizarClienteMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: ({ id, datos }: { id: string; datos: ActualizarClienteDTO }) =>
      clientesService.actualizarCliente(id, datos),
    onSuccess: (cliente, variables) => {
      // Invalidar detalle del cliente actualizado
      queryClient.invalidateQueries({ queryKey: clientesKeys.detail(variables.id) })
      // Invalidar listas
      queryClient.invalidateQueries({ queryKey: clientesKeys.lists() })
      queryClient.invalidateQueries({ queryKey: clientesKeys.estadisticas() })

      // 🎉 Toast de éxito
      toast.success('Cliente actualizado exitosamente', {
        description: `${cliente.nombres} ${cliente.apellidos}`,
        duration: 4000,
      })
    },
    onError: (error: Error) => {
      // ❌ Toast de error
      toast.error('Error al actualizar cliente', {
        description: error.message,
        duration: 5000,
      })
    },
  })
}

/**
 * Mutation: Eliminar cliente
 */
export function useEliminarClienteMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (id: string) => clientesService.eliminarCliente(id),
    onSuccess: (_, id) => {
      // Remover de cache
      queryClient.removeQueries({ queryKey: clientesKeys.detail(id) })
      // Invalidar listas
      queryClient.invalidateQueries({ queryKey: clientesKeys.lists() })
      queryClient.invalidateQueries({ queryKey: clientesKeys.estadisticas() })

      // 🎉 Toast de éxito
      toast.success('Cliente eliminado exitosamente', {
        duration: 4000,
      })
    },
    onError: (error: Error) => {
      // ❌ Toast de error
      toast.error('Error al eliminar cliente', {
        description: error.message,
        duration: 5000,
      })
    },
  })
}

/**
 * Mutation: Cambiar estado de cliente
 */
export function useCambiarEstadoClienteMutation() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: ({
      id,
      estado,
    }: {
      id: string
      estado: 'Interesado' | 'Activo' | 'Inactivo'
    }) => clientesService.cambiarEstado(id, estado),
    onSuccess: (data, variables) => {
      // Invalidar detalle del cliente
      queryClient.invalidateQueries({ queryKey: clientesKeys.detail(variables.id) })
      // Invalidar listas
      queryClient.invalidateQueries({ queryKey: clientesKeys.lists() })
      queryClient.invalidateQueries({ queryKey: clientesKeys.estadisticas() })
    },
  })
}

// ============================================================================
// HELPER: Invalidar cache de clientes
// ============================================================================

export function invalidateClientesQueries(queryClient: ReturnType<typeof useQueryClient>) {
  return Promise.all([
    queryClient.invalidateQueries({ queryKey: clientesKeys.lists() }),
    queryClient.invalidateQueries({ queryKey: clientesKeys.estadisticas() }),
  ])
}

/**
 * Hook: useConfigurarFuentesPago
 *
 * Gestiona toda la lógica de configuración de fuentes de pago para una negociación.
 *
 * Responsabilidades:
 * - Cargar fuentes de pago existentes desde la BD
 * - Calcular totales y validar cierre financiero
 * - Agregar, actualizar y eliminar fuentes
 * - Subir documentos (cartas de aprobación)
 * - Guardar cambios en la BD
 *
 * ⚠️ NOMBRES DE CAMPOS VERIFICADOS EN: docs/DATABASE-SCHEMA-REFERENCE-ACTUALIZADO.md
 */

import { useEffect, useState } from 'react'

import { toast } from 'sonner'

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'
import { fuentesPagoService } from '@/modules/clientes/services/fuentes-pago.service'
import {
    cargarTiposFuentesPagoActivas,
    type TipoFuentePagoCatalogo,
} from '@/modules/clientes/services/tipos-fuentes-pago.service'
import type { TipoFuentePago } from '@/modules/clientes/types'
import { crearCredito } from '@/modules/fuentes-pago/services/creditos-constructora.service'
import { crearCuotasCredito } from '@/modules/fuentes-pago/services/cuotas-credito.service'
import type { ParametrosCredito } from '@/modules/fuentes-pago/types'
import { calcularTablaAmortizacion } from '@/modules/fuentes-pago/utils/calculos-credito'
import { calcularCierreFinanciero } from '@/shared/hooks/useCierreFinanciero'

export interface FuentePago {
  id?: string
  tipo: TipoFuentePago
  monto_aprobado: number
  /** Solo para créditos: capital sin intereses (para cierre financiero correcto) */
  capital_para_cierre?: number
  entidad?: string
  numero_referencia?: string
  carta_asignacion_url?: string
  /** Solo para créditos: parámetros del crédito (capital, tasa, cuotas, fecha) */
  parametrosCredito?: ParametrosCredito | null
}

interface Totales {
  total: number
  porcentaje: number
  diferencia: number
}

interface UseConfigurarFuentesPagoProps {
  negociacionId: string
  valorTotal: number
  onFuentesActualizadas?: () => void
}

export function useConfigurarFuentesPago({
  negociacionId,
  valorTotal,
  onFuentesActualizadas,
}: UseConfigurarFuentesPagoProps) {
  // =====================================================
  // ESTADO
  // =====================================================
  const [fuentesPago, setFuentesPago] = useState<FuentePago[]>([])
  const [cargando, setCargando] = useState(true)
  const [cargandoTipos, setCargandoTipos] = useState(true)
  const [tiposDisponibles, setTiposDisponibles] = useState<TipoFuentePagoCatalogo[]>([])
  const [guardando, setGuardando] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [totales, setTotales] = useState<Totales>({
    total: 0,
    porcentaje: 0,
    diferencia: 0,
  })

  // =====================================================
  // EFECTOS
  // =====================================================

  /**
   * Cargar tipos de fuentes activos desde catálogo (una sola vez)
   */
  useEffect(() => {
    const cargarTipos = async () => {
      const { data } = await cargarTiposFuentesPagoActivas()
      if (data) setTiposDisponibles(data)
      setCargandoTipos(false)
    }
    cargarTipos()
  }, [])

  /**
   * Cargar fuentes de pago existentes al montar o cambiar negociacionId
   */
  useEffect(() => {
    cargarFuentesPago()
  }, [negociacionId])

  /**
   * Calcular totales cuando cambian las fuentes o el valorTotal
   */
  useEffect(() => {
    calcularTotales()
  }, [fuentesPago, valorTotal])

  // =====================================================
  // FUNCIONES DE LÓGICA
  // =====================================================

  /**
   * Cargar fuentes de pago desde la BD
   */
  const cargarFuentesPago = async () => {
    try {
      setCargando(true)
      setError(null)
      const data = await fuentesPagoService.obtenerFuentesPagoNegociacion(negociacionId)
      setFuentesPago(
        data.map((f: any) => ({
          id: f.id,
          tipo: f.tipo,
          monto_aprobado: f.monto_aprobado || 0,
          capital_para_cierre: f.capital_para_cierre ?? undefined,
          entidad: f.entidad,
          numero_referencia: f.numero_referencia,
          carta_asignacion_url: f.carta_asignacion_url,
        }))
      )
    } catch (err: unknown) {
      logger.error('Error cargando fuentes:', err)
      setError(`Error cargando fuentes de pago: ${err.message}`)
    } finally {
      setCargando(false)
    }
  }

  /**
   * Calcular totales: monto total, porcentaje cubierto, diferencia
   *
   * Uses shared calcularCierreFinanciero — capital_para_cierre is preferred
   * over monto_aprobado to avoid interest inflating the total.
   */
  const calcularTotales = () => {
    const cierre = calcularCierreFinanciero(fuentesPago, valorTotal)

    setTotales({
      total: cierre.totalParaCierre,
      porcentaje: cierre.porcentajeCubierto,
      diferencia: cierre.diferencia,
    })
  }

  /**
   * Agregar una nueva fuente de pago
   */
  const agregarFuente = (tipo: FuentePago['tipo'], permiteMultiples: boolean) => {
    // Verificar si ya existe este tipo (excepto Cuota Inicial que puede repetirse)
    if (!permiteMultiples) {
      const existe = fuentesPago.some((f) => f.tipo === tipo)
      if (existe) {
        setError(`Ya existe una fuente de tipo "${tipo}"`)
        return
      }
    }

    setFuentesPago([
      ...fuentesPago,
      {
        tipo,
        monto_aprobado: 0,
        entidad: '',
        numero_referencia: '',
      },
    ])
    setError(null)
  }

  /**
   * Actualizar un campo de una fuente existente
   */
  const actualizarFuente = (index: number, campo: keyof FuentePago, valor: any) => {
    const nuevasFuentes = [...fuentesPago]
    nuevasFuentes[index] = { ...nuevasFuentes[index], [campo]: valor }
    setFuentesPago(nuevasFuentes)
  }

  /**
   * Eliminar una fuente de pago
   * Marca como inactiva en lugar de eliminar permanentemente
   */
  const eliminarFuente = async (index: number) => {
    const fuente = fuentesPago[index]

    // Si tiene ID, inactivar en la BD
    if (fuente.id) {
      try {
        // Usar inactivarFuentePago en lugar de eliminar
        await fuentesPagoService.inactivarFuentePago(
          fuente.id,
          'Fuente eliminada por el usuario'
        )
      } catch (err: unknown) {
        // Mostrar error amigable
        if (err.message.includes('ya ha recibido')) {
          setError(
            `⚠️ No se puede eliminar esta fuente porque ya ha recibido dinero. ` +
            `Para mantener la integridad del historial de abonos, esta fuente debe permanecer activa.`
          )
        } else {
          setError(`Error eliminando fuente: ${err.message}`)
        }
        return
      }
    }

    // Eliminar del estado local
    setFuentesPago(fuentesPago.filter((_, i) => i !== index))
    setError(null)
  }

  /**
   * Validar y guardar todas las fuentes de pago
   */
  const guardarFuentes = async () => {
    try {
      setGuardando(true)
      setError(null)

      // Validar que todas las fuentes tengan monto > 0
      const invalidas = fuentesPago.filter((f) => !f.monto_aprobado || f.monto_aprobado <= 0)
      if (invalidas.length > 0) {
        setError('Todas las fuentes deben tener un monto aprobado mayor a 0')
        return
      }

      // Cargar configuración de tipos desde BD para validar sin hardcodear nombres
      const { data: tiposConfig } = await supabase
        .from('tipos_fuentes_pago')
        .select('nombre, requiere_entidad')
      const tiposMap = new Map((tiposConfig ?? []).map((t) => [t.nombre, t]))

      // Validar entidades requeridas usando la flag de BD
      for (const fuente of fuentesPago) {
        const config = tiposMap.get(fuente.tipo)
        if (config?.requiere_entidad && !fuente.entidad?.trim()) {
          setError(`La fuente "${fuente.tipo}" requiere especificar la entidad`)
          return
        }
      }

      // Guardar cada fuente
      for (const fuente of fuentesPago) {
        if (fuente.id) {
          // Actualizar existente
          await fuentesPagoService.actualizarFuentePago(fuente.id, {
            monto_aprobado: fuente.monto_aprobado,
            entidad: fuente.entidad,
            numero_referencia: fuente.numero_referencia,
          })
        } else {
          // Crear nueva
          const nuevaFuente = await fuentesPagoService.crearFuentePago({
            negociacion_id: negociacionId,
            tipo: fuente.tipo,
            monto_aprobado: fuente.monto_aprobado,
            capital_para_cierre: fuente.capital_para_cierre,
            entidad: fuente.entidad,
            numero_referencia: fuente.numero_referencia,
          })

          // Si el tipo genera cuotas y hay parámetros de crédito, crear tabla de amortización
          const tipoConfig = tiposDisponibles.find(t => t.nombre === fuente.tipo)
          if (tipoConfig?.logica_negocio?.genera_cuotas && fuente.parametrosCredito) {
            const calculo = calcularTablaAmortizacion(fuente.parametrosCredito)

            // Crear registro en creditos_constructora
            const { error: eCred } = await crearCredito({
              fuente_pago_id: nuevaFuente.id,
              capital: fuente.parametrosCredito.capital,
              tasa_mensual: fuente.parametrosCredito.tasaMensual,
              num_cuotas: fuente.parametrosCredito.numCuotas,
              fecha_inicio: fuente.parametrosCredito.fechaInicio.toISOString().split('T')[0],
              valor_cuota: calculo.valorCuotaMensual,
              interes_total: calculo.interesTotal,
              monto_total: calculo.montoTotal,
              tasa_mora_diaria: fuente.parametrosCredito.tasaMoraDiaria ?? 0.001,
            })
            if (eCred) throw eCred

            // Crear cuotas de amortización
            const { error: eCuotas } = await crearCuotasCredito(nuevaFuente.id, calculo.cuotas)
            if (eCuotas) throw eCuotas
          }
        }
      }

      // Recargar fuentes
      await cargarFuentesPago()

      // Notificar actualización
      onFuentesActualizadas?.()

      toast.info('✅ Fuentes de pago guardadas correctamente')
    } catch (err: unknown) {
      logger.error('Error guardando fuentes:', err)
      setError(`Error guardando fuentes: ${err.message}`)
    } finally {
      setGuardando(false)
    }
  }

  // =====================================================
  // VALORES COMPUTADOS
  // =====================================================

  const cierreCompleto = Math.abs(totales.diferencia) < 1 // Margen de error de 1 peso
  const porcentajeCubierto = totales.porcentaje

  // =====================================================
  // RETORNO
  // =====================================================

  return {
    // Estado
    fuentesPago,
    cargando,
    cargandoTipos,
    tiposDisponibles,
    guardando,
    error,
    totales,

    // Valores computados
    cierreCompleto,
    porcentajeCubierto,

    // Funciones
    agregarFuente,
    actualizarFuente,
    eliminarFuente,
    guardarFuentes,
    cargarFuentesPago,
  }
}

/**
 * ============================================
 * HOOK: useDetectarCambios (Clientes)
 * ============================================
 *
 * ✅ SEPARACIÓN DE RESPONSABILIDADES
 * Hook que detecta cambios entre datos originales y editados.
 * Usado en modal de confirmación de cambios.
 *
 * Basado en: src/modules/proyectos/hooks/useDetectarCambios.ts
 */

import { useMemo } from 'react'

import { formatDateShort } from '@/lib/utils/date.utils'
import type { Cliente } from '@/modules/clientes/types'

export interface Cambio {
  campo: string
  valorAnterior: any
  valorNuevo: any
  tipo?: 'texto' | 'fecha' | 'numero' | 'select'
}

interface ClienteFormData {
  nombres: string
  apellidos: string
  tipo_documento: string
  numero_documento: string
  fecha_nacimiento?: string
  telefono?: string
  telefono_alternativo?: string
  email?: string
  direccion?: string
  ciudad?: string
  departamento?: string
  estado_civil?: string
  notas?: string
  estado?: 'Interesado' | 'Activo' | 'Inactivo'
}

/**
 * Hook para detectar cambios entre datos originales y editados
 */
export function useDetectarCambios(
  datosOriginales: Cliente | null,
  datosEditados: ClienteFormData | null
): Cambio[] {
  return useMemo(() => {
    if (!datosOriginales || !datosEditados) return []

    const cambios: Cambio[] = []

    // ⭐ Nombres
    if (datosOriginales.nombres !== datosEditados.nombres) {
      cambios.push({
        campo: 'Nombres',
        valorAnterior: datosOriginales.nombres,
        valorNuevo: datosEditados.nombres,
        tipo: 'texto',
      })
    }

    // ⭐ Apellidos
    if (datosOriginales.apellidos !== datosEditados.apellidos) {
      cambios.push({
        campo: 'Apellidos',
        valorAnterior: datosOriginales.apellidos,
        valorNuevo: datosEditados.apellidos,
        tipo: 'texto',
      })
    }

    // ⭐ Tipo de Documento
    if (datosOriginales.tipo_documento !== datosEditados.tipo_documento) {
      cambios.push({
        campo: 'Tipo de Documento',
        valorAnterior: datosOriginales.tipo_documento,
        valorNuevo: datosEditados.tipo_documento,
        tipo: 'select',
      })
    }

    // ⭐ Número de Documento
    if (datosOriginales.numero_documento !== datosEditados.numero_documento) {
      cambios.push({
        campo: 'Número de Documento',
        valorAnterior: datosOriginales.numero_documento,
        valorNuevo: datosEditados.numero_documento,
        tipo: 'texto',
      })
    }

    // ⭐ Fecha de Nacimiento
    const fechaNacimientoOriginal = datosOriginales.fecha_nacimiento || ''
    const fechaNacimientoEditada = datosEditados.fecha_nacimiento || ''
    if (fechaNacimientoOriginal !== fechaNacimientoEditada) {
      cambios.push({
        campo: 'Fecha de Nacimiento',
        valorAnterior: fechaNacimientoOriginal ? formatDateShort(fechaNacimientoOriginal) : 'Sin fecha',
        valorNuevo: fechaNacimientoEditada ? formatDateShort(fechaNacimientoEditada) : 'Sin fecha',
        tipo: 'fecha',
      })
    }

    // ⭐ Teléfono
    const telefonoOriginal = datosOriginales.telefono || ''
    const telefonoEditado = datosEditados.telefono || ''
    if (telefonoOriginal !== telefonoEditado) {
      cambios.push({
        campo: 'Teléfono',
        valorAnterior: telefonoOriginal || 'Sin teléfono',
        valorNuevo: telefonoEditado || 'Sin teléfono',
        tipo: 'texto',
      })
    }

    // ⭐ Teléfono Alternativo
    const telefonoAltOriginal = datosOriginales.telefono_alternativo || ''
    const telefonoAltEditado = datosEditados.telefono_alternativo || ''
    if (telefonoAltOriginal !== telefonoAltEditado) {
      cambios.push({
        campo: 'Teléfono Alternativo',
        valorAnterior: telefonoAltOriginal || 'Sin teléfono',
        valorNuevo: telefonoAltEditado || 'Sin teléfono',
        tipo: 'texto',
      })
    }

    // ⭐ Email
    const emailOriginal = datosOriginales.email || ''
    const emailEditado = datosEditados.email || ''
    if (emailOriginal !== emailEditado) {
      cambios.push({
        campo: 'Email',
        valorAnterior: emailOriginal || 'Sin email',
        valorNuevo: emailEditado || 'Sin email',
        tipo: 'texto',
      })
    }

    // ⭐ Dirección
    const direccionOriginal = datosOriginales.direccion || ''
    const direccionEditada = datosEditados.direccion || ''
    if (direccionOriginal !== direccionEditada) {
      cambios.push({
        campo: 'Dirección',
        valorAnterior: direccionOriginal || 'Sin dirección',
        valorNuevo: direccionEditada || 'Sin dirección',
        tipo: 'texto',
      })
    }

    // ⭐ Ciudad
    const ciudadOriginal = datosOriginales.ciudad || ''
    const ciudadEditada = datosEditados.ciudad || ''
    if (ciudadOriginal !== ciudadEditada) {
      cambios.push({
        campo: 'Ciudad',
        valorAnterior: ciudadOriginal || 'Sin ciudad',
        valorNuevo: ciudadEditada || 'Sin ciudad',
        tipo: 'texto',
      })
    }

    // ⭐ Departamento
    const departamentoOriginal = datosOriginales.departamento || ''
    const departamentoEditado = datosEditados.departamento || ''
    if (departamentoOriginal !== departamentoEditado) {
      cambios.push({
        campo: 'Departamento',
        valorAnterior: departamentoOriginal || 'Sin departamento',
        valorNuevo: departamentoEditado || 'Sin departamento',
        tipo: 'texto',
      })
    }

    // ⭐ Estado Civil
    const estadoCivilOriginal = datosOriginales.estado_civil || ''
    const estadoCivilEditado = datosEditados.estado_civil || ''
    if (estadoCivilOriginal !== estadoCivilEditado) {
      cambios.push({
        campo: 'Estado Civil',
        valorAnterior: estadoCivilOriginal || 'Sin especificar',
        valorNuevo: estadoCivilEditado || 'Sin especificar',
        tipo: 'select',
      })
    }

    // ⭐ Notas
    const notasOriginal = datosOriginales.notas || ''
    const notasEditadas = datosEditados.notas || ''
    if (notasOriginal !== notasEditadas) {
      cambios.push({
        campo: 'Notas',
        valorAnterior: notasOriginal || 'Sin notas',
        valorNuevo: notasEditadas || 'Sin notas',
        tipo: 'texto',
      })
    }

    // ⭐ Estado
    if (datosEditados.estado && datosOriginales.estado !== datosEditados.estado) {
      cambios.push({
        campo: 'Estado',
        valorAnterior: datosOriginales.estado,
        valorNuevo: datosEditados.estado,
        tipo: 'select',
      })
    }

    return cambios
  }, [datosOriginales, datosEditados])
}

/**
 * ============================================
 * HOOK: useDocumentosRequeridosFuentes
 * ============================================
 *
 * Calcula documentos requeridos en TIEMPO REAL
 * consultando requisitos_fuentes_pago_config
 *
 * ✅ NO depende de documentos_pendientes
 * ✅ Fuente de verdad: requisitos_fuentes_pago_config
 * ✅ Calcula diferencia con documentos_cliente
 *
 * @version 3.0.0 - 2025-12-17
 */

import { useQuery } from '@tanstack/react-query'

import { supabase } from '@/lib/supabase/client'

// ============================================
// TYPES
// ============================================

export interface DocumentoRequeridoFuente {
  id: string // ID del requisito config
  fuente_pago_id: string
  tipo_fuente: string
  entidad: string
  tipo_documento: string
  nivel_validacion: 'DOCUMENTO_OBLIGATORIO' | 'DOCUMENTO_OPCIONAL'
  prioridad: string
  tiene_documento: boolean
  documento_id?: string
  documento_url?: string
}

export interface FuenteConRequisitos {
  fuenteId: string
  tipo: string
  entidad: string
  requisitos: DocumentoRequeridoFuente[]
  pendientes: DocumentoRequeridoFuente[]
  completados: DocumentoRequeridoFuente[]
  totalObligatorios: number
  obligatoriosPendientes: number
}

// ============================================
// HOOK
// ============================================

export function useDocumentosRequeridosFuentes(clienteId: string) {
  // 1. Obtener fuentes activas del cliente
  const { data: fuentes = [] } = useQuery({
    queryKey: ['fuentes-pago-activas', clienteId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('fuentes_pago')
        .select(`
          id,
          tipo,
          tipo_fuente_id,
          entidad,
          estado
        `)
        .eq('estado', 'Activa')
        .order('fecha_creacion', { ascending: false })

      if (error) throw error

      // Filtrar por cliente a través de negociaciones
      const fuentesConCliente = []
      for (const fuente of data || []) {
        const { data: negociacion } = await supabase
          .from('negociaciones')
          .select('cliente_id')
          .eq('id', fuente.id)
          .single()

        if (negociacion?.cliente_id === clienteId) {
          fuentesConCliente.push(fuente)
        }
      }

      return fuentesConCliente
    },
    staleTime: 1000 * 60 * 5, // 5 minutos
  })

  // 2. Obtener TODOS los requisitos configurados
  const { data: todosRequisitos = [] } = useQuery({
    queryKey: ['requisitos-fuentes-config-todos'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('requisitos_fuentes_pago_config')
        .select('id,tipo_fuente,paso_identificador,titulo,descripcion,nivel_validacion,tipo_documento_sugerido,categoria_documento,alcance,orden,activo,version')
        .eq('activo', true)
        .in('nivel_validacion', ['DOCUMENTO_OBLIGATORIO', 'DOCUMENTO_OPCIONAL'])
        .order('nivel_validacion')
        .order('orden', { ascending: true })

      if (error) throw error
      return data || []
    },
    staleTime: 1000 * 60 * 10, // 10 minutos (config cambia poco)
  })

  // 3. Obtener documentos subidos del cliente
  const { data: documentosCliente = [] } = useQuery({
    queryKey: ['documentos-cliente-fuentes', clienteId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('documentos_cliente')
        .select('id, tipo_documento, fuente_pago_relacionada, url_storage, estado')
        .eq('entidad_id', clienteId)
        .eq('estado', 'Activo')
        .not('fuente_pago_relacionada', 'is', null)

      if (error) throw error
      return data || []
    },
    staleTime: 1000 * 30, // 30 segundos
  })

  // 4. CALCULAR requisitos pendientes en tiempo real
  const fuentesConRequisitos = useQuery({
    queryKey: ['fuentes-requisitos-calculados', clienteId, fuentes, todosRequisitos, documentosCliente],
    queryFn: async () => {
      const resultado: FuenteConRequisitos[] = []

      for (const fuente of fuentes) {
        // Requisitos para este tipo de fuente
        const requisitosParaFuente = todosRequisitos.filter(
          (req) => (req as any).tipo_fuente_id === fuente.tipo_fuente_id
        )

        if (requisitosParaFuente.length === 0) {
          // Fuente sin requisitos (ej: Cuota Inicial)
          continue
        }

        const requisitosConEstado: DocumentoRequeridoFuente[] = requisitosParaFuente.map((req) => {
          // Buscar si existe documento subido para este requisito
          const documentoSubido = documentosCliente.find(
            (doc) =>
              doc.fuente_pago_relacionada === fuente.id &&
              doc.tipo_documento === (req as any).tipo_documento_sistema
          )

          return {
            id: req.id,
            fuente_pago_id: fuente.id,
            tipo_fuente: fuente.tipo,
            entidad: fuente.entidad || '',
            tipo_documento: req.titulo,
            nivel_validacion: req.nivel_validacion as 'DOCUMENTO_OBLIGATORIO' | 'DOCUMENTO_OPCIONAL',
            prioridad: req.nivel_validacion === 'DOCUMENTO_OBLIGATORIO' ? 'Alta' : 'Media',
            tiene_documento: !!documentoSubido,
            documento_id: documentoSubido?.id,
            documento_url: documentoSubido?.url_storage,
          }
        })

        const pendientes = requisitosConEstado.filter((r) => !r.tiene_documento)
        const completados = requisitosConEstado.filter((r) => r.tiene_documento)

        if (pendientes.length > 0) {
          resultado.push({
            fuenteId: fuente.id,
            tipo: fuente.tipo,
            entidad: fuente.entidad || '',
            requisitos: requisitosConEstado,
            pendientes,
            completados,
            totalObligatorios: requisitosConEstado.filter(
              (r) => r.nivel_validacion === 'DOCUMENTO_OBLIGATORIO'
            ).length,
            obligatoriosPendientes: pendientes.filter(
              (r) => r.nivel_validacion === 'DOCUMENTO_OBLIGATORIO'
            ).length,
          })
        }
      }

      return resultado
    },
    enabled: fuentes.length > 0 && todosRequisitos.length > 0,
  })

  return {
    fuentesConRequisitos: fuentesConRequisitos.data || [],
    isLoading: fuentesConRequisitos.isLoading,
    error: fuentesConRequisitos.error,
  }
}

/**
 * Hook para el formulario de cliente
 * Maneja validaciones y estado del formulario
 */

import { useCallback, useEffect, useState } from 'react'

import { logger } from '@/lib/utils/logger'

import { clientesService } from '../services/clientes.service'
import type {
    ActualizarClienteDTO,
    CrearClienteDTO,
    OrigenCliente,
    TipoDocumento,
} from '../types'
import { validarDocumentoIdentidad } from '../utils/validacion-documentos-colombia'

interface FormularioClienteHookProps {
  clienteInicial?: ActualizarClienteDTO & { id?: string }
  onSubmit: (datos: CrearClienteDTO | ActualizarClienteDTO) => Promise<void>
  onCancel?: () => void
}

export function useFormularioCliente({
  clienteInicial,
  onSubmit,
  onCancel,
}: FormularioClienteHookProps) {
  const [formData, setFormData] = useState<CrearClienteDTO>({
    nombres: clienteInicial?.nombres || '',
    apellidos: clienteInicial?.apellidos || '',
    tipo_documento: clienteInicial?.tipo_documento || 'CC',
    numero_documento: clienteInicial?.numero_documento || '',
    fecha_nacimiento: clienteInicial?.fecha_nacimiento ?? '',
    estado_civil: clienteInicial?.estado_civil ?? undefined,
    telefono: clienteInicial?.telefono || '',
    telefono_alternativo: clienteInicial?.telefono_alternativo || '',
    email: clienteInicial?.email || '',
    direccion: clienteInicial?.direccion || '',
    ciudad: clienteInicial?.ciudad || '',
    departamento: clienteInicial?.departamento || '',
    notas: clienteInicial?.notas || '',
    interes_inicial: undefined, // Solo para nuevos clientes
  })

  const [errors, setErrors] = useState<Record<string, string>>({})
  const [isSubmitting, setIsSubmitting] = useState(false)

  // =====================================================
  // EFECTO: Actualizar formulario cuando cambia cliente
  // =====================================================
  useEffect(() => {
    if (clienteInicial) {
      // ✅ Solo actualizar si realmente hay un cambio (evitar re-renders innecesarios)
      setFormData((prev) => {
        // Si ya tiene los datos correctos, no actualizar
        if (
          prev.nombres === (clienteInicial.nombres || '') &&
          prev.numero_documento === (clienteInicial.numero_documento || '')
        ) {
          return prev
        }

        // Actualizar con datos del cliente
        return {
          nombres: clienteInicial.nombres || '',
          apellidos: clienteInicial.apellidos || '',
          tipo_documento: clienteInicial.tipo_documento || 'CC',
          numero_documento: clienteInicial.numero_documento || '',
          fecha_nacimiento: clienteInicial.fecha_nacimiento ?? '',
          estado_civil: clienteInicial.estado_civil ?? undefined,
          telefono: clienteInicial.telefono || '',
          telefono_alternativo: clienteInicial.telefono_alternativo || '',
          email: clienteInicial.email || '',
          direccion: clienteInicial.direccion || '',
          ciudad: clienteInicial.ciudad || '',
          departamento: clienteInicial.departamento || '',
          notas: clienteInicial.notas || '',
          interes_inicial: undefined,
        }
      })
    } else {
      // Reset para nuevo cliente
      setFormData({
        nombres: '',
        apellidos: '',
        tipo_documento: 'CC',
        numero_documento: '',
        fecha_nacimiento: '',
        estado_civil: undefined,
        telefono: '',
        telefono_alternativo: '',
        email: '',
        direccion: '',
        ciudad: '',
        departamento: '',
        notas: '',
        interes_inicial: undefined,
      })
    }
    // Limpiar errores cuando cambia el cliente
    setErrors({})
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [clienteInicial?.id])

  // =====================================================
  // VALIDACIONES POR STEP
  // =====================================================

  /**
   * Validar Step 0: Información Personal
   * Campos obligatorios: nombres, apellidos, tipo_documento, numero_documento
   * ⚠️ VALIDACIÓN ASYNC: Verifica duplicados en la base de datos
   * ✅ VALIDACIÓN ALGORITMO: Dígito verificador para NIT y formato para CC/CE
   */
  const validarStep0 = useCallback(async (): Promise<boolean> => {
    const nuevosErrores: Record<string, string> = {}

    // Nombres (requerido)
    if (!formData.nombres.trim()) {
      nuevosErrores.nombres = 'Los nombres son requeridos'
    }

    // Apellidos (requerido)
    if (!formData.apellidos.trim()) {
      nuevosErrores.apellidos = 'Los apellidos son requeridos'
    }

    // Tipo documento (requerido)
    if (!formData.tipo_documento) {
      nuevosErrores.tipo_documento = 'El tipo de documento es requerido'
    }

    // Número documento (requerido + validación de formato/algoritmo)
    if (!formData.numero_documento.trim()) {
      nuevosErrores.numero_documento = 'El número de documento es requerido'
    } else {
      // ✅ VALIDACIÓN DE ALGORITMO (CC, CE, NIT, Pasaporte)
      const resultadoValidacion = validarDocumentoIdentidad(
        formData.tipo_documento as any,
        formData.numero_documento
      )

      if (!resultadoValidacion.valido) {
        nuevosErrores.numero_documento = resultadoValidacion.mensaje || 'Documento inválido'
        if (resultadoValidacion.detalles) {
          nuevosErrores.numero_documento += ` (${resultadoValidacion.detalles})`
        }
      } else if (!clienteInicial?.id) {
        // ⚠️ VALIDACIÓN CRÍTICA: Verificar duplicados (solo si formato es válido y es cliente nuevo)
        try {
          const clienteExistente = await clientesService.buscarPorDocumento(
            formData.tipo_documento,
            formData.numero_documento
          )

          if (clienteExistente) {
            nuevosErrores.numero_documento = `Ya existe un cliente con este documento: ${clienteExistente.nombres} ${clienteExistente.apellidos}`
            logger.error('❌ Cliente duplicado encontrado en Step 0')
          } else {
          }
        } catch (error) {
          const mensaje = error instanceof Error ? error.message : 'Error desconocido'
          logger.error('[CLIENTES] Error verificando duplicados:', mensaje, error)
          nuevosErrores.numero_documento = 'Error al verificar duplicados. Intenta de nuevo.'
        }
      }
    }

    setErrors(nuevosErrores)
    return Object.keys(nuevosErrores).length === 0
  }, [formData, clienteInicial?.id])

  /**
   * Validar Step 1: Información de Contacto
   * Campos obligatorios:
   * - telefono OR email (al menos uno válido)
   * - departamento (obligatorio)
   * - ciudad (obligatoria)
   */
  const validarStep1 = useCallback((): boolean => {
    const nuevosErrores: Record<string, string> = {}

    const tieneTelefono = formData.telefono && formData.telefono.trim() !== ''
    const tieneEmail = formData.email && formData.email.trim() !== ''

    // Validar formato de teléfono si existe
    if (tieneTelefono && !/^[0-9+\-\s()]+$/.test(formData.telefono!)) {
      nuevosErrores.telefono = 'Teléfono inválido'
    }

    // Validar formato de email si existe
    if (tieneEmail && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email!)) {
      nuevosErrores.email = 'Email inválido'
    }

    // Si no hay errores de formato, verificar que tenga al menos uno
    if (Object.keys(nuevosErrores).length === 0) {
      if (!tieneTelefono && !tieneEmail) {
        nuevosErrores.telefono = 'Requerido: teléfono o email'
        nuevosErrores.email = 'Requerido: teléfono o email'
      }
    }

    // Validar departamento (obligatorio)
    if (!formData.departamento || formData.departamento.trim() === '') {
      nuevosErrores.departamento = 'El departamento es obligatorio'
    }

    // Validar ciudad/municipio (obligatoria)
    if (!formData.ciudad || formData.ciudad.trim() === '') {
      nuevosErrores.ciudad = 'La ciudad/municipio es obligatoria'
    }

    setErrors(nuevosErrores)
    return Object.keys(nuevosErrores).length === 0
  }, [formData])

  /**
   * Validar Step 2: Interés
   * Todo opcional, pero si selecciona vivienda â†’ proyecto es requerido
   */
  const validarStep2 = useCallback((): boolean => {
    const nuevosErrores: Record<string, string> = {}

    // Si tiene vivienda pero no proyecto
    if (formData.interes_inicial?.vivienda_id && !formData.interes_inicial?.proyecto_id) {
      nuevosErrores.proyecto_interes = 'Debe seleccionar un proyecto primero'
    }

    setErrors(nuevosErrores)
    return Object.keys(nuevosErrores).length === 0
  }, [formData])

  /**
   * Validar Step 3: Adicional
   * Todo opcional - siempre válido
   */
  const validarStep3 = useCallback((): boolean => {
    // Step 3 no tiene validaciones
    return true
  }, [])

  // =====================================================
  // VALIDACIÓN COMPLETA (para submit final)
  // =====================================================

  const validarFormulario = useCallback((): boolean => {
    const nuevosErrores: Record<string, string> = {}

    // Nombres (requerido)
    if (!formData.nombres.trim()) {
      nuevosErrores.nombres = 'Los nombres son requeridos'
    }

    // Apellidos (requerido)
    if (!formData.apellidos.trim()) {
      nuevosErrores.apellidos = 'Los apellidos son requeridos'
    }

    // Tipo documento (requerido)
    if (!formData.tipo_documento) {
      nuevosErrores.tipo_documento = 'El tipo de documento es requerido'
    }

    // Número documento (requerido)
    // ✅ Regex permisivo: acepta CC (numérico), CE, PP, PEP (alfanumérico)
    if (!formData.numero_documento.trim()) {
      nuevosErrores.numero_documento = 'El número de documento es requerido'
    } else if (!/^[A-Za-z0-9]+$/.test(formData.numero_documento.trim())) {
      nuevosErrores.numero_documento = 'El documento solo puede contener letras y números'
    }

    // Contacto: Al menos teléfono o email
    const tieneTelefono = formData.telefono && formData.telefono.trim() !== ''
    const tieneEmail = formData.email && formData.email.trim() !== ''

    if (!tieneTelefono && !tieneEmail) {
      nuevosErrores.telefono = 'Requerido: teléfono o email'
      nuevosErrores.email = 'Requerido: teléfono o email'
    }

    // Email (opcional pero con formato)
    if (formData.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      nuevosErrores.email = 'Email inválido'
    }

    // Teléfono (opcional pero con formato)
    if (formData.telefono && !/^[0-9+\-\s()]+$/.test(formData.telefono)) {
      nuevosErrores.telefono = 'Teléfono inválido'
    }

    // Ubicación (obligatoria)
    if (!formData.departamento || formData.departamento.trim() === '') {
      nuevosErrores.departamento = 'El departamento es obligatorio'
    }
    if (!formData.ciudad || formData.ciudad.trim() === '') {
      nuevosErrores.ciudad = 'La ciudad/municipio es obligatoria'
    }

    setErrors(nuevosErrores)
    return Object.keys(nuevosErrores).length === 0
  }, [formData])

  // =====================================================
  // HANDLERS
  // =====================================================

  const handleChange = useCallback(
    (campo: keyof CrearClienteDTO, valor: string | TipoDocumento | OrigenCliente) => {
      setFormData((prev) => ({ ...prev, [campo]: valor }))
      // Limpiar error del campo al escribir
      if (errors[campo]) {
        setErrors((prev) => {
          const nuevos = { ...prev }
          delete nuevos[campo]
          return nuevos
        })
      }
    },
    [errors]
  )

  const handleSubmit = useCallback(
    async (e: React.FormEvent) => {
      e.preventDefault()

      if (!validarFormulario()) {
        return
      }

      setIsSubmitting(true)

      try {
        await onSubmit(formData)
      } catch (error) {
        logger.error('Error al guardar cliente:', error)
        // El error ya se maneja en el componente padre
      } finally {
        setIsSubmitting(false)
      }
    },
    [formData, onSubmit, validarFormulario]
  )

  const handleCancel = useCallback(() => {
    onCancel?.()
  }, [onCancel])

  const resetForm = useCallback(() => {
    setFormData({
      nombres: '',
      apellidos: '',
      tipo_documento: 'CC',
      numero_documento: '',
      fecha_nacimiento: '',
      telefono: '',
      telefono_alternativo: '',
      email: '',
      direccion: '',
      ciudad: '',
      departamento: '',
      notas: '',
      interes_inicial: undefined,
    })
    setErrors({})
  }, [])

  // =====================================================
  // RETURN
  // =====================================================

  return {
    formData,
    errors,
    isSubmitting,
    esEdicion: !!clienteInicial?.id,
    handleChange,
    handleSubmit,
    handleCancel,
    resetForm,
    // Validaciones por step
    validarStep0,
    validarStep1,
    validarStep2,
    validarStep3,
  }
}

/**
 * Hook: useFormularioClienteContainer
 *
 * Lógica de negocio para el contenedor del formulario de clientes.
 * Maneja mutations, estados de modales, confirmaciones y guardado.
 *
 * Separación de responsabilidades:
 * - Este hook: Lógica de negocio (mutations, estados, callbacks)
 * - Container: Orquestación y renderizado
 * - Componente: UI presentacional pura
 */

import { useCallback, useState } from 'react'

import { logger } from '@/lib/utils/logger'

import { interesesService } from '../services/intereses.service'
import type { ActualizarClienteDTO, ClienteResumen, CrearClienteDTO } from '../types'

import {
    useActualizarClienteMutation,
    useClienteQuery,
    useCrearClienteMutation,
    useDetectarCambios,
    useFormularioCliente,
    useInteresFormulario,
} from '.'


interface UseFormularioClienteContainerProps {
  clienteId?: string | null
  cliente?: ClienteResumen | null // ✅ Type-safe
  isOpen?: boolean
  onClose?: () => void
}

export function useFormularioClienteContainer({
  clienteId,
  cliente,
  isOpen = false,
  onClose,
}: UseFormularioClienteContainerProps) {
  // =====================================================
  // REACT QUERY: Datos y Mutations
  // =====================================================

  // ✅ SIEMPRE hacer fetch del cliente completo en edición
  // ClienteResumen puede no tener todos los campos necesarios
  // (Similar a Proyectos que hace fetch de proyectoConValidacion)
  const { data: clienteCompleto, isLoading: cargandoCliente } = useClienteQuery(clienteId ?? null)

  // Mutations
  const crearMutation = useCrearClienteMutation()
  const actualizarMutation = useActualizarClienteMutation()

  // =====================================================
  // ESTADOS LOCALES
  // =====================================================

  // Estados para los dos modales
  const [mostrarConfirmacionCambios, setMostrarConfirmacionCambios] = useState(false)
  const [mostrarDescarte, setMostrarDescarte] = useState(false)
  const [datosParaGuardar, setDatosParaGuardar] = useState<CrearClienteDTO | ActualizarClienteDTO | null>(null)

  // Estado del modal principal
  // ✅ En edición: esperar a que clienteCompleto esté listo (como Proyectos)
  const modalAbierto = clienteId
    ? (isOpen && !cargandoCliente && clienteCompleto !== null && clienteCompleto !== undefined)
    : (isOpen || crearMutation.isPending || actualizarMutation.isPending)

  // =====================================================
  // HOOK DE INTERÉS (solo para nuevos clientes)
  // =====================================================

  const {
    proyectos,
    viviendas,
    cargandoProyectos,
    cargandoViviendas,
    handleProyectoChange,
    handleViviendaChange,
    getInteresData,
    resetInteres,
  } = useInteresFormulario()

  // =====================================================
  // LÓGICA DE GUARDADO
  // =====================================================

  /**
   * Ejecutar guardado real (después de confirmar o directo en creación)
   */
  const ejecutarGuardado = useCallback(
    async (datos: CrearClienteDTO | ActualizarClienteDTO) => {
      if (clienteCompleto?.id) {
        // Editar cliente existente
        await actualizarMutation.mutateAsync({
          id: clienteCompleto.id,
          datos: datos as ActualizarClienteDTO,
        })
      } else {
        // Crear nuevo cliente
        const nuevoCliente = await crearMutation.mutateAsync(datos as CrearClienteDTO)

        // Si tiene interés inicial, registrarlo
        const interesData = getInteresData()
        if (nuevoCliente && interesData) {
          try {
            await interesesService.crearInteres({
              cliente_id: nuevoCliente.id,
              proyecto_id: interesData.proyecto_id,
              vivienda_id: interesData.vivienda_id,
              notas: interesData.notas_interes,
            })
          } catch (error) {
            logger.error('Error al registrar interés inicial:', error)
          }
        }
        resetInteres()
      }
      // Cerrar modal después de completar exitosamente
      setMostrarConfirmacionCambios(false)
      onClose?.()
    },
    [clienteCompleto, crearMutation, actualizarMutation, getInteresData, resetInteres, onClose]
  )

  /**
   * Interceptar submit para mostrar modal de confirmación (solo en edición)
   */
  const handleFormSubmit = useCallback(
    async (datos: CrearClienteDTO | ActualizarClienteDTO) => {
      if (clienteCompleto?.id) {
        // Si es edición, guardar datos y mostrar modal de confirmación
        setDatosParaGuardar(datos)
        setMostrarConfirmacionCambios(true)
        return
      }

      // Si es creación, guardar directo (sin confirmación)
      await ejecutarGuardado(datos)
    },
    [clienteCompleto, ejecutarGuardado]
  )

  // =====================================================
  // HOOK DE FORMULARIO
  // =====================================================

  const {
    formData,
    errors,
    isSubmitting,
    esEdicion,
    handleChange,
    handleSubmit,
    validarStep0,
    validarStep1,
    validarStep2,
    validarStep3,
  } = useFormularioCliente({
    clienteInicial: clienteCompleto
      ? {
          ...clienteCompleto,
        }
      : undefined,
    onSubmit: handleFormSubmit,
    onCancel: () => {
      resetInteres()
      onClose?.()
    },
  })

  // =====================================================
  // DETECCIÓN DE CAMBIOS
  // =====================================================

  const cambiosDetectados = useDetectarCambios(
    esEdicion ? (clienteCompleto ?? null) : null,
    esEdicion ? formData : null
  )
  const hayCambios = cambiosDetectados.length > 0

  // =====================================================
  // HANDLERS DE MODALES
  // =====================================================

  /**
   * Intentar cerrar (al presionar X o Cancelar)
   */
  const handleIntentarCerrar = useCallback(() => {
    if (esEdicion && hayCambios && !isSubmitting) {
      setMostrarDescarte(true)
      return
    }

    resetInteres()
    onClose?.()
  }, [esEdicion, hayCambios, isSubmitting, resetInteres, onClose])

  /**
   * Confirmar guardado (desde modal de confirmación de cambios)
   */
  const confirmarGuardarCambios = useCallback(async () => {
    if (datosParaGuardar) {
      await ejecutarGuardado(datosParaGuardar)
      setDatosParaGuardar(null)
    }
  }, [datosParaGuardar, ejecutarGuardado])

  /**
   * Confirmar descarte de cambios (desde modal de descarte)
   */
  const confirmarDescartarCambios = useCallback(() => {
    setMostrarDescarte(false)
    resetInteres()
    onClose?.()
  }, [resetInteres, onClose])

  // =====================================================
  // RETURN: Exponer todo lo necesario para el container
  // =====================================================

  return {
    // Datos
    clienteCompleto,

    // Estado del formulario
    formData,
    errors,
    isSubmitting,
    esEdicion,

    // Handlers del formulario
    handleChange,
    handleSubmit,
    validarStep0,
    validarStep1,
    validarStep2,
    validarStep3,

    // Interés (para nuevos clientes)
    proyectos,
    viviendas,
    cargandoProyectos,
    cargandoViviendas,
    handleProyectoChange,
    handleViviendaChange,

    // Estados de modales
    modalAbierto,
    mostrarConfirmacionCambios,
    mostrarDescarte,

    // Handlers de modales
    handleIntentarCerrar,
    setMostrarConfirmacionCambios,
    confirmarGuardarCambios,
    setMostrarDescarte,
    confirmarDescartarCambios,

    // Cambios detectados
    cambiosDetectados,
    hayCambios,

    // Estados de mutations y queries
    isPending: crearMutation.isPending || actualizarMutation.isPending,
    cargandoCliente, // ✅ Expuesto para mostrar loading en formulario
  }
}

/**
 * Hook para gestionar historial de cliente
 * Carga eventos de audit_log y los humaniza para mostrar en timeline
 */

'use client'

import { useMemo, useState } from 'react'

import { useQuery } from '@tanstack/react-query'

import { formatDateForDisplay } from '@/lib/utils/date.utils'

import { historialClienteService } from '../services/historial-cliente.service'
import { notasHistorialService } from '../services/notas-historial.service'
import type {
    EventoHistorialHumanizado,
    FiltrosHistorial,
    GrupoEventosPorFecha,
} from '../types/historial.types'
import { humanizarEventos } from '../utils/humanizador-eventos'
import { convertirNotasAEventos } from '../utils/notas-a-eventos.utils'


interface UseHistorialClienteProps {
  clienteId: string
  habilitado?: boolean
  limit?: number
}

export function useHistorialCliente({
  clienteId,
  habilitado = true,
  limit = 200,
}: UseHistorialClienteProps) {
  // ========== ESTADO ==========
  const [filtros, setFiltros] = useState<FiltrosHistorial>({})
  const [busqueda, setBusqueda] = useState('')
  const [tipoEvento, setTipoEvento] = useState('')
  const [modulo, setModulo] = useState('')
  const [usuarioFiltro, setUsuarioFiltro] = useState('')

  // ========== QUERIES (Eventos automáticos + Notas manuales) ==========
  const {
    data: eventosRaw = [],
    isLoading: isLoadingEventos,
    error: errorEventos,
    refetch: refetchEventos,
  } = useQuery({
    queryKey: ['historial-cliente', clienteId, limit],
    queryFn: () => historialClienteService.obtenerHistorial(clienteId, limit),
    enabled: habilitado && !!clienteId,
    refetchOnWindowFocus: false,
    staleTime: 0, // Sin cache - siempre fresh
  })

  const {
    data: notasRaw = [],
    isLoading: isLoadingNotas,
    error: errorNotas,
    refetch: refetchNotas,
  } = useQuery({
    queryKey: ['notas-historial-cliente', clienteId],
    queryFn: () => notasHistorialService.obtenerNotasCliente(clienteId),
    enabled: habilitado && !!clienteId,
    refetchOnWindowFocus: false,
    staleTime: 0, // Sin cache - siempre fresh
  })

  // ========== HUMANIZAR EVENTOS + CONVERTIR NOTAS ==========
  const eventosHumanizados = useMemo(() => {
    return humanizarEventos(eventosRaw)
  }, [eventosRaw])

  const notasComoEventos = useMemo(() => {
    return convertirNotasAEventos(notasRaw)
  }, [notasRaw])

  // ========== UNIFICAR EVENTOS + NOTAS EN TIMELINE ==========
  const todosLosEventos = useMemo(() => {
    return [...eventosHumanizados, ...notasComoEventos].sort((a, b) => {
      return new Date(b.fecha).getTime() - new Date(a.fecha).getTime()
    })
  }, [eventosHumanizados, notasComoEventos])

  // ========== USUARIOS DISPONIBLES ==========
  const usuariosDisponibles = useMemo(() => {
    const usuariosMap = new Map<string, { id: string; email: string }>()

    todosLosEventos.forEach((evento) => {
      if (evento.usuario.id && evento.usuario.email) {
        usuariosMap.set(evento.usuario.id, {
          id: evento.usuario.id,
          email: evento.usuario.email,
        })
      }
    })

    return Array.from(usuariosMap.values()).sort((a, b) =>
      a.email.localeCompare(b.email)
    )
  }, [todosLosEventos])

  // ========== FILTRAR Y BUSCAR ==========
  const eventosFiltrados = useMemo(() => {
    let eventos = todosLosEventos

    // Filtrar por tipo de evento (CREATE, UPDATE, DELETE)
    if (tipoEvento) {
      eventos = eventos.filter((e) => e.accion === tipoEvento)
    }

    // Filtrar por módulo
    if (modulo) {
      eventos = eventos.filter((e) => e.metadata?.modulo === modulo)
    }

    // Filtrar por usuario
    if (usuarioFiltro) {
      eventos = eventos.filter((e) => e.usuario.id === usuarioFiltro)
    }

    // Filtrar por tipo (legacy - mantener compatibilidad)
    if (filtros.tipo && filtros.tipo.length > 0) {
      eventos = eventos.filter((e) => filtros.tipo!.includes(e.tipo))
    }

    // Filtrar por búsqueda
    if (busqueda.trim()) {
      const terminoLower = busqueda.toLowerCase()
      eventos = eventos.filter((e) => {
        const textoEvento = `
          ${e.titulo}
          ${e.descripcion}
          ${e.usuario.email}
          ${e.usuario.nombres || ''}
        `.toLowerCase()

        return textoEvento.includes(terminoLower)
      })
    }

    // Filtrar por fechas
    if (filtros.fecha_desde) {
      const fechaDesde = new Date(filtros.fecha_desde)
      eventos = eventos.filter((e) => new Date(e.fecha) >= fechaDesde)
    }

    if (filtros.fecha_hasta) {
      const fechaHasta = new Date(filtros.fecha_hasta)
      eventos = eventos.filter((e) => new Date(e.fecha) <= fechaHasta)
    }

    return eventos
  }, [todosLosEventos, filtros, busqueda, tipoEvento, modulo, usuarioFiltro])

  // ========== AGRUPAR POR FECHA ==========
  const eventosAgrupados = useMemo(() => {
    const grupos: Record<string, EventoHistorialHumanizado[]> = {}

    eventosFiltrados.forEach((evento) => {
      const fecha = new Date(evento.fecha)
      const fechaKey = fecha.toISOString().split('T')[0] // YYYY-MM-DD

      if (!grupos[fechaKey]) {
        grupos[fechaKey] = []
      }

      grupos[fechaKey].push(evento)
    })

    // Convertir a array y ordenar
    const gruposArray: GrupoEventosPorFecha[] = Object.entries(grupos).map(
      ([fecha, eventos]) => ({
        fecha,
        fechaFormateada: formatearFechaRelativa(fecha),
        eventos,
        total: eventos.length,
      })
    )

    // Ordenar por fecha descendente (más reciente primero)
    gruposArray.sort((a, b) => {
      const fechaA = new Date(a.fecha).getTime()
      const fechaB = new Date(b.fecha).getTime()
      return fechaB - fechaA
    })

    return gruposArray
  }, [eventosFiltrados])

  // ========== ESTADÍSTICAS ==========
  const estadisticas = useMemo(() => {
    const total = todosLosEventos.length
    const porTipo: Record<string, number> = {}
    const porColor: Record<string, number> = {}

    // Métricas temporales
    const ahora = new Date()
    const inicioSemana = new Date(ahora)
    inicioSemana.setDate(ahora.getDate() - 7)
    const inicioMes = new Date(ahora)
    inicioMes.setDate(1)

    let estaSemana = 0
    let esteMes = 0
    let criticos = 0

    todosLosEventos.forEach((evento) => {
      const fechaEvento = new Date(evento.fecha)

      // Contar por tipo
      porTipo[evento.tipo] = (porTipo[evento.tipo] || 0) + 1

      // Contar por color
      porColor[evento.color] = (porColor[evento.color] || 0) + 1

      // Contar temporales
      if (fechaEvento >= inicioSemana) estaSemana++
      if (fechaEvento >= inicioMes) esteMes++

      // Contar críticos (DELETE o acciones de renuncias/eliminación)
      if (evento.accion === 'DELETE' || evento.color === 'red') criticos++
    })

    return {
      total,
      porTipo,
      porColor,
      filtrados: eventosFiltrados.length,
      grupos: eventosAgrupados.length,
      // Nuevas métricas
      estaSemana,
      esteMes,
      criticos,
    }
  }, [todosLosEventos, eventosFiltrados, eventosAgrupados])

  // ========== FUNCIONES DE FILTRADO ==========
  const aplicarFiltros = (nuevosFiltros: Partial<FiltrosHistorial>) => {
    setFiltros((prev) => ({ ...prev, ...nuevosFiltros }))
  }

  const limpiarFiltros = () => {
    setFiltros({})
    setBusqueda('')
    setTipoEvento('')
    setModulo('')
    setUsuarioFiltro('')
  }

  const tieneAplicados =
    Object.keys(filtros).length > 0 ||
    busqueda.trim() !== '' ||
    tipoEvento !== '' ||
    modulo !== '' ||
    usuarioFiltro !== ''

  // ========== RETORNO ==========
  return {
    // Datos
    eventosRaw,
    eventosHumanizados,
    notasRaw,
    todosLosEventos,
    eventosFiltrados,
    eventosAgrupados,
    estadisticas,
    usuariosDisponibles,

    // Estados
    isLoading: isLoadingEventos || isLoadingNotas,
    error: errorEventos || errorNotas,

    // Filtros y búsqueda
    filtros,
    busqueda,
    tipoEvento,
    modulo,
    usuarioFiltro,
    setBusqueda,
    setTipoEvento,
    setModulo,
    setUsuarioFiltro,
    aplicarFiltros,
    limpiarFiltros,
    tieneAplicados,

    // Acciones
    refetch: () => {
      refetchEventos()
      refetchNotas()
    },
  }
}

/**
 * Formatear fecha relativa (Hoy, Ayer, fecha completa)
 */
function formatearFechaRelativa(fechaStr: string): string {
  const fecha = new Date(fechaStr + 'T12:00:00') // Agregar hora para evitar timezone shift
  const hoy = new Date()
  hoy.setHours(0, 0, 0, 0)

  const ayer = new Date(hoy)
  ayer.setDate(ayer.getDate() - 1)

  const fechaInput = new Date(fecha)
  fechaInput.setHours(0, 0, 0, 0)

  if (fechaInput.getTime() === hoy.getTime()) {
    return 'Hoy'
  }

  if (fechaInput.getTime() === ayer.getTime()) {
    return 'Ayer'
  }

  // Fecha completa: "15 de noviembre de 2025"
  return formatDateForDisplay(fechaStr)
}

/**
 * Hook para gestionar historial de versiones de negociaciones
 * ✅ ACTUALIZADO: Usa tabla negociaciones_historial (nuevo sistema)
 */

import { useQuery } from '@tanstack/react-query'

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

import { NegociacionesVersionesService } from '../services/negociaciones-versiones.service'


export interface SnapshotVersion {
  id: string
  version: number
  tipo_cambio: string
  razon_cambio: string
  fecha_cambio: string
  campos_modificados: string[]
  datos_anteriores?: any
  datos_nuevos?: any
  fuentes_pago_snapshot?: any[]
  usuario_id?: string
  usuario_email?: string
  usuario_nombre?: string
}

export function useHistorialVersiones(negociacionId: string) {
  // Query: Obtener historial completo desde negociaciones_historial
  const {
    data: versiones,
    isLoading,
    error,
    refetch,
  } = useQuery({
    queryKey: ['negociaciones-historial-v2', negociacionId], // v2 para forzar refresh
    queryFn: async (): Promise<SnapshotVersion[]> => {

      const { data, error } = await supabase
        .from('negociaciones_historial')
        .select('*')
        .eq('negociacion_id', negociacionId)
        .order('version', { ascending: false })

      if (error) {
        logger.error('❌ [useHistorialVersiones] Error:', error)
        throw error
      }

      return (data || []) as SnapshotVersion[]
    },
    enabled: !!negociacionId,
    staleTime: 0, // Sin caché para debugging
    gcTime: 0, // Sin caché para debugging
  })

  // Query: Versión actual de la negociación
  const { data: versionActual } = useQuery({
    queryKey: ['negociacion-info', negociacionId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('negociaciones')
        .select('version_actual, version_lock')
        .eq('id', negociacionId)
        .single()

      if (error) throw error
      return data
    },
    enabled: !!negociacionId,
    staleTime: 1000 * 60 * 2,
    gcTime: 1000 * 60 * 5,
  })

  return {
    // Data
    versiones: versiones || [],
    versionActual: versionActual?.version_actual,
    versionLock: versionActual?.version_lock,
    totalVersiones: versiones?.length || 0,

    // Estado
    isLoading,
    error,

    // Acciones
    refetch,
  }
}

/**
 * Hook simplificado para solo obtener la versión actual
 */
export function useVersionActual(negociacionId: string) {
  const { data, isLoading, error } = useQuery({
    queryKey: ['negociacion-version-actual', negociacionId],
    queryFn: () => NegociacionesVersionesService.obtenerVersionActual(negociacionId),
    enabled: !!negociacionId,
  })

  return {
    versionActual: data,
    isLoading,
    error,
  }
}

/**
 * Hook para manejar la selección de intereses en el formulario
 * Carga proyectos y viviendas disponibles
 */

import { useCallback, useEffect, useState } from 'react'

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

interface Proyecto {
  id: string
  nombre: string
  ubicacion: string
}

interface Vivienda {
  id: string
  numero: string
  manzana_nombre: string
  valor_total: number
  estado: string
}

export function useInteresFormulario() {
  const [proyectos, setProyectos] = useState<Proyecto[]>([])
  const [viviendas, setViviendas] = useState<Vivienda[]>([])
  const [proyectoSeleccionado, setProyectoSeleccionado] = useState<string>('')
  const [viviendaSeleccionada, setViviendaSeleccionada] = useState<string>('')
  const [notasInteres, setNotasInteres] = useState<string>('')
  const [cargandoProyectos, setCargandoProyectos] = useState(false)
  const [cargandoViviendas, setCargandoViviendas] = useState(false)

  // =====================================================
  // CARGAR PROYECTOS ACTIVOS
  // =====================================================
  useEffect(() => {
    cargarProyectos()
  }, [])

  const cargarProyectos = async () => {
    setCargandoProyectos(true)
    try {
      const { data, error } = await supabase
        .from('proyectos')
        .select('id, nombre, ubicacion')
        .in('estado', ['en_planificacion', 'en_construccion'])
        .order('nombre')

      if (error) throw error
      setProyectos(data || [])
    } catch (error) {
      logger.error('Error cargando proyectos:', error)
    } finally {
      setCargandoProyectos(false)
    }
  }

  // =====================================================
  // CARGAR VIVIENDAS DISPONIBLES CUANDO SELECCIONA PROYECTO
  // =====================================================
  useEffect(() => {
    if (proyectoSeleccionado) {
      cargarViviendasProyecto(proyectoSeleccionado)
    } else {
      setViviendas([])
      setViviendaSeleccionada('')
    }
  }, [proyectoSeleccionado])

  const cargarViviendasProyecto = async (proyectoId: string) => {
    setCargandoViviendas(true)
    try {
      const { data, error } = await supabase
        .from('viviendas')
        .select(
          `
          id,
          numero,
          valor_total,
          estado,
          manzanas!inner(
            nombre,
            proyecto_id
          )
        `
        )
        .eq('manzanas.proyecto_id', proyectoId)
        .eq('estado', 'Disponible')
        .order('numero')

      if (error) throw error

      // Transformar datos
      const viviendasFormateadas =
        data?.map((v: any) => ({
          id: v.id,
          numero: v.numero,
          manzana_nombre: v.manzanas?.nombre || '',
          valor_total: v.valor_total,
          estado: v.estado,
        })) || []

      setViviendas(viviendasFormateadas)
    } catch (error) {
      logger.error('Error cargando viviendas:', error)
      setViviendas([])
    } finally {
      setCargandoViviendas(false)
    }
  }

  // =====================================================
  // HANDLERS
  // =====================================================
  const handleProyectoChange = useCallback((proyectoId: string) => {
    setProyectoSeleccionado(proyectoId)
    setViviendaSeleccionada('') // Reset vivienda cuando cambia proyecto
  }, [])

  const handleViviendaChange = useCallback((viviendaId: string) => {
    setViviendaSeleccionada(viviendaId)
  }, [])

  const handleNotasChange = useCallback((notas: string) => {
    setNotasInteres(notas)
  }, [])

  const resetInteres = useCallback(() => {
    setProyectoSeleccionado('')
    setViviendaSeleccionada('')
    setNotasInteres('')
  }, [])

  // =====================================================
  // OBTENER DATOS DEL INTERÉS
  // =====================================================
  const getInteresData = useCallback(() => {
    if (!proyectoSeleccionado) return undefined

    return {
      proyecto_id: proyectoSeleccionado,
      vivienda_id: viviendaSeleccionada || undefined,
      notas_interes: notasInteres || undefined,
    }
  }, [proyectoSeleccionado, viviendaSeleccionada, notasInteres])

  return {
    proyectos,
    viviendas,
    proyectoSeleccionado,
    viviendaSeleccionada,
    notasInteres,
    cargandoProyectos,
    cargandoViviendas,
    handleProyectoChange,
    handleViviendaChange,
    handleNotasChange,
    resetInteres,
    getInteresData,
    tieneInteres: !!proyectoSeleccionado,
  }
}

/**
 * ============================================
 * HOOK: useInteresesTab
 * ============================================
 *
 * ✅ SEPARACIÓN DE RESPONSABILIDADES + REACT QUERY
 * Hook que maneja TODA la lógica del tab de intereses.
 * El componente solo renderiza UI.
 *
 * Responsabilidades:
 * - Cargar intereses del cliente con React Query (cache automático)
 * - Descartar intereses con optimistic updates
 * - Filtrar por estado (client-side)
 * - Calcular estadísticas (memoizadas)
 */

import { useCallback, useState } from 'react'

import { logger } from '@/lib/utils/logger'

import type { ClienteInteres } from '../types'

import { useInteresesQuery } from './useInteresesQuery'

interface UseInteresesTabProps {
  clienteId: string
}

export function useInteresesTab({ clienteId }: UseInteresesTabProps) {
  // =====================================================
  // ESTADO
  // =====================================================

  const [descartandoId, setDescartandoId] = useState<string | null>(null)
  const [interesADescartar, setInteresADescartar] = useState<ClienteInteres | null>(null)

  // ✅ Hook con React Query (cache, refetch automático, estados optimizados)
  const {
    interesesFiltrados: intereses,
    loading,
    stats,
    descartarInteres,
    descartando: descartandoMutation,
    filtrarPorEstado,
    estadoFiltro,
    refetch,
  } = useInteresesQuery({ clienteId })

  // =====================================================
  // ACCIONES
  // =====================================================

  /** Abre el modal de confirmación para descartar */
  const abrirModalDescartar = useCallback((interes: ClienteInteres) => {
    setInteresADescartar(interes)
  }, [])

  /** Cancela sin descartar */
  const cancelarDescartar = useCallback(() => {
    setInteresADescartar(null)
  }, [])

  /** Ejecuta el descarte con el motivo ingresado */
  const confirmarDescartar = useCallback(
    async (motivo: string) => {
      if (!interesADescartar) return

      setDescartandoId(interesADescartar.id)
      setInteresADescartar(null)
      try {
        await descartarInteres(interesADescartar.id, motivo || 'Cliente ya no está interesado')
      } catch (error) {
        logger.error('❌ [useInteresesTab] Error al descartar:', error)
      } finally {
        setDescartandoId(null)
      }
    },
    [interesADescartar, descartarInteres]
  )

  // =====================================================
  // RETURN
  // =====================================================

  return {
    // Estado
    intereses,
    loading,
    stats,
    estadoFiltro,
    descartando: descartandoId,

    // Modal descartar
    interesADescartar,
    abrirModalDescartar,
    cancelarDescartar,
    confirmarDescartar,

    // Acciones
    filtrarPorEstado,
    recargar: refetch,
  }
}

/**
 * Hook useNegociacion
 *
 * Gestiona el ciclo completo de una negociación:
 * 1. Crear negociación (estado: 'Activa')
 * 2. Configurar fuentes de pago
 * 3. Registrar abonos y seguimiento
 * 4. Completar o registrar renuncia
 *
 * ⚠️ NOMBRES DE CAMPOS VERIFICADOS EN: docs/DATABASE-SCHEMA-REFERENCE-ACTUALIZADO.md
 */

'use client'

import { useCallback, useEffect, useState } from 'react'

import { logger } from '@/lib/utils/logger'
import { fuentesPagoService } from '@/modules/clientes/services/fuentes-pago.service'
import { negociacionesService } from '@/modules/clientes/services/negociaciones.service'

interface UseNegociacionReturn {
  // Estado
  negociacion: any | null
  fuentesPago: any[]
  totales: {
    valorTotal: number
    totalFuentes: number
    porcentajeCubierto: number
    diferencia: number
  }
  cargando: boolean
  error: string | null

  // Acciones de estado
  completarNegociacion: () => Promise<boolean>
  registrarRenuncia: (motivo: string) => Promise<boolean>

  // Operaciones CRUD
  actualizarNegociacion: (datos: any) => Promise<boolean>
  recargarNegociacion: () => Promise<void>

  // Helpers
  puedeCompletarse: boolean
  esActiva: boolean
  estaSuspendida: boolean
  estaCompletada: boolean
  estaCerrada: boolean
  estadoLegible: string
}

export function useNegociacion(negociacionId: string): UseNegociacionReturn {
  // Estado
  const [negociacion, setNegociacion] = useState<any | null>(null)
  const [fuentesPago, setFuentesPago] = useState<any[]>([])
  const [cargando, setCargando] = useState(true)
  const [error, setError] = useState<string | null>(null)

  /**
   * Cargar negociación y fuentes de pago
   */
  const cargarDatos = useCallback(async () => {
    try {
      setCargando(true)
      setError(null)

      // Cargar negociación
      const negData = await negociacionesService.obtenerNegociacion(negociacionId)
      setNegociacion(negData)

      // Cargar fuentes de pago
      const fuentesData = await fuentesPagoService.obtenerFuentesPagoNegociacion(negociacionId)
      setFuentesPago(fuentesData)
    } catch (err: unknown) {
      logger.error('Error cargando negociación:', err)
      setError(`Error cargando negociación: ${err.message}`)
    } finally {
      setCargando(false)
    }
  }, [negociacionId])

  /**
   * Cargar datos al montar
   */
  useEffect(() => {
    if (negociacionId) {
      cargarDatos()
    }
  }, [negociacionId, cargarDatos])

  /**
   * Calcular totales de fuentes de pago
   */
  const calcularTotales = useCallback(() => {
    // Para créditos con la constructora usamos capital_para_cierre (sin intereses).
    // Para el resto, monto_aprobado es el valor correcto.
    const valorTotal = negociacion?.valor_total || 0
    const totalFuentes = fuentesPago.reduce(
      (sum, f: any) => sum + (f.capital_para_cierre ?? f.monto_aprobado ?? 0),
      0
    )
    const porcentajeCubierto = valorTotal > 0 ? (totalFuentes / valorTotal) * 100 : 0
    const diferencia = valorTotal - totalFuentes

    return {
      valorTotal,
      totalFuentes,
      porcentajeCubierto,
      diferencia,
    }
  }, [negociacion, fuentesPago])

  const totales = calcularTotales()

  /**
   * Helpers de estado
   * Estados permitidos: 'Activa', 'Suspendida', 'Cerrada por Renuncia', 'Completada'
   */
  const esActiva = negociacion?.estado === 'Activa'
  const estaSuspendida = negociacion?.estado === 'Suspendida'
  const estaCompletada = negociacion?.estado === 'Completada'
  const estaCerrada = negociacion?.estado === 'Cerrada por Renuncia'
  const puedeCompletarse = esActiva && totales.porcentajeCubierto >= 100

  const estadoLegible =
    negociacion?.estado === 'Activa'
      ? 'Negociación Activa'
      : negociacion?.estado === 'Suspendida'
        ? 'Suspendida'
        : negociacion?.estado === 'Cerrada por Renuncia'
          ? 'Cerrada por Renuncia'
          : negociacion?.estado === 'Completada'
            ? 'Completada'
            : 'Desconocido'

  /**
   * Completar negociación
   * ✅ Estado final: 'Completada'
   * Requisito: Estar en estado 'Activa' y tener pago completo (100%)
   */
  const completarNegociacion = useCallback(async (): Promise<boolean> => {
    try {
      setError(null)

      if (!puedeCompletarse) {
        setError('La negociación solo puede completarse si está activa y el pago está completo')
        return false
      }

      await negociacionesService.completarNegociacion(negociacionId)
      await cargarDatos()
      return true
    } catch (err: unknown) {
      logger.error('Error completando negociación:', err)
      setError(`Error: ${err.message}`)
      return false
    }
  }, [negociacionId, puedeCompletarse, cargarDatos])

  /**
   * Registrar renuncia del cliente
   * ✅ Cambia estado de negociación a 'Cerrada por Renuncia'
   * ✅ Crea registro en tabla renuncias
   */
  const registrarRenuncia = useCallback(
    async (motivo: string): Promise<boolean> => {
      try {
        setError(null)

        if (!motivo?.trim()) {
          setError('Debes especificar el motivo de la renuncia')
          return false
        }

        await negociacionesService.cerrarPorRenuncia(negociacionId)
        await cargarDatos()
        return true
      } catch (err: unknown) {
        logger.error('Error registrando renuncia:', err)
        setError(`Error: ${err.message}`)
        return false
      }
    },
    [negociacionId, cargarDatos]
  )

  /**
   * Actualizar campos de la negociación
   */
  const actualizarNegociacion = useCallback(
    async (datos: any): Promise<boolean> => {
      try {
        setError(null)
        await negociacionesService.actualizarNegociacion(negociacionId, datos)
        await cargarDatos()
        return true
      } catch (err: unknown) {
        logger.error('Error actualizando negociación:', err)
        setError(`Error: ${err.message}`)
        return false
      }
    },
    [negociacionId, cargarDatos]
  )

  return {
    // Estado
    negociacion,
    fuentesPago,
    totales,
    cargando,
    error,

    // Acciones
    completarNegociacion,
    registrarRenuncia,

    // CRUD
    actualizarNegociacion,
    recargarNegociacion: cargarDatos,

    // Helpers
    puedeCompletarse,
    esActiva,
    estaSuspendida,
    estaCompletada,
    estaCerrada,
    estadoLegible,
  }
}

/**
 * ============================================
 * HOOK: useNegociacionesQuery
 * ============================================
 *
 * ✅ REACT QUERY + SEPARACIÓN DE RESPONSABILIDADES
 * Hook que maneja data fetching con React Query para negociaciones.
 *
 * Ventajas React Query:
 * - Cache automático de negociaciones
 * - Refetch en background
 * - Loading/error states optimizados
 * - Invalidación de cache selectiva
 * - Sincronización entre tabs/ventanas
 *
 * @version 2.0.0 - 2025-01-26 (Migrado a React Query)
 */

import { useCallback, useEffect, useMemo } from 'react'

import { useQuery, useQueryClient } from '@tanstack/react-query'

import { obtenerFuentesPagoConAbonos } from '@/modules/abonos/services/abonos.service'
import { negociacionesService } from '@/modules/clientes/services/negociaciones.service'

// ============================================
// QUERY KEYS (Centralizar para invalidación)
// ============================================

export const negociacionesQueryKeys = {
  all: ['negociaciones'] as const,
  byCliente: (clienteId: string) => [...negociacionesQueryKeys.all, 'cliente', clienteId] as const,
  detalle: (negociacionId: string) => [...negociacionesQueryKeys.all, 'detalle', negociacionId] as const,
  fuentesPago: (negociacionId: string) => ['fuentesPago', negociacionId] as const,
}

// ============================================
// TYPES
// ============================================

export interface NegociacionDetalle {
  id: string
  estado: string
  valor_negociado: number
  descuento_aplicado: number
  proyecto?: { nombre: string; id: string }
  vivienda?: {
    id: string
    numero: string
    manzanas?: { nombre: string; id: string }
  }
  fecha_negociacion: string
  fecha_creacion?: string
  fecha_completada?: string
}

export interface NegociacionConValores extends NegociacionDetalle {
  valorBase: number
  descuento: number
  valorFinal: number
}

interface FuentePago {
  id: string
  tipo: string
  monto: number // ✅ Cambiar de monto_aprobado a monto (como viene del service)
  entidad?: string
  numero_referencia?: string
  detalles?: string // ✅ Cambiar de observaciones a detalles
  monto_recibido: number
  abonos?: any[]
}

interface Abono {
  id: string
  monto: number
  fecha_abono: string
  metodo_pago?: string
  numero_recibo?: string
  observaciones?: string
  comprobante_url?: string
}

// ============================================
// HOOK PRINCIPAL
// ============================================

interface UseNegociacionesQueryProps {
  clienteId: string
  enabled?: boolean
}

export function useNegociacionesQuery({ clienteId, enabled = true }: UseNegociacionesQueryProps) {
  const queryClient = useQueryClient()

  // =====================================================
  // QUERY: Lista de negociaciones del cliente
  // =====================================================

  const {
    data: negociaciones = [],
    isLoading,
    error,
    refetch,
  } = useQuery({
    queryKey: negociacionesQueryKeys.byCliente(clienteId),
    queryFn: async () => {
      const data = await negociacionesService.obtenerNegociacionesCliente(clienteId)
      return data as NegociacionDetalle[]
    },
    enabled: enabled && !!clienteId,
    staleTime: 1000 * 30,       // 30 segundos — dato crítico, debe estar fresco
    gcTime: 1000 * 60 * 10,    // 10 minutos de cache
    refetchOnMount: true,       // Siempre refetch si stale al montar
    refetchOnWindowFocus: true, // Refetch cuando el usuario vuelve a la ventana
  })

  // =====================================================
  // SUSCRIPCIÓN AL EVENTO DE NEGOCIACIÓN CREADA
  // =====================================================
  // Capa de seguridad: si por alguna razón la invalidación explícita
  // de useCrearNegociacion no dispara el refetch, el evento lo garantiza.

  useEffect(() => {
    if (!clienteId) return
    const handleNegociacionCreada = () => {
      queryClient.invalidateQueries({ queryKey: negociacionesQueryKeys.byCliente(clienteId) })
    }
    window.addEventListener('negociacion-creada', handleNegociacionCreada)
    return () => window.removeEventListener('negociacion-creada', handleNegociacionCreada)
  }, [clienteId, queryClient])

  // =====================================================
  // CÁLCULOS COMPUTADOS
  // =====================================================

  /**
   * Negociaciones con valores calculados (memoizado)
   */
  const negociacionesConValores = useMemo((): NegociacionConValores[] => {
    return negociaciones.map((neg) => {
      const valorBase = neg.valor_negociado || 0
      const descuento = neg.descuento_aplicado || 0
      const valorFinal = valorBase - descuento

      return {
        ...neg,
        valorBase,
        descuento,
        valorFinal,
      }
    })
  }, [negociaciones])

  /**
   * Estadísticas rápidas (para header)
   */
  const stats = useMemo(() => {
    const activas = negociacionesConValores.filter((n) => n.estado === 'Activa').length
    const completadas = negociacionesConValores.filter((n) => n.estado === 'Completada').length
    const suspendidas = negociacionesConValores.filter((n) => n.estado === 'Suspendida').length

    return {
      total: negociacionesConValores.length,
      activas,
      completadas,
      suspendidas,
    }
  }, [negociacionesConValores])

  // =====================================================
  // INVALIDACIÓN DE CACHE (React Query)
  // =====================================================

  /**
   * Invalidar cache de negociaciones (forzar refetch)
   */
  const invalidarNegociaciones = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: negociacionesQueryKeys.byCliente(clienteId) })
  }, [clienteId, queryClient])

  /**
   * Invalidar todas las negociaciones (global)
   */
  const invalidarTodasNegociaciones = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: negociacionesQueryKeys.all })
  }, [queryClient])

  // =====================================================
  // RETURN
  // =====================================================

  return {
    // Data
    negociaciones: negociacionesConValores,
    stats,

    // Estado de carga
    isLoading,
    error,

    // Acciones
    refetch,
    invalidarNegociaciones,
    invalidarTodasNegociaciones,
  }
}

// ============================================
// HOOK: Detalle de negociación (fuentes + abonos)
// ============================================

interface UseNegociacionDetalleProps {
  negociacionId: string | null
  enabled?: boolean
}

export function useNegociacionDetalle({ negociacionId, enabled = true }: UseNegociacionDetalleProps) {
  // =====================================================
  // QUERY: Fuentes de pago con abonos
  // =====================================================

  const {
    data: fuentesPago = [],
    isLoading: isLoadingFuentes,
    error: errorFuentes,
  } = useQuery({
    queryKey: negociacionesQueryKeys.fuentesPago(negociacionId || ''),
    queryFn: async () => {
      if (!negociacionId) return []
      const data = await obtenerFuentesPagoConAbonos(negociacionId)
      return data as unknown as FuentePago[]
    },
    enabled: enabled && !!negociacionId,
    staleTime: 1000 * 60 * 2, // 2 minutos
    gcTime: 1000 * 60 * 5, // 5 minutos
  })

  // =====================================================
  // CÁLCULOS COMPUTADOS
  // =====================================================

  /**
   * Todos los abonos de todas las fuentes (ordenados)
   */
  const abonos = useMemo((): Abono[] => {
    const todosAbonos = fuentesPago.flatMap((fuente) => fuente.abonos || [])

    // Ordenar por fecha descendente
    return todosAbonos.sort(
      (a: any, b: any) => new Date(b.fecha_abono).getTime() - new Date(a.fecha_abono).getTime()
    )
  }, [fuentesPago])

  /**
   * Totales calculados
   */
  const totales = useMemo(() => {
    const totalFuentesPago = fuentesPago.reduce((sum, fuente) => sum + (fuente.monto || 0), 0)
    const totalAbonado = abonos.reduce((sum, abono) => sum + (abono.monto || 0), 0)

    return {
      totalFuentesPago,
      totalAbonado,
      saldoPendiente: totalFuentesPago - totalAbonado,
      porcentajePagado: totalFuentesPago > 0 ? (totalAbonado / totalFuentesPago) * 100 : 0,
    }
  }, [fuentesPago, abonos])

  /**
   * Fuentes transformadas (formato UI)
   */
  const fuentesTransformadas = useMemo(() => {
    return fuentesPago.map((fuente) => ({
      id: fuente.id, // ✅ Incluir id para edición
      tipo: fuente.tipo,
      monto: fuente.monto || 0, // ✅ Ya viene como 'monto' desde el service
      entidad: fuente.entidad || undefined,
      numero_referencia: fuente.numero_referencia || undefined,
      detalles: fuente.detalles || undefined, // ✅ Usar 'detalles' no 'observaciones'
      monto_recibido: fuente.monto_recibido || 0,
    }))
  }, [fuentesPago])

  /**
   * Último abono registrado + días desde último pago
   */
  const ultimoAbono = abonos.length > 0 ? abonos[0] : null

  const diasDesdeUltimoAbono = useMemo(() => {
    if (!ultimoAbono?.fecha_abono) return null

    const fechaAbono = new Date(ultimoAbono.fecha_abono)
    const hoy = new Date()
    const diffTime = Math.abs(hoy.getTime() - fechaAbono.getTime())
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))

    return diffDays
  }, [ultimoAbono])

  // =====================================================
  // RETURN
  // =====================================================

  return {
    // Data
    fuentesPago: fuentesTransformadas,
    abonos,
    totales,
    ultimoAbono,
    diasDesdeUltimoAbono,

    // Estado de carga
    isLoading: isLoadingFuentes,
    error: errorFuentes,
  }
}

/**
 * ============================================
 * HOOK: useNegociacionesTab
 * ============================================
 *
 * ✅ SEPARACIÓN DE RESPONSABILIDADES
 * Hook que maneja TODA la lógica del tab de negociaciones.
 * El componente solo renderiza UI.
 *
 * Responsabilidades:
 * - Cargar negociaciones del cliente
 * - Seleccionar negociación activa para ver detalle
 * - Cargar fuentes de pago y abonos de la negociación seleccionada
 * - Escuchar eventos de recarga (cuando se crea nueva negociación)
 * - Calcular totales y estadísticas
 * - Navegación y construcción de URLs
 * - Cálculos de valores con descuento
 */

import { useCallback, useEffect, useMemo, useState } from 'react'

import { useRouter } from 'next/navigation'

import { logger } from '@/lib/utils/logger'
import { construirURLCliente } from '@/lib/utils/slug.utils'
import { obtenerFuentesPagoConAbonos } from '@/modules/abonos/services/abonos.service'
import { negociacionesService } from '@/modules/clientes/services/negociaciones.service'
import type { Cliente } from '@/modules/clientes/types'

interface UseNegociacionesTabProps {
  clienteId: string
  cliente: Cliente
}

interface NegociacionDetalle {
  id: string
  estado: string
  valor_negociado: number
  descuento_aplicado: number
  proyecto?: { nombre: string }
  vivienda?: {
    numero: string
    manzanas?: { nombre: string }
  }
  fecha_negociacion: string
  fecha_completada?: string
}

interface FuentePago {
  id: string
  tipo: string
  monto_aprobado: number
  entidad?: string
  numero_referencia?: string
  observaciones?: string
  monto_recibido: number
  abonos?: any[]
}

interface Abono {
  id: string
  monto: number
  fecha_abono: string
  comprobante_url?: string
}

export function useNegociacionesTab({ clienteId, cliente }: UseNegociacionesTabProps) {
  const router = useRouter()

  // =====================================================
  // ESTADO
  // =====================================================

  const [negociaciones, setNegociaciones] = useState<NegociacionDetalle[]>([])
  const [loading, setLoading] = useState(true)
  const [negociacionActiva, setNegociacionActiva] = useState<NegociacionDetalle | null>(null)
  const [fuentesPago, setFuentesPago] = useState<FuentePago[]>([])
  const [abonos, setAbonos] = useState<Abono[]>([])
  const [loadingDatos, setLoadingDatos] = useState(false)

  // =====================================================
  // FUNCIONES
  // =====================================================

  /**
   * Cargar todas las negociaciones del cliente
   */
  const cargarNegociaciones = useCallback(async () => {
    if (!clienteId) return

    setLoading(true)
    try {
      const data = await negociacionesService.obtenerNegociacionesCliente(clienteId)
      setNegociaciones(data)
    } catch (err) {
      logger.error('❌ [useNegociacionesTab] Error cargando negociaciones:', err)
      setNegociaciones([])
    } finally {
      setLoading(false)
    }
  }, [clienteId])

  /**
   * Cargar fuentes de pago y abonos de una negociación específica
   */
  const cargarDatosNegociacion = useCallback(async (negociacionId: string) => {
    setLoadingDatos(true)
    try {
      // Cargar fuentes de pago con abonos
      const fuentesData = await obtenerFuentesPagoConAbonos(negociacionId)
      setFuentesPago(fuentesData)

      // Extraer todos los abonos de todas las fuentes
      const todosAbonos = fuentesData.flatMap((fuente: any) => fuente.abonos || [])
      // Ordenar por fecha descendente
      todosAbonos.sort((a: any, b: any) =>
        new Date(b.fecha_abono).getTime() - new Date(a.fecha_abono).getTime()
      )
      setAbonos(todosAbonos)
    } catch (err) {
      logger.error('❌ [useNegociacionesTab] Error cargando datos de negociación:', err)
      setFuentesPago([])
      setAbonos([])
    } finally {
      setLoadingDatos(false)
    }
  }, [])

  /**
   * Ver detalle de una negociación (carga sus datos asociados)
   */
  const verDetalleNegociacion = useCallback(
    async (negociacion: NegociacionDetalle) => {
      setNegociacionActiva(negociacion)
      await cargarDatosNegociacion(negociacion.id)
    },
    [cargarDatosNegociacion]
  )

  /**
   * Volver a la lista de negociaciones
   */
  const volverALista = useCallback(() => {
    setNegociacionActiva(null)
    setFuentesPago([])
    setAbonos([])
  }, [])

  /**
   * Navegar a crear negociación
   */
  const navegarACrearNegociacion = useCallback(() => {
    const clienteSlug = construirURLCliente({
      id: cliente.id,
      nombre_completo: cliente.nombre_completo,
      nombres: cliente.nombres,
      apellidos: cliente.apellidos
    }).split('/').pop()

    const nombreCliente = cliente.nombre_completo || cliente.nombres || ''
    router.push(`/clientes/${clienteSlug}/negociaciones/crear?nombre=${encodeURIComponent(nombreCliente)}` as any)
  }, [cliente, router])

  /**
   * Navegar a asignar vivienda (desde FAB)
   */
  const navegarAAsignarVivienda = useCallback(() => {
    const clienteSlug = construirURLCliente({
      id: cliente.id,
      nombre_completo: cliente.nombre_completo,
      nombres: cliente.nombres,
      apellidos: cliente.apellidos
    }).split('/').pop()

    const nombreCliente = cliente.nombre_completo || cliente.nombres || ''
    router.push(`/clientes/${clienteSlug}/asignar-vivienda?nombre=${encodeURIComponent(nombreCliente)}` as any)
  }, [cliente, router])

  /**
   * Navegar a registrar abono
   */
  const navegarARegistrarAbono = useCallback((negociacionId: string) => {
    const nombreCliente = cliente.nombre_completo || cliente.nombres || ''
    router.push(
      `/abonos?cliente_id=${cliente.id}&negociacion_id=${negociacionId}&cliente_nombre=${encodeURIComponent(nombreCliente)}` as any
    )
  }, [cliente, router])

  // =====================================================
  // CÁLCULOS COMPUTADOS
  // =====================================================

  /**
   * Calcular valores de cada negociación (con memoización)
   */
  const negociacionesConValores = useMemo(() => {
    return negociaciones.map(neg => {
      const valorBase = neg.valor_negociado || 0
      const descuento = neg.descuento_aplicado || 0
      const valorFinal = valorBase - descuento

      return {
        ...neg,
        valorBase,
        descuento,
        valorFinal,
      }
    })
  }, [negociaciones])

  const totales = {
    valorFinal: negociacionActiva
      ? (negociacionActiva.valor_negociado || 0) - (negociacionActiva.descuento_aplicado || 0)
      : 0,
    totalAbonado: abonos.reduce((sum, abono) => sum + (abono.monto || 0), 0),
    totalFuentesPago: fuentesPago.reduce((sum, fuente) => sum + (fuente.monto_aprobado || 0), 0),
  }

  /**
   * Transformar fuentes de pago al formato esperado por componentes de UI
   */
  const fuentesTransformadas = fuentesPago.map((fuente) => ({
    tipo: fuente.tipo,
    monto: fuente.monto_aprobado || 0,
    entidad: fuente.entidad || undefined,
    numero_referencia: fuente.numero_referencia || undefined,
    detalles: fuente.observaciones || undefined,
    monto_recibido: fuente.monto_recibido || 0,
  }))

  // =====================================================
  // EFECTOS
  // =====================================================

  // Cargar negociaciones al montar o cuando cambia el cliente
  useEffect(() => {
    if (clienteId) {
      cargarNegociaciones()
    }
  }, [clienteId, cargarNegociaciones])

  // Escuchar evento de recarga (cuando se crea nueva negociación)
  useEffect(() => {
    const handleRecargar = () => {
      cargarNegociaciones()
    }

    if (typeof window !== 'undefined') {
      window.addEventListener('negociacion-creada', handleRecargar)
      return () => window.removeEventListener('negociacion-creada', handleRecargar)
    }
  }, [cargarNegociaciones])

  // =====================================================
  // RETURN
  // =====================================================

  return {
    // Estado
    negociaciones: negociacionesConValores,
    loading,
    negociacionActiva,
    fuentesPago: fuentesTransformadas,
    abonos,
    loadingDatos,

    // Acciones
    verDetalleNegociacion,
    volverALista,
    recargarNegociaciones: cargarNegociaciones,

    // Navegación
    navegarACrearNegociacion,
    navegarAAsignarVivienda,
    navegarARegistrarAbono,

    // Cálculos
    totales,
  }
}

/**
 * useNuevoClienteAccordion — Hook que orquesta la creación de cliente
 * con el patrón Accordion Wizard (4 pasos).
 *
 * ✅ Zod validation por paso
 * ✅ Async: documento duplicado (paso 0)
 * ✅ Cross-field: teléfono OR email (paso 1)
 * ✅ Sanitización antes de enviar
 */

import { useCallback, useMemo, useState } from 'react'

import { zodResolver } from '@hookform/resolvers/zod'
import { useForm } from 'react-hook-form'
import { z } from 'zod'

import { useRouter } from 'next/navigation'

import type { SectionStatus, SummaryItem, WizardStepConfig } from '@/shared/components/accordion-wizard'

import { useCrearClienteMutation } from '../hooks/useClientesQuery'
import { clientesService } from '../services/clientes.service'
import type { CrearClienteDTO, EstadoCivil, TipoDocumento } from '../types'
import { sanitizeCrearClienteDTO } from '../utils/sanitize-cliente.utils'
import type { TipoDocumentoColombia } from '../utils/validacion-documentos-colombia'
import { validarDocumentoIdentidad } from '../utils/validacion-documentos-colombia'

// ── Configuración de pasos ─────────────────────────────
export const PASOS_CLIENTE: WizardStepConfig[] = [
  { id: 1, title: 'Datos Personales', description: 'Nombres, documento e información básica' },
  { id: 2, title: 'Contacto y Ubicación', description: 'Teléfono, email y dirección' },
  { id: 3, title: 'Interés Inicial', description: 'Proyecto y vivienda de interés' },
  { id: 4, title: 'Notas Adicionales', description: 'Observaciones opcionales' },
]

// ── Helpers de validación ──────────────────────────────
/** Solo letras (incluye tildes, ñ, espacios y guiones) */
const REGEX_SOLO_LETRAS = /^[a-zA-ZáéíóúÁÉÍÓÚñÑüÜ\s'-]+$/
/** Teléfono: dígitos, +, -, espacios, paréntesis */
const REGEX_TELEFONO = /^[0-9+\-\s()]+$/

// ── Schema del formulario ─────────────────────────────
const clienteFormSchema = z.object({
  // Paso 1: Datos Personales
  nombres: z.string()
    .min(2, 'Mínimo 2 caracteres')
    .max(80, 'Máximo 80 caracteres')
    .regex(REGEX_SOLO_LETRAS, 'Solo letras, espacios y tildes'),
  apellidos: z.string()
    .min(2, 'Mínimo 2 caracteres')
    .max(80, 'Máximo 80 caracteres')
    .regex(REGEX_SOLO_LETRAS, 'Solo letras, espacios y tildes'),
  tipo_documento: z.string().min(1, 'El tipo de documento es requerido'),
  numero_documento: z.string()
    .min(5, 'Mínimo 5 caracteres')
    .max(20, 'Máximo 20 caracteres'),
  fecha_nacimiento: z.string().optional(),
  estado_civil: z.string().optional(),
  // Paso 2: Contacto
  telefono: z.string()
    .regex(REGEX_TELEFONO, 'Solo números, +, -, (, ) y espacios')
    .min(7, 'Mínimo 7 dígitos')
    .max(15, 'Máximo 15 caracteres')
    .or(z.literal('')),
  telefono_alternativo: z.string()
    .regex(REGEX_TELEFONO, 'Solo números, +, -, (, ) y espacios')
    .min(7, 'Mínimo 7 dígitos')
    .max(15, 'Máximo 15 caracteres')
    .or(z.literal('')),
  email: z.string()
    .email('Correo electrónico inválido')
    .max(100, 'Máximo 100 caracteres')
    .or(z.literal('')),
  direccion: z.string()
    .min(5, 'Mínimo 5 caracteres')
    .max(200, 'Máximo 200 caracteres')
    .or(z.literal('')),
  departamento: z.string().min(1, 'El departamento es obligatorio'),
  ciudad: z.string().min(1, 'La ciudad es obligatoria'),
  // Paso 3: Interés
  proyecto_interes_id: z.string().optional(),
  vivienda_interes_id: z.string().optional(),
  notas_interes: z.string().max(500, 'Máximo 500 caracteres').optional(),
  // Paso 4: Notas
  notas: z.string().max(500, 'Máximo 500 caracteres').optional(),
})

type ClienteFormValues = z.input<typeof clienteFormSchema>

// Campos por paso
const FIELDS_PASO_1 = ['nombres', 'apellidos', 'tipo_documento', 'numero_documento'] as const
const FIELDS_PASO_2 = ['departamento', 'ciudad'] as const

export function useNuevoClienteAccordion() {
  const router = useRouter()
  const crearMutation = useCrearClienteMutation()

  const [pasoActual, setPasoActual] = useState(1)
  const [pasosCompletados, setPasosCompletados] = useState<Set<number>>(new Set())
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [isValidating, setIsValidating] = useState(false)
  const [showSuccess, setShowSuccess] = useState(false)

  // ── Formulario ──────────────────────────────────────
  const {
    register,
    watch,
    setValue,
    trigger,
    setError,
    getValues,
    formState: { errors },
  } = useForm<ClienteFormValues>({
    resolver: zodResolver(clienteFormSchema) as any,
    mode: 'onChange',
    defaultValues: {
      nombres: '',
      apellidos: '',
      tipo_documento: 'CC',
      numero_documento: '',
      fecha_nacimiento: '',
      estado_civil: '',
      telefono: '',
      telefono_alternativo: '',
      email: '',
      direccion: '',
      departamento: '',
      ciudad: '',
      proyecto_interes_id: '',
      vivienda_interes_id: '',
      notas_interes: '',
      notas: '',
    },
  })

  const formData = watch()

  // ── Estado de sección ───────────────────────────────
  const getEstadoPaso = useCallback((paso: number): SectionStatus => {
    if (pasosCompletados.has(paso)) return 'completed'
    if (paso === pasoActual) return 'active'
    return 'pending'
  }, [pasoActual, pasosCompletados])

  // ── Resúmenes ───────────────────────────────────────
  const summaryPaso1: SummaryItem[] = useMemo(() => [
    { label: 'Nombre', value: formData.nombres && formData.apellidos ? `${formData.nombres} ${formData.apellidos}` : undefined },
    { label: 'Documento', value: formData.numero_documento ? `${formData.tipo_documento} ${formData.numero_documento}` : undefined },
  ], [formData.nombres, formData.apellidos, formData.tipo_documento, formData.numero_documento])

  const summaryPaso2: SummaryItem[] = useMemo(() => {
    const contacto = formData.telefono || formData.email
    return [
      { label: 'Contacto', value: contacto || undefined },
      { label: 'Ubicación', value: formData.ciudad && formData.departamento ? `${formData.ciudad}, ${formData.departamento}` : undefined },
    ]
  }, [formData.telefono, formData.email, formData.ciudad, formData.departamento])

  const summaryPaso3: SummaryItem[] = useMemo(() => [
    { label: 'Interés', value: formData.proyecto_interes_id ? 'Proyecto seleccionado' : 'Sin interés definido' },
  ], [formData.proyecto_interes_id])

  const summaryPaso4: SummaryItem[] = useMemo(() => [
    { label: 'Notas', value: formData.notas ? 'Con observaciones' : 'Sin notas' },
  ], [formData.notas])

  // ── Progreso ────────────────────────────────────────
  const progress = useMemo(() => {
    return Math.round((pasosCompletados.size / PASOS_CLIENTE.length) * 100)
  }, [pasosCompletados.size])

  // ── Validación por paso ─────────────────────────────
  const validarPasoActual = useCallback(async (): Promise<boolean> => {
    setIsValidating(true)
    try {
      switch (pasoActual) {
        case 1: {
          // 1. Validar campos requeridos + regex (Zod)
          const syncValid = await trigger([...FIELDS_PASO_1])
          if (!syncValid) return false

          const erroresEncontrados: Array<{ campo: string; mensaje: string }> = []

          // 2. Validar formato + longitud + algoritmo del documento según tipo
          const tipoDoc = getValues('tipo_documento') as TipoDocumentoColombia
          const numDoc = getValues('numero_documento').trim()

          const resultado = validarDocumentoIdentidad(tipoDoc, numDoc)
          if (!resultado.valido) {
            erroresEncontrados.push({
              campo: 'numero_documento',
              mensaje: resultado.mensaje || 'Documento inválido',
            })
          }

          // 4. Validar fecha de nacimiento si se proporcionó
          const fechaNac = getValues('fecha_nacimiento')
          if (fechaNac) {
            const hoy = new Date()
            const fecha = new Date(fechaNac + 'T12:00:00')
            if (fecha > hoy) {
              erroresEncontrados.push({
                campo: 'fecha_nacimiento',
                mensaje: 'La fecha no puede ser futura',
              })
            }
            const edadMaxima = new Date()
            edadMaxima.setFullYear(edadMaxima.getFullYear() - 120)
            if (fecha < edadMaxima) {
              erroresEncontrados.push({
                campo: 'fecha_nacimiento',
                mensaje: 'Fecha fuera de rango válido',
              })
            }
          }

          // 5. Async: verificar duplicados
          if (erroresEncontrados.length === 0 && numDoc.length >= 5) {
            try {
              const existente = await clientesService.buscarPorDocumento(tipoDoc, numDoc)
              if (existente) {
                erroresEncontrados.push({
                  campo: 'numero_documento',
                  mensaje: `Ya existe: ${existente.nombres} ${existente.apellidos}`,
                })
              }
            } catch {
              // No bloquear si falla la red
            }
          }

          if (erroresEncontrados.length > 0) {
            erroresEncontrados.forEach((e) => {
              setError(e.campo as any, { type: 'manual', message: e.mensaje })
            })
            return false
          }
          return true
        }
        case 2: {
          // Validar departamento y ciudad (required via Zod)
          const syncValid = await trigger([...FIELDS_PASO_2])
          if (!syncValid) return false

          // Cross-field: al menos teléfono o email
          const tel = getValues('telefono')?.trim()
          const email = getValues('email')?.trim()

          if (!tel && !email) {
            setError('telefono', { type: 'manual', message: 'Requerido: teléfono o email' })
            setError('email', { type: 'manual', message: 'Requerido: teléfono o email' })
            return false
          }

          // Validar formato teléfono vía Zod (regex + min/max ya en schema)
          if (tel) {
            const telValid = await trigger('telefono')
            if (!telValid) return false
          }

          // Validar formato email vía Zod (.email() ya en schema)
          if (email) {
            const emailValid = await trigger('email')
            if (!emailValid) return false
          }

          // Validar teléfono alternativo si se proporcionó
          const telAlt = getValues('telefono_alternativo')?.trim()
          if (telAlt) {
            const telAltValid = await trigger('telefono_alternativo')
            if (!telAltValid) return false
          }

          // Validar dirección si se proporcionó
          const dir = getValues('direccion')?.trim()
          if (dir) {
            const dirValid = await trigger('direccion')
            if (!dirValid) return false
          }

          return true
        }
        case 3: {
          // Si tiene vivienda, requiere proyecto
          const vivienda = getValues('vivienda_interes_id')
          const proyecto = getValues('proyecto_interes_id')
          if (vivienda && !proyecto) {
            setError('proyecto_interes_id', { type: 'manual', message: 'Selecciona un proyecto primero' })
            return false
          }

          // Validar notas_interes (max 500 via Zod)
          const notasInteres = getValues('notas_interes')?.trim()
          if (notasInteres) {
            const notasValid = await trigger('notas_interes')
            if (!notasValid) return false
          }
          return true
        }
        case 4: {
          // Validar notas (max 500 via Zod)
          const notas = getValues('notas')?.trim()
          if (notas) {
            const notasValid = await trigger('notas')
            if (!notasValid) return false
          }
          return true
        }
        default:
          return true
      }
    } finally {
      setIsValidating(false)
    }
  }, [pasoActual, trigger, getValues, setError])

  // ── Navegación ──────────────────────────────────────
  const irSiguiente = useCallback(async () => {
    const valido = await validarPasoActual()
    if (!valido) return
    setPasosCompletados((prev) => new Set(prev).add(pasoActual))
    setPasoActual((prev) => Math.min(prev + 1, PASOS_CLIENTE.length))
  }, [pasoActual, validarPasoActual])

  const irAtras = useCallback(() => {
    setPasoActual((prev) => Math.max(prev - 1, 1))
  }, [])

  const irAPaso = useCallback((paso: number) => {
    if (pasosCompletados.has(paso)) {
      setPasosCompletados((prev) => {
        const next = new Set(prev)
        for (let i = paso; i <= PASOS_CLIENTE.length; i++) next.delete(i)
        return next
      })
      setPasoActual(paso)
    }
  }, [pasosCompletados])

  // ── Submit final ────────────────────────────────────
  const handleSubmitFinal = useCallback(async () => {
    const valido = await validarPasoActual()
    if (!valido) return

    setPasosCompletados((prev) => new Set(prev).add(pasoActual))
    setIsSubmitting(true)
    try {
      const values = getValues()

      // Construir DTO
      const dto: CrearClienteDTO = {
        nombres: values.nombres,
        apellidos: values.apellidos,
        tipo_documento: values.tipo_documento as TipoDocumento,
        numero_documento: values.numero_documento,
        fecha_nacimiento: values.fecha_nacimiento || undefined,
        estado_civil: (values.estado_civil || undefined) as EstadoCivil | undefined,
        telefono: values.telefono || undefined,
        telefono_alternativo: values.telefono_alternativo || undefined,
        email: values.email || undefined,
        direccion: values.direccion || undefined,
        departamento: values.departamento,
        ciudad: values.ciudad,
        notas: values.notas || undefined,
      }

      // Agregar interés si existe
      if (values.proyecto_interes_id) {
        dto.interes_inicial = {
          proyecto_id: values.proyecto_interes_id,
          vivienda_id: values.vivienda_interes_id || undefined,
          notas_interes: values.notas_interes || undefined,
        }
      }

      const sanitized = sanitizeCrearClienteDTO(dto)
      await crearMutation.mutateAsync(sanitized as any)
      // Toast ya lo maneja useCrearClienteMutation → no duplicar
      setShowSuccess(true)
      setTimeout(() => router.push('/clientes'), 1800)
    } catch (error) {
      // Toast de error ya lo maneja useCrearClienteMutation → no duplicar

      // Si es duplicado, volver al paso 1
      if (error instanceof Error && error.message.includes('documento')) {
        setError('numero_documento', { type: 'manual', message: error.message })
        setPasoActual(1)
        setPasosCompletados((prev) => {
          const next = new Set(prev)
          for (let i = 1; i <= PASOS_CLIENTE.length; i++) next.delete(i)
          return next
        })
      }
    } finally {
      setIsSubmitting(false)
    }
  }, [pasoActual, validarPasoActual, getValues, crearMutation, router, setError])

  return {
    // Pasos
    pasos: PASOS_CLIENTE,
    pasoActual,
    getEstadoPaso,
    progress,

    // Navegación
    irSiguiente,
    irAtras,
    irAPaso,

    // Resúmenes
    summaryPaso1,
    summaryPaso2,
    summaryPaso3,
    summaryPaso4,

    // Form
    register,
    errors,
    setValue,
    watch,
    formData,

    // Submit
    handleSubmit: handleSubmitFinal,
    isSubmitting,
    isValidating,
    showSuccess,
  }
}

/**
 * Hook para lógica de registro de interés de cliente
 * Ahora guarda en cliente_intereses en vez de negociaciones
 */

import { useCallback, useEffect, useMemo, useState } from 'react'

import { useQueryClient } from '@tanstack/react-query'
import { useForm } from 'react-hook-form'
import { toast } from 'sonner'

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

import { useDocumentoIdentidad } from '../documentos/hooks/useDocumentoIdentidad'
import { interesesService } from '../services/intereses.service'

import { interesesKeys } from './useInteresesQuery'

// Orden natural: manzana alphabético → número de vivienda numérico
function sortViviendasNatural<T extends { numero: string; manzanas?: { nombre: string } | null }>(vivs: T[]): T[] {
  return [...vivs].sort((a, b) => {
    const ma = a.manzanas?.nombre ?? ''
    const mb = b.manzanas?.nombre ?? ''
    const mCmp = ma.localeCompare(mb, 'es', { sensitivity: 'base' })
    if (mCmp !== 0) return mCmp
    return a.numero.localeCompare(b.numero, 'es', { numeric: true, sensitivity: 'base' })
  })
}

interface Proyecto {
  id: string
  nombre: string
}

interface Vivienda {
  id: string
  numero: string
  valor_total: number
  manzana_id: string
  manzanas?: {
    nombre: string
  }
}

interface FormData {
  proyectoId: string
  viviendaId: string
  notas?: string
  origen?: string
}

interface UseRegistrarInteresProps {
  clienteId: string
  onSuccess: () => void
  onClose: () => void
}

export function useRegistrarInteres({ clienteId, onSuccess, onClose }: UseRegistrarInteresProps) {
  const queryClient = useQueryClient()
  const [proyectos, setProyectos] = useState<Proyecto[]>([])
  const [viviendas, setViviendas] = useState<Vivienda[]>([])
  const [busquedaVivienda, setBusquedaVivienda] = useState('')
  const [cargandoProyectos, setCargandoProyectos] = useState(false)

  // ✅ Validación de cédula reactiva (React Query - caché compartido)
  const { tieneCedula } = useDocumentoIdentidad({ clienteId })
  const [cargandoViviendas, setCargandoViviendas] = useState(false)
  const [guardando, setGuardando] = useState(false)
  const [errorNegociacionExistente, setErrorNegociacionExistente] = useState(false)

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    reset,
    formState: { errors },
  } = useForm<FormData>({
    defaultValues: {
      proyectoId: '',
      viviendaId: '',
      notas: '',
      origen: 'Otro',
    },
  })

  const proyectoIdSeleccionado = watch('proyectoId')
  const viviendaIdSeleccionada = watch('viviendaId')

  // Cargar proyectos activos
  const cargarProyectos = useCallback(async () => {
    setCargandoProyectos(true)
    try {
      const { data, error } = await supabase
        .from('proyectos')
        .select('id, nombre, estado')
        .in('estado', ['en_planificacion', 'en_construccion'])
        .order('nombre')

      if (error) {
        logger.error('Error en query de proyectos:', error)
        throw error
      }

      setProyectos(data || [])
    } catch (error) {
      logger.error('❌ Error al cargar proyectos:', error)
      setProyectos([])
    } finally {
      setCargandoProyectos(false)
    }
  }, [])

  // Cargar viviendas del proyecto seleccionado
  const cargarViviendas = useCallback(async (proyectoId: string) => {
    if (!proyectoId) {
      setViviendas([])
      return
    }

    setCargandoViviendas(true)
    try {
      // Primero obtenemos las manzanas del proyecto
      const { data: manzanasData, error: manzanasError } = await supabase
        .from('manzanas')
        .select('id')
        .eq('proyecto_id', proyectoId)

      if (manzanasError) {
        logger.error('❌ Error al cargar manzanas:', manzanasError)
        throw manzanasError
      }

      const manzanaIds = manzanasData?.map((m) => m.id) || []

      if (manzanaIds.length === 0) {
        setViviendas([])
        setCargandoViviendas(false)
        return
      }


      // Ahora obtenemos las viviendas de esas manzanas
      const { data, error } = await supabase
        .from('viviendas')
        .select(`
          id,
          numero,
          valor_total,
          manzana_id,
          manzanas (
            nombre
          )
        `)
        .in('manzana_id', manzanaIds)
        .eq('estado', 'Disponible')
        .order('numero')

      if (error) {
        logger.error('❌ Error en query de viviendas:', error)
        throw error
      }


      // Mapear la respuesta al tipo correcto
      const viviendasMapeadas = (data || []).map((v: any) => ({
        id: v.id,
        numero: v.numero,
        valor_total: v.valor_total,
        manzana_id: v.manzana_id,
        manzanas: v.manzanas,
      }))

      setViviendas(sortViviendasNatural(viviendasMapeadas))
    } catch (error) {
      logger.error('Error al cargar viviendas:', error)
      setViviendas([])
    } finally {
      setCargandoViviendas(false)
    }
  }, [])

  // Cargar proyectos al montar
  useEffect(() => {
    cargarProyectos()
  }, [cargarProyectos])

  // Cargar viviendas cuando cambia el proyecto
  useEffect(() => {
    if (proyectoIdSeleccionado) {
      cargarViviendas(proyectoIdSeleccionado)
      setValue('viviendaId', '') // Reset vivienda seleccionada
      setBusquedaVivienda('')
    } else {
      setViviendas([])
      setBusquedaVivienda('')
    }
  }, [proyectoIdSeleccionado, cargarViviendas, setValue])

  // Filtrado client-side por manzana o número de vivienda
  const viviendasFiltradas = useMemo(() => {
    if (!busquedaVivienda.trim()) return viviendas
    const q = busquedaVivienda.toLowerCase()
    return viviendas.filter((v) => {
      const manzana = (v.manzanas?.nombre ?? '').toLowerCase()
      const numero = v.numero.toLowerCase()
      return (
        manzana.includes(q) ||
        numero.includes(q) ||
        `${manzana}${numero}`.includes(q.replace(/\s+/g, '')) ||
        `manzana ${manzana} casa ${numero}`.includes(q)
      )
    })
  }, [viviendas, busquedaVivienda])

  // Seleccionar vivienda desde el combobox
  const seleccionarVivienda = useCallback(
    (id: string) => {
      setValue('viviendaId', id, { shouldValidate: !!id, shouldDirty: true })
    },
    [setValue]
  )

  const handleRegistrar = async (data: FormData) => {
    setGuardando(true)
    setErrorNegociacionExistente(false)

    try {
      // ✅ Validar que el cliente tenga documento de identidad cargado
      if (!tieneCedula) {
        toast.error('El cliente debe tener su documento de identidad cargado antes de registrar un interés')
        setGuardando(false)
        return
      }

      // Verificar si ya existe un interés activo para esta vivienda
      const interesesExistentes = await interesesService.obtenerInteresesCliente(clienteId, true)
      const existe = interesesExistentes.some(i => i.vivienda_id === data.viviendaId)

      if (existe) {
        setErrorNegociacionExistente(true)
        setGuardando(false)
        return
      }

      // Registrar el interés
      await interesesService.crearInteres({
        cliente_id: clienteId,
        proyecto_id: data.proyectoId,
        vivienda_id: data.viviendaId,
        notas: data.notas,
        origen: (data.origen as any) || 'Otro',
      })

      // Refrescar la lista de intereses en React Query sin recargar página
      await queryClient.invalidateQueries({ queryKey: interesesKeys.byCliente(clienteId) })
      reset()
      onSuccess()
    } catch (error) {
      logger.error('Error al registrar interés:', error)
      toast.info('Error al registrar el interés. Por favor intenta nuevamente.')
    } finally {
      setGuardando(false)
    }
  }

  const handleCancelar = () => {
    reset()
    setBusquedaVivienda('')
    setErrorNegociacionExistente(false)
    onClose()
  }

  return {
    // Estados
    proyectos,
    viviendas,
    viviendasFiltradas,
    busquedaVivienda,
    setBusquedaVivienda,
    cargandoProyectos,
    cargandoViviendas,
    guardando,
    errorNegociacionExistente,

    // Valores del form
    proyectoIdSeleccionado,
    viviendaIdSeleccionada,

    // React Hook Form
    register,
    handleSubmit,
    errors,

    // Handlers
    handleRegistrar,
    handleCancelar,
    seleccionarVivienda,
  }
}

'use client'

import { useMemo } from 'react'

import { KeyRound } from 'lucide-react'

import {
    AccordionWizardHero,
    AccordionWizardLayout,
    AccordionWizardNavigation,
    AccordionWizardSection,
    AccordionWizardSuccess,
} from '@/shared/components/accordion-wizard'

import { SeccionFuentesPago, SeccionRevision, SeccionViviendaValores } from './components'
import { PASOS_ASIGNACION, useAsignarViviendaV2 } from './hooks'

interface AsignarViviendaV2PageProps {
  clienteId: string
  clienteNombre?: string
  clienteSlug?: string
}

export function AsignarViviendaV2Page({
  clienteId,
  clienteNombre = 'Cliente',
  clienteSlug,
}: AsignarViviendaV2PageProps) {
  const {
    // Wizard
    pasoActual,
    getEstadoPaso,
    progress,
    summaryPaso1,
    summaryPaso2,
    showSuccess,
    isValidating,
    pasos,
    irSiguiente,
    irAtras,
    irAPaso,
    // RHF
    register,
    errors,
    setValue,
    watch,
    // Proyecto/Vivienda
    proyectos,
    viviendas,
    proyectoSeleccionado,
    viviendaId,
    viviendaSeleccionada,
    cargandoProyectos,
    cargandoViviendas,
    setProyectoSeleccionado,
    setViviendaId,
    // Valores
    valorBase,
    gastosNotariales,
    recargoEsquinera,
    descuentoAplicado,
    valorTotal,
    // Fuentes
    cargandoTipos,
    tiposConCampos,
    fuentes,
    totalFuentes,
    diferencia,
    sumaCierra,
    erroresFuentes,
    mostrarErroresFuentes,
    handleFuenteEnabledChange,
    handleFuenteConfigChange,
    // Guardado
    handleSubmitFinal,
    creando,
    errorApi,
    clearErrorApi,
  } = useAsignarViviendaV2({ clienteId, clienteSlug })

  const proyectoNombre = useMemo(
    () => proyectos.find(p => p.id === proyectoSeleccionado)?.nombre ?? '',
    [proyectos, proyectoSeleccionado],
  )

  const aplicarDescuento = watch('aplicar_descuento') as boolean
  const tipoDescuento = (watch('tipo_descuento') as string) ?? ''
  const notas = (watch('notas') as string) ?? ''
  const valorEscrituraPublica = (watch('valor_escritura_publica') as number) ?? 0

  return (
    <AccordionWizardLayout
      moduleName="clientes"
      breadcrumbs={[
        { label: 'Clientes', href: '/clientes' },
        { label: clienteNombre, href: `/clientes/${clienteSlug ?? clienteId}` },
        { label: 'Asignar Vivienda' },
      ]}
      isSubmitting={creando}
      submitLoadingLabel="Asignando Vivienda..."
    >
      {/* Hero Header */}
      <AccordionWizardHero
        icon={KeyRound}
        title="Asignar Vivienda"
        subtitle={`Configura la vivienda y financiamiento para ${clienteNombre}. Completa cada sección en orden.`}
        moduleName="clientes"
        estimatedTime="~5 minutos"
        totalSteps={PASOS_ASIGNACION.length}
      />

      {/* ── Paso 1: Vivienda & Valores ────────────── */}
      <AccordionWizardSection
        status={getEstadoPaso(1)}
        stepNumber={1}
        title={pasos[0].title}
        description={pasos[0].description}
        icon={pasos[0].icon}
        fieldCount={{ required: 2, optional: 3 }}
        currentStep={pasoActual}
        totalSteps={PASOS_ASIGNACION.length}
        moduleName="clientes"
        summaryItems={summaryPaso1}
        onEdit={() => irAPaso(1)}
      >
        <SeccionViviendaValores
          clienteNombre={clienteNombre}
          register={register}
          errors={errors}
          setValue={setValue}
          watch={watch}
          proyectos={proyectos}
          viviendas={viviendas}
          proyectoSeleccionado={proyectoSeleccionado}
          viviendaId={viviendaId}
          viviendaSeleccionada={viviendaSeleccionada}
          cargandoProyectos={cargandoProyectos}
          cargandoViviendas={cargandoViviendas}
          setProyectoSeleccionado={setProyectoSeleccionado}
          setViviendaId={setViviendaId}
          valorBase={valorBase}
          gastosNotariales={gastosNotariales}
          recargoEsquinera={recargoEsquinera}
          descuentoAplicado={descuentoAplicado}
          valorTotal={valorTotal}
          onClearErrorApi={clearErrorApi}
        />
        <AccordionWizardNavigation
          currentStep={1}
          totalSteps={PASOS_ASIGNACION.length}
          isFirst
          isLast={false}
          isValidating={pasoActual === 1 && isValidating}
          moduleName="clientes"
          onBack={irAtras}
          onNext={irSiguiente}
        />
      </AccordionWizardSection>

      {/* ── Paso 2: Fuentes de Pago ───────────────── */}
      <AccordionWizardSection
        status={getEstadoPaso(2)}
        stepNumber={2}
        title={pasos[1].title}
        description={pasos[1].description}
        icon={pasos[1].icon}
        fieldCount={{ required: 1, optional: 0 }}
        currentStep={pasoActual}
        totalSteps={PASOS_ASIGNACION.length}
        moduleName="clientes"
        summaryItems={summaryPaso2}
        onEdit={() => irAPaso(2)}
      >
        <SeccionFuentesPago
          valorTotal={valorTotal}
          cargandoTipos={cargandoTipos}
          tiposConCampos={tiposConCampos}
          fuentes={fuentes}
          totalFuentes={totalFuentes}
          diferencia={diferencia}
          sumaCierra={sumaCierra}
          erroresFuentes={erroresFuentes}
          mostrarErroresFuentes={mostrarErroresFuentes}
          handleFuenteEnabledChange={handleFuenteEnabledChange}
          handleFuenteConfigChange={handleFuenteConfigChange}
        />
        <AccordionWizardNavigation
          currentStep={2}
          totalSteps={PASOS_ASIGNACION.length}
          isFirst={false}
          isLast={false}
          isValidating={pasoActual === 2 && isValidating}
          moduleName="clientes"
          onBack={irAtras}
          onNext={irSiguiente}
        />
      </AccordionWizardSection>

      {/* ── Paso 3: Revisión & Confirmación ───────── */}
      <AccordionWizardSection
        status={getEstadoPaso(3)}
        stepNumber={3}
        title={pasos[2].title}
        description={pasos[2].description}
        icon={pasos[2].icon}
        currentStep={pasoActual}
        totalSteps={PASOS_ASIGNACION.length}
        moduleName="clientes"
        onEdit={() => irAPaso(3)}
      >
        <SeccionRevision
          clienteNombre={clienteNombre}
          proyectoNombre={proyectoNombre}
          viviendaSeleccionada={viviendaSeleccionada}
          valorBase={valorBase}
          gastosNotariales={gastosNotariales}
          recargoEsquinera={recargoEsquinera}
          descuentoAplicado={descuentoAplicado}
          valorTotal={valorTotal}
          valorEscrituraPublica={valorEscrituraPublica}
          aplicarDescuento={aplicarDescuento}
          tipoDescuento={tipoDescuento}
          notas={notas}
          fuentes={fuentes}
          tiposConCampos={tiposConCampos}
          errorApi={errorApi}
          onEditarSeccion1={() => irAPaso(1)}
          onEditarSeccion2={() => irAPaso(2)}
        />
        <AccordionWizardNavigation
          currentStep={3}
          totalSteps={PASOS_ASIGNACION.length}
          isFirst={false}
          isLast
          isSubmitting={creando}
          isValidating={isValidating}
          moduleName="clientes"
          submitLabel="Asignar Vivienda"
          onBack={irAtras}
          onNext={irSiguiente}
          onSubmit={handleSubmitFinal}
        />
      </AccordionWizardSection>

      {/* Success celebration */}
      <AccordionWizardSuccess
        isVisible={showSuccess}
        moduleName="clientes"
        title="¡Vivienda asignada!"
        subtitle="Redirigiendo al perfil del cliente..."
      />
    </AccordionWizardLayout>
  )
}

