/**
 * Hook principal para la p�gina de Crear Negociaci�n
 * Orquesta el stepper, form data y navegaci�n entre pasos
 *
 * ?? Reutiliza hooks del modal refactorizado
 */

import { useCallback, useMemo, useState } from 'react'

import { useRouter } from 'next/navigation'

import { logger } from '@/lib/utils/logger'
import {
    useFuentesPago,
    useProyectosViviendas,
} from '@/modules/clientes/components/asignar-vivienda/hooks'
import type { StepNumber } from '@/modules/clientes/components/asignar-vivienda/types'
import { useCrearNegociacion } from '@/modules/clientes/hooks'
import { validarSumaTotal } from '@/modules/clientes/utils/validar-edicion-fuentes'
import { useTiposFuentesConCampos } from '@/modules/configuracion/hooks/useTiposFuentesConCampos'
import { useModal } from '@/shared/components/modals'

interface UseCrearNegociacionPageProps {
  clienteId: string
  viviendaId?: string
  valorVivienda?: number
}

export function useCrearNegociacionPage({
  clienteId,
  viviendaId: viviendaIdProp,
  valorVivienda,
}: UseCrearNegociacionPageProps) {
  const router = useRouter()
  const { confirm } = useModal()

  // ============================================
  // HOOKS EXTERNOS
  // ============================================

  const {
    crearNegociacion,
    creando: creandoHook,
    error: errorHook,
    limpiar: limpiarHook,
  } = useCrearNegociacion()

  // ============================================
  // ESTADO LOCAL
  // ============================================

  const [currentStep, setCurrentStep] = useState<StepNumber>(1)
  const [completedSteps, setCompletedSteps] = useState<number[]>([])
  const [descuentoAplicado, setDescuentoAplicado] = useState(0)
  const [notas, setNotas] = useState('')
  const [creando, setCreando] = useState(false)
  const [error, setError] = useState<string | null>(null)

  // ============================================
  // HOOKS PERSONALIZADOS (REUTILIZADOS)
  // ============================================

  const proyectosViviendas = useProyectosViviendas({
    viviendaIdInicial: viviendaIdProp,
    valorViviendaInicial: valorVivienda,
  })

  // Vivienda seleccionada (objeto completo, para acceder a gastos/recargo)
  const viviendaSeleccionada = useMemo(() => {
    return proyectosViviendas.viviendas.find((v) => v.id === proyectosViviendas.viviendaId) ?? null
  }, [proyectosViviendas.viviendas, proyectosViviendas.viviendaId])

  // ⚠️ CRÍTICO: El target de fuentes DEBE ser la obligación real del cliente,
  // que es valorNegociado (= valor_base) − descuento + gastos_notariales + recargo_esquinera.
  // Esto coincide exactamente con lo que el trigger calcular_valor_total_pagar producirá
  // en BD → el plan de pagos quedará SIEMPRE cuadrado al 100% al crear la negociación.
  const valorTotal = useMemo(() => {
    const gastos  = viviendaSeleccionada?.gastos_notariales ?? 0
    const recargo = (viviendaSeleccionada?.es_esquinera && viviendaSeleccionada?.recargo_esquinera)
      ? viviendaSeleccionada.recargo_esquinera
      : 0
    return Math.max(0, proyectosViviendas.valorNegociado - descuentoAplicado + gastos + recargo)
  }, [proyectosViviendas.valorNegociado, descuentoAplicado, viviendaSeleccionada])

  const { data: tiposConCampos = [], isLoading: cargandoTipos } = useTiposFuentesConCampos()

  const fuentesPago = useFuentesPago({ valorTotal, tiposConCampos, cargandoTipos })

  // ============================================
  // VALIDACIONES POR PASO
  // ============================================

  const paso1Valido = useMemo(() => {
    return (
      proyectosViviendas.viviendaId !== '' &&
      proyectosViviendas.valorNegociado > 0 &&
      descuentoAplicado >= 0 &&
      descuentoAplicado < proyectosViviendas.valorNegociado &&
      valorTotal > 0
    )
  }, [proyectosViviendas.viviendaId, proyectosViviendas.valorNegociado, descuentoAplicado, valorTotal])

  const { paso2Valido } = fuentesPago

  // ============================================
  // C�LCULO DE PROGRESO (Mejora #3)
  // ============================================

  const progressStep1 = useMemo(() => {
    const campos = [
      proyectosViviendas.proyectoSeleccionado,
      proyectosViviendas.viviendaId,
      proyectosViviendas.valorNegociado > 0,
      valorTotal > 0,
    ]
    const completos = campos.filter(Boolean).length
    return Math.round((completos / campos.length) * 100)
  }, [
    proyectosViviendas.proyectoSeleccionado,
    proyectosViviendas.viviendaId,
    proyectosViviendas.valorNegociado,
    valorTotal,
  ])

  const progressStep2 = useMemo(() => {
    if (valorTotal === 0) return 0

    const fuentesHabilitadas = fuentesPago.fuentes.filter((f) => f.enabled).length
    const sumaCierra = fuentesPago.sumaCierra

    if (fuentesHabilitadas === 0) return 0
    if (sumaCierra) return 100

    // Calcular % basado en cu�nto falta/sobra
    const porcentajeCubierto = (fuentesPago.totalFuentes / valorTotal) * 100
    return Math.min(porcentajeCubierto, 99) // M�ximo 99% si no cierra exacto
  }, [fuentesPago.fuentes, fuentesPago.sumaCierra, fuentesPago.totalFuentes, valorTotal])

  // ============================================
  // VALIDACI�N DE CAMPOS (Mejora #1)
  // ============================================

  const validacionCampos = useMemo(() => {
    return {
      proyecto: {
        valido: !!proyectosViviendas.proyectoSeleccionado,
        mensaje: proyectosViviendas.proyectoSeleccionado ? 'Proyecto seleccionado' : 'Selecciona un proyecto',
      },
      vivienda: {
        valido: !!proyectosViviendas.viviendaId,
        mensaje: proyectosViviendas.viviendaId ? 'Vivienda seleccionada' : 'Selecciona una vivienda',
      },
      valorVivienda: {
        valido: proyectosViviendas.valorNegociado > 0,
        mensaje: proyectosViviendas.valorNegociado > 0
          ? 'Valor cargado'
          : 'Selecciona una vivienda con valor',
      },
      descuento: {
        valido: descuentoAplicado >= 0 && descuentoAplicado < proyectosViviendas.valorNegociado,
        mensaje: descuentoAplicado >= proyectosViviendas.valorNegociado
          ? 'El descuento no puede ser mayor al valor'
          : 'Descuento v�lido',
      },
    }
  }, [
    proyectosViviendas.proyectoSeleccionado,
    proyectosViviendas.viviendaId,
    proyectosViviendas.valorNegociado,
    descuentoAplicado,
  ])

  // ============================================
  // EFECTOS
  // ============================================

  // Proyectos se cargan automáticamente dentro de useProyectosViviendas

  // ============================================
  // NAVEGACI�N
  // ============================================

  const handleNext = useCallback(() => {
    // PASO 1: Validar informaci�n b�sica
    if (currentStep === 1) {
      const errores: string[] = []

      if (!proyectosViviendas.proyectoSeleccionado) {
        errores.push('Debe seleccionar un proyecto')
      }
      if (!proyectosViviendas.viviendaId) {
        errores.push('Debe seleccionar una vivienda')
      }
      if (proyectosViviendas.valorNegociado <= 0) {
        errores.push('El valor de la vivienda debe ser mayor a 0')
      }
      if (descuentoAplicado < 0) {
        errores.push('El descuento no puede ser negativo')
      }
      if (descuentoAplicado >= proyectosViviendas.valorNegociado) {
        errores.push('El descuento no puede ser mayor o igual al valor de la vivienda')
      }
      if (valorTotal <= 0) {
        errores.push('El valor total debe ser mayor a 0')
      }

      if (errores.length > 0) {
        setError(errores.join('\n'))
        return
      }

      // Limpiar errores y avanzar
      setError(null)
      setCompletedSteps((prev) => [...new Set([...prev, 1])])
      setCurrentStep(2)
      window.scrollTo({ top: 0, behavior: 'smooth' })
    }
    // PASO 2: Validar fuentes de pago
    else if (currentStep === 2) {
      const errores: string[] = []
      const fuentesHabilitadas = fuentesPago.fuentes.filter((f) => f.enabled)

      // Validar que haya al menos una fuente
      if (fuentesHabilitadas.length === 0) {
        errores.push('Debe configurar al menos una fuente de pago')
      }

      // Validar cada fuente habilitada
      fuentesHabilitadas.forEach((fuente) => {
        if (!fuente.config) {
          errores.push(`${fuente.tipo}: No est� configurada`)
          return
        }

        const config = fuente.config
        const nombreFuente = fuente.tipo

        // Validar monto
        if (!config.monto_aprobado || config.monto_aprobado <= 0) {
          errores.push(`${nombreFuente}: El monto debe ser mayor a 0`)
        }

        // Validar campos espec�ficos por tipo (excepto Cuota Inicial)
        if (fuente.tipo !== 'Cuota Inicial') {
          if (!config.entidad || config.entidad.trim() === '') {
            errores.push(`${nombreFuente}: Debe especificar la entidad (banco o caja)`)
          }
          if (!config.numero_referencia || config.numero_referencia.trim() === '') {
            errores.push(`${nombreFuente}: Debe especificar el n�mero de referencia o radicado`)
          }
        }
      })

      // Validar que la suma cierre exacto
      if (!fuentesPago.sumaCierra) {
        const diferencia = Math.abs(valorTotal - fuentesPago.totalFuentes)
        if (fuentesPago.totalFuentes < valorTotal) {
          errores.push(
            `Faltan $${diferencia.toLocaleString('es-CO')} para completar el valor total`
          )
        } else {
          errores.push(
            `Hay un excedente de $${diferencia.toLocaleString('es-CO')}. Ajusta los montos`
          )
        }
      }

      if (errores.length > 0) {
        setError(errores.join('\n'))
        return
      }

      // Limpiar errores y avanzar
      setError(null)
      setCompletedSteps((prev) => [...new Set([...prev, 1, 2])])
      setCurrentStep(3)
      window.scrollTo({ top: 0, behavior: 'smooth' })
    }
  }, [currentStep, proyectosViviendas, descuentoAplicado, valorTotal, fuentesPago])

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => (prev - 1) as StepNumber)
      window.scrollTo({ top: 0, behavior: 'smooth' })
    }
  }, [currentStep])

  const goToStep = useCallback((step: number) => {
    if (step >= 1 && step <= 3) {
      setCurrentStep(step as StepNumber)
      window.scrollTo({ top: 0, behavior: 'smooth' })
    }
  }, [])

  const handleCancel = useCallback(async () => {
    const confirmed = await confirm({
      title: '�Cancelar creaci�n?',
      message: 'Se perder� toda la informaci�n ingresada.',
      confirmText: 'Cancelar Negociaci�n',
      cancelText: 'Continuar Editando',
      variant: 'warning'
    })

    if (confirmed) {
      router.push(`/clientes/${clienteId}` as any)
    }
  }, [clienteId, router, confirm])

  // ============================================
  // SUBMIT
  // ============================================

  const handleSubmit = useCallback(async () => {
    setCreando(true)
    setError(null)

    try {
      // Obtener fuentes para crear
      const fuentesParaCrear = fuentesPago.obtenerFuentesParaCrear()

      // Validar suma total
      const validacion = validarSumaTotal(fuentesParaCrear, valorTotal)

      if (!validacion.valido) {
        setError(validacion.errores.join('\n'))
        setCreando(false)
        return
      }

      // Crear negociaci�n con fuentes de pago
      const negociacion = await crearNegociacion({
        cliente_id: clienteId,
        vivienda_id: proyectosViviendas.viviendaId,
        valor_negociado: proyectosViviendas.valorNegociado,
        descuento_aplicado: descuentoAplicado,
        notas,
        fuentes_pago: fuentesParaCrear,
      })

      if (!negociacion) {
        setError(errorHook || 'Error al crear negociaci�n')
        setCreando(false)
        return
      }


      // Limpiar y navegar al detalle del cliente
      limpiarHook()
      router.push(`/clientes/${clienteId}?tab=vivienda-asignada&highlight=${negociacion.id}` as any)
    } catch (err) {
      logger.error('? Error creando negociaci�n:', err)
      setError(err instanceof Error ? err.message : 'Error al crear negociaci�n')
    } finally {
      setCreando(false)
    }
  }, [
    clienteId,
    proyectosViviendas.viviendaId,
    proyectosViviendas.valorNegociado,
    descuentoAplicado,
    notas,
    valorTotal,
    fuentesPago,
    crearNegociacion,
    errorHook,
    limpiarHook,
    router,
  ])

  // ============================================
  // RETURN
  // ============================================

  return {
    // Stepper
    currentStep,
    completedSteps,

    // Proyectos y Viviendas
    ...proyectosViviendas,

    // Descuento y Notas
    descuentoAplicado,
    setDescuentoAplicado,
    notas,
    setNotas,

    // Valor Total
    valorTotal,

    // Fuentes de Pago
    ...fuentesPago,

    // Validaciones (Mejora #1)
    paso1Valido,
    paso2Valido,
    validacionCampos,

    // Progreso (Mejora #3)
    progressStep1,
    progressStep2,

    // Estado de creaci�n
    creando: creando || creandoHook,
    error: error || errorHook,

    // Navegaci�n
    handleNext,
    handleBack,
    handleCancel,
    goToStep,

    // Acciones
    handleSubmit,
  }
}

/**
 * P�gina: Crear Negociaci�n - REDISE�ADA ?
 *
 * Vista completa para crear negociaci�n con 3 pasos:
 * 1. Informaci�n B�sica (Cliente, Vivienda, Valores)
 * 2. Fuentes de Pago (Configuraci�n completa del financiamiento)
 * 3. Revisi�n y Confirmaci�n
 *
 * ? MEJORAS IMPLEMENTADAS:
 * - #1: Validaci�n en tiempo real con feedback visual
 * - #2: Sidebar sticky con resumen financiero siempre visible
 * - #3: Progreso visual por paso con barras de completitud
 * - Dise�o minimalista y moderno
 * - Grid layout con sidebar
 *
 * ?? ARQUITECTURA LIMPIA:
 * - L�gica: hooks/useCrearNegociacionPage.ts
 * - UI Componentes: components/
 * - Estilos: styles.ts
 * - Reutiliza: Hooks y componentes del modal refactorizado
 */

'use client'

import { AnimatePresence, motion } from 'framer-motion'
import { AlertCircle } from 'lucide-react'

import { StepperNegociacion } from '@/modules/clientes/components'
import {
    Paso1InfoBasica,
    Paso2FuentesPago,
    Paso3Revision,
} from '@/modules/clientes/components/asignar-vivienda/components'

import {
    BreadcrumbsNegociacion,
    FooterNegociacion,
    HeaderNegociacion,
    SidebarResumen,
} from './components'
import { useCrearNegociacionPage } from './hooks'
import { pageStyles } from './styles'

interface CrearNegociacionPageProps {
  clienteId: string
  clienteSlug?: string // Slug para breadcrumbs (opcional para backward compatibility)
  clienteNombre?: string
  viviendaId?: string
  valorVivienda?: number
}

export function CrearNegociacionPage({
  clienteId,
  clienteSlug,
  clienteNombre,
  viviendaId,
  valorVivienda,
}: CrearNegociacionPageProps) {
  const page = useCrearNegociacionPage({
    clienteId,
    viviendaId,
    valorVivienda,
  })

  // Calcular vivienda seleccionada para sidebar
  const viviendaSeleccionada = page.viviendas.find((v) => v.id === page.viviendaId)
  const viviendaNumero = viviendaSeleccionada
    ? `${viviendaSeleccionada.manzana_nombre ? `Manzana ${viviendaSeleccionada.manzana_nombre} - ` : ''}Casa ${viviendaSeleccionada.numero}`
    : undefined

  return (
    <div className={pageStyles.container}>
      <div className={pageStyles.inner}>
        {/* Breadcrumbs */}
        <BreadcrumbsNegociacion
          clienteId={clienteSlug || clienteId}
          clienteNombre={clienteNombre}
        />

        {/* Header */}
        <HeaderNegociacion
          clienteId={clienteId}
          clienteNombre={clienteNombre}
        />

        {/* Stepper */}
        <div className={pageStyles.stepper.container}>
          <div className={pageStyles.stepper.wrapper}>
            <StepperNegociacion
              currentStep={page.currentStep}
              completedSteps={page.completedSteps}
            />
          </div>
        </div>

        {/* Layout Principal: Grid con Sidebar */}
        <div className={pageStyles.mainLayout.container}>
          {/* Contenido Principal */}
          <div className={pageStyles.mainLayout.content}>
            {/* Error Global */}
            {page.error && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className={pageStyles.alert.error}
              >
                <AlertCircle className={pageStyles.alert.icon} />
                <div className={pageStyles.alert.content}>
                  <h4 className={`${pageStyles.alert.title} text-red-900 dark:text-red-100`}>
                    Error
                  </h4>
                  <p className={`${pageStyles.alert.message} text-red-700 dark:text-red-300`}>
                    {page.error}
                  </p>
                </div>
              </motion.div>
            )}

            {/* Card de Contenido */}
            <div className={pageStyles.card.base}>
              <AnimatePresence mode="wait">
                {page.currentStep === 1 && (
                  <Paso1InfoBasica
                    key="paso1"
                    clienteNombre={clienteNombre}
                    proyectos={page.proyectos}
                    viviendas={page.viviendas}
                    cargandoProyectos={page.cargandoProyectos}
                    cargandoViviendas={page.cargandoViviendas}
                    proyectoSeleccionado={page.proyectoSeleccionado}
                    viviendaId={page.viviendaId}
                    valorNegociado={page.valorNegociado}
                    descuentoAplicado={page.descuentoAplicado}
                    valorTotal={page.valorTotal}
                    notas={page.notas}
                    viviendaIdProp={viviendaId}
                    validacionCampos={page.validacionCampos}
                    onProyectoChange={page.setProyectoSeleccionado}
                    onViviendaChange={page.setViviendaId}
                    onValorNegociadoChange={page.setValorNegociado}
                    onDescuentoChange={page.setDescuentoAplicado}
                    onNotasChange={page.setNotas}
                  />
                )}

                {page.currentStep === 2 && (
                  <Paso2FuentesPago
                    key="paso2"
                    fuentes={page.fuentes}
                    valorTotal={page.valorTotal}
                    totalFuentes={page.totalFuentes}
                    diferencia={page.diferencia}
                    sumaCierra={page.sumaCierra}
                    clienteId={clienteId}
                    clienteNombre={clienteNombre ?? ''}
                    onFuenteEnabledChange={page.handleFuenteEnabledChange}
                    onFuenteConfigChange={page.handleFuenteConfigChange}
                  />
                )}

                {page.currentStep === 3 && (
                  <Paso3Revision
                    key="paso3"
                    clienteNombre={clienteNombre}
                    proyectoNombre={
                      page.proyectos.find((p) => p.id === page.proyectoSeleccionado)?.nombre || ''
                    }
                    vivienda={viviendaSeleccionada}
                    valorNegociado={page.valorNegociado}
                    descuentoAplicado={page.descuentoAplicado}
                    valorTotal={page.valorTotal}
                    notas={page.notas}
                    fuentes={page.fuentesActivas
                      .filter((f) => f.config !== null)
                      .map((f) => ({ tipo: f.tipo, config: f.config! }))}
                    goToStep={page.goToStep}
                  />
                )}
              </AnimatePresence>

              {/* Footer de Navegaci�n */}
              <FooterNegociacion
                currentStep={page.currentStep}
                paso1Valido={page.paso1Valido}
                paso2Valido={page.paso2Valido}
                creando={page.creando}
                onBack={page.handleBack}
                onNext={page.handleNext}
                onCancel={page.handleCancel}
                onSubmit={page.handleSubmit}
              />
            </div>
          </div>

          {/* Sidebar Sticky con Resumen (Mejora #2) */}
          <div className={pageStyles.mainLayout.sidebar}>
            <SidebarResumen
              currentStep={page.currentStep}
              viviendaNumero={viviendaNumero}
              valorVivienda={page.valorNegociado}
              descuentoAplicado={page.descuentoAplicado}
              valorTotal={page.valorTotal}
              fuentesConfiguradas={page.fuentesActivas
                .filter((f) => f.enabled && f.config !== null)
                .map((f) => ({ tipo: f.tipo, config: f.config! }))}
              totalFuentes={page.totalFuentes}
              sumaCierra={page.sumaCierra}
              progressStep1={page.progressStep1}
              progressStep2={page.progressStep2}
            />
          </div>
        </div>
      </div>
    </div>
  )
}

/**
 * Servicio de Clientes
