 */

import { supabase } from '@/lib/supabase/client'
import { formatDateForDB, getTodayDateString } from '@/lib/utils/date.utils'
import { logger } from '@/lib/utils/logger'
import { auditService } from '@/services/audit.service'

import type {
    ActualizarClienteDTO,
    Cliente,
    ClienteResumen,
    CrearClienteDTO,
    FiltrosClientes,
} from '../types'
import { sanitizeActualizarClienteDTO, sanitizeCrearClienteDTO } from '../utils/sanitize-cliente.utils'

class ClientesService {
  /**
   * Obtener todos los clientes con estadísticas, negociaciones e intereses
   * ✅ Incluye datos de viviendas, proyectos y manzanas para la tabla
   */
  async obtenerClientes(filtros?: FiltrosClientes): Promise<ClienteResumen[]> {
    // 1. Obtener datos básicos de clientes desde la vista
    let query = supabase.from('vista_clientes_resumen').select(`
      id,
      nombres,
      apellidos,
      nombre_completo,
      tipo_documento,
      numero_documento,
      telefono,
      email,
      estado,
      estado_civil,
      fecha_nacimiento,
      tiene_documento_identidad,
      fecha_creacion,
      total_negociaciones,
      negociaciones_activas,
      negociaciones_completadas
    `)

    // Aplicar filtros
    if (filtros?.estado && filtros.estado.length > 0) {
      query = query.in('estado', filtros.estado)
    }

    if (filtros?.busqueda) {
      query = query.or(
        `nombre_completo.ilike.%${filtros.busqueda}%,numero_documento.ilike.%${filtros.busqueda}%,telefono.ilike.%${filtros.busqueda}%,email.ilike.%${filtros.busqueda}%`
      )
    }

    if (filtros?.fecha_desde) {
      query = query.gte('fecha_creacion', filtros.fecha_desde)
    }

    if (filtros?.fecha_hasta) {
      query = query.lte('fecha_creacion', filtros.fecha_hasta)
    }

    // ⚡ EJECUTAR TODAS LAS CONSULTAS EN PARALELO (Promise.all)
    const [
      { data, error },
      { data: negociaciones },
      { data: intereses }
    ] = await Promise.all([
      // 1. Datos básicos de clientes
      query.order('fecha_creacion', { ascending: false }),

      // 2. Negociaciones activas (en paralelo)
      supabase
        .from('negociaciones')
        .select(`
          id,
          cliente_id,
          estado,
          valor_total,
          valor_total_pagar,
          total_abonado,
          saldo_pendiente,
          viviendas!negociaciones_vivienda_id_fkey (
            id,
            numero,
            manzanas!viviendas_manzana_id_fkey (
              nombre,
              proyectos!manzanas_proyecto_id_fkey (
                nombre,
                ubicacion
              )
            )
          )
        `)
        .eq('estado', 'Activa'),

      // 3. Intereses activos (en paralelo)
      supabase
        .from('cliente_intereses')
        .select(`
          id,
          cliente_id,
          estado,
          vivienda_id,
          proyectos!cliente_intereses_proyecto_id_fkey (
            nombre
          ),
          viviendas!cliente_intereses_vivienda_id_fkey (
            numero,
            manzanas!viviendas_manzana_id_fkey (
              nombre
            )
          )
        `)
        .eq('estado', 'Activo')
    ])

    if (error) throw error

    // ⚡ CREAR MAPAS DE BÚSQUEDA RÁPIDA (O(1) lookup)
    const negociacionesMap = new Map(
      negociaciones?.map((neg) => [
        neg.cliente_id,
        {
          nombre_proyecto: neg.viviendas?.manzanas?.proyectos?.nombre,
          ubicacion_proyecto: neg.viviendas?.manzanas?.proyectos?.ubicacion,
          nombre_manzana: neg.viviendas?.manzanas?.nombre,
          numero_vivienda: neg.viviendas?.numero,
          valor_total: neg.valor_total,
          valor_total_pagar: neg.valor_total_pagar,
          total_abonado: neg.total_abonado,
          saldo_pendiente: neg.saldo_pendiente,
        }
      ]) || []
    )

    const interesesMap = new Map(
      intereses
        ?.filter((int) => !negociacionesMap.has(int.cliente_id)) // Solo si no tiene negociación
        .map((int) => [
          int.cliente_id,
          {
            nombre_proyecto: int.proyectos?.nombre,
            nombre_manzana: int.viviendas?.manzanas?.nombre,
            numero_vivienda: int.viviendas?.numero,
          }
        ]) || []
    )

    // ⚡ TRANSFORMAR Y ENRIQUECER DATOS (O(n) single pass)
    return (data || []).map((item) => {
      const negociacion = negociacionesMap.get(item.id!)
      const interes = interesesMap.get(item.id!)

      return {
        id: item.id || '',
        tipo_documento: (item.tipo_documento as any) || 'CC',
        numero_documento: item.numero_documento || '',
        nombres: item.nombres || '',
        apellidos: item.apellidos || '',
        nombre_completo: item.nombre_completo || '',
        telefono: item.telefono || '',
        email: item.email || '',
        estado_civil: item.estado_civil || undefined,
        fecha_nacimiento: item.fecha_nacimiento || undefined,
        estado: (item.estado as any) || 'Interesado',
        fecha_creacion: item.fecha_creacion || formatDateForDB(getTodayDateString()),
        fecha_actualizacion: item.fecha_creacion || formatDateForDB(getTodayDateString()),
        tiene_documento_identidad: item.tiene_documento_identidad || false,
        estadisticas: {
          total_negociaciones: item.total_negociaciones || 0,
          negociaciones_activas: item.negociaciones_activas || 0,
          negociaciones_completadas: item.negociaciones_completadas || 0,
          ultima_negociacion: undefined,
        },
        // â­ Datos de vivienda para clientes Activos (pre-calculados)
        vivienda: negociacion || undefined,
        // â­ Datos de interés para clientes Interesados (pre-calculados)
        interes: interes || undefined,
      } as ClienteResumen
    })
  }

  /**
   * Obtener un cliente por ID con sus negociaciones, intereses y estadísticas
   */
  async obtenerCliente(id: string): Promise<Cliente | null> {
    // 1. Obtener datos del cliente con negociaciones
    const { data: clienteData, error: clienteError } = await supabase
      .from('clientes')
      .select(
        `
        *,
        negociaciones!negociaciones_cliente_id_fkey (
          id,
          estado,
          valor_total,
          valor_total_pagar,
          total_abonado,
          saldo_pendiente,
          porcentaje_pagado,
          fecha_negociacion,
          fecha_completada,
          viviendas!negociaciones_vivienda_id_fkey (
            numero,
            tipo_vivienda,
            manzanas!viviendas_manzana_id_fkey (
              nombre,
              proyectos!manzanas_proyecto_id_fkey (
                nombre,
                ubicacion
              )
            )
          )
        )
      `
      )
      .eq('id', id)
      .single()

    if (clienteError) throw clienteError
    if (!clienteData) return null

    // 2. Obtener intereses del cliente usando la vista intereses_completos
    const { data: interesesData, error: interesesError } = await supabase
      .from('intereses_completos')
      .select(`
        id, cliente_id, proyecto_id, vivienda_id, estado, origen,
        notas, fecha_interes, proyecto_nombre, vivienda_numero,
        vivienda_valor, manzana_nombre, proyecto_estado, vivienda_estado,
        motivo_descarte, fecha_actualizacion
      `)
      .eq('cliente_id', id)
      .order('fecha_interes', { ascending: false })

    if (interesesError) {
      logger.error('Error cargando intereses:', interesesError)
      // No lanzamos error, continuamos sin intereses
    }

    // 3. Calcular estadísticas comerciales
    const negociaciones = clienteData.negociaciones || []
    const estadisticas = {
      total_negociaciones: negociaciones.length,
      negociaciones_activas: negociaciones.filter((n) =>
        ['Activa', 'En Proceso'].includes(n.estado)
      ).length,
      negociaciones_completadas: negociaciones.filter((n) =>
        n.estado === 'Completada'
      ).length,
      ultima_negociacion: negociaciones.length > 0
        ? negociaciones[0].fecha_negociacion
        : null,
    }

    // 4. Mapear intereses al formato ClienteInteres
    const intereses = (interesesData || []).map((interes) => ({
      id: interes.id,
      cliente_id: interes.cliente_id,
      proyecto_id: interes.proyecto_id,
      vivienda_id: interes.vivienda_id,
      proyecto_nombre: interes.proyecto_nombre,
      proyecto_estado: interes.proyecto_estado,
      vivienda_numero: interes.vivienda_numero,
      vivienda_estado: interes.vivienda_estado,
      vivienda_valor: interes.vivienda_valor,
      manzana_nombre: interes.manzana_nombre,
      notas: interes.notas,
      estado: interes.estado,
      motivo_descarte: interes.motivo_descarte,
      fecha_interes: interes.fecha_interes,
      fecha_actualizacion: interes.fecha_actualizacion,
    }))

    // 5. Retornar cliente completo con intereses y estadísticas
    return {
      ...clienteData,
      intereses,
      estadisticas,
    } as unknown as Cliente
  }

  /**
   * Buscar cliente por número de documento
   */
  async buscarPorDocumento(
    tipo_documento: string,
    numero_documento: string
  ): Promise<Cliente | null> {

    const { data, error } = await supabase
      .from('clientes')
      .select('id, nombres, apellidos, tipo_documento, numero_documento, estado')
      .eq('tipo_documento', tipo_documento)
      .eq('numero_documento', numero_documento)
      .maybeSingle()

    if (error) {
      // Si es error de "no encontrado", está bien (no hay duplicado)
      // Si es otro error, lanzarlo
      logger.error('Error buscando cliente por documento:', error)
      throw error
    }

    if (data) {
    } else {
    }

    return data as Cliente | null
  }

  /**
   * Crear un nuevo cliente
   */
  async crearCliente(datos: CrearClienteDTO): Promise<Cliente> {
    // Verificar que no exista cliente con el mismo documento
    const clienteExistente = await this.buscarPorDocumento(
      datos.tipo_documento,
      datos.numero_documento
    )

    if (clienteExistente) {
      const error = `Ya existe un cliente registrado con ${datos.tipo_documento} ${datos.numero_documento}.\n\nCliente existente: ${clienteExistente.nombres} ${clienteExistente.apellidos}`
      logger.error('❌ Cliente duplicado:', error)
      throw new Error(error)
    }


    const {
      data: { user },
    } = await supabase.auth.getUser()

    // 🧹 Sanitizar y limpiar datos (convierte strings vacíos a null, valida enums)
    const datosSanitizados = sanitizeCrearClienteDTO(datos)

    // Excluir interes_inicial (no es un campo de la tabla clientes)
    const { interes_inicial, ...datosCliente } = datosSanitizados

    const datosLimpios = {
      ...datosCliente,
      usuario_creacion: user?.id,
    }

    const { data, error } = await supabase
      .from('clientes')
      .insert(datosLimpios)
      .select()
      .single()

    if (error) {
      logger.error('❌ Error insertando en DB:', error)
      throw error
    }


    // 🔍 Auditar creación de cliente
    try {
      await auditService.auditarCreacionCliente(data)
    } catch (auditError) {
      logger.error('⚠️ Error auditando creación de cliente:', auditError)
      // No bloqueamos la operación si falla la auditoría
    }

    return data as Cliente
  }

  /**
   * Actualizar un cliente
   */
  async actualizarCliente(
    id: string,
    datos: ActualizarClienteDTO
  ): Promise<Cliente> {
    // 1. Obtener datos anteriores para auditoría
    const { data: datosAnteriores } = await supabase
      .from('clientes')
      .select(`
        id, nombres, apellidos, tipo_documento, numero_documento,
        telefono, telefono_alternativo, email, direccion, ciudad,
        departamento, fecha_nacimiento, estado_civil, notas, estado
      `)
      .eq('id', id)
      .single()
    // 2. Actualizar cliente
    // 🧹 Sanitizar datos (strings vacíos â†’ null, validar enums)
    const datosLimpios = sanitizeActualizarClienteDTO(datos)

    const { data, error } = await supabase
      .from('clientes')
      .update(datosLimpios)
      .eq('id', id)
      .select()
      .single()

    if (error) throw error

    // 3. 🔍 Auditar actualización
    if (datosAnteriores) {
      try {
        await auditService.auditarActualizacion(
          'clientes',
          id,
          datosAnteriores,
          data,
          {
            campos_modificados: Object.keys(datosLimpios),
            cliente_nombre: `${data.nombres} ${data.apellidos}`
          },
          'clientes'
        )
      } catch (auditError) {
        logger.error('⚠️ Error auditando actualización:', auditError)
      }
    }

    return data as Cliente
  }

  /**
   * Eliminar un cliente
   *
   * Restricciones:
   * - NO se puede eliminar si tiene negociaciones (activas o históricas)
   * - NO se puede eliminar si tiene viviendas asignadas
   * - Solo se permite eliminar clientes "Interesado" sin historial
   *
   * Para clientes con datos, usar estado "Inactivo" en lugar de eliminar
   */
  async eliminarCliente(id: string): Promise<void> {
    // 1. Verificar que NO tenga negociaciones (ninguna, ni activas ni históricas)
    const { data: negociaciones } = await supabase
      .from('negociaciones')
      .select('id, estado')
      .eq('cliente_id', id)
      .limit(1)

    if (negociaciones && negociaciones.length > 0) {
      throw new Error(
        'No se puede eliminar un cliente con historial de negociaciones. ' +
        'Use el estado "Inactivo" en su lugar para mantener la trazabilidad.'
      )
    }

    // 2. Verificar que NO tenga viviendas asignadas
    const { data: viviendas } = await supabase
      .from('viviendas')
      .select('id, numero')
      .eq('cliente_id', id)
      .limit(1)

    if (viviendas && viviendas.length > 0) {
      throw new Error(
        'No se puede eliminar un cliente con viviendas asignadas. ' +
        'Primero desasigne las viviendas o use el estado "Inactivo".'
      )
    }

    // 3. Solo permitir eliminar clientes en estado "Interesado" sin datos críticos
    const { data: cliente } = await supabase
      .from('clientes')
      .select('estado')
      .eq('id', id)
      .single()

    if (cliente?.estado !== 'Interesado') {
      throw new Error(
        'Solo se pueden eliminar clientes en estado "Interesado". ' +
        'Para clientes con historial, use el estado "Inactivo".'
      )
    }

    // 4. Obtener datos del cliente para auditoría
    const { data: clienteData } = await supabase
      .from('clientes')
      .select('id, nombres, apellidos, tipo_documento, numero_documento, estado')
      .eq('id', id)
      .single()

    // 5. Si pasa todas las validaciones, eliminar
    const { error } = await supabase.from('clientes').delete().eq('id', id)

    if (error) throw error

    // 6. 🔍 Auditar eliminación
    if (clienteData) {
      try {
        await auditService.auditarEliminacion(
          'clientes',
          id,
          clienteData,
          {
            motivo: 'Cliente sin historial de negociaciones',
            cliente_nombre: `${clienteData.nombres} ${clienteData.apellidos}`,
            cliente_documento: `${clienteData.tipo_documento} ${clienteData.numero_documento}`
          },
          'clientes'
        )
      } catch (auditError) {
        logger.error('⚠️ Error auditando eliminación:', auditError)
      }
    }
  }

  /**
   * Verificar si un cliente tiene una renuncia pendiente de devolución
   */
  async verificarRenunciaPendiente(
    clienteId: string
  ): Promise<{ pendiente: boolean; renunciaId?: string; consecutivo?: string }> {
    const { data, error } = await supabase
      .from('renuncias')
      .select('id, consecutivo')
      .eq('cliente_id', clienteId)
      .eq('estado', 'Pendiente Devolución')
      .limit(1)
      .maybeSingle()

    if (error) {
      logger.error('Error verificando renuncia pendiente:', error)
      return { pendiente: false }
    }

    return data
      ? { pendiente: true, renunciaId: data.id, consecutivo: data.consecutivo }
      : { pendiente: false }
  }

  /**
   * Cambiar estado de un cliente
   */
  async cambiarEstado(
    id: string,
    nuevoEstado: 'Interesado' | 'Activo' | 'Inactivo'
  ): Promise<Cliente> {
    return this.actualizarCliente(id, { estado: nuevoEstado })
  }

  /**
   * Obtener estadísticas generales de clientes
   */
  async obtenerEstadisticas() {
    const { data, error } = await supabase.from('clientes').select('estado')

    if (error) throw error

    const stats = {
      total: data?.length || 0,
      interesados: data?.filter((c) => c.estado === 'Interesado').length || 0,
      activos: data?.filter((c) => c.estado === 'Activo').length || 0,
      inactivos: data?.filter((c) => c.estado === 'Inactivo').length || 0,
      renunciaron: data?.filter((c) => c.estado === 'Renunció').length || 0,
    }

    return stats
  }
}

export const clientesService = new ClientesService()

﻿import { supabase } from '@/lib/supabase/client'
import type { TipoFuentePago } from '@/modules/clientes/types'
export type { TipoFuentePago }

// ============================================================
// DTOs
// ============================================================

export interface CrearFuentePagoDTO {
  negociacion_id: string
  tipo: TipoFuentePago
  monto_aprobado: number
  /** Para créditos: capital sin intereses. Se guarda en capital_para_cierre */
  capital_para_cierre?: number
  entidad?: string             // nombre legible (nunca UUID)
  entidad_financiera_id?: string // opcional: ID resuelto por el caller
  numero_referencia?: string
  permite_multiples_abonos?: boolean
}

export interface ActualizarFuentePagoDTO {
  monto_aprobado?: number
  capital_para_cierre?: number | null
  monto_recibido?: number
  entidad?: string
  entidad_financiera_id?: string
  numero_referencia?: string
  carta_asignacion_url?: string
  estado?: 'Activa' | 'Inactiva'
  fecha_completado?: string
}

export interface FuentePago {
  id: string
  negociacion_id: string
  tipo: TipoFuentePago
  monto_aprobado: number
  /** Para créditos: el capital sin intereses. Para otras fuentes: igual a monto_aprobado */
  capital_para_cierre: number | null
  mora_total_recibida: number
  monto_recibido: number
  saldo_pendiente: number
  porcentaje_completado: number
  entidad?: string
  entidad_financiera_id?: string
  numero_referencia?: string
  permite_multiples_abonos: boolean
  carta_asignacion_url?: string
  estado: 'Activa' | 'Inactiva'
  estado_fuente?: string
  fecha_completado?: string
  fecha_creacion: string
  fecha_actualizacion: string
}

// ============================================================
// COLUMNS SELECCIONADAS (tabla base, sin vista)
// ============================================================

const BASE_COLUMNS = `
  id, negociacion_id, tipo, entidad, entidad_financiera_id,
  monto_aprobado, monto_recibido, saldo_pendiente, porcentaje_completado,
  numero_referencia, permite_multiples_abonos, carta_asignacion_url,
  estado, estado_fuente, fecha_completado, fecha_creacion, fecha_actualizacion
`.trim()

// ============================================================
// SERVICE
// ============================================================

class FuentesPagoService {

  /** Crear fuente de pago */
  async crearFuentePago(datos: CrearFuentePagoDTO): Promise<FuentePago> {
    // Resolver tipo_fuente_id (FK NOT NULL)
    const { data: tipoFuente, error: tipoError } = await supabase
      .from('tipos_fuentes_pago')
      .select('id, permite_multiples_abonos')
      .eq('nombre', datos.tipo)
      .single()

    if (tipoError || !tipoFuente) {
      throw new Error(`Tipo de fuente de pago no encontrado: ${datos.tipo}`)
    }

    // Resolver entidad_financiera_id si no viene del caller pero sí el nombre
    let entidadFinancieraId = datos.entidad_financiera_id ?? null
    if (!entidadFinancieraId && datos.entidad) {
      const { data: ef } = await supabase
        .from('entidades_financieras')
        .select('id')
        .eq('nombre', datos.entidad)
        .maybeSingle()
      entidadFinancieraId = ef?.id ?? null
    }

    const { data, error } = await supabase
      .from('fuentes_pago')
      .insert({
        negociacion_id: datos.negociacion_id,
        tipo: datos.tipo,
        tipo_fuente_id: tipoFuente.id,
        monto_aprobado: datos.monto_aprobado,
        monto_recibido: 0,
        entidad: datos.entidad ?? null,
        entidad_financiera_id: entidadFinancieraId,
        numero_referencia: datos.numero_referencia ?? null,
        permite_multiples_abonos: datos.permite_multiples_abonos ?? tipoFuente.permite_multiples_abonos ?? false,
        capital_para_cierre: datos.capital_para_cierre ?? null,
        estado: 'Activa',
        estado_fuente: 'activa',
      })
      .select(BASE_COLUMNS)
      .single()

    if (error) throw error
    return data as unknown as FuentePago
  }

  /**
   * Obtener fuentes activas de una negociación.
   * Usa la vista fuentes_pago_con_entidad para que entidad siempre sea
   * el nombre legible (via JOIN con entidades_financieras), nunca un UUID.
   */
  async obtenerFuentesPagoNegociacion(negociacionId: string): Promise<FuentePago[]> {
    const { data, error } = await supabase
      .from('fuentes_pago_con_entidad')
      .select(`
        id, negociacion_id, tipo, entidad_display, entidad_financiera_id,
        monto_aprobado, capital_para_cierre, monto_recibido, saldo_pendiente, porcentaje_completado,
        numero_referencia, permite_multiples_abonos, carta_asignacion_url,
        estado, estado_fuente, fecha_completado, fecha_creacion, fecha_actualizacion
      `)
      .eq('negociacion_id', negociacionId)
      .eq('estado_fuente', 'activa')
      .order('fecha_creacion', { ascending: true })

    if (error) throw error

    return (data ?? []).map((row: any) => ({
      ...row,
      entidad: row.entidad_display ?? undefined,
    })) as FuentePago[]
  }

  /** Obtener fuente de pago por ID */
  async obtenerFuentePago(id: string): Promise<FuentePago | null> {
    const { data, error } = await supabase
      .from('fuentes_pago_con_entidad')
      .select(`
        id, negociacion_id, tipo, entidad_display, entidad_financiera_id,
        monto_aprobado, capital_para_cierre, monto_recibido, saldo_pendiente, porcentaje_completado,
        numero_referencia, permite_multiples_abonos, carta_asignacion_url,
        estado, estado_fuente, fecha_completado, fecha_creacion, fecha_actualizacion
      `)
      .eq('id', id)
      .maybeSingle()

    if (error) throw error
    if (!data) return null

    return { ...(data as any), entidad: (data as any).entidad_display ?? undefined } as FuentePago
  }

  /** Actualizar fuente de pago */
  async actualizarFuentePago(id: string, datos: ActualizarFuentePagoDTO): Promise<FuentePago> {
    const { data, error } = await supabase
      .from('fuentes_pago')
      .update(datos)
      .eq('id', id)
      .select(BASE_COLUMNS)
      .single()

    if (error) throw error
    return data as unknown as FuentePago
  }

  /** Registrar monto recibido (abono) */
  async registrarMontoRecibido(id: string, monto: number): Promise<FuentePago> {
    const fuente = await this.obtenerFuentePago(id)
    if (!fuente) throw new Error('Fuente de pago no encontrada')

    const nuevoTotal = fuente.monto_recibido + monto

    if (nuevoTotal > fuente.monto_aprobado) {
      throw new Error('El monto recibido excede el monto aprobado')
    }

    if (!fuente.permite_multiples_abonos && fuente.monto_recibido > 0) {
      throw new Error('Esta fuente de pago no permite múltiples abonos')
    }

    return this.actualizarFuentePago(id, { monto_recibido: nuevoTotal })
  }

  /**
   * Inactivar fuente de pago (soft delete).
   * No se puede inactivar si ya recibió dinero.
   */
  async inactivarFuentePago(id: string, razon: string, reemplazadaPor?: string): Promise<void> {
    const fuente = await this.obtenerFuentePago(id)
    if (!fuente) throw new Error('Fuente de pago no encontrada')

    if (fuente.monto_recibido > 0) {
      throw new Error(
        `No se puede eliminar una fuente que ya recibió $${fuente.monto_recibido.toLocaleString('es-CO')}. ` +
        `Debe permanecer activa para conservar el historial de abonos.`
      )
    }

    const { error } = await supabase
      .from('fuentes_pago')
      .update({
        estado: 'Inactiva',
        estado_fuente: reemplazadaPor ? 'reemplazada' : 'inactiva',
        razon_inactivacion: razon,
        fecha_inactivacion: new Date().toISOString(),
        reemplazada_por: reemplazadaPor ?? null,
      })
      .eq('id', id)

    if (error) throw error
  }

  /** Eliminar permanentemente. Solo si no tiene dinero recibido. */
  async eliminarFuentePago(id: string): Promise<void> {
    const fuente = await this.obtenerFuentePago(id)
    if (!fuente) throw new Error('Fuente de pago no encontrada')

    if (fuente.monto_recibido > 0) {
      throw new Error(
        `PROHIBIDO: No se puede eliminar una fuente con $${fuente.monto_recibido.toLocaleString('es-CO')} recibidos.`
      )
    }

    const { error } = await supabase.from('fuentes_pago').delete().eq('id', id)

    if (error) {
      throw new Error(
        error.message.includes('PROHIBIDO')
          ? 'No se puede eliminar esta fuente porque ya ha recibido dinero'
          : error.message
      )
    }
  }

  /** Calcular totales de todas las fuentes activas de una negociación */
  async calcularTotales(negociacionId: string): Promise<{
    total_aprobado: number
    total_recibido: number
    saldo_pendiente: number
    porcentaje_completado: number
  }> {
    const fuentes = await this.obtenerFuentesPagoNegociacion(negociacionId)

    const total_aprobado = fuentes.reduce((s, f) => s + f.monto_aprobado, 0)
    const total_recibido = fuentes.reduce((s, f) => s + f.monto_recibido, 0)

    return {
      total_aprobado,
      total_recibido,
      saldo_pendiente: total_aprobado - total_recibido,
      porcentaje_completado: total_aprobado > 0 ? (total_recibido / total_aprobado) * 100 : 0,
    }
  }

  /**
   * Verificar si el cierre financiero está completo.
   *
   * Usa COALESCE(capital_para_cierre, monto_aprobado) para que los créditos
   * contribuyan con su capital (no con capital+intereses) al total de financiación.
   * Evita que los intereses inflen el total por encima del valor de la vivienda.
   */
  async verificarCierreFinancieroCompleto(negociacionId: string, valorTotal: number): Promise<boolean> {
    const fuentes = await this.obtenerFuentesPagoNegociacion(negociacionId)
    const total_para_cierre = fuentes.reduce(
      (sum, f) => sum + (f.capital_para_cierre ?? f.monto_aprobado),
      0
    )
    return total_para_cierre >= valorTotal
  }
}

