/**
 * Servicio de Intereses de Clientes
 * Gestión de intereses en proyectos/viviendas
 *
 * NOTA: Este servicio usa tablas/vistas que NO existen aún en database.types.ts
 * Ejecutar supabase/cliente-intereses-schema.sql PRIMERO, luego regenerar tipos.
 * Los @ts-ignore son temporales hasta que se ejecute el SQL.
 */

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

import type {
    ActualizarInteresDTO,
    ClienteInteres,
    CrearInteresDTO,
    EstadoInteres,
} from '../types'

class InteresesService {
  /**
   * Obtener intereses de un cliente (con datos relacionados)
   */
  async obtenerInteresesCliente(
    clienteId: string,
    soloActivos = false
  ): Promise<ClienteInteres[]> {
    try {
      // @ts-ignore - Tabla cliente_intereses no existe aún en database.types (ejecutar SQL primero)
      let query = supabase
        .from('intereses_completos')
        .select(`
          id, cliente_id, proyecto_id, vivienda_id, estado, origen,
          notas, motivo_descarte, fecha_interes, fecha_actualizacion,
          usuario_creacion, proyecto_nombre, proyecto_estado,
          vivienda_numero, vivienda_valor, vivienda_estado, manzana_nombre
        `)
        .eq('cliente_id', clienteId)

      if (soloActivos) {
        query = query.eq('estado', 'Activo')
      }

      const { data, error } = await query.order('fecha_interes', {
        ascending: false,
      })

      if (error) throw error

      // Mapear vista a interface
      return (
        data?.map((row) => ({
          id: row.id,
          cliente_id: row.cliente_id,
          proyecto_id: row.proyecto_id,
          vivienda_id: row.vivienda_id,
          notas: row.notas,
          estado: row.estado as EstadoInteres,
          motivo_descarte: row.motivo_descarte,
          fecha_interes: row.fecha_interes,
          fecha_actualizacion: row.fecha_actualizacion,
          usuario_creacion: row.usuario_creacion,
          proyecto_nombre: row.proyecto_nombre,
          proyecto_estado: row.proyecto_estado,
          vivienda_numero: row.vivienda_numero,
          vivienda_valor: row.vivienda_valor,
          vivienda_estado: row.vivienda_estado,
          manzana_nombre: row.manzana_nombre,
        })) || []
      ) as unknown as ClienteInteres[]
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error obteniendo intereses del cliente:', mensaje, error)
      throw error
    }
  }

  /**
   * Obtener intereses de un proyecto
   */
  async obtenerInteresesProyecto(
    proyectoId: string,
    soloActivos = false
  ): Promise<ClienteInteres[]> {
    try {
      let query = supabase
        .from('intereses_completos')
        .select(`
          id, cliente_id, proyecto_id, vivienda_id, estado, origen,
          notas, motivo_descarte, fecha_interes, fecha_actualizacion,
          usuario_creacion, proyecto_nombre, proyecto_estado,
          vivienda_numero, vivienda_valor, vivienda_estado, manzana_nombre
        `)
        .eq('proyecto_id', proyectoId)

      if (soloActivos) {
        query = query.eq('estado', 'Activo')
      }

      const { data, error } = await query.order('fecha_interes', {
        ascending: false,
      })

      if (error) throw error

      return (
        data?.map((row) => ({
          id: row.id,
          cliente_id: row.cliente_id,
          proyecto_id: row.proyecto_id,
          vivienda_id: row.vivienda_id,
          notas: row.notas,
          estado: row.estado as EstadoInteres,
          motivo_descarte: row.motivo_descarte,
          fecha_interes: row.fecha_interes,
          fecha_actualizacion: row.fecha_actualizacion,
          usuario_creacion: row.usuario_creacion,
          proyecto_nombre: row.proyecto_nombre,
          proyecto_estado: row.proyecto_estado,
          vivienda_numero: row.vivienda_numero,
          vivienda_valor: row.vivienda_valor,
          vivienda_estado: row.vivienda_estado,
          manzana_nombre: row.manzana_nombre,
        })) || []
      ) as unknown as ClienteInteres[]
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error obteniendo intereses del proyecto:', mensaje, error)
      throw error
    }
  }

  /**
   * Crear un nuevo interés
   */
  async crearInteres(datos: CrearInteresDTO): Promise<ClienteInteres> {
    try {
      const { data, error } = await supabase
        .from('cliente_intereses')
        .insert({
          cliente_id: datos.cliente_id,
          proyecto_id: datos.proyecto_id,
          vivienda_id: datos.vivienda_id,
          notas: datos.notas,
          estado: 'Activo',
        })
        .select()
        .single()

      if (error) throw error
      return data as ClienteInteres
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error creando interés:', mensaje, error)
      throw error
    }
  }

  /**
   * Actualizar estado de un interés
   */
  async actualizarInteres(
    id: string,
    datos: ActualizarInteresDTO
  ): Promise<ClienteInteres> {
    try {
      const { data, error } = await supabase
        .from('cliente_intereses')
        .update(datos)
        .eq('id', id)
        .select()
        .single()

      if (error) throw error
      return data as ClienteInteres
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error actualizando interés:', mensaje, error)
      throw error
    }
  }

  /**
   * Descartar un interés (cambiar estado a Descartado)
   */
  async descartarInteres(
    id: string,
    motivo?: string
  ): Promise<ClienteInteres> {
    try {
      return await this.actualizarInteres(id, {
        estado: 'Descartado',
        motivo_descarte: motivo,
      })
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error descartando interés:', mensaje, error)
      throw error
    }
  }

  /**
   * Marcar interés como convertido (cuando se concreta la venta)
   * Esta función se llama automáticamente cuando se crea una negociación
   */
  async marcarInteresConvertido(
    clienteId: string,
    viviendaId: string
  ): Promise<void> {
    try {
      const { error } = await supabase.rpc('marcar_interes_convertido', {
        p_cliente_id: clienteId,
        p_vivienda_id: viviendaId,
      })

      if (error) throw error
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error marcando interés como convertido:', mensaje, error)
      throw error
    }
  }

  /**
   * Eliminar un interés (hard delete)
   */
  async eliminarInteres(id: string): Promise<void> {
    try {
      const { error } = await supabase
        .from('cliente_intereses')
        .delete()
        .eq('id', id)

      if (error) throw error
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error eliminando interés:', mensaje, error)
      throw error
    }
  }

  /**
   * Verificar si ya existe un interés activo para esa combinación
   */
  async existeInteresActivo(
    clienteId: string,
    proyectoId: string,
    viviendaId?: string
  ): Promise<boolean> {
    try {
      let query = supabase
        .from('cliente_intereses')
        .select('id', { count: 'exact', head: true })
        .eq('cliente_id', clienteId)
        .eq('proyecto_id', proyectoId)
        .eq('estado', 'Activo')

      if (viviendaId) {
        query = query.eq('vivienda_id', viviendaId)
      }

      const { count, error } = await query

      if (error) throw error
      return (count ?? 0) > 0
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error verificando interés activo:', mensaje, error)
      return false
    }
  }

  /**
   * Obtener resumen de intereses por estado
   */
  async obtenerResumenIntereses(clienteId: string) {
    try {
      const { data, error } = await supabase
        .from('cliente_intereses')
        .select('estado')
        .eq('cliente_id', clienteId)

      if (error) throw error

      const resumen = {
        activos: 0,
        descartados: 0,
        convertidos: 0,
      }

      data?.forEach((row) => {
        if (row.estado === 'Activo') resumen.activos++
        if (row.estado === 'Descartado') resumen.descartados++
        if (row.estado === 'Convertido') resumen.convertidos++
      })

      return resumen
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('[CLIENTES] Error obteniendo resumen de intereses:', mensaje, error)
      return { activos: 0, descartados: 0, convertidos: 0 }
    }
  }
}

export const interesesService = new InteresesService()

/**
 * Servicio para gestión de versiones de negociaciones
 * Maneja historial de cambios, descuentos y modificaciones
 */

import { supabase } from '@/lib/supabase/client'
import type { Database } from '@/lib/supabase/database.types'
import { logger } from '@/lib/utils/logger'

type NegociacionVersion = Database['public']['Tables']['negociaciones_versiones']['Row']
type DescuentoNegociacion = Database['public']['Tables']['descuentos_negociacion']['Row']

export interface FuentePagoSnapshot {
  id?: string
  tipo: string
  monto_aprobado: number
  entidad?: string | null
  estado?: string
}

export interface CrearVersionParams {
  negociacionId: string
  valorVivienda: number
  descuentoAplicado: number
  valorTotal: number
  fuentesPago: FuentePagoSnapshot[]
  motivoCambio: string
  tipoCambio: 'creacion_inicial' | 'modificacion_fuentes' | 'aplicacion_descuento' | 'ajuste_avaluo' | 'cambio_entidad' | 'otro'
}

export interface VersionConDescuentos extends NegociacionVersion {
  descuentos?: DescuentoNegociacion[]
  usuario?: {
    nombres: string
    apellidos: string
    email: string
  }
}

export class NegociacionesVersionesService {
  /**
   * Obtener historial completo de versiones de una negociación
   */
  static async obtenerHistorial(negociacionId: string): Promise<VersionConDescuentos[]> {
    const { data, error } = await supabase
      .from('negociaciones_versiones')
      .select(`
        *,
        descuentos:descuentos_negociacion(*)
      `)
      .eq('negociacion_id', negociacionId)
      .order('version', { ascending: false })
      .limit(50) // ✅ Limitar a últimas 50 versiones (performance)

    if (error) throw error
    return data as VersionConDescuentos[]
  }

  /**
   * Obtener versión activa actual
   */
  static async obtenerVersionActual(negociacionId: string): Promise<VersionConDescuentos | null> {
    const { data, error } = await supabase
      .from('negociaciones_versiones')
      .select(`
        *,
        descuentos:descuentos_negociacion(*)
      `)
      .eq('negociacion_id', negociacionId)
      .eq('es_version_activa', true)
      .maybeSingle()

    if (error) throw error
    return data as VersionConDescuentos | null
  }

  /**
   * Crear nueva versión (Admin only)
   * Usa la función de PostgreSQL que valida permisos
   */
  static async crearNuevaVersion(params: CrearVersionParams): Promise<string> {
    const { data, error } = await supabase.rpc('crear_nueva_version_negociacion', {
      p_negociacion_id: params.negociacionId,
      p_valor_vivienda: params.valorVivienda,
      p_descuento_aplicado: params.descuentoAplicado,
      p_valor_total: params.valorTotal,
      p_fuentes_pago: params.fuentesPago as any,
      p_motivo_cambio: params.motivoCambio,
      p_tipo_cambio: params.tipoCambio,
    })

    if (error) {
      logger.error('Error al crear versión:', error)
      throw new Error(error.message || 'Error al crear nueva versión')
    }

    return data // UUID de la nueva versión
  }

  /**
   * Comparar dos versiones
   */
  static async compararVersiones(
    negociacionId: string,
    versionA: number,
    versionB: number
  ): Promise<{
    versionA: VersionConDescuentos
    versionB: VersionConDescuentos
    diferencias: {
      valorVivienda?: { anterior: number; nuevo: number }
      descuentoAplicado?: { anterior: number; nuevo: number }
      valorTotal?: { anterior: number; nuevo: number }
      fuentesPago?: { cambios: string[] }
    }
  }> {
    // Obtener ambas versiones
    const { data: versiones, error } = await supabase
      .from('negociaciones_versiones')
      .select(`
        *,
        descuentos:descuentos_negociacion(*)
      `)
      .eq('negociacion_id', negociacionId)
      .in('version', [versionA, versionB])

    if (error) throw error
    if (!versiones || versiones.length !== 2) {
      throw new Error('No se encontraron las versiones especificadas')
    }

    const vA = versiones.find((v) => v.version === versionA) as VersionConDescuentos
    const vB = versiones.find((v) => v.version === versionB) as VersionConDescuentos

    // Calcular diferencias
    const diferencias: any = {}

    if (vA.valor_vivienda !== vB.valor_vivienda) {
      diferencias.valorVivienda = {
        anterior: vA.valor_vivienda,
        nuevo: vB.valor_vivienda,
      }
    }

    if (vA.descuento_aplicado !== vB.descuento_aplicado) {
      diferencias.descuentoAplicado = {
        anterior: vA.descuento_aplicado,
        nuevo: vB.descuento_aplicado,
      }
    }

    if (vA.valor_total !== vB.valor_total) {
      diferencias.valorTotal = {
        anterior: vA.valor_total,
        nuevo: vB.valor_total,
      }
    }

    // Comparar fuentes de pago (simplificado)
    const fuentesA = (vA.fuentes_pago as unknown as FuentePagoSnapshot[]) || []
    const fuentesB = (vB.fuentes_pago as unknown as FuentePagoSnapshot[]) || []

    if (JSON.stringify(fuentesA) !== JSON.stringify(fuentesB)) {
      diferencias.fuentesPago = {
        cambios: [
          `Versión ${versionA}: ${fuentesA.length} fuente(s)`,
          `Versión ${versionB}: ${fuentesB.length} fuente(s)`,
        ],
      }
    }

    return {
      versionA: vA,
      versionB: vB,
      diferencias,
    }
  }

  /**
   * Registrar descuento en una versión específica
   */
  static async registrarDescuento(params: {
    versionId: string
    monto: number
    tipoDescuento: 'inicial' | 'temporal' | 'pre-escritura' | 'referido' | 'otro'
    motivo: string
  }): Promise<DescuentoNegociacion> {
    const { data, error } = await supabase
      .from('descuentos_negociacion')
      .insert({
        negociacion_version_id: params.versionId,
        monto: params.monto,
        tipo_descuento: params.tipoDescuento,
        motivo: params.motivo,
      })
      .select()
      .single()

    if (error) throw error
    return data
  }
}

/**
 * Service: Notas Manuales del Historial de Cliente
 * CRUD operations para notas que complementan eventos automáticos
 */

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

import type {
    ActualizarNotaDTO,
    CrearNotaDTO,
    NotaHistorialConUsuario,
} from '../types/notas-historial.types'

class NotasHistorialService {
  /**
   * Obtener una nota específica por ID
   */
  async obtenerNotaPorId(notaId: string): Promise<NotaHistorialConUsuario | null> {
    try {
      const { data: nota, error } = await supabase
        .from('notas_historial_cliente')
        .select('id,cliente_id,titulo,contenido,es_importante,fecha_creacion,fecha_actualizacion,creado_por,actualizado_por')
        .eq('id', notaId)
        .single()

      if (error) throw error
      if (!nota) return null

      // Obtener datos del creador
      const { data: creador } = await supabase
        .from('usuarios')
        .select('id,email,nombres,apellidos,rol')
        .eq('id', nota.creado_por)
        .single()

      return {
        ...nota,
        creador: creador || {
          id: nota.creado_por,
          email: 'Desconocido',
          nombres: 'Usuario',
          apellidos: 'Eliminado',
          rol: '',
        },
      } as NotaHistorialConUsuario
    } catch (error) {
      logger.error('❌ [NOTAS] Error obteniendo nota:', error)
      return null
    }
  }

  /**
   * Obtener todas las notas de un cliente
   */
  async obtenerNotasCliente(clienteId: string): Promise<NotaHistorialConUsuario[]> {
    try {
      const { data: notas, error } = await supabase
        .from('notas_historial_cliente')
        .select('id,cliente_id,titulo,contenido,es_importante,fecha_creacion,fecha_actualizacion,creado_por,actualizado_por')
        .eq('cliente_id', clienteId)
        .order('fecha_creacion', { ascending: false })

      if (error) throw error

      if (!notas || notas.length === 0) return []

      // Obtener IDs únicos de usuarios (creadores + actualizadores)
      const usuarioIds = new Set<string>()
      notas.forEach((nota) => {
        usuarioIds.add(nota.creado_por)
        if (nota.actualizado_por) usuarioIds.add(nota.actualizado_por)
      })

      // Query única para todos los usuarios
      const { data: usuarios } = await supabase
        .from('usuarios')
        .select('id,email,nombres,apellidos,rol')
        .in('id', Array.from(usuarioIds))

      const usuariosMap = new Map((usuarios || []).map((u) => [u.id, u]))

      // Mapear notas con datos de usuarios
      return notas.map((nota) => {
        const creador = usuariosMap.get(nota.creado_por)
        const actualizador = nota.actualizado_por
          ? usuariosMap.get(nota.actualizado_por)
          : undefined

        return {
          ...nota,
          creador: creador
            ? {
                id: creador.id,
                email: creador.email,
                nombres: creador.nombres,
                apellidos: creador.apellidos,
                rol: creador.rol,
              }
            : {
                id: nota.creado_por,
                email: 'Desconocido',
                nombres: 'Usuario',
                apellidos: 'Eliminado',
                rol: '',
              },
          actualizador: actualizador
            ? {
                id: actualizador.id,
                email: actualizador.email,
                nombres: actualizador.nombres,
                apellidos: actualizador.apellidos,
              }
            : undefined,
        } as NotaHistorialConUsuario
      })
    } catch (error) {
      logger.error('❌ [NOTAS] Error obteniendo notas del cliente:', error)
      return []
    }
  }

  /**
   * Crear una nota nueva
   */
  async crearNota(datos: CrearNotaDTO): Promise<{ success: boolean; nota?: NotaHistorialConUsuario; error?: string }> {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()

      if (!user) {
        return { success: false, error: 'Usuario no autenticado' }
      }

      const { data: nota, error } = await supabase
        .from('notas_historial_cliente')
        .insert({
          cliente_id: datos.cliente_id,
          titulo: datos.titulo.trim(),
          contenido: datos.contenido.trim(),
          es_importante: datos.es_importante || false,
          creado_por: user.id,
        })
        .select()
        .single()

      if (error) throw error

      // Obtener datos del creador
      const { data: creador } = await supabase
        .from('usuarios')
        .select('id,email,nombres,apellidos,rol')
        .eq('id', user.id)
        .single()

      return {
        success: true,
        nota: {
          ...nota,
          creador: creador || {
            id: user.id,
            email: user.email || '',
            nombres: 'Usuario',
            apellidos: '',
            rol: '',
          },
        } as NotaHistorialConUsuario,
      }
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('❌ [NOTAS] Error creando nota:', error)
      return { success: false, error: mensaje }
    }
  }

  /**
   * Actualizar una nota existente
   */
  async actualizarNota(
    notaId: string,
    datos: ActualizarNotaDTO
  ): Promise<{ success: boolean; error?: string }> {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()

      if (!user) {
        return { success: false, error: 'Usuario no autenticado' }
      }

      const actualizacion: any = {
        actualizado_por: user.id,
      }

      if (datos.titulo !== undefined) actualizacion.titulo = datos.titulo.trim()
      if (datos.contenido !== undefined) actualizacion.contenido = datos.contenido.trim()
      if (datos.es_importante !== undefined) actualizacion.es_importante = datos.es_importante

      const { error } = await supabase
        .from('notas_historial_cliente')
        .update(actualizacion)
        .eq('id', notaId)

      if (error) throw error

      return { success: true }
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('❌ [NOTAS] Error actualizando nota:', error)
      return { success: false, error: mensaje }
    }
  }

  /**
   * Eliminar una nota
   */
  async eliminarNota(notaId: string): Promise<{ success: boolean; error?: string }> {
    try {
      const { error } = await supabase.from('notas_historial_cliente').delete().eq('id', notaId)

      if (error) throw error

      return { success: true }
    } catch (error) {
      const mensaje = error instanceof Error ? error.message : 'Error desconocido'
      logger.error('❌ [NOTAS] Error eliminando nota:', error)
      return { success: false, error: mensaje }
    }
  }

  /**
   * Verificar si usuario puede editar/eliminar nota
   */
  async puedeEditarNota(notaId: string): Promise<boolean> {
    try {
      const {
        data: { user },
      } = await supabase.auth.getUser()

      if (!user) return false

      // Obtener nota y usuario
      const [notaResult, usuarioResult] = await Promise.all([
        supabase.from('notas_historial_cliente').select('creado_por').eq('id', notaId).single(),
        supabase.from('usuarios').select('rol').eq('id', user.id).single(),
      ])

      if (notaResult.error || usuarioResult.error) return false

      const nota = notaResult.data
      const usuario = usuarioResult.data

      // Es Admin o es el creador
      return usuario.rol === 'Administrador' || nota.creado_por === user.id
    } catch (error) {
      logger.error('❌ [NOTAS] Error verificando permisos:', error)
      return false
    }
  }
}

