 */

import jsPDF from 'jspdf'
import autoTable from 'jspdf-autotable'

import { getTodayDateString } from '@/lib/utils/date.utils'
import { logger } from '@/lib/utils/logger'

// ============================================
// TYPES
// ============================================

interface DatosCliente {
