  )

  yPos += 8

  // ============================================
  // 5. FUENTES DE PAGO (Tabla)
  // ============================================

  yPos = addSection(doc, 'FUENTES DE PAGO', yPos)

  if (datos.fuentesPago.length === 0) {
    setFont(doc, 'body')
    doc.setTextColor(...COLORES.textSecondary)
    doc.text('Sin fuentes de pago configuradas', 14, yPos)
    yPos += 10
  } else {
    const fuentesData = datos.fuentesPago.map((f) => [
      f.tipo,
      `$${f.monto.toLocaleString('es-CO')}`,
      f.entidad || 'N/A',
    ])

    autoTable(doc, {
      startY: yPos,
      head: [['Tipo', 'Monto Configurado', 'Entidad']],
      body: fuentesData,
      theme: 'grid',
      headStyles: {
        fillColor: COLORES.primary,
        textColor: [255, 255, 255],
        fontStyle: 'bold',
        fontSize: 9,
      },
      styles: {
        fontSize: 9,
        cellPadding: 3,
      },
      columnStyles: {
        1: { halign: 'right' },
      },
    })

    yPos = (doc as any).lastAutoTable.finalY + 12
  }

  // ============================================
  // 6. NOTAS (si existen)
  // ============================================

  if (datos.notas && datos.notas.trim()) {
    yPos = checkPageBreak(doc, yPos, 30)
    yPos = addSection(doc, 'NOTAS Y OBSERVACIONES', yPos)

    setFont(doc, 'body')
    doc.setTextColor(...COLORES.textPrimary)
    const splitNotas = doc.splitTextToSize(datos.notas, 182)
    doc.text(splitNotas, 14, yPos)
    yPos += splitNotas.length * 5 + 10
  }

  // ============================================
  // 7. MARCA DE AGUA DIAGONAL "BORRADOR"
  // ============================================

  const totalPages = doc.getNumberOfPages()
  for (let i = 1; i <= totalPages; i++) {
    doc.setPage(i)

    // Marca de agua diagonal
    doc.saveGraphicsState()
    // @ts-ignore — GState constructor not typed in jspdf types
    doc.setGState(new doc.GState({ opacity: 0.1 }))
    doc.setTextColor(...COLORES.warning)
    doc.setFontSize(60)
    doc.setFont('helvetica', 'bold')
    doc.text('BORRADOR', 105, 150, {
      align: 'center',
      angle: 45,
    })
    doc.restoreGraphicsState()

    // Pie de página
    doc.setDrawColor(...COLORES.border)
    doc.setLineWidth(0.3)
    doc.line(14, 285, 196, 285)

    setFont(doc, 'caption')
    doc.setTextColor(...COLORES.textSecondary)
    doc.text(
      'Preview generado por el sistema de gestión de RyR Constructora Ltda.',
      105,
      290,
      { align: 'center' }
    )

    doc.text(`Página ${i} de ${totalPages}`, 196, 290, { align: 'right' })
  }

  // ============================================
  // GUARDAR ARCHIVO
  // ============================================

  const nombreArchivo = `Preview_Negociacion_${datos.cliente.apellidos.replace(/\s+/g, '_')}_${getTodayDateString()}.pdf`
  doc.save(nombreArchivo)
}

/**
 * Utilidad para convertir notas manuales a formato de EventoHistorialHumanizado
 * Permite unificar notas + eventos automáticos en el mismo timeline
 */

import { FileEdit, Star } from 'lucide-react'

import type { EventoHistorialHumanizado } from '../types/historial.types'
import type { NotaHistorialConUsuario } from '../types/notas-historial.types'

/**
 * Convertir array de notas a eventos humanizados
 */
export function convertirNotasAEventos(
  notas: NotaHistorialConUsuario[]
): EventoHistorialHumanizado[] {
  return notas.map((nota) => convertirNotaAEvento(nota))
}

/**
 * Convertir una nota individual a evento humanizado
 */
export function convertirNotaAEvento(
  nota: NotaHistorialConUsuario
): EventoHistorialHumanizado {
  const nombreCompleto = [nota.creador.nombres, nota.creador.apellidos]
    .filter(Boolean)
    .join(' ')

  return {
    id: `nota-${nota.id}`,
    tipo: 'nota_manual' as any, // Tipo especial para notas
    accion: 'CREATE' as any, // Notas siempre son tipo CREATE visualmente
    titulo: nota.titulo,
    descripcion: nota.contenido,
    fecha: nota.fecha_creacion,
    usuario: {
      id: nota.creado_por,
      email: nota.creador.email,
      nombres: nombreCompleto || nota.creador.email,
      rol: nota.creador.rol,
    },
    icono: nota.es_importante ? Star : FileEdit,
    color: nota.es_importante ? 'yellow' : 'purple',
    metadata: {
      esNota: true,
      notaId: nota.id,
      creadoPor: nota.creado_por, // ✅ Para verificación sincrónica de permisos
      esImportante: nota.es_importante,
      actualizado: !!nota.fecha_actualizacion,
      fechaActualizacion: nota.fecha_actualizacion,
    },
  }
}

/**
 * Component: EntidadesFinancierasLista
 *
 * Tabla profesional para administrar entidades financieras.
 * Con filtros, búsqueda, acciones inline y estados de UI.
 */

'use client'

import { useState } from 'react'

import { motion } from 'framer-motion'
import {
    AlertCircle,
    Building2,
    CircleDollarSign,
    Edit2,
    Filter,
    Landmark,
    Loader2,
    Plus,
    RefreshCw,
    Search,
    Trash2,
} from 'lucide-react'

import {
    useEliminarEntidadFinanciera,
    useEntidadesFinancieras,
    useReactivarEntidadFinanciera,
} from '../hooks/useEntidadesFinancieras'
import type {
    EntidadColor,
    EntidadFinanciera,
    TipoEntidadFinanciera,
} from '../types/entidades-financieras.types'
import { TIPO_ENTIDAD_VALUES } from '../types/entidades-financieras.types'

import { EntidadFinancieraFormModal } from './EntidadFinancieraFormModal'

// =====================================================
// ICON MAP
// =====================================================

const tipoIcons: Record<TipoEntidadFinanciera, any> = {
  Banco: Landmark,
  'Caja de Compensación': Building2,
  Cooperativa: CircleDollarSign,
  Otro: Building2,
}

// =====================================================
// COLOR MAP
// =====================================================

const colorClasses: Record<EntidadColor, { bg: string; text: string; border: string }> = {
  blue: { bg: 'bg-blue-50 dark:bg-blue-950/30', text: 'text-blue-600 dark:text-blue-400', border: 'border-blue-200 dark:border-blue-800' },
  green: { bg: 'bg-green-50 dark:bg-green-950/30', text: 'text-green-600 dark:text-green-400', border: 'border-green-200 dark:border-green-800' },
  orange: { bg: 'bg-orange-50 dark:bg-orange-950/30', text: 'text-orange-600 dark:text-orange-400', border: 'border-orange-200 dark:border-orange-800' },
  purple: { bg: 'bg-purple-50 dark:bg-purple-950/30', text: 'text-purple-600 dark:text-purple-400', border: 'border-purple-200 dark:border-purple-800' },
  red: { bg: 'bg-red-50 dark:bg-red-950/30', text: 'text-red-600 dark:text-red-400', border: 'border-red-200 dark:border-red-800' },
  yellow: { bg: 'bg-yellow-50 dark:bg-yellow-950/30', text: 'text-yellow-600 dark:text-yellow-400', border: 'border-yellow-200 dark:border-yellow-800' },
  cyan: { bg: 'bg-cyan-50 dark:bg-cyan-950/30', text: 'text-cyan-600 dark:text-cyan-400', border: 'border-cyan-200 dark:border-cyan-800' },
  pink: { bg: 'bg-pink-50 dark:bg-pink-950/30', text: 'text-pink-600 dark:text-pink-400', border: 'border-pink-200 dark:border-pink-800' },
  indigo: { bg: 'bg-indigo-50 dark:bg-indigo-950/30', text: 'text-indigo-600 dark:text-indigo-400', border: 'border-indigo-200 dark:border-indigo-800' },
  gray: { bg: 'bg-gray-50 dark:bg-gray-950/30', text: 'text-gray-600 dark:text-gray-400', border: 'border-gray-200 dark:border-gray-800' },
  emerald: { bg: 'bg-emerald-50 dark:bg-emerald-950/30', text: 'text-emerald-600 dark:text-emerald-400', border: 'border-emerald-200 dark:border-emerald-800' },
  teal: { bg: 'bg-teal-50 dark:bg-teal-950/30', text: 'text-teal-600 dark:text-teal-400', border: 'border-teal-200 dark:border-teal-800' },
  amber: { bg: 'bg-amber-50 dark:bg-amber-950/30', text: 'text-amber-600 dark:text-amber-400', border: 'border-amber-200 dark:border-amber-800' },
  sky: { bg: 'bg-sky-50 dark:bg-sky-950/30', text: 'text-sky-600 dark:text-sky-400', border: 'border-sky-200 dark:border-sky-800' },
  violet: { bg: 'bg-violet-50 dark:bg-violet-950/30', text: 'text-violet-600 dark:text-violet-400', border: 'border-violet-200 dark:border-violet-800' },
  slate: { bg: 'bg-slate-50 dark:bg-slate-950/30', text: 'text-slate-600 dark:text-slate-400', border: 'border-slate-200 dark:border-slate-800' },
  lime: { bg: 'bg-lime-50 dark:bg-lime-950/30', text: 'text-lime-600 dark:text-lime-400', border: 'border-lime-200 dark:border-lime-800' },
  rose: { bg: 'bg-rose-50 dark:bg-rose-950/30', text: 'text-rose-600 dark:text-rose-400', border: 'border-rose-200 dark:border-rose-800' },
}

// =====================================================
// COMPONENT
// =====================================================

export function EntidadesFinancierasLista() {
  // State
  const [search, setSearch] = useState('')
  const [tipoFilter, setTipoFilter] = useState<TipoEntidadFinanciera | 'Todos'>('Todos')
  const [estadoFilter, setEstadoFilter] = useState<'Todos' | 'Activas' | 'Inactivas'>('Todos')
  const [isModalOpen, setIsModalOpen] = useState(false)
  const [entidadEdit, setEntidadEdit] = useState<EntidadFinanciera | null>(null)

  // Queries & Mutations
  const { data: entidades, isLoading, isError, error, refetch } = useEntidadesFinancieras()
  const eliminarMutation = useEliminarEntidadFinanciera()
  const reactivarMutation = useReactivarEntidadFinanciera()

  // Filtrar entidades
  const entidadesFiltradas = entidades?.filter((entidad) => {
    const matchSearch =
      entidad.nombre.toLowerCase().includes(search.toLowerCase()) ||
      entidad.codigo.toLowerCase().includes(search.toLowerCase()) ||
      entidad.nit?.toLowerCase().includes(search.toLowerCase())

    const matchTipo = tipoFilter === 'Todos' || entidad.tipo === tipoFilter

    const matchEstado =
      estadoFilter === 'Todos' ||
      (estadoFilter === 'Activas' && entidad.activo) ||
      (estadoFilter === 'Inactivas' && !entidad.activo)

    return matchSearch && matchTipo && matchEstado
  })

  // Handlers
  const handleNuevo = () => {
    setEntidadEdit(null)
    setIsModalOpen(true)
  }

  const handleEdit = (entidad: EntidadFinanciera) => {
    setEntidadEdit(entidad)
    setIsModalOpen(true)
  }

  const handleEliminar = async (entidad: EntidadFinanciera) => {
    if (!confirm(`¿Desactivar "${entidad.nombre}"?`)) return
    await eliminarMutation.mutateAsync(entidad.id)
  }

  const handleReactivar = async (entidad: EntidadFinanciera) => {
    await reactivarMutation.mutateAsync(entidad.id)
  }

  // =====================================================
  // LOADING STATE
  // =====================================================

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="w-8 h-8 text-blue-600 animate-spin" />
      </div>
    )
  }

  // =====================================================
  // ERROR STATE
  // =====================================================

  if (isError) {
    return (
      <div className="rounded-xl border-2 border-red-200 dark:border-red-800 bg-red-50 dark:bg-red-950/30 p-6">
        <div className="flex items-start gap-3">
          <AlertCircle className="w-6 h-6 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" />
          <div>
            <h3 className="font-semibold text-red-900 dark:text-red-100">
              Error al cargar entidades
            </h3>
            <p className="text-sm text-red-700 dark:text-red-300 mt-1">
              {error instanceof Error ? error.message : 'Error desconocido'}
            </p>
            <button
              onClick={() => refetch()}
              className="mt-3 px-4 py-2 text-sm font-medium text-white bg-red-600 hover:bg-red-700 rounded-lg transition-colors"
            >
              Reintentar
            </button>
          </div>
        </div>
      </div>
    )
  }

  // =====================================================
  // MAIN RENDER
  // =====================================================

  return (
    <div className="space-y-4">
      {/* Header con búsqueda y filtros */}
      <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-4 shadow-lg">
        <div className="flex flex-col lg:flex-row items-start lg:items-center gap-3">
          {/* Búsqueda */}
          <div className="relative flex-1 w-full">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Buscar por nombre, código o NIT..."
              className="w-full pl-10 pr-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 dark:bg-gray-700 dark:text-white text-sm"
            />
          </div>

          {/* Filtro Tipo */}
          <div className="relative flex items-center gap-2 w-full lg:w-auto">
            <Filter className="w-4 h-4 text-gray-400" />
            <select
              value={tipoFilter}
              onChange={(e) => setTipoFilter(e.target.value as any)}
              className="flex-1 lg:flex-none px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 dark:bg-gray-700 dark:text-white text-sm min-w-[200px]"
            >
              <option value="Todos">Todos los tipos</option>
              {TIPO_ENTIDAD_VALUES.map((tipo) => (
                <option key={tipo} value={tipo}>
                  {tipo}
                </option>
              ))}
            </select>
          </div>

          {/* Filtro Estado */}
          <select
            value={estadoFilter}
            onChange={(e) => setEstadoFilter(e.target.value as any)}
            className="px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 dark:bg-gray-700 dark:text-white text-sm w-full lg:w-auto"
          >
            <option value="Todos">Todos</option>
            <option value="Activas">Activas</option>
            <option value="Inactivas">Inactivas</option>
          </select>

          {/* Botón Nuevo */}
          <button
            onClick={handleNuevo}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 rounded-lg transition-all shadow-lg w-full lg:w-auto justify-center"
          >
            <Plus className="w-4 h-4" />
            Nueva Entidad
          </button>
        </div>

        {/* Contador */}
        <div className="mt-3 pt-3 border-t border-gray-200 dark:border-gray-700">
          <p className="text-sm text-gray-600 dark:text-gray-400 font-medium">
            {entidadesFiltradas?.length || 0} entidad(es) encontrada(s)
          </p>
        </div>
      </div>

      {/* Tabla */}
      {entidadesFiltradas && entidadesFiltradas.length > 0 ? (
        <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-lg overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-gray-50 dark:bg-gray-900 border-b border-gray-200 dark:border-gray-700">
                <tr>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wider">
                    Entidad
                  </th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wider">
                    Tipo
                  </th>
                  <th className="px-4 py-3 text-left text-xs font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wider">
                    Contacto
                  </th>
                  <th className="px-4 py-3 text-center text-xs font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wider">
                    Orden
                  </th>
                  <th className="px-4 py-3 text-center text-xs font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wider">
                    Estado
                  </th>
                  <th className="px-4 py-3 text-right text-xs font-semibold text-gray-700 dark:text-gray-300 uppercase tracking-wider">
                    Acciones
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                {entidadesFiltradas.map((entidad) => {
                  const Icon = tipoIcons[entidad.tipo]
                  const colors = colorClasses[entidad.color as EntidadColor] || colorClasses.gray

                  return (
                    <motion.tr
                      key={entidad.id}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      className="hover:bg-gray-50 dark:hover:bg-gray-700/50 transition-colors"
                    >
                      {/* Entidad */}
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-3">
                          <div
                            className={`w-10 h-10 rounded-lg ${colors.bg} ${colors.border} border flex items-center justify-center flex-shrink-0`}
                          >
                            <Icon className={`w-5 h-5 ${colors.text}`} />
                          </div>
                          <div className="min-w-0">
                            <p className="text-sm font-semibold text-gray-900 dark:text-white truncate">
                              {entidad.nombre}
                            </p>
                            <p className="text-xs text-gray-500 dark:text-gray-400 font-mono">
                              {entidad.codigo}
                            </p>
                          </div>
                        </div>
                      </td>

                      {/* Tipo */}
                      <td className="px-4 py-3">
                        <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-gray-100 dark:bg-gray-700 text-xs font-medium text-gray-700 dark:text-gray-300">
                          {entidad.tipo}
                        </span>
                      </td>

                      {/* Contacto */}
                      <td className="px-4 py-3">
                        <div className="space-y-0.5 text-xs">
                          {entidad.telefono ? (
                            <p className="text-gray-600 dark:text-gray-400">{entidad.telefono}</p>
                          ) : null}
                          {entidad.email_contacto ? (
                            <p className="text-gray-600 dark:text-gray-400 truncate max-w-xs">
                              {entidad.email_contacto}
                            </p>
                          ) : null}
                          {!entidad.telefono && !entidad.email_contacto ? (
                            <p className="text-gray-400 dark:text-gray-500 italic">Sin contacto</p>
                          ) : null}
                        </div>
                      </td>

                      {/* Orden */}
                      <td className="px-4 py-3 text-center">
                        <span className="inline-flex items-center justify-center w-8 h-8 rounded-full bg-gray-100 dark:bg-gray-700 text-sm font-bold text-gray-700 dark:text-gray-300">
                          {entidad.orden}
                        </span>
                      </td>

                      {/* Estado */}
                      <td className="px-4 py-3 text-center">
                        {entidad.activo ? (
                          <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-green-100 dark:bg-green-950/30 text-xs font-medium text-green-700 dark:text-green-400">
                            <span className="w-1.5 h-1.5 rounded-full bg-green-500" />
                            Activa
                          </span>
                        ) : (
                          <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-gray-100 dark:bg-gray-700 text-xs font-medium text-gray-700 dark:text-gray-400">
                            <span className="w-1.5 h-1.5 rounded-full bg-gray-400" />
                            Inactiva
                          </span>
                        )}
                      </td>

                      {/* Acciones */}
                      <td className="px-4 py-3">
                        <div className="flex items-center justify-end gap-2">
                          <button
                            onClick={() => handleEdit(entidad)}
                            className="p-2 text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-950/30 rounded-lg transition-colors"
                            title="Editar"
                          >
                            <Edit2 className="w-4 h-4" />
                          </button>

                          {entidad.activo ? (
                            <button
                              onClick={() => handleEliminar(entidad)}
                              disabled={eliminarMutation.isPending}
                              className="p-2 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-950/30 rounded-lg transition-colors disabled:opacity-50"
                              title="Desactivar"
                            >
                              <Trash2 className="w-4 h-4" />
                            </button>
                          ) : (
                            <button
                              onClick={() => handleReactivar(entidad)}
                              disabled={reactivarMutation.isPending}
                              className="p-2 text-green-600 dark:text-green-400 hover:bg-green-50 dark:hover:bg-green-950/30 rounded-lg transition-colors disabled:opacity-50"
                              title="Reactivar"
                            >
                              <RefreshCw className="w-4 h-4" />
                            </button>
                          )}
                        </div>
                      </td>
                    </motion.tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        // Empty State
        <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-12">
          <div className="text-center">
            <Building2 className="w-12 h-12 text-gray-400 mx-auto mb-3" />
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-1">
              No hay entidades
            </h3>
            <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
              {search || tipoFilter !== 'Todos' || estadoFilter !== 'Todos'
                ? 'No se encontraron entidades con los filtros seleccionados'
                : 'Comienza creando tu primera entidad financiera'}
            </p>
            {!search && tipoFilter === 'Todos' && estadoFilter === 'Todos' ? (
              <button
                onClick={handleNuevo}
                className="inline-flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 rounded-lg transition-all shadow-lg"
              >
                <Plus className="w-4 h-4" />
                Nueva Entidad
              </button>
            ) : null}
          </div>
        </div>
      )}

      {/* Modal */}
      <EntidadFinancieraFormModal
        isOpen={isModalOpen}
        onClose={() => {
          setIsModalOpen(false)
          setEntidadEdit(null)
        }}
        entidad={entidadEdit}
      />
    </div>
  )
}

/**
 * Componente: Lista de Tipos de Fuentes de Pago
 *
 * Tabla profesional con acciones CRUD, filtros y estado de carga.
 *
 * Características:
 * - Tabla responsive con estados visuales
 * - Filtros en tiempo real
 * - Acciones inline (editar, eliminar, reactivar)
 * - Estados de loading/empty/error
 * - Drag and drop para reordenar (futuro)
 *
 * Responsabilidad: UI PRESENTACIONAL (lógica en hook)
 */

'use client'

import { useState } from 'react'

import { motion } from 'framer-motion'
import {
    AlertCircle,
    BadgeDollarSign,
    Banknote,
    Building2,
    Check,
    CreditCard,
    DollarSign,
    Edit3,
    Eye,
    EyeOff,
    HandCoins,
    Home,
    Landmark,
    Loader2,
    Plus,
    RefreshCw,
    Search,
    Shield,
    Wallet,
    X
} from 'lucide-react'

import {
    useEliminarTipoFuentePago,
    useReactivarTipoFuentePago,
    useTiposFuentesPago,
} from '../hooks'
import type { TipoFuenteIcono, TipoFuentePago } from '../types'

import { TipoFuentePagoFormModal } from './TipoFuentePagoFormModal'

// =====================================================
// ICON MAP
// =====================================================

const ICON_MAP: Record<TipoFuenteIcono, React.ComponentType<{ className?: string }>> = {
  Wallet,
  Building2,
  Home,
  Shield,
  CreditCard,
  Landmark,
  BadgeDollarSign,
  DollarSign,
  Banknote,
  HandCoins,
}

// =====================================================
// COLOR MAP
// =====================================================

const COLOR_MAP: Record<string, { bg: string; text: string; border: string }> = {
  blue: {
    bg: 'bg-blue-100 dark:bg-blue-900/30',
    text: 'text-blue-700 dark:text-blue-300',
    border: 'border-blue-300 dark:border-blue-700',
  },
  green: {
    bg: 'bg-green-100 dark:bg-green-900/30',
    text: 'text-green-700 dark:text-green-300',
    border: 'border-green-300 dark:border-green-700',
  },
  purple: {
    bg: 'bg-purple-100 dark:bg-purple-900/30',
    text: 'text-purple-700 dark:text-purple-300',
    border: 'border-purple-300 dark:border-purple-700',
  },
  orange: {
    bg: 'bg-orange-100 dark:bg-orange-900/30',
    text: 'text-orange-700 dark:text-orange-300',
    border: 'border-orange-300 dark:border-orange-700',
  },
  red: {
    bg: 'bg-red-100 dark:bg-red-900/30',
    text: 'text-red-700 dark:text-red-300',
    border: 'border-red-300 dark:border-red-700',
  },
  cyan: {
    bg: 'bg-cyan-100 dark:bg-cyan-900/30',
    text: 'text-cyan-700 dark:text-cyan-300',
    border: 'border-cyan-300 dark:border-cyan-700',
  },
  pink: {
    bg: 'bg-pink-100 dark:bg-pink-900/30',
    text: 'text-pink-700 dark:text-pink-300',
    border: 'border-pink-300 dark:border-pink-700',
  },
  indigo: {
    bg: 'bg-indigo-100 dark:bg-indigo-900/30',
    text: 'text-indigo-700 dark:text-indigo-300',
    border: 'border-indigo-300 dark:border-indigo-700',
  },
  yellow: {
    bg: 'bg-yellow-100 dark:bg-yellow-900/30',
    text: 'text-yellow-700 dark:text-yellow-300',
    border: 'border-yellow-300 dark:border-yellow-700',
  },
  emerald: {
    bg: 'bg-emerald-100 dark:bg-emerald-900/30',
    text: 'text-emerald-700 dark:text-emerald-300',
    border: 'border-emerald-300 dark:border-emerald-700',
  },
}

// =====================================================
// COMPONENT
// =====================================================

export function TiposFuentesPagoLista() {
  // Estado local
  const [busqueda, setBusqueda] = useState('')
  const [mostrarInactivos, setMostrarInactivos] = useState(false)
  const [modalAbierto, setModalAbierto] = useState(false)
  const [tipoSeleccionado, setTipoSeleccionado] = useState<TipoFuentePago | null>(null)

  // React Query
  const {
    data: tiposFuentes = [],
    isLoading,
    isError,
    error,
    refetch,
    isFetching,
  } = useTiposFuentesPago(
    {
      activo: mostrarInactivos ? undefined : true,
      search: busqueda || undefined,
    },
    'orden',
    'asc'
  )

  const { mutate: eliminar, isPending: isDeleting } = useEliminarTipoFuentePago()
  const { mutate: reactivar, isPending: isReactivating } = useReactivarTipoFuentePago()

  // Handlers
  const handleNuevo = () => {
    setTipoSeleccionado(null)
    setModalAbierto(true)
  }

  const handleEditar = (tipo: TipoFuentePago) => {
    setTipoSeleccionado(tipo)
    setModalAbierto(true)
  }

  const handleEliminar = (id: string) => {
    if (confirm('¿Estás seguro de desactivar esta fuente de pago?')) {
      eliminar(id)
    }
  }

  const handleReactivar = (id: string) => {
    reactivar(id)
  }

  // Filtrado local adicional
  const tiposFiltrados = tiposFuentes.filter((tipo) => {
    if (!busqueda) return true
    const termino = busqueda.toLowerCase()
    return (
      tipo.nombre.toLowerCase().includes(termino) ||
      tipo.codigo.toLowerCase().includes(termino) ||
      tipo.descripcion?.toLowerCase().includes(termino)
    )
  })

  return (
    <div className="space-y-6">
      {/* Header con Acciones */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900 dark:text-white">
            Tipos de Fuentes de Pago
          </h2>
          <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
            Administra las fuentes de pago disponibles en el sistema
          </p>
        </div>

        <motion.button
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          onClick={handleNuevo}
          className="flex items-center gap-2 px-4 py-2.5 rounded-lg bg-gradient-to-r from-blue-600 to-indigo-600 text-white hover:from-blue-700 hover:to-indigo-700 transition-all font-medium shadow-lg shadow-blue-500/30"
        >
          <Plus className="w-5 h-5" />
          Nueva Fuente
        </motion.button>
      </div>

      {/* Filtros */}
      <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-3 p-4 bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm">
        {/* Búsqueda */}
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 pointer-events-none" />
          <input
            type="text"
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
            placeholder="Buscar por nombre, código o descripción..."
            className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900/50 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all text-gray-900 dark:text-white placeholder:text-gray-400"
          />
          {busqueda && (
            <button
              onClick={() => setBusqueda('')}
              className="absolute right-3 top-1/2 -translate-y-1/2 p-1 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors"
            >
              <X className="w-4 h-4 text-gray-400" />
            </button>
          )}
        </div>

        {/* Mostrar Inactivos */}
        <label className="flex items-center gap-2 px-4 py-2.5 bg-gray-50 dark:bg-gray-900/50 rounded-lg border-2 border-gray-200 dark:border-gray-700 cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-900 transition-colors">
          <input
            type="checkbox"
            checked={mostrarInactivos}
            onChange={(e) => setMostrarInactivos(e.target.checked)}
            className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-2 focus:ring-blue-500/20"
          />
          <span className="text-sm font-medium text-gray-700 dark:text-gray-300">
            Mostrar inactivos
          </span>
        </label>

        {/* Refresh */}
        <motion.button
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          onClick={() => refetch()}
          disabled={isFetching}
          className="p-2.5 rounded-lg bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors disabled:opacity-50"
        >
          <RefreshCw className={`w-5 h-5 ${isFetching ? 'animate-spin' : ''}`} />
        </motion.button>
      </div>

      {/* Estados de Carga/Error */}
      {isLoading && (
        <div className="flex flex-col items-center justify-center py-16 text-gray-500 dark:text-gray-400">
          <Loader2 className="w-12 h-12 animate-spin mb-4 text-blue-600" />
          <p className="text-sm font-medium">Cargando fuentes de pago...</p>
        </div>
      )}

      {isError && (
        <div className="flex flex-col items-center justify-center py-16">
          <div className="p-4 rounded-full bg-red-100 dark:bg-red-900/30 mb-4">
            <AlertCircle className="w-12 h-12 text-red-600 dark:text-red-400" />
          </div>
          <p className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
            Error al cargar datos
          </p>
          <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
            {error?.message || 'Ocurrió un error inesperado'}
          </p>
          <button
            onClick={() => refetch()}
            className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700 transition-colors font-medium"
          >
            Reintentar
          </button>
        </div>
      )}

      {/* Estado Vacío */}
      {!isLoading && !isError && tiposFiltrados.length === 0 && (
        <div className="flex flex-col items-center justify-center py-16 text-gray-500 dark:text-gray-400">
          <div className="p-4 rounded-full bg-gray-100 dark:bg-gray-800 mb-4">
            <Search className="w-12 h-12" />
          </div>
          <p className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
            {busqueda ? 'No se encontraron resultados' : 'No hay fuentes de pago'}
          </p>
          <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
            {busqueda
              ? 'Intenta con otros términos de búsqueda'
              : 'Comienza creando tu primera fuente de pago'}
          </p>
          {!busqueda && (
            <button
              onClick={handleNuevo}
              className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-700 transition-colors font-medium"
            >
              Nueva Fuente
            </button>
          )}
        </div>
      )}

      {/* Tabla */}
      {!isLoading && !isError && tiposFiltrados.length > 0 && (
        <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-gray-50 dark:bg-gray-900/50 border-b border-gray-200 dark:border-gray-700">
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider">
                    Fuente
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider">
                    Código
                  </th>
                  <th className="px-6 py-3 text-left text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider">
                    Configuración
                  </th>
                  <th className="px-6 py-3 text-center text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider">
                    Orden
                  </th>
                  <th className="px-6 py-3 text-center text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider">
                    Estado
                  </th>
                  <th className="px-6 py-3 text-right text-xs font-semibold text-gray-600 dark:text-gray-400 uppercase tracking-wider">
                    Acciones
                  </th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                {tiposFiltrados.map((tipo) => {
                  const Icon = ICON_MAP[tipo.icono] || Wallet // ✅ Fallback a Wallet si icono no existe
                  const colorConfig = COLOR_MAP[tipo.color] || COLOR_MAP.blue // ✅ Fallback a blue

                  return (
                    <motion.tr
                      key={tipo.id}
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      className="hover:bg-gray-50 dark:hover:bg-gray-900/30 transition-colors"
                    >
                      {/* Fuente */}
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <div
                            className={`w-10 h-10 rounded-lg ${colorConfig.bg} ${colorConfig.border} border-2 flex items-center justify-center flex-shrink-0`}
                          >
                            <Icon className={`w-5 h-5 ${colorConfig.text}`} />
                          </div>
                          <div>
                            <p className="text-sm font-semibold text-gray-900 dark:text-white">
                              {tipo.nombre}
                            </p>
                            {tipo.descripcion && (
                              <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
                                {tipo.descripcion.length > 60
                                  ? `${tipo.descripcion.slice(0, 60)}...`
                                  : tipo.descripcion}
                              </p>
                            )}
                          </div>
                        </div>
                      </td>

                      {/* Código */}
                      <td className="px-6 py-4">
                        <code className="px-2 py-1 rounded bg-gray-100 dark:bg-gray-900/50 text-xs font-mono text-gray-900 dark:text-white">
                          {tipo.codigo}
                        </code>
                      </td>

                      {/* Configuración */}
                      <td className="px-6 py-4">
                        <div className="flex flex-wrap gap-1.5">
                          {tipo.requiere_entidad && (
                            <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-blue-100 dark:bg-blue-900/30 text-xs font-medium text-blue-700 dark:text-blue-300">
                              <Building2 className="w-3 h-3" />
                              Entidad
                            </span>
                          )}
                          {tipo.permite_multiples_abonos && (
                            <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-purple-100 dark:bg-purple-900/30 text-xs font-medium text-purple-700 dark:text-purple-300">
                              <DollarSign className="w-3 h-3" />
                              Abonos
                            </span>
                          )}
                          {tipo.es_subsidio && (
                            <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full bg-green-100 dark:bg-green-900/30 text-xs font-medium text-green-700 dark:text-green-300">
                              <Shield className="w-3 h-3" />
                              Subsidio
                            </span>
                          )}
                        </div>
                      </td>

                      {/* Orden */}
                      <td className="px-6 py-4 text-center">
                        <span className="inline-flex items-center justify-center w-8 h-8 rounded-full bg-gray-100 dark:bg-gray-900/50 text-sm font-semibold text-gray-700 dark:text-gray-300">
                          {tipo.orden}
                        </span>
                      </td>

                      {/* Estado */}
                      <td className="px-6 py-4 text-center">
                        {tipo.activo ? (
                          <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-green-100 dark:bg-green-900/30 border border-green-300 dark:border-green-700 text-xs font-medium text-green-700 dark:text-green-300">
                            <Check className="w-3.5 h-3.5" />
                            Activo
                          </span>
                        ) : (
                          <span className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-gray-100 dark:bg-gray-900/30 border border-gray-300 dark:border-gray-700 text-xs font-medium text-gray-700 dark:text-gray-300">
                            <X className="w-3.5 h-3.5" />
                            Inactivo
                          </span>
                        )}
                      </td>

                      {/* Acciones */}
                      <td className="px-6 py-4">
                        <div className="flex items-center justify-end gap-2">
                          {/* Editar */}
                          <button
                            onClick={() => handleEditar(tipo)}
                            className="p-2 rounded-lg bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300 hover:bg-blue-200 dark:hover:bg-blue-900/50 transition-colors"
                            title="Editar"
                          >
                            <Edit3 className="w-4 h-4" />
                          </button>

                          {/* Eliminar/Reactivar */}
                          {tipo.activo ? (
                            <button
                              onClick={() => handleEliminar(tipo.id)}
                              disabled={isDeleting}
                              className="p-2 rounded-lg bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300 hover:bg-red-200 dark:hover:bg-red-900/50 transition-colors disabled:opacity-50"
                              title="Desactivar"
                            >
                              <EyeOff className="w-4 h-4" />
                            </button>
                          ) : (
                            <button
                              onClick={() => handleReactivar(tipo.id)}
                              disabled={isReactivating}
                              className="p-2 rounded-lg bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300 hover:bg-green-200 dark:hover:bg-green-900/50 transition-colors disabled:opacity-50"
                              title="Reactivar"
                            >
                              <Eye className="w-4 h-4" />
                            </button>
                          )}
                        </div>
                      </td>
                    </motion.tr>
                  )
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Resumen */}
      {!isLoading && !isError && tiposFiltrados.length > 0 && (
        <div className="flex items-center justify-between px-4 py-3 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-gray-200 dark:border-gray-700">
          <p className="text-sm text-gray-600 dark:text-gray-400">
            {tiposFiltrados.length === 1
              ? '1 fuente de pago'
              : `${tiposFiltrados.length} fuentes de pago`}
          </p>
          {busqueda && (
            <p className="text-xs text-gray-500 dark:text-gray-400">
              Filtrando por: <span className="font-medium">"{busqueda}"</span>
            </p>
          )}
        </div>
      )}

      {/* Modal de Formulario */}
      <TipoFuentePagoFormModal
        isOpen={modalAbierto}
        onClose={() => {
          setModalAbierto(false)
          setTipoSeleccionado(null)
        }}
        tipoFuente={tipoSeleccionado}
        onSuccess={() => {
          refetch()
        }}
      />
    </div>
  )
}

/**
 * Componente: CampoItem
 *
 * Item de campo arrastrable con drag & drop.
 * Muestra información del campo y acciones (editar/eliminar).
 *
 * @version 1.0 - Diseño Compacto
 */

'use client'

import { useSortable } from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import { Edit2, GripVertical, Trash2 } from 'lucide-react'

import type { CampoConfig } from '../../types/campos-dinamicos.types'

import { configuradorStyles as s } from './configurador-campos.styles'

interface CampoItemProps {
  campo: CampoConfig
  onEditar: (campo: CampoConfig) => void
  onEliminar: (nombreCampo: string) => void
}

export function CampoItem({ campo, onEditar, onEliminar }: CampoItemProps) {
  // ============================================
  // DRAG & DROP
  // ============================================

  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: campo.nombre })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  }

  // ============================================
  // RENDERIZADO
  // ============================================

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`${s.campoItem.container} ${isDragging ? s.campoItem.containerDragging : ''}`}
    >
      <div className="flex items-start gap-3">
        {/* Drag Handle */}
        <button
          type="button"
          className={s.campoItem.dragHandle}
          {...attributes}
          {...listeners}
        >
          <GripVertical className={s.campoItem.dragIcon} />
        </button>

        {/* Contenido */}
        <div className={s.campoItem.content}>
          {/* Header */}
          <div className={s.campoItem.header}>
            <span className={s.campoItem.orden}>{campo.orden}</span>
            <span className={s.campoItem.nombre}>{campo.label}</span>
            {campo.requerido && (
              <span className={s.campoItem.required}>Requerido</span>
            )}
            {/* 🔥 Badge de Rol */}
            {campo.rol && campo.rol !== 'informativo' && (
              <span className={
                campo.rol === 'monto' ? 'px-2 py-0.5 rounded-full bg-green-100 dark:bg-green-900/30 text-[10px] font-bold text-green-700 dark:text-green-400' :
                campo.rol === 'entidad' ? 'px-2 py-0.5 rounded-full bg-blue-100 dark:bg-blue-900/30 text-[10px] font-bold text-blue-700 dark:text-blue-400' :
                'px-2 py-0.5 rounded-full bg-purple-100 dark:bg-purple-900/30 text-[10px] font-bold text-purple-700 dark:text-purple-400'
              }>
                {campo.rol === 'monto' ? '💰 Monto' : campo.rol === 'entidad' ? '🏦 Entidad' : '📄 Ref'}
              </span>
            )}
          </div>

          {/* Detalles */}
          <div className={s.campoItem.details}>
            <span className={s.campoItem.tipo}>{campo.tipo}</span>
            <span>•</span>
            <span className="font-mono text-[10px]">{campo.nombre}</span>
            {campo.placeholder && (
              <>
                <span>•</span>
                <span className="italic">"{campo.placeholder}"</span>
              </>
            )}
          </div>

          {/* Ayuda */}
          {campo.ayuda && (
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1 leading-relaxed">
              💡 {campo.ayuda}
            </p>
          )}
        </div>

        {/* Acciones */}
        <div className={s.campoItem.actions}>
          <button
            type="button"
            onClick={() => onEditar(campo)}
            className={`${s.campoItem.button} ${s.campoItem.buttonEdit}`}
            title="Editar campo"
          >
            <Edit2 className="w-4 h-4" />
          </button>
          <button
            type="button"
            onClick={() => onEliminar(campo.nombre)}
            className={`${s.campoItem.button} ${s.campoItem.buttonDelete}`}
            title="Eliminar campo"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  )
}

/**
 * Componente: ConfiguradorCamposModal
 *
 * Modal principal con drag & drop para configurar campos dinámicos.
 * Integra: CampoItem (arrastrable) + EditarCampoModal (crear/editar).
 *
 * @version 1.0 - Diseño Premium con @dnd-kit
 */

'use client'

import {
    closestCenter,
    DndContext,
    DragEndEvent,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
} from '@dnd-kit/core'
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
} from '@dnd-kit/sortable'
import { AnimatePresence, motion } from 'framer-motion'
import { AlertCircle, FileCode, Plus, Save, X } from 'lucide-react'

import type { ConfiguracionCampos } from '../../types/campos-dinamicos.types'

import { CampoItem } from './CampoItem'
import { configuradorStyles as s } from './configurador-campos.styles'
import { EditarCampoModal } from './EditarCampoModal'
import { useConfiguradorCampos } from './useConfiguradorCampos'

interface ConfiguradorCamposModalProps {
  isOpen: boolean
  tipoId: string
  tipoNombre: string
  tipoColor: string
  configuracionInicial: ConfiguracionCampos
  onClose: () => void
}

export function ConfiguradorCamposModal({
  isOpen,
  tipoId,
  tipoNombre,
  tipoColor,
  configuracionInicial,
  onClose,
}: ConfiguradorCamposModalProps) {
  // ============================================
  // HOOK CON LÓGICA
  // ============================================

  const hook = useConfiguradorCampos({
    tipoId,
    configuracionInicial,
    onClose,
  })

  // ============================================
  // DRAG & DROP SENSORS
  // ============================================

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 8, // Evitar activar drag en clicks
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  )

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event

    if (over && active.id !== over.id) {
      const oldIndex = hook.campos.findIndex((c) => c.nombre === active.id)
      const newIndex = hook.campos.findIndex((c) => c.nombre === over.id)
      const reordenados = arrayMove(hook.campos, oldIndex, newIndex)
      hook.handleReordenar(reordenados)
    }
  }

  if (!isOpen) return null

  // ============================================
  // RENDERIZADO
  // ============================================

  return (
    <>
      {/* Modal Principal */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        className={s.modal.overlay}
        onClick={hook.handleCancelar}
      >
        <motion.div
          initial={{ scale: 0.95, opacity: 0, y: 20 }}
          animate={{ scale: 1, opacity: 1, y: 0 }}
          exit={{ scale: 0.95, opacity: 0, y: 20 }}
          className={s.modal.container}
          onClick={(e) => e.stopPropagation()}
        >
          {/* Header */}
          <div
            className={s.modal.header.container}
            style={{
              background: `linear-gradient(135deg, ${tipoColor}, ${adjustColor(tipoColor, -20)})`,
            }}
          >
            <div className="flex items-center justify-between">
              <div>
                <h2 className="text-lg font-bold text-white">
                  ⚙️ Configurar Campos - {tipoNombre}
                </h2>
                <p className="text-xs text-white/90 mt-0.5">
                  Arrastra los campos para reordenar • Edita o elimina campos existentes
                </p>
              </div>
              <button
                type="button"
                onClick={hook.handleCancelar}
                className="p-2 rounded-lg hover:bg-white/20 transition-colors text-white"
              >
                <X className="w-5 h-5" />
              </button>
            </div>
          </div>

          {/* Body */}
          <div className={s.modal.body.container}>
            <div className={s.modal.body.content}>
              {/* Sin campos */}
              {hook.campos.length === 0 && (
                <div className={s.modal.body.empty}>
                  <FileCode className={s.modal.body.emptyIcon} />
                  <p className={s.modal.body.emptyText}>
                    No hay campos configurados aún.
                    <br />
                    Presiona <strong>"Agregar Campo"</strong> para comenzar.
                  </p>
                </div>
              )}

              {/* Lista de campos con drag & drop */}
              {hook.campos.length > 0 && (
                <DndContext
                  sensors={sensors}
                  collisionDetection={closestCenter}
                  onDragEnd={handleDragEnd}
                >
                  <SortableContext
                    items={hook.campos.map((c) => c.nombre)}
                    strategy={verticalListSortingStrategy}
                  >
                    {hook.campos.map((campo) => (
                      <CampoItem
                        key={campo.nombre}
                        campo={campo}
                        onEditar={hook.handleEditarCampo}
                        onEliminar={hook.handleEliminarCampo}
                      />
                    ))}
                  </SortableContext>
                </DndContext>
              )}

              {/* Info: Campos editables */}
              <div className="mt-4 p-3 rounded-lg bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800">
                <div className="flex items-start gap-2">
                  <AlertCircle className="w-4 h-4 text-blue-600 dark:text-blue-400 mt-0.5 flex-shrink-0" />
                  <div className="flex-1">
                    <p className="text-xs text-blue-900 dark:text-blue-100 font-semibold">
                      💡 Arrastra para reordenar
                    </p>
                    <p className="text-xs text-blue-700 dark:text-blue-300 mt-0.5">
                      El orden de los campos en esta lista será el mismo que se mostrará en el
                      formulario.
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* Footer */}
          <div className={s.modal.footer.container}>
            <div className="flex items-center gap-2">
              <button
                type="button"
                onClick={hook.handleAgregarCampo}
                className={s.modal.footer.buttonAdd}
              >
                <Plus className="w-4 h-4" />
                Agregar Campo
              </button>

              <span className="text-xs text-gray-500 dark:text-gray-400">
                {hook.campos.length} campo{hook.campos.length !== 1 ? 's' : ''}
              </span>
            </div>

            <div className="flex items-center gap-2">
              <button
                type="button"
                onClick={hook.handleCancelar}
                className={s.modal.footer.buttonSecondary}
                disabled={hook.guardando}
              >
                <X className="w-4 h-4" />
                Cancelar
              </button>

              <button
                type="button"
                onClick={hook.handleGuardar}
                disabled={hook.guardando || hook.campos.length === 0}
                className={`${s.modal.footer.buttonPrimary} bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 disabled:opacity-50 disabled:cursor-not-allowed`}
              >
                {hook.guardando ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                    Guardando...
                  </>
                ) : (
                  <>
                    <Save className="w-4 h-4" />
                    Guardar Configuración
                  </>
                )}
              </button>
            </div>
          </div>
        </motion.div>
      </motion.div>

      {/* Modal Editor (Crear/Editar Campo) */}
      <AnimatePresence>
        {hook.modalEditorAbierto && (
          <EditarCampoModal
            isOpen={hook.modalEditorAbierto}
            modo={hook.modoEditor}
            campoInicial={hook.campoEditando}
            camposExistentes={hook.campos}
            onConfirmar={
              hook.modoEditor === 'crear'
                ? hook.handleConfirmarAgregar
                : hook.handleConfirmarEditar
            }
            onCancelar={hook.handleCancelarEditor}
          />
        )}
      </AnimatePresence>
    </>
  )
}

