import type { RolCampo, TipoCampoDinamico } from '../../../types/campos-dinamicos.types';

// ============================================
// TIPOS DE CAMPOS DISPONIBLES
// ============================================

export const TIPOS_DISPONIBLES: Array<{ value: TipoCampoDinamico; label: string }> = [
