/**
 * Hook: useEditarCampoModal
 *
 * Lógica de negocio para crear/editar campos dinámicos.
 * Maneja estado, validación y transformación de datos.
 *
 * @version 1.0 - Separación de responsabilidades
 */

import { useCallback, useMemo, useState } from 'react'

import type { CampoConfig, RolCampo, TipoCampoDinamico } from '../../../types/campos-dinamicos.types'
import { ROLES_DISPONIBLES } from '../constants/campos-disponibles'

// ============================================
// TIPOS
// ============================================

interface UseEditarCampoModalParams {
  modo: 'crear' | 'editar'
  campoInicial: CampoConfig | null
  camposExistentes: CampoConfig[]
  onConfirmar: (campo: CampoConfig) => void
}

interface Errores {
  nombre?: string
  label?: string
  tipo?: string
  rol?: string
}

// ============================================
// HOOK
// ============================================

export function useEditarCampoModal({
  modo,
  campoInicial,
  camposExistentes,
  onConfirmar,
}: UseEditarCampoModalParams) {
  // ============================================
  // ESTADO
  // ============================================

  const [nombre, setNombre] = useState(campoInicial?.nombre || '')
  const [tipo, setTipo] = useState<TipoCampoDinamico>(campoInicial?.tipo || 'text')
  const [rol, setRol] = useState<RolCampo>(campoInicial?.rol || 'informativo')
  const [label, setLabel] = useState(campoInicial?.label || '')
  const [placeholder, setPlaceholder] = useState(campoInicial?.placeholder || '')
  const [ayuda, setAyuda] = useState(campoInicial?.ayuda || '')
  const [requerido, setRequerido] = useState(campoInicial?.requerido || false)
  const [errores, setErrores] = useState<Errores>({})

  // ============================================
  // ROLES DISPONIBLES (FILTRADOS)
  // ============================================

  const rolesDisponibles = useMemo(() => {
    // Verificar si ya existe un campo con rol='monto'
    const yaExisteMonto = camposExistentes.some(
      (c) => c.rol === 'monto' && c.nombre !== campoInicial?.nombre
    )

    // Si ya existe, filtrar el rol 'monto' de las opciones
    if (yaExisteMonto) {
      return ROLES_DISPONIBLES.filter((r) => r.value !== 'monto')
    }

    return ROLES_DISPONIBLES
  }, [camposExistentes, campoInicial])

  // ============================================
  // VALIDACIÓN
  // ============================================

  const validar = useCallback((): boolean => {
    const nuevosErrores: Errores = {}

    // Nombre
    if (!nombre.trim()) {
      nuevosErrores.nombre = 'El nombre es obligatorio'
    } else if (!/^[a-z_][a-z0-9_]*$/.test(nombre)) {
      nuevosErrores.nombre = 'Solo minúsculas, números y guiones bajos (snake_case)'
    } else if (modo === 'crear' && camposExistentes.some((c) => c.nombre === nombre)) {
      nuevosErrores.nombre = 'Ya existe un campo con este nombre'
    }

    // Label
    if (!label.trim()) {
      nuevosErrores.label = 'La etiqueta es obligatoria'
    }

    // Tipo
    if (!tipo) {
      nuevosErrores.tipo = 'El tipo es obligatorio'
    }

    setErrores(nuevosErrores)
    return Object.keys(nuevosErrores).length === 0
  }, [nombre, label, tipo, rol, modo, camposExistentes, campoInicial])

  // ============================================
  // HANDLERS
  // ============================================

  const handleConfirmar = useCallback(() => {
    if (!validar()) return

    // Calcular orden (último + 1 si es nuevo)
    const orden =
      modo === 'crear'
        ? Math.max(0, ...camposExistentes.map((c) => c.orden)) + 1
        : campoInicial?.orden || 1

    const campo: CampoConfig = {
      nombre,
      tipo,
      rol,
      label,
      placeholder: placeholder.trim() || undefined,
      ayuda: ayuda.trim() || undefined,
      requerido,
      orden,
    }

    onConfirmar(campo)
  }, [
    nombre,
    tipo,
    rol,
    label,
    placeholder,
    ayuda,
    requerido,
    modo,
    campoInicial,
    camposExistentes,
    validar,
    onConfirmar,
  ])

  // Obtener descripción del rol seleccionado
  const rolDescripcion = ROLES_DISPONIBLES.find((r) => r.value === rol)?.description || ''

  // ============================================
  // RETURN
  // ============================================

  return {
    // Estado
    nombre,
    tipo,
    rol,
    label,
    placeholder,
    ayuda,
    requerido,
    errores,
    rolDescripcion,
    rolesDisponibles,

    // Setters
    setNombre,
    setTipo,
    setRol,
    setLabel,
    setPlaceholder,
    setAyuda,
    setRequerido,

    // Handlers
    handleConfirmar,
  }
}

/**
 * Hook: useConfiguradorCampos
 *
 * Lógica de negocio para el configurador de campos dinámicos.
 * Maneja estado, validación, drag & drop, y guardado.
 *
 * @version 1.0 - Separación de Responsabilidades
 */

'use client'

import { useCallback, useState } from 'react'

import { toast } from 'sonner'

import { useActualizarConfiguracionCampos } from '../../hooks/useTiposFuentesConCampos'
import type { CampoConfig, ConfiguracionCampos } from '../../types/campos-dinamicos.types'

interface UseConfiguradorCamposProps {
  tipoId: string
  configuracionInicial: ConfiguracionCampos
  onClose: () => void
}

export function useConfiguradorCampos({
  tipoId,
  configuracionInicial,
  onClose,
}: UseConfiguradorCamposProps) {
  // ============================================
  // ESTADO
  // ============================================

  const [campos, setCampos] = useState<CampoConfig[]>(configuracionInicial.campos)
  const [campoEditando, setCampoEditando] = useState<CampoConfig | null>(null)
  const [modoEditor, setModoEditor] = useState<'crear' | 'editar'>('crear')
  const [modalEditorAbierto, setModalEditorAbierto] = useState(false)

  // ============================================
  // REACT QUERY
  // ============================================

  const { mutate: actualizar, isPending: guardando } = useActualizarConfiguracionCampos()

  // ============================================
  // HANDLERS: AGREGAR
  // ============================================

  const handleAgregarCampo = useCallback(() => {
    setCampoEditando(null)
    setModoEditor('crear')
    setModalEditorAbierto(true)
  }, [])

  const handleConfirmarAgregar = useCallback((nuevoCampo: CampoConfig) => {
    setCampos((prev) => [...prev, nuevoCampo])
    setModalEditorAbierto(false)
    toast.success('Campo agregado', {
      description: `"${nuevoCampo.label}" agregado correctamente`,
    })
  }, [])

  // ============================================
  // HANDLERS: EDITAR
  // ============================================

  const handleEditarCampo = useCallback((campo: CampoConfig) => {
    setCampoEditando(campo)
    setModoEditor('editar')
    setModalEditorAbierto(true)
  }, [])

  const handleConfirmarEditar = useCallback((campoActualizado: CampoConfig) => {
    setCampos((prev) =>
      prev.map((c) => (c.nombre === campoEditando?.nombre ? campoActualizado : c))
    )
    setModalEditorAbierto(false)
    toast.success('Campo actualizado', {
      description: `"${campoActualizado.label}" actualizado correctamente`,
    })
  }, [campoEditando])

  // ============================================
  // HANDLERS: ELIMINAR
  // ============================================

  const handleEliminarCampo = useCallback((nombreCampo: string) => {
    const campo = campos.find((c) => c.nombre === nombreCampo)
    if (!campo) return

    // Confirmación
    if (!window.confirm(`¿Eliminar el campo "${campo.label}"?`)) return

    setCampos((prev) => prev.filter((c) => c.nombre !== nombreCampo))
    toast.success('Campo eliminado', {
      description: `"${campo.label}" eliminado correctamente`,
    })
  }, [campos])

  // ============================================
  // HANDLERS: REORDENAR (DRAG & DROP)
  // ============================================

  const handleReordenar = useCallback((camposReordenados: CampoConfig[]) => {
    // Actualizar propiedad "orden" según nuevo índice
    const camposConOrdenActualizado = camposReordenados.map((campo, index) => ({
      ...campo,
      orden: index + 1,
    }))
    setCampos(camposConOrdenActualizado)
  }, [])

  // ============================================
  // HANDLERS: GUARDAR
  // ============================================

  const handleGuardar = useCallback(() => {
    // Validar que haya al menos un campo
    if (campos.length === 0) {
      toast.error('Configuración inválida', {
        description: 'Debe haber al menos un campo configurado',
      })
      return
    }

    // Validar que todos los campos tengan nombre único
    const nombres = campos.map((c) => c.nombre)
    const nombresUnicos = new Set(nombres)
    if (nombres.length !== nombresUnicos.size) {
      toast.error('Nombres duplicados', {
        description: 'Hay campos con el mismo nombre',
      })
      return
    }

    // 🔥 Validar que solo haya UN campo con rol='monto'
    const camposMonto = campos.filter((c) => c.rol === 'monto')
    if (camposMonto.length === 0) {
      toast.error('Campo de Monto obligatorio', {
        description: 'Debe configurar al menos un campo de Monto Principal',
      })
      return
    }
    if (camposMonto.length > 1) {
      toast.error('Múltiples campos de Monto', {
        description: `Solo puede haber UN campo de Monto Principal. Actualmente hay ${camposMonto.length} campos con ese rol.`,
      })
      return
    }

    // Guardar en BD
    actualizar(
      {
        tipoId,
        configuracion: { campos },
      },
      {
        onSuccess: () => {
          onClose()
        },
      }
    )
  }, [campos, tipoId, actualizar, onClose])

  // ============================================
  // HANDLERS: CANCELAR
  // ============================================

  const handleCancelar = useCallback(() => {
    // Confirmar si hay cambios sin guardar
    const tienesCambios = JSON.stringify(campos) !== JSON.stringify(configuracionInicial.campos)
    if (tienesCambios) {
      if (!window.confirm('¿Descartar los cambios sin guardar?')) return
    }
    onClose()
  }, [campos, configuracionInicial, onClose])

  const handleCancelarEditor = useCallback(() => {
    setModalEditorAbierto(false)
  }, [])

  // ============================================
  // RETURN
  // ============================================

  return {
    // Estado
    campos,
    campoEditando,
    modoEditor,
    modalEditorAbierto,
    guardando,

    // Handlers
    handleAgregarCampo,
    handleConfirmarAgregar,
    handleEditarCampo,
    handleConfirmarEditar,
    handleEliminarCampo,
    handleReordenar,
    handleGuardar,
    handleCancelar,
    handleCancelarEditor,
  }
}

/**
 * FormularioConfiguracion - Formulario para crear/editar configuración
 * ✅ React Hook Form + Zod
 * ✅ Formato de moneda
 */

'use client'

import { useEffect } from 'react'

import { zodResolver } from '@hookform/resolvers/zod'
import { motion } from 'framer-motion'
import { AlertCircle, DollarSign, FileText, Tag, Type } from 'lucide-react'
import { useForm } from 'react-hook-form'
import { z } from 'zod'

import { configuracionService, type ConfiguracionRecargo } from '../services/configuracion.service'

const schema = z.object({
  tipo: z.string().min(1, 'El tipo es obligatorio'),
  nombre: z.string().min(3, 'El nombre debe tener al menos 3 caracteres'),
  valor: z.number().min(1, 'El valor debe ser mayor a 0'),
  descripcion: z.string().optional(),
  activo: z.boolean(),
})

type FormData = z.infer<typeof schema>

interface Props {
  configuracion?: ConfiguracionRecargo | null
  onGuardar: (datos: any) => Promise<boolean>
  onCancelar: () => void
}

export function FormularioConfiguracion({ configuracion, onGuardar, onCancelar }: Props) {
  const esEdicion = !!configuracion

  const {
    register,
    handleSubmit,
    setValue,
    watch,
    formState: { errors, isSubmitting },
    reset,
  } = useForm<FormData>({
    resolver: zodResolver(schema),
    defaultValues: {
      tipo: '',
      nombre: '',
      valor: 0,
      descripcion: '',
      activo: true,
    },
  })

  // Cargar datos si es edición
  useEffect(() => {
    if (configuracion) {
      reset({
        tipo: configuracion.tipo,
        nombre: configuracion.nombre,
        valor: configuracion.valor,
        descripcion: configuracion.descripcion || '',
        activo: configuracion.activo ?? true,
      })
    }
  }, [configuracion, reset])

  const onSubmit = async (datos: FormData) => {
    const exito = await onGuardar(datos)
    if (exito) {
      reset()
      onCancelar()
    }
  }

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency',
      currency: 'COP',
      minimumFractionDigits: 0,
    }).format(value || 0)
  }

  const valorActual = watch('valor')
  const tiposDisponibles = configuracionService.getTiposDisponibles()

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
      {/* Tipo */}
      <div className="space-y-2">
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
          Tipo <span className="text-red-500">*</span>
        </label>
        <div className="relative">
          <Tag className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <select
            {...register('tipo')}
            disabled={esEdicion}
            className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900/50 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all disabled:opacity-50"
          >
            <option value="">Selecciona un tipo</option>
            {tiposDisponibles.map((tipo) => (
              <option key={tipo.value} value={tipo.value}>
                {tipo.label}
              </option>
            ))}
          </select>
        </div>
        {errors.tipo && (
          <p className="flex items-center gap-1 text-xs text-red-600 dark:text-red-400">
            <AlertCircle className="w-3 h-3" />
            {errors.tipo.message}
          </p>
        )}
      </div>

      {/* Nombre */}
      <div className="space-y-2">
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
          Nombre <span className="text-red-500">*</span>
        </label>
        <div className="relative">
          <Type className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            {...register('nombre')}
            type="text"
            placeholder="Ej: Gastos Notariales 2025"
            className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900/50 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all"
          />
        </div>
        {errors.nombre && (
          <p className="flex items-center gap-1 text-xs text-red-600 dark:text-red-400">
            <AlertCircle className="w-3 h-3" />
            {errors.nombre.message}
          </p>
        )}
      </div>

      {/* Valor */}
      <div className="space-y-2">
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
          Valor <span className="text-red-500">*</span>
        </label>
        <div className="relative">
          <DollarSign className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            {...register('valor', { valueAsNumber: true })}
            type="number"
            step="100000"
            min="0"
            placeholder="5000000"
            className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900/50 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all"
          />
        </div>
        {errors.valor && (
          <p className="flex items-center gap-1 text-xs text-red-600 dark:text-red-400">
            <AlertCircle className="w-3 h-3" />
            {errors.valor.message}
          </p>
        )}
        <p className="text-xs text-gray-500 dark:text-gray-400">
          Valor formateado: {formatCurrency(valorActual)}
        </p>
      </div>

      {/* Descripción */}
      <div className="space-y-2">
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
          Descripción (Opcional)
        </label>
        <div className="relative">
          <FileText className="absolute left-3 top-3 w-4 h-4 text-gray-400" />
          <textarea
            {...register('descripcion')}
            rows={3}
            placeholder="Descripción del recargo..."
            className="w-full pl-10 pr-4 py-2.5 bg-gray-50 dark:bg-gray-900/50 border-2 border-gray-200 dark:border-gray-700 rounded-lg focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-all resize-none"
          />
        </div>
      </div>

      {/* Activo */}
      <div className="flex items-center gap-3">
        <input
          {...register('activo')}
          id="activo"
          type="checkbox"
          className="w-5 h-5 rounded border-2 border-gray-300 dark:border-gray-600 text-blue-500 focus:ring-2 focus:ring-blue-500/20 transition-colors"
        />
        <label htmlFor="activo" className="text-sm font-medium text-gray-700 dark:text-gray-300 cursor-pointer">
          Configuración activa
        </label>
      </div>

      {/* Botones */}
      <div className="flex items-center gap-3 pt-4">
        <motion.button
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          type="submit"
          disabled={isSubmitting}
          className="flex-1 px-4 py-2.5 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-lg font-medium shadow-lg shadow-blue-500/30 hover:shadow-xl hover:shadow-blue-500/40 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
        >
          {isSubmitting ? 'Guardando...' : esEdicion ? 'Actualizar' : 'Crear'}
        </motion.button>
        <motion.button
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          type="button"
          onClick={onCancelar}
          className="px-4 py-2.5 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg font-medium hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors"
        >
          Cancelar
        </motion.button>
      </div>
    </form>
  )
}

/**
 * React Query Hooks: Entidades Financieras
 *
 * Custom hooks para gestión de estado de servidor con React Query v5.
 * Implementa cache strategies, optimistic updates y error handling.
 */

'use client'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { showEntitySuccessToast } from '@/components/toasts/custom-toasts'
import { logger } from '@/lib/utils/logger'

import { entidadesFinancierasService } from '../services/entidades-financieras.service'
import type {
    ActualizarEntidadFinancieraDTO,
    CrearEntidadFinancieraDTO,
    EntidadesFinancierasFilters,
    EntidadesFinancierasOrderBy,
    EntidadFinanciera,
    EntidadFinancieraOption,
    TipoEntidadFinanciera,
} from '../types/entidades-financieras.types'

// =====================================================
// QUERY KEYS FACTORY
// =====================================================

export const entidadesFinancierasKeys = {
  all: ['entidades-financieras'] as const,
  lists: () => [...entidadesFinancierasKeys.all, 'list'] as const,
  list: (filters?: EntidadesFinancierasFilters, orderBy?: EntidadesFinancierasOrderBy) =>
    [...entidadesFinancierasKeys.lists(), { filters, orderBy }] as const,
  details: () => [...entidadesFinancierasKeys.all, 'detail'] as const,
  detail: (id: string) => [...entidadesFinancierasKeys.details(), id] as const,
  stats: () => [...entidadesFinancierasKeys.all, 'stats'] as const,
  activas: (tipo?: TipoEntidadFinanciera) =>
    [...entidadesFinancierasKeys.all, 'activas', tipo] as const,
}

// =====================================================
// QUERY HOOKS
// =====================================================

/**
 * Hook principal: Obtener lista de entidades con filtros
 */
export function useEntidadesFinancieras(
  filters?: EntidadesFinancierasFilters,
  orderBy?: EntidadesFinancierasOrderBy
) {
  return useQuery({
    queryKey: entidadesFinancierasKeys.list(filters, orderBy),
    queryFn: async () => {
      const result = await entidadesFinancierasService.getAll(filters, orderBy)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    staleTime: 5 * 60 * 1000, // 5 minutos
    gcTime: 10 * 60 * 1000, // 10 minutos
  })
}

/**
 * Hook: Obtener entidad por ID
 */
export function useEntidadFinanciera(id: string) {
  return useQuery({
    queryKey: entidadesFinancierasKeys.detail(id),
    queryFn: async () => {
      const result = await entidadesFinancierasService.getById(id)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    enabled: !!id,
    staleTime: 5 * 60 * 1000,
    gcTime: 10 * 60 * 1000,
  })
}

/**
 * Hook: Obtener estadísticas
 */
export function useEntidadesFinancierasStats() {
  return useQuery({
    queryKey: entidadesFinancierasKeys.stats(),
    queryFn: async () => {
      const result = await entidadesFinancierasService.getStats()

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    staleTime: 5 * 60 * 1000,
    gcTime: 10 * 60 * 1000,
  })
}

/**
 * Hook optimizado: Obtener solo entidades activas para formularios
 */
export function useEntidadesFinancierasActivas(tipo?: TipoEntidadFinanciera) {
  return useQuery({
    queryKey: entidadesFinancierasKeys.activas(tipo),
    queryFn: async () => {
      const result = await entidadesFinancierasService.getActivas(tipo)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    staleTime: 10 * 60 * 1000, // 10 minutos (datos estables)
    gcTime: 15 * 60 * 1000,
  })
}

/**
 * Hook: Opciones para <select> / Combobox
 */
export function useEntidadesFinancierasOptions(tipo?: TipoEntidadFinanciera) {
  return useQuery({
    queryKey: [...entidadesFinancierasKeys.activas(tipo), 'options'],
    queryFn: async () => {
      const result = await entidadesFinancierasService.getActivas(tipo)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      const options: EntidadFinancieraOption[] = result.data.map((entidad) => ({
        value: entidad.id,
        label: entidad.nombre,
        tipo: entidad.tipo,
        codigo: entidad.codigo,
        activo: entidad.activo,
      }))

      return options
    },
    staleTime: 10 * 60 * 1000,
    gcTime: 15 * 60 * 1000,
  })
}

// =====================================================
// MUTATION HOOKS
// =====================================================

/**
 * Mutation: Crear entidad
 */
export function useCrearEntidadFinanciera() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async (dto: CrearEntidadFinancieraDTO) => {
      const result = await entidadesFinancierasService.create(dto)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    onSuccess: (data) => {
      // Invalidar todas las queries relacionadas
      queryClient.invalidateQueries({ queryKey: entidadesFinancierasKeys.all })

      showEntitySuccessToast({ entityName: data.nombre, action: 'created' })
    },
    onError: (error: Error) => {
      logger.error('Error al crear entidad financiera:', error)
      toast.error('Error al crear entidad', {
        description: error.message,
      })
    },
  })
}

/**
 * Mutation: Actualizar entidad
 */
export function useActualizarEntidadFinanciera() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async ({ id, dto }: { id: string; dto: ActualizarEntidadFinancieraDTO }) => {
      const result = await entidadesFinancierasService.update(id, dto)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    onMutate: async ({ id, dto }) => {
      // Cancel outgoing refetches
      await queryClient.cancelQueries({ queryKey: entidadesFinancierasKeys.detail(id) })

      // Snapshot the previous value
      const previousData = queryClient.getQueryData<EntidadFinanciera>(
        entidadesFinancierasKeys.detail(id)
      )

      // Optimistically update
      if (previousData) {
        queryClient.setQueryData<EntidadFinanciera>(entidadesFinancierasKeys.detail(id), {
          ...previousData,
          ...dto,
        })
      }

      return { previousData }
    },
    onError: (error: Error, variables, context) => {
      // Rollback on error
      if (context?.previousData) {
        queryClient.setQueryData(
          entidadesFinancierasKeys.detail(variables.id),
          context.previousData
        )
      }

      logger.error('Error al actualizar entidad financiera:', error)
      toast.error('Error al actualizar entidad', {
        description: error.message,
      })
    },
    onSuccess: (data) => {
      // Invalidar queries
      queryClient.invalidateQueries({ queryKey: entidadesFinancierasKeys.all })

      showEntitySuccessToast({ entityName: data.nombre, action: 'updated' })
    },
  })
}

/**
 * Mutation: Desactivar entidad (soft delete)
 */
export function useEliminarEntidadFinanciera() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async (id: string) => {
      const result = await entidadesFinancierasService.softDelete(id)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: entidadesFinancierasKeys.all })

      toast.success('✓ Entidad desactivada', {
        description: `${data.nombre} ya no aparecerá en las opciones de selección`,
      })
    },
    onError: (error: Error) => {
      logger.error('Error al desactivar entidad financiera:', error)
      toast.error('Error al desactivar entidad', {
        description: error.message,
      })
    },
  })
}

/**
 * Mutation: Reactivar entidad
 */
export function useReactivarEntidadFinanciera() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async (id: string) => {
      const result = await entidadesFinancierasService.reactivate(id)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: entidadesFinancierasKeys.all })

      toast.success('✓ Entidad reactivada exitosamente', {
        description: `${data.nombre} vuelve a estar disponible para usar`,
      })
    },
    onError: (error: Error) => {
      logger.error('Error al reactivar entidad financiera:', error)
      toast.error('Error al reactivar entidad', {
        description: error.message,
      })
    },
  })
}

/**
 * Mutation: Reordenar entidades
 */
export function useReordenarEntidadesFinancieras() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async (updates: Array<{ id: string; orden: number }>) => {
      const result = await entidadesFinancierasService.reordenar(updates)

      if (!result.success) {
        throw new Error((result as any).error)
      }

      return result.data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: entidadesFinancierasKeys.all })

      toast.success('Orden actualizado', {
        description: 'El orden de las entidades se actualizó correctamente',
      })
    },
    onError: (error: Error) => {
      logger.error('Error al reordenar entidades:', error)
      toast.error('Error al reordenar', {
        description: error.message,
      })
    },
  })
}

/**
 * ============================================
 * HOOK: Gestión de Plantillas de Requisitos
 * ============================================
 *
 * Hook con React Query para gestionar plantillas de requisitos
 * y su asignación a tipos de fuente de pago.
 *
 * @version 1.0.0 - 2025-12-12
 */

'use client'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'

import { PlantillasRequisitosService } from '../services/plantillas-requisitos.service'

// ============================================
// QUERY KEYS
// ============================================

export const PLANTILLAS_QUERY_KEYS = {
  all: ['plantillas-requisitos'] as const,
  list: () => [...PLANTILLAS_QUERY_KEYS.all, 'list'] as const,
  byTipo: (tipoFuente: string) => [...PLANTILLAS_QUERY_KEYS.all, 'tipo', tipoFuente] as const,
  configuradas: (tipoFuente: string) => [...PLANTILLAS_QUERY_KEYS.all, 'configuradas', tipoFuente] as const,
}

// ============================================
// HOOKS
// ============================================

/**
 * Hook para obtener todas las plantillas disponibles
 */
export function usePlantillasRequisitos() {
  return useQuery({
    queryKey: PLANTILLAS_QUERY_KEYS.list(),
    queryFn: () => PlantillasRequisitosService.obtenerPlantillas(),
    staleTime: 5 * 60 * 1000, // 5 minutos (plantillas no cambian frecuentemente)
    gcTime: 30 * 60 * 1000, // 30 minutos
  })
}

/**
 * Hook para obtener requisitos configurados de un tipo de fuente
 */
export function useRequisitosPorTipo(tipoFuente: string | undefined) {
  return useQuery({
    queryKey: PLANTILLAS_QUERY_KEYS.byTipo(tipoFuente || ''),
    queryFn: () => PlantillasRequisitosService.obtenerRequisitosPorTipo(tipoFuente!),
    enabled: !!tipoFuente,
    staleTime: 30000, // 30 segundos
  })
}

/**
 * Hook para obtener IDs de plantillas configuradas
 */
export function usePlantillasConfiguradas(tipoFuente: string | undefined) {
  return useQuery({
    queryKey: PLANTILLAS_QUERY_KEYS.configuradas(tipoFuente || ''),
    queryFn: () => PlantillasRequisitosService.obtenerPlantillasConfiguradas(tipoFuente!),
    enabled: !!tipoFuente,
    staleTime: 30000,
  })
}

/**
 * Hook para configurar requisitos de un tipo de fuente
 */
export function useConfigurarRequisitos() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: ({
      tipoFuente,
      plantillasSeleccionadas,
    }: {
      tipoFuente: string
      plantillasSeleccionadas: string[]
    }) => PlantillasRequisitosService.configurarRequisitos(tipoFuente, plantillasSeleccionadas),
    onSuccess: (_, variables) => {
      // Invalidar queries relacionadas
      queryClient.invalidateQueries({
        queryKey: PLANTILLAS_QUERY_KEYS.byTipo(variables.tipoFuente),
      })
      queryClient.invalidateQueries({
        queryKey: PLANTILLAS_QUERY_KEYS.configuradas(variables.tipoFuente),
      })
    },
  })
}

/**
 * React Query Hooks: Tipos de Fuentes de Pago
 *
 * Hooks profesionales con @tanstack/react-query para gestión de estado del servidor.
 *
 * Ventajas de React Query:
 * - Cache automático inteligente
 * - Sincronización en tiempo real
 * - Optimistic updates
 * - Invalidación automática
 * - Manejo de loading/error states
 * - Deduplicación de requests
 *
 * Patrón: Custom Hooks + React Query
 */

'use client'

import { useMutation, useQuery, useQueryClient, type UseMutationOptions, type UseQueryOptions } from '@tanstack/react-query'
import { toast } from 'sonner'

import {
    TiposFuentesPagoService
} from '../services'
import type {
    ActualizarTipoFuentePagoDTO,
    CrearTipoFuentePagoDTO,
    OrderDirection,
    TipoFuentePago,
    TipoFuentePagoFilters,
    TipoFuentePagoOption,
    TipoFuentePagoOrderBy
} from '../types'

// =====================================================
// QUERY KEYS (centralizadas para invalidación)
// =====================================================

export const tiposFuentesPagoKeys = {
  all: ['tipos-fuentes-pago'] as const,
  lists: () => [...tiposFuentesPagoKeys.all, 'list'] as const,
  list: (filters: TipoFuentePagoFilters, orderBy: TipoFuentePagoOrderBy, direction: OrderDirection) =>
    [...tiposFuentesPagoKeys.lists(), { filters, orderBy, direction }] as const,
  options: () => [...tiposFuentesPagoKeys.all, 'options'] as const,
  details: () => [...tiposFuentesPagoKeys.all, 'detail'] as const,
  detail: (id: string) => [...tiposFuentesPagoKeys.details(), id] as const,
  detailByCodigo: (codigo: string) => [...tiposFuentesPagoKeys.all, 'codigo', codigo] as const,
}

// =====================================================
// QUERIES (READ)
// =====================================================

/**
 * Hook: Obtener todos los tipos de fuentes de pago
 *
 * @example
 * ```typescript
 * const { data, isLoading, error } = useTiposFuentesPago({
 *   filters: { activo: true },
 *   orderBy: 'orden'
 * })
 * ```
 */
export function useTiposFuentesPago(
  filters: TipoFuentePagoFilters = {},
  orderBy: TipoFuentePagoOrderBy = 'orden',
  direction: OrderDirection = 'asc',
  options?: Omit<UseQueryOptions<TipoFuentePago[], Error>, 'queryKey' | 'queryFn'>
) {
  const service = new TiposFuentesPagoService()

  return useQuery({
    queryKey: tiposFuentesPagoKeys.list(filters, orderBy, direction),
    queryFn: async () => {
      const result = await service.getAll(filters, orderBy, direction)

      if (!result.success) {
        throw new Error((result as any).error?.mensaje ?? String((result as any).error))
      }

      return result.data
    },
    staleTime: 5 * 60 * 1000, // 5 minutos (datos relativamente estáticos)
    gcTime: 10 * 60 * 1000, // 10 minutos en cache
    ...options,
  })
}

/**
 * Hook: Obtener tipos activos como opciones para selects
 *
 * @example
 * ```typescript
 * const { data: opciones = [] } = useTiposFuentesPagoOptions()
 *
 * <select>
 *   {opciones.map(opt => (
 *     <option key={opt.value} value={opt.value}>{opt.label}</option>
 *   ))}
 * </select>
 * ```
 */
export function useTiposFuentesPagoOptions(
  options?: Omit<UseQueryOptions<TipoFuentePagoOption[], Error>, 'queryKey' | 'queryFn'>
) {
  const service = new TiposFuentesPagoService()

  return useQuery({
    queryKey: tiposFuentesPagoKeys.options(),
    queryFn: async () => {
      const result = await service.getOptionsActivas()

      if (!result.success) {
        throw new Error((result as any).error?.mensaje ?? String((result as any).error))
      }

      return result.data
    },
    staleTime: 10 * 60 * 1000, // 10 minutos (muy estable)
    gcTime: 30 * 60 * 1000, // 30 minutos en cache
    ...options,
  })
}

/**
 * Hook: Obtener un tipo de fuente de pago por ID
 *
 * @example
 * ```typescript
 * const { data: tipo } = useTipoFuentePago('uuid-123')
 * ```
 */
export function useTipoFuentePago(
  id: string | null,
  options?: Omit<UseQueryOptions<TipoFuentePago, Error>, 'queryKey' | 'queryFn'>
) {
  const service = new TiposFuentesPagoService()

  return useQuery({
    queryKey: tiposFuentesPagoKeys.detail(id!),
    queryFn: async () => {
      const result = await service.getById(id!)

      if (!result.success) {
        throw new Error((result as any).error?.mensaje ?? String((result as any).error))
      }

      return result.data
    },
    enabled: !!id, // Solo ejecutar si hay ID
    staleTime: 5 * 60 * 1000,
    ...options,
  })
}

