 */
export function useEliminarTipoFuentePago(
  options?: Omit<UseMutationOptions<TipoFuentePago, Error, string>, 'mutationFn'>
) {
  const queryClient = useQueryClient()
  const service = new TiposFuentesPagoService()

  return useMutation({
