      })
    },
  })
}

'use client'

import { useState } from 'react'

import { useQueryClient } from '@tanstack/react-query'

import { supabase } from '@/lib/supabase/client'
import { documentosPendientesKeys } from '@/modules/clientes/types/documentos-pendientes.types'

import { DocumentosEliminacionService } from '../services/documentos-eliminacion.service'
import type { TipoEntidad } from '../types/entidad.types'

export interface ConfirmacionEliminarState {
  isOpen: boolean
  detectando: boolean
  esDocumentoCritico: boolean
  entidadAfectada: string | null
  documentoId: string | null
  totalVersiones: number
}

const ESTADO_INICIAL: ConfirmacionEliminarState = {
  isOpen: false,
  detectando: false,
  esDocumentoCritico: false,
  entidadAfectada: null,
  documentoId: null,
  totalVersiones: 1,
}

const TABLAS_POR_ENTIDAD: Record<TipoEntidad, string> = {
  proyecto: 'documentos_proyecto',
  cliente: 'documentos_cliente',
  vivienda: 'documentos_vivienda',
}

async function detectarCriticidad(documento: any): Promise<{ esCritico: boolean; entidad: string | null }> {
  // Con el FK requisito_config_id, la criticidad se detecta directamente:
  // - Subido desde el banner → requisito_config_id NOT NULL → crítico
  // - Subido con vinculación manual a fuente → fuente_pago_relacionada NOT NULL → crítico
  const esCritico = !!documento.requisito_config_id || !!documento.fuente_pago_relacionada
  const entidad = documento.metadata?.entidad_fuente || documento.entidad || null
  return { esCritico, entidad }
}

async function contarVersionesActivas(documento: any, tipoEntidad: TipoEntidad): Promise<number> {
  const tabla = TABLAS_POR_ENTIDAD[tipoEntidad]
  const padreId = documento.documento_padre_id || documento.id
  const { count } = await supabase
    .from(tabla as any)
    .select('*', { count: 'exact', head: true })
    .or(`id.eq.${padreId},documento_padre_id.eq.${padreId}`)
    .eq('estado', 'activo')
  return count ?? 1
}

/**
 * Hook para eliminar documentos con confirmación inteligente.
 *
 * Dos flujos de uso:
 *
 * A) El componente maneja su propia lógica de refresh (DocumentoCard):
 *    - Llama abrirConfirmacion(doc, tipoEntidad)
 *    - Renderiza ConfirmacionModal con onConfirm = su propia función de borrado
 *
 * B) El hook maneja todo (SeccionDocumentosIdentidad, etc.):
 *    - Llama abrirConfirmacion(doc, tipoEntidad)
 *    - Renderiza ConfirmacionModal con onConfirm = ejecutarEliminacion(tipoEntidad, onSuccess)
 */
export function useEliminarDocumento() {
  const [confirmacion, setConfirmacion] = useState<ConfirmacionEliminarState>(ESTADO_INICIAL)
  const [eliminando, setEliminando] = useState(false)
  const queryClient = useQueryClient()

  const abrirConfirmacion = async (documento: any, tipoEntidad: TipoEntidad = 'cliente') => {
    // Detectar primero, abrir después → sin flash de modal intermedio
    const [criticidad, totalVersiones] = await Promise.all([
      detectarCriticidad(documento),
      contarVersionesActivas(documento, tipoEntidad),
    ])

    setConfirmacion({
      isOpen: true,
      detectando: false,
      esDocumentoCritico: criticidad.esCritico,
      entidadAfectada: criticidad.entidad,
      documentoId: documento.id,
      totalVersiones,
    })
  }

  const cerrarConfirmacion = () => {
    setConfirmacion(prev => ({ ...prev, isOpen: false }))
  }

  /**
   * Ejecuta el borrado en BD. Usar cuando el hook maneja toda la lógica.
   * Si el componente padre tiene su propio handler (ej: DocumentoCard con onDelete prop),
   * llamar ese handler directamente en onConfirm del modal en lugar de esto.
   */
  const ejecutarEliminacion = async (tipoEntidad: TipoEntidad, onSuccess?: () => void) => {
    if (!confirmacion.documentoId) return
    setEliminando(true)
    try {
      await DocumentosEliminacionService.eliminarDocumento(confirmacion.documentoId, tipoEntidad)
      // Si era un documento crítico, el pendiente vuelve a aparecer en la vista SQL
      // inmediatamente — invalidar cache de React Query para que se muestre al instante
      if (confirmacion.esDocumentoCritico) {
        await queryClient.invalidateQueries({ queryKey: documentosPendientesKeys.all })
      }
      onSuccess?.()
      cerrarConfirmacion()
    } finally {
      setEliminando(false)
    }
  }

  return {
    abrirConfirmacion,
    cerrarConfirmacion,
    ejecutarEliminacion,
    confirmacion,
    eliminando,
  }
}

/**
 * Hook para manejar expansión y selección de versiones eliminadas
 * en cards de Papelera
 *
 * Funcionalidad:
 * - Expandir/colapsar lista de versiones
 * - Seleccionar versiones individuales
 * - Restaurar versiones seleccionadas
 */

import { useMemo, useState } from 'react'

import { useQuery, useQueryClient } from '@tanstack/react-query'

import { DocumentosService } from '../services/documentos.service'
import type { TipoEntidad } from '../types/entidad.types'

interface UseVersionesEliminadasCardProps {
  documentoId: string
  documentoTitulo: string
  modulo: 'proyectos' | 'viviendas' | 'clientes'
  tipoEntidad?: TipoEntidad
}

export function useVersionesEliminadasCard({
  documentoId,
  documentoTitulo,
  modulo,
  tipoEntidad = 'proyecto',
}: UseVersionesEliminadasCardProps) {
  const queryClient = useQueryClient()

  // Estado de expansión del card
  const [isExpanded, setIsExpanded] = useState(false)

  // Query para obtener versiones eliminadas (solo cuando está expandido)
  const {
    data: versiones = [],
    isLoading,
    error,
  } = useQuery({
    queryKey: ['versiones-eliminadas', documentoId, modulo, tipoEntidad],
    queryFn: async () => {

      // Usar servicio correcto según módulo
      if (modulo === 'viviendas') {
        // Importar dinámicamente para viviendas (path directo al archivo)
        const { DocumentosEliminacionService: ViviendaEliminacionService } = await import('@/modules/viviendas/services/documentos/documentos-eliminacion.service')
        return ViviendaEliminacionService.obtenerVersionesEliminadas(documentoId)
      }

      // Por defecto, proyectos
      return DocumentosService.obtenerVersionesEliminadas(documentoId, tipoEntidad)
    },
    enabled: isExpanded, // Solo cargar cuando se expande
    staleTime: 30000, // 30 segundos
  })

  // Toggle expansión
  const toggleExpansion = () => {
    setIsExpanded(!isExpanded)
  }

  // Estadísticas (todas las versiones son eliminadas)
  const stats = useMemo(
    () => {
      return {
        totalVersiones: versiones.length,
        eliminadas: versiones.length, // Todas son eliminadas
      }
    },
    [versiones.length]
  )

  return {
    // Estado
    isExpanded,
    versiones,
    isLoading,
    error,
    stats,

    // Acciones
    toggleExpansion,
  }
}

// ============================================
// SCHEMAS: Validaciones para Documentos
// ============================================

import { z } from 'zod'

// ============================================
// Constantes de Validación
// ============================================

export const MAX_FILE_SIZE = 50 * 1024 * 1024 // 50 MB
export const MIN_FILE_SIZE = 1024 // 1 KB

export const TIPOS_MIME_PERMITIDOS = [
  // Documentos
  'application/pdf',

  // Imágenes
  'image/jpeg',
  'image/jpg',
  'image/png',
  'image/webp',

  // Office
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document', // .docx
  'application/msword', // .doc
  'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet', // .xlsx
  'application/vnd.ms-excel', // .xls
  'application/vnd.openxmlformats-officedocument.presentationml.presentation', // .pptx
  'application/vnd.ms-powerpoint', // .ppt

  // Comprimidos
  'application/zip',
  'application/x-zip-compressed',
  'application/x-rar-compressed',

  // CAD
  'application/dwg',
  'application/dxf',
  'image/vnd.dwg',
  'image/vnd.dxf',

  // Texto
  'text/plain',
] as const

// ============================================
// Schema: Categoría de Documento
// ============================================

export const categoriaFormSchema = z.object({
  nombre: z
    .string()
    .min(2, 'El nombre debe tener al menos 2 caracteres')
    .max(100, 'El nombre es demasiado largo (máx. 100 caracteres)')
    .trim()
    .refine(val => val.length > 0, 'El nombre es requerido'),

  descripcion: z
    .string()
    .max(500, 'La descripción es demasiado larga (máx. 500 caracteres)')
    .optional()
    .or(z.literal('')),

  color: z
    .string()
    .regex(/^[a-z]+$/, 'Color inválido')
    .default('blue'),

  icono: z.string().min(1, 'Debe seleccionar un ícono').default('Folder'),

  // Nuevos campos para sistema flexible
  esGlobal: z.boolean().optional(),
  modulosPermitidos: z.array(z.enum(['proyectos', 'clientes', 'viviendas'])).optional(),
})

export type CategoriaFormData = z.infer<typeof categoriaFormSchema>

// ============================================
// Schema: Documento
// ============================================

export const documentoFormSchema = z.object({
  // Campo obligatorio
  titulo: z
    .string()
    .min(3, 'El título debe tener al menos 3 caracteres')
    .max(200, 'El título es demasiado largo (máx. 200 caracteres)')
    .trim()
    .refine(val => val.length > 0, 'El título es requerido'),

  // Campos opcionales
  descripcion: z
    .string()
    .max(1000, 'La descripción es demasiado larga (máx. 1000 caracteres)')
    .optional()
    .or(z.literal('')),

  categoria_id: z
    .string()
    .uuid('ID de categoría inválido')
    .optional()
    .or(z.literal(''))
    .or(z.null()),

  fecha_documento: z
    .string()
    .optional()
    .or(z.literal(''))
    .refine(val => {
      if (!val) return true
      const fecha = new Date(val)
      return !isNaN(fecha.getTime())
    }, 'Fecha inválida')
    .refine(val => {
      if (!val) return true
      const fechaDocumento = new Date(val + 'T12:00:00') // Hora mediodía para evitar timezone issues
      const hoy = new Date()
      hoy.setHours(23, 59, 59, 999) // Final del día actual
      return fechaDocumento <= hoy
    }, 'La fecha del documento no puede ser futura'),

  fecha_vencimiento: z
    .string()
    .optional()
    .or(z.literal(''))
    .refine(val => {
      if (!val) return true
      const fecha = new Date(val)
      return !isNaN(fecha.getTime())
    }, 'Fecha inválida'),

  es_importante: z.boolean().optional(),

  es_documento_identidad: z.boolean().optional(),

  metadata: z.record(z.string(), z.any()).optional(),
}).refine(
  (data) => {
    // Validación 1: No puede haber vencimiento sin fecha de emisión
    if (data.fecha_vencimiento && !data.fecha_documento) {
      return false
    }
    return true
  },
  {
    message: 'Debes especificar la fecha de emisión del documento antes de establecer una fecha de vencimiento',
    path: ['fecha_documento'], // El error se mostrará en el campo fecha_documento
  }
).refine(
  (data) => {
    // Validación 2: fecha_vencimiento debe ser posterior a fecha_documento
    if (!data.fecha_documento || !data.fecha_vencimiento) {
      return true // Si alguna no está definida, no validamos esta regla
    }

    const fechaDocumento = new Date(data.fecha_documento)
    const fechaVencimiento = new Date(data.fecha_vencimiento)

    return fechaVencimiento > fechaDocumento
  },
  {
    message: 'La fecha de vencimiento debe ser posterior a la fecha de emisión del documento',
    path: ['fecha_vencimiento'], // El error se mostrará en el campo fecha_vencimiento
  }
)

export type DocumentoFormData = z.infer<typeof documentoFormSchema>

// Schema para validación de archivo (separado porque File no se serializa bien)
export const archivoSchema = z.object({
  archivo: z
    .instanceof(File, { message: 'Debe seleccionar un archivo' })
    .refine(
      file => file.size >= MIN_FILE_SIZE,
      `El archivo es demasiado pequeño (mín. ${MIN_FILE_SIZE / 1024} KB)`
    )
    .refine(
      file => file.size <= MAX_FILE_SIZE,
      `El archivo supera el límite de ${MAX_FILE_SIZE / (1024 * 1024)} MB`
    )
    .refine(
      file => TIPOS_MIME_PERMITIDOS.includes(file.type as any),
      'Tipo de archivo no permitido'
    ),
})

// Schema completo combinado (para frontend)
export const documentoConArchivoSchema =
  documentoFormSchema.merge(archivoSchema)

export type DocumentoConArchivoFormData = z.infer<
  typeof documentoConArchivoSchema
>

// ============================================
// Helpers de Validación
// ============================================

export function validarNombreArchivo(nombre: string): {
  valido: boolean
  error?: string
} {
  // Caracteres prohibidos
  const caracteresProhibidos = /[<>:"|?*\x00-\x1f]/g
  if (caracteresProhibidos.test(nombre)) {
    return {
      valido: false,
      error: 'El nombre del archivo contiene caracteres no permitidos',
    }
  }

  // Longitud máxima
  if (nombre.length > 255) {
    return {
      valido: false,
      error: 'El nombre del archivo es demasiado largo (máx. 255 caracteres)',
    }
  }

  // Nombres reservados en Windows
  const nombresReservados = [
    'CON',
    'PRN',
    'AUX',
    'NUL',
    'COM1',
    'COM2',
    'LPT1',
    'LPT2',
  ]
  const nombreBase = nombre.split('.')[0].toUpperCase()
  if (nombresReservados.includes(nombreBase)) {
    return {
      valido: false,
      error: 'El nombre del archivo está reservado por el sistema',
    }
  }

  return { valido: true }
}

export function validarExtensionArchivo(
  nombre: string,
  tipoMime: string
): { valido: boolean; error?: string } {
  const extension = nombre.toLowerCase().split('.').pop()

  if (!extension) {
    return {
      valido: false,
      error: 'El archivo no tiene extensión',
    }
  }

  // Mapeo de extensiones esperadas por tipo MIME
  const extensionesValidas: Record<string, string[]> = {
    'application/pdf': ['pdf'],
    'image/jpeg': ['jpg', 'jpeg'],
    'image/png': ['png'],
    'image/webp': ['webp'],
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document': [
      'docx',
    ],
    'application/msword': ['doc'],
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet': [
      'xlsx',
    ],
    'application/vnd.ms-excel': ['xls'],
    'application/zip': ['zip'],
    'application/dwg': ['dwg'],
    'application/dxf': ['dxf'],
  }

  const extensionesEsperadas = extensionesValidas[tipoMime]

  if (extensionesEsperadas && !extensionesEsperadas.includes(extension)) {
    return {
      valido: false,
      error: `La extensión .${extension} no coincide con el tipo de archivo ${tipoMime}`,
    }
  }

  // Validar extensión doble (posible bypass de seguridad)
  const partes = nombre.split('.')
  if (partes.length > 2) {
    const extensionesPeligrosas = [
      'exe',
      'bat',
      'cmd',
      'sh',
      'ps1',
      'vbs',
      'js',
      'msi',
    ]
    const penultimaExt = partes[partes.length - 2].toLowerCase()
    if (extensionesPeligrosas.includes(penultimaExt)) {
      return {
        valido: false,
        error: 'Archivo potencialmente peligroso detectado (extensión doble)',
      }
    }
  }

  return { valido: true }
}

export function obtenerTipoArchivoLegible(tipoMime: string): string {
  const tipos: Record<string, string> = {
    'application/pdf': 'PDF',
    'image/jpeg': 'Imagen JPEG',
    'image/png': 'Imagen PNG',
    'image/webp': 'Imagen WebP',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document':
      'Word (DOCX)',
    'application/msword': 'Word (DOC)',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet':
      'Excel (XLSX)',
    'application/vnd.ms-excel': 'Excel (XLS)',
    'application/zip': 'ZIP',
    'application/dwg': 'AutoCAD (DWG)',
    'text/plain': 'Texto',
  }

  return tipos[tipoMime] || 'Documento'
}

// ============================================
// SERVICE: Gestión de Categorías de Documentos
// ============================================

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

import type {
    CategoriaDocumento,
    ModuloDocumento,
} from '../types/documento.types'

export class CategoriasService {
  /**
   * Obtener todas las categorías del usuario (DEPRECADO - usar obtenerCategoriasPorModulo)
   * @deprecated Usar obtenerCategoriasPorModulo() para sistema flexible multi-módulo
   */
  static async obtenerCategorias(
    userId: string,
    tipoEntidad?: 'proyecto' | 'cliente' | 'ambos'
  ): Promise<CategoriaDocumento[]> {
    const { data, error } = await supabase
      .from('categorias_documento')
      .select('id,user_id,nombre,descripcion,color,icono,orden,es_global,modulos_permitidos,fecha_creacion')
      .eq('user_id', userId)
      .order('orden', { ascending: true })
      .order('nombre', { ascending: true })

    if (error) throw error
    return (data || []) as CategoriaDocumento[]
  }

  /**
   * Obtener categorías disponibles para un módulo específico
   * Sistema flexible: solo categorías globales (compartidas entre todos los usuarios)
   * @param modulo - 'proyectos' | 'clientes' | 'viviendas'
   */
  static async obtenerCategoriasPorModulo(
    userId: string, // Mantenido por compatibilidad, no se usa para filtrar
    modulo: 'proyectos' | 'clientes' | 'viviendas'
  ): Promise<CategoriaDocumento[]> {
    // ✅ SOLO categorías globales (visibles para TODOS los usuarios: admin, contadora, ayudante)
    const { data, error } = await supabase
      .from('categorias_documento')
      .select('id,user_id,nombre,descripcion,color,icono,orden,es_global,modulos_permitidos,fecha_creacion')
      .eq('es_global', true) // Solo categorías globales del sistema
      .order('orden', { ascending: true })
      .order('nombre', { ascending: true })

    if (error) {
      logger.error('❌ Error al obtener categorías:', error)
      throw error
    }

    // Filtrar por módulo en JavaScript
    const filtradas = (data || []).filter((cat) => {
      // Si tiene modulos_permitidos y contiene el módulo actual
      if (cat.modulos_permitidos && Array.isArray(cat.modulos_permitidos)) {
        return cat.modulos_permitidos.includes(modulo)
      }

      // Si es global sin módulos específicos, incluir en todos
      return true
    })

    return filtradas as CategoriaDocumento[]
  }

  /**
   * Crear una nueva categoría con sistema flexible de módulos
   */
  static async crearCategoria(
    userId: string,
    categoria: Omit<CategoriaDocumento, 'id' | 'user_id' | 'fecha_creacion'>
  ): Promise<CategoriaDocumento> {
    const { data, error } = await supabase
      .from('categorias_documento')
      .insert({
        user_id: userId,
        nombre: categoria.nombre,
        descripcion: categoria.descripcion,
        color: categoria.color,
        icono: categoria.icono,
        orden: categoria.orden,
        es_global: categoria.es_global ?? false,
        // ✅ FIX: es_global NO vacía modulos_permitidos
        // es_global = true → visible para todos los usuarios (admin, contadora, ayudante)
        // modulos_permitidos → define en qué módulos aparece (proyectos, clientes, viviendas)
        modulos_permitidos: categoria.modulos_permitidos ?? ['proyectos'],
      })
      .select()
      .single()

    if (error) {
      logger.error('❌ Error al crear categoría:', error)
      throw error
    }

    return data as CategoriaDocumento
  }

  /**
   * Actualizar una categoría existente (ahora incluye es_global y modulos_permitidos)
   */
  static async actualizarCategoria(
    categoriaId: string,
    updates: any
  ): Promise<CategoriaDocumento> {
    // Convertir camelCase a snake_case y preparar datos
    const updateData: any = {}

    if (updates.nombre !== undefined) updateData.nombre = updates.nombre
    if (updates.descripcion !== undefined) updateData.descripcion = updates.descripcion
    if (updates.color !== undefined) updateData.color = updates.color
    if (updates.icono !== undefined) updateData.icono = updates.icono
    if (updates.orden !== undefined) updateData.orden = updates.orden

    // Manejar es_global (acepta tanto camelCase como snake_case)
    const esGlobal = updates.esGlobal ?? updates.es_global
    if (esGlobal !== undefined) {
      updateData.es_global = esGlobal
    }

    // Manejar modulos_permitidos independientemente de es_global
    if (updates.modulosPermitidos !== undefined || updates.modulos_permitidos !== undefined) {
      updateData.modulos_permitidos = updates.modulosPermitidos ?? updates.modulos_permitidos
    }

    const { data, error } = await supabase
      .from('categorias_documento')
      .update(updateData)
      .eq('id', categoriaId)
      .select()
      .single()

    if (error) throw error
    return {
      ...data,
      modulos_permitidos: data.modulos_permitidos as ModuloDocumento[],
    } as CategoriaDocumento
  }

  /**
   * Eliminar una categoría con validaciones
   * REQUIERE: Usuario con rol 'Administrador'
   */
  static async eliminarCategoria(categoriaId: string): Promise<void> {
    // ✅ VALIDACIÓN 0: Verificar que el usuario es Administrador
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
      throw new Error('Usuario no autenticado')
    }

    const { data: usuario, error: errorUsuario } = await supabase
      .from('usuarios')
      .select('rol')
      .eq('id', user.id)
      .single()

    if (errorUsuario || !usuario) {
      throw new Error('No se pudo verificar el rol del usuario')
    }

    if (usuario.rol !== 'Administrador') {
      throw new Error('Solo los administradores pueden eliminar categorías')
    }

    // ✅ VALIDACIÓN 1: Verificar si tiene documentos asociados en PROYECTOS
    const { count: countProyectos } = await supabase
      .from('documentos_proyecto')
      .select('id', { count: 'exact', head: true })
      .eq('categoria_id', categoriaId)

    // ✅ VALIDACIÓN 2: Verificar si tiene documentos asociados en CLIENTES
    const { count: countClientes } = await supabase
      .from('documentos_cliente')
      .select('id', { count: 'exact', head: true })
      .eq('categoria_id', categoriaId)

    // ✅ VALIDACIÓN 3: Verificar si tiene documentos asociados en VIVIENDAS
    const { count: countViviendas } = await supabase
      .from('documentos_vivienda')
      .select('id', { count: 'exact', head: true })
      .eq('categoria_id', categoriaId)

    const totalDocumentos = (countProyectos || 0) + (countClientes || 0) + (countViviendas || 0)

    if (totalDocumentos > 0) {
      const detalles = []
      if (countProyectos) detalles.push(`${countProyectos} en Proyectos`)
      if (countClientes) detalles.push(`${countClientes} en Clientes`)
      if (countViviendas) detalles.push(`${countViviendas} en Viviendas`)

      throw new Error(
        `No se puede eliminar esta categoría porque tiene ${totalDocumentos} documento(s) asociado(s): ${detalles.join(', ')}`
      )
    }

    // ✅ Si pasa todas las validaciones, eliminar
    const { error } = await supabase
      .from('categorias_documento')
      .delete()
      .eq('id', categoriaId)

    if (error) throw error
  }

  /**
   * Reordenar categorías
   */
  static async reordenarCategorias(
    categorias: Array<{ id: string; orden: number }>
  ): Promise<void> {
    const updates = categorias.map(({ id, orden }) =>
      supabase.from('categorias_documento').update({ orden }).eq('id', id)
    )

    await Promise.all(updates)
  }

  /**
   * Crear categorías por defecto para nuevo usuario
   * NOTA: Este método ya no es necesario porque la migración SQL
   * crea automáticamente las categorías cuando el usuario crea su primera categoría
   * @deprecated Las categorías se crean automáticamente en la migración SQL
   */
  static async crearCategoriasDefault(
    userId: string
  ): Promise<CategoriaDocumento[]> {
    // Ya no creamos categorías por defecto desde código
    // La migración SQL las crea automáticamente con el sistema flexible
    return []
  }

  /**
   * Verificar si el usuario tiene categorías
   */
  static async tieneCategorias(userId: string): Promise<boolean> {
    const { count, error } = await supabase
      .from('categorias_documento')
      .select('id', { count: 'exact', head: true })
      .eq('user_id', userId)

    if (error) throw error
    return (count || 0) > 0
  }

  /**
   * ✅ Crear categorías por defecto para módulo proyectos
   * Llama a la función SQL que crea las 5 categorías esenciales
   */
  static async crearCategoriasProyectosDefault(userId: string): Promise<void> {
    const { error } = await supabase.rpc('crear_categorias_proyectos_default', {
      p_user_id: userId
    })

    if (error) {
      logger.error('Error al crear categorías por defecto para proyectos:', error)
      throw error
    }
  }

  /**
   * ✅ Crear categorías por defecto para módulo viviendas
   * Llama a la función SQL que crea las 6 categorías esenciales
   */
  static async crearCategoriasViviendasDefault(userId: string): Promise<void> {
    const { error } = await supabase.rpc('crear_categorias_viviendas_default', {
      p_user_id: userId
    })

    if (error) {
      logger.error('Error al crear categorías por defecto para viviendas:', error)
      throw error
    }
  }
}

