  ): Promise<void> {
    const tabla = getTablaDocumentos(tipoEntidad)

    const { error } = await supabase
      .from(tabla)
      .update({ estado: 'activo' }) // ✅ Minúscula para consistencia
      .eq('id', documentoId)

    if (error) throw error
  }
}

