// ============================================
// SERVICE: Documentos - Eliminación y Papelera
// ============================================

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

import type { DocumentoProyecto } from '../types/documento.types'
import { type TipoEntidad, obtenerConfiguracionEntidad } from '../types/entidad.types'

/**
 * ✅ SERVICIO GENÉRICO: Eliminación de documentos (soft/hard delete)
 * Soporta: proyectos, viviendas, clientes, contratos, proveedores
 * Responsabilidades: archivar, eliminar (soft), restaurar, eliminar definitivo (hard)
 */
export class DocumentosEliminacionService {
  /**
   * ✅ GENÉRICO: Archivar documento completo (todas las versiones)
   */
  static async archivarDocumento(
    documentoId: string,
    tipoEntidad: TipoEntidad,
    motivoCategoria?: string,
    motivoDetalle?: string
  ): Promise<void> {
    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const tabla = config.tabla

    const { data: documentoResult, error: getError } = await supabase
      .from(tabla as any)
      .select('id, documento_padre_id')
      .eq('id', documentoId)
      .single()
    const documento = documentoResult as any

    if (getError) throw getError
    if (!documento) throw new Error('Documento no encontrado')

    const documentoPadreId = documento.documento_padre_id || documentoId

    const { error } = await supabase
      .from(tabla as any)
      .update({
        estado: 'archivado',
        motivo_categoria: motivoCategoria || null,
        motivo_detalle: motivoDetalle || null
      })
      .or(`id.eq.${documentoPadreId},documento_padre_id.eq.${documentoPadreId}`)

    if (error) throw error
  }

  /**
   * ✅ GENÉRICO: Restaurar documento archivado (todas las versiones)
   */
  static async restaurarDocumentoArchivado(
    documentoId: string,
    tipoEntidad: TipoEntidad
  ): Promise<void> {
    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const tabla = config.tabla

    const { data: documentoResult, error: getError } = await supabase
      .from(tabla as any)
      .select('id, documento_padre_id')
      .eq('id', documentoId)
      .single()
    const documento = documentoResult as any

    if (getError) throw getError
    if (!documento) throw new Error('Documento no encontrado')

    const documentoPadreId = documento.documento_padre_id || documentoId

    const { error } = await supabase
      .from(tabla as any)
      .update({ estado: 'activo' })
      .or(`id.eq.${documentoPadreId},documento_padre_id.eq.${documentoPadreId}`)

    if (error) throw error
  }

  /**
   * ✅ GENÉRICO: Obtener documentos archivados de una entidad
   */
  static async obtenerDocumentosArchivados(
    entidadId: string,
    tipoEntidad: TipoEntidad
  ): Promise<DocumentoProyecto[]> {
    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const tabla = config.tabla

    const { data, error } = await supabase
      .from(tabla as any)
      .select(`
        *,
        usuario:usuarios!${config.fkSubidoPor} (
          nombres,
          apellidos,
          email
        )
      `)
      .eq(config.campoEntidad, entidadId)
      .eq('estado', 'archivado')
      .eq('es_version_actual', true)
      .order('fecha_creacion', { ascending: false })

    if (error) throw error
    return (data || []) as unknown as DocumentoProyecto[]
  }

  /**
   * ✅ GENÉRICO: Eliminar documento (soft delete)
   * Elimina el documento y TODAS sus versiones
   */
  static async eliminarDocumento(
    documentoId: string,
    tipoEntidad: TipoEntidad
  ): Promise<void> {

    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const tabla = config.tabla

    const { data: documentoResult2, error: getError } = await supabase
      .from(tabla as any)
      .select('id, documento_padre_id, version, es_version_actual')
      .eq('id', documentoId)
      .single()
    const documento = documentoResult2 as any

    if (getError) throw getError
    if (!documento) throw new Error('Documento no encontrado')

    const documentoPadreId = documento.documento_padre_id || documentoId

    const { data: versiones, error: versionesError } = await supabase
      .from(tabla as any)
      .select('id, version, es_version_actual')
      .or(`id.eq.${documentoPadreId},documento_padre_id.eq.${documentoPadreId}`)
      .eq('estado', 'activo')
      .order('version', { ascending: false })

    if (versionesError) throw versionesError


    if (versiones && versiones.length > 0) {
      const versionMasAlta = (versiones as any[])[0]
      const idsAEliminar = (versiones as any[]).map((v: any) => v.id)

      const { error: updateError } = await supabase
        .from(tabla as any)
        .update({ estado: 'eliminado' })
        .in('id', idsAEliminar)

      if (updateError) throw updateError

      // Asegurar que la versión más alta tenga es_version_actual=true
      const { error: flagError } = await supabase
        .from(tabla as any)
        .update({ es_version_actual: true })
        .eq('id', (versionMasAlta as any).id)

      if (flagError) throw flagError

    }
  }

  /**
   * ✅ GENÉRICO: Obtener documentos eliminados (Papelera)
   * @param tipoEntidad - Opcional: filtra por tipo de entidad. Si no se provee, muestra todos
   */
  static async obtenerDocumentosEliminados(
    tipoEntidad?: TipoEntidad
  ): Promise<DocumentoProyecto[]> {
    // Siempre especificar tipoEntidad para usar la FK correcta (evitar join ambiguo)
    const config = tipoEntidad
      ? obtenerConfiguracionEntidad(tipoEntidad)
      : obtenerConfiguracionEntidad('proyecto') // Fallback explícito

    const tabla = config.tabla
    const fk = config.fkSubidoPor

    const { data, error } = await supabase
      .from(tabla as any)
      .select(`
        *,
        usuario:usuarios!${fk} (nombres, apellidos, email)
      `)
      .eq('estado', 'eliminado')
      .eq('es_version_actual', true)
      .order('fecha_actualizacion', { ascending: false })

    if (error) throw error
    return (data || []) as unknown as DocumentoProyecto[]
  }

  /**
   * ✅ GENÉRICO: Obtener versiones eliminadas de un documento
   */
  static async obtenerVersionesEliminadas(
    documentoId: string,
    tipoEntidad: TipoEntidad
  ): Promise<DocumentoProyecto[]> {
    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const tabla = config.tabla

    const { data: documentoResult, error: getError } = await supabase
      .from(tabla as any)
      .select('id, documento_padre_id')
      .eq('id', documentoId)
      .single()
    const documento = documentoResult as any

    if (getError) throw getError
    if (!documento) throw new Error('Documento no encontrado')

    const documentoPadreId = documento.documento_padre_id || documentoId

    const { data, error } = await supabase
      .from(tabla as any)
      .select(`
        *,
        usuario:usuarios!${config.fkSubidoPor} (
          nombres,
          apellidos,
          email
        )
      `)
      .or(`id.eq.${documentoPadreId},documento_padre_id.eq.${documentoPadreId}`)
      .eq('estado', 'eliminado')
      .order('version', { ascending: true })

    if (error) throw error
    return (data || []) as unknown as DocumentoProyecto[]
  }

  /**
   * ✅ GENÉRICO: Restaurar versiones seleccionadas
   */
  static async restaurarVersionesSeleccionadas(
    versionIds: string[],
    tipoEntidad: TipoEntidad
  ): Promise<void> {
    if (versionIds.length === 0) {
      throw new Error('Debe seleccionar al menos una versión para restaurar')
    }

    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const tabla = config.tabla

    const { error } = await supabase
      .from(tabla as any)
      .update({ estado: 'activo' })
      .in('id', versionIds)

    if (error) throw error
  }

  /**
   * ✅ GENÉRICO: Restaurar documento eliminado (con todas sus versiones)
   */
  static async restaurarDocumentoEliminado(
    documentoId: string,
    tipoEntidad: TipoEntidad
  ): Promise<void> {
    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const tabla = config.tabla

    const { data: documentoResult3, error: getError } = await supabase
      .from(tabla as any)
      .select('id, documento_padre_id, es_version_actual')
      .eq('id', documentoId)
      .single()
    const documento = documentoResult3 as any

    if (getError) throw getError
    if (!documento) throw new Error('Documento no encontrado')

    let documentosARestaurar: string[] = []

    if (documento.documento_padre_id) {
      // Es una versión â†’ Restaurar toda la cadena
      const { data: padreResult } = await supabase
        .from(tabla as any)
        .select('id')
        .eq('id', documento.documento_padre_id)
        .single()
      const padre = padreResult as any

      if (padre) {
        const { data: versiones } = await supabase
          .from(tabla as any)
          .select('id')
          .or(`id.eq.${padre.id},documento_padre_id.eq.${padre.id}`)
          .eq('estado', 'eliminado')

        if (versiones) {
          documentosARestaurar = (versiones as any[]).map((v: any) => v.id)
        }
      }
    } else {
      // Es documento independiente o versión 1
      const { data: versiones } = await supabase
        .from(tabla as any)
        .select('id')
        .or(`id.eq.${documentoId},documento_padre_id.eq.${documentoId}`)
        .eq('estado', 'eliminado')

      if (versiones) {
        documentosARestaurar = (versiones as any[]).map((v: any) => v.id)
      }
    }

    if (documentosARestaurar.length > 0) {
      const { error: updateError } = await supabase
        .from(tabla as any)
        .update({ estado: 'activo' })
        .in('id', documentosARestaurar)

      if (updateError) throw updateError
    } else {
      // Fallback
      const { error } = await supabase
        .from(tabla as any)
        .update({ estado: 'activo' })
        .eq('id', documentoId)

      if (error) throw error
    }
  }

  /**
   * ✅ GENÉRICO: Eliminar definitivamente (hard delete - NO reversible)
   */
  static async eliminarDefinitivo(
    documentoId: string,
    tipoEntidad: TipoEntidad
  ): Promise<void> {
    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const tabla = config.tabla
    const bucket = config.bucket

    const { data: documentoResult3, error: getError } = await supabase
      .from(tabla as any)
      .select('id, documento_padre_id, es_version_actual')
      .eq('id', documentoId)
      .single()
    const documento = documentoResult3 as any

    if (getError) throw getError
    if (!documento) throw new Error('Documento no encontrado')

    let documentosAEliminar: string[] = []

    if (documento.documento_padre_id) {
      const { data: padreDefResult } = await supabase
        .from(tabla as any)
        .select('id')
        .eq('id', documento.documento_padre_id)
        .single()
      const padre = padreDefResult as any

      if (padre) {
        const { data: versiones } = await supabase
          .from(tabla as any)
          .select('id, url_storage')
          .or(`id.eq.${padre.id},documento_padre_id.eq.${padre.id}`)
          .eq('estado', 'eliminado')

        if (versiones) {
          // ✅ STORAGE GENÉRICO
          for (const version of (versiones as any[]) as any[]) {
            try {
              await supabase.storage.from(bucket).remove([version.url_storage])
            } catch (err) {
              logger.warn('⚠️ Error al eliminar archivo de Storage:', err)
            }
          }

          documentosAEliminar = (versiones as any[]).map((v: any) => v.id)
        }
      }
    } else {
      const { data: versiones } = await supabase
        .from(tabla as any)
        .select('id, url_storage')
        .or(`id.eq.${documentoId},documento_padre_id.eq.${documentoId}`)
        .eq('estado', 'eliminado')

      if (versiones) {
        // ✅ STORAGE GENÉRICO
        for (const version of (versiones as any[]) as any[]) {
          try {
            await supabase.storage.from(bucket).remove([version.url_storage])
          } catch (err) {
            logger.warn('⚠️ Error al eliminar archivo de Storage:', err)
          }
        }

        documentosAEliminar = (versiones as any[]).map((v: any) => v.id)
      }
    }

    // Eliminar registros de BD (DELETE físico)
    if (documentosAEliminar.length > 0) {
      const { error: deleteError } = await supabase
        .from(tabla as any)
        .delete()
        .in('id', documentosAEliminar)

      if (deleteError) throw deleteError
    }
  }
}

// ============================================
// SERVICE: Documentos - Reemplazo Seguro (GENÉRICO)
// ============================================

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'
import { auditService } from '@/services/audit.service'

import { type TipoEntidad, obtenerConfiguracionEntidad } from '../types/entidad.types'

/**
 * Servicio de reemplazo seguro de archivos con rollback automático
 * Responsabilidades: reemplazar archivo con validación, backup automático, transacciones y auditoría
 */
export class DocumentosReemplazoService {
  /**
   * REEMPLAZAR ARCHIVO SEGURO (Admin Only)
   * ✅ Con rollback automático en caso de error
   * ✅ Manejo de transacciones
   * ✅ Backup verificado antes de proceder
   */
  static async reemplazarArchivoSeguro(
    documentoId: string,
    nuevoArchivo: File,
    motivo: string,
    password: string,
    tipoEntidad: TipoEntidad = 'proyecto'
  ): Promise<void> {
    // ✅ Obtener configuración dinámica
    const config = obtenerConfiguracionEntidad(tipoEntidad)
    const { bucket, tabla, campoEntidad, nombreSingular } = config

    // Variables para rollback
    let backupPath: string | null = null
    let archivoReemplazado = false
    let documento: any = null

    try {
      // ============================================
      // 1. VALIDACIÓN DE SEGURIDAD
      // ============================================
      const { data: { user } } = await supabase.auth.getUser()
      if (!user) throw new Error('Usuario no autenticado')

      // Verificar rol de administrador
      const { data: usuarioResult, error: usuarioError } = await supabase
        .from('usuarios')
        .select('rol')
        .eq('id', user.id)
        .single()
      const usuario = usuarioResult as any

      if (usuarioError || !usuario) {
        throw new Error('No se pudo verificar el usuario')
      }

      if (usuario.rol !== 'Administrador') {
        throw new Error('⛔ Solo administradores pueden reemplazar archivos')
      }

      // Validar contraseña
      const { data: passwordValid, error: passwordError } = await supabase.rpc(
        'validar_password_admin',
        { p_user_id: user.id, p_password: password }
      )

      if (passwordError) {
        logger.error('❌ [REEMPLAZO] Error validando contraseña:', passwordError)
        throw new Error('Error al validar contraseña de administrador')
      }

      if (!passwordValid) {
        throw new Error('❌ Contraseña incorrecta')
      }


      // ============================================
      // 2. OBTENER DOCUMENTO Y VALIDAR
      // ============================================
      const { data: _docData, error: fetchError } = await supabase
        .from(tabla as any)
        .select('*')
        .eq('id', documentoId)
        .single()
      documento = _docData as any

      if (fetchError || !documento) {
        throw new Error(`Documento no encontrado en ${tabla}`)
      }

      const entidadId = documento[campoEntidad]
      if (!entidadId) {
        throw new Error(`Campo ${campoEntidad} no encontrado en documento`)
      }


      // ============================================
      // 3. CREAR Y VERIFICAR BACKUP
      // ============================================
      backupPath = `${entidadId}/backups/reemplazos/${documentoId}_backup_${Date.now()}_${documento.nombre_archivo}`


      // Descargar archivo original
      const { data: archivoOriginal, error: downloadError } = await supabase.storage
        .from(bucket)
        .download(documento.url_storage)

      if (downloadError || !archivoOriginal) {
        throw new Error(`No se pudo descargar archivo original: ${downloadError?.message}`)
      }

      // Verificar que el archivo descargado tiene contenido
      if (archivoOriginal.size === 0) {
        throw new Error('El archivo original descargado está vacío')
      }

      // Subir backup
      const { error: backupError } = await supabase.storage
        .from(bucket)
        .upload(backupPath, archivoOriginal, {
          contentType: documento.tipo_mime,
          upsert: false
        })

      if (backupError) {
        throw new Error(`Error al crear backup: ${backupError.message}`)
      }

      // Verificar que el backup existe
      const { data: backupExists, error: verifyError } = await supabase.storage
        .from(bucket)
        .list(backupPath.split('/').slice(0, -1).join('/'), {
          search: backupPath.split('/').pop()
        })

      if (verifyError || !backupExists || backupExists.length === 0) {
        throw new Error('No se pudo verificar la creación del backup')
      }


      // ============================================
      // 4. REEMPLAZAR ARCHIVO EN STORAGE
      // ============================================

      const { error: replaceError } = await supabase.storage
        .from(bucket)
        .update(documento.url_storage, nuevoArchivo, {
          contentType: nuevoArchivo.type,
          upsert: true
        })

      if (replaceError) {
        throw new Error(`Error al reemplazar archivo: ${replaceError.message}`)
      }

      archivoReemplazado = true

      // ============================================
      // 5. ACTUALIZAR METADATA EN BD
      // ============================================
      const metadataReemplazo = {
        ...(typeof documento.metadata === 'object' && documento.metadata !== null
          ? documento.metadata
          : {}),
        reemplazo: {
          fecha: new Date().toISOString(),
          motivo,
          archivo_original: documento.nombre_archivo,
          archivo_nuevo: nuevoArchivo.name,
          tamano_original: documento.tamano_bytes,
          tamano_nuevo: nuevoArchivo.size,
          backup_path: backupPath,
          reemplazado_por: user.email
        }
      }

      const { error: updateError } = await supabase
        .from(tabla as any)
        .update({
          nombre_archivo: nuevoArchivo.name,
          nombre_original: nuevoArchivo.name,
          tamano_bytes: nuevoArchivo.size,
          tipo_mime: nuevoArchivo.type,
          metadata: metadataReemplazo,
          fecha_actualizacion: new Date().toISOString()
        })
        .eq('id', documentoId)

      if (updateError) {
        throw new Error(`Error al actualizar metadata: ${updateError.message}`)
      }


      // ============================================
      // 6. REGISTRAR AUDITORÍA
      // ============================================
      await this.registrarAuditoriaReemplazo({
        documento,
        nuevoArchivo,
        motivo,
        backupPath,
        entidadId,
        tipoEntidad,
        tabla,
        campoEntidad,
        bucket,
        user
      })


    } catch (error) {
      logger.error('💥 [REEMPLAZO] Error en el proceso:', error)

      // ============================================
      // ROLLBACK AUTOMÁTICO
      // ============================================
      if (archivoReemplazado && backupPath) {
        logger.warn('⚠️ [ROLLBACK] Intentando restaurar archivo original...')
        try {
          // Descargar backup
          const { data: backupData } = await supabase.storage
            .from(bucket)
            .download(backupPath)

          if (backupData) {
            // Restaurar archivo original
            await supabase.storage
              .from(bucket)
              .update(documento.url_storage, backupData, {
                contentType: documento.tipo_mime,
                upsert: true
              })

          }
        } catch (rollbackError) {
          logger.error('💥 [ROLLBACK] Error crítico al restaurar archivo:', rollbackError)
          logger.error(`⚠️ ACCIÓN MANUAL REQUERIDA: Restaurar desde backup: ${backupPath}`)
        }
      }

      throw error
    }
  }

  /**
   * Registrar auditoría del reemplazo
   * Separado para mantener método principal limpio
   */
  private static async registrarAuditoriaReemplazo(params: {
    documento: any
    nuevoArchivo: File
    motivo: string
    backupPath: string
    entidadId: string
    tipoEntidad: TipoEntidad
    tabla: string
    campoEntidad: string
    bucket: string
    user: any
  }) {
    const {
      documento,
      nuevoArchivo,
      motivo,
      backupPath,
      entidadId,
      tipoEntidad,
      tabla,
      campoEntidad,
      bucket,
      user
    } = params

    try {
      // Obtener URLs firmadas
      const { data: backupUrlData } = await supabase.storage
        .from(bucket)
        .createSignedUrl(backupPath, 31536000)

      const { data: nuevoUrlData } = await supabase.storage
        .from(bucket)
        .createSignedUrl(documento.url_storage, 31536000)

      await auditService.registrarAccion({
        tabla: tabla as any,
        accion: 'UPDATE',
        registroId: documento.id,
        datosAnteriores: {
          nombre_archivo: documento.nombre_archivo,
          tamano_bytes: documento.tamano_bytes,
          tipo_mime: documento.tipo_mime
        },
        datosNuevos: {
          nombre_archivo: nuevoArchivo.name,
          tamano_bytes: nuevoArchivo.size,
          tipo_mime: nuevoArchivo.type
        },
        metadata: {
          tipo_operacion: 'REEMPLAZO_ARCHIVO',
          tipo_entidad: tipoEntidad,
          entidad_id: entidadId,
          motivo_reemplazo: motivo,
          archivo_original: {
            nombre: documento.nombre_archivo,
            tamano_bytes: documento.tamano_bytes,
            tamano_mb: (documento.tamano_bytes / (1024 * 1024)).toFixed(2),
            tipo_mime: documento.tipo_mime,
            url_backup: backupUrlData?.signedUrl || null,
            backup_path: backupPath
          },
          archivo_nuevo: {
            nombre: nuevoArchivo.name,
            tamano_bytes: nuevoArchivo.size,
            tamano_mb: (nuevoArchivo.size / (1024 * 1024)).toFixed(2),
            tipo_mime: nuevoArchivo.type,
            url_actual: nuevoUrlData?.signedUrl || null
          },
          comparacion: {
            diferencia_bytes: nuevoArchivo.size - documento.tamano_bytes,
            diferencia_mb: ((nuevoArchivo.size - documento.tamano_bytes) / (1024 * 1024)).toFixed(2),
            porcentaje_cambio: documento.tamano_bytes > 0
              ? (((nuevoArchivo.size - documento.tamano_bytes) / documento.tamano_bytes) * 100).toFixed(2)
              : '0.00'
          },
          contexto: {
            [campoEntidad]: entidadId,
            categoria_id: documento.categoria_id,
            titulo: documento.titulo,
            version: documento.version
          },
          usuario_reemplazo: {
            usuario_id: user.id,
            email: user.email,
            timestamp: new Date().toISOString()
          }
        },
        modulo: 'documentos'
      })

    } catch (auditError) {
      logger.error('⚠️ [AUDITORÍA] Error al registrar (no crítico):', auditError)
    }
  }
}

