      <div className="space-y-2 mt-3">
        {pendientes.map((doc) => (
          <div
            key={`${doc.requisito_id}-${doc.tipo_fuente_nombre}`}
            className="flex items-center gap-2 p-2 rounded bg-white dark:bg-gray-800 border border-orange-200 dark:border-orange-700"
          >
