          />
        </motion.div>
      </div>
    </div>
  )
}

'use client'

import { useEffect, useMemo, useRef } from 'react'

import { motion } from 'framer-motion'
import type { FieldErrors, UseFormRegister, UseFormSetValue, UseFormWatch } from 'react-hook-form'

import { AccordionWizardField, AccordionWizardSelect, AccordionWizardTextarea, fieldStaggerAnim } from '@/shared/components/accordion-wizard'
import { getCiudadesPorDepartamento, getDepartamentos } from '@/shared/data/colombia-locations'

interface PasoInfoGeneralProps {
  register: UseFormRegister<any>
  errors: FieldErrors
  watch: UseFormWatch<any>
  setValue: UseFormSetValue<any>
}

/**
 * Paso 1: Información General (nombre, departamento, ciudad, dirección, descripción)
 */
export function PasoInfoGeneral({ register, errors, watch, setValue }: PasoInfoGeneralProps) {
  const departamentos = useMemo(() => getDepartamentos(), [])
  const departamentoSeleccionado = watch('departamento')

  const ciudades = useMemo(() => {
    if (!departamentoSeleccionado) return []
    return getCiudadesPorDepartamento(departamentoSeleccionado)
  }, [departamentoSeleccionado])

  // Reset ciudad cuando el USUARIO cambia departamento (no en carga inicial del formulario)
  const prevDepartamento = useRef(departamentoSeleccionado)

  useEffect(() => {
    if (
      departamentoSeleccionado &&
      prevDepartamento.current &&
      prevDepartamento.current !== departamentoSeleccionado
    ) {
      const ciudadActual = watch('ciudad')
      if (ciudadActual && !getCiudadesPorDepartamento(departamentoSeleccionado).includes(ciudadActual)) {
        setValue('ciudad', '')
      }
    }
    prevDepartamento.current = departamentoSeleccionado
  }, [departamentoSeleccionado, setValue, watch])

  // ✅ Re-sync: cuando las opciones de ciudad se renderizan en el DOM,
  // re-aplicar el valor interno de RHF al <select>.
  // Resuelve la race condition donde reset() setea ciudad antes de que las <option> existan.
  useEffect(() => {
    if (!ciudades.length) return
    const ciudadEnFormulario = watch('ciudad')
    if (ciudadEnFormulario && ciudades.includes(ciudadEnFormulario)) {
      setValue('ciudad', ciudadEnFormulario, { shouldValidate: false })
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [ciudades, setValue])

  return (
    <div className="space-y-4 pt-4">
      <motion.div {...fieldStaggerAnim(0)}>
        <AccordionWizardField
          label="Nombre del proyecto"
          moduleName="proyectos"
          required
          error={errors.nombre?.message as string}
          {...register('nombre')}
        />
      </motion.div>

      {/* Departamento + Ciudad en fila */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <motion.div {...fieldStaggerAnim(1)}>
          <AccordionWizardSelect
            label="Departamento"
            moduleName="proyectos"
            required
            error={errors.departamento?.message as string}
            {...register('departamento')}
          >
            <option value="">Selecciona un departamento</option>
            {departamentos.map((d) => (
              <option key={d} value={d}>{d}</option>
            ))}
          </AccordionWizardSelect>
        </motion.div>
        <motion.div {...fieldStaggerAnim(2)}>
          <AccordionWizardSelect
            label="Ciudad / Municipio"
            moduleName="proyectos"
            required
            error={errors.ciudad?.message as string}
            disabled={!departamentoSeleccionado}
            {...register('ciudad')}
          >
            <option value="">
              {departamentoSeleccionado ? 'Selecciona una ciudad' : 'Primero selecciona un departamento'}
            </option>
            {ciudades.map((c) => (
              <option key={c} value={c}>{c}</option>
            ))}
          </AccordionWizardSelect>
        </motion.div>
      </div>

      <motion.div {...fieldStaggerAnim(3)}>
        <AccordionWizardField
          label="Dirección"
          moduleName="proyectos"
          required
          placeholder="Ej: Calle 48 Norte #4E-07"
          error={errors.direccion?.message as string}
          {...register('direccion')}
        />
      </motion.div>

      <motion.div {...fieldStaggerAnim(4)}>
        <AccordionWizardTextarea
          label="Descripción"
          moduleName="proyectos"
          required
          error={errors.descripcion?.message as string}
          {...register('descripcion')}
        />
      </motion.div>
    </div>
  )
}

'use client'

import { motion } from 'framer-motion'
import { Home, Plus, Trash2 } from 'lucide-react'
import type { FieldArrayWithId, FieldErrors, UseFormRegister } from 'react-hook-form'

import { AccordionWizardField, fieldStaggerAnim } from '@/shared/components/accordion-wizard'

interface ManzanaFormValues {
  id?: string
  nombre: string
  totalViviendas: number
}

interface PasoManzanasProps {
  register: UseFormRegister<any>
  errors: FieldErrors
  fields: FieldArrayWithId[]
  manzanasWatch: ManzanaFormValues[]
  totalManzanas: number
  totalViviendas: number
  onAgregar: () => void
  onEliminar: (index: number) => void
  canAgregar?: boolean
}

/**
 * Paso 3: Manzanas (array dinámico de manzana: nombre + totalViviendas)
 */
export function PasoManzanas({
  register,
  errors,
  fields,
  manzanasWatch,
  totalManzanas,
  totalViviendas,
  onAgregar,
  onEliminar,
  canAgregar = true,
}: PasoManzanasProps) {
  const manzanasErrors = (errors.manzanas as any)

  return (
    <div className="space-y-4 pt-4">
      {/* Resumen rápido */}
      <motion.div
        {...fieldStaggerAnim(0)}
        className="flex items-center gap-4 px-4 py-3 rounded-xl bg-green-50 dark:bg-green-950/20 border border-green-200 dark:border-green-800"
      >
        <div className="flex items-center gap-2 text-sm">
          <span className="font-semibold text-green-700 dark:text-green-300">{totalManzanas}</span>
          <span className="text-green-600 dark:text-green-400">manzana(s)</span>
        </div>
        <div className="w-px h-4 bg-green-300 dark:bg-green-700" />
        <div className="flex items-center gap-2 text-sm">
          <Home className="w-3.5 h-3.5 text-green-500" />
          <span className="font-semibold text-green-700 dark:text-green-300">{totalViviendas}</span>
          <span className="text-green-600 dark:text-green-400">vivienda(s) total</span>
        </div>
      </motion.div>

      {/* Manzanas existentes */}
      <div className="space-y-3">
        {fields.map((field, index) => (
          <motion.div
            key={field.id}
            {...fieldStaggerAnim(index + 1)}
            className="flex items-start gap-3 p-4 rounded-xl bg-gray-50 dark:bg-gray-800/50 border border-gray-200 dark:border-gray-700"
          >
            <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 gap-3">
              <AccordionWizardField
                label={`Manzana ${index + 1} - Nombre`}
                moduleName="proyectos"
                required
                error={manzanasErrors?.[index]?.nombre?.message}
                {...register(`manzanas.${index}.nombre`)}
              />
              <AccordionWizardField
                label="Cantidad de viviendas"
                type="number"
                moduleName="proyectos"
                required
                error={manzanasErrors?.[index]?.totalViviendas?.message}
                {...register(`manzanas.${index}.totalViviendas`, { valueAsNumber: true })}
              />
            </div>
            {fields.length > 1 ? (
              <button
                type="button"
                onClick={() => onEliminar(index)}
                className="mt-3 p-2 rounded-lg text-red-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-950/30 transition-colors"
                aria-label={`Eliminar manzana ${index + 1}`}
              >
                <Trash2 className="w-4 h-4" />
              </button>
            ) : null}
          </motion.div>
        ))}
      </div>

      {/* Error global de manzanas */}
      {typeof manzanasErrors?.message === 'string' ? (
        <p className="text-xs text-red-500 dark:text-red-400 flex items-center gap-1">
          <span className="inline-block w-1 h-1 rounded-full bg-red-500" />
          {manzanasErrors.message}
        </p>
      ) : null}

      {/* Agregar manzana */}
      <div className="space-y-1.5">
        <button
          type="button"
          onClick={onAgregar}
          disabled={!canAgregar}
          className={`w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl border-2 border-dashed text-sm font-medium transition-colors ${
            canAgregar
              ? 'border-green-300 dark:border-green-700 text-green-600 dark:text-green-400 hover:bg-green-50 dark:hover:bg-green-950/20 hover:border-green-400 dark:hover:border-green-600'
              : 'border-gray-200 dark:border-gray-700 text-gray-400 dark:text-gray-600 cursor-not-allowed opacity-60'
          }`}
        >
          <Plus className="w-4 h-4" />
          Agregar manzana
        </button>
        {!canAgregar ? (
          <p className="text-center text-xs text-gray-400 dark:text-gray-500">
            Límite de 20 manzanas alcanzado
          </p>
        ) : null}
      </div>
    </div>
  )
}

/**
 * ProyectosFiltrosPremium - Filtros premium con diseño de pills/chips
 * ✅ Diseño sticky con glassmorphism
 * ✅ Pills interactivas para estados
 * ✅ Búsqueda destacada
 * ✅ Animaciones suaves
 */

'use client'

import { useEffect, useState } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import { Filter, LayoutGrid, Search, Table, X } from 'lucide-react'

import type { TipoVista } from '@/shared/hooks/useVistaPreference'
import { cn } from '@/shared/utils/helpers'

import { ESTADOS_PROYECTO } from '../constants'
import { proyectosPageStyles as styles } from '../styles/proyectos-page.styles'
import type { FiltroProyecto } from '../types'

interface ProyectosFiltrosPremiumProps {
  totalResultados?: number
  // ✅ Props para sincronizar filtros con el componente padre
  filtros?: FiltroProyecto
  onActualizarFiltros?: (filtros: Partial<FiltroProyecto>) => void
  onLimpiarFiltros?: () => void
  // ✅ Props para toggle de vista
  vista?: TipoVista
  onCambiarVista?: (vista: TipoVista) => void
}

export function ProyectosFiltrosPremium({
  totalResultados = 0,
  filtros = { busqueda: '', estado: undefined },
  onActualizarFiltros = () => {},
  onLimpiarFiltros = () => {},
  vista = 'cards',
  onCambiarVista = () => {},
}: ProyectosFiltrosPremiumProps) {
  // ✅ FIX HYDRATION: Evitar mismatch entre servidor y cliente
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    setMounted(true)
  }, [])

  const hasFilters = Boolean(filtros.busqueda || filtros.estado || filtros.verArchivados)

  const handleLimpiarFiltros = () => {
    onLimpiarFiltros()
  }

  const handleToggleEstado = (estado: string | undefined) => {
    onActualizarFiltros({
      estado: estado as any,
    })
  }

  return (
    <motion.div {...styles.animations.filtros} className={styles.filtros.container}>
      {/* Barra principal de búsqueda */}
      <div className={styles.filtros.searchBar}>
        {/* Búsqueda mejorada */}
        <div className={styles.filtros.searchWrapper}>
          <label htmlFor="search-proyectos" className={styles.filtros.label}>
            Buscar
          </label>
          <Search className={styles.filtros.searchIcon} />
          <input
            id="search-proyectos"
            type="text"
            value={filtros.busqueda || ''}
            onChange={e => onActualizarFiltros({ busqueda: e.target.value })}
            placeholder="Buscar por nombre, ubicación..."
            className={styles.filtros.searchInput}
          />
          {filtros.busqueda && (
            <motion.button
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.8 }}
              onClick={() => onActualizarFiltros({ busqueda: '' })}
              className={styles.filtros.searchClearButton}
              aria-label="Limpiar búsqueda"
            >
              <X className="w-4 h-4" />
            </motion.button>
          )}
        </div>
      </div>

      {/* Pills de Estado */}
      <div className={styles.filtros.pillsSection}>
        <div className={styles.filtros.pillsLabel}>
          <Filter className="w-3.5 h-3.5 text-gray-500 dark:text-gray-400" />
          <span className="text-xs font-medium text-gray-600 dark:text-gray-400">
            Estado:
          </span>
        </div>
        <div className="flex items-center gap-3">
          <div className={styles.filtros.pillsContainer}>
          {ESTADOS_PROYECTO.map(estado => {
            const isActive = filtros.estado === estado.value
            const getIcon = () => {
              if (estado.value === undefined) return '📋' // Todos
              if (estado.value === 'en_proceso') return '🏗️'
              if (estado.value === 'completado') return '✅'
              return '📋'
            }

            return (
              <motion.button
                key={estado.label}
                onClick={() => handleToggleEstado(estado.value)}
                className={
                  isActive ? styles.filtros.pillActive : styles.filtros.pill
                }
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
              >
                <span className={styles.filtros.pillIcon}>
                  {getIcon()}
                </span>
                <span className={styles.filtros.pillLabel}>{estado.label}</span>
                {isActive && (
                  <motion.div
                    initial={{ scale: 0 }}
                    animate={{ scale: 1 }}
                    className={styles.filtros.pillCheck}
                  >
                    ✓
                  </motion.div>
                )}
              </motion.button>
            )
          })}
          </div>
          {/* Toggle Ver Archivados */}
          <label className="flex items-center gap-2 px-3 py-1.5 rounded-lg bg-gray-50 dark:bg-gray-800/50 border border-gray-200 dark:border-gray-700 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors cursor-pointer">
            <input
              type="checkbox"
              checked={filtros.verArchivados || false}
              onChange={(e) => onActualizarFiltros({ verArchivados: e.target.checked })}
              className="w-4 h-4 rounded border-gray-300 dark:border-gray-600 text-amber-600 focus:ring-2 focus:ring-amber-500/20 focus:ring-offset-0 bg-white dark:bg-gray-900 cursor-pointer"
            />
            <span className="text-xs font-medium text-gray-700 dark:text-gray-300 whitespace-nowrap">
              📦 Ver archivados
            </span>
          </label>
        </div>
      </div>

      {/* Footer con toggle de vista, contador y limpiar */}
      <div className={styles.filtros.footer}>
        {/* Toggle Cards/Tabla - Solo renderizar después de montar para evitar hydration mismatch */}
        {mounted && (
          <div className="flex items-center gap-1 p-1 bg-gray-100 dark:bg-gray-800 rounded-lg">
            <button
              onClick={() => onCambiarVista('cards')}
              className={cn(
                'px-2.5 py-1.5 rounded-md text-xs font-medium transition-all flex items-center gap-1.5',
                vista === 'cards'
                  ? 'bg-white dark:bg-gray-700 text-orange-600 dark:text-orange-400 shadow-sm'
                  : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
              )}
              title="Vista de cards"
            >
              <LayoutGrid className="w-3.5 h-3.5" />
              <span>Cards</span>
            </button>
            <button
              onClick={() => onCambiarVista('tabla')}
              className={cn(
                'px-2.5 py-1.5 rounded-md text-xs font-medium transition-all flex items-center gap-1.5',
                vista === 'tabla'
                  ? 'bg-white dark:bg-gray-700 text-orange-600 dark:text-orange-400 shadow-sm'
                  : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
              )}
              title="Vista de tabla"
            >
              <Table className="w-3.5 h-3.5" />
              <span>Tabla</span>
            </button>
          </div>
        )}

        <p className={styles.filtros.resultCount}>
          {totalResultados} {totalResultados === 1 ? 'resultado' : 'resultados'}
        </p>
        <AnimatePresence>
          {hasFilters && (
            <motion.button
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 20 }}
              {...styles.animations.clearButton}
              onClick={handleLimpiarFiltros}
              className={styles.filtros.clearButton}
            >
              <X className={styles.filtros.clearIcon} />
              Limpiar filtros
            </motion.button>
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  )
}

/**
 * ProyectosForm - Componente presentacional PREMIUM
 * ✅ Separación de responsabilidades ESTRICTA
 * ✅ Diseño premium con gradientes naranja/ámbar
 * ✅ Animaciones Framer Motion
 * ✅ Modo oscuro completo
 */

'use client'

import { useEffect, useMemo } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import { AlertCircle, Building2, Calendar, CheckCircle2, FileCheck, FileText, Home, Loader2, Lock, LockOpen, MapPin, Plus, Trash2 } from 'lucide-react'

import { getCiudadesPorDepartamento, getDepartamentos } from '@/shared/data/colombia-locations'

import { cn } from '../../../shared/utils/helpers'
import { useProyectosForm } from '../hooks/useProyectosForm'
import { proyectosFormPremiumStyles as styles } from '../styles/proyectos-form-premium.styles'
import type { ProyectoFormData } from '../types'

interface ProyectosFormProps {
  onSubmit: (data: ProyectoFormData) => void | Promise<void>
  onCancel: () => void
  isLoading?: boolean
  initialData?: Partial<ProyectoFormData>
  isEditing?: boolean
  onHasChanges?: (hasChanges: boolean) => void // ✅ Callback para notificar cambios
  onTotalsChange?: (totals: { totalManzanas: number; totalViviendas: number }) => void // ✅ Callback para notificar totales
}

export function ProyectosForm({
  onSubmit,
  onCancel,
  isLoading,
  initialData,
  isEditing = false,
  onHasChanges,
  onTotalsChange,
}: ProyectosFormProps) {
  // Hook con toda la lógica
  const {
    register,
    handleSubmit,
    errors,
    touchedFields, // ← Para validación progresiva
    fields,
    handleAgregarManzana,
    handleEliminarManzana,
    totalManzanas,
    totalViviendas,
    manzanasWatch, // ✅ Valores reales de las manzanas
    hasChanges, // ← Detección de cambios
    changes,
    changesCount,
    isFieldChanged,
    shouldShowChanges,
    canSave,
    getButtonText,
    canRemoveManzana,
    esManzanaEditable,
    esManzanaEliminable,
    obtenerMotivoBloqueado,
    validandoManzanas,
    validandoNombre,
    manzanasState,
    watch,
    setValue,
  } = useProyectosForm({ initialData, onSubmit, isEditing, onHasChanges })

  // Datos de ubicación en cascada
  const departamentos = useMemo(() => getDepartamentos(), [])
  const departamentoSeleccionado = watch('departamento')
  const ciudades = useMemo(() => {
    if (!departamentoSeleccionado) return []
    return getCiudadesPorDepartamento(departamentoSeleccionado)
  }, [departamentoSeleccionado])

  // Reset ciudad si el departamento cambia y la ciudad actual ya no aplica
  useEffect(() => {
    if (departamentoSeleccionado) {
      const ciudadActual = watch('ciudad')
      if (ciudadActual && !getCiudadesPorDepartamento(departamentoSeleccionado).includes(ciudadActual)) {
        setValue('ciudad', '')
      }
    }
  }, [departamentoSeleccionado, setValue, watch])

  // ✅ Notificar cambios en totales al padre
  useEffect(() => {
    if (onTotalsChange) {
      onTotalsChange({ totalManzanas, totalViviendas })
    }
  }, [totalManzanas, totalViviendas, onTotalsChange])

  return (
    <motion.form
      {...styles.animations.container}
      onSubmit={handleSubmit}
      className={styles.form}
    >
      {/* LAYOUT DE 2 COLUMNAS */}
      <div className={styles.grid}>
        {/* COLUMNA IZQUIERDA: Información General */}
        <motion.div
          {...styles.animations.infoSection}
          className={styles.infoSection.container}
        >
          {/* Header */}
          <div className={styles.infoSection.header}>
            <div className={styles.infoSection.headerIcon}>
              <FileCheck className={styles.infoSection.headerIconSvg} />
            </div>
            <h3 className={styles.infoSection.headerTitle}>Información General</h3>
          </div>

          <div className={styles.infoSection.content}>
            {/* Campo: Nombre */}
            <div className={styles.field.container}>
              <label className={styles.field.label}>
                Nombre del Proyecto <span className={styles.field.required}>*</span>
                {/* Indicador de campo modificado */}
                {isEditing && isFieldChanged('nombre') && (
                  <span className="ml-2 text-xs text-orange-600 dark:text-orange-400 font-medium">
                    ✏️ Modificado
                  </span>
                )}
              </label>
              <div className={styles.field.inputWrapper}>
                <Building2 className={styles.field.inputIcon} />
                <input
                  {...register('nombre')}
                  type='text'
                  placeholder='Ej: Urbanización Los Pinos'
                  maxLength={100}
                  className={cn(
                    styles.field.input,
                    errors.nombre && styles.field.inputError,
                    touchedFields.nombre && !errors.nombre && 'border-green-300 dark:border-green-700 bg-green-50/50 dark:bg-green-950/20',
                    isEditing && isFieldChanged('nombre') && !errors.nombre && 'border-orange-300 dark:border-orange-700 bg-orange-50/50 dark:bg-orange-950/20'
                  )}
                />
                {/* Indicador de estado (validando/error/success) */}
                {touchedFields.nombre && (
                  <div className="absolute right-3 top-1/2 -translate-y-1/2">
                    {validandoNombre ? (
                      <Loader2 className="w-5 h-5 text-blue-500 animate-spin" />
                    ) : errors.nombre ? (
                      <AlertCircle className="w-5 h-5 text-red-500" />
                    ) : (
                      <CheckCircle2 className="w-5 h-5 text-green-500 animate-in fade-in zoom-in duration-200" />
                    )}
                  </div>
                )}
              </div>
              {errors.nombre && (
                <motion.div {...styles.animations.errorMessage} className={styles.field.error}>
                  <AlertCircle className={styles.field.errorIcon} />
                  {errors.nombre.message}
                </motion.div>
              )}
              {!errors.nombre && (
                <p className={styles.field.helper}>
                  Solo letras, números, espacios, guiones, paréntesis y puntos
                </p>
              )}
            </div>

            {/* Campos: Departamento + Ciudad */}
            <div className="grid grid-cols-2 gap-3">
              {/* Departamento */}
              <div className={styles.field.container}>
                <label className={styles.field.label}>
                  Departamento <span className={styles.field.required}>*</span>
                  {isEditing && isFieldChanged('departamento') && (
                    <span className="ml-2 text-xs text-orange-600 dark:text-orange-400 font-medium">
                      ✏️ Modificado
                    </span>
                  )}
                </label>
                <div className={styles.field.inputWrapper}>
                  <MapPin className={styles.field.inputIcon} />
                  <select
                    {...register('departamento')}
                    className={cn(
                      styles.field.input,
                      errors.departamento && styles.field.inputError,
                      touchedFields.departamento && !errors.departamento && 'border-green-300 dark:border-green-700 bg-green-50/50 dark:bg-green-950/20',
                      isEditing && isFieldChanged('departamento') && !errors.departamento && 'border-orange-300 dark:border-orange-700 bg-orange-50/50 dark:bg-orange-950/20'
                    )}
                  >
                    <option value="">Selecciona un departamento</option>
                    {departamentos.map((d) => (
                      <option key={d} value={d}>{d}</option>
                    ))}
                  </select>
                  {touchedFields.departamento && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none">
                      {errors.departamento ? (
                        <AlertCircle className="w-5 h-5 text-red-500" />
                      ) : (
                        <CheckCircle2 className="w-5 h-5 text-green-500 animate-in fade-in zoom-in duration-200" />
                      )}
                    </div>
                  )}
                </div>
                {errors.departamento && (
                  <motion.div {...styles.animations.errorMessage} className={styles.field.error}>
                    <AlertCircle className={styles.field.errorIcon} />
                    {errors.departamento.message}
                  </motion.div>
                )}
              </div>

              {/* Ciudad */}
              <div className={styles.field.container}>
                <label className={styles.field.label}>
                  Ciudad / Municipio <span className={styles.field.required}>*</span>
                  {isEditing && isFieldChanged('ciudad') && (
                    <span className="ml-2 text-xs text-orange-600 dark:text-orange-400 font-medium">
                      ✏️ Modificado
                    </span>
                  )}
                </label>
                <div className={styles.field.inputWrapper}>
                  <MapPin className={styles.field.inputIcon} />
                  <select
                    {...register('ciudad')}
                    disabled={!departamentoSeleccionado}
                    className={cn(
                      styles.field.input,
                      errors.ciudad && styles.field.inputError,
                      touchedFields.ciudad && !errors.ciudad && 'border-green-300 dark:border-green-700 bg-green-50/50 dark:bg-green-950/20',
                      isEditing && isFieldChanged('ciudad') && !errors.ciudad && 'border-orange-300 dark:border-orange-700 bg-orange-50/50 dark:bg-orange-950/20',
                      !departamentoSeleccionado && 'opacity-50 cursor-not-allowed'
                    )}
                  >
                    <option value="">
                      {departamentoSeleccionado ? 'Selecciona una ciudad' : 'Primero selecciona un depto.'}
                    </option>
                    {ciudades.map((c) => (
                      <option key={c} value={c}>{c}</option>
                    ))}
                  </select>
                  {touchedFields.ciudad && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none">
                      {errors.ciudad ? (
                        <AlertCircle className="w-5 h-5 text-red-500" />
                      ) : (
                        <CheckCircle2 className="w-5 h-5 text-green-500 animate-in fade-in zoom-in duration-200" />
                      )}
                    </div>
                  )}
                </div>
                {errors.ciudad && (
                  <motion.div {...styles.animations.errorMessage} className={styles.field.error}>
                    <AlertCircle className={styles.field.errorIcon} />
                    {errors.ciudad.message}
                  </motion.div>
                )}
              </div>
            </div>

            {/* Campo: Dirección */}
            <div className={styles.field.container}>
              <label className={styles.field.label}>
                Dirección <span className={styles.field.required}>*</span>
                {isEditing && isFieldChanged('direccion') && (
                  <span className="ml-2 text-xs text-orange-600 dark:text-orange-400 font-medium">
                    ✏️ Modificado
                  </span>
                )}
              </label>
              <div className={styles.field.inputWrapper}>
                <MapPin className={styles.field.inputIcon} />
                <input
                  {...register('direccion')}
                  type='text'
                  placeholder='Ej: Calle 48 Norte #4E-07'
                  maxLength={200}
                  className={cn(
                    styles.field.input,
                    errors.direccion && styles.field.inputError,
                    touchedFields.direccion && !errors.direccion && 'border-green-300 dark:border-green-700 bg-green-50/50 dark:bg-green-950/20',
                    isEditing && isFieldChanged('direccion') && !errors.direccion && 'border-orange-300 dark:border-orange-700 bg-orange-50/50 dark:bg-orange-950/20'
                  )}
                />
                {touchedFields.direccion && (
                  <div className="absolute right-3 top-1/2 -translate-y-1/2">
                    {errors.direccion ? (
                      <AlertCircle className="w-5 h-5 text-red-500" />
                    ) : (
                      <CheckCircle2 className="w-5 h-5 text-green-500 animate-in fade-in zoom-in duration-200" />
                    )}
                  </div>
                )}
              </div>
              {errors.direccion && (
                <motion.div {...styles.animations.errorMessage} className={styles.field.error}>
                  <AlertCircle className={styles.field.errorIcon} />
                  {errors.direccion.message}
                </motion.div>
              )}
              {!errors.direccion && (
                <p className={styles.field.helper}>
                  Dirección exacta del proyecto
                </p>
              )}
            </div>

            {/* Campo: Descripción */}
            <div>
              <label className={styles.field.label}>
                Descripción <span className={styles.field.required}>*</span>
                {/* Indicador de campo modificado */}
                {isEditing && isFieldChanged('descripcion') && (
                  <span className="ml-2 text-xs text-orange-600 dark:text-orange-400 font-medium">
                    ✏️ Modificado
                  </span>
                )}
              </label>
              <div className={styles.field.textareaWrapper}>
                <FileText className={styles.field.textareaIcon} />
                <textarea
                  {...register('descripcion')}
                  rows={3}
                  placeholder='Descripción breve del proyecto...'
                  maxLength={1000}
                  className={cn(
                    styles.field.textarea,
                    errors.descripcion && styles.field.textareaError,
                    touchedFields.descripcion && !errors.descripcion && 'border-green-300 dark:border-green-700 bg-green-50/50 dark:bg-green-950/20',
                    isEditing && isFieldChanged('descripcion') && !errors.descripcion && 'border-orange-300 dark:border-orange-700 bg-orange-50/50 dark:bg-orange-950/20'
                  )}
                />
                {/* Indicador de estado */}
                {touchedFields.descripcion && (
                  <div className="absolute right-3 top-3">
                    {errors.descripcion ? (
                      <AlertCircle className="w-5 h-5 text-red-500" />
                    ) : (
                      <CheckCircle2 className="w-5 h-5 text-green-500 animate-in fade-in zoom-in duration-200" />
                    )}
                  </div>
                )}
              </div>
              {errors.descripcion && (
                <motion.div {...styles.animations.errorMessage} className={styles.field.error}>
                  <AlertCircle className={styles.field.errorIcon} />
                  {errors.descripcion.message}
                </motion.div>
              )}
              {!errors.descripcion && (
                <p className={styles.field.helper}>
                  Mínimo 10 caracteres. Puedes usar letras, números y puntuación básica
                </p>
              )}
            </div>

            {/* Campo: Estado */}
            <div className={styles.field.container}>
              <label className={styles.field.label}>
                Estado del Proyecto <span className={styles.field.required}>*</span>
                {isEditing && isFieldChanged('estado') && (
                  <span className="ml-2 text-xs text-orange-600 dark:text-orange-400 font-medium">
                    ✏️ Modificado
                  </span>
                )}
              </label>
              <div className={styles.field.inputWrapper}>
                <Building2 className={styles.field.inputIcon} />
                <select
                  {...register('estado')}
                  className={cn(
                    styles.field.select,
                    errors.estado && styles.field.selectError,
                    touchedFields.estado && !errors.estado && 'border-green-300 dark:border-green-700',
                    isEditing && isFieldChanged('estado') && !errors.estado && 'border-orange-300 dark:border-orange-700'
                  )}
                >
                  <option value="en_planificacion">En Planificación</option>
                  <option value="en_proceso">En Proceso</option>
                  <option value="en_construccion">En Construcción</option>
                  <option value="completado">Completado</option>
                  <option value="pausado">Pausado</option>
                </select>
                {touchedFields.estado && (
                  <div className="absolute right-10 top-1/2 -translate-y-1/2 pointer-events-none">
                    {errors.estado ? (
                      <AlertCircle className="w-5 h-5 text-red-500" />
                    ) : (
                      <CheckCircle2 className="w-5 h-5 text-green-500 animate-in fade-in zoom-in duration-200" />
                    )}
                  </div>
                )}
              </div>
              {errors.estado && (
                <motion.div {...styles.animations.errorMessage} className={styles.field.error}>
                  <AlertCircle className={styles.field.errorIcon} />
                  {errors.estado.message}
                </motion.div>
              )}
              {!errors.estado && (
                <p className={styles.field.helper}>
                  Marca el estado actual del proyecto
                </p>
              )}
            </div>

            {/* Fechas en Grid 2 columnas */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Campo: Fecha de Inicio */}
              <div className={styles.field.container}>
                <label className={styles.field.label}>
                  Fecha de Inicio
                  {isEditing && isFieldChanged('fechaInicio') && (
                    <span className="ml-2 text-xs text-orange-600 dark:text-orange-400 font-medium">
                      ✏️ Modificado
                    </span>
                  )}
                </label>
                <div className={styles.field.inputWrapper}>
                  <Calendar className={styles.field.inputIcon} />
                  <input
                    {...register('fechaInicio')}
                    type='date'
                    className={cn(
                      styles.field.input,
                      errors.fechaInicio && styles.field.inputError,
                      touchedFields.fechaInicio && !errors.fechaInicio && 'border-green-300 dark:border-green-700 bg-green-50/50 dark:bg-green-950/20',
                      isEditing && isFieldChanged('fechaInicio') && !errors.fechaInicio && 'border-orange-300 dark:border-orange-700 bg-orange-50/50 dark:bg-orange-950/20'
                    )}
                  />
                  {touchedFields.fechaInicio && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none">
                      {errors.fechaInicio ? (
                        <AlertCircle className="w-5 h-5 text-red-500" />
                      ) : (
                        <CheckCircle2 className="w-5 h-5 text-green-500 animate-in fade-in zoom-in duration-200" />
                      )}
                    </div>
                  )}
                </div>
                {errors.fechaInicio && (
                  <motion.div {...styles.animations.errorMessage} className={styles.field.error}>
                    <AlertCircle className={styles.field.errorIcon} />
                    {errors.fechaInicio.message}
                  </motion.div>
                )}
              </div>

              {/* Campo: Fecha de Fin Estimada */}
              <div className={styles.field.container}>
                <label className={styles.field.label}>
                  Fecha de Fin Estimada
                  {isEditing && isFieldChanged('fechaFinEstimada') && (
                    <span className="ml-2 text-xs text-orange-600 dark:text-orange-400 font-medium">
                      ✏️ Modificado
                    </span>
                  )}
                </label>
                <div className={styles.field.inputWrapper}>
                  <Calendar className={styles.field.inputIcon} />
                  <input
                    {...register('fechaFinEstimada')}
                    type='date'
                    className={cn(
                      styles.field.input,
                      errors.fechaFinEstimada && styles.field.inputError,
                      touchedFields.fechaFinEstimada && !errors.fechaFinEstimada && 'border-green-300 dark:border-green-700 bg-green-50/50 dark:bg-green-950/20',
                      isEditing && isFieldChanged('fechaFinEstimada') && !errors.fechaFinEstimada && 'border-orange-300 dark:border-orange-700 bg-orange-50/50 dark:bg-orange-950/20'
                    )}
                  />
                  {touchedFields.fechaFinEstimada && (
                    <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none">
                      {errors.fechaFinEstimada ? (
                        <AlertCircle className="w-5 h-5 text-red-500" />
                      ) : (
                        <CheckCircle2 className="w-5 h-5 text-green-500 animate-in fade-in zoom-in duration-200" />
                      )}
                    </div>
                  )}
                </div>
                {errors.fechaFinEstimada && (
                  <motion.div {...styles.animations.errorMessage} className={styles.field.error}>
                    <AlertCircle className={styles.field.errorIcon} />
                    {errors.fechaFinEstimada.message}
                  </motion.div>
                )}
              </div>
            </div>
          </div>
        </motion.div>

        {/* COLUMNA DERECHA: Manzanas */}
        <motion.div
          {...styles.animations.manzanasSection}
          className={styles.manzanasSection.container}
        >
          {/* Header */}
          <div className={styles.manzanasSection.header}>
            <div className={styles.manzanasSection.headerLeft}>
              <div className={styles.manzanasSection.headerIcon}>
                <Building2 className={styles.manzanasSection.headerIconSvg} />
              </div>
              <h3 className={styles.manzanasSection.headerTitle}>
                Manzanas del Proyecto
              </h3>
            </div>
            <button
              type='button'
              onClick={handleAgregarManzana}
              className={styles.manzanasSection.addButton}
            >
              <Plus className={styles.manzanasSection.addButtonIcon} />
              Agregar
            </button>
          </div>

          {/* Error general de manzanas */}
          {errors.manzanas && !Array.isArray(errors.manzanas) && (
            <motion.div
              {...styles.animations.errorMessage}
              className={styles.manzanasSection.errorMessage}
            >
              <AlertCircle className={styles.manzanasSection.errorIcon} />
              {errors.manzanas.message}
            </motion.div>
          )}

          {/* Mensaje informativo en modo edición */}
          {isEditing && fields.length > 0 && (
            <motion.div
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              className="rounded-lg border-2 border-blue-200 dark:border-blue-800 bg-blue-50 dark:bg-blue-950/30 p-2.5 mb-4"
            >
              <div className="flex items-start gap-3">
                <AlertCircle className="w-5 h-5 text-blue-600 dark:text-blue-400 flex-shrink-0 mt-0.5" />
                <div className="space-y-1.5 flex-1">
                  <p className="text-sm font-semibold text-blue-900 dark:text-blue-100">
                    ℹ️ Edición inteligente de manzanas
                  </p>
                  <p className="text-xs text-blue-700 dark:text-blue-300 leading-relaxed">
                    Puedes <strong>agregar nuevas manzanas</strong> o <strong>modificar/eliminar las existentes</strong> que NO tienen viviendas creadas.
                    Las manzanas con viviendas están protegidas para mantener la integridad de datos.
                  </p>
                  <div className="flex items-center gap-4 text-xs text-blue-700 dark:text-blue-300 mt-1.5">
                    <div className="flex items-center gap-1.5">
                      <LockOpen className="w-4 h-4 text-green-600 dark:text-green-400" />
                      <span>Sin viviendas = Editable</span>
                    </div>
                    <div className="flex items-center gap-1.5">
                      <Lock className="w-4 h-4 text-red-600 dark:text-red-400" />
                      <span>Con viviendas = Bloqueada</span>
                    </div>
                  </div>
                </div>
              </div>
            </motion.div>
          )}

          {/* Lista de manzanas con AnimatePresence */}
          <div className={styles.manzanasSection.list}>
            {fields.length === 0 ? (
              <div className={styles.manzanasSection.emptyState}>
                <Building2 className={styles.manzanasSection.emptyIcon} />
                <p className={styles.manzanasSection.emptyTitle}>
                  No hay manzanas agregadas
                </p>
                <p className={styles.manzanasSection.emptySubtitle}>
                  Haz clic en "Agregar" para comenzar
                </p>
              </div>
            ) : (
              <AnimatePresence mode='popLayout'>
                {fields.map((field, index) => {
                  const esEditable = esManzanaEditable(index)
                  const esEliminable = esManzanaEliminable(index)
                  const manzanaReal = manzanasWatch?.[index] // ✅ Valor real del formulario
                  const motivoBloqueado = manzanaReal?.id ? obtenerMotivoBloqueado(manzanaReal.id) : ''

                  // ✅ OPTIMIZACIÓN: Usar datos precargados si existen, sino usar manzanasState (fallback)
                  const cantidadViviendasCreadas = manzanaReal?.cantidadViviendasCreadas ??
                    (manzanaReal?.id ? manzanasState.get(manzanaReal.id)?.cantidadViviendas : undefined)

                  const tieneValidacion = isEditing && (
                    manzanaReal?.esEditable !== undefined ||
                    (manzanaReal?.id && manzanasState.has(manzanaReal.id))
                  )

                  return (
                    <motion.div
                      key={field.id}
                      {...styles.animations.manzanaCard}
                      className={cn(
                        styles.manzanaCard.container,
                        !esEditable && 'opacity-75 ring-2 ring-red-200 dark:ring-red-800'
                      )}
                    >
                      {/* Header de la manzana */}
                      <div className={styles.manzanaCard.header}>
                        <div className={styles.manzanaCard.headerLeft}>
                          <Building2 className={styles.manzanaCard.headerIcon} />
                          <span className={styles.manzanaCard.headerTitle}>
                            Manzana #{index + 1}
                          </span>
                          {/* Badge de estado */}
                          {tieneValidacion && (
                            <div className="flex items-center gap-1.5">
                              {esEditable ? (
                                <div className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-green-100 dark:bg-green-900/30 border border-green-300 dark:border-green-700">
                                  <LockOpen className="w-3 h-3 text-green-600 dark:text-green-400" />
                                  <span className="text-[10px] font-medium text-green-700 dark:text-green-300">
                                    Editable
                                  </span>
                                </div>
                              ) : cantidadViviendasCreadas !== undefined && cantidadViviendasCreadas > 0 && (
                                <div
                                  className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-red-100 dark:bg-red-900/30 border border-red-300 dark:border-red-700"
                                  title={motivoBloqueado}
                                >
                                  <Lock className="w-3 h-3 text-red-600 dark:text-red-400" />
                                  <span className="text-[10px] font-medium text-red-700 dark:text-red-300">
                                    {cantidadViviendasCreadas} vivienda{cantidadViviendasCreadas !== 1 ? 's' : ''}
                                  </span>
                                </div>
                              )}
                            </div>
                          )}
                        </div>
                        {(!isEditing || esEliminable) && canRemoveManzana() && (
                          <button
                            type='button'
                            onClick={() => handleEliminarManzana(index)}
                            className={styles.manzanaCard.deleteButton}
                            title={!esEliminable ? motivoBloqueado : 'Eliminar manzana'}
                          >
                            <Trash2 className={styles.manzanaCard.deleteIcon} />
                          </button>
                        )}
                      </div>

                    {/* Campos */}
                    <div className={styles.manzanaCard.grid}>
                      {/* Nombre */}
                      <div className={styles.manzanaCard.field.container}>
                        <label className={styles.manzanaCard.field.label}>
                          Nombre de la manzana
                        </label>
                        <input
                          {...register(`manzanas.${index}.nombre`)}
                          type='text'
                          placeholder='Nombre'
                          disabled={!esEditable}
                          className={cn(
                            styles.manzanaCard.field.input,
                            errors.manzanas?.[index]?.nombre &&
                              styles.manzanaCard.field.inputError,
                            !esEditable && 'opacity-60 cursor-not-allowed bg-gray-100 dark:bg-gray-800'
                          )}
                        />
                        {errors.manzanas?.[index]?.nombre && (
                          <motion.p
                            {...styles.animations.errorMessage}
                            className={styles.manzanaCard.field.error}
                          >
                            <AlertCircle className={styles.manzanaCard.field.errorIcon} />
                            {errors.manzanas[index]?.nombre?.message}
                          </motion.p>
                        )}
                      </div>

                      {/* Cantidad Viviendas */}
                      <div className={styles.manzanaCard.field.container}>
                        <label className={styles.manzanaCard.field.label}>
                          Cantidad de viviendas
                        </label>
                        <div className={styles.manzanaCard.field.inputWrapper}>
                          <Home className={styles.manzanaCard.field.inputIcon} />
                          <input
                            {...register(`manzanas.${index}.totalViviendas`, {
                              valueAsNumber: true,
                            })}
                            type='number'
                            min='1'
                            placeholder='N° Viviendas'
                            disabled={!esEditable}
                            className={cn(
                              styles.manzanaCard.field.inputWithIcon,
                              errors.manzanas?.[index]?.totalViviendas &&
                                styles.manzanaCard.field.inputError,
                              !esEditable && 'opacity-60 cursor-not-allowed bg-gray-100 dark:bg-gray-800'
                            )}
                          />
                        </div>
                        {errors.manzanas?.[index]?.totalViviendas && (
                          <motion.p
                            {...styles.animations.errorMessage}
                            className={styles.manzanaCard.field.error}
                          >
                            <AlertCircle className={styles.manzanaCard.field.errorIcon} />
                            {errors.manzanas[index]?.totalViviendas?.message}
                          </motion.p>
                        )}
                      </div>

                      {/* Mensaje de por qué está bloqueada */}
                      {!esEditable && motivoBloqueado && (
                        <motion.div
                          initial={{ opacity: 0, height: 0 }}
                          animate={{ opacity: 1, height: 'auto' }}
                          className="col-span-2 mt-2 p-2 rounded-lg bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-800"
                        >
                          <p className="text-xs text-red-700 dark:text-red-300 flex items-start gap-2">
                            <Lock className="w-3.5 h-3.5 flex-shrink-0 mt-0.5" />
                            <span>{motivoBloqueado}</span>
                          </p>
                        </motion.div>
                      )}
                    </div>
                  </motion.div>
                  )
                })}
              </AnimatePresence>
            )}
          </div>
        </motion.div>
      </div>

      {/* BOTONES FOOTER */}
      <motion.div
        {...styles.animations.footer}
        className={styles.footer.container}
      >
        <button
          type='button'
          onClick={onCancel}
          disabled={isLoading}
          className={styles.footer.cancelButton}
        >
          Cancelar
        </button>
        <button
          type='submit'
          disabled={isLoading || !canSave} // ← Deshabilitar si no hay cambios (en edición)
          className={cn(
            styles.footer.submitButton,
            !canSave && 'opacity-50 cursor-not-allowed' // ← Estilo deshabilitado
          )}
        >
          {isLoading ? (
            <>
              <Loader2 className={cn(styles.footer.submitButtonIcon, 'animate-spin')} />
              Guardando...
            </>
          ) : (
            <>
              <Building2 className={styles.footer.submitButtonIcon} />
              {getButtonText(isEditing)}
            </>
          )}
        </button>
      </motion.div>
    </motion.form>
  )
}

'use client'

import { useCallback, useMemo, useState } from 'react'

import { motion } from 'framer-motion'

import { useRouter } from 'next/navigation'

import { construirURLProyecto } from '@/lib/utils/slug.utils'
import { Modal } from '@/shared/components/ui/Modal'
import { NoResults } from '@/shared/components/ui/NoResults'
import { Pagination } from '@/shared/components/ui/Pagination'
import { useVistaPreference } from '@/shared/hooks/useVistaPreference'

import {
    useEstadisticasProyectosQuery,
    useProyectosFiltradosQuery,
    useProyectosQuery,
} from '../hooks'
import { proyectosPageStyles as styles } from '../styles/proyectos-page.styles'
import type { Proyecto } from '../types'


import { ArchivarProyectoModal } from './modals/archivar-proyecto-modal'
import { RestaurarProyectoModal } from './modals/restaurar-proyecto-modal'
import { ProyectosEmpty } from './proyectos-empty'
import { ProyectosFiltrosPremium } from './proyectos-filtros-premium'
import { ProyectosHeaderPremium } from './proyectos-header-premium'
import { ProyectosLista } from './proyectos-lista'
import { ProyectosMetricasPremium } from './proyectos-metricas-premium'
import { ProyectosSkeleton } from './proyectos-skeleton'
import { ProyectosTabla } from './proyectos-tabla'

/**
 * Permisos del usuario (pasados desde Server Component)
 */
interface ProyectosPageProps {
  canCreate?: boolean
  canEdit?: boolean
  canDelete?: boolean
  canView?: boolean
  isAdmin?: boolean
}

/**
 * Página principal de proyectos
 * Orquesta todos los componentes hijos
 *
 * ✅ PROTEGIDA POR MIDDLEWARE
 * - Recibe permisos como props desde Server Component
 * - No necesita validar autenticación (ya validada)
 * - Solo maneja UI y lógica de negocio
 */
export function ProyectosPage({
  canCreate = false,
  canEdit = false,
  canDelete = false,
  canView = true,
  isAdmin = false,
}: ProyectosPageProps = {}) {
  // ✅ Debug logs comentados (funcionalidad verificada)
  // console.log('🏗️ [PROYECTOS MAIN] Client Component montado con permisos:', {
  //   canCreate,
  //   canEdit,
  //   canDelete,
  //   canView,
  //   isAdmin,
  // })

  const [modalEliminar, setModalEliminar] = useState(false)
  const [proyectoEliminar, setProyectoEliminar] = useState<string | null>(null)
  const [modalArchivar, setModalArchivar] = useState(false)
  const [proyectoArchivar, setProyectoArchivar] = useState<Proyecto | null>(null)
  const [modalRestaurar, setModalRestaurar] = useState(false)
  const [proyectoRestaurar, setProyectoRestaurar] = useState<Proyecto | null>(null)

  const router = useRouter()

  // ✅ REACT QUERY: Hooks con cache inteligente
  const {
    eliminarProyecto,
    archivarProyecto,
    restaurarProyecto,
    cargando,
    eliminando,
    archivando,
    restaurando
  } = useProyectosQuery()
  const { proyectos, filtros, actualizarFiltros, limpiarFiltros } = useProyectosFiltradosQuery()
  const estadisticas = useEstadisticasProyectosQuery()

  // Detectar si hay filtros activos
  const hayFiltrosActivos = Boolean(filtros.busqueda || filtros.estado)

  // Hook para preferencia de vista (cards vs tabla)
  const [vista, setVista] = useVistaPreference({ moduleName: 'proyectos' })

  // Paginación para vista de cards
  const [paginaActual, setPaginaActual] = useState(1)
  const [itemsPorPagina, setItemsPorPagina] = useState(9)

  const totalPaginas = useMemo(
    () => Math.max(1, Math.ceil(proyectos.length / itemsPorPagina)),
    [proyectos.length, itemsPorPagina]
  )

  const proyectosPaginados = useMemo(
    () => proyectos.slice((paginaActual - 1) * itemsPorPagina, paginaActual * itemsPorPagina),
    [proyectos, paginaActual, itemsPorPagina]
  )

  const cambiarPagina = useCallback((pagina: number) => {
    setPaginaActual(Math.max(1, Math.min(pagina, totalPaginas)))
  }, [totalPaginas])

  const cambiarItemsPorPagina = useCallback((items: number) => {
    setItemsPorPagina(items)
    setPaginaActual(1)
  }, [])

  // Proyecto que se va a eliminar (lookup por ID)
  const proyectoEliminando = proyectos.find(p => p.id === proyectoEliminar)

  const handleAbrirModal = () => {
    router.push('/proyectos/nuevo')
  }

  const handleEditarProyecto = (proyecto: Proyecto) => {
    router.push(`${construirURLProyecto({ id: proyecto.id, nombre: proyecto.nombre })}/editar`)
  }

  const handleEliminarProyecto = async (id: string) => {
    setProyectoEliminar(id)
    setModalEliminar(true)
  }

  const confirmarEliminar = async () => {
    if (!proyectoEliminar) return

    try {
      await eliminarProyecto(proyectoEliminar)
      setModalEliminar(false)
      setProyectoEliminar(null)
    } catch (_error) {
      // Error ya manejado por React Query con toast
    }
  }

  const handleArchivarProyecto = async (id: string) => {
    const proyecto = proyectos.find(p => p.id === id)
    if (proyecto) {
      setProyectoArchivar(proyecto)
      setModalArchivar(true)
    }
  }

  const confirmarArchivar = async (motivo?: string) => {
    if (!proyectoArchivar) return

    try {
      await archivarProyecto(proyectoArchivar.id, motivo)
      setModalArchivar(false)
      setProyectoArchivar(null)
    } catch (_error) {
      // Error ya manejado por React Query con toast
    }
  }

  const handleRestaurarProyecto = async (id: string) => {
    const proyecto = proyectos.find(p => p.id === id)
    if (proyecto) {
      setProyectoRestaurar(proyecto)
      setModalRestaurar(true)
    }
  }

  const confirmarRestaurar = async () => {
    if (!proyectoRestaurar) return

    try {
      await restaurarProyecto(proyectoRestaurar.id)
      setModalRestaurar(false)
      setProyectoRestaurar(null)
    } catch (_error) {
      // Error ya manejado por React Query con toast
    }
  }

  return (
    <div className={styles.container.page}>
      {/* Animación simplificada para navegación instantánea */}
      <motion.div {...styles.animations.container} className={styles.container.content}>
        {/* Header Premium */}
        <ProyectosHeaderPremium
          onNuevoProyecto={canCreate ? handleAbrirModal : undefined}
          totalProyectos={estadisticas.total}
        />

        {/* Métricas Premium */}
        <ProyectosMetricasPremium
          totalProyectos={estadisticas.total}
          enProceso={estadisticas.enProceso}
          completados={estadisticas.completados}
        />

        {/* Filtros Premium con toggle de vista */}
        <ProyectosFiltrosPremium
          totalResultados={proyectos.length}
          filtros={filtros}
          onActualizarFiltros={actualizarFiltros}
          onLimpiarFiltros={limpiarFiltros}
          vista={vista}
          onCambiarVista={setVista}
        />

        {/* Contenido Principal */}
        {cargando ? (
          <ProyectosSkeleton />
        ) : proyectos.length === 0 ? (
          // Si hay filtros activos pero no hay resultados → NoResults
          // Si NO hay filtros y no hay proyectos → Empty
          hayFiltrosActivos ? (
            <NoResults
              moduleName="proyectos"
              onLimpiarFiltros={limpiarFiltros}
              mensaje={
                filtros.busqueda && filtros.estado
                  ? 'No se encontraron proyectos que coincidan con tu búsqueda y el estado seleccionado'
                  : filtros.busqueda
                    ? 'No se encontraron proyectos que coincidan con tu búsqueda'
                    : filtros.estado
                      ? 'No hay proyectos con el estado seleccionado'
                      : undefined
              }
            />
          ) : (
            <ProyectosEmpty onCrear={canCreate ? handleAbrirModal : undefined} />
          )
        ) : vista === 'cards' ? (
          <div className="space-y-4">
            <ProyectosLista
              proyectos={proyectosPaginados}
              onEdit={canEdit ? handleEditarProyecto : undefined}
              onDelete={canDelete ? handleEliminarProyecto : undefined}
              onArchive={canEdit ? handleArchivarProyecto : undefined}
              onRestore={canEdit ? handleRestaurarProyecto : undefined}
              canEdit={canEdit}
              canDelete={canDelete}
            />

            {totalPaginas > 1 ? (
              <Pagination
                currentPage={paginaActual}
                totalPages={totalPaginas}
                totalItems={proyectos.length}
                itemsPerPage={itemsPorPagina}
                onPageChange={cambiarPagina}
                onItemsPerPageChange={cambiarItemsPorPagina}
              />
            ) : null}
          </div>
        ) : (
          <ProyectosTabla
            proyectos={proyectos}
            onView={(proyecto) => router.push(construirURLProyecto({ id: proyecto.id, nombre: proyecto.nombre }))}
            onEdit={canEdit ? handleEditarProyecto : undefined}
            onDelete={canDelete ? handleEliminarProyecto : undefined}
            onArchive={canEdit ? handleArchivarProyecto : undefined}
            onRestore={canEdit ? handleRestaurarProyecto : undefined}
            canEdit={canEdit}
            canDelete={canDelete}
          />
        )}
      </motion.div>

      {/* Modal Confirmar Eliminación */}
      <Modal
        isOpen={modalEliminar}
        onClose={() => {
          setModalEliminar(false)
          setProyectoEliminar(null)
        }}
        title='Eliminar Proyecto'
        description='Esta acción no se puede deshacer'
        size='sm'
        gradientColor='orange'
        compact={true}
      >
        <div className='space-y-3'>
          <p className='text-sm text-gray-600 dark:text-gray-400'>
            ¿Estas seguro de eliminar{' '}
            <span className='font-semibold text-gray-900 dark:text-gray-100'>
              "{proyectoEliminando?.nombre}"
            </span>
            ?
          </p>
          {proyectoEliminando && proyectoEliminando.manzanas.length > 0 && (
            <div className='rounded-lg border border-red-200 bg-red-50 p-2.5 dark:border-red-800 dark:bg-red-900/20'>
              <p className='text-xs text-red-800 dark:text-red-300'>
                ⚠️ Incluye <strong>{proyectoEliminando.manzanas.length} manzana(s)</strong>
              </p>
            </div>
          )}
          <div className='flex justify-end gap-2 pt-2'>
            <button
              type='button'
              onClick={() => {
                setModalEliminar(false)
                setProyectoEliminar(null)
              }}
              disabled={eliminando}
              className='rounded-lg border border-gray-300 bg-white px-3 py-1.5 text-sm font-medium text-gray-700 transition-colors hover:bg-gray-50 dark:border-gray-600 dark:bg-gray-800 dark:text-gray-300 dark:hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed'
            >
              Cancelar
            </button>
            <button
              type='button'
              onClick={confirmarEliminar}
              disabled={eliminando}
              className='rounded-lg bg-red-600 px-3 py-1.5 text-sm font-medium text-white transition-colors hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2'
            >
              {eliminando && (
                <svg
                  className="animate-spin h-4 w-4"
                  xmlns="http://www.w3.org/2000/svg"
                  fill="none"
                  viewBox="0 0 24 24"
                >
                  <circle
                    className="opacity-25"
                    cx="12"
                    cy="12"
                    r="10"
                    stroke="currentColor"
                    strokeWidth="4"
                  />
                  <path
                    className="opacity-75"
                    fill="currentColor"
                    d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"
                  />
                </svg>
              )}
              {eliminando ? 'Eliminando...' : 'Eliminar'}
            </button>
          </div>
        </div>
      </Modal>

      {/* Modal Archivar Proyecto */}
      <ArchivarProyectoModal
        isOpen={modalArchivar}
        nombreProyecto={proyectoArchivar?.nombre || ''}
        onConfirm={confirmarArchivar}
        onCancel={() => {
          setModalArchivar(false)
          setProyectoArchivar(null)
        }}
        archivando={archivando}
      />

      {/* Modal Restaurar Proyecto */}
      <RestaurarProyectoModal
        isOpen={modalRestaurar}
        nombreProyecto={proyectoRestaurar?.nombre || ''}
        fechaArchivado={proyectoRestaurar?.fechaArchivado}
        motivoArchivo={proyectoRestaurar?.motivoArchivo}
        onConfirm={confirmarRestaurar}
        onCancel={() => {
          setModalRestaurar(false)
          setProyectoRestaurar(null)
        }}
        restaurando={restaurando}
      />
    </div>
  )
}

/**
 * useDetectarCambios - Hook para detectar y comparar cambios en proyectos
 *
 * ✅ Hook personalizado (SOLO lógica)
 * ✅ < 200 líneas
 * ✅ Funciones puras de comparación
 */

import { useMemo } from 'react'

import type { Proyecto, ProyectoFormData } from '../types'
import { formatearEstadoProyecto } from '../utils/estado.utils'

/**
 * Normaliza una fecha a formato YYYY-MM-DD para comparación
 */
function normalizarFecha(fecha: string | null | undefined): string {
  if (!fecha) return ''
  // Extraer solo la parte de la fecha (YYYY-MM-DD)
  return fecha.split('T')[0]
}

export interface CambioDetectado {
  campo: string
  label: string
  valorAnterior: any
  valorNuevo: any
  tipo: 'texto' | 'numero' | 'lista'
}

export interface CambioManzana {
  tipo: 'agregada' | 'eliminada' | 'modificada'
  nombre: string
  cambios?: {
    nombreAnterior?: string
    nombreNuevo?: string
    viviendasAnterior?: number
    viviendasNuevo?: number
  }
}

export interface ResumenCambios {
  proyecto: CambioDetectado[]
  manzanas: CambioManzana[]
  totalCambios: number
  hayCambios: boolean
}

export function useDetectarCambios(
  proyectoOriginal: Proyecto | null,
  nuevosDatos: ProyectoFormData | null
): ResumenCambios {
  const resumen = useMemo(() => {
    if (!proyectoOriginal || !nuevosDatos) {
      return {
        proyecto: [],
        manzanas: [],
        totalCambios: 0,
        hayCambios: false,
      }
    }

    const cambiosProyecto: CambioDetectado[] = []

    // Comparar campos del proyecto
    if (proyectoOriginal.nombre !== nuevosDatos.nombre) {
      cambiosProyecto.push({
        campo: 'nombre',
        label: 'Nombre del Proyecto',
        valorAnterior: proyectoOriginal.nombre,
        valorNuevo: nuevosDatos.nombre,
        tipo: 'texto',
      })
    }

    if (proyectoOriginal.descripcion !== nuevosDatos.descripcion) {
      cambiosProyecto.push({
        campo: 'descripcion',
        label: 'Descripción',
        valorAnterior: proyectoOriginal.descripcion,
        valorNuevo: nuevosDatos.descripcion,
        tipo: 'texto',
      })
    }

    if (proyectoOriginal.departamento !== nuevosDatos.departamento) {
      cambiosProyecto.push({
        campo: 'departamento',
        label: 'Departamento',
        valorAnterior: proyectoOriginal.departamento || 'No especificado',
        valorNuevo: nuevosDatos.departamento || 'No especificado',
        tipo: 'texto',
      })
    }

    if (proyectoOriginal.ciudad !== nuevosDatos.ciudad) {
      cambiosProyecto.push({
        campo: 'ciudad',
        label: 'Ciudad',
        valorAnterior: proyectoOriginal.ciudad || 'No especificado',
        valorNuevo: nuevosDatos.ciudad || 'No especificado',
        tipo: 'texto',
      })
    }

    if (proyectoOriginal.direccion !== nuevosDatos.direccion) {
      cambiosProyecto.push({
        campo: 'direccion',
        label: 'Dirección',
        valorAnterior: proyectoOriginal.direccion || 'No especificado',
        valorNuevo: nuevosDatos.direccion || 'No especificado',
        tipo: 'texto',
      })
    }

    // 🆕 Comparar estado
    if (proyectoOriginal.estado !== nuevosDatos.estado) {
      cambiosProyecto.push({
        campo: 'estado',
        label: 'Estado',
        valorAnterior: formatearEstadoProyecto(proyectoOriginal.estado),
        valorNuevo: formatearEstadoProyecto(nuevosDatos.estado),
        tipo: 'texto',
      })
    }

    // 🆕 Comparar fecha de inicio (normalizar para evitar falsos positivos)
    const fechaInicioOriginal = normalizarFecha(proyectoOriginal.fechaInicio)
    const fechaInicioNueva = normalizarFecha(nuevosDatos.fechaInicio)

    if (fechaInicioOriginal !== fechaInicioNueva) {
      cambiosProyecto.push({
        campo: 'fechaInicio',
        label: 'Fecha de Inicio',
        valorAnterior: fechaInicioOriginal || 'No especificado',
        valorNuevo: fechaInicioNueva || 'No especificado',
        tipo: 'texto',
      })
    }

    // 🆕 Comparar fecha estimada de finalización (normalizar para evitar falsos positivos)
    const fechaFinOriginal = normalizarFecha(proyectoOriginal.fechaFinEstimada)
    const fechaFinNueva = normalizarFecha(nuevosDatos.fechaFinEstimada)

    if (fechaFinOriginal !== fechaFinNueva) {
      cambiosProyecto.push({
        campo: 'fechaFinEstimada',
        label: 'Fecha Estimada de Finalización',
        valorAnterior: fechaFinOriginal || 'No especificado',
        valorNuevo: fechaFinNueva || 'No especificado',
        tipo: 'texto',
      })
    }

    // 🆕 Comparar responsable del proyecto
    if ((proyectoOriginal as any).responsable !== nuevosDatos.responsable) {
      cambiosProyecto.push({
        campo: 'responsable',
        label: 'Responsable del Proyecto',
        valorAnterior: (proyectoOriginal as any).responsable || 'No asignado',
        valorNuevo: nuevosDatos.responsable || 'No asignado',
        tipo: 'texto',
      })
    }

    // Detectar cambios en manzanas
    const cambiosManzanas: CambioManzana[] = []
    const manzanasOriginales = proyectoOriginal.manzanas || []
    const manzanasNuevas = nuevosDatos.manzanas || []

    // Manzanas eliminadas
    manzanasOriginales.forEach(manzanaOriginal => {
      const existe = manzanasNuevas.some(
        m => m.nombre === manzanaOriginal.nombre
      )
      if (!existe) {
        cambiosManzanas.push({
          tipo: 'eliminada',
          nombre: manzanaOriginal.nombre,
        })
      }
    })

    // Manzanas agregadas o modificadas
    manzanasNuevas.forEach(manzanaNueva => {
      const manzanaOriginal = manzanasOriginales.find(
        m => m.nombre === manzanaNueva.nombre
      )

      if (!manzanaOriginal) {
        // Manzana nueva
        cambiosManzanas.push({
          tipo: 'agregada',
          nombre: manzanaNueva.nombre,
          cambios: {
            viviendasNuevo: manzanaNueva.totalViviendas,
          },
        })
      } else {
        // Verificar si cambió el número de viviendas
        if (manzanaOriginal.totalViviendas !== manzanaNueva.totalViviendas) {
          cambiosManzanas.push({
            tipo: 'modificada',
            nombre: manzanaNueva.nombre,
            cambios: {
              viviendasAnterior: manzanaOriginal.totalViviendas,
              viviendasNuevo: manzanaNueva.totalViviendas,
            },
          })
        }
      }
    })

    // Detectar cambios de nombre en manzanas (cuando índice coincide pero nombre no)
    manzanasNuevas.forEach((manzanaNueva, index) => {
      if (index < manzanasOriginales.length) {
        const manzanaOriginal = manzanasOriginales[index]

        // Si el nombre cambió pero no es una manzana nueva/eliminada
        if (
          manzanaOriginal.nombre !== manzanaNueva.nombre &&
          !cambiosManzanas.some(c => c.nombre === manzanaOriginal.nombre && c.tipo === 'eliminada') &&
          !cambiosManzanas.some(c => c.nombre === manzanaNueva.nombre && c.tipo === 'agregada')
        ) {
          const cambioExistente = cambiosManzanas.find(
            c => c.nombre === manzanaNueva.nombre && c.tipo === 'modificada'
          )

          if (cambioExistente) {
            // Actualizar el cambio existente con el cambio de nombre
            cambioExistente.cambios = {
              ...cambioExistente.cambios,
              nombreAnterior: manzanaOriginal.nombre,
              nombreNuevo: manzanaNueva.nombre,
            }
          } else {
            // Crear nuevo cambio
            cambiosManzanas.push({
              tipo: 'modificada',
              nombre: manzanaNueva.nombre,
              cambios: {
                nombreAnterior: manzanaOriginal.nombre,
                nombreNuevo: manzanaNueva.nombre,
                viviendasAnterior: manzanaOriginal.totalViviendas,
                viviendasNuevo: manzanaNueva.totalViviendas,
              },
            })
          }
        }
      }
    })

    const totalCambios = cambiosProyecto.length + cambiosManzanas.length
    const hayCambios = totalCambios > 0

    return {
      proyecto: cambiosProyecto,
      manzanas: cambiosManzanas,
      totalCambios,
      hayCambios,
    }
  }, [proyectoOriginal, nuevosDatos])

  return resumen
}

/**
 * useProyectosForm - Hook con lógica del formulario de proyectos
 * ✅ Separación de responsabilidades ESTRICTA
 * ✅ Validación con Zod
 * ✅ React Hook Form
 * ✅ Cálculos y transformaciones
 * ✅ Validación granular de manzanas editables
 */

import { useEffect, useMemo, useState } from 'react'

import { zodResolver } from '@hookform/resolvers/zod'
import { useFieldArray, useForm } from 'react-hook-form'
import { toast } from 'sonner'
import { z } from 'zod'

import { logger } from '@/lib/utils/logger'
import { getDepartamentos, validarCiudadDepartamento } from '@/shared/data/colombia-locations'
import { useFormChanges } from '@/shared/hooks/useFormChanges'

import { proyectosService } from '../services/proyectos.service'
import type { ProyectoFormData } from '../types'

import { useManzanasEditables } from './useManzanasEditables'


// ==================== SCHEMAS ====================
const manzanaSchema = z.object({
  id: z.string().optional(), // ID real de la DB (si existe)
  nombre: z
    .string()
    .min(1, 'El nombre de la manzana es obligatorio')
    .regex(
      /^[a-zA-ZáéíóúÁÉÍÓÚñÃ‘0-9\s\-_().]+$/,
      'Solo se permiten letras, números, espacios, guiones, paréntesis y puntos'
    ),
  totalViviendas: z
    .number({
      message: 'La cantidad de viviendas es obligatoria',
    })
    .min(1, 'Mínimo 1 vivienda')
    .max(100, 'Máximo 100 viviendas')
    .int('Debe ser un número entero'),
  // ✅ Campos opcionales para validación precargada
  cantidadViviendasCreadas: z.number().optional(),
  esEditable: z.boolean().optional(),
  motivoBloqueado: z.string().optional(),
})

const proyectoSchema = z.object({
  id: z.string().optional(), // ID del proyecto (cuando se edita)
  responsable: z.string().optional(), // Responsable del proyecto
  nombre: z
    .string()
    .min(3, 'El nombre del proyecto debe tener al menos 3 caracteres')
    .max(100, 'El nombre no puede exceder 100 caracteres')
    .regex(
      /^[a-zA-ZáéíóúÁÉÍÓÚñÃ‘0-9\s\-_().]+$/,
      'Solo se permiten letras (con acentos), números, espacios, guiones, paréntesis y puntos'
    ),
  descripcion: z
    .string()
    .min(10, 'La descripción debe tener al menos 10 caracteres')
    .max(1000, 'La descripción no puede exceder 1000 caracteres')
    .regex(
      /^[a-zA-ZáéíóúÁÉÍÓÚñÃ‘0-9\s\-_.,;:()\n¿?¡!'"Â°%$]+$/,
      'Caracteres no permitidos en la descripción. Use solo letras, números y puntuación básica'
    ),
  departamento: z
    .string()
    .min(1, 'Selecciona un departamento')
    .refine(
      (val) => !val || getDepartamentos().includes(val),
      { message: 'El departamento seleccionado no es válido' }
    ),
  ciudad: z
    .string()
    .min(1, 'Selecciona una ciudad o municipio'),
  direccion: z
    .string()
    .min(5, 'La dirección debe tener al menos 5 caracteres')
    .max(200, 'La dirección no puede exceder 200 caracteres')
    .regex(
      /^[a-zA-ZáéíóúÁÉÍÓÚñÃ'0-9\s\-,#.Â°]+$/,
      'Solo se permiten letras, números, espacios, comas, guiones, # y puntos'
    ),
  estado: z.enum(['en_planificacion', 'en_proceso', 'en_construccion', 'completado', 'pausado'], {
    message: 'Selecciona un estado para el proyecto',
  }),
  fechaInicio: z.string().optional(),
  fechaFinEstimada: z.string().optional(),
  manzanas: z.array(manzanaSchema)
    .min(1, 'Debe agregar al menos una manzana')
    .max(20, 'Máximo 20 manzanas por proyecto'),
}).refine(
  (data) => {
    // Solo validar si ambas fechas están presentes y no son strings vacías
    if (data.fechaInicio && data.fechaFinEstimada &&
        data.fechaInicio.trim() !== '' && data.fechaFinEstimada.trim() !== '') {
      return new Date(data.fechaFinEstimada) > new Date(data.fechaInicio)
    }
    return true
  },
  {
    message: 'La fecha de fin debe ser posterior a la fecha de inicio',
    path: ['fechaFinEstimada'],
  }
).refine(
  (data) => {
    // ✅ VALIDACIÓN: Fechas coherentes con estado del proyecto
    const ahora = new Date()
    const fechaInicio = data.fechaInicio ? new Date(data.fechaInicio) : null
    const fechaFin = data.fechaFinEstimada ? new Date(data.fechaFinEstimada) : null

    // Si está "completado", la fecha de fin no puede ser futura
    if (data.estado === 'completado' && fechaFin && fechaFin > ahora) {
      return false
    }

    // Si está "en_proceso" o "en_construccion", la fecha de inicio no puede ser futura
    if (
      (data.estado === 'en_proceso' || data.estado === 'en_construccion') &&
      fechaInicio &&
      fechaInicio > ahora
    ) {
      return false
    }

    return true
  },
  {
    message: 'Las fechas no son coherentes con el estado del proyecto',
    path: ['estado'],
  }
).refine(
  (data) => {
    if (!data.departamento || !data.ciudad) return true
    return validarCiudadDepartamento(data.ciudad, data.departamento)
  },
  {
    message: 'La ciudad seleccionada no corresponde al departamento elegido',
    path: ['ciudad'],
  }
)

// ✅ Schema factory: permite acceso a initialData e isEditing para validaciones async
const createProyectoSchema = (params: { initialData?: Partial<ProyectoFormData>, isEditing: boolean }) => {
  return proyectoSchema.superRefine(async (data, ctx) => {
    // ✅ Validación async: Verificar nombres duplicados de PROYECTOS
    if (data.nombre && data.nombre.length >= 3) {
      // No validar si es el mismo nombre en modo edición
      if (params.isEditing && data.nombre === params.initialData?.nombre) {
        return
      }

      try {
        const existe = await proyectosService.verificarNombreDuplicado(
          data.nombre,
          params.isEditing ? params.initialData?.id : undefined
        )

        if (existe) {
          ctx.addIssue({
            code: z.ZodIssueCode.custom,
            message: `Ya existe un proyecto con el nombre "${data.nombre}"`,
            path: ['nombre'],
          })
        }
      } catch (error) {
        logger.error('Error al validar nombre duplicado:', error)
        // No bloqueamos el submit si falla la validación async
      }
    }

    // ✅ Validación síncrona: Verificar nombres únicos de MANZANAS dentro del proyecto
    if (data.manzanas && data.manzanas.length > 1) {
      const nombresNormalizados = data.manzanas.map(m => m.nombre.trim().toLowerCase())
      const duplicados = nombresNormalizados.filter((nombre, index) =>
        nombresNormalizados.indexOf(nombre) !== index
      )

      if (duplicados.length > 0) {
        // Encontrar índice de la primera manzana duplicada
        const indiceDuplicado = nombresNormalizados.findIndex((nombre, index) =>
          nombresNormalizados.indexOf(nombre) !== index
        )

        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: `Ya existe una manzana con este nombre en el proyecto`,
          path: ['manzanas', indiceDuplicado, 'nombre'],
        })
      }
    }

    // ✅ Validación síncrona: Verificar formato de ubicación (evitar genéricas)
    // [removido: ahora se captura por campos departamento, ciudad, direccion separados]
  })
}

type ProyectoFormSchema = z.infer<typeof proyectoSchema>

// ==================== TIPOS ====================
interface UseProyectosFormParams {
  initialData?: Partial<ProyectoFormData>
  onSubmit: (data: ProyectoFormData) => void | Promise<void>
  isEditing?: boolean
  onHasChanges?: (hasChanges: boolean) => void // ✅ Callback para notificar cambios al padre
}

export function useProyectosForm({
  initialData,
  onSubmit,
  isEditing = false,
  onHasChanges,
}: UseProyectosFormParams) {
  // Estado para spinner de validación de nombre
  const [validandoNombre, setValidandoNombre] = useState(false)

  // ✅ OPTIMIZACIÓN: Si initialData ya tiene validación (de useProyectoConValidacion),
  // construir Map desde initialData en vez de consultar DB
  const manzanasConValidacionInicial = initialData?.manzanas?.filter(m => m.id && m.esEditable !== undefined)
  const validacionPrecargada = manzanasConValidacionInicial && manzanasConValidacionInicial.length > 0

  // Hook de validación de manzanas editables (solo si NO hay validación precargada)
  const {
    manzanasState,
    validarManzanas,
    cargando: validandoManzanas,
    puedeEliminar,
    puedeEditar,
    obtenerMotivoBloqueado,
  } = useManzanasEditables()

  // React Hook Form con schema que incluye validación async
  const schemaConValidacionAsync = useMemo(
    () => createProyectoSchema({ initialData, isEditing }),
    [initialData?.id, initialData?.nombre, isEditing]
  )

  // React Hook Form con schema SIN validación async (para evitar validación constante)
  const {
    register,
    handleSubmit,
    control,
    watch,
    reset,
    setError,
    clearErrors,
    trigger,
    setValue,
    formState: { errors, touchedFields, isValidating },
  } = useForm<ProyectoFormSchema>({
    resolver: zodResolver(proyectoSchema), // â† Schema básico SIN validación async
    mode: 'onBlur', // â† Validar al salir del campo
    reValidateMode: 'onSubmit', // â† CRÍTICO: No re-validar en cada cambio, solo al enviar
    defaultValues: {
      nombre: initialData?.nombre || '',
      descripcion: initialData?.descripcion || '',
      departamento: initialData?.departamento || '',
      ciudad: initialData?.ciudad || '',
      direccion: initialData?.direccion || '',
      estado: initialData?.estado || 'en_planificacion',
      fechaInicio: initialData?.fechaInicio?.split('T')[0] || '',
      fechaFinEstimada: initialData?.fechaFinEstimada?.split('T')[0] || '',
      manzanas: initialData?.manzanas || [],
    },
  })

  // useFieldArray para manzanas
  const { fields, append, remove } = useFieldArray({
    control,
    name: 'manzanas',
  })

  // Watch manzanas para calcular totales
  const manzanasWatch = watch('manzanas')

  // ==================== EFECTOS ====================
  // 🔄 CRÍTICO: Reset del formulario cuando initialData cambia (ej: después de actualización exitosa)
  // ⚠️ SOLO resetear cuando el ID del proyecto cambia, NO en cada render
  useEffect(() => {
    if (!initialData) return

    reset({
      nombre: initialData?.nombre || '',
      descripcion: initialData?.descripcion || '',
      departamento: initialData?.departamento || '',
      ciudad: initialData?.ciudad || '',
      direccion: initialData?.direccion || '',
      estado: initialData?.estado || 'en_planificacion',
      fechaInicio: initialData?.fechaInicio?.split('T')[0] || '',
      fechaFinEstimada: initialData?.fechaFinEstimada?.split('T')[0] || '',
      manzanas: initialData?.manzanas || [],
    })
  }, [initialData?.id, reset]) // ✅ Solo cuando cambia el ID (proyecto diferente)

  // ✅ OPTIMIZACIÓN: Validar manzanas SOLO si NO hay validación precargada
  useEffect(() => {
    if (validacionPrecargada) {
      return
    }

    // Validación tradicional (solo si no hay datos precargados)
    if (isEditing && manzanasWatch && manzanasWatch.length > 0) {
      const manzanasIds = manzanasWatch
        .map(m => m.id)
        .filter(Boolean) as string[]

      if (manzanasIds.length > 0) {
        validarManzanas(manzanasIds)
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isEditing, validacionPrecargada]) // Solo ejecutar al montar si no hay precarga

  // ==================== CÁLCULOS ====================
  const totalManzanas = useMemo(() => {
    return fields.length
  }, [fields.length])

  const totalViviendas = useMemo(() => {
    return manzanasWatch?.reduce((sum, m) => sum + (m.totalViviendas || 0), 0) || 0
  }, [manzanasWatch])

  // ==================== DETECCIÓN DE CAMBIOS (solo en modo edición) ====================
  const {
    hasChanges,
    changes,
    changesCount,
    isFieldChanged,
  } = useFormChanges(
    {
      nombre: watch('nombre'),
      departamento: watch('departamento'),
      ciudad: watch('ciudad'),
      direccion: watch('direccion'),
      descripcion: watch('descripcion'),
      estado: watch('estado'),
      fechaInicio: watch('fechaInicio'),
      fechaFinEstimada: watch('fechaFinEstimada'),
      responsable: watch('responsable'),
      manzanas: manzanasWatch,
    },
    {
      nombre: initialData?.nombre || '',
      departamento: initialData?.departamento || '',
      ciudad: initialData?.ciudad || '',
      direccion: initialData?.direccion || '',
      descripcion: initialData?.descripcion || '',
      estado: initialData?.estado || 'en_planificacion',
      fechaInicio: initialData?.fechaInicio?.split('T')[0] || '',
      fechaFinEstimada: initialData?.fechaFinEstimada?.split('T')[0] || '',
      responsable: initialData?.responsable || '',
      manzanas: initialData?.manzanas || [],
    },
    {
      fieldLabels: {
        nombre: 'Nombre del Proyecto',
        departamento: 'Departamento',
        ciudad: 'Ciudad',
        direccion: 'Dirección',
        descripcion: 'Descripción',
        estado: 'Estado',
        fechaInicio: 'Fecha de Inicio',
        fechaFinEstimada: 'Fecha de Fin Estimada',
        responsable: 'Responsable',
        manzanas: 'Manzanas',
      },
    }
  )

  // Solo habilitar detección de cambios en modo edición
  const shouldShowChanges = isEditing
  const canSave = isEditing ? hasChanges : true // En creación siempre puede guardar

  // ✅ Notificar al padre cuando cambie hasChanges
  useEffect(() => {
    onHasChanges?.(hasChanges)
  }, [hasChanges, onHasChanges])

  // ==================== HANDLERS ====================
  const MAX_MANZANAS = 20
  const canAgregarManzana = fields.length < MAX_MANZANAS

  const handleAgregarManzana = () => {
    if (!canAgregarManzana) {
      toast.warning(`Has alcanzado el límite de ${MAX_MANZANAS} manzanas por proyecto`)
      return
    }
    append({
      nombre: `${String.fromCharCode(65 + fields.length)}`,
      totalViviendas: 0,
    })
  }

  const handleEliminarManzana = (index: number) => {
    // En modo edición, verificar si la manzana puede ser eliminada
    if (isEditing && manzanasWatch) {
      const manzana = manzanasWatch[index]
      if (manzana.id && !puedeEliminar(manzana.id)) {
        const motivo = obtenerMotivoBloqueado(manzana.id)
        toast.error(`No se puede eliminar esta manzana: ${motivo}`)
        return
      }
    }
    remove(index)
  }

  const onSubmitForm = async (data: ProyectoFormSchema) => {
    // ✅ VALIDACIÓN DE DUPLICADOS: Solo al enviar el formulario
    if (data.nombre && data.nombre !== initialData?.nombre) {
      try {
        const esDuplicado = await proyectosService.verificarNombreDuplicado(
          data.nombre,
          isEditing ? initialData?.id : undefined
        )

        if (esDuplicado) {
          setError('nombre', {
            type: 'manual',
            message: 'Ya existe un proyecto con este nombre'
          })
          return // Detener envío
        }
      } catch (error) {
        logger.error('Error validando nombre:', error)
        setError('nombre', {
          type: 'manual',
          message: 'Error al validar el nombre. Intenta de nuevo.'
        })
        return
      }
    }

    // ✅ FIX: En modo edición, enviar TODOS los campos del formulario
    if (isEditing) {
      // Modo edición: Enviar todos los campos editables
      const formDataEdicion: ProyectoFormData = {
        ...data,
        // Agregar campos faltantes a las manzanas (preservando IDs)
        manzanas: data.manzanas.map(m => ({
          ...m,
          precioBase: 0,
          superficieTotal: 0,
          ubicacion: '',
        })),
        // Convertir fechas opcionales de input (YYYY-MM-DD) a ISO con hora mediodía
        fechaInicio: data.fechaInicio && data.fechaInicio.trim() !== ''
          ? `${data.fechaInicio}T12:00:00`
          : null,
        fechaFinEstimada: data.fechaFinEstimada && data.fechaFinEstimada.trim() !== ''
          ? `${data.fechaFinEstimada}T12:00:00`
          : null,
      } as ProyectoFormData

      onSubmit(formDataEdicion)
    } else {
      // Modo creación: Completar con valores por defecto
      const formDataCompleto: ProyectoFormData = {
        ...data,
        manzanas: data.manzanas.map(m => ({
          ...m,
          precioBase: 0,
          superficieTotal: 0,
          ubicacion: '',
        })),
        // Convertir fechas de input (YYYY-MM-DD) a ISO con hora mediodía
        // Si están vacías, enviar null (las fechas son opcionales)
        fechaInicio: data.fechaInicio && data.fechaInicio.trim() !== ''
          ? `${data.fechaInicio}T12:00:00`
          : null,
        fechaFinEstimada: data.fechaFinEstimada && data.fechaFinEstimada.trim() !== ''
          ? `${data.fechaFinEstimada}T12:00:00`
          : null,
        presupuesto: 0,
      }

      onSubmit(formDataCompleto)
    }
  }

  // ==================== HELPERS ====================
  const getButtonText = (isEditing: boolean) => {
    return isEditing ? 'Actualizar Proyecto' : 'Crear Proyecto'
  }

  const canRemoveManzana = () => {
    return fields.length > 1
  }

  /**
   * Verifica si una manzana específica puede ser editada/eliminada
   */
  const esManzanaEditable = (index: number): boolean => {
    if (!isEditing) return true // En modo creación, todo es editable

    const manzana = manzanasWatch?.[index]
    if (!manzana || !manzana.id) return true // Manzana nueva (sin ID), es editable

    // ✅ OPTIMIZACIÓN: Usar validación precargada si existe
    if (manzana.esEditable !== undefined) {
      return manzana.esEditable
    }

    // Fallback: usar validación de DB
    return puedeEditar(manzana.id)
  }

  /**
   * Verifica si una manzana específica puede ser eliminada
   */
  const esManzanaEliminable = (index: number): boolean => {
    if (!isEditing) return canRemoveManzana() // En modo creación, validar cantidad mínima

    const manzana = manzanasWatch?.[index]
    if (!manzana || !manzana.id) return true // Manzana nueva, puede eliminarse

    // ✅ OPTIMIZACIÓN: Usar validación precargada si existe
    if (manzana.esEditable !== undefined) {
      return manzana.esEditable
    }

    // Fallback: usar validación de DB
    return puedeEliminar(manzana.id)
  }

  /**
   * Obtiene el motivo por el cual una manzana está bloqueada
   */
  const obtenerMotivoBloqueadoLocal = (manzanaId: string): string => {
    // ✅ OPTIMIZACIÓN: Buscar en manzanas precargadas primero
    const manzanaPrecargada = manzanasWatch?.find(m => m.id === manzanaId)
    if (manzanaPrecargada?.motivoBloqueado) {
      return manzanaPrecargada.motivoBloqueado
    }

    // Fallback: usar validación de DB
    return obtenerMotivoBloqueado(manzanaId)
  }

  return {
    // Form state
    register,
    handleSubmit: handleSubmit(onSubmitForm),
    control,
    errors,
    touchedFields,
    trigger,
    watch,
    setValue,
    setError,
    // Field array
    fields,
    handleAgregarManzana,
    handleEliminarManzana,

    // Computed values
    totalManzanas,
    totalViviendas,
    manzanasWatch, // ✅ Exportar para acceder a valores reales
    canAgregarManzana,

    // Detección de cambios
    hasChanges,
    changes,
    changesCount,
    isFieldChanged,
    shouldShowChanges,
    canSave,

    // Helpers
    getButtonText,
    canRemoveManzana,
    esManzanaEditable,
    esManzanaEliminable,
    obtenerMotivoBloqueado: obtenerMotivoBloqueadoLocal,

    // Validación state
    validandoManzanas,
    validandoNombre: false, // ✅ Validación solo al enviar, no mostrar spinner en campo
    manzanasState,
  }
}

/**
 * ============================================
 * USE PROYECTOS QUERY (REACT QUERY)
 * ============================================
 *
 * Hook principal para proyectos usando React Query
 * Reemplaza Zustand store con cache inteligente
 *
 * BENEFICIOS vs Zustand:
 * - ✅ Cache automático (stale-while-revalidate)
 * - ✅ Sin race conditions (una sola fuente de verdad)
 * - ✅ Invalidación automática después de mutations
 * - ✅ Background refetching inteligente
 * - ✅ Optimistic updates built-in
 * - ✅ Sin conflictos con localStorage
 */

'use client'

import { useMemo, useState } from 'react'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { proyectosService } from '../services/proyectos.service'
import type { FiltroProyecto, ProyectoFormData } from '../types'

// ============================================
// QUERY KEYS (Constantes para cache)
// ============================================
export const proyectosKeys = {
  all: ['proyectos'] as const,
  lists: () => [...proyectosKeys.all, 'list'] as const,
  list: (filtros?: FiltroProyecto) => [...proyectosKeys.lists(), { filtros }] as const,
  details: () => [...proyectosKeys.all, 'detail'] as const,
  detail: (id: string) => [...proyectosKeys.details(), id] as const,
}

// ============================================
// 1. HOOK PRINCIPAL: useProyectosQuery
// ============================================
export function useProyectosQuery() {
  const queryClient = useQueryClient()

  // ✅ QUERY: Obtener todos los proyectos (incluye archivados para filtrado local)
  const {
    data: proyectos = [],
    isLoading: cargando,
    error,
    refetch: refrescar,
  } = useQuery({
    queryKey: proyectosKeys.lists(),
    queryFn: () => proyectosService.obtenerProyectos(true), // ✅ Siempre traer todos (incluidos archivados) para filtrado local
    staleTime: 5 * 60 * 1000, // 5 minutos - datos frescos
    gcTime: 10 * 60 * 1000, // 10 minutos - retención en cache
  })

  // ✅ MUTATION: Crear proyecto
  const crearProyectoMutation = useMutation({
    mutationFn: (data: ProyectoFormData) => proyectosService.crearProyecto(data),
    onSuccess: async (nuevoProyecto) => {
      // ✅ INVALIDAR + REFETCH inmediato
      await queryClient.invalidateQueries({
        queryKey: proyectosKeys.lists(),
        refetchType: 'all' // Refetch todas (activas e inactivas)
      })

      toast.success('Proyecto creado correctamente', {
        description: `${nuevoProyecto.nombre} ha sido creado exitosamente`,
      })
    },
    onError: (error: Error) => {
      toast.error('Error al crear proyecto', {
        description: error.message,
      })
    },
  })

  // ✅ MUTATION: Actualizar proyecto
  const actualizarProyectoMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: Partial<ProyectoFormData> }) => {
      return proyectosService.actualizarProyecto(id, data)
    },
    onSuccess: async (proyectoActualizado) => {
      // ✅ INVALIDAR + REFETCH inmediato
      await queryClient.invalidateQueries({
        queryKey: proyectosKeys.lists(),
        refetchType: 'all'
      })
      await queryClient.invalidateQueries({
        queryKey: proyectosKeys.detail(proyectoActualizado.id),
        refetchType: 'all'
      })

      // ✅ Invalidar también query de validación (para modal de edición)
      await queryClient.invalidateQueries({
        queryKey: ['proyecto-validacion', proyectoActualizado.id],
        refetchType: 'all'
      })

      toast.success('Proyecto actualizado', {
        description: `${proyectoActualizado.nombre} ha sido actualizado`,
      })
    },
    onError: (error: Error) => {
      toast.error('Error al actualizar proyecto', {
        description: error.message,
      })
    },
  })

  // ✅ MUTATION: Eliminar proyecto
  const eliminarProyectoMutation = useMutation({
    mutationFn: (id: string) => proyectosService.eliminarProyecto(id),
    onSuccess: (_, id) => {
      queryClient.invalidateQueries({ queryKey: proyectosKeys.lists() })
      queryClient.removeQueries({ queryKey: proyectosKeys.detail(id) })
      toast.success('Proyecto eliminado correctamente')
    },
    onError: (error: Error) => {
      toast.error('Error al eliminar proyecto', {
        description: error.message,
      })
    },
  })

  // ✅ MUTATION: Archivar proyecto
  const archivarProyectoMutation = useMutation({
    mutationFn: ({ id, motivo }: { id: string; motivo?: string }) =>
      proyectosService.archivarProyecto(id, motivo),
    onSuccess: async (_, { id }) => {
      await queryClient.invalidateQueries({ queryKey: proyectosKeys.lists() })
      queryClient.removeQueries({ queryKey: proyectosKeys.detail(id) })
      toast.success('Proyecto archivado correctamente', {
        description: 'El proyecto ya no aparecerá en la lista activa',
      })
    },
    onError: (error: Error) => {
      toast.error('Error al archivar proyecto', {
        description: error.message,
      })
    },
  })

  // ✅ MUTATION: Restaurar proyecto archivado
  const restaurarProyectoMutation = useMutation({
    mutationFn: (id: string) => proyectosService.restaurarProyecto(id),
    onSuccess: async () => {
      await queryClient.invalidateQueries({ queryKey: proyectosKeys.lists() })
      toast.success('Proyecto restaurado correctamente', {
        description: 'El proyecto vuelve a estar activo',
      })
    },
    onError: (error: Error) => {
      toast.error('Error al restaurar proyecto', {
        description: error.message,
      })
    },
  })

  // ✅ MUTATION: Eliminar proyecto definitivo
  const eliminarDefinitivoMutation = useMutation({
    mutationFn: (id: string) => proyectosService.eliminarProyectoDefinitivo(id),
    onSuccess: (_, id) => {
      queryClient.invalidateQueries({ queryKey: proyectosKeys.lists() })
      queryClient.removeQueries({ queryKey: proyectosKeys.detail(id) })
      toast.success('Proyecto eliminado definitivamente')
    },
    onError: (error: Error) => {
      toast.error('Error al eliminar proyecto definitivamente', {
        description: error.message,
      })
    },
  })

  return {
    proyectos,
    cargando,
    error: error as Error | null,
    crearProyecto: crearProyectoMutation.mutateAsync,
    actualizarProyecto: (id: string, data: Partial<ProyectoFormData>) => {
      return actualizarProyectoMutation.mutateAsync({ id, data })
    },
    eliminarProyecto: eliminarProyectoMutation.mutateAsync,
    archivarProyecto: (id: string, motivo?: string) => {
      return archivarProyectoMutation.mutateAsync({ id, motivo })
    },
    restaurarProyecto: restaurarProyectoMutation.mutateAsync,
    eliminarProyectoDefinitivo: eliminarDefinitivoMutation.mutateAsync,
    refrescar,
    // Estados de mutations
    creando: crearProyectoMutation.isPending,
    actualizando: actualizarProyectoMutation.isPending,
    eliminando: eliminarProyectoMutation.isPending,
    archivando: archivarProyectoMutation.isPending,
    restaurando: restaurarProyectoMutation.isPending,
  }
}

// ============================================
// 2. HOOK: useProyectoQuery (detalle individual)
// ============================================
export function useProyectoQuery(id?: string) {
  const {
    data: proyecto,
    isLoading: cargando,
    error,
  } = useQuery({
    queryKey: proyectosKeys.detail(id!),
    queryFn: () => proyectosService.obtenerProyecto(id!),
    enabled: !!id, // Solo ejecutar si hay ID
    staleTime: 3 * 60 * 1000, // 3 minutos para detalles
    retry: 2, // Reintentar 2 veces si falla
    retryDelay: 1000, // Esperar 1s entre reintentos
  })

  return {
    proyecto,
    cargando,
    error: error as Error | null,
  }
}

// ============================================
// 3. HOOK: useProyectosFiltrados
// ============================================
export function useProyectosFiltrados() {
  const [filtros, setFiltrosState] = useState<FiltroProyecto>({
    busqueda: '',
    estado: undefined,
    fechaDesde: undefined,
    fechaHasta: undefined,
    verArchivados: false,
  })

  const { proyectos, cargando } = useProyectosQuery()

  // Filtrado local (muy rápido, no requiere query nueva)
  const proyectosFiltrados = useMemo(() => {
    let resultado = [...proyectos]

    // ✅ Filtro por archivados (primero, para optimizar)
    if (!filtros.verArchivados) {
      // Por defecto, NO mostrar archivados
      resultado = resultado.filter(proyecto => !proyecto.archivado)
    }
    // Si verArchivados = true, mostrar todos (incluidos archivados)

    // Filtro por búsqueda
    if (filtros.busqueda) {
      const termino = filtros.busqueda.toLowerCase()
      resultado = resultado.filter(
        proyecto =>
          proyecto.nombre.toLowerCase().includes(termino) ||
          proyecto.ubicacion.toLowerCase().includes(termino) ||
          proyecto.descripcion.toLowerCase().includes(termino) ||
          (proyecto as any).responsable?.toLowerCase().includes(termino)
      )
    }

    // Filtro por estado (con compatibilidad para estados antiguos)
    if (filtros.estado) {
      if (filtros.estado === 'en_proceso') {
        resultado = resultado.filter(
          proyecto =>
            proyecto.estado === 'en_proceso' ||
            proyecto.estado === 'en_planificacion' ||
            proyecto.estado === 'en_construccion' ||
            proyecto.estado === 'pausado'
        )
      } else if (filtros.estado === 'completado') {
        resultado = resultado.filter(proyecto => proyecto.estado === 'completado')
      } else {
        resultado = resultado.filter(proyecto => proyecto.estado === filtros.estado)
      }
    }

    // Filtro por fechas
    if (filtros.fechaDesde) {
      resultado = resultado.filter(
        proyecto => new Date(proyecto.fechaInicio ?? '') >= new Date(filtros.fechaDesde!)
      )
    }

    if (filtros.fechaHasta) {
      resultado = resultado.filter(
        proyecto => new Date(proyecto.fechaInicio ?? '') <= new Date(filtros.fechaHasta!)
      )
    }

    return resultado
  }, [proyectos, filtros])

  const actualizarFiltros = (nuevosFiltros: Partial<FiltroProyecto>) => {
    setFiltrosState(prev => ({ ...prev, ...nuevosFiltros }))
  }

  const limpiarFiltros = () => {
    setFiltrosState({
      busqueda: '',
      estado: undefined,
      fechaDesde: undefined,
      fechaHasta: undefined,
      verArchivados: false,
    })
  }

  return {
    proyectos: proyectosFiltrados,
    filtros,
    cargando,
    actualizarFiltros,
    limpiarFiltros,
    totalProyectos: proyectos.length,
    proyectosFiltrados: proyectosFiltrados.length,
  }
}

// ============================================
// 4. HOOK: useVistaProyectos (UI state - NO usar React Query)
// ============================================
export function useVistaProyectos() {
  const [vista, setVista] = useState<'grid' | 'lista'>('grid')

  const cambiarVista = () => {
    setVista(prev => (prev === 'grid' ? 'lista' : 'grid'))
  }

  return {
    vista,
    esGrid: vista === 'grid',
    esLista: vista === 'lista',
    setVista,
    cambiarVista,
  }
}

// ============================================
// 5. HOOK: useEstadisticasProyectos
// ============================================
export function useEstadisticasProyectos() {
  const { proyectos } = useProyectosQuery()

  const estadisticas = useMemo(() => {
    // ✅ Filtrar solo proyectos NO archivados para estadísticas
    const proyectosActivos = proyectos.filter(p => !p.archivado)

    const total = proyectosActivos.length

    const enProceso = proyectosActivos.filter(
      p =>
        p.estado === 'en_proceso' ||
        p.estado === 'en_planificacion' ||
        p.estado === 'en_construccion' ||
        p.estado === 'pausado'
    ).length

    const completados = proyectosActivos.filter(p => p.estado === 'completado').length

    const presupuestoTotal = proyectosActivos.reduce((sum, p) => sum + p.presupuesto, 0)

    const progresoPromedio =
      proyectosActivos.length > 0
        ? proyectosActivos.reduce((sum, p) => sum + (p.progreso || 0), 0) / proyectosActivos.length
        : 0

    return {
      total,
      enProceso,
      completados,
      presupuestoTotal,
      progresoPromedio: Math.round(progresoPromedio),
    }
  }, [proyectos])

  return estadisticas
}

import { supabase } from '@/lib/supabase/client'
import type { Database } from '@/lib/supabase/database.types'
import { formatDateForDB, getTodayDateString } from '@/lib/utils/date.utils'
import { logger } from '@/lib/utils/logger'
import { auditService } from '@/services/audit.service'
import { getDepartamentos, validarCiudadDepartamento } from '@/shared/data/colombia-locations'

import type {
    EstadoManzana,
    EstadoProyecto,
    Manzana,
    Proyecto,
    ProyectoFormData,
} from '../types'
import { sanitizeProyectoFormData, sanitizeProyectoUpdate } from '../utils/sanitize-proyecto.utils'

/**
 * Servicio para gestionar proyectos usando Supabase
 * Incluye auditoría completa de todas las operaciones CRUD
 */
class ProyectosService {
  // ==================== CRUD OPERATIONS ====================

  /**
   * Obtiene todos los proyectos de la base de datos
   * @param incluirArchivados - Si es true, incluye proyectos archivados. Por defecto false.
   * @returns Array de proyectos con sus manzanas
   * @throws Error si falla la consulta a Supabase
   * @example
   * ```ts
   * const proyectos = await proyectosService.obtenerProyectos()
   * const todosIncluidos = await proyectosService.obtenerProyectos(true)
   * ```
   */
  async obtenerProyectos(incluirArchivados: boolean = false): Promise<Proyecto[]> {
    let query = supabase
      .from('proyectos')
      .select(
        `
                *,
                manzanas (
                    id,
                    nombre,
                    numero_viviendas
                )
            `
      )

    // Por defecto, solo mostrar proyectos activos (NO archivados)
    if (!incluirArchivados) {
      query = query.eq('archivado', false)
    }

    const { data, error } = await query.order('fecha_creacion', { ascending: false })

    if (error) {
      logger.error('Error al obtener proyectos:', error)
      throw new Error(`Error al obtener proyectos: ${error.message}`)
    }

    // Transformar datos de Supabase a formato de la aplicación
    return (data || []).map(d => this.transformarProyectoDeDB(d as any))
  }

  /**
   * Obtiene un proyecto específico por su ID
   * @param id - UUID del proyecto a buscar
   * @returns Proyecto encontrado o null si no existe
   * @throws Error si falla la consulta a Supabase
   * @example
   * ```ts
   * const proyecto = await proyectosService.obtenerProyecto('uuid-123')
   * if (proyecto) logger.info(proyecto.nombre)
   * ```
   */
  async obtenerProyecto(id: string): Promise<Proyecto | null> {
    const { data, error } = await supabase
      .from('proyectos')
      .select(
        `
                *,
                manzanas (
                    id,
                    nombre,
                    numero_viviendas
                )
            `
      )
      .eq('id', id)
      .single()

    if (error) {
      if (error.code === 'PGRST116') {
        return null // No encontrado
      }
      logger.error('Error al obtener proyecto:', error)
      throw new Error(`Error al obtener proyecto: ${error.message}`)
    }

    return this.transformarProyectoDeDB(data as any)
  }

  /**
   * Crea un nuevo proyecto en la base de datos
   * @param proyectoData - Datos del formulario de proyecto
   * @returns Proyecto creado con ID asignado
   * @throws Error si falla la creación o auditoría
   * @example
   * ```ts
   * const nuevoProyecto = await proyectosService.crearProyecto({
   *   nombre: 'Proyecto Norte',
   *   ubicacion: 'Calle 123 #45-67',
   *   estado: 'planificacion',
   *   manzanas: [{ nombre: 'A', numero_viviendas: 10 }]
   * })
   * ```
   */
  async crearProyecto(proyectoData: ProyectoFormData): Promise<Proyecto> {
    // 🧹 Sanitizar datos (strings vacíos → null)
    const formData = sanitizeProyectoFormData(proyectoData)

    // ✅ VALIDACIÓN: Departamento y ciudad contra catálogo de Colombia
    const departamentosValidos = getDepartamentos()
    if (!departamentosValidos.includes(formData.departamento)) {
      throw new Error(`Departamento inválido: "${formData.departamento}". Selecciona un departamento de Colombia válido.`)
    }
    if (!validarCiudadDepartamento(formData.ciudad, formData.departamento)) {
      throw new Error(`La ciudad "${formData.ciudad}" no pertenece al departamento "${formData.departamento}".`)
    }

    // Combinar los 3 campos de ubicación en el formato del campo DB
    const ubicacionCombinada = [formData.direccion, formData.ciudad, formData.departamento]
      .filter(Boolean)
      .join(', ')

    // 1. Crear el proyecto principal
    const { data: proyecto, error: errorProyecto } = await supabase
      .from('proyectos')
      .insert({
        nombre: formData.nombre,
        descripcion: formData.descripcion,
        ubicacion: ubicacionCombinada,
        fecha_inicio: formData.fechaInicio,
        fecha_fin_estimada: formData.fechaFinEstimada,
        presupuesto: formData.presupuesto,
        estado: formData.estado,
        progreso: 0,
      })
      .select()
      .single()

    if (errorProyecto) {
      logger.error('Error al crear proyecto:', errorProyecto)
      throw new Error(`Error al crear proyecto: ${errorProyecto.message}`)
    }

    // 2. Crear las manzanas si existen
    let manzanas: Manzana[] = []
    if (formData.manzanas && formData.manzanas.length > 0) {
      const manzanasData = formData.manzanas.map(m => ({
        proyecto_id: proyecto.id,
        nombre: m.nombre,
        numero_viviendas: m.totalViviendas,
      }))

      const { data: manzanasCreadas, error: errorManzanas } = await supabase
        .from('manzanas')
        .insert(manzanasData)
        .select()

      if (errorManzanas) {
        logger.error('Error al crear manzanas:', errorManzanas)
        // No lanzamos error aquí, el proyecto ya fue creado
      } else {
        manzanas = (manzanasCreadas || []).map(m => ({
          id: m.id,
          nombre: m.nombre,
          totalViviendas: m.numero_viviendas,
          viviendasVendidas: 0,
          precioBase:
            formData.manzanas.find(fm => fm.nombre === m.nombre)?.precioBase ||
            0,
          superficieTotal:
            formData.manzanas.find(fm => fm.nombre === m.nombre)
              ?.superficieTotal || 0,
          proyectoId: proyecto.id,
          estado: 'planificada' as EstadoManzana,
          fechaCreacion: m.fecha_creacion ?? '',
        })) as unknown as Manzana[]
      }
    }

    // 3. Preparar objeto completo para retornar
    const { departamento, ciudad, direccion } = this.parsearUbicacion(proyecto.ubicacion)
    const proyectoCompleto: Proyecto = {
      id: proyecto.id,
      nombre: proyecto.nombre,
      descripcion: proyecto.descripcion,
      ubicacion: proyecto.ubicacion,
      departamento,
      ciudad,
      direccion,
      fechaInicio: proyecto.fecha_inicio,
      fechaFinEstimada: proyecto.fecha_fin_estimada,
      presupuesto: proyecto.presupuesto,
      estado: proyecto.estado as any, // Type assertion para evitar error de tipos con Supabase
      progreso: proyecto.progreso,
      manzanas,
      fechaCreacion: proyecto.fecha_creacion ?? '',
      fechaActualizacion: proyecto.fecha_actualizacion ?? '',
      // ✅ Campos de archivado
      archivado: proyecto.archivado || false,
      fechaArchivado: proyecto.fecha_archivado || null,
      motivoArchivo: proyecto.motivo_archivo || null,
    }

    // 4. 🔍 AUDITORÍA DETALLADA: Registrar creación del proyecto con todos los detalles
    try {
      await auditService.auditarCreacionProyecto(proyectoCompleto, manzanas)
    } catch (auditError) {
      logger.error('Error al auditar creación de proyecto:', auditError)
      // No lanzamos error, la auditoría es secundaria
    }

    return proyectoCompleto
  }

  /**
   * Actualiza un proyecto existente y sus manzanas
   * @param id - UUID del proyecto a actualizar
   * @param data - Datos parciales del proyecto a actualizar
   * @returns Proyecto actualizado con cambios aplicados
   * @throws Error si no existe el proyecto o falla la actualización
   * @remarks
   * - Valida transiciones de estado coherentes
   * - Advierte al cambiar nombre con viviendas vendidas
   * - No permite marcar como completado si hay viviendas disponibles
   * - Actualiza/crea/elimina manzanas según cambios en formulario
   * @example
   * ```ts
   * const actualizado = await proyectosService.actualizarProyecto('uuid-123', {
   *   estado: 'en_construccion',
   *   fecha_inicio: '2025-01-15',
   *   manzanas: [{ nombre: 'A', totalViviendas: 15 }]
   * })
   * ```
   */
  async actualizarProyecto(
    id: string,
    data: Partial<ProyectoFormData>
  ): Promise<Proyecto> {
    // 1. 🔍 AUDITORÍA: Obtener datos ANTES de actualizar
    let proyectoAnterior: Proyecto | null = null
    try {
      proyectoAnterior = await this.obtenerProyecto(id)
    } catch (error) {
      if (error instanceof Error) {
        logger.error('[PROYECTOS] Error al obtener proyecto para auditoría:', error.message)
      } else {
        logger.error('[PROYECTOS] Error desconocido al obtener proyecto:', String(error))
      }
    }

    // 2. ✅ VALIDACIÓN: Advertencia al cambiar nombre con viviendas vendidas
    if (data.nombre && proyectoAnterior && proyectoAnterior.nombre !== data.nombre) {
      const { data: manzanas } = await supabase
        .from('manzanas')
        .select('id')
        .eq('proyecto_id', id)

      const manzanasIds = manzanas?.map(m => m.id) || []

      if (manzanasIds.length > 0) {
        const { count: viviendasVendidas } = await supabase
          .from('viviendas')
          .select('*', { count: 'exact', head: true })
          .eq('estado', 'vendida')
          .in('manzana_id', manzanasIds)

        if (viviendasVendidas && viviendasVendidas > 0) {
          logger.warn(
            `⚠️ ADVERTENCIA: Cambiando nombre de proyecto de "${proyectoAnterior.nombre}" a "${data.nombre}". ` +
            `El proyecto tiene ${viviendasVendidas} vivienda(s) vendida(s). ` +
            `Verificar que no afecte documentos legales o contratos.`
          )
        }
      }
    }

    // 3. ✅ VALIDACIÓN: Transiciones de estado coherentes
    if (data.estado && proyectoAnterior && proyectoAnterior.estado !== data.estado) {
      const { data: manzanas } = await supabase
        .from('manzanas')
        .select('id')
        .eq('proyecto_id', id)

      const manzanasIds = manzanas?.map(m => m.id) || []

      // No permitir marcar como "completado" si hay viviendas disponibles
      if (data.estado === 'completado' && manzanasIds.length > 0) {
        const { count: viviendasDisponibles } = await supabase
          .from('viviendas')
          .select('*', { count: 'exact', head: true })
          .eq('estado', 'Disponible')
          .in('manzana_id', manzanasIds)

        if (viviendasDisponibles && viviendasDisponibles > 0) {
          throw new Error(
            `No se puede marcar el proyecto como completado porque tiene ` +
            `${viviendasDisponibles} vivienda(s) aún disponibles. ` +
            `Todas las viviendas deben estar vendidas o reservadas.`
          )
        }
      }

      // Advertencia al pausar proyecto con negociaciones activas
      if (data.estado === 'pausado') {
        logger.warn(
          `⚠️ ADVERTENCIA: Pausando proyecto "${proyectoAnterior.nombre}". ` +
          `Verificar que no haya negociaciones activas o compromisos pendientes.`
        )
      }
    }

    // 4. Preparar datos para actualización
    // 🧹 Sanitizar datos (strings vacíos → null)
    const dataSanitizada = sanitizeProyectoUpdate(data)

    // ✅ VALIDACIÓN: Departamento y ciudad contra catálogo de Colombia (al actualizar ubicación)
    const departamentosValidos = getDepartamentos()
    if (dataSanitizada.departamento !== undefined) {
      if (!departamentosValidos.includes(dataSanitizada.departamento)) {
        throw new Error(`Departamento inválido: "${dataSanitizada.departamento}". Selecciona un departamento de Colombia válido.`)
      }
    }
    if (dataSanitizada.ciudad !== undefined) {
      const depActual = dataSanitizada.departamento ?? proyectoAnterior?.departamento ?? ''
      if (depActual && !validarCiudadDepartamento(dataSanitizada.ciudad, depActual)) {
        throw new Error(`La ciudad "${dataSanitizada.ciudad}" no pertenece al departamento "${depActual}".`)
      }
    }

    const updateData: Partial<Database['public']['Tables']['proyectos']['Update']> = {}

    // Mapear campos de la aplicación a campos de DB
    if (dataSanitizada.nombre !== undefined) updateData.nombre = dataSanitizada.nombre
    if (dataSanitizada.descripcion !== undefined) updateData.descripcion = dataSanitizada.descripcion
    // Reconstruir ubicacion combinada si alguno de los 3 campos cambió
    if (
      dataSanitizada.departamento !== undefined ||
      dataSanitizada.ciudad !== undefined ||
      dataSanitizada.direccion !== undefined
    ) {
      const dep = dataSanitizada.departamento ?? proyectoAnterior?.departamento ?? ''
      const ciu = dataSanitizada.ciudad ?? proyectoAnterior?.ciudad ?? ''
      const dir = dataSanitizada.direccion ?? proyectoAnterior?.direccion ?? ''
      updateData.ubicacion = [dir, ciu, dep].filter(Boolean).join(', ')
    }
    if (dataSanitizada.fechaInicio !== undefined) updateData.fecha_inicio = dataSanitizada.fechaInicio
    if (dataSanitizada.fechaFinEstimada !== undefined)
      updateData.fecha_fin_estimada = dataSanitizada.fechaFinEstimada
    if (dataSanitizada.presupuesto !== undefined)
      updateData.presupuesto = dataSanitizada.presupuesto
    if (dataSanitizada.estado !== undefined) updateData.estado = dataSanitizada.estado

    // 5. Actualizar proyecto en DB
    const { data: proyecto, error } = await supabase
      .from('proyectos')
      .update(updateData)
      .eq('id', id)
      .select(
        `
                *,
                manzanas (
                    id,
                    nombre,
                    numero_viviendas
                )
            `
      )
      .single()

    if (error) {
      logger.error('Error al actualizar proyecto:', error)
      throw new Error(`Error al actualizar proyecto: ${error.message}`)
    }

    // 6. ✅ Actualizar manzanas si se proporcionaron
    if (data.manzanas && data.manzanas.length > 0) {
      // Obtener IDs de manzanas existentes
      const manzanasExistentesIds = (proyecto.manzanas || []).map((m) => m.id)

      // Procesar cada manzana
      for (const manzana of data.manzanas) {
        const manzanaData = {
          proyecto_id: id,
          nombre: manzana.nombre,
          numero_viviendas: manzana.totalViviendas,
        }

        // Si la manzana tiene ID y existe en DB → Actualizar
        if ('id' in manzana && manzana.id && manzanasExistentesIds.includes(manzana.id)) {
          const { error: updateError } = await supabase
            .from('manzanas')
            .update(manzanaData)
            .eq('id', manzana.id)

          if (updateError) {
            logger.error('Error al actualizar manzana:', updateError)
          }
        }
        // Si NO tiene ID o NO existe en DB → Crear nueva
        else {
          const { error: insertError } = await supabase
            .from('manzanas')
            .insert(manzanaData)

          if (insertError) {
            logger.error('Error al crear manzana:', insertError)
          }
        }
      }

      // Eliminar manzanas que ya no están en el formulario
      // (Solo las que NO tienen viviendas - validación granular)
      const manzanasFormularioIds = data.manzanas
        .map((m) => 'id' in m ? m.id : null)
        .filter(Boolean) as string[]

      const manzanasAEliminar = manzanasExistentesIds.filter(
        id => !manzanasFormularioIds.includes(id)
      )

      for (const manzanaId of manzanasAEliminar) {
        // Verificar que no tenga viviendas antes de eliminar
        const { count } = await supabase
          .from('viviendas')
          .select('*', { count: 'exact', head: true })
          .eq('manzana_id', manzanaId)

        if (count === 0) {
          const { error: deleteError } = await supabase
            .from('manzanas')
            .delete()
            .eq('id', manzanaId)

          if (deleteError) {
            logger.error('Error al eliminar manzana:', deleteError)
          }
        }
      }
    }

    const proyectoActualizado = this.transformarProyectoDeDB(proyecto as any)

    // 7. 🔍 AUDITORÍA: Registrar actualización
    if (proyectoAnterior) {
      try {
        await auditService.auditarActualizacion(
          'proyectos',
          id,
          proyectoAnterior,
          proyectoActualizado,
          {
            campos_modificados: Object.keys(updateData),
          },
          'proyectos'
        )
      } catch (auditError) {
        logger.error('Error al auditar actualización de proyecto:', auditError)
      }
    }

    return proyectoActualizado
  }

  /**
   * Elimina un proyecto (soft delete - marca como archivado)
   * @param id - UUID del proyecto a eliminar
   * @throws Error si no existe el proyecto o falla la eliminación
   * @example
   * ```ts
   * await proyectosService.eliminarProyecto('uuid-123')
   * ```
   */
  async eliminarProyecto(id: string): Promise<void> {
    // 1. 🔍 AUDITORÍA: Obtener datos ANTES de eliminar
    let proyectoEliminado: Proyecto | null = null
    try {
      proyectoEliminado = await this.obtenerProyecto(id)
    } catch (error) {
      if (error instanceof Error) {
        logger.error('[PROYECTOS] Error al obtener proyecto para auditoría:', error.message)
      } else {
        logger.error('[PROYECTOS] Error desconocido al obtener proyecto:', String(error))
      }
    }

    // 2. ✅ VALIDACIÓN CRÍTICA: Verificar que NO tenga viviendas
    const { data: manzanas } = await supabase
      .from('manzanas')
      .select('id')
      .eq('proyecto_id', id)

    const manzanasIds = manzanas?.map(m => m.id) || []

    if (manzanasIds.length > 0) {
      // Verificar viviendas en las manzanas
      const { count: totalViviendas } = await supabase
        .from('viviendas')
        .select('*', { count: 'exact', head: true })
        .in('manzana_id', manzanasIds)

      if (totalViviendas && totalViviendas > 0) {
        throw new Error(
          `No se puede eliminar el proyecto porque tiene ${totalViviendas} vivienda(s) registrada(s). ` +
          `Por seguridad de datos, archive el proyecto en lugar de eliminarlo.`
        )
      }
    }

    // 3. ✅ VALIDACIÓN CRÍTICA: Verificar que NO tenga documentos
    const { count: totalDocumentos } = await supabase
      .from('documentos_proyecto')
      .select('*', { count: 'exact', head: true })
      .eq('proyecto_id', id)

    if (totalDocumentos && totalDocumentos > 0) {
      throw new Error(
        `No se puede eliminar el proyecto porque tiene ${totalDocumentos} documento(s) asociado(s). ` +
        `Elimine primero los documentos o archive el proyecto.`
      )
    }

    // 4. Eliminar de DB (solo si pasó todas las validaciones)
    const { error } = await supabase.from('proyectos').delete().eq('id', id)

    if (error) {
      logger.error('Error al eliminar proyecto:', error)
      throw new Error(`Error al eliminar proyecto: ${error.message}`)
    }

    // 5. 🔍 AUDITORÍA: Registrar eliminación
    if (proyectoEliminado) {
      try {
        await auditService.auditarEliminacion(
          'proyectos',
          id,
          proyectoEliminado,
          {
            nombre_proyecto: proyectoEliminado.nombre,
            total_manzanas: proyectoEliminado.manzanas.length,
            estado_al_eliminar: proyectoEliminado.estado,
          },
          'proyectos'
        )
      } catch (auditError) {
        logger.error('Error al auditar eliminación de proyecto:', auditError)
      }
    }
  }

  /**
   * Archiva un proyecto (soft delete sin eliminar datos)
   * @param id - UUID del proyecto a archivar
   * @param motivo - Razón del archivado (opcional)
   * @throws Error si no existe el proyecto o falla el archivado
   * @remarks
   * - Permite ocultar proyectos manteniendo historial completo
   * - No afecta viviendas, manzanas ni documentos asociados
   * - Registra fecha y motivo del archivado
   * @example
   * ```ts
   * await proyectosService.archivarProyecto('uuid-123', 'Proyecto cancelado por cliente')
   * ```
   */
  async archivarProyecto(id: string, motivo?: string): Promise<void> {
    // 1. 🔍 AUDITORÍA: Obtener datos ANTES de archivar
    let proyectoArchivado: Proyecto | null = null
    try {
      proyectoArchivado = await this.obtenerProyecto(id)
    } catch (error) {
      if (error instanceof Error) {
        logger.error('[PROYECTOS] Error al obtener proyecto para auditoría:', error.message)
      } else {
        logger.error('[PROYECTOS] Error desconocido al obtener proyecto:', String(error))
      }
    }

    // 2. Archivar proyecto
    const { error } = await supabase
      .from('proyectos')
      .update({
        archivado: true,
        fecha_archivado: formatDateForDB(getTodayDateString()),
        motivo_archivo: motivo || null,
      })
      .eq('id', id)

    if (error) {
      logger.error('Error al archivar proyecto:', error)
      throw new Error(`Error al archivar proyecto: ${error.message}`)
    }

    // 3. 🔍 AUDITORÍA: Registrar archivado
    if (proyectoArchivado) {
      try {
        await auditService.auditarActualizacion(
          'proyectos',
          id,
          proyectoArchivado,
          { ...proyectoArchivado, archivado: true },
          {
            accion: 'archivado',
            motivo_archivo: motivo,
            nombre_proyecto: proyectoArchivado.nombre,
            estado_al_archivar: proyectoArchivado.estado,
          },
          'proyectos'
        )
      } catch (auditError) {
        logger.error('Error al auditar archivado de proyecto:', auditError)
      }
    }
  }

  /**
   * Restaura un proyecto archivado
   * @param id - UUID del proyecto a restaurar
   * @throws Error si no existe el proyecto o falla la restauración
   * @remarks
   * - Quita marca de archivado y limpia metadatos
   * - Restaura acceso completo al proyecto
   * @example
   * ```ts
   * await proyectosService.restaurarProyecto('uuid-123')
   * ```
   */
  async restaurarProyecto(id: string): Promise<void> {
    // 1. 🔍 AUDITORÍA: Obtener datos ANTES de restaurar
    let proyectoRestaurado: Proyecto | null = null
    try {
      proyectoRestaurado = await this.obtenerProyecto(id)
    } catch (error) {
      if (error instanceof Error) {
        logger.error('[PROYECTOS] Error al obtener proyecto para auditoría:', error.message)
      } else {
        logger.error('[PROYECTOS] Error desconocido al obtener proyecto:', String(error))
      }
    }

    // 2. Restaurar proyecto
    const { error } = await supabase
      .from('proyectos')
      .update({
        archivado: false,
        fecha_archivado: null,
        motivo_archivo: null,
      })
      .eq('id', id)

    if (error) {
      logger.error('Error al restaurar proyecto:', error)
      throw new Error(`Error al restaurar proyecto: ${error.message}`)
    }

    // 3. 🔍 AUDITORÍA: Registrar restauración
    if (proyectoRestaurado) {
      try {
        await auditService.auditarActualizacion(
          'proyectos',
          id,
          proyectoRestaurado,
          { ...proyectoRestaurado, archivado: false },
          {
            accion: 'restaurado',
            nombre_proyecto: proyectoRestaurado.nombre,
          },
          'proyectos'
        )
      } catch (auditError) {
        logger.error('Error al auditar restauración de proyecto:', auditError)
      }
    }
  }

  // ==================== ELIMINACIÓN DEFINITIVA (ADMIN ONLY) ====================

  /**
   * Elimina definitivamente un proyecto de la base de datos
   * @param id - UUID del proyecto a eliminar
   * @throws Error si el proyecto no está archivado o falla la eliminación
   * @remarks
   * - ⚠️ SOLO ADMINS - Acción irreversible
   * - Requiere que el proyecto esté archivado primero
   * - Elimina también manzanas sin viviendas asociadas
   * @example
   * ```ts
   * await proyectosService.eliminarProyectoDefinitivo('uuid-123')
   * ```
   */
  async eliminarProyectoDefinitivo(id: string): Promise<void> {
    // 1. Verificar que el proyecto esté archivado
    const { data: proyecto } = await supabase
      .from('proyectos')
      .select('archivado, nombre')
      .eq('id', id)
      .single()

    if (!proyecto?.archivado) {
      throw new Error(
        'El proyecto debe estar archivado antes de eliminarlo definitivamente. ' +
        'Archive primero el proyecto y luego proceda con la eliminación.'
      )
    }

    // 2. Ejecutar eliminación normal (con todas las validaciones)
    await this.eliminarProyecto(id)
  }

  // Métodos de transformación
  private parsearUbicacion(ubicacion: string): { departamento: string; ciudad: string; direccion: string } {
    const partes = ubicacion.split(', ')
    if (partes.length >= 3) {
      return {
        departamento: partes[partes.length - 1],
        ciudad: partes[partes.length - 2],
        direccion: partes.slice(0, -2).join(', '),
      }
    } else if (partes.length === 2) {
      return { departamento: partes[1], ciudad: partes[0], direccion: '' }
    }
    return { departamento: '', ciudad: '', direccion: ubicacion }
  }

  private transformarProyectoDeDB(data: Database['public']['Tables']['proyectos']['Row'] & {
    manzanas?: Array<Database['public']['Tables']['manzanas']['Row']>
  }): Proyecto {
    const { departamento, ciudad, direccion } = this.parsearUbicacion(data.ubicacion)
    return {
      id: data.id,
      nombre: data.nombre,
      descripcion: data.descripcion,
      ubicacion: data.ubicacion,
      departamento,
      ciudad,
      direccion,
      fechaInicio: data.fecha_inicio,
      fechaFinEstimada: data.fecha_fin_estimada,
      presupuesto: data.presupuesto,
      estado: data.estado as EstadoProyecto,
      progreso: data.progreso,
      manzanas: (data.manzanas || []).map((m) => ({
        id: m.id,
        nombre: m.nombre,
        totalViviendas: m.numero_viviendas || 0,
        viviendasVendidas: 0,
        precioBase: 0,
        superficieTotal: 0,
        proyectoId: data.id,
        estado: 'planificada' as EstadoManzana,
        fechaCreacion: m.fecha_creacion || formatDateForDB(getTodayDateString()),
      })),
      fechaCreacion: data.fecha_creacion ?? '',
      fechaActualizacion: data.fecha_actualizacion ?? '',
      // ✅ Campos de archivado
      archivado: data.archivado || false,
      fechaArchivado: data.fecha_archivado || null,
      motivoArchivo: data.motivo_archivo || null,
    }
  }

  /**
   * Verifica si ya existe un proyecto con el mismo nombre (case-insensitive)
   * @param nombre - Nombre del proyecto a verificar
   * @param excludeId - ID del proyecto a excluir (para edición)
   * @returns true si el nombre ya existe, false si está disponible
   */
  async verificarNombreDuplicado(
    nombre: string,
    excludeId?: string
  ): Promise<boolean> {
    const { data, error } = await supabase
      .from('proyectos')
      .select('id, nombre')
      .ilike('nombre', nombre) // Case-insensitive comparison

    if (error) {
      logger.error('Error al verificar nombre duplicado:', error)
      throw new Error(`Error al verificar nombre: ${error.message}`)
    }

    // Si estamos editando, excluir el proyecto actual
    const duplicados = excludeId
      ? data?.filter(p => p.id !== excludeId) || []
      : data || []

    return duplicados.length > 0
  }
}

