              >
                <Upload className="w-6 h-6 text-gray-400 mb-1" />
                <p className="text-xs text-gray-500 dark:text-gray-400">PDF, PNG, JPG (máx 10 MB)</p>
              </div>
            )}
          </div>

          {/* Notas cierre */}
          <div>
            <label className={s.label}>
              Notas de cierre <span className="text-gray-400 font-normal normal-case">(opcional)</span>
            </label>
            <textarea
              rows={2}
              className={s.textarea}
              value={notasCierre}
              onChange={(e) => setNotasCierre(e.target.value)}
              placeholder="Observaciones sobre la devolución..."
            />
          </div>

          {/* Error */}
          {error ? (
            <div className={s.errorBox}>
              <AlertTriangle className="w-4 h-4 flex-shrink-0 mt-0.5" />
              <span>{error}</span>
            </div>
          ) : null}
        </div>

        {/* Footer */}
        <div className={s.footer}>
          <button onClick={onClose} className={s.btnSecondary}>Cancelar</button>
          <button
            onClick={handleConfirmar}
            disabled={!formularioValido}
            className={s.btnPrimary}
          >
            <CheckCircle className="w-4 h-4" />
            Confirmar Devolución
          </button>
        </div>
      </motion.div>
    </motion.div>
  )
}

'use client'

import { useCallback, useEffect, useMemo, useState } from 'react'

import { logger } from '@/lib/utils/logger'

import { obtenerAbonosNegociacion, obtenerNegociacionExpediente, obtenerRenunciaPorConsecutivo, obtenerViviendaExpediente } from '../services/renuncias.service'
import type {
    AbonoExpediente,
    ExpedienteData,
    FuenteExpediente,
    RenunciaConInfo,
    ResumenFinanciero,
    TimelineHito,
    ViviendaDetalle,
} from '../types'
import { transformarRenunciaRow } from '../utils/renuncias.utils'

interface UseExpedienteRenunciaReturn {
  datos: ExpedienteData | null
  cargando: boolean
  error: string | null
  recargar: () => void
}

export function useExpedienteRenuncia(consecutivo: string): UseExpedienteRenunciaReturn {
  const [renuncia, setRenuncia] = useState<RenunciaConInfo | null>(null)
  const [abonos, setAbonos] = useState<AbonoExpediente[]>([])
  const [negociacion, setNegociacion] = useState<any>(null)
  const [viviendaDetalle, setViviendaDetalle] = useState<ViviendaDetalle | null>(null)
  const [cargando, setCargando] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const cargarDatos = useCallback(async () => {
    setCargando(true)
    setError(null)

    try {
      // 1. Renuncia completa
      const row = await obtenerRenunciaPorConsecutivo(consecutivo)
      const renunciaInfo = transformarRenunciaRow(row)
      setRenuncia(renunciaInfo)

      // 2. Abonos + negociación + vivienda en paralelo
      const negId = row.negociacion_id
      const vivId = row.vivienda_id
      const promises: Promise<unknown>[] = [
        obtenerViviendaExpediente(vivId),
      ]
      if (negId) {
        promises.push(obtenerAbonosNegociacion(negId), obtenerNegociacionExpediente(negId))
      }
      const results = await Promise.all(promises)
      setViviendaDetalle(results[0] ?? null)
      if (negId) {
        setAbonos(results[1] ?? [])
        setNegociacion(results[2] ?? null)
      }
    } catch (err: unknown) {
      logger.error('Error cargando expediente:', err)
      setError(err.message ?? 'Error al cargar expediente')
    } finally {
      setCargando(false)
    }
  }, [consecutivo])

  useEffect(() => {
    cargarDatos()
  }, [cargarDatos])

  // ==========================================
  // DATOS DERIVADOS
  // ==========================================

  const timeline = useMemo((): TimelineHito[] => {
    if (!renuncia) return []

    const hitos: TimelineHito[] = []

    // Inicio de negociación
    const fechaInicio = negociacion?.fecha_negociacion
    if (fechaInicio) {
      hitos.push({ label: 'Inicio de negociación', fecha: fechaInicio, icono: 'Handshake', completado: true })
    }

    // Primer abono
    const abonosActivos = abonos.filter(a => a.estado === 'Activo')
    if (abonosActivos.length > 0) {
      hitos.push({ label: 'Primer abono', fecha: abonosActivos[0].fecha_abono, icono: 'DollarSign', completado: true })
    }

    // Último abono (si hay más de 1)
    if (abonosActivos.length > 1) {
      hitos.push({ label: 'Último abono', fecha: abonosActivos[abonosActivos.length - 1].fecha_abono, icono: 'TrendingUp', completado: true })
    }

    // Solicitud de renuncia
    hitos.push({ label: 'Solicitud de renuncia', fecha: renuncia.fecha_renuncia, icono: 'FileX', completado: true })

    // Cierre
    if (renuncia.fecha_cierre) {
      hitos.push({ label: 'Cierre de renuncia', fecha: renuncia.fecha_cierre, icono: 'CheckCircle', completado: true })
    }

    // Devolución procesada
    if (renuncia.fecha_devolucion) {
      hitos.push({ label: 'Devolución procesada', fecha: renuncia.fecha_devolucion, icono: 'Banknote', completado: true })
    }

    return hitos
  }, [renuncia, abonos, negociacion])

  const fuentes = useMemo((): FuenteExpediente[] => {
    if (!renuncia?.abonos_snapshot) return []
    const snap = renuncia.abonos_snapshot
    if (Array.isArray(snap)) {
      const mapped = snap.map((f: any) => ({
        tipo: f.tipo ?? 'N/A',
        entidad: f.entidad ?? null,
        monto_aprobado: Number(f.monto_aprobado ?? 0),
        monto_recibido: Number(f.monto_recibido ?? 0),
        estado: f.estado ?? 'Inactiva',
        fecha_resolucion: f.fecha_resolucion ?? null,
        fecha_completado: f.fecha_completado ?? null,
      }))
      // Ordenar por prioridad estándar (tipos_fuentes_pago.orden)
      return mapped.sort((a, b) => getFuenteOrden(a.tipo) - getFuenteOrden(b.tipo))
    }
    return []
  }, [renuncia])

  const resumenFinanciero = useMemo((): ResumenFinanciero => {
    if (!renuncia) {
      return { valorNegociado: 0, totalAbonado: 0, saldoPendiente: 0, porcentajePagado: 0, descuento: null, retencion: null, montoADevolver: 0 }
    }

    const valorNegociado = renuncia.negociacion.valor_total_pagar ?? renuncia.negociacion.valor_total ?? 0
    const totalAbonado = abonosActivos(abonos)
    const saldoPendiente = valorNegociado - totalAbonado
    const porcentajePagado = valorNegociado > 0 ? (totalAbonado / valorNegociado) * 100 : 0

    const descuento = negociacion?.descuento_aplicado
      ? {
          tipo: negociacion.tipo_descuento ?? 'N/A',
          porcentaje: negociacion.porcentaje_descuento ?? 0,
          monto: negociacion.descuento_aplicado,
          motivo: negociacion.motivo_descuento ?? '',
        }
      : null

    const retencion = renuncia.retencion_monto > 0
      ? { monto: renuncia.retencion_monto, motivo: renuncia.retencion_motivo ?? '' }
      : null

    return {
      valorNegociado,
      totalAbonado,
      saldoPendiente,
      porcentajePagado,
      descuento,
      retencion,
      montoADevolver: renuncia.monto_a_devolver,
    }
  }, [renuncia, abonos, negociacion])

  const duracionDias = useMemo(() => {
    if (!renuncia || !negociacion?.fecha_negociacion) return 0
    const inicio = new Date(negociacion.fecha_negociacion)
    const fin = new Date(renuncia.fecha_renuncia)
    return Math.max(0, Math.round((fin.getTime() - inicio.getTime()) / (1000 * 60 * 60 * 24)))
  }, [renuncia, negociacion])

  const datos = useMemo((): ExpedienteData | null => {
    if (!renuncia) return null
    return {
      renuncia,
      abonos,
      negociacion: {
        fecha_negociacion: negociacion?.fecha_negociacion ?? null,
        valor_negociado: negociacion?.valor_negociado ?? null,
        descuento_aplicado: negociacion?.descuento_aplicado ?? null,
        tipo_descuento: negociacion?.tipo_descuento ?? null,
        porcentaje_descuento: negociacion?.porcentaje_descuento ?? null,
        motivo_descuento: negociacion?.motivo_descuento ?? null,
        promesa_compraventa_url: negociacion?.promesa_compraventa_url ?? null,
        promesa_firmada_url: negociacion?.promesa_firmada_url ?? null,
      },
      viviendaDetalle,
      timeline,
      resumenFinanciero,
      fuentes,
      duracionDias,
    }
  }, [renuncia, abonos, negociacion, viviendaDetalle, timeline, resumenFinanciero, fuentes, duracionDias])

  return { datos, cargando, error, recargar: cargarDatos }
}

// ==========================================
// HELPERS
// ==========================================

function abonosActivos(abonos: AbonoExpediente[]): number {
  return abonos
    .filter(a => a.estado === 'Activo')
    .reduce((sum, a) => sum + a.monto, 0)
}

/** Orden estándar de fuentes (coincide con tipos_fuentes_pago.orden) */
const FUENTE_ORDEN: Record<string, number> = {
  'Cuota Inicial': 1,
  'Crédito Hipotecario': 2,
  'Subsidio Mi Casa Ya': 3,
  'Subsidio Caja Compensación': 4,
  'Crédito con la Constructora': 5,
  // Alias comunes
  'Subsidio Comfandi': 4,
}

function getFuenteOrden(tipo: string): number {
  return FUENTE_ORDEN[tipo] ?? 99
}

/**
 * ============================================
 * REACT QUERY: Renuncias
 * ============================================
 *
 * Query keys, hooks de query y mutations standalone.
 */

'use client'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { logger } from '@/lib/utils/logger'

import {
    obtenerMetricas,
    obtenerRenuncia,
    obtenerRenuncias,
    procesarDevolucion,
    registrarRenuncia,
    subirComprobante,
    subirFormularioRenuncia,
    validarPuedeRenunciar,
} from '../services/renuncias.service'
import type { ProcesarDevolucionDTO, RegistrarRenunciaDTO } from '../types'
import { transformarRenunciaRow } from '../utils/renuncias.utils'

// ============================================
// QUERY KEYS
// ============================================

export const renunciasKeys = {
  all: ['renuncias'] as const,
  lists: () => [...renunciasKeys.all, 'list'] as const,
  list: (filtros?: Record<string, unknown>) => [...renunciasKeys.lists(), { filtros }] as const,
  details: () => [...renunciasKeys.all, 'detail'] as const,
  detail: (id: string) => [...renunciasKeys.details(), id] as const,
  metricas: () => [...renunciasKeys.all, 'metricas'] as const,
  validacion: (negociacionId: string) => [...renunciasKeys.all, 'validacion', negociacionId] as const,
}

// ============================================
// QUERIES
// ============================================

/** Hook para obtener todas las renuncias */
export function useRenunciasQuery() {
  return useQuery({
    queryKey: renunciasKeys.lists(),
    queryFn: async () => {
      const rows = await obtenerRenuncias()
      return rows.map(transformarRenunciaRow)
    },
  })
}

/** Hook para obtener una renuncia por ID */
export function useRenunciaDetailQuery(id: string | null) {
  return useQuery({
    queryKey: renunciasKeys.detail(id ?? ''),
    queryFn: async () => {
      if (!id) throw new Error('ID requerido')
      const row = await obtenerRenuncia(id)
      return transformarRenunciaRow(row)
    },
    enabled: !!id,
  })
}

/** Hook para obtener métricas */
export function useRenunciasMetricas() {
  return useQuery({
    queryKey: renunciasKeys.metricas(),
    queryFn: obtenerMetricas,
  })
}

/** Hook para validar si una negociación puede renunciar */
export function useValidarRenuncia(negociacionId: string | null) {
  return useQuery({
    queryKey: renunciasKeys.validacion(negociacionId ?? ''),
    queryFn: () => validarPuedeRenunciar(negociacionId!),
    enabled: !!negociacionId,
  })
}

// ============================================
// MUTATIONS
// ============================================

/** Mutation standalone: registrar renuncia */
export function useRegistrarRenuncia() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async ({
      dto,
      formularioRenuncia,
    }: {
      dto: RegistrarRenunciaDTO
      formularioRenuncia?: File
    }) => {
      // 1. Registrar renuncia (RPC atómica)
      const result = await registrarRenuncia(dto)
      const rpcResult = result as Record<string, unknown> | null

      // 2. Si hay formulario, subirlo post-RPC
      const renunciaId = rpcResult?.renuncia_id as string | undefined
      if (formularioRenuncia && renunciaId) {
        try {
          await subirFormularioRenuncia(formularioRenuncia, renunciaId)
        } catch (err) {
          logger.warn('⚠️ Formulario no se pudo subir, renuncia ya registrada:', err)
          toast.warning('Renuncia registrada, pero el formulario no se pudo adjuntar. Intente subirlo nuevamente.')
        }
      } else if (formularioRenuncia && !renunciaId) {
        logger.warn('⚠️ No se pudo extraer renuncia_id del RPC para subir formulario. Result:', result)
        toast.warning('Renuncia registrada, pero el formulario no se pudo adjuntar.')
      }

      return result
    },
    onSuccess: () => {
      toast.success('Renuncia registrada exitosamente')
      queryClient.invalidateQueries({ queryKey: renunciasKeys.all })
      queryClient.invalidateQueries({ queryKey: ['clientes'] })
      queryClient.invalidateQueries({ queryKey: ['viviendas'] })
      queryClient.invalidateQueries({ queryKey: ['negociaciones'] })
      queryClient.invalidateQueries({ queryKey: ['abonos'] })
    },
    onError: (error: Error) => {
      logger.error('❌ Error registrando renuncia:', error)
      toast.error(error.message || 'Error al registrar renuncia')
    },
  })
}

/** Mutation standalone: procesar devolución */
export function useProcesarDevolucion() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async ({
      renunciaId,
      dto,
      comprobante,
    }: {
      renunciaId: string
      dto: ProcesarDevolucionDTO
      comprobante?: File
    }) => {
      let comprobanteUrl: string | undefined

      if (comprobante) {
        comprobanteUrl = await subirComprobante(comprobante, renunciaId)
      }

      return procesarDevolucion(renunciaId, {
        ...dto,
        comprobante_devolucion_url: comprobanteUrl ?? dto.comprobante_devolucion_url,
      })
    },
    onSuccess: () => {
      toast.success('Devolución procesada exitosamente')
      queryClient.invalidateQueries({ queryKey: renunciasKeys.all })
    },
    onError: (error: Error) => {
      logger.error('❌ Error procesando devolución:', error)
      toast.error(error.message || 'Error al procesar devolución')
    },
  })
}

// =====================================================
// SERVICIO: Módulo de Renuncias
// Comunicación con Supabase (queries + RPC)
// =====================================================

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'

import type {
    AbonoExpediente,
    MetricasRenuncias,
    ProcesarDevolucionDTO,
    RegistrarRenunciaDTO,
    RenunciaCompletaRow,
    ValidacionRenuncia,
} from '../types'

// =====================================================
// OBTENER RENUNCIAS (vista v_renuncias_completas)
// =====================================================

export async function obtenerRenuncias(): Promise<RenunciaCompletaRow[]> {
  // @ts-ignore - vista existe en BD pero puede no estar en tipos generados
  const { data, error } = await supabase
    .from('v_renuncias_completas')
    .select('*')

  if (error) {
    logger.error('❌ Error obteniendo renuncias:', error)
    throw new Error(`Error al obtener renuncias: ${error.message}`)
  }

  return (data ?? []) as RenunciaCompletaRow[]
}

// =====================================================
// OBTENER RENUNCIA POR ID
// =====================================================

export async function obtenerRenuncia(id: string): Promise<RenunciaCompletaRow> {
  // @ts-ignore - vista existe en BD
  const { data, error } = await supabase
    .from('v_renuncias_completas')
    .select('*')
    .eq('id', id)
    .single()

  if (error) {
    logger.error('❌ Error obteniendo renuncia:', error)
    throw new Error(`Error al obtener renuncia: ${error.message}`)
  }

  return data as RenunciaCompletaRow
}

// =====================================================
// VALIDAR PRE-RENUNCIA
// =====================================================

/**
 * Valida si una negociación puede renunciar.
 * Checks: estado válido, sin renuncia previa, sin desembolsos.
 */
export async function validarPuedeRenunciar(negociacionId: string): Promise<ValidacionRenuncia> {
  // 1. Obtener negociación con cliente y vivienda (separate joins for reliability)
  const { data: neg, error: errNeg } = await supabase
    .from('negociaciones')
    .select('id, estado, valor_total, total_abonado, cliente_id, vivienda_id')
    .eq('id', negociacionId)
    .single()

  if (errNeg || !neg) {
    throw new Error('Negociación no encontrada')
  }

  // 2. Obtener cliente
  const { data: cliente } = await supabase
    .from('clientes')
    .select('id, nombre_completo, numero_documento')
    .eq('id', neg.cliente_id)
    .single()

  // 3. Obtener vivienda → manzana → proyecto
  const { data: vivienda } = await supabase
    .from('viviendas')
    .select('id, numero, manzana_id')
    .eq('id', neg.vivienda_id)
    .single()

  let manzanaNombre = ''
  let proyectoNombre = ''

  if (vivienda?.manzana_id) {
    const { data: manzana } = await supabase
      .from('manzanas')
      .select('nombre, proyecto_id')
      .eq('id', vivienda.manzana_id)
      .single()

    if (manzana) {
      manzanaNombre = manzana.nombre ?? ''
      const { data: proyecto } = await supabase
        .from('proyectos')
        .select('nombre')
        .eq('id', manzana.proyecto_id)
        .single()
      proyectoNombre = proyecto?.nombre ?? ''
    }
  }

  const negInfo = {
    id: neg.id,
    estado: neg.estado,
    cliente_nombre: cliente?.nombre_completo ?? 'N/A',
    vivienda_numero: vivienda?.numero ?? 'N/A',
    manzana_nombre: manzanaNombre,
    proyecto_nombre: proyectoNombre,
  }

  const totalAbonado = Number(neg.total_abonado ?? 0)

  // Validar estado
  const estadosValidos = ['Activa', 'Suspendida']
  if (!estadosValidos.includes(neg.estado)) {
    return {
      puede_renunciar: false,
      motivo_bloqueo: `Solo negociaciones Activas o Suspendidas pueden renunciar. Estado actual: ${neg.estado}`,
      negociacion: negInfo,
      total_abonado: 0,
      fuentes_con_desembolso: [],
    }
  }

  // Validar sin renuncia previa
  const { data: renunciaExistente } = await supabase
    .from('renuncias')
    .select('id')
    .eq('negociacion_id', negociacionId)
    .maybeSingle()

  if (renunciaExistente) {
    return {
      puede_renunciar: false,
      motivo_bloqueo: 'Ya existe una renuncia registrada para esta negociación',
      negociacion: negInfo,
      total_abonado: 0,
      fuentes_con_desembolso: [],
    }
  }

  // 4. Obtener fuentes de pago para validar desembolsos
  const { data: fuentes = [] } = await supabase
    .from('fuentes_pago')
    .select('id, tipo, estado, monto_recibido')
    .eq('negociacion_id', negociacionId)

  const fuentesConDesembolso = (fuentes ?? [])
    .filter((f: any) => {
      // Solo fuentes externas (no Cuota Inicial): si tienen monto_recibido > 0 implica desembolso
      const esExterna = !['Cuota Inicial'].includes(f.tipo ?? '')
      return esExterna && (f.monto_recibido ?? 0) > 0
    })
    .map((f: any) => f.tipo ?? 'Desconocida')

  if (fuentesConDesembolso.length > 0) {
    return {
      puede_renunciar: false,
      motivo_bloqueo: `Fuente(s) con desembolso: ${fuentesConDesembolso.join(', ')}. No se puede renunciar.`,
      negociacion: negInfo,
      total_abonado: 0,
      fuentes_con_desembolso: fuentesConDesembolso,
    }
  }

  return {
    puede_renunciar: true,
    negociacion: negInfo,
    total_abonado: totalAbonado,
    fuentes_con_desembolso: [],
  }
}

// =====================================================
// REGISTRAR RENUNCIA (RPC atómica)
// =====================================================

export async function registrarRenuncia(dto: RegistrarRenunciaDTO) {
  const { data: session } = await supabase.auth.getSession()
  const userId = session?.session?.user?.id ?? null

  const { data, error } = await supabase.rpc('registrar_renuncia_completa', {
    p_negociacion_id: dto.negociacion_id,
    p_motivo: dto.motivo.trim(),
    p_retencion_monto: dto.retencion_monto ?? 0,
    p_retencion_motivo: dto.retencion_motivo?.trim() || undefined,
    p_notas: dto.notas?.trim() || undefined,
    p_usuario_id: userId ?? undefined,
  })

  if (error) {
    logger.error('❌ Error registrando renuncia:', error)
    throw new Error(error.message)
  }

  return data
}

// =====================================================
// PROCESAR DEVOLUCIÓN
// =====================================================

export async function procesarDevolucion(renunciaId: string, dto: ProcesarDevolucionDTO) {
  const { data: session } = await supabase.auth.getSession()
  const userId = session?.session?.user?.id ?? null

  // Resolver nombre + rol del usuario (mismo formato que registrar_renuncia_completa en DB)
  let usuarioCierreLabel: string | null = userId
  if (userId) {
    const { data: perfil } = await supabase
      .from('usuarios')
      .select('nombres, apellidos, rol')
      .eq('id', userId)
      .single()
    if (perfil) {
      usuarioCierreLabel = `${perfil.nombres} ${perfil.apellidos} (${perfil.rol})`
    }
  }

  const { data, error } = await supabase
    .from('renuncias')
    .update({
      estado: 'Cerrada',
      fecha_devolucion: dto.fecha_devolucion,
      metodo_devolucion: dto.metodo_devolucion,
      numero_comprobante: dto.numero_comprobante?.trim() || null,
      comprobante_devolucion_url: dto.comprobante_devolucion_url || null,
      notas_cierre: dto.notas_cierre?.trim() || null,
      fecha_cierre: new Date().toISOString(),
      usuario_cierre: usuarioCierreLabel,
    })
    .eq('id', renunciaId)
    .eq('estado', 'Pendiente Devolución')
    .select()
    .single()

  if (error) {
    logger.error('❌ Error procesando devolución:', error)
    throw new Error(error.message)
  }

  return data
}

// =====================================================
// SUBIR COMPROBANTE
// =====================================================

export async function subirComprobante(file: File, renunciaId: string): Promise<string> {
  const ext = file.name.split('.').pop()
  const filePath = `${renunciaId}/${Date.now()}.${ext}`

  const { error } = await supabase.storage
    .from('renuncias-comprobantes')
    .upload(filePath, file, { upsert: false })

  if (error) {
    logger.error('❌ Error subiendo comprobante:', error)
    throw new Error(`Error al subir comprobante: ${error.message}`)
  }

  // 🔒 Bucket privado: guardamos el PATH (no la URL pública).
  // Para visualizar se usa generarUrlFirmadaComprobante(path).
  return filePath
}

/**
 * Genera una URL firmada (expiración 1 hora) para ver un comprobante privado.
 * El valor puede ser:
 *   - Un path relativo: "uuid/1234567890.pdf"  (registros nuevos)
 *   - Una URL pública completa (registros anteriores al bucket privado)
 * En ambos casos se extrae el path correcto antes de llamar a createSignedUrl.
 */
export async function generarUrlFirmadaComprobante(pathOrUrl: string): Promise<string> {
  // Normalizar: si viene una URL completa, extraer solo el path relativo al bucket
  const BUCKET = 'renuncias-comprobantes'
  let filePath = pathOrUrl
  const marker = `/${BUCKET}/`
  const idx = pathOrUrl.indexOf(marker)
  if (idx !== -1) {
    filePath = pathOrUrl.slice(idx + marker.length)
  }

  const { data, error } = await supabase.storage
    .from(BUCKET)
    .createSignedUrl(filePath, 3600) // 1 hora de expiración

  if (error || !data?.signedUrl) {
    logger.error('❌ Error generando URL firmada:', error)
    throw new Error('No se pudo generar el enlace al comprobante')
  }

  return data.signedUrl
}

// =====================================================
// SUBIR FORMULARIO DE RENUNCIA
// =====================================================

/**
 * Sube el formulario de renuncia al bucket privado y actualiza la columna en la tabla.
 * Se ejecuta DESPUÉS de registrar la renuncia exitosamente.
 */
export async function subirFormularioRenuncia(file: File, renunciaId: string): Promise<string> {
  const ext = file.name.split('.').pop()
  const filePath = `${renunciaId}/formulario-renuncia.${ext}`

  const { error: uploadError } = await supabase.storage
    .from('renuncias-comprobantes')
    .upload(filePath, file, { upsert: true })

  if (uploadError) {
    logger.error('❌ Error subiendo formulario de renuncia:', uploadError)
    throw new Error(`Error al subir formulario: ${uploadError.message}`)
  }

  // Actualizar la columna en la tabla renuncias
  const { error: updateError } = await supabase
    .from('renuncias')
    .update({ formulario_renuncia_url: filePath })
    .eq('id', renunciaId)

  if (updateError) {
    logger.error('❌ Error actualizando URL formulario:', updateError)
    throw new Error(`Error al vincular formulario: ${updateError.message}`)
  }

  return filePath
}

