    setFormulario({
      nombres: '',
      apellidos: '',
      telefono: '',
      rol: 'Contador',
      estado: 'Activo',
    })
    setErrores({})
    onClose()
  }

  if (!usuario) return null

  return (
    <Modal isOpen={isOpen} onClose={handleCerrar} title="Editar Usuario" maxWidth="lg">
      <form onSubmit={handleSubmit} className="space-y-3">
