/**
 * EJEMPLO DE USO - FORMULARIO CON VALIDACIONES COMPLETAS
 *
 * Integra:
 * 1. Zod (validación síncrona)
 * 2. React Hook Form (gestión de formulario)
 * 3. Validaciones asíncronas (BD)
 * 4. TanStack Query (cache y debouncing)
 */

// @ts-nocheck — Example file with unimplemented stubs
'use client'

import { useState } from 'react'

import { zodResolver } from '@hookform/resolvers/zod'
import { AlertCircle, CheckCircle2, Loader2, XCircle } from 'lucide-react'
import { useForm } from 'react-hook-form'

import { logger } from '@/lib/utils/logger'

import { useViviendaValidationStatus } from '../hooks/useViviendaValidation'
import { viviendaFormSchema, type ViviendaFormData } from '../schemas/vivienda-form.schema'
import { validarViviendaCompleta } from '../services/vivienda-validation.service'

export function FormularioViviendaEjemplo() {
  const [isSubmitting, setIsSubmitting] = useState(false)

  // ============================================================================
  // 1. CONFIGURAR REACT HOOK FORM CON ZOD
  // ============================================================================

  const {
    register,
    handleSubmit,
    watch,
    setError,
    formState: { errors, isValid },
  } = useForm<ViviendaFormData>({
    resolver: zodResolver(viviendaFormSchema), // â† Validación Zod automática
    mode: 'onChange', // Validar mientras escribe
  })

  // ============================================================================
  // 2. OBSERVAR CAMBIOS PARA VALIDACIONES ASÍNCRONAS
  // ============================================================================

  const formValues = watch() // Observa todos los campos
  const validationStatus = useViviendaValidationStatus({
    numero_matricula: formValues.numero_matricula,
    numero_casa: formValues.numero_casa,
    proyecto_id: formValues.proyecto_id,
    manzana_id: formValues.manzana_id,
  })

  // ============================================================================
  // 3. SUBMIT CON VALIDACIÓN COMPLETA
  // ============================================================================

  const onSubmit = async (data: ViviendaFormData) => {
    setIsSubmitting(true)

    try {
      // Validación completa contra BD antes de guardar
      const validacion = await validarViviendaCompleta(data)

      if (!validacion.valid) {
        // Marcar errores en los campos correspondientes
        Object.entries(validacion.errores).forEach(([campo, mensaje]) => {
          setError(campo as any, {
            type: 'manual',
            message: mensaje,
          })
        })

        return
      }

      // TODO: Guardar en BD

      // Aquí llamarías a tu service para crear la vivienda
      // await viviendaService.create(data)

    } catch (error) {
      logger.error('Error al validar/guardar:', error)
    } finally {
      setIsSubmitting(false)
    }
  }

  // ============================================================================
  // 4. RENDERIZADO CON INDICADORES VISUALES
  // ============================================================================

  return (
    <form onSubmit={handleSubmit(onSubmit)} className="space-y-6">
      {/* CAMPO: Número de Matrícula */}
      <div className="space-y-2">
        <label className="text-sm font-medium">
          Número de Matrícula <span className="text-red-500">*</span>
        </label>

        <div className="relative">
          <input
            {...register('numero_matricula')}
            type="text"
            placeholder="ABC-123456"
            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
          />

          {/* INDICADOR DE VALIDACIÓN ASÍNCRONA */}
          <div className="absolute right-3 top-1/2 -translate-y-1/2">
            {validationStatus.matricula.isValidating && (
              <Loader2 className="w-5 h-5 animate-spin text-blue-500" />
            )}
            {!validationStatus.matricula.isValidating &&
              validationStatus.matricula.isValid && (
                <CheckCircle2 className="w-5 h-5 text-green-500" />
              )}
            {!validationStatus.matricula.isValidating &&
              validationStatus.matricula.error && (
                <XCircle className="w-5 h-5 text-red-500" />
              )}
          </div>
        </div>

        {/* ERRORES ZOD (síncronos) */}
        {errors.numero_matricula && (
          <p className="text-sm text-red-500 flex items-center gap-1">
            <AlertCircle className="w-4 h-4" />
            {errors.numero_matricula.message}
          </p>
        )}

        {/* ERRORES ASÍNCRONOS (BD) */}
        {validationStatus.matricula.error && (
          <p className="text-sm text-red-500 flex items-center gap-1">
            <AlertCircle className="w-4 h-4" />
            {validationStatus.matricula.error}
          </p>
        )}
      </div>

      {/* CAMPO: Número de Casa */}
      <div className="space-y-2">
        <label className="text-sm font-medium">
          Número de Casa <span className="text-red-500">*</span>
        </label>

        <div className="relative">
          <input
            {...register('numero_casa')}
            type="text"
            placeholder="101"
            className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
          />

          <div className="absolute right-3 top-1/2 -translate-y-1/2">
            {validationStatus.casa.isValidating && (
              <Loader2 className="w-5 h-5 animate-spin text-blue-500" />
            )}
            {!validationStatus.casa.isValidating && validationStatus.casa.isValid && (
              <CheckCircle2 className="w-5 h-5 text-green-500" />
            )}
            {!validationStatus.casa.isValidating && validationStatus.casa.error && (
              <XCircle className="w-5 h-5 text-red-500" />
            )}
          </div>
        </div>

        {errors.numero_casa && (
          <p className="text-sm text-red-500">{errors.numero_casa.message}</p>
        )}
        {validationStatus.casa.error && (
          <p className="text-sm text-red-500">{validationStatus.casa.error}</p>
        )}
      </div>

      {/* CAMPO: Valor Base */}
      <div className="space-y-2">
        <label className="text-sm font-medium">
          Valor Base <span className="text-red-500">*</span>
        </label>

        <input
          {...register('valor_base')}
          type="number"
          placeholder="150000000"
          className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
        />

        {errors.valor_base && (
          <p className="text-sm text-red-500">{errors.valor_base.message}</p>
        )}
      </div>

      {/* Más campos... */}

      {/* BOTÓN SUBMIT */}
      <div className="flex items-center justify-end gap-3">
        {/* Indicador de validaciones en progreso */}
        {validationStatus.isAnyValidating && (
          <p className="text-sm text-blue-600 flex items-center gap-2">
            <Loader2 className="w-4 h-4 animate-spin" />
            Validando datos...
          </p>
        )}

        <button
          type="submit"
          disabled={
            isSubmitting ||
            validationStatus.isAnyValidating ||
            validationStatus.hasAnyError ||
            !isValid
          }
          className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
        >
          {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
          {isSubmitting ? 'Guardando...' : 'Guardar Vivienda'}
        </button>
      </div>
    </form>
  )
}

/**
 * NuevaViviendaView - Vista dedicada para crear vivienda
 * ? Componente presentacional puro
 * ? Separaci�n de responsabilidades
 * ? Dise�o est�ndar compacto
 * ? Paleta Naranja/�mbar (Viviendas)
 */

'use client'

import { useEffect, useState } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import {
    Check,
    CheckCircle,
    ChevronLeft,
    ChevronRight,
    Compass,
    DollarSign,
    FileText,
    Home,
    MapPin,
    X
} from 'lucide-react'
import { toast } from 'sonner'


import Link from 'next/link'

import { logger } from '@/lib/utils/logger'
import { cn } from '@/shared/utils/helpers'


import { proyectosService } from '../../proyectos/services/proyectos.service'
import { useNuevaVivienda } from '../hooks/useNuevaVivienda'
import { useCrearViviendaMutation } from '../hooks/useViviendasQuery'
import { viviendasService } from '../services/viviendas.service'
import { nuevaViviendaStyles as styles } from '../styles/nueva-vivienda.styles'

import { PasoFinancieroNuevo } from './paso-financiero-nuevo'
import { PasoLegalNuevo } from './paso-legal-nuevo'
import { PasoLinderosNuevo } from './paso-linderos-nuevo'
import { PasoResumenNuevo } from './paso-resumen-nuevo'
import { PasoUbicacionNuevo } from './paso-ubicacion-nuevo'

// Mapeo de iconos
const iconMap = {
  MapPin,
  Compass,
  FileText,
  DollarSign,
  CheckCircle,
}

export function NuevaViviendaView() {
  // Estados para nombres (para el preview)
  const [proyectoNombre, setProyectoNombre] = useState<string | null>(null)
  const [manzanaNombre, setManzanaNombre] = useState<string | null>(null)

  // ? Mutation de React Query para crear vivienda (sin toast autom�tico)
  const crearViviendaMutation = useCrearViviendaMutation({ showToast: false })

  const {
    register,
    handleSubmit,
    errors,
    setValue,
    watch,
    pasoActual,
    pasoActualConfig,
    totalPasos,
    progreso,
    esPrimerPaso,
    esUltimoPaso,
    irSiguiente,
    irAtras,
    irAPaso,
    cancelar,
    submitting,
    autorizarSubmit, // ? NUEVA funci�n para autorizar submit
    previewData,
    formData,
    pasos,
    gastosNotariales,
    resumenFinanciero,
    configuracionRecargos,
  } = useNuevaVivienda({
    onSubmit: async (data) => {
      try {

        const nuevaVivienda = await crearViviendaMutation.mutateAsync(data)

        // ? Toast con nombre de manzana
        toast.success('�Vivienda creada exitosamente!', {
          description: manzanaNombre
            ? `Se cre� con �xito la vivienda ${data.numero} de ${manzanaNombre}`
            : `Se cre� con �xito la vivienda ${data.numero}`,
          duration: 4000,
        })

        // Retornar la vivienda creada para que el hook sepa que todo sali\u00f3 bien
        return void nuevaVivienda
      } catch (error) {
        logger.error('? Error al crear vivienda:', error)
        toast.error('Error al crear vivienda', {
          description: error instanceof Error ? error.message : 'Ocurri� un error inesperado',
          duration: 5000,
        })
        throw error // Re-lanzar para que el hook maneje el estado
      }
    },
  })

  // Logs eliminados para mejorar performance

  // Cargar nombres de proyecto y manzana cuando cambian los IDs
  const proyectoId = watch('proyecto_id')
  const manzanaId = watch('manzana_id')

  useEffect(() => {
    async function cargarNombreProyecto() {
      if (!proyectoId) {
        setProyectoNombre(null)
        return
      }
      try {
        const proyectos = await proyectosService.obtenerProyectos()
        const proyecto = proyectos.find(p => p.id === proyectoId)
        setProyectoNombre(proyecto?.nombre || null)
      } catch (error) {
      }
    }
    cargarNombreProyecto()
  }, [proyectoId])

  useEffect(() => {
    async function cargarNombreManzana() {
      if (!manzanaId || !proyectoId) {
        setManzanaNombre(null)
        return
      }
      try {
        const manzanas = await viviendasService.obtenerManzanasDisponibles(proyectoId)
        const manzana = manzanas.find(m => m.id === manzanaId)
        setManzanaNombre(manzana ? `Manzana ${manzana.nombre}` : null)
      } catch (error) {
      }
    }
    cargarNombreManzana()
  }, [manzanaId, proyectoId])

  return (
    <div className={styles.container.page}>
      <div className={styles.container.content}>
        {/* HEADER CON BREADCRUMBS */}
        <motion.div {...styles.animations.container} className={styles.header.container}>
          <div className={styles.header.pattern} />
          <div className={styles.header.content}>
            {/* Breadcrumbs */}
            <nav className={styles.header.breadcrumbs}>
              <Link href="/viviendas" className={styles.header.breadcrumbItem}>
                Viviendas
              </Link>
              <ChevronRight className="w-3 h-3" />
              <span className={styles.header.breadcrumbCurrent}>Nueva Vivienda</span>
            </nav>

            {/* T�tulo */}
            <div className={styles.header.titleRow}>
              <div className={styles.header.titleLeft}>
                <div className={styles.header.icon}>
                  <Home className={styles.header.iconSvg} />
                </div>
                <div className={styles.header.titleContent}>
                  <h1 className={styles.header.title}>Nueva Vivienda</h1>
                  <p className={styles.header.subtitle}>
                    Completa los 5 pasos � Progreso: {progreso}%
                  </p>
                </div>
              </div>

              {/* Bot�n cancelar */}
              <div className={styles.header.actions}>
                <button onClick={cancelar} className={styles.header.cancelButton} type="button">
                  <X className="w-4 h-4" />
                  Cancelar
                </button>
              </div>
            </div>
          </div>
        </motion.div>

        {/* STEPPER HORIZONTAL (STICKY) */}
        <motion.div {...styles.animations.container} className={styles.stepper.container}>
          <div className={styles.stepper.list}>
            {pasos.map((paso, index) => {
              const Icon = iconMap[paso.icon as keyof typeof iconMap]
              const completado = paso.id < pasoActual
              const activo = paso.id === pasoActual
              const inactivo = paso.id > pasoActual

              return (
                <div key={paso.id} className={styles.stepper.step.container}>
                  {/* Conector (l�nea entre pasos) - ANTES del iconWrapper */}
                  {index < pasos.length - 1 && (
                    <div
                      className={cn(
                        styles.stepper.step.connector,
                        completado
                          ? styles.stepper.step.connectorCompleted
                          : styles.stepper.step.connectorInactive
                      )}
                    />
                  )}

                  {/* Icono */}
                  <div className={styles.stepper.step.iconWrapper}>
                    <button
                      onClick={() => irAPaso(paso.id)}
                      className={cn(
                        styles.stepper.step.iconCircle,
                        completado && styles.stepper.step.iconCircleCompleted,
                        activo && styles.stepper.step.iconCircleActive,
                        inactivo && styles.stepper.step.iconCircleInactive
                      )}
                      type="button"
                    >
                      {completado ? (
                        <Check className={styles.stepper.step.checkIcon} />
                      ) : (
                        <Icon className={styles.stepper.step.icon} />
                      )}
                    </button>
                  </div>

                  {/* Label */}
                  <span
                    className={cn(
                      styles.stepper.step.label,
                      completado && styles.stepper.step.labelCompleted,
                      activo && styles.stepper.step.labelActive,
                      inactivo && styles.stepper.step.labelInactive
                    )}
                  >
                    {paso.titulo}
                  </span>
                </div>
              )
            })}
          </div>
        </motion.div>

        {/* FORMULARIO */}
        {/* ?? IMPORTANTE: El submit est� protegido en useNuevaVivienda.onSubmitForm */}
        {/* Solo se procesa cuando pasoActual === 5 (Resumen) */}
        {/* Si se presiona Enter en pasos 1-4, avanza al siguiente paso en lugar de crear */}
        {/* ?? CR�TICO: onSubmit con preventDefault para evitar auto-submit de React Hook Form */}
        <form onSubmit={(e) => {

          // ?? PREVENIR AUTO-SUBMIT: Si no estamos en paso 5, bloquear submit
          if (pasoActual < 5) {
                                    e.preventDefault()
            e.stopPropagation()
                        return false
          }


          handleSubmit(e)
        }}>
          {/* CONTENIDO DEL PASO ACTUAL */}
          <motion.div {...styles.animations.step} key={pasoActual} className={styles.content.container}>
            {/* Layout de 1 columna (sin sidebar) */}
            <div className="w-full max-w-4xl mx-auto">
              {/* CONTENIDO DEL FORMULARIO */}
              <div className={styles.content.formColumn}>
                <AnimatePresence mode="wait">
                  {(() => {
                    switch (pasoActual) {
                      case 1:
                        return (
                          <PasoUbicacionNuevo
                            key="paso-1"
                            register={register}
                            errors={errors}
                            setValue={setValue}
                            watch={watch}
                          />
                        )
                      case 2:
                        return (
                          <PasoLinderosNuevo
                            key="paso-2"
                            register={register}
                            errors={errors}
                          />
                        )
                      case 3: {
                        const PasoLegal = PasoLegalNuevo as any
                        return (
                          <PasoLegal
                            key="paso-3"
                            register={register}
                            errors={errors}
                            setValue={setValue}
                          />
                        )
                      }
                      case 4:
                        return (
                          <PasoFinancieroNuevo
                            key="paso-4"
                            register={register}
                            errors={errors}
                            watch={watch}
                            setValue={setValue}
                            resumenFinanciero={resumenFinanciero}
                            configuracionRecargos={configuracionRecargos}
                          />
                        )
                      case 5:
                        return (
                          <PasoResumenNuevo
                            key="paso-5"
                            formData={formData}
                            proyectoNombre={proyectoNombre}
                            manzanaNombre={manzanaNombre}
                            gastosNotariales={gastosNotariales}
                          />
                        )
                      default:
                        return null
                    }
                  })()}
                </AnimatePresence>
              </div>
            </div>
          </motion.div>

          {/* BOTONES DE NAVEGACI�N (STICKY BOTTOM) */}
          <motion.div {...styles.animations.container} className={styles.navigation.container}>
            <div className={styles.navigation.content}>
              {/* Bot�n Atr�s */}
              <button
                onClick={irAtras}
                disabled={esPrimerPaso}
                className={styles.navigation.backButton}
                type="button"
              >
                <ChevronLeft className={styles.navigation.backIcon} />
                Atr�s
              </button>

              {/* Indicador de paso */}
              <span className={styles.navigation.stepIndicator}>
                Paso {pasoActual} de {totalPasos}
              </span>

              {/* Bot�n Siguiente/Guardar */}
              {(() => {

                if (esUltimoPaso) {

                  return (
                    <button
                      type="submit"
                      disabled={submitting}
                      className={styles.navigation.submitButton}
                      onClick={(e) => {

                        // ?? AUTORIZAR SUBMIT: Marcar que el usuario hizo click expl�citamente
                        autorizarSubmit()


                        // El submit se dispara autom�ticamente porque type="submit"
                      }}
                    >
                      {submitting ? (
                        <>
                          <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
                          Guardando...
                        </>
                      ) : (
                        <>
                          <Check className={styles.navigation.submitIcon} />
                          Guardar Vivienda
                        </>
                      )}
                    </button>
                  )
                } else {

                  return (
                    <button
                      onClick={() => {
                                                                        irSiguiente()
                      }}
                      className={styles.navigation.nextButton}
                      type="button"
                    >
                      Siguiente
                      <ChevronRight className={styles.navigation.nextIcon} />
                    </button>
                  )
                }
              })()}
            </div>
          </motion.div>
        </form>
      </div>
    </div>
  )
}

/**
 * PasoConfirmarCambios - Paso 5: Confirmar cambios detectados
 * ✅ Componente presentacional puro
 * ✅ Muestra SOLO campos modificados en formato diff
 * ✅ Paleta naranja/ámbar (viviendas)
 */

'use client'

import { motion } from 'framer-motion'
import {
    AlertCircle,
    ArrowRight,
    CheckCircle2,
    Compass,
    DollarSign,
    FileText
} from 'lucide-react'

interface CambioDetectado {
  campo: string
  label: string
  valorAnterior: string | number
  valorNuevo: string | number
  icono: any
  categoria: 'linderos' | 'legal' | 'financiero'
}

interface PasoConfirmarCambiosProps {
  cambiosDetectados: CambioDetectado[]
  viviendaActual: any
}

const categoriasConfig = {
  linderos: {
    titulo: 'Linderos',
    icono: Compass,
    color: 'purple',
  },
  legal: {
    titulo: 'Información Legal',
    icono: FileText,
    color: 'green',
  },
  financiero: {
    titulo: 'Información Financiera',
    icono: DollarSign,
    color: 'orange',
  },
}

export function PasoConfirmarCambios({ cambiosDetectados, _viviendaActual }: PasoConfirmarCambiosProps) {
  // Agrupar cambios por categoría
  const cambiosPorCategoria = cambiosDetectados.reduce((acc, cambio) => {
    if (!acc[cambio.categoria]) {
      acc[cambio.categoria] = []
    }
    acc[cambio.categoria].push(cambio)
    return acc
  }, {} as Record<string, CambioDetectado[]>)

  const totalCambios = cambiosDetectados.length

  if (totalCambios === 0) {
    return (
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        className="flex flex-col items-center justify-center py-12 px-6"
      >
        <div className="w-20 h-20 rounded-full bg-gradient-to-br from-gray-100 to-gray-200 dark:from-gray-800 dark:to-gray-700 flex items-center justify-center mb-4">
          <AlertCircle className="w-10 h-10 text-gray-400 dark:text-gray-500" />
        </div>
        <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">
          No se detectaron cambios
        </h3>
        <p className="text-sm text-gray-600 dark:text-gray-400 text-center max-w-md">
          No has modificado ningún campo. Puedes cerrar este modal o volver atrás para realizar cambios.
        </p>
      </motion.div>
    )
  }

  return (
    <motion.div
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.2 }}
      className="space-y-4"
    >
      {/* Título */}
      <div>
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">
          Confirmar Cambios
        </h2>
        <p className="text-sm text-gray-600 dark:text-gray-400">
          Revisa los cambios detectados antes de guardar
        </p>
      </div>

      {/* Resumen de cambios */}
      <div className="flex items-center gap-3 p-4 rounded-xl bg-gradient-to-r from-orange-50 to-amber-50 dark:from-orange-950/30 dark:to-amber-950/30 border border-orange-200 dark:border-orange-800">
        <CheckCircle2 className="w-6 h-6 text-orange-600 dark:text-orange-400 flex-shrink-0" />
        <p className="text-sm text-orange-900 dark:text-orange-100">
          Se detectaron{' '}
          <strong className="font-bold text-orange-600 dark:text-orange-400">
            {totalCambios}
          </strong>{' '}
          cambio(s) en la vivienda
        </p>
      </div>

      {/* Cambios por categoría */}
      <div className="space-y-4">
        {Object.entries(cambiosPorCategoria).map(([categoria, cambios]) => {
          const config = categoriasConfig[categoria as keyof typeof categoriasConfig]
          const IconoCategoria = config.icono

          return (
            <motion.div
              key={categoria}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              className="rounded-xl bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 overflow-hidden"
            >
              {/* Header de categoría */}
              <div className="px-4 py-3 bg-gray-50 dark:bg-gray-800/50 border-b border-gray-200 dark:border-gray-700">
                <div className="flex items-center gap-2">
                  <div className={`w-8 h-8 rounded-lg bg-gradient-to-br from-${config.color}-500 to-${config.color}-600 flex items-center justify-center shadow-lg`}>
                    <IconoCategoria className="w-4 h-4 text-white" />
                  </div>
                  <h3 className="text-base font-bold text-gray-900 dark:text-white">
                    {config.titulo} ({cambios.length})
                  </h3>
                </div>
              </div>

              {/* Lista de cambios */}
              <div className="p-4 space-y-3">
                {cambios.map((cambio, index) => {
                  const Icono = cambio.icono

                  return (
                    <div
                      key={index}
                      className="rounded-lg border border-gray-200 dark:border-gray-700 overflow-hidden"
                    >
                      {/* Label del campo */}
                      <div className="px-3 py-2 bg-gray-50 dark:bg-gray-800/50 border-b border-gray-200 dark:border-gray-700">
                        <div className="flex items-center gap-2">
                          <Icono className="w-4 h-4 text-gray-400 dark:text-gray-500" />
                          <span className="text-xs font-semibold text-gray-600 dark:text-gray-400">
                            {cambio.label}
                          </span>
                        </div>
                      </div>

                      {/* Diff: Anterior → Nuevo */}
                      <div className="p-3 space-y-2">
                        {/* Valor anterior (rojo) */}
                        <div className="flex items-start gap-2 p-2 rounded-lg bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-800">
                          <div className="flex-shrink-0 w-16 px-2 py-0.5 rounded bg-red-100 dark:bg-red-900/50 border border-red-300 dark:border-red-700">
                            <span className="text-xs font-bold text-red-700 dark:text-red-300">
                              Anterior
                            </span>
                          </div>
                          <p className="flex-1 text-sm text-red-900 dark:text-red-100 line-through">
                            {cambio.valorAnterior}
                          </p>
                        </div>

                        {/* Flecha */}
                        <div className="flex justify-center">
                          <ArrowRight className="w-5 h-5 text-orange-500 dark:text-orange-400" />
                        </div>

                        {/* Valor nuevo (verde) */}
                        <div className="flex items-start gap-2 p-2 rounded-lg bg-green-50 dark:bg-green-950/30 border border-green-200 dark:border-green-800">
                          <div className="flex-shrink-0 w-16 px-2 py-0.5 rounded bg-green-100 dark:bg-green-900/50 border border-green-300 dark:border-green-700">
                            <span className="text-xs font-bold text-green-700 dark:text-green-300">
                              Nuevo
                            </span>
                          </div>
                          <p className="flex-1 text-sm font-semibold text-green-900 dark:text-green-100">
                            {cambio.valorNuevo}
                          </p>
                        </div>
                      </div>
                    </div>
                  )
                })}
              </div>
            </motion.div>
          )
        })}
      </div>

      {/* Advertencia final */}
      <div className="flex items-start gap-3 p-4 rounded-xl bg-amber-50 dark:bg-amber-950/30 border border-amber-200 dark:border-amber-800">
        <AlertCircle className="w-5 h-5 text-amber-600 dark:text-amber-400 flex-shrink-0 mt-0.5" />
        <div>
          <p className="text-sm font-semibold text-amber-900 dark:text-amber-100 mb-1">
            ⚠️ Cambios permanentes
          </p>
          <p className="text-xs text-amber-700 dark:text-amber-300">
            Estos cambios se guardarán permanentemente en el sistema. Asegúrate de revisar que toda la información sea correcta.
          </p>
        </div>
      </div>
    </motion.div>
  )
}

/**
 * PasoFinancieroNuevo - Paso 4: Información financiera
 * ✅ Diseño compacto estándar
 * ✅ Formato de moneda en inputs
 * ✅ Gastos notariales automáticos
 */

'use client'

import { motion } from 'framer-motion'
import { AlertCircle, DollarSign, Lock, TrendingUp } from 'lucide-react'
import type { FieldErrors, UseFormRegister, UseFormSetValue, UseFormWatch } from 'react-hook-form'

import { cn } from '@/shared/utils/helpers'

import { nuevaViviendaStyles as styles } from '../styles/nueva-vivienda.styles'
import type { ConfiguracionRecargo, ResumenFinanciero, ViviendaEstado } from '../types'
import { formatCurrencyInput, parseCurrency } from '../utils'

interface PasoFinancieroProps {
  register: UseFormRegister<any>
  errors: FieldErrors<any>
  watch: UseFormWatch<any>
  setValue: UseFormSetValue<any>
  resumenFinanciero: ResumenFinanciero
  configuracionRecargos: ConfiguracionRecargo[]
  bloqueado?: boolean
  estadoVivienda?: ViviendaEstado | string
}

export function PasoFinancieroNuevo({ register, errors, watch, setValue, resumenFinanciero, configuracionRecargos, bloqueado = false, estadoVivienda }: PasoFinancieroProps) {
  const valorBase = watch('valor_base') || 0
  const esEsquinera = watch('es_esquinera') || false
  const recargoEsquinera = watch('recargo_esquinera') || 0

  // Filtrar recargos de tipo esquinera
  const recargosEsquinera = configuracionRecargos.filter(r =>
    r.tipo.toLowerCase().includes('esquinera') && r.activo
  )

  // Formatear moneda para display
  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency',
      currency: 'COP',
      minimumFractionDigits: 0,
    }).format(value)
  }

  return (
    <motion.div
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.2 }}
      className="space-y-3"
    >
      {/* Título del paso */}
      <div>
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">
          Información Financiera
        </h2>
        <p className="text-sm text-gray-600 dark:text-gray-400">
          Define el valor base y recargos de la vivienda
        </p>
      </div>

      {/* Banner de bloqueo para viviendas Entregadas */}
      {bloqueado ? (
        <div className="flex items-start gap-3 p-3 rounded-xl bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-800/40">
          <Lock className="w-5 h-5 text-amber-600 dark:text-amber-400 flex-shrink-0 mt-0.5" />
          <div>
            <p className="text-sm font-bold text-amber-800 dark:text-amber-300">
              Campos financieros bloqueados
            </p>
            <p className="text-xs text-amber-700 dark:text-amber-400 mt-0.5">
              Esta vivienda está en estado <strong>{estadoVivienda}</strong>. Los valores financieros
              no pueden modificarse una vez entregada.
            </p>
          </div>
        </div>
      ) : null}

      {/* Valor Base */}
      <div className={styles.field.container}>
        <label htmlFor="valor_base" className={styles.field.label}>
          Valor Base <span className={styles.field.required}>*</span>
        </label>
        <div className={styles.field.inputWrapper}>
          <DollarSign className={styles.field.inputIcon} />
          <input
            id="valor_base"
            type="text"
            value={formatCurrencyInput(valorBase?.toString() || '')}
            onChange={(e) => {
              const valor = parseCurrency(e.target.value)
              setValue('valor_base', valor)
            }}
            placeholder="$ 50.000.000"
            disabled={bloqueado}
            className={cn(
              styles.field.input,
              errors.valor_base && styles.field.inputError,
              bloqueado && 'opacity-60 cursor-not-allowed bg-gray-100 dark:bg-gray-800'
            )}
          />
        </div>
        {errors.valor_base && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className={styles.field.error}
          >
            <AlertCircle className={styles.field.errorIcon} />
            {errors.valor_base.message as string}
          </motion.div>
        )}
        <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
          Precio base sin recargos: {formatCurrency(valorBase)}
        </p>
      </div>

      {/* Es Esquinera */}
      <div className="space-y-2">
        <div className="flex items-center gap-2">
          <input
            {...register('es_esquinera')}
            id="es_esquinera"
            type="checkbox"
            disabled={bloqueado}
            className={cn(
              'w-5 h-5 rounded border-2 border-gray-300 dark:border-gray-600 text-orange-500 focus:ring-2 focus:ring-orange-500/20 transition-colors',
              bloqueado && 'opacity-60 cursor-not-allowed'
            )}
          />
          <label htmlFor="es_esquinera" className="text-sm font-medium text-gray-700 dark:text-gray-300 cursor-pointer">
            ¿Es vivienda esquinera?
          </label>
        </div>

        {/* Recargo Esquinera (solo si es esquinera) */}
        {esEsquinera && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className={styles.field.container}
          >
            <label htmlFor="recargo_esquinera" className={styles.field.label}>
              Recargo por Esquinera <span className={styles.field.required}>*</span>
            </label>
            <div className={styles.field.inputWrapper}>
              <TrendingUp className={styles.field.inputIcon} />
              <select
                {...register('recargo_esquinera', { valueAsNumber: true })}
                id="recargo_esquinera"
                disabled={bloqueado}
                className={cn(
                  styles.field.input,
                  errors.recargo_esquinera && styles.field.inputError,
                  bloqueado && 'opacity-60 cursor-not-allowed bg-gray-100 dark:bg-gray-800'
                )}
              >
                <option value="0">Selecciona el recargo por esquinera</option>
                {recargosEsquinera.map((recargo) => (
                  <option key={recargo.id} value={recargo.valor}>
                    {recargo.nombre} - {formatCurrency(recargo.valor)}
                  </option>
                ))}
              </select>
            </div>
            {errors.recargo_esquinera && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className={styles.field.error}
              >
                <AlertCircle className={styles.field.errorIcon} />
                {errors.recargo_esquinera.message as string}
              </motion.div>
            )}
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
              Recargo adicional: {formatCurrency(recargoEsquinera)}
            </p>
          </motion.div>
        )}
      </div>

      {/* Resumen Financiero */}
      <div className="rounded-xl bg-gradient-to-br from-orange-50 to-amber-50 dark:from-orange-950/30 dark:to-amber-950/30 border border-orange-200 dark:border-orange-800 p-3">
        <div className="flex items-center gap-2 mb-3">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-orange-500 to-amber-500 flex items-center justify-center shadow-lg shadow-orange-500/30">
            <DollarSign className="w-4 h-4 text-white" />
          </div>
          <h3 className="text-base font-bold text-orange-900 dark:text-orange-100">
            Resumen Financiero
          </h3>
        </div>

        <div className="space-y-2">
          <div className="flex items-center justify-between py-1.5 border-b border-orange-200 dark:border-orange-800">
            <span className="text-sm text-gray-600 dark:text-gray-400">Valor Base:</span>
            <span className="text-sm font-semibold text-gray-900 dark:text-white">
              {formatCurrency(resumenFinanciero.valor_base)}
            </span>
          </div>

          <div className="flex items-center justify-between py-1.5 border-b border-orange-200 dark:border-orange-800">
            <span className="text-sm text-gray-600 dark:text-gray-400">Gastos Notariales (Automático):</span>
            <span className="text-sm font-semibold text-blue-600 dark:text-blue-400">
              + {formatCurrency(resumenFinanciero.gastos_notariales)}
            </span>
          </div>

          {esEsquinera && (
            <div className="flex items-center justify-between py-1.5 border-b border-orange-200 dark:border-orange-800">
              <span className="text-sm text-gray-600 dark:text-gray-400">Recargo Esquinera:</span>
              <span className="text-sm font-semibold text-orange-600 dark:text-orange-400">
                + {formatCurrency(resumenFinanciero.recargo_esquinera)}
              </span>
            </div>
          )}

          <div className="flex items-center justify-between pt-2">
            <span className="text-base font-bold text-gray-900 dark:text-white">Valor Total:</span>
            <span className="text-xl font-bold bg-gradient-to-br from-orange-600 to-amber-600 bg-clip-text text-transparent">
              {formatCurrency(resumenFinanciero.valor_total)}
            </span>
          </div>
        </div>

        {/* Nota informativa */}
        <div className="mt-3 rounded-lg border border-blue-200 bg-blue-50 dark:border-blue-700 dark:bg-blue-900/20 p-2">
          <p className="text-xs text-blue-900 dark:text-blue-100">
            ℹ️ <strong>Nota:</strong> Los gastos notariales son un recargo <strong>obligatorio</strong> que se suma automáticamente al valor base de todas las viviendas.
          </p>
        </div>
      </div>
    </motion.div>
  )
}

'use client'

import { DollarSign } from 'lucide-react'

import { LABELS, OPCIONES_RECARGO, PLACEHOLDERS } from '../constants'
import { fieldClasses, financieroClasses, sectionClasses } from '../styles/vivienda-form.styles'
import type { ConfiguracionRecargo, ResumenFinanciero } from '../types'
import { formatCurrencyInput, parseCurrency } from '../utils'

import { ResumenFinancieroCard } from './resumen-financiero-card'

interface PasoFinancieroProps {
  valorBase: number | undefined
  esEsquinera: boolean
  recargoEsquinera: number
  resumen: ResumenFinanciero
  configuracionRecargos: ConfiguracionRecargo[]
  errores: Record<string, string>
  onChange: (campo: string, valor: any) => void
  onToggleEsquinera: (checked: boolean) => void
}

/**
 * Paso 4: Información Financiera
 * Valor base, toggle esquinera, select de recargo y resumen en vivo
 */
export function PasoFinanciero({
  valorBase,
  esEsquinera,
  recargoEsquinera,
  resumen,
  configuracionRecargos,
  errores,
  onChange,
  onToggleEsquinera,
}: PasoFinancieroProps) {
  // Filtrar solo recargos de tipo esquinera
  const recargosEsquinera = configuracionRecargos.filter((r) =>
    r.tipo.includes('esquinera')
  )

  // Si no hay configuración cargada, usar valores por defecto
  const opcionesRecargo = recargosEsquinera.length > 0
    ? recargosEsquinera.map((r) => ({
        label: r.nombre,
        value: r.valor,
        tipo: r.tipo,
      }))
    : OPCIONES_RECARGO

  return (
    <div className={sectionClasses.container}>
      <div className={sectionClasses.card}>
        <div className={sectionClasses.header}>
          <div className="flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-yellow-100 dark:bg-yellow-900">
              <DollarSign className="h-5 w-5 text-yellow-600 dark:text-yellow-400" />
            </div>
            <div>
              <h2 className={sectionClasses.title}>Información Financiera</h2>
              <p className={sectionClasses.subtitle}>
                Define el valor base y recargos aplicables
              </p>
            </div>
          </div>
        </div>

        <div className={financieroClasses.container}>
          {/* Valor Base */}
          <div className={financieroClasses.valorBaseGroup.container}>
            <label htmlFor="valor_base" className={fieldClasses.label}>
              💵 {LABELS.VALOR_BASE}
              <span className={fieldClasses.required}>*</span>
            </label>
            <div className={financieroClasses.valorBaseGroup.inputWrapper}>
              <span className={financieroClasses.valorBaseGroup.prefix}>$</span>
              <input
                id="valor_base"
                type="text"
                value={formatCurrencyInput(valorBase?.toString() || '')}
                onChange={(e) => {
                  const valor = parseCurrency(e.target.value)
                  onChange('valor_base', valor)
                }}
                placeholder={PLACEHOLDERS.VALOR}
                className={`${financieroClasses.valorBaseGroup.input} ${errores.valor_base ? fieldClasses.input.error : ''}`}
              />
            </div>
            {errores.valor_base && (
              <p className={fieldClasses.error}>{errores.valor_base}</p>
            )}
            <p className={fieldClasses.hint}>
              Escribe el valor base de la vivienda sin recargos
            </p>
          </div>

          {/* Toggle Casa Esquinera */}
          <div className={financieroClasses.toggleGroup.container}>
            <label htmlFor="es_esquinera" className={financieroClasses.toggleGroup.label}>
              🏠 {LABELS.CASA_ESQUINERA}
            </label>
            <button
              type="button"
              role="switch"
              aria-checked={esEsquinera}
              onClick={() => onToggleEsquinera(!esEsquinera)}
              className={`${financieroClasses.toggleGroup.toggle} ${
                esEsquinera
                  ? financieroClasses.toggleGroup.toggleActive
                  : financieroClasses.toggleGroup.toggleInactive
              }`}
            >
              <span
                className={`${financieroClasses.toggleGroup.toggleButton} ${
                  esEsquinera
                    ? financieroClasses.toggleGroup.toggleButtonActive
                    : financieroClasses.toggleGroup.toggleButtonInactive
                }`}
              />
            </button>
          </div>

          {/* Select de Recargo (solo si toggle activo) */}
          {esEsquinera && (
            <div className={financieroClasses.selectRecargo.container}>
              <label htmlFor="recargo_esquinera" className={fieldClasses.label}>
                💰 {LABELS.SELECCIONAR_RECARGO}
                <span className={fieldClasses.required}>*</span>
              </label>
              <select
                id="recargo_esquinera"
                value={recargoEsquinera}
                onChange={(e) => onChange('recargo_esquinera', parseInt(e.target.value))}
                className={`${financieroClasses.selectRecargo.select} ${errores.recargo_esquinera ? fieldClasses.select.error : ''}`}
              >
                <option value="0">{PLACEHOLDERS.RECARGO}</option>
                {opcionesRecargo.map((opcion) => (
                  <option key={opcion.tipo} value={opcion.value}>
                    {opcion.label}
                  </option>
                ))}
              </select>
              {errores.recargo_esquinera && (
                <p className={fieldClasses.error}>{errores.recargo_esquinera}</p>
              )}
            </div>
          )}

          {/* Resumen Financiero EN VIVO */}
          <div className="mt-8">
            <ResumenFinancieroCard resumen={resumen} mostrarDesglose={true} />
          </div>

          {/* Nota informativa */}
          <div className="mt-6 rounded-lg border border-blue-200 bg-blue-50 p-4 dark:border-blue-700 dark:bg-blue-900/20">
            <p className="text-sm text-blue-900 dark:text-blue-100">
              ℹ️ <strong>Nota:</strong> Los gastos notariales son un recargo{' '}
              <strong>obligatorio</strong> que se suma automáticamente al valor base de
              todas las viviendas.
            </p>
          </div>
        </div>
      </div>
    </div>
  )
}

/**
 * PasoLegalNuevo - Paso 3: Información legal
 * ✅ Componente presentacional puro
 * ✅ Lógica en usePasoLegal hook
 */

'use client'

import { useCallback, useRef, useState } from 'react'

import { AnimatePresence, motion } from 'framer-motion'
import { AlertCircle, FileText, Hash, MapPin, Maximize } from 'lucide-react'
import type { FieldErrors, UseFormRegister } from 'react-hook-form'

import { cn } from '@/shared/utils/helpers'

import { nuevaViviendaStyles as styles } from '../styles/nueva-vivienda.styles'

interface PasoLegalProps {
  register: UseFormRegister<any>
  errors: FieldErrors<any>
}

export function PasoLegalNuevo({ register, errors }: PasoLegalProps) {
  const [areaHint, setAreaHint] = useState<string | null>(null)
  const hintTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  const showAreaHint = useCallback((message: string) => {
    if (hintTimeoutRef.current) clearTimeout(hintTimeoutRef.current)
    setAreaHint(message)
    hintTimeoutRef.current = setTimeout(() => setAreaHint(null), 2500)
  }, [])

  // ✅ Prevenir teclas inválidas con retroalimentación visual
  const handleDecimalKeyDown = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    const { key, ctrlKey, metaKey } = e
    if (ctrlKey || metaKey || ['Backspace', 'Delete', 'ArrowLeft', 'ArrowRight', 'Tab', 'Home', 'End'].includes(key)) return

    const input = e.currentTarget
    const value = input.value
    const selStart = input.selectionStart ?? value.length
    const selEnd = input.selectionEnd ?? value.length
    const hasSelection = selStart !== selEnd

    if (!/[\d.]/.test(key)) {
      e.preventDefault()
      showAreaHint('Solo se permiten números y punto decimal')
      return
    }

    if (key === '.' && value.includes('.') && !hasSelection) {
      e.preventDefault()
      showAreaHint('Solo se permite un punto decimal')
      return
    }

    if (/\d/.test(key) && value.includes('.') && !hasSelection) {
      const dotIndex = value.indexOf('.')
      const decimals = value.slice(dotIndex + 1)
      if (selStart > dotIndex && decimals.length >= 3) {
        e.preventDefault()
        showAreaHint('Máximo 3 decimales (Ej: 66.125)')
        return
      }
    }
  }, [showAreaHint])

  // ✅ Filtrar input para operaciones de pegado (fallback)
  const handleDecimalInput = useCallback((e: React.FormEvent<HTMLInputElement>) => {
    const input = e.currentTarget
    let cleaned = input.value.replace(/[^\d.]/g, '')
    const parts = cleaned.split('.')
    if (parts.length > 2) {
      cleaned = parts[0] + '.' + parts.slice(1).join('')
    }
    if (parts.length === 2 && parts[1].length > 3) {
      cleaned = parts[0] + '.' + parts[1].slice(0, 3)
    }
    if (input.value !== cleaned) {
      input.value = cleaned
      showAreaHint('Se ajustó el valor — solo números con hasta 3 decimales')
    }
  }, [showAreaHint])

  return (
    <motion.div
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.2 }}
      className="space-y-3"
    >
      {/* Título del paso */}
      <div>
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">
          Información Legal
        </h2>
        <p className="text-sm text-gray-600 dark:text-gray-400">
          Datos catastrales y documentos de la vivienda
        </p>
      </div>

      {/* Matrícula Inmobiliaria */}
      <div className={styles.field.container}>
        <label htmlFor="matricula_inmobiliaria" className={styles.field.label}>
          Matrícula Inmobiliaria <span className={styles.field.required}>*</span>
        </label>
        <div className={styles.field.inputWrapper}>
          <FileText className={styles.field.inputIcon} />
          <input
            {...register('matricula_inmobiliaria')}
            id="matricula_inmobiliaria"
            type="text"
            placeholder="Ej: 050-123456"
            className={cn(
              styles.field.input,
              errors.matricula_inmobiliaria && styles.field.inputError
            )}
          />
        </div>
        {errors.matricula_inmobiliaria && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className={styles.field.error}
          >
            <AlertCircle className={styles.field.errorIcon} />
            {errors.matricula_inmobiliaria.message as string}
          </motion.div>
        )}
      </div>

      {/* Nomenclatura */}
      <div className={styles.field.container}>
        <label htmlFor="nomenclatura" className={styles.field.label}>
          Nomenclatura <span className={styles.field.required}>*</span>
        </label>
        <div className={styles.field.inputWrapper}>
          <MapPin className={styles.field.inputIcon} />
          <input
            {...register('nomenclatura')}
            id="nomenclatura"
            type="text"
            placeholder="Ej: Calle 123 # 45-67"
            className={cn(
              styles.field.input,
              errors.nomenclatura && styles.field.inputError
            )}
          />
        </div>
        {errors.nomenclatura && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className={styles.field.error}
          >
            <AlertCircle className={styles.field.errorIcon} />
            {errors.nomenclatura.message as string}
          </motion.div>
        )}
      </div>

      {/* Áreas */}
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        {/* Área del Lote */}
        <div className={styles.field.container}>
          <label htmlFor="area_lote" className={styles.field.label}>
            Área del Lote (m²) <span className={styles.field.required}>*</span>
          </label>
          <div className={styles.field.inputWrapper}>
            <Maximize className={styles.field.inputIcon} />
            <input
              {...register('area_lote')}
              id="area_lote"
              type="text"
              inputMode="decimal"
              placeholder="120.50"
              onKeyDown={handleDecimalKeyDown}
              onInput={handleDecimalInput}
              className={cn(
                styles.field.input,
                errors.area_lote && styles.field.inputError
              )}
            />
          </div>
          {errors.area_lote && (
            <motion.div
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              className={styles.field.error}
            >
              <AlertCircle className={styles.field.errorIcon} />
              {errors.area_lote.message as string}
            </motion.div>
          )}
        </div>

        {/* Área Construida */}
        <div className={styles.field.container}>
          <label htmlFor="area_construida" className={styles.field.label}>
            Área Construida (m²) <span className={styles.field.required}>*</span>
          </label>
          <div className={styles.field.inputWrapper}>
            <Maximize className={styles.field.inputIcon} />
            <input
              {...register('area_construida')}
              id="area_construida"
              type="text"
              inputMode="decimal"
              placeholder="80.00"
              onKeyDown={handleDecimalKeyDown}
              onInput={handleDecimalInput}
              className={cn(
                styles.field.input,
                errors.area_construida && styles.field.inputError
              )}
            />
          </div>
          {errors.area_construida && (
            <motion.div
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              className={styles.field.error}
            >
              <AlertCircle className={styles.field.errorIcon} />
              {errors.area_construida.message as string}
            </motion.div>
          )}
        </div>
      </div>

      {/* Hint dinámico para campos de área */}
      <AnimatePresence>
        {areaHint ? (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -10 }}
            transition={{ duration: 0.2 }}
            className={styles.field.error}
          >
            <AlertCircle className={styles.field.errorIcon} />
            {areaHint}
          </motion.div>
        ) : null}
      </AnimatePresence>

      {/* Tipo de Vivienda */}
      <div className={styles.field.container}>
        <label htmlFor="tipo_vivienda" className={styles.field.label}>
          Tipo de Vivienda <span className={styles.field.required}>*</span>
        </label>
        <div className={styles.field.inputWrapper}>
          <Hash className={styles.field.inputIcon} />
          <select
            {...register('tipo_vivienda')}
            id="tipo_vivienda"
            className={cn(
              styles.field.select,
              errors.tipo_vivienda && styles.field.inputError
            )}
          >
            <option value="">Selecciona un tipo</option>
            <option value="Regular">Regular</option>
            <option value="Irregular">Irregular</option>
          </select>
        </div>
        {errors.tipo_vivienda && (
          <motion.div
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            className={styles.field.error}
          >
            <AlertCircle className={styles.field.errorIcon} />
            {errors.tipo_vivienda.message as string}
          </motion.div>
        )}
        <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
          Regular: Lote rectangular. Irregular: Lote con formas atípicas.
        </p>
      </div>

      {/* Info: Certificado de Tradición */}
      <div className="rounded-lg border border-blue-200 bg-blue-50 dark:border-blue-800 dark:bg-blue-950/30 p-3">
        <p className="text-sm text-blue-900 dark:text-blue-100">
          📄 <strong>Nota:</strong> El Certificado de Tradición se gestiona desde el módulo de <strong>Documentos</strong> después de crear la vivienda.
        </p>
      </div>
    </motion.div>
  )
}

'use client'

import { useRef, useState } from 'react'

import { CheckCircle, FileText, Upload, X } from 'lucide-react'

import { LABELS, PLACEHOLDERS, TIPO_VIVIENDA_OPTIONS } from '../constants'
import {
    fieldClasses,
    legalClasses,
    sectionClasses,
} from '../styles/vivienda-form.styles'
import type { TipoVivienda } from '../types'
import { validarArchivoPDF } from '../utils'

interface PasoLegalProps {
  matriculaInmobiliaria: string
  nomenclatura: string
  areaLote: number | undefined
  areaConstruida: number | undefined
  tipoVivienda: TipoVivienda | undefined
  certificadoFile: File | undefined
  errores: Record<string, string>
  onChange: (campo: string, valor: any) => void
}

/**
 * Paso 3: Información Legal
 * Datos catastrales y documento de certificado de tradición
 */
export function PasoLegal({
  matriculaInmobiliaria,
  nomenclatura,
  areaLote,
  areaConstruida,
  tipoVivienda,
  certificadoFile,
  errores,
  onChange,
}: PasoLegalProps) {
  const fileInputRef = useRef<HTMLInputElement>(null)
  const [fileError, setFileError] = useState<string>('')

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    const validacion = validarArchivoPDF(file)
    if (!validacion.valido) {
      setFileError(validacion.mensaje!)
      onChange('certificado_tradicion_file', undefined)
      return
    }

    setFileError('')
    onChange('certificado_tradicion_file', file)
  }

  const removeFile = () => {
    onChange('certificado_tradicion_file', undefined)
    if (fileInputRef.current) {
      fileInputRef.current.value = ''
    }
  }

  return (
    <div className={sectionClasses.container}>
      <div className={sectionClasses.card}>
        <div className={sectionClasses.header}>
          <div className="flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-green-100 dark:bg-green-900">
              <FileText className="h-5 w-5 text-green-600 dark:text-green-400" />
            </div>
            <div>
              <h2 className={sectionClasses.title}>Información Legal</h2>
              <p className={sectionClasses.subtitle}>
                Datos catastrales y documentos de la vivienda
              </p>
            </div>
          </div>
        </div>

        <div className={legalClasses.grid}>
          {/* Matrícula Inmobiliaria */}
          <div className={fieldClasses.group}>
            <label htmlFor="matricula" className={fieldClasses.label}>
              {LABELS.MATRICULA}
              <span className={fieldClasses.required}>*</span>
            </label>
            <input
              id="matricula"
              type="text"
              value={matriculaInmobiliaria}
              onChange={(e) => onChange('matricula_inmobiliaria', e.target.value)}
              placeholder={PLACEHOLDERS.MATRICULA}
              className={`${fieldClasses.input.base} ${errores.matricula_inmobiliaria ? fieldClasses.input.error : ''}`}
            />
            {errores.matricula_inmobiliaria && (
              <p className={fieldClasses.error}>{errores.matricula_inmobiliaria}</p>
            )}
          </div>

          {/* Nomenclatura */}
          <div className={fieldClasses.group}>
            <label htmlFor="nomenclatura" className={fieldClasses.label}>
              {LABELS.NOMENCLATURA}
              <span className={fieldClasses.required}>*</span>
            </label>
            <input
              id="nomenclatura"
              type="text"
              value={nomenclatura}
              onChange={(e) => onChange('nomenclatura', e.target.value)}
              placeholder={PLACEHOLDERS.NOMENCLATURA}
              className={`${fieldClasses.input.base} ${errores.nomenclatura ? fieldClasses.input.error : ''}`}
            />
            {errores.nomenclatura && (
              <p className={fieldClasses.error}>{errores.nomenclatura}</p>
            )}
          </div>

          {/* Área del Lote */}
          <div className={fieldClasses.group}>
            <label htmlFor="area_lote" className={fieldClasses.label}>
              {LABELS.AREA_LOTE}
              <span className={fieldClasses.required}>*</span>
            </label>
            <div className="relative">
              <input
                id="area_lote"
                type="number"
                step="0.01"
                value={areaLote || ''}
                onChange={(e) => onChange('area_lote', parseFloat(e.target.value) || 0)}
                placeholder={PLACEHOLDERS.AREA}
                className={`${fieldClasses.input.base} ${errores.area_lote ? fieldClasses.input.error : ''} pr-12`}
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm font-medium">
                m²
              </span>
            </div>
            {errores.area_lote && (
              <p className={fieldClasses.error}>{errores.area_lote}</p>
            )}
          </div>

          {/* Área Construida */}
          <div className={fieldClasses.group}>
            <label htmlFor="area_construida" className={fieldClasses.label}>
              {LABELS.AREA_CONSTRUIDA}
              <span className={fieldClasses.required}>*</span>
            </label>
            <div className="relative">
              <input
                id="area_construida"
                type="number"
                step="0.01"
                value={areaConstruida || ''}
                onChange={(e) => onChange('area_construida', parseFloat(e.target.value) || 0)}
                placeholder={PLACEHOLDERS.AREA}
                className={`${fieldClasses.input.base} ${errores.area_construida ? fieldClasses.input.error : ''} pr-12`}
              />
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm font-medium">
                m²
              </span>
            </div>
            {errores.area_construida && (
              <p className={fieldClasses.error}>{errores.area_construida}</p>
            )}
          </div>

          {/* Tipo de Vivienda */}
          <div className={`${fieldClasses.group} ${legalClasses.fullWidth}`}>
            <label htmlFor="tipo_vivienda" className={fieldClasses.label}>
              {LABELS.TIPO_VIVIENDA}
              <span className={fieldClasses.required}>*</span>
            </label>
            <select
              id="tipo_vivienda"
              value={tipoVivienda || ''}
              onChange={(e) => onChange('tipo_vivienda', e.target.value as TipoVivienda)}
              className={`${fieldClasses.select.base} ${errores.tipo_vivienda ? fieldClasses.select.error : ''}`}
            >
              <option value="">Selecciona el tipo</option>
              {TIPO_VIVIENDA_OPTIONS.map((option) => (
                <option key={option.value} value={option.value}>
                  {option.label}
                </option>
              ))}
            </select>
            {errores.tipo_vivienda && (
              <p className={fieldClasses.error}>{errores.tipo_vivienda}</p>
            )}
          </div>

          {/* Certificado de Tradición (Opcional) */}
          <div className={`${fieldClasses.group} ${legalClasses.fullWidth}`}>
            <label className={fieldClasses.label}>{LABELS.CERTIFICADO}</label>

            <div className={legalClasses.fileUpload.container}>
              <input
                ref={fileInputRef}
                type="file"
                accept="application/pdf"
                onChange={handleFileChange}
                className="hidden"
              />

              {!certificadoFile ? (
                <button
                  type="button"
                  onClick={() => fileInputRef.current?.click()}
                  className={legalClasses.fileUpload.button}
                >
                  <Upload className="h-4 w-4" />
                  Seleccionar archivo PDF
                </button>
              ) : (
                <div className="flex items-center gap-3 rounded-lg border border-green-200 bg-green-50 p-3 dark:border-green-700 dark:bg-green-900/20">
                  <CheckCircle className="h-5 w-5 text-green-600 dark:text-green-400" />
                  <div className="flex-1">
                    <p className="text-sm font-medium text-green-900 dark:text-green-100">
                      {certificadoFile.name}
                    </p>
                    <p className="text-xs text-green-700 dark:text-green-300">
                      {(certificadoFile.size / 1024 / 1024).toFixed(2)} MB
                    </p>
                  </div>
                  <button
                    type="button"
                    onClick={removeFile}
                    className="rounded-lg p-1 text-green-600 hover:bg-green-100 dark:text-green-400 dark:hover:bg-green-800"
                  >
                    <X className="h-4 w-4" />
                  </button>
                </div>
              )}

              {fileError && <p className={fieldClasses.error}>{fileError}</p>}

              <p className={fieldClasses.hint}>
                Formato: PDF | Tamaño máximo: 10MB | Opcional
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

/**
 * PasoLinderosNuevo - Paso 2: Linderos de la vivienda
 * ✅ Diseño compacto estándar
 * ✅ 4 linderos (Norte, Sur, Oriente, Occidente)
 */

'use client'

import { motion } from 'framer-motion'
import { AlertCircle, Compass, Lightbulb } from 'lucide-react'
import type { FieldErrors, UseFormRegister } from 'react-hook-form'

import { cn } from '@/shared/utils/helpers'

import { nuevaViviendaStyles as styles } from '../styles/nueva-vivienda.styles'

interface PasoLinderosProps {
  register: UseFormRegister<any>
