/**
 * PasoResumenNuevo - Paso 5: Resumen final
 * ✅ Componente presentacional puro
 * ✅ Sin lógica innecesaria
 */

'use client'

import { motion } from 'framer-motion'
import {
    Building2,
    CheckCircle,
    Compass,
    DollarSign,
    FileText,
    Home,
    MapPin,
    Maximize,
} from 'lucide-react'

interface PasoResumenProps {
  formData: any
  proyectoNombre?: string | null
  manzanaNombre?: string | null
  gastosNotariales?: number
  numeroVivienda?: number | null
}

export function PasoResumenNuevo({ formData, proyectoNombre, manzanaNombre, gastosNotariales = 5_000_000, numeroVivienda }: PasoResumenProps) {
  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('es-CO', {
      style: 'currency',
      currency: 'COP',
      minimumFractionDigits: 0,
    }).format(value || 0)
  }

  const sections = [
    {
      title: 'Ubicación',
      icon: MapPin,
      color: 'blue',
      items: [
        { label: 'Proyecto', value: proyectoNombre || 'No disponible', icon: Building2 },
        { label: 'Manzana', value: manzanaNombre || 'No disponible', icon: MapPin },
        { label: 'Número de Casa', value: (formData.numero || numeroVivienda) ? `#${formData.numero || numeroVivienda}` : 'No disponible', icon: Home },
      ],
    },
    {
      title: 'Linderos',
      icon: Compass,
      color: 'purple',
      items: [
        { label: '⬆️ Norte', value: formData.lindero_norte || 'No definido' },
        { label: '⬇️ Sur', value: formData.lindero_sur || 'No definido' },
        { label: '➡️ Oriente', value: formData.lindero_oriente || 'No definido' },
        { label: '⬅️ Occidente', value: formData.lindero_occidente || 'No definido' },
      ],
    },
    {
      title: 'Información Legal',
      icon: FileText,
      color: 'green',
      items: [
        { label: 'Matrícula Inmobiliaria', value: formData.matricula_inmobiliaria || 'No ingresada', icon: FileText },
        { label: 'Nomenclatura', value: formData.nomenclatura || 'No ingresada', icon: MapPin },
        { label: 'Área Lote', value: formData.area_lote ? `${formData.area_lote} m²` : 'No ingresada', icon: Maximize },
        { label: 'Área Construida', value: formData.area_construida ? `${formData.area_construida} m²` : 'No ingresada', icon: Maximize },
        { label: 'Tipo Vivienda', value: formData.tipo_vivienda || 'No seleccionado', icon: Home },
      ],
    },
    {
      title: 'Información Financiera',
      icon: DollarSign,
      color: 'orange',
      items: [
        { label: 'Valor Base', value: formatCurrency(formData.valor_base), icon: DollarSign },
        { label: 'Gastos Notariales', value: formatCurrency(gastosNotariales), icon: FileText },
        { label: 'Es Esquinera', value: formData.es_esquinera ? 'Sí' : 'No', icon: CheckCircle },
        ...(formData.es_esquinera ? [{ label: 'Recargo Esquinera', value: formatCurrency(formData.recargo_esquinera), icon: DollarSign }] : []),
        {
          label: 'Valor Total',
          value: formatCurrency((formData.valor_base || 0) + gastosNotariales + (formData.recargo_esquinera || 0)),
          icon: DollarSign,
          highlight: true,
        },
      ],
    },
  ]

  return (
    <motion.div
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.2 }}
      className="space-y-3"
    >
      {/* Título del paso */}
      <div>
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">
          Resumen Final
        </h2>
        <p className="text-sm text-gray-600 dark:text-gray-400">
          Revisa la información antes de guardar la vivienda
        </p>
      </div>

      {/* Secciones de resumen */}
      <div className="space-y-3">
        {sections.map((section, sectionIndex) => {
          const SectionIcon = section.icon

          return (
            <motion.div
              key={section.title}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: sectionIndex * 0.1 }}
              className="rounded-xl bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 p-3 shadow-lg"
            >
              {/* Header de sección */}
              <div className="flex items-center gap-2 mb-2 pb-2 border-b border-gray-200 dark:border-gray-700">
                <div className={`w-8 h-8 rounded-lg bg-gradient-to-br from-${section.color}-500 to-${section.color}-600 flex items-center justify-center shadow-lg`}>
                  <SectionIcon className="w-4 h-4 text-white" />
                </div>
                <h3 className="text-base font-bold text-gray-900 dark:text-white">
                  {section.title}
                </h3>
              </div>

              {/* Items de la sección */}
              <div className="space-y-2">
                {section.items.map((item, itemIndex) => {
                  const ItemIcon = 'icon' in item ? item.icon : null
                  return (
                    <div
                      key={itemIndex}
                      className={`flex items-start gap-2 py-1 ${
                        'highlight' in item && item.highlight
                          ? 'p-2 rounded-lg bg-gradient-to-r from-orange-50 to-amber-50 dark:from-orange-950/30 dark:to-amber-950/30 border border-orange-200 dark:border-orange-800'
                          : ''
                      }`}
                    >
                      {ItemIcon && (
                        <ItemIcon className={`w-4 h-4 flex-shrink-0 mt-0.5 ${
                          'highlight' in item && item.highlight
                            ? 'text-orange-600 dark:text-orange-400'
                            : 'text-gray-400 dark:text-gray-500'
                        }`} />
                      )}
                      <div className="flex-1 min-w-0">
                        <p className={`text-xs font-medium ${
                          'highlight' in item && item.highlight
                            ? 'text-orange-900 dark:text-orange-100'
                            : 'text-gray-500 dark:text-gray-400'
                        }`}>
                          {item.label}
                        </p>
                        <p className={`text-sm mt-0.5 ${
                          'highlight' in item && item.highlight
                            ? 'font-bold text-lg bg-gradient-to-br from-orange-600 to-amber-600 bg-clip-text text-transparent'
                            : 'font-semibold text-gray-900 dark:text-white'
                        }`}>
                          {item.value}
                        </p>
                      </div>
                    </div>
                  )
                })}
              </div>
            </motion.div>
          )
        })}
      </div>

      {/* Nota final */}
      <div className="flex items-start gap-2 p-3 rounded-xl bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800">
        <CheckCircle className="w-4 h-4 text-green-600 dark:text-green-400 flex-shrink-0 mt-0.5" />
        <div>
          <p className="text-sm font-medium text-green-900 dark:text-green-100 mb-1">
            ¡Todo listo!
          </p>
          <p className="text-xs text-green-700 dark:text-green-300">
            Haz clic en "Guardar Vivienda" para registrar esta vivienda en el sistema.
          </p>
        </div>
      </div>
    </motion.div>
  )
}

/**
 * PasoUbicacionNuevo - Paso 1: Selección de ubicación
 * ✅ Componente presentacional puro
 * ✅ Lógica en usePasoUbicacion hook
 * ✅ React Query para carga de datos
 * ✅ Soporta modo edición (muestra datos como solo lectura)
 */

'use client'

import { motion } from 'framer-motion'
import { AlertCircle, Building2, Home, Info, MapPin } from 'lucide-react'
import type { FieldErrors, UseFormRegister, UseFormSetValue, UseFormWatch } from 'react-hook-form'

import { cn } from '@/shared/utils/helpers'

import { usePasoUbicacion } from '../hooks/usePasoUbicacion'
import { nuevaViviendaStyles as styles } from '../styles/nueva-vivienda.styles'
import type { Vivienda } from '../types'

interface PasoUbicacionProps {
  register: UseFormRegister<any>
  errors: FieldErrors<any>
  setValue: UseFormSetValue<any>
  watch: UseFormWatch<any>
  mode?: 'create' | 'edit'
  viviendaActual?: Vivienda | null
}

export function PasoUbicacionNuevo({
  register,
  errors,
  setValue,
  watch,
  mode = 'create',
  viviendaActual = null
}: PasoUbicacionProps) {
  const isEditMode = mode === 'edit'

  // ✅ Hook con toda la lógica - SOLO en modo creación
  const hookData = usePasoUbicacion({
    setValue,
    watch,
    enabled: !isEditMode // ← NO ejecutar queries en modo edición
  })

  const {
    proyectos = [],
    manzanas = [],
    numerosDisponibles = [],
    manzanaInfo,
    cargandoProyectos = false,
    cargandoManzanas = false,
    cargandoNumeros = false,
  } = isEditMode ? {} : hookData

  // Variables observadas del formulario
  const proyectoSeleccionado = watch('proyecto_id')
  const manzanaSeleccionada = watch('manzana_id')
  const numeroVivienda = watch('numero')

  // Datos para modo edición - usar directamente de viviendaActual (sin queries)
  const proyectoNombre = isEditMode && viviendaActual?.manzanas?.proyectos
    ? viviendaActual.manzanas.proyectos.nombre
    : proyectos.find(p => p.id === proyectoSeleccionado)?.nombre || 'Cargando...'
  const manzanaNombre = isEditMode && viviendaActual?.manzanas
    ? viviendaActual.manzanas.nombre
    : manzanas.find(m => m.id === manzanaSeleccionada)?.nombre || 'Cargando...'
  const numeroDisplay = isEditMode && viviendaActual
    ? viviendaActual.numero
    : numeroVivienda

  return (
    <motion.div
      initial={{ opacity: 0, x: 20 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: -20 }}
      transition={{ duration: 0.2 }}
      className="space-y-3"
    >
      {/* Título del paso */}
      <div className="mb-2">
        <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">
          Ubicación de la Vivienda
        </h2>
        <p className="text-xs text-gray-600 dark:text-gray-400">
          {isEditMode
            ? 'Información de ubicación (no modificable)'
            : 'Selecciona el proyecto, manzana y número de vivienda disponible'
          }
        </p>
      </div>

      {/* Alerta informativa en modo edición */}
      {isEditMode && (
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          className="flex items-start gap-2 p-2.5 rounded-lg bg-blue-50 dark:bg-blue-950/30 border border-blue-200 dark:border-blue-800"
        >
          <Info className="w-4 h-4 text-blue-600 dark:text-blue-400 mt-0.5 flex-shrink-0" />
          <p className="text-xs text-blue-900 dark:text-blue-100">
            La ubicación de la vivienda no puede modificarse. Para cambiar estos datos, debes crear una nueva vivienda.
          </p>
        </motion.div>
      )}

      {/* Proyecto */}
      <div className={styles.field.container}>
        <label htmlFor="proyecto_id" className={styles.field.label}>
          Proyecto <span className={styles.field.required}>*</span>
        </label>
        {isEditMode ? (
          <div className="flex items-center gap-3 p-3 rounded-lg bg-gray-50 dark:bg-gray-900/50 border-2 border-gray-200 dark:border-gray-700">
            <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-blue-500 to-blue-600 flex items-center justify-center shadow-lg">
              <Building2 className="w-5 h-5 text-white" />
            </div>
            <div className="flex-1">
              <p className="text-sm font-bold text-gray-900 dark:text-white">
                {proyectoNombre}
              </p>
              <p className="text-xs text-gray-500 dark:text-gray-400">
                Proyecto actual
              </p>
            </div>
          </div>
        ) : (
          <>
            <div className={styles.field.inputWrapper}>
              <Building2 className={styles.field.inputIcon} />
              <select
                {...register('proyecto_id')}
                id="proyecto_id"
                disabled={cargandoProyectos}
                className={cn(
                  styles.field.select,
                  errors.proyecto_id && styles.field.inputError
                )}
              >
                <option value="">Selecciona un proyecto</option>
                {proyectos.map(proyecto => (
                  <option key={proyecto.id} value={proyecto.id}>
                    {proyecto.nombre}
                  </option>
                ))}
              </select>
            </div>
            {errors.proyecto_id && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className={styles.field.error}
              >
                <AlertCircle className={styles.field.errorIcon} />
                {errors.proyecto_id.message as string}
              </motion.div>
            )}
          </>
        )}
      </div>

      {/* Manzana */}
      <div className={styles.field.container}>
        <label htmlFor="manzana_id" className={styles.field.label}>
          Manzana <span className={styles.field.required}>*</span>
        </label>
        {isEditMode ? (
          <div className="flex items-center gap-3 p-3 rounded-lg bg-gray-50 dark:bg-gray-900/50 border-2 border-gray-200 dark:border-gray-700">
            <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-orange-500 to-amber-600 flex items-center justify-center shadow-lg">
              <MapPin className="w-5 h-5 text-white" />
            </div>
            <div className="flex-1">
              <p className="text-sm font-bold text-gray-900 dark:text-white">
                Manzana {manzanaNombre}
              </p>
              <p className="text-xs text-gray-500 dark:text-gray-400">
                Manzana actual
              </p>
            </div>
          </div>
        ) : (
          <>
            <div className={styles.field.inputWrapper}>
              <MapPin className={styles.field.inputIcon} />
              <select
                {...register('manzana_id')}
                id="manzana_id"
                disabled={!proyectoSeleccionado || cargandoManzanas}
                className={cn(
                  styles.field.select,
                  errors.manzana_id && styles.field.inputError
                )}
              >
                <option value="">
                  {!proyectoSeleccionado
                    ? 'Primero selecciona un proyecto'
                    : cargandoManzanas
                    ? 'Cargando manzanas...'
                    : manzanas.length === 0
                    ? 'No hay manzanas disponibles'
                    : 'Selecciona una manzana'}
                </option>
                {manzanas.map(manzana => (
                  <option
                    key={manzana.id}
                    value={manzana.id}
                    disabled={!manzana.tiene_disponibles}
                  >
                    Manzana {manzana.nombre} ({manzana.viviendas_disponibles} disponibles)
                  </option>
                ))}
              </select>
            </div>
            {errors.manzana_id && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className={styles.field.error}
              >
                <AlertCircle className={styles.field.errorIcon} />
                {errors.manzana_id.message as string}
              </motion.div>
            )}
            {manzanaInfo && (
              <div className={styles.field.hint}>
                <AlertCircle className={styles.field.hintIcon} />
                Total en manzana: {manzanaInfo.total_viviendas} viviendas •
                Creadas: {manzanaInfo.viviendas_creadas} •
                Disponibles: {manzanaInfo.viviendas_disponibles}
              </div>
            )}
          </>
        )}
      </div>

      {/* Número de vivienda */}
      <div className={styles.field.container}>
        <label htmlFor="numero" className={styles.field.label}>
          Número de Casa <span className={styles.field.required}>*</span>
        </label>
        {isEditMode ? (
          <div className="flex items-center gap-3 p-3 rounded-lg bg-gray-50 dark:bg-gray-900/50 border-2 border-gray-200 dark:border-gray-700">
            <div className="w-10 h-10 rounded-lg bg-gradient-to-br from-green-500 to-emerald-600 flex items-center justify-center shadow-lg">
              <Home className="w-5 h-5 text-white" />
            </div>
            <div className="flex-1">
              <p className="text-sm font-bold text-gray-900 dark:text-white">
                Casa Número {numeroDisplay}
              </p>
              <p className="text-xs text-gray-500 dark:text-gray-400">
                Número de casa
              </p>
            </div>
          </div>
        ) : (
          <>
            <div className={styles.field.inputWrapper}>
              <Home className={styles.field.inputIcon} />
              <select
                {...register('numero')}
                id="numero"
                disabled={!manzanaSeleccionada || numerosDisponibles.length === 0}
                className={cn(
                  styles.field.select,
                  errors.numero && styles.field.inputError
                )}
              >
                <option value="">
                  {!manzanaSeleccionada
                    ? 'Primero selecciona una manzana'
                    : numerosDisponibles.length === 0
                    ? 'No hay casas disponibles'
                    : 'Selecciona el número de casa'}
                </option>
                {numerosDisponibles.map(num => (
                  <option key={num} value={num.toString()}>
                    Casa Número {num}
                  </option>
                ))}
              </select>
            </div>
            {errors.numero && (
              <motion.div
                initial={{ opacity: 0, y: -10 }}
                animate={{ opacity: 1, y: 0 }}
                className={styles.field.error}
              >
                <AlertCircle className={styles.field.errorIcon} />
                {errors.numero.message as string}
              </motion.div>
            )}
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">
              Selecciona el número de casa que deseas crear de las disponibles
            </p>
          </>
        )}
      </div>
    </motion.div>
  )
}

/**
 * ViviendaCard - Componente principal con renderizado condicional
 * Renderiza diferentes versiones según el estado de la vivienda
 */

import type { Vivienda } from '../types'

import { ViviendaCardAsignada } from './cards/vivienda-card-asignada'
import { ViviendaCardDisponible } from './cards/vivienda-card-disponible'
import { ViviendaCardEntregada } from './cards/vivienda-card-entregada'

interface ViviendaCardProps {
  vivienda: Vivienda
  onVerDetalle?: () => void
  onAsignarCliente?: () => void
  onVerAbonos?: () => void
  onRegistrarPago?: () => void
  onGenerarEscritura?: () => void
  onEditar?: () => void
  onEliminar?: () => void
}

/**
 * Componente inteligente que renderiza la card apropiada según el estado
 */
export function ViviendaCard({
  vivienda,
  onVerDetalle,
  onAsignarCliente,
  onVerAbonos,
  onRegistrarPago,
  onGenerarEscritura,
  onEditar,
  onEliminar,
}: ViviendaCardProps) {
  // Renderizado condicional según el estado
  switch (vivienda.estado) {
    case 'Disponible':
      return (
        <ViviendaCardDisponible
          vivienda={vivienda}
          onVerDetalle={onVerDetalle}
          onAsignarCliente={onAsignarCliente}
          onEditar={onEditar}
        />
      )

    case 'Asignada':
      return (
        <ViviendaCardAsignada
          vivienda={vivienda}
          onVerDetalle={onVerDetalle}
          onVerAbonos={onVerAbonos}
          onRegistrarPago={onRegistrarPago}
          onEditar={onEditar}
        />
      )

    case 'Entregada':
      return (
        <ViviendaCardEntregada
          vivienda={vivienda}
          onVerDetalle={onVerDetalle}
          onVerAbonos={onVerAbonos}
          onEditar={onEditar}
        />
      )

    default:
      // Fallback a card disponible
      return (
        <ViviendaCardDisponible
          vivienda={vivienda}
          onVerDetalle={onVerDetalle}
          onAsignarCliente={onAsignarCliente}
          onEditar={onEditar}
        />
      )
  }
}

'use client'

import { motion } from 'framer-motion'

import { Pagination } from '@/shared/components/ui/Pagination'

import { staggerContainer, staggerItem } from '../../../shared/styles/animations'
import { viviendasListStyles as styles } from '../styles/viviendasList.styles'
import type { Vivienda } from '../types'

import { ViviendaCard } from './vivienda-card'

interface ViviendasListaProps {
  viviendas: Vivienda[]
  onVerDetalle?: (vivienda: Vivienda) => void
  onAsignarCliente?: (vivienda: Vivienda) => void
  onVerAbonos?: (vivienda: Vivienda) => void
  onRegistrarPago?: (vivienda: Vivienda) => void
  onGenerarEscritura?: (vivienda: Vivienda) => void
  onEditar?: (vivienda: Vivienda) => void
  onEliminar?: (id: string) => void
  // Paginación
  paginaActual?: number
  totalPaginas?: number
  totalItems?: number
  itemsPorPagina?: number
  onCambiarPagina?: (pagina: number) => void
  onCambiarItemsPorPagina?: (items: number) => void
}

/**
 * Lista de viviendas en grid con paginación
 * Componente presentacional puro
 */
export function ViviendasLista({
  viviendas,
  onVerDetalle,
  onAsignarCliente,
  onVerAbonos,
  onRegistrarPago,
  onGenerarEscritura,
  onEditar,
  onEliminar,
  paginaActual = 1,
  totalPaginas = 1,
  totalItems = 0,
  itemsPorPagina = 9,
  onCambiarPagina,
  onCambiarItemsPorPagina,
}: ViviendasListaProps) {
  return (
    <div className="space-y-6">
      <motion.div
        key={`page-${paginaActual}`}
        variants={staggerContainer}
        initial="hidden"
        animate="visible"
        className={styles.grid.container}
      >
        {viviendas.map(vivienda => (
          <motion.div key={vivienda.id} variants={staggerItem}>
            <ViviendaCard
              vivienda={vivienda}
              onVerDetalle={() => onVerDetalle?.(vivienda)}
              onAsignarCliente={() => onAsignarCliente?.(vivienda)}
              onVerAbonos={() => onVerAbonos?.(vivienda)}
              onRegistrarPago={() => onRegistrarPago?.(vivienda)}
              onGenerarEscritura={() => onGenerarEscritura?.(vivienda)}
              onEditar={() => onEditar?.(vivienda)}
              onEliminar={() => onEliminar?.(vivienda.id)}
            />
          </motion.div>
        ))}
      </motion.div>

      {/* Paginación - Mostrar siempre */}
      {onCambiarPagina && (
        <Pagination
          currentPage={paginaActual}
          totalPages={totalPaginas}
          totalItems={totalItems}
          itemsPerPage={itemsPorPagina}
          onPageChange={onCambiarPagina}
          onItemsPerPageChange={onCambiarItemsPorPagina}
        />
      )}
    </div>
  )
}

