import { useCallback, useState } from 'react'

import type { CategoriaFormData } from '@/modules/documentos/schemas/documento.schema'

import {
    useActualizarCategoriaMutation,
    useCategoriasViviendaQuery,
    useCrearCategoriaMutation,
    useEliminarCategoriaMutation
} from './useDocumentosViviendaQuery'

type Modo = 'lista' | 'crear' | 'editar'

interface UseCategoriasManagerProps {
  userId: string
  modulo?: 'proyectos' | 'clientes' | 'viviendas'
}

export function useCategoriasManager({ userId, modulo = 'viviendas' }: UseCategoriasManagerProps) {
  // Estado local
  const [modo, setModo] = useState<Modo>('lista')
  const [categoriaEditando, setCategoriaEditando] = useState<any>(null)
  const [eliminando, setEliminando] = useState<string | null>(null)

  // Estado para modal de confirmación de eliminación
  const [modalEliminarAbierto, setModalEliminarAbierto] = useState(false)
  const [categoriaAEliminar, setCategoriaAEliminar] = useState<{ id: string; nombre: string } | null>(null)

  // ✅ REACT QUERY: Datos del servidor
  const { categorias = [], cargando: cargandoCategorias } = useCategoriasViviendaQuery(userId)

  // ✅ REACT QUERY: Mutations
  const crearMutation = useCrearCategoriaMutation(userId)
  const actualizarMutation = useActualizarCategoriaMutation(userId)
  const eliminarMutation = useEliminarCategoriaMutation(userId)

  // Handlers
  const handleCrear = useCallback(
    async (data: CategoriaFormData) => {
      await crearMutation.mutateAsync({
        nombre: data.nombre,
        color: data.color,
        icono: data.icono,
        descripcion: data.descripcion,
      })
      setModo('lista')
    },
    [userId, modulo, crearMutation]
  )

  const handleActualizar = useCallback(
    async (data: CategoriaFormData) => {
      if (!categoriaEditando) return

      await actualizarMutation.mutateAsync({
        categoriaId: categoriaEditando.id,
        updates: {
          nombre: data.nombre,
          color: data.color,
          icono: data.icono,
        },
      })

      setModo('lista')
      setCategoriaEditando(null)
    },
    [categoriaEditando, actualizarMutation]
  )

  const handleEliminar = useCallback(
    async (categoriaId: string, categoriaNombre: string) => {
      // Abrir modal de confirmación
      setCategoriaAEliminar({ id: categoriaId, nombre: categoriaNombre })
      setModalEliminarAbierto(true)
    },
    []
  )

  const confirmarEliminar = useCallback(
    async () => {
      if (!categoriaAEliminar) return

      setEliminando(categoriaAEliminar.id)
      try {
        await eliminarMutation.mutateAsync(categoriaAEliminar.id)
        setModalEliminarAbierto(false)
        setCategoriaAEliminar(null)
      } finally {
        setEliminando(null)
      }
    },
    [categoriaAEliminar, eliminarMutation]
  )

  const cancelarEliminar = useCallback(() => {
    setModalEliminarAbierto(false)
    setCategoriaAEliminar(null)
  }, [])

  const handleIrACrear = useCallback(() => {
    setModo('crear')
  }, [])

  const handleIrAEditar = useCallback((categoria: any) => {
    setCategoriaEditando(categoria)
    setModo('editar')
  }, [])

  const handleVolverALista = useCallback(() => {
    setModo('lista')
    setCategoriaEditando(null)
  }, [])

  // Computed
  const tieneCategorias = categorias.length > 0
  const estaCargando = cargandoCategorias

  return {
    // Estado
    modo,
    categoriaEditando,
    eliminando,
    categorias,
    cargandoCategorias,
    tieneCategorias,
    estaCargando,

    // Estado modal eliminar
    modalEliminarAbierto,
    categoriaAEliminar,

    // Handlers de navegación
    handleIrACrear,
    handleIrAEditar,
    handleVolverALista,

    // Handlers de acciones
    handleCrear,
    handleActualizar,
    handleEliminar,
    confirmarEliminar,
    cancelarEliminar,
  }
}

'use client'

import { useState } from 'react'

import { toast } from 'sonner'

import { supabase } from '@/lib/supabase/client'
import { formatDateForDB } from '@/lib/utils/date.utils'
import { logger } from '@/lib/utils/logger'

interface EditarMetadatosData {
  titulo?: string
  descripcion?: string
  categoria_id?: string
  fecha_documento?: string | null
  fecha_vencimiento?: string | null
  etiquetas?: string[]
}

export function useDocumentoEditar() {
  const [editando, setEditando] = useState(false)
  const [error, setError] = useState<string | null>(null)

  const editarMetadatos = async (
    documentoId: string,
    data: EditarMetadatosData
  ): Promise<boolean> => {
    setEditando(true)
    setError(null)

    try {
      // Validaciones
      if (data.titulo && data.titulo.trim().length < 3) {
        throw new Error('El título debe tener al menos 3 caracteres')
      }

      if (data.fecha_vencimiento && data.fecha_documento) {
        const fechaDocumento = new Date(data.fecha_documento)
        const fechaVencimiento = new Date(data.fecha_vencimiento)

        if (fechaVencimiento <= fechaDocumento) {
          throw new Error('La fecha de vencimiento debe ser posterior a la fecha del documento')
        }
      }

      // Preparar datos para actualizar (solo campos que cambiaron)
      const updateData: any = {
        fecha_actualizacion: new Date().toISOString()
      }

      if (data.titulo !== undefined) updateData.titulo = data.titulo.trim()
      if (data.descripcion !== undefined) updateData.descripcion = data.descripcion?.trim() || null
      if (data.categoria_id !== undefined) updateData.categoria_id = data.categoria_id || null
      if (data.fecha_documento !== undefined) {
        updateData.fecha_documento = data.fecha_documento ? formatDateForDB(data.fecha_documento) : null
      }
      if (data.fecha_vencimiento !== undefined) {
        updateData.fecha_vencimiento = data.fecha_vencimiento ? formatDateForDB(data.fecha_vencimiento) : null
      }
      if (data.etiquetas !== undefined) updateData.etiquetas = data.etiquetas

      // Actualizar en base de datos
      const { error: updateError } = await supabase
        .from('documentos_vivienda')
        .update(updateData)
        .eq('id', documentoId)

      if (updateError) {
        logger.error('Error al actualizar metadatos:', updateError)
        throw new Error('No se pudo actualizar el documento')
      }

      toast.success('Documento actualizado correctamente', {
        description: 'Los cambios se guardaron exitosamente'
      })

      return true
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : 'Error desconocido'
      setError(errorMsg)
      toast.error('Error al editar documento', {
        description: errorMsg
      })
      return false
    } finally {
      setEditando(false)
    }
  }

  return {
    editando,
    error,
    editarMetadatos
  }
}

/**
 * 🗑️ HOOK: useDocumentosEliminados - VIVIENDAS
 *
 * Lógica de negocio para la Papelera de Documentos de Viviendas (Admin Only)
 * - Cargar documentos eliminados (soft delete)
 * - Restaurar documento (estado = 'activo')
 * - Eliminar definitivo (DELETE físico BD + Storage)
 *
 * ADAPTADO DESDE: src/modules/documentos/hooks/useDocumentosEliminados.ts
 */

import { useMemo, useState } from 'react'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { useAuth } from '@/contexts/auth-context'
import { logger } from '@/lib/utils/logger'

import { DocumentosViviendaService } from '../../services/documentos'

// Tipos para estado de modales
interface ModalState {
  isOpen: boolean
  documentoId: string
  titulo: string
}

export function useDocumentosEliminados() {
  const { perfil } = useAuth()
  const queryClient = useQueryClient()

  // Estados locales UI
  const [busqueda, setBusqueda] = useState('')
  const [viviendaFiltro, setViviendaFiltro] = useState<string>('todos')

  // 🆕 Estados para modales custom
  const [modalRestaurar, setModalRestaurar] = useState<ModalState>({
    isOpen: false,
    documentoId: '',
    titulo: '',
  })

  const [modalEliminar, setModalEliminar] = useState<ModalState>({
    isOpen: false,
    documentoId: '',
    titulo: '',
  })

  const [confirmacionTexto, setConfirmacionTexto] = useState('')

  // ✅ REACT QUERY: Cargar documentos eliminados
  const {
    data: documentos = [],
    isLoading: cargando,
    error,
    refetch,
  } = useQuery({
    queryKey: ['documentos-vivienda-eliminados'],
    queryFn: () => DocumentosViviendaService.obtenerDocumentosEliminados(),
    enabled: perfil?.rol === 'Administrador', // Solo admins
    staleTime: 30 * 1000, // 30 segundos (datos menos críticos)
    gcTime: 5 * 60 * 1000, // 5 minutos
  })

  // ✅ MUTATION: Restaurar documento
  const restaurarMutation = useMutation({
    mutationFn: (documentoId: string) =>
      DocumentosViviendaService.restaurarDocumentoEliminado(documentoId),
    onSuccess: async () => {
      toast.success('✅ Documento restaurado correctamente')

      // 🔧 FIX: Usar refetchQueries para forzar recarga INMEDIATA
      await Promise.all([
        queryClient.refetchQueries({ queryKey: ['documentos-vivienda-eliminados'] }),
        queryClient.refetchQueries({ queryKey: ['documentos-vivienda'] }), // ← Documentos activos de viviendas
        queryClient.refetchQueries({ queryKey: ['versiones-documento-vivienda'] }), // ← Historial de versiones
        queryClient.refetchQueries({ queryKey: ['versiones-eliminadas-vivienda'] }), // ← Versiones en papelera
      ])
    },
    onError: (error: unknown) => {
      logger.error('Error al restaurar documento:', error)
      const msg = error instanceof Error ? error.message : 'Error al restaurar el documento'
      toast.error(msg)
    },
  })

  // ✅ MUTATION: Eliminar definitivo
  const eliminarDefinitivoMutation = useMutation({
    mutationFn: (documentoId: string) =>
      DocumentosViviendaService.eliminarDefinitivo(documentoId),
    onSuccess: () => {
      toast.success('🗑️ Documento eliminado permanentemente')
      queryClient.invalidateQueries({ queryKey: ['documentos-vivienda-eliminados'] })
    },
    onError: (error: unknown) => {
      logger.error('Error al eliminar definitivamente:', error)
      const msg = error instanceof Error ? error.message : 'Error al eliminar el documento'
      toast.error(msg)
    },
  })

  // ✅ FILTROS: Búsqueda y vivienda
  const documentosFiltrados = useMemo(() => {
    let resultado = [...documentos]

    // Filtro por búsqueda (título, categoría, vivienda)
    if (busqueda.trim()) {
      const termino = busqueda.toLowerCase()
      resultado = resultado.filter(
        (doc) =>
          doc.titulo?.toLowerCase().includes(termino) ||
          doc.categoria?.nombre?.toLowerCase().includes(termino) ||
          (doc as any).viviendas?.codigo?.toLowerCase().includes(termino)
      )
    }

    // Filtro por vivienda
    if (viviendaFiltro && viviendaFiltro !== 'todos') {
      resultado = resultado.filter((doc) => doc.vivienda_id === viviendaFiltro)
    }

    return resultado
  }, [documentos, busqueda, viviendaFiltro])

  // ✅ ESTADÍSTICAS
  const estadisticas = useMemo(() => {
    return {
      total: documentos.length,
      filtrados: documentosFiltrados.length,
      // Viviendas únicas
      viviendas: Array.from(
        new Set(documentos.map((d) => d.vivienda_id).filter(Boolean))
      ),
    }
  }, [documentos, documentosFiltrados])

  // ✅ ACCIONES
  const handleRestaurar = async (documentoId: string, titulo: string) => {
    // Abrir modal de confirmación
    setModalRestaurar({ isOpen: true, documentoId, titulo })
  }

  const confirmarRestaurar = async () => {
    await restaurarMutation.mutateAsync(modalRestaurar.documentoId)
    setModalRestaurar({ isOpen: false, documentoId: '', titulo: '' })
  }

  const handleEliminarDefinitivo = async (documentoId: string, titulo: string) => {
    // Abrir modal de confirmación con prompt
    setModalEliminar({ isOpen: true, documentoId, titulo })
    setConfirmacionTexto('') // Limpiar input
  }

  const confirmarEliminarDefinitivo = async () => {
    if (confirmacionTexto !== 'ELIMINAR') {
      toast.error('❌ Debes escribir "ELIMINAR" en mayúsculas para confirmar')
      return
    }

    await eliminarDefinitivoMutation.mutateAsync(modalEliminar.documentoId)
    setModalEliminar({ isOpen: false, documentoId: '', titulo: '' })
    setConfirmacionTexto('')
  }

  return {
    // Data
    documentos: documentosFiltrados,
    documentosOriginales: documentos,
    cargando,
    error: error as Error | null,
    estadisticas,

    // Filtros
    busqueda,
    setBusqueda,
    viviendaFiltro,
    setViviendaFiltro,

    // Acciones
    handleRestaurar,
    handleEliminarDefinitivo,
    refrescar: refetch,

    // Estados de mutations
    restaurando: restaurarMutation.isPending ? modalRestaurar.documentoId : null,
    eliminando: eliminarDefinitivoMutation.isPending ? modalEliminar.documentoId : null,

    // 🆕 Modales custom
    modalRestaurar,
    setModalRestaurar,
    confirmarRestaurar,
    modalEliminar,
    setModalEliminar,
    confirmarEliminarDefinitivo,
    confirmacionTexto,
    setConfirmacionTexto,
  }
}

/**
 * ============================================
 * USE DOCUMENTOS LISTA (REACT QUERY) - VIVIENDAS
 * ============================================
 *
 * Hook principal para gestión de documentos de viviendas
 * Migrado de Zustand a React Query
 *
 * ADAPTADO DESDE: src/modules/documentos/hooks/useDocumentosLista.ts
 */

import { useCallback, useMemo, useState } from 'react'

import { useAuth } from '@/contexts/auth-context'
import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'
import { useModal } from '@/shared/components/modals'

import { DocumentosViviendaService } from '../../services/documentos'
import type { DocumentoVivienda } from '../../types/documento-vivienda.types'

import {
    useArchivarDocumentoViviendaMutation,
    useCategoriasViviendaQuery,
    useDocumentosViviendaQuery,
    useEliminarDocumentoViviendaMutation,
    useRestaurarDocumentoViviendaMutation,
    useToggleImportanteViviendaMutation,
} from './useDocumentosViviendaQuery'

interface UseDocumentosListaProps {
  viviendaId: string
  onViewDocumento?: (documento: DocumentoVivienda) => void
}

export function useDocumentosLista({
  viviendaId,
  onViewDocumento,
}: UseDocumentosListaProps) {
  // Estado local UI
  const [vista, setVista] = useState<'grid' | 'lista'>('grid')
  const [documentoSeleccionado, setDocumentoSeleccionado] =
    useState<DocumentoVivienda | null>(null)
  const [modalViewerAbierto, setModalViewerAbierto] = useState(false)
  const [urlPreview, setUrlPreview] = useState<string | undefined>(undefined)

  // Estado local para filtros
  const [categoriaFiltro, setCategoriaFiltro] = useState<string | null>(null)
  const [busqueda, setBusqueda] = useState('')
  const [soloImportantes, setSoloImportantes] = useState(false)

  const { user } = useAuth()
  const { confirm } = useModal()

  // ✅ REACT QUERY: Datos del servidor (cache automático)
  const { documentos, cargando: cargandoDocumentos, refrescar } = useDocumentosViviendaQuery(viviendaId)
  const { categorias } = useCategoriasViviendaQuery(user?.id)

  // ✅ REACT QUERY: Mutations
  const eliminarMutation = useEliminarDocumentoViviendaMutation(viviendaId)
  const toggleImportanteMutation = useToggleImportanteViviendaMutation(viviendaId)
  const archivarMutation = useArchivarDocumentoViviendaMutation(viviendaId)
  const restaurarMutation = useRestaurarDocumentoViviendaMutation(viviendaId)

  // Filtrado de documentos (local)
  const documentosFiltrados = useMemo(() => {
    let filtered = documentos

    if (categoriaFiltro) {
      filtered = filtered.filter(doc => doc.categoria_id === categoriaFiltro)
    }

    if (soloImportantes) {
      filtered = filtered.filter(doc => doc.es_importante)
    }

    if (busqueda) {
      const busquedaLower = busqueda.toLowerCase()
      filtered = filtered.filter(
        doc =>
          doc.titulo.toLowerCase().includes(busquedaLower) ||
          doc.nombre_original.toLowerCase().includes(busquedaLower) ||
          doc.descripcion?.toLowerCase().includes(busquedaLower)
      )
    }

    // ✅ ORDENAMIENTO INTELIGENTE
    return filtered.sort((a, b) => {
      // 1. Documentos VENCIDOS primero (CRÍTICO)
      const aVencido = a.fecha_vencimiento && new Date(a.fecha_vencimiento) < new Date()
      const bVencido = b.fecha_vencimiento && new Date(b.fecha_vencimiento) < new Date()

      if (aVencido && !bVencido) return -1
      if (!aVencido && bVencido) return 1

      // 2. Documentos próximos a vencer (30 días)
      const calcularDiasParaVencer = (fecha: string | undefined) => {
        if (!fecha) return Infinity
        return Math.ceil((new Date(fecha).getTime() - Date.now()) / (1000 * 60 * 60 * 24))
      }

      const diasA = calcularDiasParaVencer(a.fecha_vencimiento)
      const diasB = calcularDiasParaVencer(b.fecha_vencimiento)

      const aProximoVencer = diasA >= 0 && diasA <= 30
      const bProximoVencer = diasB >= 0 && diasB <= 30

      if (aProximoVencer && !bProximoVencer) return -1
      if (!aProximoVencer && bProximoVencer) return 1

      // Si ambos están próximos a vencer, ordenar por días restantes (menos días primero)
      if (aProximoVencer && bProximoVencer) {
        return diasA - diasB
      }

      // 3. Documentos importantes
      if (a.es_importante && !b.es_importante) return -1
      if (!a.es_importante && b.es_importante) return 1

      // 4. Más recientes primero (por fecha de creación)
      return new Date(b.fecha_creacion).getTime() - new Date(a.fecha_creacion).getTime()
    })
  }, [documentos, categoriaFiltro, busqueda, soloImportantes])

  // Handlers
  const handleView = useCallback(
    async (documento: DocumentoVivienda) => {
      setDocumentoSeleccionado(documento)
      setModalViewerAbierto(true)

      // Generar URL de preview para PDFs e imágenes
      const isPDF = documento.tipo_mime?.includes('pdf')
      const isImage = documento.tipo_mime?.startsWith('image/')

      if (isPDF || isImage) {
        try {
          // Bucket privado requiere signed URL
          const { data, error } = await supabase.storage
            .from('documentos-viviendas')
            .createSignedUrl(documento.url_storage, 3600) // 1 hora

          if (error) throw error

          setUrlPreview(data.signedUrl)
        } catch (error) {
          logger.error('Error al obtener URL de preview:', error)
          setUrlPreview(undefined)
        }
      } else {
        setUrlPreview(undefined)
      }

      onViewDocumento?.(documento)
    },
    [onViewDocumento]
  )

  const handleCloseViewer = useCallback(() => {
    setModalViewerAbierto(false)
    setDocumentoSeleccionado(null)
    setUrlPreview(undefined)
  }, [])

  const handleDownload = useCallback(async (documento: DocumentoVivienda) => {
    try {
      const url = await DocumentosViviendaService.obtenerUrlDescarga(
        documento.url_storage
      )
      window.open(url, '_blank')
    } catch (error) {
      logger.error('Error al descargar documento:', error)
    }
  }, [])

  const handleToggleImportante = useCallback(
    async (documento: DocumentoVivienda) => {
      try {
        await toggleImportanteMutation.mutateAsync(documento.id)
      } catch (error) {
        logger.error('Error al actualizar documento:', error)
      }
    },
    [toggleImportanteMutation]
  )

  const handleArchive = useCallback(
    async (documento: DocumentoVivienda) => {
      // ✅ Si el documento ya está archivado → Confirmar antes de restaurar
      if (documento.estado === 'archivado') {
        const confirmed = await confirm({
          title: 'Restaurar documento',
          message: `¿Estás seguro de que deseas restaurar "${documento.titulo}"?\n\n✅ El documento volverá a estar activo y visible en la pestaña "Activos".\n\n💡 Podrás archivarlo nuevamente en cualquier momento.`,
          confirmText: 'Restaurar',
          variant: 'info'
        })

        if (confirmed) {
          try {
            await restaurarMutation.mutateAsync(documento.id)
          } catch (error) {
            logger.error('Error al restaurar documento:', error)
          }
        }
        return
      }

      // ❌ Si está activo → Mostrar confirmación antes de archivar
      // Contar versiones para mensaje informativo
      const { total } = await DocumentosViviendaService.contarVersionesActivas(documento.id)

      const mensaje = total > 1
        ? `¿Estás seguro de que deseas archivar "${documento.titulo}"?\n\n⚠️ Se archivarán TODAS las ${total} versiones de este documento.\n\n✅ Podrás restaurarlo completo desde la pestaña "Archivados".`
        : `¿Estás seguro de que deseas archivar "${documento.titulo}"?\n\n✅ Podrás restaurarlo desde la pestaña "Archivados".`

      const confirmed = await confirm({
        title: 'Archivar documento completo',
        message: mensaje,
        confirmText: 'Archivar',
        variant: 'warning'
      })

      if (confirmed) {
        await archivarMutation.mutateAsync(documento.id)
      }
    },
    [archivarMutation, restaurarMutation, confirm]
  )

  const handleDelete = useCallback(
    async (documento: DocumentoVivienda) => {
      try {
        // 1. Verificar si el usuario es Administrador
        const esAdmin = user?.role === 'Administrador'

        // 2. Contar versiones activas del documento
        const { total } = await DocumentosViviendaService.contarVersionesActivas(documento.id)

        // 3. Construir mensaje según cantidad de versiones y rol
        let title = '¿Eliminar documento?'
        let message = ''

        if (total > 1) {
          // Documento con múltiples versiones
          title = `⚠️ Eliminar documento con ${total} versiones`
          message = `Se eliminarán TODAS las versiones de "${documento.titulo}".\n\n`

          if (esAdmin) {
            message += `📋 Si deseas eliminar solo UNA versión específica, usa el botón "Ver Historial" en la card del documento.\n\n✅ Podrás recuperar este documento desde la Papelera.\n\n¿Continuar con la eliminación completa?`
          } else {
            message += `⚠️ IMPORTANTE:\n• Los documentos eliminados solo pueden ser recuperados por un Administrador desde la Papelera.\n• Si deseas eliminar solo 1 versión específica, solicítalo a un Administrador (acción restringida).\n\n¿Continuar con la eliminación?`
          }
        } else {
          // Documento sin versiones adicionales
          if (esAdmin) {
            message = `Se eliminará "${documento.titulo}".\n\n✅ Podrás recuperarlo desde la Papelera.`
          } else {
            message = `Se eliminará "${documento.titulo}".\n\n⚠️ Solo un Administrador podrá recuperarlo desde la Papelera.\n\n¿Continuar?`
          }
        }

        const confirmed = await confirm({
          title,
          message,
          confirmText: total > 1 ? `Eliminar ${total} versiones` : 'Eliminar',
          cancelText: 'Cancelar',
          variant: 'danger'
        })

        if (confirmed) {
          await eliminarMutation.mutateAsync(documento.id)
        }
      } catch (error) {
        logger.error('Error al eliminar documento:', error)
      }
    },
    [eliminarMutation, confirm, user?.role]
  )

  // Helpers
  const getCategoriaByDocumento = useCallback(
    (documento: DocumentoVivienda) => {
      return categorias.find(c => c.id === documento.categoria_id)
    },
    [categorias]
  )

  const hasDocumentos = documentos.length > 0

  return {
    // Estado UI
    vista,
    setVista,
    documentoSeleccionado,
    modalViewerAbierto,
    urlPreview,

    // Datos
    documentosFiltrados,
    categorias,
    cargandoDocumentos,
    hasDocumentos,

    // Handlers
    handleView,
    handleCloseViewer,
    handleDownload,
    handleToggleImportante,
    handleArchive,
    handleDelete,
    getCategoriaByDocumento,

    // 🆕 Refrescar datos
    refrescar,
  }
}

/**
 * ============================================
 * USE DOCUMENTOS VIVIENDA QUERY (REACT QUERY)
 * ============================================
 *
 * Hooks para gestionar documentos de vivienda usando React Query
 * Reemplaza Zustand store con cache inteligente
 *
 * BENEFICIOS vs Zustand:
 * - ✅ Cache automático (stale-while-revalidate)
 * - ✅ Sin race conditions
 * - ✅ Invalidación automática después de mutations
 * - ✅ Background refetching inteligente
 */

'use client'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { logger } from '@/lib/utils/logger'
import { CategoriasService } from '@/modules/documentos/services'

import { DocumentosViviendaService } from '../../services/documentos'
import type { DocumentoVivienda } from '../../types/documento-vivienda.types'

// ============================================
// QUERY KEYS (Constantes para cache)
// ============================================
export const documentosViviendaKeys = {
  all: ['documentos-vivienda'] as const,
  lists: () => [...documentosViviendaKeys.all, 'list'] as const,
  list: (viviendaId: string) => [...documentosViviendaKeys.lists(), viviendaId] as const,
  categorias: (userId: string) => ['categorias-vivienda', userId] as const,
}

// ============================================
// 1. HOOK: useDocumentosViviendaQuery
// ============================================
export function useDocumentosViviendaQuery(viviendaId: string) {
  const {
    data: documentos = [],
    isLoading: cargando,
    error,
    refetch,
  } = useQuery({
    queryKey: documentosViviendaKeys.list(viviendaId),
    queryFn: () => DocumentosViviendaService.obtenerDocumentosPorVivienda(viviendaId),
    enabled: !!viviendaId,
    staleTime: 5 * 60 * 1000, // 5 minutos
    gcTime: 10 * 60 * 1000, // 10 minutos
  })

  return {
    documentos,
    cargando,
    error: error as Error | null,
    refrescar: refetch,
  }
}

// ============================================
// 2. HOOK: useCategoriasViviendaQuery
// ============================================
export function useCategoriasViviendaQuery(userId?: string) {
  const queryClient = useQueryClient()

  const {
    data: categorias = [],
    isLoading: cargando,
    error,
  } = useQuery({
    queryKey: [...documentosViviendaKeys.categorias(userId!), 'viviendas'],
    queryFn: async () => {
      const cats = await CategoriasService.obtenerCategoriasPorModulo(userId!, 'viviendas')

      // ✅ SEED AUTOMÁTICO: Si no hay categorías para viviendas, crear las por defecto
      if (cats.length === 0) {
        // Por ahora retornar vacío, el usuario puede crear manualmente o usar las de proyectos
        return []
      }

      return cats
    },
    enabled: !!userId,
    staleTime: 10 * 60 * 1000, // 10 minutos (categorías cambian poco)
    gcTime: 30 * 60 * 1000, // 30 minutos
  })

  return {
    categorias,
    cargando,
    error: error as Error | null,
  }
}

// ============================================
// 3. HOOK: useSubirDocumentoViviendaMutation
// ============================================
export function useSubirDocumentoViviendaMutation(viviendaId: string) {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (params: {
      archivo: File
      titulo: string
      descripcion?: string
      categoriaId?: string
      fechaDocumento?: string
      fechaVencimiento?: string
      esImportante?: boolean
      userId: string
    }) =>
      DocumentosViviendaService.subirDocumento(
        {
          vivienda_id: viviendaId,
          categoria_id: params.categoriaId,
          titulo: params.titulo,
          descripcion: params.descripcion,
          archivo: params.archivo,
          fecha_documento: params.fechaDocumento,
          fecha_vencimiento: params.fechaVencimiento,
          es_importante: params.esImportante,
        },
        params.userId
      ),
    onSuccess: async (nuevoDocumento) => {
      // ✅ PASO 1: Invalidar todas las queries relacionadas con documentos
      await queryClient.invalidateQueries({
        queryKey: documentosViviendaKeys.list(viviendaId),
      })

      // ✅ PASO 2: Refetch INMEDIATO y FORZADO
      await queryClient.refetchQueries({
        queryKey: documentosViviendaKeys.list(viviendaId),
        type: 'active',
      })

      // ✅ PASO 3: Actualización optimista del cache (agregar documento manualmente)
      queryClient.setQueryData<DocumentoVivienda[]>(
        documentosViviendaKeys.list(viviendaId),
        (oldDocumentos = []) => {
          // Si el documento ya está en la lista (del refetch), no duplicar
          const existe = oldDocumentos.some(doc => doc.id === nuevoDocumento.id)
          if (existe) return oldDocumentos

          // Agregar el nuevo documento al inicio de la lista
          return [nuevoDocumento, ...oldDocumentos]
        }
      )

      toast.success('Documento subido correctamente', {
        description: nuevoDocumento.titulo,
      })
    },
    onError: (error: Error) => {
      toast.error('Error al subir documento', {
        description: error.message,
      })
    },
  })
}

// ============================================
// 4. HOOK: useActualizarDocumentoViviendaMutation
// ============================================
export function useActualizarDocumentoViviendaMutation(viviendaId: string) {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: ({
      documentoId,
      updates,
    }: {
      documentoId: string
      updates: Partial<DocumentoVivienda>
    }) => DocumentosViviendaService.actualizarDocumento(documentoId, updates),
    onSuccess: async () => {
      await queryClient.invalidateQueries({ queryKey: documentosViviendaKeys.list(viviendaId) })
      toast.success('Documento actualizado')
    },
    onError: (error: Error) => {
      toast.error('Error al actualizar documento', {
        description: error.message,
      })
    },
  })
}

// ============================================
// 5. HOOK: useEliminarDocumentoViviendaMutation
// ============================================
export function useEliminarDocumentoViviendaMutation(viviendaId: string) {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (documentoId: string) => DocumentosViviendaService.eliminarDocumento(documentoId),
    onSuccess: async () => {
      // 🔧 FIX: Usar refetchQueries para forzar recarga INMEDIATA en Papelera
      await Promise.all([
        queryClient.refetchQueries({ queryKey: documentosViviendaKeys.list(viviendaId) }),
        queryClient.refetchQueries({ queryKey: ['documentos-vivienda-eliminados'] }), // â† Papelera
        queryClient.refetchQueries({ queryKey: ['versiones-vivienda-eliminadas'] }), // â† Versiones en papelera
      ])
      toast.success('Documento eliminado correctamente')
    },
    onError: (error: Error) => {
      toast.error('Error al eliminar documento', {
        description: error.message,
      })
    },
  })
}

// ============================================
// 6. HOOK: useToggleImportanteViviendaMutation
// ============================================
export function useToggleImportanteViviendaMutation(viviendaId: string) {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async (documentoId: string) => {

      // Obtener documento actual del cache
      const documentos = queryClient.getQueryData<DocumentoVivienda[]>(
        documentosViviendaKeys.list(viviendaId)
      )
      const documento = documentos?.find((d) => d.id === documentoId)

      if (!documento) {
        logger.error('❌ [Toggle Importante] Documento no encontrado en cache')
        throw new Error('Documento no encontrado')
      }

      // Toggle importante
      return DocumentosViviendaService.actualizarDocumento(documentoId, {
        es_importante: !documento.es_importante,
      })
    },
    onSuccess: async (result) => {

      // ✅ Invalidar y refetch inmediato (sin optimistic update)
      await queryClient.invalidateQueries({
        queryKey: documentosViviendaKeys.list(viviendaId),
      })

      await queryClient.refetchQueries({
        queryKey: documentosViviendaKeys.list(viviendaId),
        type: 'active',
      })

      toast.success('✅ Documento actualizado')
    },
    onError: (err) => {
      logger.error('❌ [Toggle Importante] Error:', err)
      toast.error('Error al actualizar documento')
    },
  })
}

// ============================================
// 7. HOOK: useArchivarDocumentoViviendaMutation
// ============================================
export function useArchivarDocumentoViviendaMutation(viviendaId: string) {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (documentoId: string) => DocumentosViviendaService.archivarDocumento(documentoId),
    onSuccess: async () => {
      // Invalidar ambas queries: activos y archivados
      await Promise.all([
        queryClient.refetchQueries({ queryKey: documentosViviendaKeys.list(viviendaId) }),
        queryClient.refetchQueries({ queryKey: [...documentosViviendaKeys.list(viviendaId), 'archivados'] }),
      ])

      toast.success('📦 Documento archivado correctamente')
    },
    onError: (error: Error) => {
      toast.error('Error al archivar documento', {
        description: error.message,
      })
    },
  })
}

// ============================================
// 8. HOOK: useRestaurarDocumentoViviendaMutation
// ============================================
export function useRestaurarDocumentoViviendaMutation(viviendaId: string) {
  const queryClient = useQueryClient()

