/**
 * Función para crear las categorías del sistema si no existen
 */
async function seedCategoriasSistema(supabase: any, userId: string) {

  const categorias = CATEGORIAS_SISTEMA_VIVIENDAS.map((cat) => ({
    user_id: userId,
    nombre: cat.nombre,
    descripcion: cat.descripcion,
    color: cat.color,
    icono: cat.icono,
    orden: cat.orden,
    es_sistema: true,
    es_global: true,
    modulos_permitidos: ['viviendas'],
  }))

  const { error } = await supabase
    .from('categorias_documento')
    .insert(categorias)

  if (error) {
    logger.error('❌ Error al crear categorías del sistema:', error)
    throw new Error(`Error al crear categorías: ${error.message}`)
  }

}

/**
 * Hook para obtener categorías del sistema para viviendas
 * ✅ AUTO-SEED: Crea automáticamente las categorías si no existen
 */
export function useCategoriasSistemaViviendas() {
  const supabase = createClient()

  const { data: categorias = [], isLoading } = useQuery({
    queryKey: ['categorias-sistema-viviendas'],
    queryFn: async () => {
      // 1. Intentar obtener categorías existentes
      const { data, error } = await supabase
        .from('categorias_documento')
        .select('id, user_id, nombre, descripcion, color, icono, orden, es_global, modulos_permitidos, fecha_creacion')
        .contains('modulos_permitidos', ['viviendas'])
        .eq('es_sistema', true)
        .order('orden', { ascending: true })

      if (error) {
        logger.error('❌ Error al cargar categorías de sistema:', error)
        throw new Error(`Error al cargar categorías: ${error.message}`)
      }

      // 2. Si NO hay categorías, crear las predefinidas
      if (!data || data.length === 0) {
        logger.warn('⚠️ No se encontraron categorías del sistema. Creando automáticamente...')

        // Obtener usuario actual (necesario para user_id)
        const { data: { user } } = await supabase.auth.getUser()

        if (!user) {
          logger.error('❌ No hay usuario autenticado para crear categorías')
          return []
        }

        // Crear categorías del sistema
        await seedCategoriasSistema(supabase, user.id)

        // Re-fetch después de crear
        const { data: newData, error: refetchError } = await supabase
          .from('categorias_documento')
          .select('id, user_id, nombre, descripcion, color, icono, orden, es_global, modulos_permitidos, fecha_creacion')
          .contains('modulos_permitidos', ['viviendas'])
          .eq('es_sistema', true)
          .order('orden', { ascending: true })

        if (refetchError) {
          logger.error('❌ Error al recargar categorías:', refetchError)
          return []
        }

        return (newData || []).map((cat) => ({ ...cat, es_sistema: true })) as CategoriaSistema[]
      }

      // 3. Categorías encontradas, retornar
      return data.map((cat) => ({ ...cat, es_sistema: true })) as CategoriaSistema[]
    },
    staleTime: Infinity, // Las categorías del sistema nunca cambian
    gcTime: Infinity, // Mantener en caché indefinidamente
  })

  // Helpers para acceder a categorías específicas por nombre
  const obtenerPorNombre = (nombre: string) => {
    return categorias.find((c) => c.nombre === nombre)
  }

  // Helper para detectar categoría por nombre de archivo
  const obtenerCategoriaPorNombre = (nombreArchivo: string) => {
    const nombreLower = nombreArchivo.toLowerCase()

    // Mapeo de palabras clave a categorías
    const mapeo: Record<string, string> = {
      'tradicion': 'Certificado de Tradición',
      'certificado': 'Certificado de Tradición',
      'escritura': 'Escrituras Públicas',
      'plano': 'Planos Arquitectónicos',
      'licencia': 'Licencias y Permisos',
      'permiso': 'Licencias y Permisos',
      'avaluo': 'Avalúos Comerciales',
      'avalúo': 'Avalúos Comerciales',
      'foto': 'Fotos de Progreso',
      'imagen': 'Fotos de Progreso',
      'contrato': 'Contrato de Promesa',
      'promesa': 'Contrato de Promesa',
      'recibo': 'Recibos de Servicios',
      'servicio': 'Recibos de Servicios',
    }

    // Buscar coincidencia
    for (const [keyword, categoriaNombre] of Object.entries(mapeo)) {
      if (nombreLower.includes(keyword)) {
        return obtenerPorNombre(categoriaNombre)
      }
    }

    return undefined
  }

  return {
    // Data
    categoriasSistema: categorias,
    categorias, // Alias para compatibilidad
    isLoading,

    // Categorías específicas (las más comunes)
    certificadoTradicion: obtenerPorNombre('Certificado de Tradición'),
    escriturasPublicas: obtenerPorNombre('Escrituras Públicas'),
    planosArquitectonicos: obtenerPorNombre('Planos Arquitectónicos'),
    licenciasPermisos: obtenerPorNombre('Licencias y Permisos'),
    avaluosComerciales: obtenerPorNombre('Avalúos Comerciales'),
    fotosProgreso: obtenerPorNombre('Fotos de Progreso'),
    contratoPromesa: obtenerPorNombre('Contrato de Promesa'),
    recibosServicios: obtenerPorNombre('Recibos de Servicios'),

    // Helpers
    obtenerPorNombre,
    obtenerCategoriaPorNombre,
    existeCategoria: (nombre: string) => !!obtenerPorNombre(nombre),
  }
}

/**
 * 🎣 Hook: Lógica de Modal Desactivar Vivienda
 *
 * Responsabilidad:
 * - Manejar estado del modal (motivo, confirmación, validación)
 * - Validar automáticamente al abrir
 * - Calcular caracteres restantes
 * - Ejecutar desactivación
 * - Limpiar al cerrar
 */

'use client'

import { useCallback, useEffect, useState } from 'react'

import { logger } from '@/lib/utils/logger'

import { useViviendaInactivacion } from './useViviendaInactivacion'

// ============================================================
// TIPOS
// ============================================================

interface UseDesactivarViviendaModalParams {
  isOpen: boolean
  viviendaId: string
  onSuccess: () => void
  onClose: () => void
}

interface UseDesactivarViviendaModalReturn {
  // Estado
  motivo: string
  confirmado: boolean
  validacion: any
  validando: boolean
  procesando: boolean
  error: string | null

  // Validaciones
  motivoValido: boolean
  caracteresRestantes: number
  puedeDesactivar: boolean

  // Acciones
  setMotivo: (motivo: string) => void
  setConfirmado: (confirmado: boolean) => void
  handleDesactivar: () => Promise<void>
}

const MOTIVO_MINIMO = 50

// ============================================================
// HOOK
// ============================================================

export function useDesactivarViviendaModal({
  isOpen,
  viviendaId,
  onSuccess,
  onClose,
}: UseDesactivarViviendaModalParams): UseDesactivarViviendaModalReturn {
  const { validarEliminacion, desactivar, validando, procesando, error, limpiarError } =
    useViviendaInactivacion()

  const [motivo, setMotivo] = useState('')
  const [confirmado, setConfirmado] = useState(false)
  const [validacion, setValidacion] = useState<any>(null)

  // Calcular validaciones
  const caracteresRestantes = MOTIVO_MINIMO - motivo.length
  const motivoValido = motivo.trim().length >= MOTIVO_MINIMO
  const puedeDesactivar = motivoValido && confirmado && !procesando && validacion?.puedeEliminar

  // Validar al abrir modal
  useEffect(() => {
    if (isOpen && viviendaId) {
      validarEliminacion(viviendaId)
        .then((result) => setValidacion(result))
        .catch((err) => logger.error('Error al validar:', err))
    }
  }, [isOpen, viviendaId, validarEliminacion])

  // Limpiar al cerrar
  useEffect(() => {
    if (!isOpen) {
      setMotivo('')
      setConfirmado(false)
      setValidacion(null)
      limpiarError()
    }
  }, [isOpen, limpiarError])

  // Ejecutar desactivación
  const handleDesactivar = useCallback(async () => {
    if (!puedeDesactivar) return

    try {
      await desactivar(viviendaId, motivo)
      onSuccess()
      onClose()
    } catch (err) {
      // Error manejado por el hook base
    }
  }, [puedeDesactivar, desactivar, viviendaId, motivo, onSuccess, onClose])

  return {
    motivo,
    confirmado,
    validacion,
    validando,
    procesando,
    error,
    motivoValido,
    caracteresRestantes,
    puedeDesactivar,
    setMotivo,
    setConfirmado,
    handleDesactivar,
  }
}

/**
 * 🔄 HOOK: useDocumentoVersiones
 *
 * Lógica de negocio para gestión de versiones de documentos
 * - Cargar historial de versiones
 * - Ver/Descargar versiones
 * - Restaurar versión anterior (con invalidación de caché)
 * - Eliminar versión (soft delete)
 */

import { useEffect, useState } from 'react'

import { useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { useAuth } from '@/contexts/auth-context'
import { logger } from '@/lib/utils/logger'

import { DocumentosViviendaService } from '../services/documentos'
import type { DocumentoVivienda } from '../types/documento-vivienda.types'

interface UseDocumentoVersionesProps {
  documentoId: string
  isOpen: boolean
  onVersionRestaurada?: () => void
}

export function useDocumentoVersiones({
  documentoId,
  isOpen,
  onVersionRestaurada
}: UseDocumentoVersionesProps) {
  const { user, perfil } = useAuth() // ✅ Obtener perfil también
  const queryClient = useQueryClient()
  const [versiones, setVersiones] = useState<DocumentoVivienda[]>([])
  const [cargando, setCargando] = useState(false)
  const [restaurando, setRestaurando] = useState<string | null>(null)
  const [eliminando, setEliminando] = useState<string | null>(null)

  // Estado del modal de confirmación de restauración
  const [mostrarModalMotivo, setMostrarModalMotivo] = useState(false)
  const [versionARestaurar, setVersionARestaurar] = useState<{ id: string; numero: number } | null>(null)
  const [motivoRestauracion, setMotivoRestauracion] = useState('')

  const cargarVersiones = async () => {
    setCargando(true)
    try {
      const data = await DocumentosViviendaService.obtenerVersiones(documentoId)
      setVersiones(data)
    } catch (error) {
      logger.error('❌ Error al cargar versiones:', error)
      toast.error('Error al cargar historial de versiones')
    } finally {
      setCargando(false)
    }
  }

  useEffect(() => {
    if (isOpen && documentoId) {
      cargarVersiones()
    }
  }, [isOpen, documentoId])

  const handleVerDocumento = async (documento: DocumentoVivienda) => {
    try {
      const url = await DocumentosViviendaService.obtenerUrlDescarga(documento.url_storage)
      window.open(url, '_blank')
    } catch (error) {
      logger.error('Error al ver documento:', error)
      toast.error('Error al abrir el documento')
    }
  }

  const handleDescargar = async (documento: DocumentoVivienda) => {
    try {
      const url = await DocumentosViviendaService.obtenerUrlDescarga(documento.url_storage)
      const response = await fetch(url)
      const blob = await response.blob()
      const downloadUrl = window.URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = downloadUrl
      a.download = documento.nombre_original
      document.body.appendChild(a)
      a.click()
      window.URL.revokeObjectURL(downloadUrl)
      document.body.removeChild(a)
      toast.success('Descarga iniciada')
    } catch (error) {
      logger.error('Error al descargar:', error)
      toast.error('Error al descargar el documento')
    }
  }

  const solicitarRestauracion = (versionId: string, versionNumero: number) => {
    setVersionARestaurar({ id: versionId, numero: versionNumero })
    setMotivoRestauracion('')
    setMostrarModalMotivo(true)
  }

  const cancelarRestauracion = () => {
    setMostrarModalMotivo(false)
    setVersionARestaurar(null)
    setMotivoRestauracion('')
  }

  const handleRestaurar = async (versionId: string) => {
    if (!user) {
      toast.error('Debes iniciar sesión')
      return
    }

    if (!motivoRestauracion.trim()) {
      toast.error('Debes proporcionar un motivo para la restauración')
      return
    }

    setRestaurando(versionId)
    try {
      await DocumentosViviendaService.restaurarVersion(versionId, user.id, motivoRestauracion.trim())
      toast.success('Versión restaurada correctamente')

      // ✅ NUEVO: Invalidar caché de React Query para actualizar la lista
      // Necesitamos obtener el vivienda_id del documento actual
      const docActual = versiones.find(v => v.id === versionId)
      if (docActual) {
        queryClient.invalidateQueries({
          queryKey: ['documentos-vivienda', docActual.vivienda_id],
        })
      }

      await cargarVersiones()
      onVersionRestaurada?.()
      // Limpiar estado
      setMostrarModalMotivo(false)
      setVersionARestaurar(null)
      setMotivoRestauracion('')
    } catch (error) {
      logger.error('Error al restaurar versión:', error)
      toast.error('Error al restaurar la versión')
    } finally {
      setRestaurando(null)
    }
  }

  const handleEliminar = async (versionId: string, versionNumero: number) => {
    if (!user) {
      toast.error('Debes iniciar sesión')
      return
    }

    // ✅ Validar rol de Administrador
    if (perfil?.rol !== 'Administrador') {
      toast.error('❌ Solo Administradores pueden eliminar versiones')
      return
    }

    // 🔍 Verificar si es versión actual (CRÍTICA - no se puede eliminar)
    const version = versiones.find(v => v.id === versionId)

    let mensaje = `¿Estás seguro de eliminar la versión ${versionNumero}?\n\nProporciona el motivo de eliminación (mínimo 20 caracteres):`

    if (version?.es_version_actual) {
      mensaje = `⚠️ ESTA ES LA VERSIÓN ACTUAL.\n\n¿Estás SEGURO de eliminar la versión ${versionNumero}?\n\nProporciona el motivo de eliminación (mínimo 20 caracteres):`
    }

    const motivo = window.prompt(mensaje)

    if (!motivo) return

    if (motivo.length < 20) {
      toast.error('El motivo debe tener mínimo 20 caracteres')
      return
    }

    setEliminando(versionId)
    try {
      await DocumentosViviendaService.eliminarVersion(versionId, user.id, perfil.rol, motivo)
      toast.success('Versión eliminada correctamente')

      // ✅ Invalidar caché de React Query
      const docActual = versiones.find(v => v.id === versionId)
      if (docActual) {
        queryClient.invalidateQueries({
          queryKey: ['documentos-vivienda', docActual.vivienda_id],
        })
      }

      await cargarVersiones()
    } catch (error: unknown) {
      logger.error('Error al eliminar versión:', error)
      toast.error(error?.message || 'Error al eliminar la versión')
    } finally {
      setEliminando(null)
    }
  }

  return {
    // Data
    versiones,
    cargando,
    restaurando,
    eliminando,
    perfil, // ✅ Exportar perfil para validación de rol en componente

    // Modal de motivo
    mostrarModalMotivo,
    versionARestaurar,
    motivoRestauracion,
    setMotivoRestauracion,

    // Acciones
    handleVerDocumento,
    handleDescargar,
    solicitarRestauracion,
    cancelarRestauracion,
    handleRestaurar,
    handleEliminar,
    cargarVersiones, // ✅ Exportar para refrescar desde el modal
  }
}

/**
 * 🗑️ HOOK: useDocumentosPapelera
 *
 * Lógica de negocio para gestión de documentos eliminados (papelera)
 * - Listar documentos eliminados
 * - Restaurar documentos
 * - Eliminar permanentemente
 */

import { useCallback } from 'react'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { useAuth } from '@/contexts/auth-context'
import { logger } from '@/lib/utils/logger'
import { documentosViviendaService } from '@/modules/viviendas/services/documentos-vivienda.service'


interface UseDocumentosPapeleraParams {
  viviendaId: string
}

export function useDocumentosPapelera({ viviendaId }: UseDocumentosPapeleraParams) {
  const { user, perfil } = useAuth()
  const queryClient = useQueryClient()

  // ✅ QUERY: Obtener documentos eliminados
  const {
    data: documentosEliminados = [],
    isLoading,
    error,
    refetch
  } = useQuery({
    queryKey: ['documentos-eliminados', viviendaId],
    queryFn: () => documentosViviendaService.obtenerDocumentosEliminados(viviendaId),
    enabled: perfil?.rol === 'Administrador', // Solo Admin puede ver
    staleTime: 1000 * 60 * 5, // 5 minutos
  })

  // ✅ Contar total de documentos raíz (no versiones)
  const cantidadEliminados = documentosEliminados.length

  // ✅ MUTATION: Restaurar documento
  const restaurarMutation = useMutation({
    mutationFn: async (id: string) => {
      if (!user || !perfil) {
        throw new Error('Debe iniciar sesión')
      }
      return documentosViviendaService.restaurarDocumento(id, user.id, perfil.rol)
    },
    onMutate: () => {
      toast.loading('Restaurando documento...', { id: 'restore-doc' })
    },
    onSuccess: () => {
      // Invalidar queries
      queryClient.invalidateQueries({
        queryKey: ['documentos-eliminados', viviendaId],
      })
      queryClient.invalidateQueries({
        queryKey: ['documentos-vivienda', viviendaId],
      })

      toast.success('Documento restaurado correctamente', {
        id: 'restore-doc',
      })
    },
    onError: (error: Error) => {
      toast.error(error.message || 'Error al restaurar', {
        id: 'restore-doc',
      })
    },
  })

  // ✅ MUTATION: Eliminar permanentemente
  const eliminarPermanenteMutation = useMutation({
    mutationFn: async ({ id, motivo, soloEstaVersion = false }: { id: string; motivo: string; soloEstaVersion?: boolean }) => {
      if (!user || !perfil) {
        throw new Error('Debe iniciar sesión')
      }
      return documentosViviendaService.eliminarPermanente(id, user.id, perfil.rol, motivo, soloEstaVersion)
    },
    onMutate: () => {
      toast.loading('Eliminando permanentemente...', { id: 'delete-permanent' })
    },
    onSuccess: () => {
      // Invalidar query de papelera
      queryClient.invalidateQueries({
        queryKey: ['documentos-eliminados', viviendaId],
      })

      toast.success('Documento eliminado permanentemente', {
        id: 'delete-permanent',
      })
    },
    onError: (error: Error) => {
      toast.error(error.message || 'Error al eliminar permanentemente', {
        id: 'delete-permanent',
      })
    },
  })

  // ✅ Handler: Restaurar documento
  const handleRestaurar = useCallback(
    async (id: string, titulo: string) => {
      const confirmado = window.confirm(
        `¿Restaurar el documento "${titulo}"?\n\nEl documento volverá a estar activo con todas sus versiones.`
      )

      if (!confirmado) return

      try {
        await restaurarMutation.mutateAsync(id)
      } catch (error) {
        logger.error('❌ Error al restaurar documento:', error)
      }
    },
    [restaurarMutation]
  )

  // ✅ Handler: Eliminar permanentemente
  const handleEliminarPermanente = useCallback(
    async (id: string, titulo: string, soloEstaVersion: boolean = false) => {
      // 1. Primera confirmación
      const mensaje = soloEstaVersion
        ? `⚠️ ADVERTENCIA: Esta acción es IRREVERSIBLE\n\n` +
          `Vas a eliminar PERMANENTEMENTE esta versión:\n` +
          `"${titulo}"\n\n` +
          `Se eliminarán:\n` +
          `- El registro de esta versión\n` +
          `- El archivo físico de Storage\n\n` +
          `¿Estás ABSOLUTAMENTE seguro?`
        : `⚠️ ADVERTENCIA: Esta acción es IRREVERSIBLE\n\n` +
          `Vas a eliminar PERMANENTEMENTE:\n` +
          `"${titulo}" y TODAS sus versiones\n\n` +
          `Se eliminarán:\n` +
          `- Todos los registros de la base de datos\n` +
          `- Todos los archivos físicos de Storage\n\n` +
          `¿Estás ABSOLUTAMENTE seguro?`

      const confirmado = window.confirm(mensaje)

      if (!confirmado) return

      // 2. Solicitar motivo
      const motivo = window.prompt(
        `Proporciona el motivo de eliminación PERMANENTE (mínimo 20 caracteres):`
      )

      if (!motivo) return

      if (motivo.trim().length < 20) {
        toast.error('El motivo debe tener al menos 20 caracteres')
        return
      }

      // 3. Segunda confirmación (doble check)
      const confirmadoFinal = window.confirm(
        `🔥 ÚLTIMA CONFIRMACIÓN\n\n` +
        `Eliminarás PERMANENTEMENTE "${titulo}"\n\n` +
        `Motivo: ${motivo}\n\n` +
        `Esta acción NO se puede deshacer.\n` +
        `¿Proceder?`
      )

      if (!confirmadoFinal) return

      try {
        await eliminarPermanenteMutation.mutateAsync({
          id,
          motivo: motivo.trim(),
          soloEstaVersion
        })
      } catch (error) {
        logger.error('❌ Error al eliminar permanentemente:', error)
      }
    },
    [eliminarPermanenteMutation]
  )

  return {
    // Data
    documentosEliminados,
    isLoading,
    error: error ? (error as Error).message : null,
    cantidadEliminados,

    // Actions
    handleRestaurar,
    handleEliminarPermanente,
    refetch,

    // States
    isRestaurando: restaurarMutation.isPending,
    isEliminandoPermanente: eliminarPermanenteMutation.isPending,
  }
}

/**
 * 🗑️ HOOK: useDocumentosPapelera V2
 *
 * Lógica de negocio para gestión de documentos eliminados (papelera)
 * - Listar documentos eliminados (raíz + versiones jerárquicas)
 * - Restaurar documentos (completos o versiones individuales)
 * - Eliminar permanentemente (completo o versiones específicas seleccionadas)
 */

import { useCallback, useMemo, useState } from 'react'

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { useAuth } from '@/contexts/auth-context'
import { logger } from '@/lib/utils/logger'
import { documentosViviendaService } from '@/modules/viviendas/services/documentos-vivienda.service'


interface UseDocumentosPapeleraParams {
  viviendaId: string
}

export interface DocumentoEliminadoJerarquico {
  id: string
  titulo: string
  version: number
  documento_padre_id: string | null
  metadata: any
  fecha_creacion: string
  versiones: DocumentoEliminadoJerarquico[] // Versiones hijas
  total_versiones: number // Total incluyendo hijas
}

export function useDocumentosPapeleraV2({ viviendaId }: UseDocumentosPapeleraParams) {
  const { user, perfil } = useAuth()
  const queryClient = useQueryClient()

  // Estado para versiones seleccionadas por documento
  const [versionesSeleccionadas, setVersionesSeleccionadas] = useState<Record<string, Set<string>>>({})

  // ✅ QUERY: Obtener documentos eliminados
  const {
    data: documentosEliminadosRaw = [],
    isLoading,
    error,
    refetch
  } = useQuery({
    queryKey: ['documentos-eliminados', viviendaId],
    queryFn: () => documentosViviendaService.obtenerDocumentosEliminados(viviendaId),
    enabled: perfil?.rol === 'Administrador', // Solo Admin puede ver
    staleTime: 1000 * 60 * 5, // 5 minutos
  })

  // ✅ COMPUTED: Organizar documentos en jerarquía (raíz + versiones)
  const documentosEliminados = useMemo(() => {
    const raices = documentosEliminadosRaw.filter(doc => !doc.documento_padre_id)

    return raices.map(raiz => {
      const versiones = documentosEliminadosRaw.filter(
        doc => doc.documento_padre_id === raiz.id
      ).sort((a, b) => a.version - b.version)

      return {
        ...raiz,
        versiones: versiones.map(v => ({ ...v, versiones: [], total_versiones: 1 })),
        total_versiones: 1 + versiones.length
      } as DocumentoEliminadoJerarquico
    })
  }, [documentosEliminadosRaw])

  // ✅ Handlers de selección
  const toggleVersionSeleccionada = useCallback((documentoRaizId: string, versionId: string) => {
    setVersionesSeleccionadas(prev => {
      const seleccionadas = new Set(prev[documentoRaizId] || [])

      if (seleccionadas.has(versionId)) {
        seleccionadas.delete(versionId)
      } else {
        seleccionadas.add(versionId)
      }

      return {
        ...prev,
        [documentoRaizId]: seleccionadas
      }
    })
  }, [])

  const toggleTodasVersiones = useCallback((documentoRaizId: string, documento: DocumentoEliminadoJerarquico) => {
    setVersionesSeleccionadas(prev => {
      const seleccionadas = new Set(prev[documentoRaizId] || [])
      const todasLasVersiones = [documento.id, ...documento.versiones.map(v => v.id)]

      // Si todas están seleccionadas, deseleccionar todo
      const todasSeleccionadas = todasLasVersiones.every(id => seleccionadas.has(id))

      if (todasSeleccionadas) {
        return {
          ...prev,
          [documentoRaizId]: new Set()
        }
      } else {
        // Seleccionar todas
        return {
          ...prev,
          [documentoRaizId]: new Set(todasLasVersiones)
        }
      }
    })
  }, [])

  const limpiarSeleccion = useCallback((documentoRaizId: string) => {
    setVersionesSeleccionadas(prev => {
      const nuevo = { ...prev }
      delete nuevo[documentoRaizId]
      return nuevo
    })
  }, [])

  // ✅ MUTATION: Restaurar documento
  const restaurarMutation = useMutation({
    mutationFn: async (id: string) => {
      if (!user || !perfil) {
        throw new Error('Debe iniciar sesión')
      }
      return documentosViviendaService.restaurarDocumento(id, user.id, perfil.rol)
    },
    onMutate: () => {
      toast.loading('Restaurando documento...', { id: 'restore-doc' })
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ['documentos-eliminados', viviendaId],
      })
      queryClient.invalidateQueries({
        queryKey: ['documentos-vivienda', viviendaId],
      })

      toast.success('Documento restaurado correctamente', {
        id: 'restore-doc',
      })
    },
    onError: (error: Error) => {
      toast.error(error.message || 'Error al restaurar', {
        id: 'restore-doc',
      })
    },
  })

  // ✅ MUTATION: Eliminar permanentemente (múltiples versiones)
  const eliminarPermanenteMutation = useMutation({
    mutationFn: async ({ ids, motivo }: { ids: string[]; motivo: string }) => {
      if (!user || !perfil) {
        throw new Error('Debe iniciar sesión')
      }

      // Eliminar cada ID individualmente
      const promesas = ids.map(id =>
        documentosViviendaService.eliminarPermanente(id, user.id, perfil.rol, motivo)
      )

      return Promise.all(promesas)
    },
    onMutate: () => {
      toast.loading('Eliminando permanentemente...', { id: 'delete-permanent' })
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ['documentos-eliminados', viviendaId],
      })

      toast.success('Documentos eliminados permanentemente', {
        id: 'delete-permanent',
      })
    },
    onError: (error: Error) => {
      toast.error(error.message || 'Error al eliminar permanentemente', {
        id: 'delete-permanent',
      })
    },
  })

  // ✅ Handler: Restaurar documento (completo o versión individual)
  const handleRestaurar = useCallback(
    async (id: string, titulo: string, esRaiz: boolean) => {
      const mensaje = esRaiz
        ? `¿Restaurar el documento "${titulo}" con todas sus versiones?\n\nTodo volverá a estar activo.`
        : `¿Restaurar solo esta versión de "${titulo}"?`

      const confirmado = window.confirm(mensaje)

      if (!confirmado) return

      try {
        await restaurarMutation.mutateAsync(id)
      } catch (error) {
        logger.error('❌ Error al restaurar documento:', error)
      }
    },
    [restaurarMutation]
  )

  // ✅ Handler: Eliminar permanentemente versiones seleccionadas
  const handleEliminarSeleccionadas = useCallback(
    async (documentoRaizId: string, titulo: string) => {
      const seleccionadas = versionesSeleccionadas[documentoRaizId]

      if (!seleccionadas || seleccionadas.size === 0) {
        toast.error('Selecciona al menos una versión para eliminar')
        return
      }

      const ids = Array.from(seleccionadas)
      const cantidad = ids.length

      // 1. Primera confirmación
      const textoConfirmacion = cantidad === 1
        ? `⚠️ ADVERTENCIA: Esta acción es IRREVERSIBLE\n\nVas a eliminar PERMANENTEMENTE 1 versión de:\n"${titulo}"`
        : `⚠️ ADVERTENCIA: Esta acción es IRREVERSIBLE\n\nVas a eliminar PERMANENTEMENTE ${cantidad} versiones de:\n"${titulo}"`

      const confirmado = window.confirm(
        `${textoConfirmacion}\n\n` +
        `Se eliminarán:\n` +
        `- ${cantidad} registro(s) de la base de datos\n` +
        `- ${cantidad} archivo(s) físicos de Storage\n\n` +
        `¿Estás ABSOLUTAMENTE seguro?`
      )

      if (!confirmado) return

      // 2. Solicitar motivo
      const motivo = window.prompt(
        `Proporciona el motivo de eliminación PERMANENTE (mínimo 20 caracteres):`
      )

      if (!motivo) return

      if (motivo.trim().length < 20) {
        toast.error('El motivo debe tener al menos 20 caracteres')
        return
      }

      // 3. Segunda confirmación (doble check)
      const confirmadoFinal = window.confirm(
        `🔥 ÚLTIMA CONFIRMACIÓN\n\n` +
        `Eliminarás PERMANENTEMENTE ${cantidad} versión(es) de "${titulo}"\n\n` +
        `Motivo: ${motivo}\n\n` +
        `Esta acción NO se puede deshacer.\n` +
        `¿Proceder?`
      )

      if (!confirmadoFinal) return

      try {
        await eliminarPermanenteMutation.mutateAsync({ ids, motivo: motivo.trim() })
        limpiarSeleccion(documentoRaizId)
      } catch (error) {
        logger.error('❌ Error al eliminar permanentemente:', error)
      }
    },
    [versionesSeleccionadas, eliminarPermanenteMutation, limpiarSeleccion]
  )

  return {
    // Data
    documentosEliminados,
    isLoading,
    error: error ? (error as Error).message : null,
    cantidadEliminados: documentosEliminados.length,

    // Selección
    versionesSeleccionadas,
    toggleVersionSeleccionada,
    toggleTodasVersiones,
    limpiarSeleccion,

    // Actions
    handleRestaurar,
    handleEliminarSeleccionadas,
    refetch,

    // States
    isRestaurando: restaurarMutation.isPending,
    isEliminandoPermanente: eliminarPermanenteMutation.isPending,
  }
}

/**
 * useNuevaVivienda - Hook con lógica del wizard de 5 pasos
 * ✅ Separación de responsabilidades ESTRICTA
 * ✅ Gestión de pasos
 * ✅ Validación por paso
 * ✅ Preview en tiempo real
 */

import { useCallback, useEffect, useMemo, useRef, useState } from 'react'

import { zodResolver } from '@hookform/resolvers/zod'
import { useForm } from 'react-hook-form'
import { z } from 'zod'

import { useRouter } from 'next/navigation'

import { logger } from '@/lib/utils/logger'

import { viviendasService } from '../services/viviendas.service'
import type { ResumenFinanciero, ViviendaFormData } from '../types'
import { calcularValorTotal } from '../utils'

// ==================== SCHEMAS POR PASO ====================

const paso1Schema = z.object({
  proyecto_id: z.string().min(1, 'Selecciona un proyecto'),
  manzana_id: z.string().min(1, 'Selecciona una manzana'),
  numero: z.string().min(1, 'El número de vivienda es obligatorio'),
})

const paso2Schema = z.object({
  lindero_norte: z
    .string()
    .min(5, 'Describe el lindero Norte (mínimo 5 caracteres)')
    .regex(
      /^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ.,\-()]+$/,
      'Solo se permiten letras, números, espacios, puntos, comas y guiones'
    ),
  lindero_sur: z
    .string()
    .min(5, 'Describe el lindero Sur (mínimo 5 caracteres)')
    .regex(
      /^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ.,\-()]+$/,
      'Solo se permiten letras, números, espacios, puntos, comas y guiones'
    ),
  lindero_oriente: z
    .string()
    .min(5, 'Describe el lindero Oriente (mínimo 5 caracteres)')
    .regex(
      /^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ.,\-()]+$/,
      'Solo se permiten letras, números, espacios, puntos, comas y guiones'
    ),
  lindero_occidente: z
    .string()
    .min(5, 'Describe el lindero Occidente (mínimo 5 caracteres)')
    .regex(
      /^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ.,\-()]+$/,
      'Solo se permiten letras, números, espacios, puntos, comas y guiones'
    ),
})

const paso3SchemaBase = z.object({
  matricula_inmobiliaria: z
    .string()
    .min(1, 'La matrícula inmobiliaria es obligatoria')
    .regex(
      /^[0-9\-]+$/,
      'Solo se permiten números y guiones (Ej: 050-123456)'
    ),
  nomenclatura: z
    .string()
    .min(5, 'Mínimo 5 caracteres')
    .regex(
      /^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ#.,\-()°]+$/,
      'Solo se permiten letras, números, #, -, espacios, puntos, comas, paréntesis y grado (°)'
    ),
  // ✅ SOLUCIÓN PROFESIONAL: String que se valida como número decimal
  area_lote: z
    .string()
    .min(1, 'El área del lote es obligatoria')
    .refine((val) => !isNaN(Number(val)) && Number(val) > 0, {
      message: 'Debe ser un número mayor a 0'
    })
    .transform((val) => Number(val)), // Convierte a número al final
  area_construida: z
    .string()
    .min(1, 'El área construida es obligatoria')
    .refine((val) => !isNaN(Number(val)) && Number(val) > 0, {
      message: 'Debe ser un número mayor a 0'
    })
    .transform((val) => Number(val)), // Convierte a número al final
  tipo_vivienda: z.enum(['Regular', 'Irregular']),
  certificado_tradicion_file: z.instanceof(File).optional(),
}).refine(
  (data) => {
    // ✅ Validación cruzada: área construida no puede ser mayor al área del lote
    const areaLote = Number(data.area_lote)
    const areaConstruida = Number(data.area_construida)
    return areaConstruida <= areaLote
  },
  {
    message: 'El área construida no puede ser mayor al área del lote',
    path: ['area_construida'], // Mostrar error en el campo area_construida
  }
)

const paso4Schema = z.object({
  // ✅ SOLUCIÓN PROFESIONAL: Acepta string O number, transforma a number
  valor_base: z.union([
    z.string().min(1, 'El valor base es obligatorio'),
    z.number()
  ]).pipe(
    z.coerce.number().min(1, 'El valor base debe ser mayor a 0') as any
  ),
  es_esquinera: z.boolean(),
  recargo_esquinera: z.union([
    z.string(),
    z.number()
  ]).pipe(
    z.coerce.number().min(0, 'El recargo debe ser mayor o igual a 0') as any
  ).optional().default(0),
})

// ✅ Schema factory: permite validación async de matrícula duplicada
const createPaso3Schema = (viviendaId?: string) => {
  return paso3SchemaBase
    .superRefine(async (data, ctx) => {
      // ✅ Validación async: Verificar matrícula duplicada
      if (data.matricula_inmobiliaria && data.matricula_inmobiliaria.length >= 7) {
        try {
          const resultado = await viviendasService.verificarMatriculaUnica(
            data.matricula_inmobiliaria,
            viviendaId
          )

          if (!resultado.esUnica && resultado.viviendaDuplicada) {
            ctx.addIssue({
              code: z.ZodIssueCode.custom,
              message: `Esta matrícula ya está registrada en la Mz. ${resultado.viviendaDuplicada.manzana} Casa #${resultado.viviendaDuplicada.numero}`,
              path: ['matricula_inmobiliaria'],
            })
          }
        } catch (_error) {
          // No bloqueamos el submit si falla la validación async
        }
      }
    })
}

// Schema base sin validación async (para uso general)
const paso3Schema = paso3SchemaBase

// Schema completo base (sin validación async)
const viviendaSchemaBase = paso1Schema
  .merge(paso2Schema)
  .merge(paso3Schema)
  .merge(paso4Schema)

// ✅ Schema factory completo con validación async
const createViviendaSchema = (viviendaId?: string) => {
  return paso1Schema
    .merge(paso2Schema)
    .merge(createPaso3Schema(viviendaId))
    .merge(paso4Schema)
}

// Schema para tipo (sin validación async)
const viviendaSchema = viviendaSchemaBase

type ViviendaFormSchema = z.infer<typeof viviendaSchema>

// ==================== CONFIGURACIÓN DE PASOS ====================

// ✅ Factory para configuración de pasos (permite inyectar viviendaId)
const createPasosConfig = (viviendaId?: string) => [
  {
    id: 1,
    titulo: 'Ubicación',
    descripcion: 'Selecciona proyecto, manzana y vivienda',
    icon: 'MapPin',
    schema: paso1Schema,
  },
  {
    id: 2,
    titulo: 'Linderos',
    descripcion: 'Define los límites de la vivienda',
    icon: 'Compass',
    schema: paso2Schema,
  },
  {
    id: 3,
    titulo: 'Información Legal',
    descripcion: 'Datos catastrales y documentos',
    icon: 'FileText',
    schema: createPaso3Schema(viviendaId), // ← Schema con validación async
  },
  {
    id: 4,
    titulo: 'Información Financiera',
    descripcion: 'Valor base y recargos',
    icon: 'DollarSign',
    schema: paso4Schema,
  },
  {
    id: 5,
    titulo: 'Resumen',
    descripcion: 'Revisa la información antes de guardar',
    icon: 'CheckCircle',
    schema: z.object({}), // Sin validación, solo preview
  },
]

// ==================== HOOK ====================

interface UseNuevaViviendaParams {
  onSubmit: (data: ViviendaFormData) => Promise<void>
  viviendaId?: string // ← Para modo edición (futuro)
}

export function useNuevaVivienda({ onSubmit, viviendaId }: UseNuevaViviendaParams) {
  const router = useRouter()
  const [pasoActual, setPasoActual] = useState(1)
  const [submitting, setSubmitting] = useState(false)
  const [gastosNotariales, setGastosNotariales] = useState(5_000_000) // Default: 5M
  const [configuracionRecargos, setConfiguracionRecargos] = useState<any[]>([])

  // ✅ Crear configuración de pasos con validación async
  const PASOS_CONFIG = useMemo(() => createPasosConfig(viviendaId), [viviendaId])

  // ✅ Crear schema con validación async de matrícula
  const schemaConValidacionAsync = useMemo(
    () => createViviendaSchema(viviendaId),
    [viviendaId]
  )

  // 🔒 GUARDIA CRÍTICA: Ref para trackear si el usuario hizo click explícito en "Guardar"
  const submitAutorizadoRef = useRef(false)

  // 🔍 LOGGER: Detectar cambios en pasoActual
  useEffect(() => {

    // 🔒 RESET: Al cambiar de paso, resetear autorización de submit
    submitAutorizadoRef.current = false
  }, [pasoActual])

  // Cargar gastos notariales y configuración de recargos desde DB
  useEffect(() => {
    async function cargarConfiguracion() {
      try {
        const [gastos, recargos] = await Promise.all([
          viviendasService.obtenerGastosNotariales(),
          viviendasService.obtenerConfiguracionRecargos(),
        ])


        setGastosNotariales(gastos)
        setConfiguracionRecargos(recargos)
      } catch (_error) {
      }
    }
    cargarConfiguracion()
  }, [])

  // React Hook Form con schema BASE (sin validación async)
  // ✅ La validación async se ejecutará solo en handleSiguientePaso paso 3
  const {
    register,
    handleSubmit,
    watch,
    setValue,
    trigger,
    setError,
    getValues,
    formState: { errors, isValidating },
  } = useForm<ViviendaFormSchema>({
    resolver: zodResolver(viviendaSchema) as any, // ← Schema base sin validación async
    mode: 'onChange',
    defaultValues: {
      proyecto_id: '',
      manzana_id: '',
      numero: '',
      lindero_norte: '',
      lindero_sur: '',
      lindero_oriente: '',
      lindero_occidente: '',
      matricula_inmobiliaria: '',
      nomenclatura: '',
      area_lote: '' as any,
      area_construida: '' as any,
      tipo_vivienda: 'Regular' as const,
      valor_base: 0,
      es_esquinera: false,
      recargo_esquinera: 0,
    },
  })

  // Watch de todos los campos para preview
  const formData = watch()

  // ==================== CÁLCULOS FINANCIEROS ====================

  // Calcular resumen financiero en tiempo real
  const resumenFinanciero = useMemo((): ResumenFinanciero => {
    const valorBase = formData.valor_base || 0
    const recargoEsquinera = formData.es_esquinera ? (formData.recargo_esquinera || 0) : 0
    const valorTotal = calcularValorTotal(valorBase, gastosNotariales, recargoEsquinera)

    return {
      valor_base: valorBase,
      gastos_notariales: gastosNotariales,
      recargo_esquinera: recargoEsquinera,
      valor_total: valorTotal,
    }
  }, [formData.valor_base, formData.es_esquinera, formData.recargo_esquinera, gastosNotariales])

  // ==================== CÁLCULOS ====================

  const pasoActualConfig = useMemo(() => {
    return PASOS_CONFIG.find(p => p.id === pasoActual) || PASOS_CONFIG[0]
  }, [pasoActual])

  const totalPasos = PASOS_CONFIG.length

  const progreso = useMemo(() => {
    return Math.round((pasoActual / totalPasos) * 100)
  }, [pasoActual, totalPasos])

  const esPrimerPaso = pasoActual === 1
  const esUltimoPaso = pasoActual === totalPasos

  // ==================== VALIDACIÓN POR PASO ====================

  const validarPasoActual = useCallback(async (): Promise<boolean> => {

    // 🔍 DEBUGGING: Ver valores actuales del formulario
    const valoresActuales = watch()

    const config = PASOS_CONFIG.find(p => p.id === pasoActual)
    if (!config || pasoActual === 5) {
      return true
    }

    try {
      // ✅ PASO 3: Validación sync + async manual de matrícula
      if (pasoActual === 3) {
        const camposDelPaso = Object.keys(config.schema.shape)

        // 1. Validar campos normales (sync)
        const esValidoSync = await trigger(camposDelPaso as any)

        // 🔍 DEBUG: Ver errores de validación
        if (!esValidoSync) {
          logger.error('❌ [PASO 3] Campos con error:', JSON.stringify(errors, null, 2))
          return false
        }

        // ✅ ACUMULAR ERRORES: Validar TODO antes de setear errores
        const erroresEncontrados: Array<{ campo: string; mensaje: string }> = []

        // 2. ✅ Validación cruzada: área construida <= área lote
        const areaLote = Number(getValues('area_lote'))
        const areaConstruida = Number(getValues('area_construida'))

        if (areaConstruida > areaLote) {
          erroresEncontrados.push({
            campo: 'area_construida',
            mensaje: 'El área construida no puede ser mayor al área del lote',
          })
        }

        // 3. Validar matrícula duplicada (async manual)
        const matricula = getValues('matricula_inmobiliaria')

        if (matricula && matricula.length >= 7) {
          try {
            const resultado = await viviendasService.verificarMatriculaUnica(
              matricula,
              viviendaId
            )

            if (!resultado.esUnica && resultado.viviendaDuplicada) {
              erroresEncontrados.push({
                campo: 'matricula_inmobiliaria',
                mensaje: `Esta matrícula ya está registrada en la Mz. ${resultado.viviendaDuplicada.manzana} Casa #${resultado.viviendaDuplicada.numero}`,
              })
            }
          } catch (error) {
            logger.error('❌ [PASO 3] Error al verificar matrícula:', error)
            // Continuamos si falla la verificación de red
          }
        }

        // ✅ Setear TODOS los errores a la vez
        if (erroresEncontrados.length > 0) {
          erroresEncontrados.forEach((error) => {
            setError(error.campo as any, {
              type: 'manual',
              message: error.mensaje,
            })
          })
          return false
        }

        return true
      }

      // Para otros pasos, validación normal
      const camposDelPaso = Object.keys(config.schema.shape)
      const esValido = await trigger(camposDelPaso as any)

      if (!esValido) {
        return false
      }
      return true
    } catch (_error) {
      return false
    }
  }, [pasoActual, trigger, watch, setError, errors, PASOS_CONFIG])

  // Validar todos los pasos anteriores a un paso específico
  const validarPasosAnteriores = useCallback(async (hastaElPaso: number): Promise<boolean> => {
    for (let i = 1; i < hastaElPaso; i++) {
      const config = PASOS_CONFIG.find(p => p.id === i)
      if (!config || i === 5) continue // Paso 5 no requiere validación

      try {
        const camposDelPaso = Object.keys(config.schema.shape)
        const esValido = await trigger(camposDelPaso as any)

        if (!esValido) {
          return false
        }
      } catch (_error) {
        return false
      }
    }
    return true
  }, [trigger, PASOS_CONFIG])

  // ==================== NAVEGACIÓN ====================

  const irSiguiente = useCallback(async () => {

        const esValido = await validarPasoActual()

    if (!esValido) {
                  return
    }

    if (pasoActual < totalPasos) {
      const siguientePaso = pasoActual + 1

      setPasoActual(prev => {
        return prev + 1
      })

            window.scrollTo({ top: 0, behavior: 'smooth' })

    } else {
    }

      }, [pasoActual, totalPasos, validarPasoActual])

  const irAtras = useCallback(() => {
    if (pasoActual > 1) {
      setPasoActual(prev => prev - 1)
      window.scrollTo({ top: 0, behavior: 'smooth' })
    }
  }, [pasoActual])

  const irAPaso = useCallback(async (paso: number) => {
    // Solo permitir ir a pasos anteriores o al actual
    // Para ir a pasos posteriores, se deben validar todos los anteriores
    if (paso < pasoActual) {
      // Permitir retroceder sin validación
      setPasoActual(paso)
      window.scrollTo({ top: 0, behavior: 'smooth' })
      return
    }

    if (paso === pasoActual) {
      // Ya estamos en este paso, no hacer nada
      return
    }

    // Intentar ir a un paso posterior - validar todos los anteriores
    const pasosAnterioresValidos = await validarPasosAnteriores(paso)

    if (!pasosAnterioresValidos) {
      return
    }

    if (paso >= 1 && paso <= totalPasos) {
      setPasoActual(paso)
      window.scrollTo({ top: 0, behavior: 'smooth' })
    }
  }, [pasoActual, totalPasos, validarPasosAnteriores])

  const cancelar = useCallback(() => {
    router.back()
  }, [router])

  // ==================== SUBMIT ====================

  const onSubmitForm = async (data: ViviendaFormSchema) => {
        console.trace('SUBMIT FORM TRACE')

    // 🔒 GUARDIA CRÍTICA #1: Verificar que el usuario autorizó el submit
    if (!submitAutorizadoRef.current) {
                                    return // ← BLOQUEAR COMPLETAMENTE
    }

    // �🚨 GUARDIA CRÍTICA #2: PREVENIR SUBMIT HASTA ESTAR EN PASO 5 (RESUMEN)
    if (pasoActual < 5) {

      // Resetear autorización y avanzar
      submitAutorizadoRef.current = false
      await irSiguiente()
      return
    }

    // Resetear autorización después de usar
    submitAutorizadoRef.current = false

    try {
      setSubmitting(true)

      // Transformar datos al formato esperado
      const viviendaData = {
        ...data,
      } as unknown as ViviendaFormData

      await onSubmit(viviendaData)

      // ✅ SOLUCIÓN PROFESIONAL: Navegar inmediatamente
      // React Query ya garantizó que el refetch se completó en el onSuccess
      router.push('/viviendas')
    } catch (error) {
      logger.error('❌ Error en handleFormSubmit:', error)

      // Si es error de matrícula duplicada, mostrar en el campo correspondiente
      if (error instanceof Error && error.message.includes('matrícula inmobiliaria')) {
        setError('matricula_inmobiliaria', {
          type: 'manual',
          message: error.message
        })
        // Volver al paso 3 donde está el campo de matrícula
        setPasoActual(3)
      }
      // El toast de error ya se muestra en nueva-vivienda-view.tsx
    } finally {
      setSubmitting(false)
    }
  }

  // ==================== PREVIEW ====================

  const previewData = useMemo(() => {
    return {
      // Paso 1
      proyecto: formData.proyecto_id || null,
      manzana: formData.manzana_id || null,
      numero: formData.numero || null,

      // Paso 2
      linderos: {
        norte: formData.lindero_norte || null,
        sur: formData.lindero_sur || null,
        oriente: formData.lindero_oriente || null,
        occidente: formData.lindero_occidente || null,
      },

      // Paso 3
      legal: {
        matricula: formData.matricula_inmobiliaria || null,
        nomenclatura: formData.nomenclatura || null,
        areaLote: formData.area_lote || 0,
        areaConstruida: formData.area_construida || 0,
        tipoVivienda: formData.tipo_vivienda || 'Regular',
      },

      // Paso 4
      financiero: {
        valorBase: formData.valor_base || 0,
        esEsquinera: formData.es_esquinera || false,
        recargoEsquinera: formData.recargo_esquinera || 0,
      },
    }
  }, [formData])

  // 🔒 Función para autorizar submit desde botón "Guardar Vivienda"
  const autorizarSubmit = useCallback(() => {
        submitAutorizadoRef.current = true
          }, [pasoActual])

  return {
    // Form state
    register,
    handleSubmit: handleSubmit(onSubmitForm as any),
    errors,
    isValidating, // ← Exponer estado de validación async
    setValue,
    watch,

    // Paso actual
    pasoActual,
    pasoActualConfig,
    totalPasos,
    progreso,
    esPrimerPaso,
    esUltimoPaso,

    // Navegación
    irSiguiente,
    irAtras,
    irAPaso,
    cancelar,

    // Submit
    submitting,
    autorizarSubmit, // ← NUEVA función para autorizar submit

    // Preview
    previewData,
    formData,

    // Finanzas
    gastosNotariales,
    resumenFinanciero,
    configuracionRecargos,

    // Config
    pasos: PASOS_CONFIG,
  }
}

/**
 * useNuevaViviendaAccordion — Hook que orquesta la creación de vivienda
 * con el patrón Accordion Wizard (5 pasos).
 *
 * ✅ Separación de responsabilidades
 * ✅ Validación por paso (sync + async)
 * ✅ Cálculos financieros en tiempo real
 * ✅ Estado de sección (completed/active/pending)
 */

import { useCallback, useEffect, useMemo, useState } from 'react'

import { zodResolver } from '@hookform/resolvers/zod'
import { ClipboardCheck, DollarSign, MapPin, Ruler, Scale } from 'lucide-react'
import { useForm } from 'react-hook-form'
import { toast } from 'sonner'
import { z } from 'zod'

import { useRouter } from 'next/navigation'

import type { SectionStatus, SummaryItem, WizardStepConfig } from '@/shared/components/accordion-wizard'

import { viviendasService } from '../services/viviendas.service'
import type { ResumenFinanciero, ViviendaFormData } from '../types'
import { calcularValorTotal } from '../utils'

import { useCrearViviendaMutation } from './useViviendasQuery'

// ── Configuración de pasos ───────────────────────────────────────
export const PASOS_VIVIENDA: WizardStepConfig[] = [
  { id: 1, title: 'Ubicación', description: 'Selecciona el proyecto, manzana y número de la vivienda a registrar.', icon: MapPin },
  { id: 2, title: 'Linderos', description: 'Define los límites físicos (norte, sur, este, oeste) de la vivienda.', icon: Ruler },
  { id: 3, title: 'Información Legal', description: 'Datos catastrales: matrícula inmobiliaria, nomenclatura y áreas.', icon: Scale },
  { id: 4, title: 'Información Financiera', description: 'Valor base de la vivienda y recargos aplicables (esquinera, etc.).', icon: DollarSign },
  { id: 5, title: 'Resumen', description: 'Revisa toda la información antes de confirmar la creación.', icon: ClipboardCheck },
]

// ── Schema para el formulario (sin cross-field .refine) ──
const viviendaFormSchema = z.object({
  // Paso 1
  proyecto_id: z.string().min(1, 'Selecciona un proyecto'),
  manzana_id: z.string().min(1, 'Selecciona una manzana'),
  numero: z.string().min(1, 'El número de vivienda es obligatorio'),
  // Paso 2
  lindero_norte: z
    .string()
    .min(5, 'Mínimo 5 caracteres')
    .regex(/^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ.,\-()]+$/, 'Solo letras, números, puntos, comas y guiones'),
  lindero_sur: z
    .string()
    .min(5, 'Mínimo 5 caracteres')
    .regex(/^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ.,\-()]+$/, 'Solo letras, números, puntos, comas y guiones'),
  lindero_oriente: z
    .string()
    .min(5, 'Mínimo 5 caracteres')
    .regex(/^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ.,\-()]+$/, 'Solo letras, números, puntos, comas y guiones'),
  lindero_occidente: z
    .string()
    .min(5, 'Mínimo 5 caracteres')
    .regex(/^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ.,\-()]+$/, 'Solo letras, números, puntos, comas y guiones'),
  // Paso 3
  matricula_inmobiliaria: z
    .string()
    .min(1, 'La matrícula inmobiliaria es obligatoria')
    .regex(/^[0-9\-]+$/, 'Solo números y guiones (Ej: 050-123456)'),
  nomenclatura: z
    .string()
    .min(5, 'Mínimo 5 caracteres')
    .regex(/^[a-zA-Z0-9\sáéíóúÁÉÍÓÚñÑ#.,\-()°]+$/, 'Solo letras, números, #, -, puntos, comas'),
  area_lote: z
    .string()
    .min(1, 'El área del lote es obligatoria')
    .regex(/^\d+(\.\d{0,3})?$/, 'Solo números y hasta 3 decimales (Ej: 66.125)')
    .refine((val) => !isNaN(Number(val)) && Number(val) > 0, 'Debe ser un número mayor a 0'),
  area_construida: z
    .string()
    .min(1, 'El área construida es obligatoria')
    .regex(/^\d+(\.\d{0,3})?$/, 'Solo números y hasta 3 decimales (Ej: 80.500)')
    .refine((val) => !isNaN(Number(val)) && Number(val) > 0, 'Debe ser un número mayor a 0'),
  tipo_vivienda: z.enum(['Regular', 'Irregular']),
  // Paso 4
  valor_base: z.coerce.number().min(1, 'El valor base es obligatorio'),
  es_esquinera: z.boolean().default(false),
  recargo_esquinera: z.coerce.number().min(0).default(0),
})

type ViviendaFormValues = z.input<typeof viviendaFormSchema>

// Campos por paso (para trigger de validación parcial)
const FIELDS_PASO_1 = ['proyecto_id', 'manzana_id', 'numero'] as const
const FIELDS_PASO_2 = ['lindero_norte', 'lindero_sur', 'lindero_oriente', 'lindero_occidente'] as const
const FIELDS_PASO_3 = ['matricula_inmobiliaria', 'nomenclatura', 'area_lote', 'area_construida', 'tipo_vivienda'] as const
const FIELDS_PASO_4 = ['valor_base', 'es_esquinera', 'recargo_esquinera'] as const

export function useNuevaViviendaAccordion() {
  const router = useRouter()
  const crearMutation = useCrearViviendaMutation({ showToast: false })

  const [pasoActual, setPasoActual] = useState(1)
  const [pasosCompletados, setPasosCompletados] = useState<Set<number>>(new Set())
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [isValidating, setIsValidating] = useState(false)
  const [showSuccess, setShowSuccess] = useState(false)
  const [gastosNotariales, setGastosNotariales] = useState(5_000_000)
  const [configuracionRecargos, setConfiguracionRecargos] = useState<any[]>([])

  // ── Cargar configuración financiera ─────────────────
  useEffect(() => {
    async function cargar() {
      try {
        const [gastos, recargos] = await Promise.all([
          viviendasService.obtenerGastosNotariales(),
          viviendasService.obtenerConfiguracionRecargos(),
        ])
        setGastosNotariales(gastos)
        setConfiguracionRecargos(recargos)
      } catch {
        // Usar defaults
      }
    }
    cargar()
  }, [])

  // ── Formulario ──────────────────────────────────────
  const {
    register,
    watch,
    setValue,
    trigger,
    setError,
    getValues,
    formState: { errors },
  } = useForm<ViviendaFormValues>({
    resolver: zodResolver(viviendaFormSchema) as any,
    mode: 'onChange',
    defaultValues: {
      proyecto_id: '',
      manzana_id: '',
      numero: '',
      lindero_norte: '',
      lindero_sur: '',
      lindero_oriente: '',
      lindero_occidente: '',
      matricula_inmobiliaria: '',
      nomenclatura: '',
      area_lote: '' as any,
      area_construida: '' as any,
      tipo_vivienda: 'Regular',
      valor_base: 0,
      es_esquinera: false,
      recargo_esquinera: 0,
    },
  })

  const formData = watch()

  // ── Cálculos financieros ────────────────────────────
  const resumenFinanciero = useMemo((): ResumenFinanciero => {
    const valorBase = Number(formData.valor_base) || 0
    const recargoEsquinera = formData.es_esquinera ? (Number(formData.recargo_esquinera) || 0) : 0
    const valorTotal = calcularValorTotal(valorBase, gastosNotariales, recargoEsquinera)
    return {
      valor_base: valorBase,
      gastos_notariales: gastosNotariales,
      recargo_esquinera: recargoEsquinera,
      valor_total: valorTotal,
    }
  }, [formData.valor_base, formData.es_esquinera, formData.recargo_esquinera, gastosNotariales])

  // ── Estado de cada sección ──────────────────────────
  const getEstadoPaso = useCallback((paso: number): SectionStatus => {
    if (pasosCompletados.has(paso)) return 'completed'
    if (paso === pasoActual) return 'active'
    return 'pending'
  }, [pasoActual, pasosCompletados])

  // ── Resumen de cada sección completada ──────────────
  const summaryPaso1: SummaryItem[] = useMemo(() => [
    { label: 'Proyecto', value: formData.proyecto_id ? 'Seleccionado' : undefined },
    { label: 'Manzana', value: formData.manzana_id ? 'Seleccionada' : undefined },
    { label: 'Número', value: formData.numero || undefined },
  ], [formData.proyecto_id, formData.manzana_id, formData.numero])

  const summaryPaso2: SummaryItem[] = useMemo(() => {
    const definidos = [formData.lindero_norte, formData.lindero_sur, formData.lindero_oriente, formData.lindero_occidente]
      .filter(Boolean).length
    return [{ label: 'Linderos', value: definidos > 0 ? `${definidos} de 4 definidos` : undefined }]
  }, [formData.lindero_norte, formData.lindero_sur, formData.lindero_oriente, formData.lindero_occidente])

  const summaryPaso3: SummaryItem[] = useMemo(() => [
    { label: 'Matrícula', value: formData.matricula_inmobiliaria || undefined },
    { label: 'Área', value: formData.area_lote ? `${formData.area_lote} m²` : undefined },
  ], [formData.matricula_inmobiliaria, formData.area_lote])

  const summaryPaso4: SummaryItem[] = useMemo(() => {
    const val = resumenFinanciero.valor_total
    return [
      {
        label: 'Valor Total',
        value: val > 0
          ? `$${val.toLocaleString('es-CO')}`
          : undefined,
      },
    ]
  }, [resumenFinanciero.valor_total])

  // ── Progreso global ─────────────────────────────────
  const progress = useMemo(() => {
    return Math.round((pasosCompletados.size / PASOS_VIVIENDA.length) * 100)
  }, [pasosCompletados.size])

  // ── Validación por paso ─────────────────────────────
  const validarPasoActual = useCallback(async (): Promise<boolean> => {
    setIsValidating(true)
    try {
      switch (pasoActual) {
        case 1:
          return await trigger([...FIELDS_PASO_1])
        case 2:
          return await trigger([...FIELDS_PASO_2])
        case 3: {
          // 1. Validar campos sync
          const syncValid = await trigger([...FIELDS_PASO_3])
          if (!syncValid) return false

          const erroresEncontrados: Array<{ campo: string; mensaje: string }> = []

          // 2. Cross-field: área construida <= área lote
          const areaLote = Number(getValues('area_lote'))
          const areaConstruida = Number(getValues('area_construida'))
          if (areaConstruida > areaLote) {
            erroresEncontrados.push({
              campo: 'area_construida',
              mensaje: 'El área construida no puede ser mayor al área del lote',
            })
          }

          // 3. Async: matrícula duplicada
          const matricula = getValues('matricula_inmobiliaria')
          if (matricula && matricula.length >= 7) {
            try {
              const resultado = await viviendasService.verificarMatriculaUnica(matricula)
              if (!resultado.esUnica && resultado.viviendaDuplicada) {
                erroresEncontrados.push({
                  campo: 'matricula_inmobiliaria',
                  mensaje: `Matrícula ya registrada en Mz. ${resultado.viviendaDuplicada.manzana} Casa #${resultado.viviendaDuplicada.numero}`,
                })
              }
            } catch {
              // No bloquear si falla la red
            }
          }

          if (erroresEncontrados.length > 0) {
            erroresEncontrados.forEach((e) => {
              setError(e.campo as any, { type: 'manual', message: e.mensaje })
            })
            return false
          }
          return true
        }
        case 4:
          return await trigger([...FIELDS_PASO_4])
        case 5:
          return true // Resumen, sin validación
        default:
          return true
      }
    } finally {
      setIsValidating(false)
    }
  }, [pasoActual, trigger, getValues, setError])

  // ── Navegación ──────────────────────────────────────
  const irSiguiente = useCallback(async () => {
    const valido = await validarPasoActual()
    if (!valido) return
    setPasosCompletados((prev) => new Set(prev).add(pasoActual))
    setPasoActual((prev) => Math.min(prev + 1, PASOS_VIVIENDA.length))
  }, [pasoActual, validarPasoActual])

  const irAtras = useCallback(() => {
    setPasoActual((prev) => Math.max(prev - 1, 1))
  }, [])

  const irAPaso = useCallback((paso: number) => {
    if (pasosCompletados.has(paso)) {
      setPasosCompletados((prev) => {
        const next = new Set(prev)
        for (let i = paso; i <= PASOS_VIVIENDA.length; i++) next.delete(i)
        return next
      })
      setPasoActual(paso)
    }
  }, [pasosCompletados])

  // ── Submit final ────────────────────────────────────
  const handleSubmitFinal = useCallback(async () => {
    const valido = await validarPasoActual()
    if (!valido) return

    setPasosCompletados((prev) => new Set(prev).add(pasoActual))
    setIsSubmitting(true)
    try {
      const values = getValues()
      // Transformar áreas de string a number para el service
      const data = {
        ...values,
        area_lote: Number(values.area_lote),
        area_construida: Number(values.area_construida),
        valor_base: Number(values.valor_base),
        recargo_esquinera: Number(values.recargo_esquinera) || 0,
      } as unknown as ViviendaFormData

      await crearMutation.mutateAsync(data)
      toast.success('¡Vivienda creada exitosamente!')
      setShowSuccess(true)
      setTimeout(() => router.push('/viviendas'), 1800)
    } catch (error) {
      const msg = error instanceof Error ? error.message : 'Error al crear vivienda'
      toast.error(msg)
      // Si es error de matrícula, volver al paso 3
      if (error instanceof Error && error.message.includes('matrícula')) {
        setError('matricula_inmobiliaria', { type: 'manual', message: error.message })
        setPasoActual(3)
        setPasosCompletados((prev) => {
          const next = new Set(prev)
          for (let i = 3; i <= PASOS_VIVIENDA.length; i++) next.delete(i)
          return next
        })
      }
    } finally {
      setIsSubmitting(false)
    }
  }, [pasoActual, validarPasoActual, getValues, crearMutation, router, setError])

  // ── Preview para paso 5 (resumen) ──────────────────
  const previewData = useMemo(() => ({
    proyecto: formData.proyecto_id || null,
    manzana: formData.manzana_id || null,
    numero: formData.numero || null,
    linderos: {
      norte: formData.lindero_norte || null,
      sur: formData.lindero_sur || null,
      oriente: formData.lindero_oriente || null,
      occidente: formData.lindero_occidente || null,
    },
    legal: {
      matricula: formData.matricula_inmobiliaria || null,
      nomenclatura: formData.nomenclatura || null,
      areaLote: Number(formData.area_lote) || 0,
      areaConstruida: Number(formData.area_construida) || 0,
      tipoVivienda: formData.tipo_vivienda || 'Regular',
    },
    financiero: {
      valorBase: Number(formData.valor_base) || 0,
      esEsquinera: formData.es_esquinera || false,
      recargoEsquinera: Number(formData.recargo_esquinera) || 0,
    },
  }), [formData])

  return {
    // Pasos
    pasos: PASOS_VIVIENDA,
    pasoActual,
    getEstadoPaso,
    progress,

    // Navegación
    irSiguiente,
    irAtras,
    irAPaso,

    // Resúmenes
    summaryPaso1,
    summaryPaso2,
    summaryPaso3,
    summaryPaso4,

    // Form (para componentes paso existentes)
    register,
    errors,
    setValue,
    watch,
    formData,
    previewData,

    // Finanzas
    resumenFinanciero,
    gastosNotariales,
    configuracionRecargos,

    // Submit
    handleSubmit: handleSubmitFinal,
    isSubmitting,
    isValidating,
    showSuccess,
  }
}

/**
 * usePasoLegal - Hook para lógica del Paso 3 (Información Legal)
 * ✅ Separación de responsabilidades
 * ✅ Manejo de archivo centralizado
 */

import { useRef, useState } from 'react'

import type { UseFormSetValue } from 'react-hook-form'

export function usePasoLegal({ setValue }: { setValue: UseFormSetValue<any> }) {
  const [certificadoFile, setCertificadoFile] = useState<File | null>(null)
  const [fileError, setFileError] = useState<string>('')
  const fileInputRef = useRef<HTMLInputElement>(null)

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    // Validar tipo
    if (file.type !== 'application/pdf') {
      setFileError('Solo se permiten archivos PDF')
      return
    }

    // Validar tamaño (10MB)
    if (file.size > 10 * 1024 * 1024) {
      setFileError('El archivo no debe superar los 10MB')
      return
    }

    setFileError('')
    setCertificadoFile(file)
    setValue('certificado_tradicion_file', file)
  }

  const removeFile = () => {
    setCertificadoFile(null)
    setValue('certificado_tradicion_file', undefined)
    if (fileInputRef.current) {
      fileInputRef.current.value = ''
    }
    setFileError('')
  }

  return {
    certificadoFile,
    fileError,
    fileInputRef,
    handleFileChange,
    removeFile,
  }
}

/**
 * usePasoUbicacion - Hook para lógica del Paso 1 (Ubicación)
 * ✅ Separación de responsabilidades
 * ✅ React Query para carga de datos
 * ✅ Sin lógica en el componente
 */

import { useEffect, useMemo, useRef } from 'react'

import { useQuery } from '@tanstack/react-query'
import type { UseFormSetValue, UseFormWatch } from 'react-hook-form'

import { proyectosService } from '@/modules/proyectos/services/proyectos.service'

import { viviendasService } from '../services/viviendas.service'

interface UsePasoUbicacionProps {
  setValue: UseFormSetValue<any>
  watch: UseFormWatch<any>
  enabled?: boolean // ← Nuevo: permitir desactivar queries
}

export function usePasoUbicacion({ setValue, watch, enabled = true }: UsePasoUbicacionProps) {
  const proyectoSeleccionado = watch('proyecto_id')
  const manzanaSeleccionada = watch('manzana_id')

  // ✅ React Query: Cargar proyectos (no depende de nada, pero respeta enabled)
  const {
    data: proyectos = [],
    isLoading: cargandoProyectos,
    error: errorProyectos,
  } = useQuery({
    queryKey: ['proyectos'],
    queryFn: () => proyectosService.obtenerProyectos(),
    enabled, // ← Respetar flag enabled
    staleTime: 5 * 60 * 1000, // 5 minutos
  })

  // ✅ React Query: Cargar manzanas (solo si hay proyecto seleccionado Y enabled)
  const {
    data: manzanas = [],
    isLoading: cargandoManzanas,
    error: errorManzanas,
  } = useQuery({
    queryKey: ['manzanas', proyectoSeleccionado],
    queryFn: () => viviendasService.obtenerManzanasDisponibles(proyectoSeleccionado!),
    enabled: enabled && !!proyectoSeleccionado, // ← Solo ejecuta si enabled Y hay proyecto
    staleTime: 2 * 60 * 1000, // 2 minutos
  })

  // ✅ React Query: Cargar viviendas de la manzana (para calcular números disponibles)
  const {
    data: viviendasManzana = [],
    isLoading: cargandoNumeros,
  } = useQuery({
    queryKey: ['viviendas-manzana', manzanaSeleccionada],
    queryFn: () => viviendasService.obtenerPorManzana(manzanaSeleccionada!),
    enabled: enabled && !!manzanaSeleccionada, // ← Solo ejecuta si enabled Y hay manzana
    staleTime: 1 * 60 * 1000, // 1 minuto
  })

  // ✅ Calcular números disponibles (useMemo para optimización)
  const numerosDisponibles = useMemo(() => {
    if (!manzanaSeleccionada || !manzanas.length) return []

    const manzanaInfo = manzanas.find(m => m.id === manzanaSeleccionada)
    if (!manzanaInfo) return []

    const numerosUsados = viviendasManzana.map(v => parseInt(v.numero))
    const todosNumeros = Array.from({ length: manzanaInfo.total_viviendas }, (_, i) => i + 1)

    return todosNumeros.filter(num => !numerosUsados.includes(num))
  }, [manzanaSeleccionada, manzanas, viviendasManzana])

  // ✅ Refs para rastrear cambios del USUARIO (no limpiar al re-montar con valor existente)
  const prevProyecto = useRef(proyectoSeleccionado)
  const prevManzana = useRef(manzanaSeleccionada)

  // ✅ Limpiar manzana y número cuando el USUARIO cambia el proyecto
  useEffect(() => {
    if (
      proyectoSeleccionado &&
      prevProyecto.current &&
      prevProyecto.current !== proyectoSeleccionado
    ) {
      setValue('manzana_id', '')
      setValue('numero', '')
    }
    prevProyecto.current = proyectoSeleccionado
  }, [proyectoSeleccionado, setValue])

  // ✅ Limpiar número cuando el USUARIO cambia la manzana
  useEffect(() => {
    if (
      manzanaSeleccionada &&
      prevManzana.current &&
      prevManzana.current !== manzanaSeleccionada
    ) {
      setValue('numero', '')
    }
    prevManzana.current = manzanaSeleccionada
  }, [manzanaSeleccionada, setValue])

  // ✅ Información de la manzana seleccionada
  const manzanaInfo = useMemo(() =>
    manzanas.find(m => m.id === manzanaSeleccionada),
    [manzanas, manzanaSeleccionada]
  )

  return {
    // Datos
    proyectos,
    manzanas,
    numerosDisponibles,
    manzanaInfo,

    // Estados de carga
    cargandoProyectos,
    cargandoManzanas,
    cargandoNumeros,

    // Errores (para mostrar en UI si es necesario)
    errorProyectos,
    errorManzanas,
  }
}

/**
 * 🎣 Hook: Lógica de Modal Reactivar Vivienda
 *
 * Responsabilidad:
 * - Manejar estado del modal (motivo, confirmación, validación)
 * - Validar automáticamente al abrir
 * - Calcular caracteres restantes
 * - Ejecutar reactivación
 * - Limpiar al cerrar
 */

'use client'

import { useCallback, useEffect, useState } from 'react'

import { logger } from '@/lib/utils/logger'

import { useViviendaInactivacion } from './useViviendaInactivacion'

// ============================================================
// TIPOS
// ============================================================

interface UseReactivarViviendaModalParams {
  isOpen: boolean
  viviendaId: string
  onSuccess: () => void
  onClose: () => void
}

interface UseReactivarViviendaModalReturn {
  // Estado
  motivo: string
  confirmado: boolean
  validacion: any
  validando: boolean
  procesando: boolean
  error: string | null

  // Validaciones
  motivoValido: boolean
  caracteresRestantes: number
  puedeReactivar: boolean

  // Acciones
  setMotivo: (motivo: string) => void
  setConfirmado: (confirmado: boolean) => void
  handleReactivar: () => Promise<void>
}

const MOTIVO_MINIMO = 30

// ============================================================
// HOOK
// ============================================================

export function useReactivarViviendaModal({
  isOpen,
  viviendaId,
  onSuccess,
  onClose,
}: UseReactivarViviendaModalParams): UseReactivarViviendaModalReturn {
  const { validarReactivacion, reactivar, validando, procesando, error, limpiarError } =
    useViviendaInactivacion()

  const [motivo, setMotivo] = useState('')
  const [confirmado, setConfirmado] = useState(false)
  const [validacion, setValidacion] = useState<any>(null)

  // Calcular validaciones
  const caracteresRestantes = MOTIVO_MINIMO - motivo.length
  const motivoValido = motivo.trim().length >= MOTIVO_MINIMO
  const puedeReactivar = motivoValido && confirmado && !procesando && validacion?.puedeReactivar

  // Validar al abrir modal
  useEffect(() => {
    if (isOpen && viviendaId) {
      validarReactivacion(viviendaId)
        .then((result) => setValidacion(result))
        .catch((err) => logger.error('Error al validar:', err))
    }
  }, [isOpen, viviendaId, validarReactivacion])

  // Limpiar al cerrar
  useEffect(() => {
    if (!isOpen) {
      setMotivo('')
      setConfirmado(false)
      setValidacion(null)
      limpiarError()
    }
  }, [isOpen, limpiarError])

  // Ejecutar reactivación
  const handleReactivar = useCallback(async () => {
    if (!puedeReactivar) return

    try {
      await reactivar(viviendaId, motivo)
      onSuccess()
      onClose()
    } catch (err) {
      // Error manejado por el hook base
    }
  }, [puedeReactivar, reactivar, viviendaId, motivo, onSuccess, onClose])

  return {
    motivo,
    confirmado,
    validacion,
    validando,
    procesando,
    error,
    motivoValido,
    caracteresRestantes,
    puedeReactivar,
    setMotivo,
    setConfirmado,
    handleReactivar,
  }
}

/**
 * ?? Hook: Estado de Bloqueo de Vivienda
 *
 * Responsabilidad:
 * - Cargar estado de bloqueo de edici�n de una vivienda
 * - Determinar campos editables/restringidos/bloqueados
 * - Validar permisos por campo espec�fico
 * - Refrescar estado cuando cambian negociaciones
 *
 * Uso:
 * ```tsx
 * const { estadoBloqueo, cargando, validarCampo } = useViviendaBloqueo(viviendaId)
 * ```
 */

'use client'

import { useCallback, useEffect, useState } from 'react'

import { useAuth } from '@/contexts/auth-context'
import { logger } from '@/lib/utils/logger'

import {
    ViviendaValidacionService,
    type CampoVivienda,
    type EstadoBloqueoVivienda,
    type ValidacionCampo,
} from '../services/viviendas-validacion.service'


// ============================================================
// TIPOS
// ============================================================

interface UseViviendaBloqueoReturn {
  estadoBloqueo: EstadoBloqueoVivienda | null
  cargando: boolean
  error: string | null
  refetch: () => Promise<void>
  validarCampo: (campo: CampoVivienda) => Promise<ValidacionCampo>
  puedeEditarCampo: (campo: CampoVivienda) => boolean
}

// ============================================================
// HOOK
// ============================================================

export function useViviendaBloqueo(viviendaId: string | null): UseViviendaBloqueoReturn {
  const { user, perfil } = useAuth()
  const [estadoBloqueo, setEstadoBloqueo] = useState<EstadoBloqueoVivienda | null>(null)
  const [cargando, setCargando] = useState(true)
  const [error, setError] = useState<string | null>(null)

  const esAdmin = perfil?.rol === 'Administrador'

  // Cargar estado de bloqueo
  const cargarEstadoBloqueo = useCallback(async () => {
    if (!viviendaId) {
      setCargando(false)
      return
    }

    try {
      setCargando(true)
      setError(null)

      const estado = await ViviendaValidacionService.verificarEstadoBloqueo(viviendaId)
      setEstadoBloqueo(estado)
    } catch (err) {
      const mensaje = err instanceof Error ? err.message : 'Error al cargar estado de bloqueo'
      setError(mensaje)
      logger.error('? Error en useViviendaBloqueo:', err)
    } finally {
      setCargando(false)
    }
  }, [viviendaId])

  // Cargar al montar y cuando cambia viviendaId
  useEffect(() => {
    cargarEstadoBloqueo()
  }, [cargarEstadoBloqueo])

  // Validar campo espec�fico
  const validarCampo = useCallback(
    async (campo: CampoVivienda): Promise<ValidacionCampo> => {
      if (!viviendaId) {
        return {
          puedeEditar: false,
          requiereAdmin: false,
          requiereMotivo: false,
          razon: 'ID de vivienda no v�lido',
        }
      }

      return ViviendaValidacionService.puedeEditarCampo(viviendaId, campo, esAdmin)
    },
    [viviendaId, esAdmin]
  )

  // Helper: Verificar si puede editar campo (sin async)
  const puedeEditarCampo = useCallback(
    (campo: CampoVivienda): boolean => {
      if (!estadoBloqueo) return false

      // Si est� bloqueada completamente, solo campos editables permitidos
      if (estadoBloqueo.bloqueadaCompletamente) {
        return estadoBloqueo.camposEditables.includes(campo)
      }

      // Si el campo est� bloqueado, no permitir
      if (estadoBloqueo.camposBloqueados.includes(campo)) {
        return false
      }

      // Si el campo est� restringido, solo admin
      if (estadoBloqueo.camposRestringidos.includes(campo)) {
        return esAdmin
      }

      // Si est� en editables, permitir
      return estadoBloqueo.camposEditables.includes(campo)
    },
    [estadoBloqueo, esAdmin]
  )

  return {
    estadoBloqueo,
    cargando,
    error,
    refetch: cargarEstadoBloqueo,
    validarCampo,
    puedeEditarCampo,
  }
}

import { useCallback, useEffect, useMemo, useState } from 'react'

import { logger } from '@/lib/utils/logger'

import { MENSAJES, PASOS_FORMULARIO, VIVIENDA_DEFAULTS } from '../constants'
import { viviendasService } from '../services/viviendas.service'
import type {
    ConfiguracionRecargo,
    ManzanaConDisponibilidad,
    PasoFormulario,
    Proyecto,
    ResumenFinanciero,
    ViviendaFormData,
} from '../types'
import {
    calcularValorTotal,
    validarArea,
    validarLindero,
    validarMatricula,
    validarNomenclatura,
    validarValorBase
} from '../utils'

/**
 * Hook principal para el formulario de creación de viviendas
 * Maneja la lógica completa del wizard multi-paso
 */
export function useViviendaForm() {
  // ============================================
  // ESTADO
  // ============================================

  // Paso actual del wizard
  const [pasoActual, setPasoActual] = useState<PasoFormulario>('ubicacion')

  // Pasos completados
  const [pasosCompletados, setPasosCompletados] = useState<PasoFormulario[]>([])

  // Datos del formulario
  const [formData, setFormData] = useState<Partial<ViviendaFormData>>({
    es_esquinera: false,
    recargo_esquinera: 0,
  })

  // Errores de validación
  const [errores, setErrores] = useState<Record<string, string>>({})

  // Estados de carga
  const [loading, setLoading] = useState(false)
  const [loadingProyectos, setLoadingProyectos] = useState(false)
  const [loadingManzanas, setLoadingManzanas] = useState(false)

  // Datos de selección
  const [proyectos, setProyectos] = useState<Proyecto[]>([])
  const [manzanas, setManzanas] = useState<ManzanaConDisponibilidad[]>([])
  const [numerosOcupados, setNumerosOcupados] = useState<string[]>([])
  const [numerosDisponibles, setNumerosDisponibles] = useState<number[]>([])
  const [gastosNotariales, setGastosNotariales] = useState(VIVIENDA_DEFAULTS.GASTOS_NOTARIALES)
  const [configuracionRecargos, setConfiguracionRecargos] = useState<ConfiguracionRecargo[]>([])

  // Validación de matrícula
  const [validandoMatricula, setValidandoMatricula] = useState(false)

  // ============================================
  // CARGA INICIAL
  // ============================================

  useEffect(() => {
    cargarProyectos()
    cargarConfiguracionRecargos()
  }, [])

  const cargarProyectos = useCallback(async () => {
    try {
      setLoadingProyectos(true)
      const data = await viviendasService.obtenerProyectos()
      setProyectos(data)
    } catch (error) {
      logger.error('Error cargando proyectos:', error)
    } finally {
      setLoadingProyectos(false)
    }
  }, [])

  const cargarConfiguracionRecargos = useCallback(async () => {
    try {
      const [recargos, gastosNot] = await Promise.all([
        viviendasService.obtenerConfiguracionRecargos(),
        viviendasService.obtenerGastosNotariales(),
      ])
      setConfiguracionRecargos(recargos)
      setGastosNotariales(gastosNot)
    } catch (error) {
      logger.error('Error cargando configuración:', error)
    }
  }, [])

  // ============================================
  // SELECCIÓN DE PROYECTO
  // ============================================

  const seleccionarProyecto = useCallback(
    async (proyectoId: string) => {
      setFormData((prev) => ({
        ...prev,
        proyecto_id: proyectoId,
        manzana_id: undefined,
        numero: undefined,
      }))

      // Cargar manzanas disponibles del proyecto
      try {
        setLoadingManzanas(true)
        const data = await viviendasService.obtenerManzanasDisponibles(proyectoId)
        setManzanas(data)
      } catch (error) {
        logger.error('Error cargando manzanas:', error)
      } finally {
        setLoadingManzanas(false)
      }
    },
    []
  )

  // ============================================
  // SELECCIÓN DE MANZANA
  // ============================================

  const seleccionarManzana = useCallback(
    async (manzanaId: string) => {
      try {
        // Obtener números ocupados y generar disponibles
        const [ocupados, manzanaData] = await Promise.all([
          viviendasService.obtenerNumerosOcupados(manzanaId),
          manzanas.find((m) => m.id === manzanaId),
        ])

        setNumerosOcupados(ocupados)

        // Generar lista de números disponibles
        if (manzanaData) {
          const totalViviendas = manzanaData.total_viviendas
          const disponibles: number[] = []

          for (let i = 1; i <= totalViviendas; i++) {
            if (!ocupados.includes(i.toString())) {
              disponibles.push(i)
            }
          }

          setNumerosDisponibles(disponibles)

          // NO asignar automáticamente, dejar que el usuario seleccione
          setFormData((prev) => ({
            ...prev,
            manzana_id: manzanaId,
            numero: undefined, // Vacío hasta que el usuario seleccione
          }))
        }
      } catch (error) {
        logger.error('Error cargando números disponibles:', error)
      }
    },
    [manzanas]
  )

  // ============================================
  // MANZANA SELECCIONADA
  // ============================================

  const manzanaSeleccionada = useMemo(() => {
    if (!formData.manzana_id) return null
    return manzanas.find((m) => m.id === formData.manzana_id)
  }, [formData.manzana_id, manzanas])

  // ============================================
  // ACTUALIZAR CAMPO
  // ============================================

  const actualizarCampo = useCallback(<K extends keyof ViviendaFormData>(
    campo: K,
    valor: ViviendaFormData[K]
  ) => {
    setFormData((prev) => ({
      ...prev,
      [campo]: valor,
    }))

    // Limpiar error del campo
    setErrores((prev) => {
      const newErrors = { ...prev }
      delete newErrors[campo]
      return newErrors
    })
  }, [])

  // ============================================
  // TOGGLE CASA ESQUINERA
  // ============================================

  const toggleEsquinera = useCallback((checked: boolean) => {
    setFormData((prev) => ({
      ...prev,
      es_esquinera: checked,
      recargo_esquinera: checked ? prev.recargo_esquinera || 0 : 0,
    }))
  }, [])

  // ============================================
  // RESUMEN FINANCIERO CALCULADO
  // ============================================

  const resumenFinanciero: ResumenFinanciero = useMemo(() => {
    const valorBase = formData.valor_base || 0
    const recargoEsquinera = formData.es_esquinera ? formData.recargo_esquinera || 0 : 0
    const valorTotal = calcularValorTotal(valorBase, gastosNotariales, recargoEsquinera)

    return {
      valor_base: valorBase,
      gastos_notariales: gastosNotariales,
      recargo_esquinera: recargoEsquinera,
      valor_total: valorTotal,
    }
  }, [formData.valor_base, formData.es_esquinera, formData.recargo_esquinera, gastosNotariales])

  // ============================================
  // VALIDACIÓN POR PASO
  // ============================================

  const validarPasoUbicacion = useCallback((): boolean => {
    const newErrors: Record<string, string> = {}

    if (!formData.proyecto_id) {
      newErrors.proyecto_id = 'Debe seleccionar un proyecto'
    }
    if (!formData.manzana_id) {
      newErrors.manzana_id = 'Debe seleccionar una manzana'
    }
    if (!formData.numero) {
      newErrors.numero = 'El número de vivienda es requerido'
    }

    setErrores(newErrors)
    return Object.keys(newErrors).length === 0
  }, [formData])

  const validarPasoLinderos = useCallback((): boolean => {
    const newErrors: Record<string, string> = {}

    const errorNorte = validarLindero(formData.lindero_norte || '')
    if (errorNorte) newErrors.lindero_norte = errorNorte

    const errorSur = validarLindero(formData.lindero_sur || '')
    if (errorSur) newErrors.lindero_sur = errorSur

    const errorOriente = validarLindero(formData.lindero_oriente || '')
    if (errorOriente) newErrors.lindero_oriente = errorOriente

    const errorOccidente = validarLindero(formData.lindero_occidente || '')
    if (errorOccidente) newErrors.lindero_occidente = errorOccidente

    setErrores(newErrors)
    return Object.keys(newErrors).length === 0
  }, [formData])

  const validarPasoLegal = useCallback(async (): Promise<boolean> => {
    const newErrors: Record<string, string> = {}

    const errorMatricula = validarMatricula(formData.matricula_inmobiliaria || '')
    if (errorMatricula) {
      newErrors.matricula_inmobiliaria = errorMatricula
    } else if (formData.matricula_inmobiliaria) {
      // Validar que la matrícula sea única
      setValidandoMatricula(true)
      try {
        const esUnica = await viviendasService.verificarMatriculaUnica(
          formData.matricula_inmobiliaria
        )
        if (!esUnica) {
          newErrors.matricula_inmobiliaria =
            'Esta matrícula inmobiliaria ya existe. Cada vivienda debe tener una matrícula única.'
        }
      } catch (error) {
        logger.error('Error validando matrícula:', error)
        newErrors.matricula_inmobiliaria = 'Error al validar la matrícula. Intente nuevamente.'
      } finally {
        setValidandoMatricula(false)
      }
    }

    const errorNomenclatura = validarNomenclatura(formData.nomenclatura || '')
    if (errorNomenclatura) newErrors.nomenclatura = errorNomenclatura

    const errorAreaLote = validarArea(formData.area_lote || '', 'lote')
    if (errorAreaLote) newErrors.area_lote = errorAreaLote

    const errorAreaConstruida = validarArea(formData.area_construida || '', 'construida')
    if (errorAreaConstruida) newErrors.area_construida = errorAreaConstruida

    if (!formData.tipo_vivienda) {
      newErrors.tipo_vivienda = 'El tipo de vivienda es requerido'
    }

    setErrores(newErrors)
    return Object.keys(newErrors).length === 0
  }, [formData])

  const validarPasoFinanciero = useCallback((): boolean => {
    const newErrors: Record<string, string> = {}

    const errorValorBase = validarValorBase(formData.valor_base || 0)
    if (errorValorBase) newErrors.valor_base = errorValorBase

    if (formData.es_esquinera && !formData.recargo_esquinera) {
      newErrors.recargo_esquinera = 'Debe seleccionar el recargo para casa esquinera'
    }

    setErrores(newErrors)
    return Object.keys(newErrors).length === 0
  }, [formData])

  // ============================================
  // NAVEGACIÓN ENTRE PASOS
  // ============================================

  const avanzarPaso = useCallback(async () => {
    // Validar paso actual antes de avanzar
    let esValido = false

    switch (pasoActual) {
      case 'ubicacion':
        esValido = validarPasoUbicacion()
        break
      case 'linderos':
        esValido = validarPasoLinderos()
        break
      case 'legal':
        esValido = await validarPasoLegal() // Ahora es async
        break
      case 'financiero':
        esValido = validarPasoFinanciero()
        break
      case 'resumen':
        esValido = true
        break
    }

    if (!esValido) return

    // Marcar paso como completado
    if (!pasosCompletados.includes(pasoActual)) {
      setPasosCompletados((prev) => [...prev, pasoActual])
    }

    // Avanzar al siguiente paso
    const pasoIndex = PASOS_FORMULARIO.findIndex((p) => p.id === pasoActual)
    if (pasoIndex < PASOS_FORMULARIO.length - 1) {
      setPasoActual(PASOS_FORMULARIO[pasoIndex + 1].id)
    }
  }, [
    pasoActual,
    pasosCompletados,
    validarPasoUbicacion,
    validarPasoLinderos,
    validarPasoLegal,
    validarPasoFinanciero,
  ])

  const retrocederPaso = useCallback(() => {
    const pasoIndex = PASOS_FORMULARIO.findIndex((p) => p.id === pasoActual)
    if (pasoIndex > 0) {
      setPasoActual(PASOS_FORMULARIO[pasoIndex - 1].id)
    }
  }, [pasoActual])

  const irAPaso = useCallback((paso: PasoFormulario) => {
    setPasoActual(paso)
  }, [])

  // ============================================
  // SUBMIT
  // ============================================

  const submitFormulario = useCallback(async () => {
    try {
      setLoading(true)

      // Validar todos los pasos
      const ubicacionValida = validarPasoUbicacion()
      const linderosValidos = validarPasoLinderos()
      const legalValido = validarPasoLegal()
      const financieroValido = validarPasoFinanciero()

      if (!ubicacionValida || !linderosValidos || !legalValido || !financieroValido) {
        throw new Error('Por favor completa todos los campos requeridos')
      }

      // Crear vivienda
      await viviendasService.crear(formData as ViviendaFormData)

      // Resetear formulario
      resetFormulario()

      return { success: true, mensaje: MENSAJES.EXITO_CREAR }
    } catch (error: unknown) {
      logger.error('Error creando vivienda:', error)
      return { success: false, mensaje: error.message || MENSAJES.ERROR_CREAR }
    } finally {
      setLoading(false)
    }
  }, [formData, validarPasoUbicacion, validarPasoLinderos, validarPasoLegal, validarPasoFinanciero])

  // ============================================
  // RESET
  // ============================================

  const resetFormulario = useCallback(() => {
    setFormData({ es_esquinera: false, recargo_esquinera: 0 })
    setPasoActual('ubicacion')
    setPasosCompletados([])
    setErrores({})
    setManzanas([])
  }, [])

  // ============================================
  // RETURN
  // ============================================

  return {
    // Estado del wizard
    pasoActual,
    pasosCompletados,
    formularioCompleto: pasosCompletados.length === PASOS_FORMULARIO.length,

    // Datos
    formData,
    errores,
    resumenFinanciero,

    // Datos de selección
    proyectos,
    manzanas,
    manzanaSeleccionada,
    numerosDisponibles,
    gastosNotariales,
    configuracionRecargos,

    // Estados de carga
    loading,
    loadingProyectos,
    loadingManzanas,
    validandoMatricula,

    // Acciones
    actualizarCampo,
    seleccionarProyecto,
    seleccionarManzana,
    toggleEsquinera,
    avanzarPaso,
    retrocederPaso,
    irAPaso,
    submitFormulario,
    resetFormulario,
  }
}

/**
 * HOOK DE VALIDACIÓN CON DEBOUNCING - VIVIENDA
 *
 * CAPA 3: Integración con React Hook Form y TanStack Query
 * Gestiona validaciones asíncronas con cache y debouncing
 */

import { useEffect, useState } from 'react'

import { useQuery } from '@tanstack/react-query'

import {
  validarManzanaExiste,
  validarMatriculaDuplicada,
  validarNumeroCasaDuplicado,
  validarProyectoExiste,
} from '../services/vivienda-validation.service'

// ============================================================================
// CONFIGURACIÓN DE DEBOUNCING
// ============================================================================

const DEBOUNCE_DELAY = 500 // milisegundos

/**
 * Hook para validar matrícula con debouncing y cache
 */
export function useValidarMatricula(
  numeroMatricula: string | undefined,
  viviendaIdActual?: string
) {
  const [debouncedValue, setDebouncedValue] = useState(numeroMatricula)

  // Debouncing
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedValue(numeroMatricula)
    }, DEBOUNCE_DELAY)

    return () => clearTimeout(timer)
  }, [numeroMatricula])

  // Query con cache
  return useQuery({
    queryKey: ['validar-matricula', debouncedValue, viviendaIdActual],
    queryFn: () => validarMatriculaDuplicada(debouncedValue!, viviendaIdActual),
    enabled: Boolean(debouncedValue && debouncedValue.length >= 5), // Solo validar si tiene mínimo 5 caracteres
    staleTime: 30000, // Cache 30 segundos
    retry: 1,
  })
}

/**
 * Hook para validar número de casa con debouncing
 */
export function useValidarNumeroCasa(
  numeroCasa: string | undefined,
  proyectoId: string | undefined,
  manzanaId: string | undefined,
  viviendaIdActual?: string
) {
  const [debouncedValue, setDebouncedValue] = useState(numeroCasa)

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedValue(numeroCasa)
    }, DEBOUNCE_DELAY)

    return () => clearTimeout(timer)
  }, [numeroCasa])

  return useQuery({
    queryKey: [
      'validar-numero-casa',
      debouncedValue,
      proyectoId,
      manzanaId,
      viviendaIdActual,
    ],
    queryFn: () =>
      validarNumeroCasaDuplicado(
        debouncedValue!,
        proyectoId!,
        manzanaId!,
        viviendaIdActual
      ),
    enabled: Boolean(debouncedValue && proyectoId && manzanaId),
    staleTime: 30000,
    retry: 1,
  })
}

/**
 * Hook para validar proyecto
 */
export function useValidarProyecto(proyectoId: string | undefined) {
  return useQuery({
    queryKey: ['validar-proyecto', proyectoId],
    queryFn: () => validarProyectoExiste(proyectoId!),
    enabled: Boolean(proyectoId),
    staleTime: 60000, // Proyectos cambian poco, cache 1 minuto
    retry: 1,
  })
}

/**
 * Hook para validar manzana
 */
export function useValidarManzana(
  manzanaId: string | undefined,
  proyectoId: string | undefined
) {
  return useQuery({
    queryKey: ['validar-manzana', manzanaId, proyectoId],
    queryFn: () => validarManzanaExiste(manzanaId!, proyectoId!),
    enabled: Boolean(manzanaId && proyectoId),
    staleTime: 60000,
    retry: 1,
  })
}

// ============================================================================
// HOOK AGREGADOR (todos los estados juntos)
// ============================================================================

/**
 * Hook que agrega todos los estados de validación
 * Útil para mostrar indicadores de validación en el formulario
 */
export function useViviendaValidationStatus(formData: {
  numero_matricula?: string
  numero_casa?: string
  proyecto_id?: string
  manzana_id?: string
  vivienda_id?: string
}) {
  const matriculaValidation = useValidarMatricula(
    formData.numero_matricula,
    formData.vivienda_id
  )
  const casaValidation = useValidarNumeroCasa(
    formData.numero_casa,
    formData.proyecto_id,
    formData.manzana_id,
    formData.vivienda_id
  )
  const proyectoValidation = useValidarProyecto(formData.proyecto_id)
  const manzanaValidation = useValidarManzana(
    formData.manzana_id,
    formData.proyecto_id
  )

  return {
    matricula: {
      isValidating: matriculaValidation.isFetching,
      isValid: matriculaValidation.data?.exists === false,
      error: matriculaValidation.data?.mensaje,
    },
    casa: {
      isValidating: casaValidation.isFetching,
      isValid: casaValidation.data?.exists === false,
      error: casaValidation.data?.mensaje,
    },
    proyecto: {
      isValidating: proyectoValidation.isFetching,
      isValid: proyectoValidation.data?.exists === true,
      error: proyectoValidation.data?.mensaje,
      nombre: proyectoValidation.data?.nombre,
    },
    manzana: {
      isValidating: manzanaValidation.isFetching,
      isValid: manzanaValidation.data?.exists === true,
      error: manzanaValidation.data?.mensaje,
      nombre: manzanaValidation.data?.nombre,
    },
    // Estado general
    isAnyValidating:
      matriculaValidation.isFetching ||
      casaValidation.isFetching ||
      proyectoValidation.isFetching ||
      manzanaValidation.isFetching,
    hasAnyError:
      matriculaValidation.data?.exists ||
      casaValidation.data?.exists ||
      !proyectoValidation.data?.exists ||
      !manzanaValidation.data?.exists,
  }
}

import { useCallback, _useMemo } from 'react'

import type { Tables } from '@/lib/supabase/database.types'

import type { FiltrosViviendas } from '../types'

import { useViviendasQuery, useCrearViviendaMutation, useActualizarViviendaMutation, useEliminarViviendaMutation } from './useViviendasQuery'

type Vivienda = Tables<'viviendas'>

interface UseViviendasReturn {
  viviendas: Vivienda[]
  cargando: boolean
  error: string | null
  refrescar: () => Promise<void>
  crearVivienda: (data: any) => Promise<void>
  actualizarVivienda: (id: string, data: any) => Promise<void>
  eliminarVivienda: (id: string) => Promise<void>
}

/**
 * Hook para gestión de viviendas
 * Refactorizado con React Query
 */
export function useViviendas(filtros?: FiltrosViviendas): UseViviendasReturn {
  const { data: viviendasRaw = [], isLoading: cargando, error, refetch } = useViviendasQuery(filtros || undefined)
  const viviendas = viviendasRaw as any[]
  const crearMutation = useCrearViviendaMutation()
  const actualizarMutation = useActualizarViviendaMutation()
  const eliminarMutation = useEliminarViviendaMutation()

  const refrescar = useCallback(async () => {
    await refetch()
  }, [refetch])

  const crearVivienda = useCallback(async (data: any) => {
    await crearMutation.mutateAsync(data)
  }, [crearMutation])

  const actualizarVivienda = useCallback(async (id: string, data: any) => {
    await actualizarMutation.mutateAsync({ id, data })
  }, [actualizarMutation])

  const eliminarVivienda = useCallback(async (id: string) => {
    await eliminarMutation.mutateAsync(id)
  }, [eliminarMutation])

  return {
    viviendas,
    cargando,
    error: error?.message || null,
    refrescar,
    crearVivienda,
    actualizarVivienda,
    eliminarVivienda,
  }
}

/**
 * ============================================
 * REACT QUERY HOOKS: Viviendas
 * ============================================
 * Hooks para gestión de viviendas con React Query
 * SOLO datos del servidor - UI state en hooks separados
 */

import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query'
import { toast } from 'sonner'

import { viviendasService } from '../services/viviendas.service'
import type { FiltrosViviendas, ViviendaFormData } from '../types'

// ============================================
// QUERY KEYS (Cache keys centralizadas)
// ============================================
export const viviendasKeys = {
  all: ['viviendas'] as const,
  lists: () => [...viviendasKeys.all, 'list'] as const,
  list: (filtros?: FiltrosViviendas) => [...viviendasKeys.lists(), filtros] as const,
  details: () => [...viviendasKeys.all, 'detail'] as const,
  detail: (id: string) => [...viviendasKeys.details(), id] as const,
  manzanaViviendas: (manzanaId: string) => [...viviendasKeys.all, 'manzana', manzanaId] as const,

  // Relacionados
  proyectos: ['viviendas', 'proyectos'] as const,
  manzanas: (proyectoId: string) => ['viviendas', 'manzanas', proyectoId] as const,
  siguienteNumero: (manzanaId: string) => ['viviendas', 'siguiente-numero', manzanaId] as const,
  numerosOcupados: (manzanaId: string) => ['viviendas', 'numeros-ocupados', manzanaId] as const,
  recargos: ['viviendas', 'recargos'] as const,
  gastosNotariales: ['viviendas', 'gastos-notariales'] as const,
}

// ============================================
// 1. QUERY: Lista de viviendas con filtros
// ============================================
export function useViviendasQuery(filtros?: FiltrosViviendas) {
  return useQuery({
    queryKey: viviendasKeys.list(filtros),
    queryFn: () => viviendasService.listar(filtros),
    staleTime: 0, // ✅ SIEMPRE re-fetch al montar para evitar "0 resultados" al navegar
    gcTime: 1000 * 60 * 5, // 5 minutos en cache después de desmontar
    refetchOnMount: 'always', // ← CRÍTICO: Refetch siempre al montar (incluso con datos en cache)
  })
}

// ============================================
// 2. QUERY: Vivienda individual (detalle)
// ============================================
export function useViviendaQuery(id: string) {
  return useQuery({
    queryKey: viviendasKeys.detail(id),
    queryFn: () => viviendasService.obtenerVivienda(id),
    enabled: !!id,
    staleTime: 0, // ✅ SIEMPRE re-fetch para tener datos actualizados
    gcTime: 1000 * 60 * 5, // 5 minutos en cache
  })
}

