// ============================================================
// SERVICIO
// ============================================================

export class ViviendaInactivacionService {
  /**
   * Validar si una vivienda puede ser inactivada
   *
   * Criterios:
   * - NO debe tener negociaciones activas
   * - NO debe tener abonos registrados
   * - Opcionalmente: NO debe tener documentos importantes
   */
  static async validarEliminacion(viviendaId: string): Promise<ValidacionEliminacion> {
    try {
      // Contar negociaciones
      const { count: negociacionesCount, error: negError } = await supabase
        .from('negociaciones')
        .select('*', { count: 'exact', head: true })
        .eq('vivienda_id', viviendaId)

      if (negError) throw negError

      if (negociacionesCount && negociacionesCount > 0) {
        return {
          puedeEliminar: false,
          razon: `La vivienda tiene ${negociacionesCount} negociación(es). No se puede inactivar.`,
          detalles: {
            negociaciones: negociacionesCount,
            abonos: 0,
            montoTotal: 0,
            documentos: 0,
          },
        }
      }

      // Contar abonos
      const { data: abonosRaw, error: abonosError } = await supabase
        .from('abonos' as any)
        .select('monto_abono')
        .eq('vivienda_id', viviendaId)
      const abonos = abonosRaw as any[] | null

      if (abonosError) throw abonosError

      const abonosCount = abonos?.length || 0
      const montoTotal = abonos?.reduce((sum, abono) => sum + (abono.monto_abono || 0), 0) || 0

      if (abonosCount > 0) {
        return {
          puedeEliminar: false,
          razon: `La vivienda tiene ${abonosCount} abono(s) por un total de $${montoTotal.toLocaleString()}. No se puede inactivar.`,
          detalles: {
            negociaciones: 0,
            abonos: abonosCount,
            montoTotal,
            documentos: 0,
          },
        }
      }

      // Contar documentos importantes (opcional)
      const { count: documentosCount, error: docsError } = await supabase
        .from('documentos_vivienda')
        .select('*', { count: 'exact', head: true })
        .eq('vivienda_id', viviendaId)
        .eq('es_importante', true)
        .eq('estado', 'activo')

      if (docsError) throw docsError

      // Vivienda limpia, puede inactivarse
      return {
        puedeEliminar: true,
        detalles: {
          negociaciones: 0,
          abonos: 0,
          montoTotal: 0,
          documentos: documentosCount || 0,
        },
      }
    } catch (error) {
      logger.error('❌ Error al validar eliminación:', error)
      throw error
    }
  }

  /**
   * Marcar vivienda como inactiva (soft delete)
   *
   * Proceso:
   * 1. Validar que puede inactivarse
   * 2. UPDATE estado = 'Inactiva'
   * 3. Registrar auditoría (fecha, motivo, usuario)
   * 4. INSERT en viviendas_historial_estados
   */
  static async marcarComoInactiva(
    viviendaId: string,
    datos: MotivoInactivacion
  ): Promise<void> {
    try {
      // Validar que puede inactivarse
      const validacion = await this.validarEliminacion(viviendaId)

      if (!validacion.puedeEliminar) {
        throw new Error(validacion.razon)
      }

      // Validar motivo mínimo
      if (!datos.motivo || datos.motivo.trim().length < 50) {
        throw new Error('El motivo debe tener al menos 50 caracteres')
      }

      // Obtener estado actual
      const { data: vivienda, error: viviendaError } = await supabase
        .from('viviendas')
        .select('estado, contador_desactivaciones')
        .eq('id', viviendaId)
        .single()

      if (viviendaError) throw viviendaError

      const estadoAnterior = vivienda.estado
      const contadorActual = vivienda.contador_desactivaciones || 0

      // Actualizar vivienda
      const { error: updateError } = await supabase
        .from('viviendas')
        .update({
          estado: 'Inactiva',
          fecha_inactivacion: new Date().toISOString(),
          motivo_inactivacion: datos.motivo.trim(),
          inactivada_por: datos.userId,
          contador_desactivaciones: contadorActual + 1,
        })
        .eq('id', viviendaId)

      if (updateError) throw updateError

      // Registrar en historial
      const { error: historialError } = await supabase
        .from('viviendas_historial_estados')
        .insert({
          vivienda_id: viviendaId,
          estado_anterior: estadoAnterior,
          estado_nuevo: 'Inactiva',
          motivo: datos.motivo.trim(),
          usuario_id: datos.userId,
          metadata: {
            tipo_operacion: 'inactivacion',
            detalles_validacion: validacion.detalles,
          },
        })

      if (historialError) throw historialError

    } catch (error) {
      logger.error('❌ Error al marcar como inactiva:', error)
      throw error
    }
  }

  /**
   * Validar si una vivienda puede ser reactivada
   *
   * Criterios:
   * - Proyecto debe estar activo
   * - NO debe existir otra vivienda activa con el mismo número en la manzana
   */
  static async validarReactivacion(viviendaId: string): Promise<ValidacionReactivacion> {
    try {
      // Obtener datos de la vivienda
      const { data: viviendaRaw, error: viviendaError } = await supabase
        .from('viviendas')
        .select(
          `
          numero,
          manzana_id,
          proyecto_id,
          proyectos (
            estado,
            archivado
          )
        `
        )
        .eq('id', viviendaId)
        .single()
      const vivienda = viviendaRaw as any

      if (viviendaError) throw viviendaError

      // Validar proyecto activo
      if (vivienda.proyectos?.archivado || vivienda.proyectos?.estado !== 'en_proceso') {
        return {
          puedeReactivar: false,
          razon: 'El proyecto asociado está inactivo o no está en proceso',
          conflictos: {
            proyectoInactivo: true,
          },
        }
      }

      // Validar número duplicado
      const { data: duplicada, error: duplicadaError } = await supabase
        .from('viviendas')
        .select('id, numero, estado')
        .eq('manzana_id', vivienda.manzana_id)
        .eq('numero', vivienda.numero)
        .neq('id', viviendaId)
        .neq('estado', 'Inactiva')
        .maybeSingle()

      if (duplicadaError) throw duplicadaError

      if (duplicada) {
        return {
          puedeReactivar: false,
          razon: `Ya existe una vivienda activa con el número ${vivienda.numero} en esta manzana`,
          conflictos: {
            viviendaDuplicada: {
              id: duplicada.id,
              numero: duplicada.numero,
              estado: duplicada.estado,
            },
          },
        }
      }

      // Todo OK, puede reactivarse
      return {
        puedeReactivar: true,
      }
    } catch (error) {
      logger.error('❌ Error al validar reactivación:', error)
      throw error
    }
  }

  /**
   * Reactivar vivienda (cambiar estado a Disponible)
   *
   * Proceso:
   * 1. Validar que puede reactivarse
   * 2. UPDATE estado = 'Disponible'
   * 3. Registrar auditoría (fecha, motivo, usuario)
   * 4. INSERT en viviendas_historial_estados
   */
  static async reactivarVivienda(
    viviendaId: string,
    datos: MotivoReactivacion
  ): Promise<void> {
    try {
      // Validar que puede reactivarse
      const validacion = await this.validarReactivacion(viviendaId)

      if (!validacion.puedeReactivar) {
        throw new Error(validacion.razon)
      }

      // Validar motivo mínimo
      if (!datos.motivo || datos.motivo.trim().length < 30) {
        throw new Error('El motivo debe tener al menos 30 caracteres')
      }

      // Actualizar vivienda
      const { error: updateError } = await supabase
        .from('viviendas')
        .update({
          estado: 'Disponible',
          fecha_reactivacion: new Date().toISOString(),
          motivo_reactivacion: datos.motivo.trim(),
          reactivada_por: datos.userId,
        })
        .eq('id', viviendaId)

      if (updateError) throw updateError

      // Registrar en historial
      const { error: historialError } = await supabase
        .from('viviendas_historial_estados')
        .insert({
          vivienda_id: viviendaId,
          estado_anterior: 'Inactiva',
          estado_nuevo: 'Disponible',
          motivo: datos.motivo.trim(),
          usuario_id: datos.userId,
          metadata: {
            tipo_operacion: 'reactivacion',
          },
        })

      if (historialError) throw historialError

    } catch (error) {
      logger.error('❌ Error al reactivar vivienda:', error)
      throw error
    }
  }
}

/**
 * 🔐 Servicio de Validación y Bloqueo de Viviendas
 *
 * Responsabilidad:
 * - Verificar estado de bloqueo de edición según negociaciones
 * - Validar permisos por campo (matrícula, dirección, área, valor)
 * - Determinar campos editables/restringidos/bloqueados
 *
 * Regla de Oro: Minuta firmada = BLOQUEO TOTAL
 */

import { supabase } from '@/lib/supabase/client'
import { logger } from '@/lib/utils/logger'
import type { _Vivienda } from '@/modules/viviendas/types'

// ============================================================
// TIPOS
// ============================================================

export interface EstadoBloqueoVivienda {
  bloqueadaCompletamente: boolean
  razonBloqueo?: string
  negociacionBloqueante?: {
    id: string
    estado: string
    fecha_firma_minuta: string | null
    cliente_nombre: string
  }
  camposEditables: string[]
  camposRestringidos: string[] // Requieren Admin + motivo
  camposBloqueados: string[] // NO editables bajo ninguna circunstancia
}

export interface ValidacionCampo {
  puedeEditar: boolean
  requiereAdmin: boolean
  requiereMotivo: boolean
  razon?: string
}

export type CampoVivienda =
  | 'matricula_inmobiliaria'
  | 'area_lote'
  | 'area_construida'
  | 'valor_base'
  | 'numero'

// Estados que bloquean completamente la edición
const ESTADOS_BLOQUEANTES = ['Escriturada', 'Entregada', 'Finalizada']

// ============================================================
// SERVICIO
// ============================================================

export class ViviendaValidacionService {
  /**
   * Verificar estado de bloqueo de una vivienda
   *
   * Lógica:
   * 1. Sin negociaciones → Todo editable (campos legales requieren Admin)
   * 2. Negociación activa pre-minuta → Restringido (valor editable)
   * 3. Minuta firmada o estado bloqueante → BLOQUEADO COMPLETAMENTE
   */
  static async verificarEstadoBloqueo(viviendaId: string): Promise<EstadoBloqueoVivienda> {
    try {
      // Buscar negociaciones activas
      const { data: negociacionesRaw, error } = await supabase
        .from('negociaciones')
        .select(
          `
          id,
          estado,
          fecha_firma_minuta,
          clientes (
            nombres,
            apellidos
          )
        `
        )
        .eq('vivienda_id', viviendaId)
        .in('estado', ['Activa', 'Escriturada', 'Entregada', 'Finalizada'])
        .order('created_at', { ascending: false })
      const negociaciones = negociacionesRaw as any[]

      if (error) throw error

      // CASO 1: Sin negociaciones activas
      if (!negociaciones || negociaciones.length === 0) {
        return {
          bloqueadaCompletamente: false,
          camposEditables: [
            'matricula_inmobiliaria',
            'direccion',
            'area_lote',
            'area_construida',
            'valor_base',
            'descripcion',
            'numero',
          ],
          camposRestringidos: ['matricula_inmobiliaria', 'direccion', 'area_lote', 'area_construida'], // Requieren Admin
          camposBloqueados: [],
        }
      }

      const negociacion = negociaciones[0]

      // CASO 2: Minuta firmada o estado bloqueante → BLOQUEO TOTAL
      if (negociacion.fecha_firma_minuta || ESTADOS_BLOQUEANTES.includes(negociacion.estado)) {
        const clienteNombre = negociacion.clientes
          ? `${negociacion.clientes.nombres} ${negociacion.clientes.apellidos}`
          : 'Cliente desconocido'

        return {
          bloqueadaCompletamente: true,
          razonBloqueo: negociacion.fecha_firma_minuta
            ? `🔒 BLOQUEADO: Minuta firmada el ${new Date(negociacion.fecha_firma_minuta).toLocaleDateString()} - Datos legales congelados`
            : `🔒 BLOQUEADO: Estado "${negociacion.estado}" - Proceso completado`,
          negociacionBloqueante: {
            id: negociacion.id,
            estado: negociacion.estado,
            fecha_firma_minuta: negociacion.fecha_firma_minuta,
            cliente_nombre: clienteNombre,
          },
          camposEditables: ['descripcion'], // Solo campo informativo
          camposRestringidos: [],
          camposBloqueados: [
            'matricula_inmobiliaria',
            'direccion',
            'area_lote',
            'area_construida',
            'valor_base',
            'numero',
          ],
        }
      }

      // CASO 3: Negociación activa pre-minuta → RESTRINGIDO
      const clienteNombre = negociacion.clientes
        ? `${negociacion.clientes.nombres} ${negociacion.clientes.apellidos}`
        : 'Cliente desconocido'

      return {
        bloqueadaCompletamente: false,
        razonBloqueo: `⚠️ RESTRINGIDO: Negociación activa con ${clienteNombre}`,
        negociacionBloqueante: {
          id: negociacion.id,
          estado: negociacion.estado,
          fecha_firma_minuta: negociacion.fecha_firma_minuta,
          cliente_nombre: clienteNombre,
        },
        camposEditables: ['descripcion', 'valor_base'], // Valor aún editable
        camposRestringidos: ['matricula_inmobiliaria', 'direccion', 'area_lote', 'area_construida'], // Admin + motivo
        camposBloqueados: [],
      }
    } catch (error) {
      logger.error('❌ Error al verificar estado de bloqueo:', error)
      throw error
    }
  }

  /**
   * Validar si un campo específico puede ser editado
   *
   * @param viviendaId - ID de la vivienda
   * @param campo - Campo a validar
   * @param esAdmin - Si el usuario es Administrador
   * @returns Validación con permisos y razón
   */
  static async puedeEditarCampo(
    viviendaId: string,
    campo: CampoVivienda,
    esAdmin: boolean
  ): Promise<ValidacionCampo> {
    const estadoBloqueo = await this.verificarEstadoBloqueo(viviendaId)

    // Si está bloqueada completamente y el campo no es editable
    if (
      estadoBloqueo.bloqueadaCompletamente &&
      !estadoBloqueo.camposEditables.includes(campo)
    ) {
      return {
        puedeEditar: false,
        requiereAdmin: false,
        requiereMotivo: false,
        razon: estadoBloqueo.razonBloqueo,
      }
    }

    // Si el campo está en restringidos, requiere Admin
    if (estadoBloqueo.camposRestringidos.includes(campo)) {
      if (!esAdmin) {
        return {
          puedeEditar: false,
          requiereAdmin: true,
          requiereMotivo: true,
          razon: `⚠️ Campo "${campo}" requiere permisos de Administrador ${
            estadoBloqueo.razonBloqueo ? `(${estadoBloqueo.razonBloqueo})` : ''
          }`,
        }
      }

      // Admin puede editar pero debe justificar
      return {
        puedeEditar: true,
        requiereAdmin: true,
        requiereMotivo: true,
        razon: 'Campo crítico - Requiere justificación',
      }
    }

    // Campo editable sin restricciones
    return {
      puedeEditar: true,
      requiereAdmin: false,
      requiereMotivo: false,
    }
  }

  /**
   * Obtener historial completo de estados de una vivienda
   */
  static async obtenerHistorialCompleto(viviendaId: string) {
    try {
      const { data: historial, error } = await supabase
        .from('viviendas_historial_estados')
        .select(
          `
          id,
          estado_anterior,
          estado_nuevo,
          fecha_cambio,
          motivo,
          usuarios (
            nombres,
            apellidos,
            email
          ),
          metadata
        `
        )
        .eq('vivienda_id', viviendaId)
        .order('fecha_cambio', { ascending: false })

      if (error) throw error

      return historial || []
    } catch (error) {
      logger.error('❌ Error al obtener historial de estados:', error)
      throw error
    }
  }

  /**
   * Obtener historial de cambios de matrícula (solo Admin)
   */
  static async obtenerHistorialMatriculas(viviendaId: string) {
    try {
      const { data: historial, error } = await supabase
        .from('viviendas_historial_matriculas')
        .select(
          `
          id,
          matricula_anterior,
          matricula_nueva,
          fecha_cambio,
          motivo,
          nivel_riesgo,
          usuarios (
            nombres,
            apellidos,
            email
          ),
          negociaciones_snapshot,
          abonos_snapshot
        `
        )
        .eq('vivienda_id', viviendaId)
        .order('fecha_cambio', { ascending: false })

      if (error) throw error

      return historial || []
    } catch (error) {
      logger.error('❌ Error al obtener historial de matrículas:', error)
      throw error
    }
  }
}

