import { useFormChanges } from './useFormChanges'

function MyForm() {
  const initialData = {
    nombre: 'Proyecto Original',
    ubicacion: 'Medellín',
    descripcion: 'Descripción original',
    manzanas: [{ nombre: 'A', totalViviendas: 10 }]
