  return (
    <div>
      {hasChanges && (
        <div className="bg-yellow-50 p-4 rounded">
          <p className="font-medium">{changesCount} cambio(s) detectado(s):</p>
          <ul>
            {changes.map(change => (
              <li key={change.field}>
                • {change.label}: "{change.oldValue}" → "{change.newValue}"
              </li>
            ))}
          </ul>
        </div>
      )}

      <button disabled={!hasChanges}>
        Guardar Cambios
      </button>
    </div>
  )
}
